window.QUIZ_DATA = [{"id": "set1", "title": "ชุดที่ 1 — Cardiology + Pulmonology", "questions": [{"topic": "Cardiology", "q": "A 58-year-old man has crushing central chest pain radiating to the jaw for 40 minutes with diaphoresis. ECG shows ST elevation in V2–V4. He is at a hospital capable of primary PCI. What is the most appropriate reperfusion strategy?", "choices": ["Primary PCI within 90 minutes", "Immediate fibrinolytic (thrombolytic) therapy", "Wait for a positive troponin before deciding", "Start warfarin for anticoagulation", "Observe on telemetry for 24 hours"], "ans": 0, "exp": "นี่คือ anterior STEMI (LAD). เมื่อทำ primary PCI ได้ในเวลา ควรเลือก PCI ภายใน 90 นาที (door-to-balloon) ซึ่งเป็น reperfusion ที่ดีที่สุด. Fibrinolytic ใช้เมื่อ PCI ไม่ทัน (คาดว่าเกิน 120 นาที). ไม่ต้องรอ troponin เพราะ ST elevation วินิจฉัย STEMI ได้แล้ว.", "id": "set1-1"}, {"topic": "Cardiology", "q": "A patient with inferior STEMI (II, III, aVF) has BP 88/60. After sublingual nitroglycerin the BP drops markedly. What is the most likely mechanism?", "choices": ["Acute aortic dissection extension", "Right ventricular infarction", "Pericardial tamponade physiology", "Tension pneumothorax reducing preload", "Vasovagal reaction to the nitrate"], "ans": 1, "exp": "Inferior MI มักมี RV infarction ร่วม ซึ่ง preload-dependent การให้ nitrate จะลด preload ทำให้ BP ตก. รักษาด้วย IV fluid และหลีกเลี่ยง nitrate. ควรตรวจ right-sided lead (V4R).", "id": "set1-2"}, {"topic": "Cardiology", "q": "A 65-year-old woman with DM and HT has exertional dyspnea, orthopnea, leg edema, elevated JVP, bibasal crepitations, and S3. Echo shows EF 30%. Which drug does NOT reduce mortality in HFrEF?", "choices": ["ARNI (sacubitril/valsartan)", "Beta-blocker (e.g., carvedilol)", "Amlodipine (a dihydropyridine CCB)", "SGLT2 inhibitor (e.g., dapagliflozin)", "MRA (spironolactone/eplerenone)"], "ans": 2, "exp": "HFrEF ใช้ 4 เสาหลัก: ARNI/ACEI/ARB + beta-blocker + MRA + SGLT2i. Amlodipine (DHP-CCB) ไม่ลด mortality ใน HFrEF ใช้เฉพาะคุมความดัน/angina; non-DHP CCB (verapamil/diltiazem) เป็นข้อห้ามใน HFrEF.", "id": "set1-3"}, {"topic": "Cardiology", "q": "A 70-year-old man has palpitations and an irregularly irregular pulse. ECG shows absent P waves. CHA2DS2-VASc = 4. Which intervention most reduces his stroke risk?", "choices": ["Aspirin monotherapy alone", "Rate control with digoxin", "Immediate cardioversion without work-up", "Anticoagulation with a DOAC", "High-intensity statin therapy"], "ans": 3, "exp": "AF ที่ CHA2DS2-VASc ≥ 2 (ชาย) ควรได้ anticoagulant โดย DOAC เป็นตัวเลือกแรก (เหนือ warfarin ยกเว้น mechanical valve/moderate-severe MS). Aspirin ไม่พอ; cardioversion โดยไม่ประเมิน thrombus เสี่ยง embolic stroke.", "id": "set1-4"}, {"topic": "Cardiology", "q": "A patient with AF for more than 48 hours who has NOT been anticoagulated is scheduled for cardioversion. What is the most important risk?", "choices": ["Torsades de pointes arrhythmia", "Life-threatening hyperkalemia", "Malignant hyperthermia crisis", "Acute aortic dissection", "Embolic (thromboembolic) stroke"], "ans": 4, "exp": "AF > 48 ชม. อาจมี thrombus ใน left atrial appendage การ cardiovert อาจทำให้ลิ่มหลุดเกิด embolic stroke. ต้อง anticoagulate ≥ 3 สัปดาห์ก่อน หรือทำ TEE ตัด thrombus ก่อน แล้ว anticoagulate ต่อ ≥ 4 สัปดาห์.", "id": "set1-5"}, {"topic": "Cardiology", "q": "A patient develops polymorphic VT that twists around the baseline; ECG before the event showed a prolonged QT. What is the most appropriate immediate treatment?", "choices": ["IV magnesium sulfate", "IV amiodarone bolus", "IV digoxin loading", "IV verapamil push", "IV adenosine rapid push"], "ans": 0, "exp": "นี่คือ Torsades de pointes (polymorphic VT บน long QT). รักษาด้วย IV magnesium sulfate + แก้สาเหตุ QT ยาว (ยา, hypoK/Mg/Ca), overdrive pacing ถ้าจำเป็น. Amiodarone/ยาที่ยืด QT อาจทำให้แย่ลง.", "id": "set1-6"}, {"topic": "Cardiology", "q": "A 60-year-old man has predictable chest pain on exertion that resolves within 5 minutes of rest, with no dynamic troponin change. What is the most appropriate diagnosis and next step?", "choices": ["Unstable angina; give immediate fibrinolytic therapy", "Stable angina; exercise stress test or CT coronary angiography", "STEMI; activate the cath lab for primary PCI", "Acute pericarditis; treat with high-dose NSAIDs", "Aortic dissection; obtain urgent CT of the aorta"], "ans": 1, "exp": "อาการ predictable เจ็บเวลาออกแรงและหายเมื่อพัก = stable angina. ประเมินด้วย non-invasive test (exercise stress test/CTCA) และให้ ASA + statin + anti-anginal + คุมปัจจัยเสี่ยง.", "id": "set1-7"}, {"topic": "Cardiology", "q": "According to current guidelines, the LDL-C target for a very-high-risk patient after ACS is:", "choices": ["< 130 mg/dL with no time limit", "< 100 mg/dL as the sole target", "< 55 mg/dL and ≥ 50% reduction", "< 70 mg/dL without a reduction goal", "No specific LDL-C target needed"], "ans": 2, "exp": "แนวทางปัจจุบัน (ESC 2023 ACS / ACC-AHA 2025) เป้า LDL-C < 55 mg/dL และลดลง ≥ 50% จาก baseline. ถ้าไม่ถึงเป้าด้วย high-intensity statin เต็มขนาด เพิ่ม ezetimibe แล้ว PCSK9 inhibitor. (สไลด์เดิมมักระบุ < 70).", "id": "set1-8"}, {"topic": "Cardiology", "q": "A 55-year-old asymptomatic woman has office BP averaging 150/95 on two visits. What is the most appropriate step before confirming a diagnosis of hypertension?", "choices": ["Start two antihypertensive drugs immediately", "Refer directly for adrenalectomy surgery", "Give an empiric trial of a diuretic", "Confirm with home or ambulatory BP monitoring", "Diagnose a hypertensive emergency now"], "ans": 3, "exp": "ควรยืนยันด้วยการวัดนอกคลินิก (HBPM เฉลี่ย ≥135/85 หรือ ABPM) เพื่อตัด white-coat hypertension ก่อนวินิจฉัยและเริ่มยา (ยกเว้น BP สูงมาก/มี target organ damage).", "id": "set1-9"}, {"topic": "Cardiology", "q": "A 30-year-old man has hypertension resistant to three drugs and is found to have hypokalemia. Which screening test is most appropriate for a secondary cause?", "choices": ["24-hour urine free cortisol", "Renal artery Doppler ultrasound", "Plasma free metanephrines", "Serum TSH measurement", "Aldosterone-to-renin ratio"], "ans": 4, "exp": "HT + hypokalemia (โดยเฉพาะ resistant/อายุน้อย) นึกถึง primary aldosteronism (Conn) คัดกรองด้วย aldosterone-to-renin ratio ที่สูง. Pheochromocytoma (metanephrine) มี HT เป็นพักๆ + ปวดหัว/เหงื่อ/ใจสั่น.", "id": "set1-10"}, {"topic": "Cardiology", "q": "A 45-year-old man has BP 230/130 with severe headache, blurred vision, papilledema, and rising creatinine. What is the appropriate management?", "choices": ["Controlled IV BP reduction (~10–20% in the first hour)", "Oral antihypertensive then discharge home", "Normalize the BP within 15 minutes", "No acute BP reduction is needed", "Sublingual nifedipine to drop BP fast"], "ans": 0, "exp": "นี่คือ hypertensive emergency (encephalopathy + retinopathy + AKI) ต้องลด BP แบบควบคุมด้วยยา IV ~10–20% ใน 1 ชม.แรก (dissection ลดเร็วกว่า) เพื่อเลี่ยง hypoperfusion. Sublingual nifedipine เสี่ยง ischemia.", "id": "set1-11"}, {"topic": "Cardiology", "q": "ECG shows the PR interval progressively lengthening until a QRS is dropped, then the cycle repeats. What is the diagnosis?", "choices": ["First-degree AV block only", "Mobitz type I (Wenckebach)", "Mobitz type II AV block", "Complete (third-degree) heart block", "Atrial flutter with variable block"], "ans": 1, "exp": "PR ยาวขึ้นเรื่อยๆ จน drop beat = Mobitz I (Wenckebach) มักไม่รุนแรง ไม่ต้อง pacemaker ถ้าไม่มีอาการ. ต่างจาก Mobitz II (PR คงที่แล้ว drop ทันที) ที่เสี่ยงและต้อง pacemaker.", "id": "set1-12"}, {"topic": "Cardiology", "q": "A patient with complete (third-degree) AV block, heart rate 35, has recurrent presyncope. What is the definitive long-term treatment?", "choices": ["Atropine infusion indefinitely", "Oral beta-blocker therapy", "Permanent pacemaker implantation", "Digoxin for rate control", "Observation without intervention"], "ans": 2, "exp": "Complete heart block ที่มีอาการเสี่ยง asystole รักษาชั่วคราวด้วย atropine/transcutaneous pacing และรักษาถาวรด้วย permanent pacemaker. Beta-blocker/digoxin จะยิ่งกด conduction.", "id": "set1-13"}, {"topic": "Cardiology", "q": "A 68-year-old woman has exertional syncope, an ejection systolic murmur at the base radiating to the carotids, and pulsus parvus et tardus. What is the diagnosis?", "choices": ["Mitral regurgitation", "Mitral stenosis", "Aortic regurgitation", "Aortic stenosis", "Ventricular septal defect"], "ans": 3, "exp": "Ejection systolic murmur ร้าวคอ + pulsus parvus et tardus = aortic stenosis. Triad: angina/syncope/HF; symptomatic severe AS ควรทำ AVR/TAVI. Syncope เวลาออกแรงเป็นลักษณะเด่น.", "id": "set1-14"}, {"topic": "Cardiology", "q": "A patient has fever, a new murmur, splinter hemorrhages, and blood cultures growing Staphylococcus aureus. What is the diagnosis and the key confirmatory investigation?", "choices": ["Rheumatic fever; ASO antibody titer", "Acute pericarditis; ECG changes", "Acute myocarditis; cardiac MRI", "Pulmonary embolism; CT pulmonary angiogram", "Infective endocarditis; echocardiography"], "ans": 4, "exp": "ไข้ + murmur ใหม่ + peripheral emboli + positive blood culture เข้า Duke criteria ของ infective endocarditis. ทำ echocardiography หา vegetation และให้ IV antibiotics ตามเชื้อ 4–6 สัปดาห์.", "id": "set1-15"}, {"topic": "Cardiology", "q": "In a diabetic patient with albuminuria, which antihypertensive class is first-line?", "choices": ["ACE inhibitor or ARB", "Beta-blocker (e.g., atenolol)", "Alpha-blocker (e.g., doxazosin)", "Direct vasodilator hydralazine", "Loop diuretic (e.g., furosemide)"], "ans": 0, "exp": "เบาหวาน + albuminuria/CKD ควรใช้ ACEI หรือ ARB เป็นแนวหน้าเพราะลด proteinuria และชะลอไตเสื่อม. ห้ามใช้ ACEI ร่วม ARB. อาจเพิ่ม SGLT2i เพื่อป้องกันไต/หัวใจ.", "id": "set1-16"}, {"topic": "Cardiology", "q": "A patient with stable, narrow-complex regular SVT is hemodynamically stable. What is the first step?", "choices": ["Immediate synchronized cardioversion", "Vagal maneuver then adenosine", "Amiodarone infusion drip", "Unsynchronized defibrillation", "IV verapamil push immediately"], "ans": 1, "exp": "SVT ที่ stable เริ่มด้วย vagal maneuver (Valsalva/carotid massage) ถ้าไม่ได้ผลให้ adenosine IV push. ถ้า unstable จึงทำ synchronized cardioversion. Defibrillation ใช้กับ pulseless VT/VF.", "id": "set1-17"}, {"topic": "Cardiology", "q": "A CKD patient has ECG showing peaked T waves, prolonged PR, and widening QRS. Which drug should be given FIRST to protect the heart?", "choices": ["Insulin plus glucose infusion", "Nebulized salbutamol therapy", "IV calcium gluconate", "IV sodium bicarbonate", "Oral Kayexalate (resin)"], "ans": 2, "exp": "ECG เข้าได้กับ hyperkalemia รุนแรง. ลำดับแรกคือ IV calcium gluconate เพื่อ stabilize cardiac membrane (แม้ไม่ลดระดับ K). จากนั้นจึง shift K (insulin+glucose, beta-agonist) และกำจัด K (diuretic/resin/dialysis).", "id": "set1-18"}, {"topic": "Cardiology", "q": "Which murmur is characteristic of mitral stenosis?", "choices": ["Holosystolic murmur radiating to the axilla", "Ejection systolic radiating to the carotids", "Early diastolic at the left sternal border", "Mid-diastolic rumble with opening snap at the apex", "Continuous machinery murmur"], "ans": 3, "exp": "Mitral stenosis: mid-diastolic rumble ที่ apex + opening snap. สาเหตุหลัก rheumatic heart disease มักสัมพันธ์ AF และ hemoptysis. Holosystolic ร้าวรักแร้ = MR; early diastolic = AR.", "id": "set1-19"}, {"topic": "Cardiology", "q": "A patient in acute decompensated heart failure with pulmonary edema has BP 150/90. What is the appropriate initial management?", "choices": ["Give an IV beta-blocker bolus", "Give a rapid IV fluid bolus", "Start a calcium channel blocker", "Give immediate IV digoxin", "Sit upright, O2/NIV, IV loop diuretic ± nitrate"], "ans": 4, "exp": "Acute pulmonary edema: นั่งตัวตรง, O2/NIV, IV loop diuretic (furosemide) ลด preload, nitrate ถ้า BP พอ, หา precipitant. IV fluid และ beta-blocker bolus เป็นข้อห้ามในภาวะ decompensated.", "id": "set1-20"}, {"topic": "Cardiology", "q": "Which complication is the most common cause of sudden death in the first hour of an acute MI?", "choices": ["Ventricular arrhythmia (VT/VF)", "Ventricular free wall rupture", "Dressler (post-MI) syndrome", "Papillary muscle rupture", "Left ventricular aneurysm"], "ans": 0, "exp": "สาเหตุตายเฉียบพลันที่พบบ่อยสุดในช่วงแรกของ MI คือ ventricular arrhythmia (VT/VF). Free wall/papillary muscle rupture มักเกิดวันถัดมา; Dressler syndrome เกิดเป็นสัปดาห์-เดือนหลัง MI.", "id": "set1-21"}, {"topic": "Cardiology", "q": "How long should standard dual antiplatelet therapy (DAPT) be given after ACS in a patient not at high bleeding risk?", "choices": ["About 1 month only", "At least 12 months", "About 3 months only", "About 1 week only", "Not necessary at all"], "ans": 1, "exp": "DAPT (aspirin + P2Y12 inhibitor) มาตรฐานหลัง ACS คืออย่างน้อย 12 เดือนในผู้ที่ไม่เสี่ยงเลือดออกสูง. ถ้าเสี่ยงเลือดออกอาจสั้นลง; ถ้าเสี่ยง ischemic สูงอาจยาวขึ้น.", "id": "set1-22"}, {"topic": "Cardiology", "q": "Which ECG leads localize an inferior wall myocardial infarction?", "choices": ["Leads V1–V2", "Leads V3–V4", "Leads II, III, aVF", "Leads I and aVL", "Leads V5–V6"], "ans": 2, "exp": "Inferior wall MI แสดง ST changes ที่ II, III, aVF (มัก RCA). V1–V2 = septal, V3–V4 = anterior (LAD), I/aVL/V5–V6 = lateral (LCx).", "id": "set1-23"}, {"topic": "Cardiology", "q": "Which pulse finding is characteristic of chronic aortic regurgitation?", "choices": ["Pulsus parvus et tardus", "Pulsus paradoxus", "Pulsus alternans", "Water-hammer (Corrigan) pulse", "Bisferiens pulse only"], "ans": 3, "exp": "AR เรื้อรังมี wide pulse pressure ทำให้เกิด water-hammer (Corrigan) pulse + early diastolic murmur. Pulsus parvus et tardus = AS; pulsus paradoxus = tamponade.", "id": "set1-24"}, {"topic": "Cardiology", "q": "A patient with AF and rheumatic moderate-to-severe mitral stenosis needs anticoagulation. Which agent should be used?", "choices": ["DOAC such as apixaban", "Aspirin monotherapy", "Clopidogrel monotherapy", "No anticoagulation needed", "Warfarin (vitamin K antagonist)"], "ans": 4, "exp": "AF ที่มี moderate-severe mitral stenosis (rheumatic) หรือ mechanical valve ต้องใช้ warfarin เท่านั้น ไม่ใช้ DOAC เพราะ DOAC ด้อยกว่าและยังไม่รับรองในกลุ่มนี้.", "id": "set1-25"}, {"topic": "Cardiology", "q": "Under the 2024 ESC classification, the new category of 'Elevated BP' corresponds to which range?", "choices": ["120–139/70–89 mmHg", "Below 120/70 mmHg", "140–159/90–99 mmHg", "At least 160/100 mmHg", "At least 180/110 mmHg"], "ans": 0, "exp": "ESC 2024 เพิ่มหมวด Elevated BP = 120–139/70–89 (พิจารณาให้ยาตามความเสี่ยง CV); Non-elevated < 120/70; Hypertension ≥ 140/90. เป้าการรักษา default SBP 120–129 ถ้าทนได้.", "id": "set1-26"}, {"topic": "Cardiology", "q": "A patient with stable angina cannot take a beta-blocker due to severe asthma. Which anti-anginal is appropriate?", "choices": ["Digoxin for rate control", "A calcium channel blocker and/or long-acting nitrate", "Warfarin anticoagulation", "Furosemide diuresis", "Spironolactone therapy"], "ans": 1, "exp": "เมื่อ beta-blocker มีข้อห้าม ใช้ CCB (non-DHP diltiazem หรือ DHP amlodipine) และ/หรือ long-acting nitrate เป็น anti-anginal ร่วมกับ ASA + statin.", "id": "set1-27"}, {"topic": "Cardiology", "q": "A patient with chest pain has diffuse concave ST elevation with PR depression and an audible friction rub. What is the diagnosis?", "choices": ["Acute STEMI", "Aortic dissection", "Acute pericarditis", "Pulmonary embolism", "Benign early repolarization"], "ans": 2, "exp": "Diffuse concave ST elevation + PR depression + friction rub = acute pericarditis. รักษาด้วย NSAID + colchicine. ต่างจาก STEMI ที่ ST elevation จำกัด territory + reciprocal change.", "id": "set1-28"}, {"topic": "Cardiology", "q": "Which bedside test best confirms pericardial tamponade?", "choices": ["A 12-lead ECG", "Portable chest X-ray", "Serum troponin level", "Bedside echocardiography", "Serum BNP level"], "ans": 3, "exp": "Tamponade วินิจฉัยด้วย echocardiography (pericardial effusion + RA/RV diastolic collapse). อาการ Beck triad + pulsus paradoxus. รักษา pericardiocentesis.", "id": "set1-29"}, {"topic": "Cardiology", "q": "Which ECG feature characterizes Wolff-Parkinson-White syndrome?", "choices": ["Peaked (tented) T waves", "A prolonged QT interval", "An epsilon wave", "An Osborn (J) wave", "Delta wave with a short PR interval"], "ans": 4, "exp": "WPW มี accessory pathway → short PR + delta wave + wide QRS. ระวัง AF ใน WPW ห้ามใช้ AV nodal blocker (digoxin/verapamil/adenosine) เพราะอาจ conduct เร็วผ่าน accessory pathway.", "id": "set1-30"}, {"topic": "Cardiology", "q": "In a young athlete with hypertrophic cardiomyopathy, strenuous exercise most increases the risk of which event?", "choices": ["Sudden cardiac death", "Acute aortic dissection", "Acute pulmonary embolism", "Stroke from AF only", "Myxoma embolization"], "ans": 0, "exp": "HCM (โดยเฉพาะในนักกีฬาอายุน้อย) เป็นสาเหตุ sudden cardiac death ขณะออกกำลังหักโหม จาก outflow obstruction/arrhythmia. ควรจำกัดกิจกรรมหักโหมและประเมิน ICD ในผู้เสี่ยงสูง.", "id": "set1-31"}, {"topic": "Cardiology", "q": "Which agent, beyond its benefit in HFrEF, also reduces heart-failure hospitalization in HFpEF based on recent evidence?", "choices": ["Digoxin therapy", "An SGLT2 inhibitor", "Ivabradine therapy", "Hydralazine therapy", "Amlodipine therapy"], "ans": 1, "exp": "SGLT2 inhibitor (dapagliflozin/empagliflozin) ลด HF hospitalization ทั้งใน HFrEF และ HFpEF จึงเป็นเสาหลักที่ใช้ได้กว้าง. Ivabradine/hydralazine ใช้เฉพาะ HFrEF บางกลุ่ม.", "id": "set1-32"}, {"topic": "Cardiology", "q": "A 50-year-old man develops sudden dyspnea after major surgery, with a swollen left leg. ECG shows sinus tachycardia and an S1Q3T3 pattern. What should be suspected first?", "choices": ["Acute myocardial infarction", "Acute pericarditis", "Acute pulmonary embolism", "Acute aortic dissection", "Spontaneous pneumothorax"], "ans": 2, "exp": "หลังผ่าตัด + ขาบวมข้างเดียว + เหนื่อยเฉียบพลัน + S1Q3T3/RV strain ชี้ pulmonary embolism (VTE). ยืนยันด้วย CTPA; รักษา anticoagulation, massive PE + shock พิจารณา thrombolysis.", "id": "set1-33"}, {"topic": "Cardiology", "q": "What is the immediate treatment of pulseless ventricular tachycardia or ventricular fibrillation?", "choices": ["Synchronized cardioversion", "IV adenosine push", "IV magnesium sulfate only", "Immediate defibrillation with CPR", "A vagal maneuver"], "ans": 3, "exp": "Pulseless VT/VF เป็น cardiac arrest ต้อง defibrillation (unsynchronized) ทันที + CPR คุณภาพสูง + epinephrine ตาม ACLS. Synchronized cardioversion ใช้กับ tachyarrhythmia ที่ยังมีชีพจรแต่ unstable.", "id": "set1-34"}, {"topic": "Cardiology", "q": "Three weeks after an MI, a patient develops low-grade fever, pleuritic chest pain, a friction rub, and a pericardial effusion. What is the diagnosis?", "choices": ["Reinfarction of the myocardium", "Infective endocarditis", "Acute pulmonary embolism", "Acute viral myocarditis", "Dressler syndrome (post-MI pericarditis)"], "ans": 4, "exp": "Dressler syndrome = post-MI autoimmune pericarditis เกิดหลายสัปดาห์หลัง MI. รักษาด้วย NSAID/colchicine (หลีกเลี่ยง steroid ระยะแรกหลัง MI).", "id": "set1-35"}, {"topic": "Cardiology", "q": "A patient with symptomatic bradycardia (HR 38, BP 80/50) does not respond to atropine. What is the next step?", "choices": ["Transcutaneous pacing (± dopamine/epinephrine)", "IV beta-blocker therapy", "IV adenosine push", "IV digoxin loading", "IV verapamil push"], "ans": 0, "exp": "Symptomatic bradycardia ที่ไม่ตอบสนอง atropine ให้ transcutaneous pacing และ/หรือ chronotropic infusion (dopamine/epinephrine) แล้วเตรียม pacemaker. ยา AV nodal blocker เป็นข้อห้าม.", "id": "set1-36"}, {"topic": "Cardiology", "q": "In a diabetic patient screened for lipids, what is the first-line drug class to reduce ASCVD risk?", "choices": ["Fibrate as the primary agent", "Statin according to risk level", "Omega-3 fatty acids alone", "Niacin as the main therapy", "No lipid-lowering drug needed"], "ans": 1, "exp": "ยาแนวหน้าลด ASCVD คือ statin ตามระดับความเสี่ยง (high-intensity ในผู้เสี่ยงสูง/มี ASCVD). Fibrate ใช้เมื่อ TG สูงมากเพื่อลด pancreatitis. เป้า LDL ต่ำลงตามความเสี่ยง.", "id": "set1-37"}, {"topic": "Cardiology", "q": "Which adverse effect of NSAIDs is most concerning in a patient with heart failure?", "choices": ["Marked hypokalemia and arrhythmia", "Drug-induced hyperthyroidism", "Fluid retention worsening HF and reduced diuretic effect", "Symptomatic bradycardia", "QT-interval prolongation"], "ans": 2, "exp": "NSAID ทำให้ Na/น้ำคั่ง ลดประสิทธิภาพ diuretic และ ACEI/ARB ทำให้ HF กำเริบและเสี่ยง AKI จึงควรหลีกเลี่ยงใน HF/CKD.", "id": "set1-38"}, {"topic": "Cardiology", "q": "Which auscultatory finding is characteristic of mitral valve prolapse?", "choices": ["Opening snap after S2", "Continuous machinery murmur", "Early diastolic decrescendo murmur", "Mid-systolic click and late systolic murmur", "Fixed splitting of S2"], "ans": 3, "exp": "MVP มี mid-systolic click ตามด้วย late systolic murmur; ท่าที่ลด preload (standing/Valsalva) ทำให้ click มาเร็วขึ้น. MVP เป็นสาเหตุ chronic MR ที่พบบ่อย.", "id": "set1-39"}, {"topic": "Cardiology", "q": "After successful fibrinolysis for STEMI, what should be done next?", "choices": ["Observation without further action", "Start long-term warfarin immediately", "Stop all antiplatelet therapy", "Give a calcium channel blocker", "Refer for coronary angiography ± PCI"], "ans": 4, "exp": "หลัง fibrinolytic ควรส่งต่อทำ coronary angiography ± PCI (routine early หรือ rescue PCI ถ้า reperfusion ล้มเหลว) ตาม pharmaco-invasive strategy. ยังคง DAPT + anticoagulant ตามข้อบ่งชี้.", "id": "set1-40"}, {"topic": "Cardiology", "q": "A woman at 30 weeks gestation has BP 160/110 with proteinuria and headache. What is the diagnosis and appropriate drug?", "choices": ["Preeclampsia; labetalol/hydralazine/nifedipine", "Chronic hypertension; an ACE inhibitor", "Gestational hypertension; atenolol", "Pheochromocytoma; phenoxybenzamine", "White-coat hypertension; no drug"], "ans": 0, "exp": "BP สูง + proteinuria หลัง 20 สัปดาห์ = preeclampsia. ยาปลอดภัย: labetalol, hydralazine, nifedipine + MgSO4 ป้องกัน/รักษา eclampsia. ACEI/ARB เป็นข้อห้ามในการตั้งครรภ์.", "id": "set1-41"}, {"topic": "Cardiology", "q": "Which drug reduces mortality in HFrEF via neprilysin inhibition combined with an ARB?", "choices": ["Ivabradine therapy", "Sacubitril/valsartan (ARNI)", "Digoxin therapy", "Amlodipine therapy", "Hydrochlorothiazide therapy"], "ans": 1, "exp": "Sacubitril/valsartan (ARNI) ยับยั้ง neprilysin + block AT1 receptor ลด mortality เหนือ ACEI ใน HFrEF. ห้ามใช้ร่วม/ใกล้ ACEI (เสี่ยง angioedema) ต้องเว้น 36 ชม.", "id": "set1-42"}, {"topic": "Cardiology", "q": "ECG shows a wide QRS with an rSR' pattern in V1 and a slurred S wave in leads I and V6. What is it?", "choices": ["Left bundle branch block", "Left ventricular hypertrophy", "Right bundle branch block", "Wolff-Parkinson-White pattern", "Hyperkalemia changes"], "ans": 2, "exp": "rSR' (rabbit ear) ที่ V1 + wide QRS + slurred S ที่ lateral leads = RBBB. LBBB จะมี broad monophasic R ที่ I/V6 และอาจ mask MI.", "id": "set1-43"}, {"topic": "Cardiology", "q": "In symptomatic severe aortic stenosis, which intervention improves survival?", "choices": ["Vasodilator therapy", "Beta-blocker therapy", "Balloon valvuloplasty as permanent therapy", "Aortic valve replacement (SAVR/TAVI)", "Diuretic therapy alone"], "ans": 3, "exp": "Symptomatic severe AS มี prognosis แย่หากไม่ผ่าตัด การรักษาที่ปรับ prognosis คือ aortic valve replacement (surgical/TAVI). Vasodilator ต้องระวังเพราะ preload/afterload sensitive.", "id": "set1-44"}, {"topic": "Cardiology", "q": "Which antihypertensive class should be avoided in a patient with gout?", "choices": ["ACE inhibitor therapy", "ARB therapy", "Calcium channel blocker", "An ARB plus a CCB", "High-dose thiazide diuretic"], "ans": 4, "exp": "Thiazide เพิ่มกรดยูริกและกระตุ้น gout จึงควรหลีกเลี่ยง. ทางเลือกที่ดีกว่าเช่น CCB/ACEI/ARB (losartan มีฤทธิ์ลด uric เล็กน้อย).", "id": "set1-45"}, {"topic": "Cardiology", "q": "Using the rapid '300 rule', if the R-R interval spans 4 large boxes, the heart rate is approximately:", "choices": ["About 75 /min", "About 150 /min", "About 100 /min", "About 60 /min", "About 50 /min"], "ans": 0, "exp": "300 หารด้วยจำนวนช่องใหญ่ระหว่าง R-R: 300/4 = 75 ครั้ง/นาที (1 ช่อง=300, 2=150, 3=100, 4=75, 5=60, 6=50).", "id": "set1-46"}, {"topic": "Cardiology", "q": "Which is first-line rate control for AF in a patient with normal EF and no heart failure?", "choices": ["Digoxin monotherapy", "Beta-blocker or non-DHP calcium channel blocker", "Amiodarone infusion", "IV adenosine push", "Ivabradine therapy"], "ans": 1, "exp": "Rate control ใน AF ที่ EF ปกติ เริ่มด้วย beta-blocker หรือ non-DHP CCB (diltiazem/verapamil). Digoxin ใช้เสริมเมื่อมี HF/ความดันต่ำ. ใน HFrEF ห้าม non-DHP CCB.", "id": "set1-47"}, {"topic": "Cardiology", "q": "A 55-year-old man with prior MI has LDL-C 60 mg/dL on maximally tolerated statin. His residual risk is high. What is the reasonable next step to lower LDL further?", "choices": ["Stop the statin entirely", "Switch the statin to a fibrate", "Add ezetimibe ± PCSK9 inhibitor", "Add niacin to the statin", "No change is needed"], "ans": 2, "exp": "เป้า LDL หลัง ACS < 55; ที่ 60 ยังไม่ถึงเป้า ควรเพิ่ม ezetimibe และ/หรือ PCSK9 inhibitor ตามแนวทาง 2025 ACS lipid. Fibrate/niacin ไม่ใช่ตัวเลือกหลักลด LDL.", "id": "set1-48"}, {"topic": "Cardiology", "q": "A patient with new AF is planned for rhythm control. According to the 2023 AF guideline, in which group is early rhythm control/catheter ablation particularly favored as first-line?", "choices": ["Asymptomatic elderly with permanent AF", "AF with a mechanical valve only", "Isolated first episode that self-resolved", "Symptomatic AF, especially with HFrEF", "AF with active major bleeding"], "ans": 3, "exp": "2023 ACC/AHA/ACCP/HRS เน้น early rhythm control และ catheter ablation เป็น first-line ในบางกลุ่ม เช่น symptomatic AF และผู้ป่วย HFrEF (ablation ลด mortality/HF hospitalization). และเน้น modify ปัจจัยเสี่ยง.", "id": "set1-49"}, {"topic": "Cardiology", "q": "A 65-year-old man has sudden severe 'tearing' chest pain radiating to the back, BP 180/100 in the right arm but 140/80 in the left arm, and a widened mediastinum on CXR. What is the most likely diagnosis?", "choices": ["Acute myocardial infarction", "Acute pulmonary embolism", "Acute pericarditis", "Spontaneous pneumothorax", "Acute aortic dissection"], "ans": 4, "exp": "เจ็บอกแบบ tearing ร้าวหลัง + ความดันสองแขนต่างกัน + mediastinum กว้าง = aortic dissection. Type A (ascending) ต้องผ่าตัดฉุกเฉิน; Type B คุมด้วยยา (beta-blocker ลด HR/BP ก่อน). ยืนยันด้วย CT angiography.", "id": "set1-50"}, {"topic": "Pulmonology", "q": "A 25-year-old with episodic wheeze and nocturnal cough has spirometry showing an obstructive pattern that improves after a bronchodilator (FEV1 rises 15% and 300 mL). What is the diagnosis?", "choices": ["Bronchial asthma", "COPD", "Bronchiectasis", "Interstitial lung disease", "Vocal cord dysfunction"], "ans": 0, "exp": "Reversible airflow obstruction (FEV1 เพิ่ม ≥12% และ ≥200 mL หลัง bronchodilator) + อาการเป็นๆ หายๆ = asthma. ต่างจาก COPD ที่ obstruction ไม่ reversible เต็มที่.", "id": "set1-51"}, {"topic": "Pulmonology", "q": "According to GINA 2025, what is the preferred reliever/controller strategy even in mild asthma?", "choices": ["SABA alone as needed", "ICS-formoterol as reliever (and maintenance)", "Oral steroid as needed", "LABA alone as needed", "Theophylline as needed"], "ans": 1, "exp": "GINA 2025 ห้ามใช้ SABA เดี่ยว; ทุกคนต้องได้ ICS-containing reliever โดยแนะนำ ICS-formoterol เป็นทั้ง reliever และ maintenance (AIR/MART) เพราะลดการกำเริบรุนแรงและการเสียชีวิต.", "id": "set1-52"}, {"topic": "Pulmonology", "q": "A patient with acute severe asthma is tiring; ABG shows a 'normal' PaCO2. How should this be interpreted?", "choices": ["Reassuring, patient improving", "Compensated metabolic alkalosis", "Impending respiratory failure", "A normal, expected finding", "Chronic compensation only"], "ans": 2, "exp": "ในหอบรุนแรง ผู้ป่วยควร hyperventilate ทำให้ PaCO2 ต่ำ. PaCO2 ที่ 'ปกติ' หรือสูงขึ้นบ่งชี้กล้ามเนื้อหายใจล้า = impending respiratory failure ต้องเฝ้าใกล้ชิด/เตรียมช่วยหายใจ.", "id": "set1-53"}, {"topic": "Pulmonology", "q": "A 65-year-old smoker has chronic productive cough and dyspnea; post-bronchodilator FEV1/FVC is 0.60. What is the single most effective intervention to slow disease progression?", "choices": ["Inhaled corticosteroid", "Oral theophylline", "Long-term antibiotics", "Smoking cessation", "Mucolytic agents"], "ans": 3, "exp": "COPD (FEV1/FVC < 0.70 post-BD). การหยุดบุหรี่เป็นสิ่งเดียวที่ชะลอการเสื่อมของ lung function และลด mortality ได้ชัดเจนที่สุด. ยาสูดช่วยอาการ/ลด exacerbation แต่ไม่ชะลอ decline เท่า.", "id": "set1-54"}, {"topic": "Pulmonology", "q": "Under GOLD 2025, a COPD patient in Group B or Group E should be started on which initial inhaled therapy?", "choices": ["SABA as needed only", "ICS monotherapy", "Oral corticosteroid", "Theophylline therapy", "LABA + LAMA combination"], "ans": 4, "exp": "GOLD 2025 แนะนำเริ่ม LABA + LAMA (คู่) ในทั้ง Group B และ Group E. Group A ใช้ bronchodilator เดี่ยว. เพิ่ม ICS (triple) เมื่อ eosinophil > 300 หรือ Group E ที่ eos สูง.", "id": "set1-55"}, {"topic": "Pulmonology", "q": "A COPD patient presents with increased dyspnea, sputum volume, and purulence. Besides bronchodilators and systemic steroids, what else is indicated?", "choices": ["Add antibiotics", "Immediate intubation", "IV magnesium sulfate", "Diuretic therapy", "Long-term home oxygen"], "ans": 0, "exp": "AECOPD ที่มี cardinal symptoms ครบ (เหนื่อยเพิ่ม + เสมหะเพิ่ม + เสมหะเป็นหนอง) หรือเสมหะเป็นหนอง+อีก 1 ข้อ หรือต้องใช้ ventilator → ให้ antibiotics ร่วมกับ SABA±SAMA และ systemic corticosteroid 5 วัน.", "id": "set1-56"}, {"topic": "Pulmonology", "q": "A COPD patient in exacerbation has pH 7.28, PaCO2 68. What is the most appropriate respiratory support?", "choices": ["High-flow O2 to reach SpO2 100%", "Non-invasive ventilation (BiPAP)", "Immediate tracheostomy", "Nasal cannula oxygen only", "Sedation and observation"], "ans": 1, "exp": "Hypercapnic respiratory acidosis (pH < 7.35, PaCO2 สูง) ใน AECOPD ตอบสนองดีต่อ NIV (BiPAP) ซึ่งลดการใส่ท่อและ mortality. ให้ O2 แบบควบคุม (เป้า SpO2 88–92%) ไม่ใช่ให้จนถึง 100%.", "id": "set1-57"}, {"topic": "Pulmonology", "q": "A previously healthy adult with CAP has CURB-65 = 0 and no comorbidities. What is appropriate first-line outpatient therapy?", "choices": ["IV ceftriaxone plus azithromycin", "IV respiratory fluoroquinolone", "High-dose amoxicillin (or a macrolide/doxycycline)", "IV vancomycin therapy", "No antibiotic needed"], "ans": 2, "exp": "CAP ที่ CURB-65 ต่ำและไม่มีโรคร่วม รักษาแบบผู้ป่วยนอกด้วย amoxicillin ขนาดสูง หรือ macrolide/doxycycline. ผู้มีโรคร่วมใช้ β-lactam + macrolide หรือ respiratory FQ; admit ใช้ ceftriaxone + azithromycin.", "id": "set1-58"}, {"topic": "Pulmonology", "q": "A 32-year-old man with HIV (CD4 120) has 3 weeks of exertional dyspnea, dry cough, SpO2 88%, and bilateral perihilar interstitial infiltrates. Which test best confirms the diagnosis?", "choices": ["Sputum AFB smear and culture", "PCR of sputum for Mycoplasma", "Blood culture for pneumococcus", "Immunofluorescence of induced sputum for Pneumocystis jirovecii", "Urine antigen for Legionella"], "ans": 3, "exp": "ภาพเข้าได้กับ PCP (Pneumocystis jirovecii) ใน HIV ที่ CD4 < 200. ยืนยันด้วย immunofluorescence/stain ของ induced sputum หรือ BAL. รักษาด้วย high-dose co-trimoxazole + steroid ถ้า PaO2 ต่ำ/A-a gradient กว้าง. (แนวข้อสอบ NLE2)", "id": "set1-59"}, {"topic": "Pulmonology", "q": "A 50-year-old with 2 weeks of productive cough, hemoptysis, night sweats, and a right-upper-lobe cavity on CXR most likely has:", "choices": ["Community-acquired pneumonia", "Aspiration lung abscess", "Acute pulmonary embolism", "Pulmonary sarcoidosis", "Pulmonary tuberculosis"], "ans": 4, "exp": "ไอเรื้อรัง + ไอเป็นเลือด + เหงื่อกลางคืน + upper-lobe cavity เข้าได้กับ pulmonary TB. ยืนยันด้วย sputum AFB/Xpert MTB/RIF (บอกดื้อ rifampicin) + culture.", "id": "set1-60"}, {"topic": "Pulmonology", "q": "According to WHO 2022, which regimen is now an option for drug-susceptible pulmonary TB?", "choices": ["A 4-month rifapentine–moxifloxacin regimen", "A 24-month injectable regimen", "Isoniazid monotherapy", "Rifampicin alone for 2 months", "The BPaL regimen for all cases"], "ans": 0, "exp": "WHO 2022 มีสูตร 4 เดือนสำหรับ DS-TB (2 เดือน HPZM + 2 เดือน HPM, rifapentine+moxifloxacin) เป็นทางเลือกนอกเหนือสูตร 6 เดือน 2HRZE/4HR. BPaL/BPaLM ใช้กับ DR-TB.", "id": "set1-61"}, {"topic": "Pulmonology", "q": "Which anti-TB drug most classically causes optic neuritis (reduced visual acuity and color vision)?", "choices": ["Isoniazid", "Ethambutol", "Rifampicin", "Pyrazinamide", "Streptomycin"], "ans": 1, "exp": "Ethambutol ทำให้เกิด optic neuritis (visual acuity/color vision ลด). INH → peripheral neuropathy (ให้ pyridoxine); Rifampicin → orange secretions; PZA → hyperuricemia; ทั้งกลุ่มเสี่ยง hepatitis.", "id": "set1-62"}, {"topic": "Pulmonology", "q": "A pleural effusion has pleural/serum protein ratio 0.7 and pleural/serum LDH ratio 0.8. How is it classified and what does it suggest?", "choices": ["Transudate; from heart failure", "Transudate; from cirrhosis", "Exudate; infection/malignancy/TB", "Chylothorax from lymphatics", "Hemothorax from bleeding"], "ans": 2, "exp": "เข้าเกณฑ์ Light's criteria เป็น exudate (protein ratio > 0.5 หรือ LDH ratio > 0.6). สาเหตุ exudate = infection (parapneumonic/empyema), malignancy, TB. Transudate = HF, cirrhosis, nephrotic.", "id": "set1-63"}, {"topic": "Pulmonology", "q": "A parapneumonic effusion has pH 7.10, low glucose, and frank pus. What is the appropriate management?", "choices": ["Antibiotics alone without drainage", "Observation without drainage", "Diuretic therapy", "Chest tube drainage plus antibiotics", "Repeat tap in 1 week"], "ans": 3, "exp": "Complicated parapneumonic effusion/empyema (pH < 7.2, glucose ต่ำ, หนอง) ต้องระบายด้วย chest tube (ICD) ร่วมกับ antibiotics; อาจต้อง fibrinolytic/VATS ถ้า loculated.", "id": "set1-64"}, {"topic": "Pulmonology", "q": "A tall thin young man has sudden pleuritic chest pain and dyspnea; exam shows hyperresonance and absent breath sounds on one side with tracheal deviation and hypotension. What is the immediate action?", "choices": ["Obtain a chest X-ray first", "Obtain a CT of the chest first", "Observation with oxygen only", "Endotracheal intubation only", "Needle/finger decompression then chest tube"], "ans": 4, "exp": "อาการเข้ากับ tension pneumothorax (hypotension + tracheal deviation) เป็นการวินิจฉัยทางคลินิก อย่ารอ CXR ต้อง decompress ทันที (needle/finger) แล้วใส่ ICD.", "id": "set1-65"}, {"topic": "Pulmonology", "q": "Which describes type 2 (hypercapnic) respiratory failure?", "choices": ["PaCO2 > 45 with respiratory acidosis", "PaO2 < 60 with normal/low PaCO2", "A completely normal ABG", "Metabolic acidosis only", "Isolated hypoxemia from shunt"], "ans": 0, "exp": "Type 2 respiratory failure = hypoventilation → PaCO2 > 45 + respiratory acidosis (COPD, neuromuscular, CNS depression). Type 1 = hypoxemic (PaO2 < 60, PaCO2 ปกติ/ต่ำ) จาก V/Q mismatch/shunt.", "id": "set1-66"}, {"topic": "Pulmonology", "q": "ABG: pH 7.30, HCO3 14, PaCO2 30, Na 140, Cl 100. What is the primary disorder?", "choices": ["Primary respiratory acidosis", "High anion gap metabolic acidosis", "Primary metabolic alkalosis", "Primary respiratory alkalosis", "A normal acid-base state"], "ans": 1, "exp": "pH ต่ำ + HCO3 ต่ำ = metabolic acidosis; anion gap = 140 − 100 − 14 = 26 (สูง) → high anion gap metabolic acidosis. PaCO2 30 = respiratory compensation (Winter: 1.5×14+8=29 ≈ เหมาะสม). สาเหตุ MUDPILES.", "id": "set1-67"}, {"topic": "Pulmonology", "q": "Which condition causes a NORMAL anion gap (hyperchloremic) metabolic acidosis?", "choices": ["Diabetic ketoacidosis", "Lactic acidosis", "Severe diarrhea", "Methanol poisoning", "Uremia from renal failure"], "ans": 2, "exp": "Severe diarrhea เสีย HCO3 ทาง GI ทำให้ normal anion gap (hyperchloremic) metabolic acidosis. DKA, lactic acidosis, methanol, uremia ล้วนเป็น high anion gap (MUDPILES).", "id": "set1-68"}, {"topic": "Pulmonology", "q": "A patient with sepsis-related ARDS has bilateral infiltrates and PaO2/FiO2 = 150 with no cardiac cause. Which ventilator strategy is recommended?", "choices": ["High tidal volume around 12 mL/kg", "High FiO2 with high PEEP only", "A permissive hyperoxia strategy", "Lung-protective ventilation (Vt ~6 mL/kg, plateau < 30) + consider prone", "Ventilation while avoiding PEEP"], "ans": 3, "exp": "ARDS ใช้ lung-protective ventilation (Vt 6 mL/kg predicted BW, plateau pressure < 30) + prone positioning ในราย moderate-severe + จัดการสาเหตุ. High tidal volume เพิ่ม ventilator-induced lung injury.", "id": "set1-69"}, {"topic": "Pulmonology", "q": "A post-operative patient develops sudden dyspnea and pleuritic chest pain; Wells score is high. What is the best confirmatory test?", "choices": ["Serum D-dimer assay", "Plain chest X-ray", "Bedside echocardiography", "Sputum culture", "CT pulmonary angiography"], "ans": 4, "exp": "เมื่อ pretest probability สูง (Wells สูง) ควรทำ CT pulmonary angiography (gold standard) เลย ไม่ใช้ D-dimer (มีประโยชน์เฉพาะ low/intermediate เพื่อ rule out). V/Q scan ใช้เมื่อทำ CT ไม่ได้.", "id": "set1-70"}, {"topic": "Pulmonology", "q": "A hemodynamically unstable patient with massive PE and shock should receive:", "choices": ["Systemic thrombolysis (or embolectomy)", "Anticoagulation with a DOAC only", "IVC filter placement alone", "Aspirin monotherapy", "Observation without treatment"], "ans": 0, "exp": "Massive PE (hypotension/shock) มี indication สำหรับ systemic thrombolysis (หรือ catheter/surgical embolectomy ถ้ามีข้อห้าม) นอกเหนือจาก anticoagulation. Submassive/stable ใช้ anticoagulation เป็นหลัก.", "id": "set1-71"}, {"topic": "Pulmonology", "q": "A 55-year-old heavy smoker has a spiculated 2 cm lung nodule that grew compared to a prior film. What is the most appropriate next step?", "choices": ["Repeat the chest X-ray in 1 year", "Tissue diagnosis (biopsy) ± PET/CT staging", "Reassure with no further follow-up", "Start empiric antibiotics", "Start empiric anti-TB drugs"], "ans": 1, "exp": "Nodule ที่ spiculated, โตขึ้น, ในผู้สูบจัด = เสี่ยงมะเร็งสูง ควร characterize ด้วย CT/PET และ tissue diagnosis (biopsy) เพื่อวินิจฉัยและ staging. การรอเฉยเหมาะกับ nodule เสี่ยงต่ำเท่านั้น.", "id": "set1-72"}, {"topic": "Pulmonology", "q": "Which lung cancer is most strongly associated with SIADH and Cushing (ectopic ACTH) paraneoplastic syndromes?", "choices": ["Pulmonary adenocarcinoma", "Squamous cell carcinoma", "Small cell lung cancer", "Large cell carcinoma", "Pulmonary carcinoid tumor"], "ans": 2, "exp": "Small cell lung cancer (SCLC) สัมพันธ์ paraneoplastic ที่เป็น neuroendocrine เช่น SIADH และ ectopic ACTH (Cushing), Lambert-Eaton. Squamous cell → hypercalcemia (PTHrP).", "id": "set1-73"}, {"topic": "Pulmonology", "q": "A squamous cell lung cancer patient presents with confusion, constipation, and a calcium of 13 mg/dL. What is the mechanism?", "choices": ["SIADH-mediated effect", "Ectopic ACTH secretion", "Bone metastasis alone", "PTHrP secretion (humoral hypercalcemia)", "Primary hypoparathyroidism"], "ans": 3, "exp": "Squamous cell carcinoma หลั่ง PTHrP ทำให้เกิด humoral hypercalcemia of malignancy (hyperCa → stones/bones/groans/moans). รักษา IV fluid + bisphosphonate/calcitonin + รักษามะเร็ง.", "id": "set1-74"}, {"topic": "Pulmonology", "q": "Which oxygen delivery device most precisely controls FiO2, useful in COPD patients at risk of CO2 retention?", "choices": ["Simple nasal cannula", "Simple face mask", "Non-rebreather mask", "Bag-valve mask", "Venturi (air-entrainment) mask"], "ans": 4, "exp": "Venturi mask ให้ FiO2 ที่แม่นยำ (24–60%) จึงเหมาะกับ COPD ที่ต้องคุม O2 (เป้า SpO2 88–92%) เพื่อเลี่ยง CO2 retention. Non-rebreather ให้ FiO2 สูงแต่ควบคุมไม่แม่น.", "id": "set1-75"}, {"topic": "Pulmonology", "q": "A patient with stable COPD has resting PaO2 54 mmHg (SpO2 87%). Which intervention improves survival?", "choices": ["Long-term oxygen therapy (>15 h/day)", "Inhaled corticosteroid", "Oral theophylline", "Prophylactic antibiotics", "Mucolytic agents"], "ans": 0, "exp": "Long-term oxygen therapy (LTOT) ในผู้ป่วย COPD ที่ PaO2 ≤ 55 หรือ SpO2 ≤ 88% (หรือ ≤ 59/89% ที่มี cor pulmonale/polycythemia) ช่วยเพิ่มอัตราการรอดชีวิตเมื่อใช้ > 15 ชม./วัน.", "id": "set1-76"}, {"topic": "Pulmonology", "q": "A young non-smoker with recurrent pneumonia, chronic cough with copious purulent sputum, and 'tram-track' opacities most likely has:", "choices": ["Bronchial asthma", "Bronchiectasis", "Simple chronic bronchitis", "Pulmonary fibrosis", "Pulmonary sarcoidosis"], "ans": 1, "exp": "อาการไอเสมหะมากเรื้อรัง + ปอดอักเสบซ้ำ + tram-track/ring shadow เข้าได้กับ bronchiectasis (ยืนยันด้วย HRCT). หาสาเหตุ (post-infection, CF, immunodeficiency) + airway clearance + ATB เวลากำเริบ.", "id": "set1-77"}, {"topic": "Pulmonology", "q": "Which finding on examination suggests consolidation (e.g., lobar pneumonia)?", "choices": ["Hyperresonance with absent breath sounds", "Tracheal deviation to the opposite side", "Bronchial breath sounds, increased vocal fremitus, egophony", "Isolated expiratory wheeze", "A pleural friction rub only"], "ans": 2, "exp": "Consolidation ทำให้เสียงส่งผ่านดีขึ้น: bronchial breath sound, increased tactile/vocal fremitus, egophony (E→A), dullness to percussion. Hyperresonance + absent breath sound = pneumothorax.", "id": "set1-78"}, {"topic": "Pulmonology", "q": "A patient has an exudative lymphocyte-predominant pleural effusion with high adenosine deaminase (ADA). What is the most likely cause in an endemic area?", "choices": ["Heart failure effusion", "Rheumatoid pleural effusion", "Chylothorax", "Tuberculous pleuritis", "Empyema (frank pus)"], "ans": 3, "exp": "Exudate ที่ lymphocyte เด่น + ADA สูง ในพื้นที่ระบาด เข้าได้กับ tuberculous pleuritis. ยืนยันด้วย pleural biopsy (granuloma)/culture; ตอบสนองดีต่อ anti-TB.", "id": "set1-79"}, {"topic": "Pulmonology", "q": "What is the classic ECG finding sometimes seen in acute pulmonary embolism (though sinus tachycardia is most common)?", "choices": ["A delta wave", "Peaked T waves", "Prominent U waves", "An Osborn wave", "An S1Q3T3 pattern"], "ans": 4, "exp": "S1Q3T3 (S ใน I, Q และ T inversion ใน III) เป็น classic แต่พบไม่บ่อยใน PE; สิ่งที่พบบ่อยสุดคือ sinus tachycardia. อาจเห็น RV strain (T inversion V1–V4).", "id": "set1-80"}, {"topic": "Pulmonology", "q": "A patient on long-term home oxygen for COPD suddenly becomes drowsy after oxygen was turned up to high flow. What happened?", "choices": ["CO2 retention/hypercapnia worsened by uncontrolled high-flow O2", "An oxygen-toxicity seizure", "Acute hypoglycemia", "Acute pulmonary embolism", "Spontaneous pneumothorax"], "ans": 0, "exp": "ในบาง COPD ที่เป็น chronic CO2 retainer การให้ O2 สูงเกินไปอาจทำให้ CO2 คั่งมากขึ้น (ลด hypoxic drive + V/Q + Haldane effect) → ซึม. ควรให้ O2 แบบควบคุมเป้า SpO2 88–92% และตรวจ ABG.", "id": "set1-81"}, {"topic": "Pulmonology", "q": "Which is the initial diagnostic test of choice to confirm airflow obstruction in suspected COPD?", "choices": ["High-resolution chest CT", "Spirometry (post-bronchodilator FEV1/FVC)", "Peak flow measurement only", "Arterial blood gas", "Serum D-dimer"], "ans": 1, "exp": "COPD ยืนยันด้วย spirometry ที่ post-bronchodilator FEV1/FVC < 0.70. CXR/CT ช่วยดู complication/ตัดสาเหตุอื่น แต่ไม่ใช้วินิจฉัยหลัก.", "id": "set1-82"}, {"topic": "Pulmonology", "q": "A patient with asthma has frequent night symptoms despite low-dose ICS-formoterol maintenance. According to GINA, what is the appropriate step-up?", "choices": ["Add a SABA reliever only", "Stop the inhaled corticosteroid", "Increase to medium-dose ICS-formoterol", "Long-term oral corticosteroid", "Add empiric antibiotics"], "ans": 2, "exp": "เมื่อคุมไม่ได้ด้วย low-dose ICS-formoterol maintenance (step 3) ให้ step up เป็น medium-dose ICS-formoterol (step 4) ก่อนพิจารณา LAMA/biologic (step 5). ตรวจ adherence/inhaler technique/trigger ก่อนเสมอ.", "id": "set1-83"}, {"topic": "Pulmonology", "q": "A patient develops an anaphylactic reaction with wheeze, hypotension, and angioedema after a bee sting. What is the first-line drug?", "choices": ["IV hydrocortisone", "IV antihistamine", "Nebulized salbutamol", "Intramuscular adrenaline (epinephrine)", "IV fluids alone"], "ans": 3, "exp": "Anaphylaxis รักษาลำดับแรกด้วย IM adrenaline (epinephrine) ที่ต้นขาด้านนอก ทันที + วางราบ/ยกขา + O2 + IV fluid; steroid/antihistamine เป็น adjunct ไม่ใช่ตัวหลัก.", "id": "set1-84"}, {"topic": "Pulmonology", "q": "A patient with idiopathic pulmonary fibrosis has fine bibasal 'velcro' crackles and reticular changes with honeycombing at the bases on HRCT. Which is true about management?", "choices": ["High-dose steroids are curative", "Antibiotics are curative", "Bronchodilators reverse it", "No treatment affects progression", "Antifibrotics (pirfenidone/nintedanib) slow decline"], "ans": 4, "exp": "IPF (UIP pattern: subpleural basal reticulation + honeycombing) รักษาด้วย antifibrotic (pirfenidone/nintedanib) ชะลอการเสื่อมของ FVC; steroid ไม่ช่วยและอาจอันตรายใน IPF. พิจารณา lung transplant.", "id": "set1-85"}, {"topic": "Pulmonology", "q": "A diabetic patient has fever, right-sided chest pain, and CXR shows a cavity with an air-fluid level following an aspiration event. What is the likely diagnosis?", "choices": ["Lung abscess", "Pulmonary tuberculosis", "Pulmonary embolism", "Pulmonary sarcoidosis", "Cavitating lung cancer"], "ans": 0, "exp": "หลัง aspiration + cavity ที่มี air-fluid level = lung abscess (มัก anaerobe/mixed oral flora, บริเวณ dependent เช่น RLL/posterior segment). รักษาด้วย antibiotics คลุม anaerobe (clindamycin/β-lactam-β-lactamase inhibitor) นาน.", "id": "set1-86"}, {"topic": "Pulmonology", "q": "A young woman has dyspnea, bilateral hilar lymphadenopathy on CXR, erythema nodosum, and elevated serum ACE. What is the most likely diagnosis?", "choices": ["Pulmonary tuberculosis", "Sarcoidosis", "Mediastinal lymphoma", "Silicosis", "Histoplasmosis"], "ans": 1, "exp": "Bilateral hilar lymphadenopathy + erythema nodosum + ACE สูง เข้าได้กับ sarcoidosis (non-caseating granuloma). Löfgren syndrome (arthritis + BHL + erythema nodosum) พยากรณ์ดี มักหายเอง.", "id": "set1-87"}, {"topic": "Pulmonology", "q": "In interpreting a chest X-ray, Kerley B lines and cephalization of vessels suggest:", "choices": ["Lobar pneumonia", "Pneumothorax", "Pulmonary edema (cardiogenic congestion)", "Emphysema", "Pleural effusion only"], "ans": 2, "exp": "Kerley B lines + cephalization + perihilar (bat-wing) opacities + cardiomegaly เข้าได้กับ cardiogenic pulmonary edema. ช่วยแยกจาก ARDS ที่หัวใจปกติและ infiltrate กระจายทั่ว.", "id": "set1-88"}, {"topic": "Pulmonology", "q": "A patient with severe CAP requiring ICU admission should receive which empiric regimen?", "choices": ["Oral amoxicillin alone", "Oral doxycycline alone", "IV vancomycin alone", "IV beta-lactam (e.g., ceftriaxone) plus a macrolide or respiratory fluoroquinolone", "No antibiotics until culture"], "ans": 3, "exp": "Severe CAP (ICU) ใช้ IV β-lactam (ceftriaxone) + macrolide (azithromycin) หรือ respiratory fluoroquinolone. พิจารณาคลุม MRSA/Pseudomonas ตามความเสี่ยง.", "id": "set1-89"}, {"topic": "Pulmonology", "q": "A patient with obstructive sleep apnea has daytime somnolence and witnessed apneas. What is the first-line treatment for moderate-to-severe OSA?", "choices": ["Weight loss measures only", "Nocturnal oxygen alone", "Sedative medication", "Surgical tracheostomy", "Continuous positive airway pressure (CPAP)"], "ans": 4, "exp": "OSA ระดับปานกลาง-รุนแรง first-line คือ CPAP (ร่วมกับลดน้ำหนัก/เลี่ยงแอลกอฮอล์-ยานอนหลับ). O2 เดี่ยวไม่แก้ obstruction; sedative จะทำให้แย่ลง.", "id": "set1-90"}, {"topic": "Pulmonology", "q": "A patient with massive hemoptysis (>200 mL/day). What is the priority in initial management?", "choices": ["Airway protection and positioning bleeding side down", "Immediate emergency lobectomy", "Give systemic thrombolytics", "Start therapeutic anticoagulation", "Discharge with a cough suppressant"], "ans": 0, "exp": "Massive hemoptysis เสี่ยง asphyxiation มากกว่า exsanguination — จัดการ airway ก่อน (ป้องกันเลือดท่วมปอดดี, จัดท่าให้ข้างที่เลือดออกอยู่ล่าง), resuscitate, แล้ว localize (bronchoscopy/CT) + bronchial artery embolization; หลีกเลี่ยง anticoagulant.", "id": "set1-91"}, {"topic": "Pulmonology", "q": "Which criterion is part of CURB-65 for pneumonia severity?", "choices": ["Age ≥ 50 years alone", "Confusion, Urea > 19 mg/dL, RR ≥ 30, BP < 90/60, Age ≥ 65", "WBC greater than 12,000", "CRP greater than 100", "SpO2 below 95%"], "ans": 1, "exp": "CURB-65 = Confusion, Urea > 7 mmol/L (~19 mg/dL BUN), RR ≥ 30, BP (SBP<90 หรือ DBP≤60), Age ≥ 65. คะแนนสูงขึ้น = พิจารณา admit/ICU.", "id": "set1-92"}, {"topic": "Pulmonology", "q": "A febrile neutropenic oncology patient develops cough and a new lung infiltrate. Empiric antibiotics should be started within what time frame?", "choices": ["Within about 24 hours", "Within about 72 hours", "Within 1 hour", "Only after culture results", "Only if the patient is unstable"], "ans": 2, "exp": "Febrile neutropenia เป็นภาวะฉุกเฉิน ต้องให้ empiric broad-spectrum antibiotic (คลุม Pseudomonas เช่น piperacillin-tazobactam/cefepime/carbapenem) ภายใน 1 ชม.หลังเจาะ culture.", "id": "set1-93"}, {"topic": "Pulmonology", "q": "A patient with COPD is assessed for exacerbation risk. Which parameter guides the addition of inhaled corticosteroid to LABA/LAMA?", "choices": ["Serum CRP level", "Serum D-dimer", "Serum BNP level", "Blood eosinophil count", "Serum IgE level only"], "ans": 3, "exp": "GOLD ใช้ blood eosinophil count นำการเพิ่ม ICS: เพิ่ม ICS (triple therapy) เมื่อ eos ≥ 300 หรือใน Group E ที่ eos สูง/ประวัติ exacerbation บ่อย; หลีกเลี่ยง ICS ถ้า eos < 100 (ประโยชน์น้อย เสี่ยงปอดอักเสบ).", "id": "set1-94"}, {"topic": "Pulmonology", "q": "A 40-year-old presents with acute hypersensitivity: fever, cough, and dyspnea hours after exposure to moldy hay, with diffuse ground-glass on CT. What is the diagnosis?", "choices": ["Acute bronchial asthma", "Bacterial pneumonia", "Pulmonary embolism", "COPD exacerbation", "Hypersensitivity pneumonitis"], "ans": 4, "exp": "อาการหลังสัมผัส antigen (moldy hay = Farmer's lung) + ไข้/ไอ/เหนื่อย + ground-glass เข้าได้กับ hypersensitivity pneumonitis. การรักษาสำคัญคือหลีกเลี่ยง antigen ± corticosteroid.", "id": "set1-95"}, {"topic": "Pulmonology", "q": "Which best differentiates cardiogenic pulmonary edema (type of respiratory failure) from ARDS?", "choices": ["Elevated BNP and cardiac cause supports cardiogenic edema", "Bilateral infiltrates are present in both", "The PaO2/FiO2 ratio value", "The presence of dyspnea", "The need for supplemental oxygen"], "ans": 0, "exp": "ทั้งคู่มี bilateral infiltrate + hypoxemia. สิ่งที่แยกคือหลักฐานของ cardiac cause (BNP สูง, EF ต่ำ, cardiomegaly, response to diuretic) ใน cardiogenic edema; ARDS ไม่ได้เกิดจาก hydrostatic/cardiac เพียงอย่างเดียว.", "id": "set1-96"}, {"topic": "Pulmonology", "q": "A patient develops stridor and drooling with rapid-onset severe sore throat and high fever; he is sitting forward (tripod). What is the immediate concern?", "choices": ["Simple viral pharyngitis", "Acute epiglottitis (airway emergency)", "The common cold", "Allergic rhinitis", "A tonsillar stone (tonsillolith)"], "ans": 1, "exp": "Stridor + drooling + tripod position + toxic เข้าได้กับ acute epiglottitis เป็นภาวะฉุกเฉินทางเดินหายใจ — ห้ามตรวจคอโดยไม่พร้อม, ให้ secure airway โดยผู้เชี่ยวชาญ + IV antibiotics (ceftriaxone).", "id": "set1-97"}, {"topic": "Pulmonology", "q": "A patient recovering from viral illness develops a normal-anion-gap picture with rapid deep breathing (Kussmaul) — actually found to have DKA. Kussmaul breathing represents what compensation?", "choices": ["Primary respiratory acidosis", "Primary metabolic alkalosis", "Respiratory compensation for metabolic acidosis", "Primary respiratory alkalosis", "No compensation occurring"], "ans": 2, "exp": "Kussmaul breathing (หายใจลึกเร็ว) เป็น respiratory compensation ต่อ metabolic acidosis (เช่น DKA) เพื่อขับ CO2 ลด acidemia. คำนวณด้วย Winter's formula เพื่อดูว่า compensation เหมาะสม.", "id": "set1-98"}, {"topic": "Pulmonology", "q": "Which patient with a solitary pulmonary nodule can be safely followed with serial imaging rather than immediate biopsy?", "choices": ["Spiculated, growing nodule in a heavy smoker", "A nodule with high PET avidity", "Cavitating nodule with weight loss", "Small (<6 mm) smooth nodule with benign calcification in a low-risk patient", "A nodule enlarging over 3 months"], "ans": 3, "exp": "Nodule ที่เล็ก, ขอบเรียบ, มี benign calcification (popcorn = hamartoma, central/laminated), ในคนเสี่ยงต่ำ มีโอกาสมะเร็งต่ำ ติดตามด้วย imaging ได้. ลักษณะเสี่ยง (spiculated, โตเร็ว, PET avid, สูบจัด) → biopsy.", "id": "set1-99"}, {"topic": "Pulmonology", "q": "A patient presents with acute dyspnea and wheeze. Which single feature most strongly indicates a life-threatening asthma attack requiring immediate escalation?", "choices": ["Peak flow at 70% of predicted", "Only mild expiratory wheeze", "A respiratory rate of 18", "An SpO2 of 97%", "Silent chest with inability to speak in full sentences"], "ans": 4, "exp": "Silent chest (airflow น้อยจนไม่ได้ยิน wheeze) + พูดไม่จบประโยค + ใช้กล้ามเนื้อช่วยหายใจ = life-threatening asthma. ต้อง O2, nebulized SABA+ipratropium ซ้ำ, systemic steroid, IV magnesium และเตรียมช่วยหายใจ.", "id": "set1-100"}]}, {"id": "set2", "title": "ชุดที่ 2 — Nephrology + Endocrine", "questions": [{"topic": "Nephrology", "q": "A hypotensive patient after GI bleeding has oliguria, BUN/Cr ratio 25, FeNa 0.5%, and concentrated urine. What type of AKI is this?", "choices": ["Prerenal azotemia", "Acute tubular necrosis", "Acute interstitial nephritis", "Postrenal obstruction", "Acute glomerulonephritis"], "ans": 0, "exp": "BUN/Cr > 20, FeNa < 1%, urine เข้มข้น + ประวัติ hypovolemia = prerenal AKI (ไตยัง reabsorb Na/น้ำได้ดี). รักษาโดยแก้ volume; ถ้าปล่อยไว้อาจกลายเป็น ATN.", "id": "set2-1"}, {"topic": "Nephrology", "q": "A patient develops AKI after prolonged hypotension; urine shows muddy brown granular casts and FeNa 3%. What is the diagnosis?", "choices": ["Prerenal azotemia", "Acute tubular necrosis", "Postrenal obstruction", "Minimal change disease", "Prerenal azotemia from CHF"], "ans": 1, "exp": "Muddy brown granular cast + FeNa > 2% (ไตเสียความสามารถ reabsorb Na) หลัง ischemia/hypotension = acute tubular necrosis. รักษาแบบประคับประคอง หลีกเลี่ยง nephrotoxin, รอ recovery.", "id": "set2-2"}, {"topic": "Nephrology", "q": "Which is an absolute indication for urgent dialysis in AKI?", "choices": ["A blood urea nitrogen of 40 mg/dL without other complications", "A serum creatinine of 2.5 mg/dL without other complications", "Refractory hyperkalemia, pulmonary edema, severe acidosis, or uremia", "A mild metabolic acidosis that responds to bicarbonate", "Isolated proteinuria without any electrolyte disturbance"], "ans": 2, "exp": "ข้อบ่งชี้ dialysis (AEIOU): Acidosis รุนแรงดื้อยา, Electrolyte (hyperK ดื้อยา), Intoxication, Overload (pulmonary edema ดื้อยา), Uremia (encephalopathy/pericarditis/bleeding). ค่า BUN/Cr เดี่ยวไม่ใช่ข้อบ่งชี้.", "id": "set2-3"}, {"topic": "Nephrology", "q": "A patient started on an ACE inhibitor for hypertension has a creatinine rise of 40% within a week and a bruit is heard over the abdomen. What is the likely cause?", "choices": ["Diabetic nephropathy", "Acute glomerulonephritis", "Simple dehydration only", "Bilateral renal artery stenosis", "Expected normal ACEI effect"], "ans": 3, "exp": "Cr เพิ่มมาก (> 30%) หลังเริ่ม ACEI + abdominal bruit นึกถึง bilateral renal artery stenosis ซึ่ง efferent arteriole พึ่ง angiotensin II เพื่อคง GFR. หยุด ACEI และประเมิน renal artery.", "id": "set2-4"}, {"topic": "Nephrology", "q": "A CKD patient has Hb 8.5, low iron studies corrected, and no bleeding. What is the main mechanism of the anemia?", "choices": ["Iron deficiency alone", "Chronic hemolysis", "Vitamin B12 deficiency", "Underlying thalassemia", "Reduced erythropoietin production"], "ans": 4, "exp": "Anemia of CKD เกิดจากไตผลิต erythropoietin ลดลง (normocytic normochromic). รักษาด้วย ESA (erythropoiesis-stimulating agent) หลังแก้ iron ให้พอ; เป้า Hb ไม่สูงเกิน (~10–11.5).", "id": "set2-5"}, {"topic": "Nephrology", "q": "Which medication class is now recommended to slow CKD progression in a patient with eGFR 30 and albuminuria (per KDIGO 2024)?", "choices": ["An SGLT2 inhibitor", "A loop diuretic", "A calcium channel blocker", "A beta-blocker", "An NSAID"], "ans": 0, "exp": "KDIGO 2024 แนะนำ SGLT2 inhibitor ใน CKD (eGFR ≥ 20) ที่มี albuminuria (ACR ≥ 200) หรือ HF เพื่อชะลอการเสื่อมของไต ร่วมกับ ACEI/ARB. Finerenone เพิ่มเติมใน T2D + albuminuria.", "id": "set2-6"}, {"topic": "Nephrology", "q": "A patient with type 2 diabetes, eGFR 40, albuminuria persists despite maximal ARB and an SGLT2i, K+ normal. What can be added to further reduce albuminuria?", "choices": ["Spironolactone (steroidal MRA)", "Finerenone (nonsteroidal MRA)", "A second added ARB", "Amlodipine therapy", "Hydralazine therapy"], "ans": 1, "exp": "KDIGO/ADA แนะนำ finerenone (nonsteroidal MRA) ใน T2D + albuminuria, eGFR > 25, K+ ปกติ ที่ยังมี albuminuria แม้ใช้ RASi เต็มที่ — ลด CV/renal events. ไม่ใช้ ACEI+ARB ร่วมกัน.", "id": "set2-7"}, {"topic": "Nephrology", "q": "A patient has serum Na 118 mmol/L, is euvolemic, with high urine osmolality and urine Na > 40. Which is the most likely cause?", "choices": ["Diarrheal fluid loss", "Heart failure", "SIADH", "Diabetes insipidus", "Adrenal hormone excess"], "ans": 2, "exp": "Euvolemic hyponatremia + urine osmolality สูง + urine Na สูง = SIADH (หลัง exclude hypothyroid/adrenal insufficiency). สาเหตุ: CNS, ปอด (SCLC), ยา, ปวด/คลื่นไส้. รักษาจำกัดน้ำ + แก้สาเหตุ.", "id": "set2-8"}, {"topic": "Nephrology", "q": "When correcting severe chronic hyponatremia, what complication results from correcting too rapidly?", "choices": ["Cerebral edema from overcorrection", "Seizure from hypocalcemia", "Rhabdomyolysis", "Osmotic demyelination syndrome (central pontine myelinolysis)", "Severe hyperkalemia"], "ans": 3, "exp": "แก้ Na เร็วเกิน (> 8–10 mEq/L/24 ชม.) ใน chronic hyponatremia เสี่ยง osmotic demyelination (central pontine myelinolysis). แก้ hypernatremia เร็วเกินต่างหากที่เสี่ยง cerebral edema.", "id": "set2-9"}, {"topic": "Nephrology", "q": "A patient with CKD has ECG showing peaked T waves and K+ 7.2. After IV calcium, which combination best shifts potassium into cells?", "choices": ["Furosemide diuresis", "Kayexalate (resin)", "Sodium bicarbonate alone", "Normal saline infusion", "Insulin with glucose (± nebulized salbutamol)"], "ans": 4, "exp": "หลัง calcium gluconate (stabilize membrane) ให้ insulin + glucose (± beta-agonist) เพื่อ shift K เข้าเซลล์อย่างรวดเร็ว. Furosemide/resin/dialysis กำจัด K ออกจากร่างกาย (ช้ากว่า).", "id": "set2-10"}, {"topic": "Nephrology", "q": "A patient with hypokalemia does not improve despite potassium replacement. What should be checked and corrected?", "choices": ["Serum magnesium level", "Serum calcium level", "Serum phosphate level", "Serum albumin level", "Serum TSH level"], "ans": 0, "exp": "Hypokalemia ที่ดื้อต่อการเติม K มักมี hypomagnesemia ร่วม (Mg ต่ำทำให้ renal K wasting) ต้องแก้ Mg ก่อน K จึงจะขึ้น.", "id": "set2-11"}, {"topic": "Nephrology", "q": "A patient has hypercalcemia with 'stones, bones, groans, and psychiatric moans'. PTH is elevated and phosphate is low. What is the diagnosis?", "choices": ["Malignancy-related hypercalcemia", "Primary hyperparathyroidism", "Vitamin D toxicity", "Sarcoidosis", "Milk-alkali syndrome"], "ans": 1, "exp": "Hypercalcemia + PTH สูง + phosphate ต่ำ = primary hyperparathyroidism (มัก parathyroid adenoma). ต่างจาก malignancy ที่ PTH ต่ำ (PTHrP). รักษา parathyroidectomy ถ้าเข้าเกณฑ์.", "id": "set2-12"}, {"topic": "Nephrology", "q": "Immediate management of severe symptomatic hypercalcemia (Ca 14) includes:", "choices": ["Restrict fluids strictly to avoid worsening fluid overload", "Start a thiazide diuretic to promote calcium excretion", "IV isotonic saline hydration + calcitonin ± bisphosphonate", "Give oral calcium supplements to correct the imbalance", "Give high-dose vitamin D to improve calcium handling"], "ans": 2, "exp": "Severe hypercalcemia รักษาด้วย IV isotonic saline (rehydrate + promote calciuresis) + calcitonin (ออกเร็ว) + bisphosphonate (ออกช้าแต่ยาว). หลีกเลี่ยง thiazide (เพิ่ม Ca reabsorption).", "id": "set2-13"}, {"topic": "Nephrology", "q": "A patient presents with tetany, perioral numbness, positive Chvostek sign, and a prolonged QT after thyroid surgery. What is the cause?", "choices": ["Severe hyperkalemia", "Acute hypernatremia", "Isolated hypomagnesemia", "Hypocalcemia from hypoparathyroidism", "Isolated hyperphosphatemia"], "ans": 3, "exp": "หลังผ่าตัด thyroid/parathyroid เสี่ยง hypoparathyroidism → hypocalcemia (ชา เกร็ง Chvostek/Trousseau, QT ยาว). รักษาด้วย IV/oral calcium + calcitriol.", "id": "set2-14"}, {"topic": "Nephrology", "q": "A child has periorbital edema, proteinuria > 3.5 g/day, hypoalbuminemia, and hyperlipidemia. What is the most likely histology?", "choices": ["IgA nephropathy", "Post-streptococcal GN", "Rapidly progressive GN", "Thin basement membrane disease", "Minimal change disease"], "ans": 4, "exp": "Nephrotic syndrome ในเด็กส่วนใหญ่คือ minimal change disease (ตอบสนองดีต่อ steroid). Nephrotic = proteinuria > 3.5 g/day, hypoalbuminemia, edema, hyperlipidemia; เสี่ยง infection และ VTE.", "id": "set2-15"}, {"topic": "Nephrology", "q": "A 10-year-old develops hematuria, hypertension, and periorbital edema 2 weeks after a sore throat; C3 is low and ASO is elevated. What is the diagnosis?", "choices": ["Post-streptococcal glomerulonephritis", "Minimal change disease", "IgA nephropathy", "Alport syndrome", "Membranous nephropathy"], "ans": 0, "exp": "Nephritic syndrome หลัง strep 1–3 สัปดาห์ + C3 ต่ำ + ASO สูง = post-streptococcal GN. รักษาประคับประคอง (คุมความดัน/บวม); ส่วนใหญ่หายเองในเด็ก.", "id": "set2-16"}, {"topic": "Nephrology", "q": "A patient with gross hematuria occurring 1–2 days after an upper respiratory infection (synpharyngitic) most likely has:", "choices": ["Post-streptococcal GN", "IgA nephropathy", "Minimal change disease", "Diabetic nephropathy", "Membranous nephropathy"], "ans": 1, "exp": "Hematuria พร้อม/หลัง URI ทันที (1–2 วัน, synpharyngitic) ต่างจาก PSGN (ล่าช้า 1–3 สัปดาห์) = IgA nephropathy (Berger). วินิจฉัยด้วย renal biopsy (mesangial IgA).", "id": "set2-17"}, {"topic": "Nephrology", "q": "A nephrotic syndrome patient develops sudden flank pain and worsening renal function. Which complication should be suspected?", "choices": ["Acute pyelonephritis", "An obstructing renal stone", "Renal vein thrombosis", "Renal artery stenosis", "Renal papillary necrosis"], "ans": 2, "exp": "Nephrotic syndrome ทำให้ hypercoagulable (เสีย antithrombin III ทางปัสสาวะ) เสี่ยง renal vein thrombosis (โดยเฉพาะ membranous) → flank pain + hematuria + ไตแย่ลง. ยืนยันด้วย imaging; รักษา anticoagulation.", "id": "set2-18"}, {"topic": "Nephrology", "q": "A woman has dysuria, frequency, and suprapubic discomfort but no fever or flank pain. What is the appropriate management of uncomplicated cystitis?", "choices": ["IV ceftriaxone therapy", "No treatment needed", "Long-term antibiotics", "Short course nitrofurantoin/fosfomycin/co-trimoxazole", "Renal ultrasound first"], "ans": 3, "exp": "Uncomplicated cystitis (ไม่มีไข้/ปวดสีข้าง) รักษาด้วยยา oral สั้น: nitrofurantoin, fosfomycin, หรือ co-trimoxazole (ตาม local resistance). ไม่ต้อง imaging ในรายไม่ซับซ้อน.", "id": "set2-19"}, {"topic": "Nephrology", "q": "A woman has high fever, chills, and costovertebral angle tenderness with pyuria. What is the diagnosis and management?", "choices": ["Cystitis; oral nitrofurantoin", "Asymptomatic bacteriuria; observe", "Interstitial cystitis; analgesia", "Renal stone; lithotripsy", "Acute pyelonephritis; ceftriaxone or fluoroquinolone"], "ans": 4, "exp": "ไข้สูง + CVA tenderness + pyuria = acute pyelonephritis. เก็บ urine + hemoculture, ให้ ceftriaxone/fluoroquinolone, admit ถ้ารุนแรง/อาเจียน/ตั้งครรภ์. Nitrofurantoin ไม่เหมาะกับ pyelonephritis (tissue level ต่ำ).", "id": "set2-20"}, {"topic": "Nephrology", "q": "In which situation should asymptomatic bacteriuria be treated?", "choices": ["Pregnancy or before a urologic procedure", "All elderly patients routinely", "All diabetic patients routinely", "Any patient with an indwelling catheter", "It should never be treated"], "ans": 0, "exp": "Asymptomatic bacteriuria รักษาเฉพาะหญิงตั้งครรภ์ (ลด pyelonephritis/preterm) และก่อนหัตถการทางเดินปัสสาวะที่เสี่ยงเลือดออก. กลุ่มอื่น (สูงอายุ, เบาหวาน, คาสาย) ไม่ต้องรักษาเพราะเพิ่ม resistance.", "id": "set2-21"}, {"topic": "Nephrology", "q": "Urinalysis shows RBC casts. Which condition does this most specifically indicate?", "choices": ["Urinary tract infection", "Glomerulonephritis", "Acute tubular necrosis", "Prerenal azotemia", "Bladder carcinoma"], "ans": 1, "exp": "RBC cast จำเพาะต่อ glomerular bleeding = glomerulonephritis. WBC cast = pyelonephritis/AIN; muddy brown cast = ATN; hyaline cast = ปกติ/dehydration.", "id": "set2-22"}, {"topic": "Nephrology", "q": "A patient with diabetes has microalbuminuria. Besides glycemic control, which drug slows progression of diabetic nephropathy?", "choices": ["A beta-blocker", "A calcium channel blocker", "ACE inhibitor or ARB (plus SGLT2i)", "An alpha-blocker", "A loop diuretic"], "ans": 2, "exp": "Diabetic nephropathy ที่มี albuminuria ใช้ ACEI/ARB ลด intraglomerular pressure/proteinuria + SGLT2i ชะลอไตเสื่อม. คุมน้ำตาล/ความดัน/lipid ร่วมด้วย.", "id": "set2-23"}, {"topic": "Nephrology", "q": "A patient on chronic NSAIDs presents with AKI, sterile pyuria, eosinophiluria, and a maculopapular rash. What is the diagnosis?", "choices": ["Acute tubular necrosis", "Prerenal azotemia", "Post-streptococcal GN", "Acute interstitial nephritis", "An obstructing renal stone"], "ans": 3, "exp": "AKI + rash + eosinophilia/eosinophiluria + ประวัติยา (NSAID, antibiotic, PPI) = acute interstitial nephritis (allergic). รักษาโดยหยุดยาต้นเหตุ ± corticosteroid.", "id": "set2-24"}, {"topic": "Nephrology", "q": "ABG in a patient with prolonged vomiting shows pH 7.50, HCO3 34, PaCO2 46. What is the primary acid-base disorder?", "choices": ["Metabolic acidosis", "Respiratory acidosis", "Respiratory alkalosis", "A normal acid-base state", "Metabolic alkalosis"], "ans": 4, "exp": "pH สูง + HCO3 สูง = metabolic alkalosis; อาเจียนเสีย HCl + volume contraction. PaCO2 สูงเล็กน้อยเป็น respiratory compensation. รักษาด้วย isotonic saline (chloride-responsive).", "id": "set2-25"}, {"topic": "Nephrology", "q": "A patient with distal (type 1) renal tubular acidosis typically has which electrolyte/stone pattern?", "choices": ["Hypokalemia, normal anion gap acidosis, and calcium phosphate stones", "Hyperkalemia with a high anion gap acidosis and no stones", "A primary metabolic alkalosis with a low serum potassium", "Hyperphosphatemia with a high anion gap and uric acid stones", "Hypernatremia with a normal anion gap and no renal stones"], "ans": 0, "exp": "Distal (type 1) RTA: ไม่สามารถขับ H+ ที่ distal tubule → normal anion gap metabolic acidosis + hypokalemia + urine pH สูง (> 5.5) + เสี่ยง calcium phosphate stones/nephrocalcinosis.", "id": "set2-26"}, {"topic": "Nephrology", "q": "A patient develops rapidly rising creatinine over days with hematuria, RBC casts, and crescents on biopsy. What is the diagnosis?", "choices": ["Minimal change disease", "Rapidly progressive (crescentic) glomerulonephritis", "Established chronic kidney disease", "Prerenal azotemia", "Acute tubular necrosis"], "ans": 1, "exp": "ไตวายเร็ว + nephritic (RBC cast) + crescents = rapidly progressive GN (RPGN). สาเหตุ: ANCA-associated vasculitis, anti-GBM (Goodpasture), immune complex (lupus). ต้องรีบวินิจฉัย + immunosuppression.", "id": "set2-27"}, {"topic": "Nephrology", "q": "Which finding best distinguishes chronic kidney disease from acute kidney injury on imaging/labs?", "choices": ["An isolated elevation of serum creatinine on a single test", "Reduced urine output over the preceding twenty-four hours", "Small echogenic kidneys, anemia, and CKD-MBD (high PTH, low Ca)", "An elevated serum potassium without any other abnormality", "Isolated proteinuria detected on a routine dipstick test"], "ans": 2, "exp": "CKD มักมีไตเล็ก echogenic, anemia (EPO ต่ำ), และ CKD-MBD (PTH สูง, Ca ต่ำ, PO4 สูง) ที่ค่อยเป็นค่อยไป — ต่างจาก AKI ที่ไตขนาดปกติและ acute. ช่วยแยกเมื่อไม่มี baseline.", "id": "set2-28"}, {"topic": "Nephrology", "q": "A patient with CKD stage 4 has high phosphate. What is the first-line dietary/pharmacologic management?", "choices": ["A high-phosphate diet", "Calcium supplement alone", "A vitamin D megadose", "Dietary phosphate restriction + phosphate binders", "Loop diuretic therapy"], "ans": 3, "exp": "Hyperphosphatemia ใน CKD จัดการด้วยจำกัดฟอสเฟตในอาหาร + phosphate binder (calcium-based หรือ non-calcium เช่น sevelamer) เพื่อคุม CKD-MBD และลด vascular calcification.", "id": "set2-29"}, {"topic": "Nephrology", "q": "A patient with rhabdomyolysis (CK very high) after crush injury is at risk of AKI. What is the key initial treatment?", "choices": ["Strict fluid restriction", "Immediate dialysis for all", "Diuretic therapy alone", "Bicarbonate is contraindicated", "Aggressive IV fluid to maintain urine output"], "ans": 4, "exp": "Rhabdomyolysis → myoglobin cast + AKI; รักษาด้วย aggressive IV fluid รักษา urine output สูง (± urine alkalinization ในบางราย). ระวัง hyperkalemia และ hypocalcemia. Dialysis เมื่อมีข้อบ่งชี้.", "id": "set2-30"}, {"topic": "Nephrology", "q": "An elderly patient with poor water intake has Na 158, lethargy, and concentrated urine. How should hypernatremia be corrected?", "choices": ["Slowly replace the free water deficit (≤ 10 mEq/L/day)", "A rapid bolus of hypotonic fluid", "Give hypertonic saline", "Strict fluid restriction", "Loop diuretic alone"], "ans": 0, "exp": "Hypernatremia แก้โดยค่อยๆ ทดแทน free water deficit ช้าๆ (ลด Na ไม่เกิน ~10 mEq/L/วัน) เพื่อป้องกัน cerebral edema. หาสาเหตุ (ขาดน้ำ, DI). การแก้เร็วเกินอันตราย.", "id": "set2-31"}, {"topic": "Nephrology", "q": "A patient with polyuria and dilute urine does not concentrate urine after water deprivation but responds to desmopressin. What is the diagnosis?", "choices": ["Nephrogenic diabetes insipidus", "Central diabetes insipidus", "Primary polydipsia", "SIADH", "Osmotic diuresis"], "ans": 1, "exp": "ตอบสนองต่อ desmopressin (urine osmolality เพิ่ม) = central DI (ขาด ADH). Nephrogenic DI จะไม่ตอบสนอง desmopressin (ไตดื้อ ADH). Primary polydipsia จะ concentrate ได้เมื่อ deprive.", "id": "set2-32"}, {"topic": "Nephrology", "q": "A patient with severe flank pain radiating to the groin and microscopic hematuria most likely has:", "choices": ["Acute pyelonephritis", "Acute cystitis", "Ureteric (renal) colic from a stone", "Acute glomerulonephritis", "Bladder carcinoma"], "ans": 2, "exp": "ปวดสีข้าวร้าวลงขาหนีบ (colicky) + hematuria = ureteric stone (renal colic). ยืนยันด้วย non-contrast CT KUB; รักษา analgesia, hydration, medical expulsive therapy (alpha-blocker) สำหรับนิ่วเล็ก; intervention ถ้านิ่วใหญ่/อุดตัน/ติดเชื้อ.", "id": "set2-33"}, {"topic": "Nephrology", "q": "A diabetic patient is scheduled for contrast CT. What is the best strategy to reduce contrast-associated AKI?", "choices": ["Give NSAIDs beforehand", "Give a diuretic before contrast", "Withhold all fluids", "Ensure adequate IV hydration and hold nephrotoxins", "Give high-dose vitamin C"], "ans": 3, "exp": "ลดเสี่ยง contrast-associated nephropathy ด้วยการให้ isotonic IV hydration รอบการฉีด contrast + หยุด nephrotoxin (NSAID) + ใช้ contrast ปริมาณน้อย. Diuretic/NSAID ทำให้แย่ลง.", "id": "set2-34"}, {"topic": "Nephrology", "q": "A cirrhotic patient with tense ascites develops AKI unresponsive to volume, with bland urine and no other cause. What is the diagnosis?", "choices": ["Prerenal azotemia", "Acute tubular necrosis", "Acute glomerulonephritis", "Postrenal obstruction", "Hepatorenal syndrome"], "ans": 4, "exp": "AKI ใน cirrhosis ที่ตัดสาเหตุอื่นและไม่ตอบสนอง volume (bland urine, FeNa ต่ำ) = hepatorenal syndrome. รักษาด้วย terlipressin (หรือ noradrenaline) + albumin; แก้ precipitant; ปลูกถ่ายตับ.", "id": "set2-35"}, {"topic": "Nephrology", "q": "An adult with flank masses, hypertension, hematuria, and a family history of kidney failure has multiple bilateral renal cysts. What is the diagnosis?", "choices": ["Autosomal dominant polycystic kidney disease", "Simple renal cysts", "Medullary sponge kidney", "Renal cell carcinoma", "Acquired cystic kidney disease"], "ans": 0, "exp": "Multiple bilateral cysts + HT + ประวัติครอบครัว = ADPKD (PKD1/2). สัมพันธ์ berry aneurysm (SAH), hepatic cysts, MVP. คุมความดัน (ACEI/ARB); tolvaptan ชะลอในรายเสี่ยงสูง.", "id": "set2-36"}, {"topic": "Nephrology", "q": "A patient has nephrotic syndrome; biopsy shows subepithelial deposits and thickened GBM (membranous nephropathy). Which underlying condition should be excluded, especially in older adults?", "choices": ["Underlying diabetes mellitus", "Underlying malignancy (with anti-PLA2R testing)", "Viral hepatitis alone", "Amyloidosis alone", "Thyroid disease"], "ans": 1, "exp": "Membranous nephropathy อาจ secondary ต่อ malignancy (โดยเฉพาะผู้สูงอายุ), infection (HBV), SLE, ยา. ควรคัดกรองมะเร็งตามอายุ + ตรวจ anti-PLA2R (primary). เสี่ยง renal vein thrombosis สูง.", "id": "set2-37"}, {"topic": "Nephrology", "q": "A young woman with SLE has proteinuria, hematuria, red cell casts, and rising creatinine. What is essential for guiding treatment?", "choices": ["Empiric antibiotic therapy", "Observation without action", "Renal biopsy to classify lupus nephritis", "Loop diuretic only", "Immediate dialysis"], "ans": 2, "exp": "Lupus nephritis ต้อง renal biopsy จำแนก class (I–VI) เพราะกำหนดการรักษา (class III/IV → induction ด้วย steroid + mycophenolate/cyclophosphamide). Complement ต่ำ + anti-dsDNA สูงช่วยประเมิน activity.", "id": "set2-38"}, {"topic": "Nephrology", "q": "A patient presents with hemoptysis and rapidly progressive glomerulonephritis; anti-GBM antibody is positive. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Microscopic polyangiitis", "IgA nephropathy", "Goodpasture syndrome (anti-GBM disease)", "Post-streptococcal GN"], "ans": 3, "exp": "RPGN + pulmonary hemorrhage + anti-GBM positive = Goodpasture syndrome. รักษาด้วย plasmapheresis + steroid + cyclophosphamide. ต่างจาก ANCA-vasculitis ที่ ANCA positive.", "id": "set2-39"}, {"topic": "Nephrology", "q": "A patient with fatigue, weight loss, sinusitis, hemoptysis, and RPGN has c-ANCA (anti-PR3) positive. What is the diagnosis?", "choices": ["Goodpasture syndrome", "Minimal change disease", "Diabetic nephropathy", "Renal amyloidosis", "Granulomatosis with polyangiitis (GPA)"], "ans": 4, "exp": "Upper+lower respiratory (sinusitis, hemoptysis) + RPGN + c-ANCA/PR3 = granulomatosis with polyangiitis. รักษา induction ด้วย steroid + rituximab/cyclophosphamide.", "id": "set2-40"}, {"topic": "Nephrology", "q": "ABG shows pH 7.34, PaCO2 60, HCO3 32 in a COPD patient. What is the interpretation?", "choices": ["Chronic (compensated) respiratory acidosis", "Acute respiratory acidosis", "Primary metabolic acidosis", "Respiratory alkalosis", "Mixed metabolic alkalosis"], "ans": 0, "exp": "PaCO2 สูง + HCO3 สูงชดเชย + pH เกือบปกติ (แค่ต่ำเล็กน้อย) = chronic respiratory acidosis with metabolic compensation (พบใน COPD). Acute จะมี pH ต่ำชัดโดย HCO3 ยังไม่ขึ้น.", "id": "set2-41"}, {"topic": "Nephrology", "q": "A patient with type 4 (hyporeninemic hypoaldosteronism) RTA, common in diabetics, typically shows:", "choices": ["Hypokalemia with alkalosis", "Hyperkalemia with normal anion gap acidosis", "High anion gap acidosis", "Metabolic alkalosis", "Hypernatremia"], "ans": 1, "exp": "Type 4 RTA (hypoaldosteronism, พบในเบาหวาน) มี hyperkalemia + normal anion gap metabolic acidosis. รักษาแก้ hyperkalemia (จำกัด K, diuretic, fludrocortisone ในบางราย).", "id": "set2-42"}, {"topic": "Nephrology", "q": "A patient develops thrombocytopenia, microangiopathic hemolytic anemia, and AKI after bloody diarrhea (E. coli O157:H7). What is the diagnosis?", "choices": ["Thrombotic thrombocytopenic purpura", "Disseminated intravascular coagulation", "Hemolytic uremic syndrome (HUS)", "Immune thrombocytopenic purpura", "Evans syndrome"], "ans": 2, "exp": "เด็ก/หลัง bloody diarrhea (Shiga toxin E. coli) + MAHA + thrombocytopenia + AKI = HUS. รักษาประคับประคอง (มัก supportive, dialysis ถ้าจำเป็น); หลีกเลี่ยง antibiotics/antimotility ที่อาจเพิ่ม toxin.", "id": "set2-43"}, {"topic": "Nephrology", "q": "An older man has difficulty voiding, weak stream, nocturia, and a distended bladder with AKI. What is the mechanism of his kidney injury?", "choices": ["Prerenal azotemia", "Intrinsic acute tubular necrosis", "Acute glomerulonephritis", "Postrenal obstruction from BPH", "Acute interstitial nephritis"], "ans": 3, "exp": "BPH ทำให้ bladder outlet obstruction → postrenal AKI (hydronephrosis 2 ข้าง). ระบายปัสสาวะด้วย catheter จะทำให้ไตดีขึ้น; ระวัง post-obstructive diuresis.", "id": "set2-44"}, {"topic": "Nephrology", "q": "A patient on hemodialysis develops hypotension, muscle cramps during the session. What is the most likely cause?", "choices": ["Air embolism", "Acute hemolysis", "Anaphylactic reaction", "Severe hyperkalemia", "Excess fluid removal (intradialytic hypotension)"], "ans": 4, "exp": "Intradialytic hypotension มักจากการดึงน้ำเร็ว/มากเกิน (ultrafiltration) → hypotension + cramps. จัดการโดยลด ultrafiltration rate, ให้ saline, ประเมิน dry weight.", "id": "set2-45"}, {"topic": "Nephrology", "q": "Which is the recommended blood pressure target for most CKD patients with albuminuria (KDIGO), if tolerated?", "choices": ["Systolic below 120 mmHg", "Below 160/100 mmHg", "Below 150/90 mmHg", "Below 140/90 only", "No specific target"], "ans": 0, "exp": "KDIGO แนะนำเป้า systolic < 120 mmHg (วัดแบบมาตรฐาน) ในผู้ป่วย CKD ส่วนใหญ่ถ้าทนได้ เพื่อลด CV events. ใช้ ACEI/ARB เป็นยาหลักเมื่อมี albuminuria.", "id": "set2-46"}, {"topic": "Nephrology", "q": "A patient has persistent proteinuria on dipstick. What is the best test to quantify and characterize it?", "choices": ["Serum albumin level only", "Spot urine albumin/protein-to-creatinine ratio", "Renal ultrasound", "Serum creatinine only", "A complete blood count"], "ans": 1, "exp": "Quantify proteinuria ด้วย spot urine protein/creatinine ratio หรือ albumin/creatinine ratio (สะดวกกว่า 24-hr และสัมพันธ์กันดี). ช่วยประเมิน glomerular disease และ CKD progression.", "id": "set2-47"}, {"topic": "Nephrology", "q": "A patient with recurrent calcium oxalate stones should be advised to:", "choices": ["Severely restrict all dietary calcium to prevent stone growth", "Increase dietary protein intake to acidify the urine further", "Increase fluids, reduce sodium/oxalate, keep normal dietary calcium", "Take high-dose vitamin C supplements to reduce recurrence", "Restrict total fluid intake to concentrate the urine output"], "ans": 2, "exp": "ป้องกันนิ่ว calcium oxalate: ดื่มน้ำมาก (urine > 2 L/วัน), ลดเกลือและ oxalate, กิน calcium ปกติ (ไม่จำกัดเข้ม เพราะการจำกัด Ca เพิ่ม oxalate absorption), thiazide ในราย hypercalciuria.", "id": "set2-48"}, {"topic": "Nephrology", "q": "A patient presents with painless gross hematuria and no infection. In an older smoker, which diagnosis must be excluded?", "choices": ["A simple urinary tract infection", "Prerenal azotemia", "Minimal change disease", "Urothelial (bladder) carcinoma", "Renal (ureteric) colic"], "ans": 3, "exp": "Painless gross hematuria ในผู้สูงอายุ/สูบบุหรี่ ต้องตัด urothelial (bladder) carcinoma ด้วย cystoscopy + CT urography. อย่าเหมาว่าเป็น UTI ถ้าไม่มีหลักฐานติดเชื้อ.", "id": "set2-49"}, {"topic": "Endocrinology", "q": "Which of the following meets the diagnostic criteria for diabetes mellitus?", "choices": ["A fasting glucose of 110 mg/dL", "Random glucose 160 mg/dL, no symptoms", "A 2-hr OGTT of 150 mg/dL", "An HbA1c of 6.0%", "HbA1c ≥ 6.5% or fasting glucose ≥ 126 mg/dL"], "ans": 4, "exp": "เกณฑ์เบาหวาน: FPG ≥ 126, 2-hr OGTT ≥ 200, HbA1c ≥ 6.5% (ยืนยันซ้ำถ้าไม่มีอาการ), หรือ random ≥ 200 + อาการ. FPG 100–125 = IFG (prediabetes); A1c 5.7–6.4 = prediabetes.", "id": "set2-50"}, {"topic": "Endocrinology", "q": "A patient with T2DM and established ASCVD needs glucose-lowering therapy. Which agents should be included irrespective of A1c?", "choices": ["A GLP-1 RA and/or SGLT2 inhibitor with CV benefit", "A sulfonylurea agent", "Basal insulin therapy", "A thiazolidinedione", "Acarbose therapy"], "ans": 0, "exp": "ADA 2025/26: ในผู้ป่วย T2DM + ASCVD/ความเสี่ยงสูง ให้ GLP-1 RA และ/หรือ SGLT2i ที่มีหลักฐานลด CV events โดยไม่ขึ้นกับ A1c หรือการใช้ metformin. HF → SGLT2i; CKD → SGLT2i first-line.", "id": "set2-51"}, {"topic": "Endocrinology", "q": "A T2DM patient with heart failure needs additional therapy. Which class both lowers glucose and reduces HF hospitalization?", "choices": ["A sulfonylurea", "An SGLT2 inhibitor", "A DPP-4 inhibitor", "A thiazolidinedione", "Insulin therapy"], "ans": 1, "exp": "SGLT2 inhibitor ลด HF hospitalization (ทั้ง HFrEF/HFpEF) และชะลอ CKD จึงเป็นตัวเลือกใน T2DM + HF. TZD (pioglitazone) ทำให้ fluid retention/HF แย่ลง.", "id": "set2-52"}, {"topic": "Endocrinology", "q": "A patient with T1DM presents with vomiting, Kussmaul breathing, glucose 450, pH 7.15, HCO3 10, and ketonuria. What is the first step in management?", "choices": ["An IV insulin bolus before fluids", "Oral hydration alone", "IV isotonic fluid resuscitation, then insulin with K+ monitoring", "Routine sodium bicarbonate", "Give glucose"], "ans": 2, "exp": "DKA รักษาลำดับ: IV fluid resuscitation ก่อน → insulin drip → เติม K (ถ้า K < 3.3 ต้องเติม K ก่อนเริ่ม insulin) → หา precipitant. Bicarbonate ให้เฉพาะ pH ต่ำมาก (< 6.9). อย่าเริ่ม insulin ก่อน fluid/ตรวจ K.", "id": "set2-53"}, {"topic": "Endocrinology", "q": "An elderly T2DM patient has glucose 900, serum osmolality 350, profound dehydration, and minimal ketones. What is the diagnosis?", "choices": ["Diabetic ketoacidosis", "Lactic acidosis", "Hypoglycemia", "Hyperosmolar hyperglycemic state (HHS)", "Diabetes insipidus"], "ans": 3, "exp": "น้ำตาลสูงมาก (>600) + osmolality สูง + ไม่มี ketoacidosis เด่น + ซึม/ขาดน้ำ = HHS. เน้น aggressive fluid resuscitation เป็นหลัก + insulin + แก้ electrolyte + หาสาเหตุ (ติดเชื้อ).", "id": "set2-54"}, {"topic": "Endocrinology", "q": "A diabetic on insulin becomes confused and diaphoretic with glucose 45 mg/dL. What is the immediate treatment if conscious and able to swallow?", "choices": ["IV insulin infusion", "IM glucagon only", "Observation only", "IV normal saline", "Oral fast-acting carbohydrate (glucose)"], "ans": 4, "exp": "Hypoglycemia (< 70) ที่รู้ตัวและกลืนได้ → ให้ oral carbohydrate/glucose 15 g ทันที (rule of 15). ถ้าไม่รู้ตัว/กลืนไม่ได้ → IV glucose หรือ IM glucagon. Whipple triad ยืนยันภาวะน้ำตาลต่ำ.", "id": "set2-55"}, {"topic": "Endocrinology", "q": "A T2DM patient is screened for diabetic complications. How often should retinal examination be performed?", "choices": ["Annually (once a year)", "Every 5 years", "Only if symptomatic", "Every month", "Never needed"], "ans": 0, "exp": "ควรตรวจตา (dilated retinal exam) อย่างน้อยปีละครั้งเพื่อคัดกรอง diabetic retinopathy; ตรวจเท้า (monofilament) และ urine ACR + eGFR ปีละครั้งเช่นกัน.", "id": "set2-56"}, {"topic": "Endocrinology", "q": "A patient with diabetic neuropathy has painful burning feet. Which is an appropriate first-line agent for neuropathic pain?", "choices": ["Paracetamol alone", "Pregabalin/gabapentin or duloxetine/amitriptyline", "Ibuprofen (an NSAID)", "An opioid as first-line", "Topical corticosteroid"], "ans": 1, "exp": "Painful diabetic neuropathy ใช้ pregabalin/gabapentin, duloxetine, หรือ TCA (amitriptyline) เป็น first-line. NSAID/paracetamol ได้ผลน้อย; opioid ไม่ใช่ตัวแรก.", "id": "set2-57"}, {"topic": "Endocrinology", "q": "A patient has palpitations, weight loss, heat intolerance, tremor, exophthalmos, and pretibial myxedema. TSH is low. What is the diagnosis?", "choices": ["Toxic multinodular goiter", "Subacute thyroiditis", "Graves disease", "Hashimoto thyroiditis", "Iodine deficiency"], "ans": 2, "exp": "Hyperthyroid + exophthalmos + pretibial myxedema (จำเพาะ) + TRAb = Graves disease (autoimmune). รักษาด้วย antithyroid drug (methimazole), RAI, หรือผ่าตัด + beta-blocker คุมอาการ.", "id": "set2-58"}, {"topic": "Endocrinology", "q": "A pregnant woman in the first trimester needs antithyroid drug for hyperthyroidism. Which is preferred?", "choices": ["Methimazole", "Radioactive iodine", "Carbimazole", "Propylthiouracil (PTU)", "Levothyroxine"], "ans": 3, "exp": "Trimester 1 เลือก PTU (methimazole เสี่ยง teratogenic – aplasia cutis, choanal atresia ในช่วงต้น). หลัง trimester 1 มักเปลี่ยนเป็น methimazole (PTU เสี่ยง hepatotoxicity). RAI เป็นข้อห้ามในการตั้งครรภ์.", "id": "set2-59"}, {"topic": "Endocrinology", "q": "A patient with fever, tachycardia/AF, agitation, and heart failure after infection has severe thyrotoxicosis. What is the treatment sequence for thyroid storm?", "choices": ["Give iodine first and then start PTU one hour afterwards", "Start levothyroxine to replace the depleted thyroid hormone", "Give radioactive iodine immediately as the definitive therapy", "Use methimazole alone without any adjunctive treatment", "PTU first, then iodine (>1 h later), beta-blocker, hydrocortisone"], "ans": 4, "exp": "Thyroid storm: ให้ PTU (block synthesis + peripheral T4→T3 conversion) ก่อน แล้วให้ iodine (Lugol) หลัง ≥ 1 ชม. (ให้ก่อนจะเป็นสารตั้งต้น hormone) + beta-blocker (propranolol) + hydrocortisone + ลดไข้ + รักษา precipitant.", "id": "set2-60"}, {"topic": "Endocrinology", "q": "A patient has fatigue, cold intolerance, weight gain, constipation, and bradycardia. TSH is high and free T4 low. What is the treatment?", "choices": ["Levothyroxine", "Methimazole", "Radioactive iodine", "Propranolol", "Prednisolone"], "ans": 0, "exp": "Primary hypothyroidism (TSH สูง, FT4 ต่ำ; มัก Hashimoto) รักษาด้วย levothyroxine แล้วปรับตาม TSH. เริ่มขนาดต่ำในผู้สูงอายุ/โรคหัวใจ.", "id": "set2-61"}, {"topic": "Endocrinology", "q": "A patient presents with hypothermia, bradycardia, hyponatremia, and depressed consciousness with a history of untreated hypothyroidism. What is the management of myxedema coma?", "choices": ["Oral levothyroxine then discharge", "IV levothyroxine (± T3) plus IV hydrocortisone and support", "Methimazole therapy", "Active rewarming only", "Observation only"], "ans": 1, "exp": "Myxedema coma เป็นภาวะฉุกเฉิน: IV levothyroxine (± T3) + IV hydrocortisone (กัน adrenal crisis) + supportive (warming, ventilation, แก้ hyponatremia/hypoglycemia) + รักษา precipitant.", "id": "set2-62"}, {"topic": "Endocrinology", "q": "A patient has a thyroid nodule. What is the appropriate initial investigation?", "choices": ["Immediate surgery", "CT of the neck", "Serum TSH, then thyroid ultrasound and FNA by risk", "Thyroid scan for all", "Start levothyroxine"], "ans": 2, "exp": "Thyroid nodule เริ่มด้วย TSH → ถ้าต่ำทำ thyroid scan (hot nodule มักไม่ร้าย); ทำ ultrasound (TIRADS) แล้ว FNA ตามขนาด/ลักษณะเสี่ยง (Bethesda). ไม่ผ่าตัดทุกราย.", "id": "set2-63"}, {"topic": "Endocrinology", "q": "Which thyroid cancer is the most common and generally has the best prognosis?", "choices": ["Follicular carcinoma", "Medullary carcinoma", "Anaplastic carcinoma", "Papillary carcinoma", "Thyroid lymphoma"], "ans": 3, "exp": "Papillary thyroid carcinoma พบบ่อยสุดและพยากรณ์ดี (แพร่ทาง lymphatic). Follicular แพร่ทาง hematogenous; medullary จาก C-cell (calcitonin, MEN2); anaplastic ดุ พยากรณ์แย่.", "id": "set2-64"}, {"topic": "Endocrinology", "q": "A patient with medullary thyroid carcinoma should be screened for which associated condition?", "choices": ["MEN 1 syndrome only", "Addison disease", "Graves disease", "Cushing disease", "MEN 2 (pheochromocytoma, hyperparathyroidism)"], "ans": 4, "exp": "Medullary thyroid carcinoma สัมพันธ์กับ MEN 2 (pheochromocytoma, primary hyperparathyroidism, RET mutation). ต้องคัดกรอง pheochromocytoma ก่อนผ่าตัด thyroid.", "id": "set2-65"}, {"topic": "Endocrinology", "q": "A patient has central obesity, moon face, purple striae, proximal weakness, hypertension, and hyperglycemia. Which test screens for Cushing syndrome?", "choices": ["Late-night salivary cortisol, 1-mg dexamethasone, or 24-h urinary cortisol", "A single random serum cortisol level drawn at any time of day", "An ACTH stimulation (Synacthen) test to assess the response", "Serum TSH and free thyroxine to exclude thyroid dysfunction", "Plasma renin and aldosterone measured together in the morning"], "ans": 0, "exp": "คัดกรอง Cushing ด้วย 1 ใน 3: overnight low-dose dexamethasone suppression test, 24-hr urinary free cortisol, หรือ late-night salivary cortisol. จากนั้นหาสาเหตุด้วย ACTH + high-dose dexamethasone/imaging.", "id": "set2-66"}, {"topic": "Endocrinology", "q": "A patient has fatigue, weight loss, hyperpigmentation, hypotension, hyponatremia, and hyperkalemia. What is the diagnosis?", "choices": ["Cushing syndrome", "Primary adrenal insufficiency (Addison disease)", "Hyperthyroidism", "Conn syndrome", "SIADH"], "ans": 1, "exp": "Hyperpigmentation (ACTH สูง) + hypotension + hypoNa + hyperK = primary adrenal insufficiency (Addison). ยืนยันด้วย morning cortisol ต่ำ + ACTH stimulation test. รักษา hydrocortisone + fludrocortisone.", "id": "set2-67"}, {"topic": "Endocrinology", "q": "A patient in shock refractory to fluids and vasopressors, with a history of chronic steroid use recently stopped, should receive:", "choices": ["Give more intravenous crystalloid fluids and nothing else", "Start broad-spectrum antibiotics and await culture results", "IV hydrocortisone immediately (treat adrenal crisis)", "Give an insulin infusion to control the blood glucose", "Start thyroxine replacement to correct the hypotension"], "ans": 2, "exp": "Shock ดื้อ fluid/vasopressor + ประวัติหยุด steroid = adrenal crisis. ให้ IV hydrocortisone ทันทีโดยไม่ต้องรอผลตรวจ + fluid resuscitation + หา/แก้ precipitant.", "id": "set2-68"}, {"topic": "Endocrinology", "q": "A patient has episodic severe hypertension with headache, palpitations, and diaphoresis. Which test and treatment order are correct?", "choices": ["Metanephrines; give beta-blocker first", "TSH; give levothyroxine", "Aldosterone; give spironolactone", "Plasma/urine metanephrines; alpha- then beta-blockade, then surgery", "Cortisol; proceed to surgery"], "ans": 3, "exp": "Pheochromocytoma: HT เป็นพักๆ + triad (ปวดหัว/ใจสั่น/เหงื่อ). ตรวจ plasma/urine metanephrines. ผ่าตัดหลังเตรียมด้วย alpha-blockade (phenoxybenzamine) ก่อน beta-block (ถ้าให้ beta ก่อนจะเกิด unopposed alpha → HT crisis).", "id": "set2-69"}, {"topic": "Endocrinology", "q": "A hypertensive patient with hypokalemia and a high aldosterone-to-renin ratio most likely has:", "choices": ["Pheochromocytoma", "Cushing syndrome", "Addison disease", "Renal artery stenosis", "Primary aldosteronism (Conn syndrome)"], "ans": 4, "exp": "HT + hypokalemia + aldosterone/renin ratio สูง = primary aldosteronism (Conn). ยืนยันด้วย confirmatory test + adrenal imaging/AVS; รักษา MRA (spironolactone/eplerenone) หรือผ่าตัดถ้า adenoma ข้างเดียว.", "id": "set2-70"}, {"topic": "Endocrinology", "q": "A young woman has amenorrhea, galactorrhea, and reduced libido; prolactin is markedly elevated with a pituitary mass. What is first-line treatment?", "choices": ["Dopamine agonist (cabergoline)", "Transsphenoidal surgery first", "Radiotherapy", "Estrogen therapy", "Observation only"], "ans": 0, "exp": "Prolactinoma รักษาลำดับแรกด้วย dopamine agonist (cabergoline/bromocriptine) ซึ่งลด prolactin และขนาด tumor ได้ดีแม้ macroadenoma. ผ่าตัดสงวนไว้เมื่อดื้อยา/ทน side effect ไม่ได้.", "id": "set2-71"}, {"topic": "Endocrinology", "q": "An adult with enlarging hands/feet, coarse facial features, and headache has elevated IGF-1. What confirms acromegaly?", "choices": ["A random GH level", "OGTT showing failure to suppress GH", "Serum prolactin", "Serum TSH", "Serum cortisol"], "ans": 1, "exp": "Acromegaly (GH เกินในผู้ใหญ่): คัดกรองด้วย IGF-1 สูง ยืนยันด้วย OGTT ที่ GH ไม่ suppress. หา pituitary adenoma ด้วย MRI; รักษาผ่าตัด ± somatostatin analog.", "id": "set2-72"}, {"topic": "Endocrinology", "q": "A patient with head trauma develops polyuria with dilute urine and rising sodium; urine osmolality is inappropriately low. What is the diagnosis?", "choices": ["SIADH", "Primary polydipsia", "Central diabetes insipidus", "Osmotic diuresis", "Nephrogenic DI"], "ans": 2, "exp": "หลัง head trauma/ผ่าตัด pituitary + polyuria เจือจาง + hypernatremia + urine osmolality ต่ำ = central diabetes insipidus (ขาด ADH). รักษาด้วย desmopressin.", "id": "set2-73"}, {"topic": "Endocrinology", "q": "A patient with lung small cell carcinoma has euvolemic hyponatremia, high urine osmolality, and high urine sodium. What is the diagnosis and initial management?", "choices": ["Addison; give steroid", "DI; give desmopressin", "Diuretic effect; stop diuretic", "SIADH; fluid restriction", "Cushing; surgery"], "ans": 3, "exp": "Euvolemic hyponatremia + urine osmolality/Na สูง + มะเร็งปอด = SIADH (ectopic ADH). รักษาเริ่มด้วยจำกัดน้ำ; รายรุนแรง/ชักใช้ hypertonic saline (แก้ช้าๆ), รักษาสาเหตุ.", "id": "set2-74"}, {"topic": "Endocrinology", "q": "A postmenopausal woman has a fragility fracture. A DEXA scan shows a T-score of -2.8. What is the diagnosis and a first-line treatment?", "choices": ["Osteomalacia; vitamin D only", "Paget disease; calcitonin", "Normal scan; no treatment", "Hyperparathyroidism; surgery", "Osteoporosis; bisphosphonate + calcium/vitamin D"], "ans": 4, "exp": "T-score ≤ -2.5 = osteoporosis (fragility fracture ยิ่งยืนยัน). รักษาด้วย bisphosphonate (alendronate) + calcium/vitamin D + ออกกำลัง/ป้องกันล้ม. ประเมิน secondary causes.", "id": "set2-75"}, {"topic": "Endocrinology", "q": "A patient with subclinical hypothyroidism has TSH 8 and normal free T4, is asymptomatic and not pregnant. What is the general recommendation?", "choices": ["Treat if TSH > 10, symptomatic, pregnant, or antibody-positive; else monitor", "Always start levothyroxine immediately in every such patient", "Start methimazole and reassess thyroid function in six weeks", "Give radioactive iodine ablation to prevent any progression", "Refer for thyroid surgery once the diagnosis is confirmed"], "ans": 0, "exp": "Subclinical hypothyroidism (TSH สูงเล็กน้อย, FT4 ปกติ) พิจารณา levothyroxine เมื่อ TSH > 10, มีอาการ, ตั้งครรภ์/วางแผนตั้งครรภ์, หรือ anti-TPO บวก; ที่เหลือมักติดตาม.", "id": "set2-76"}, {"topic": "Endocrinology", "q": "A patient recently started metformin. Which is a key contraindication/precaution to remember?", "choices": ["It is absolutely contraindicated in any patient who is obese", "Caution if eGFR > 30; stop if eGFR < 30 or acute illness (lactic acidosis)", "It very commonly causes significant weight gain over time", "It frequently causes hypoglycemia even used as monotherapy", "It cannot be combined with an SGLT2 inhibitor at all"], "ans": 1, "exp": "Metformin หลีกเลี่ยงเมื่อ eGFR < 30 (เสี่ยง lactic acidosis) และหยุดชั่วคราวช่วงเจ็บป่วยเฉียบพลัน/ก่อนฉีด contrast ในราย eGFR ต่ำ. ข้อดี: ไม่ทำให้น้ำตาลต่ำ/น้ำหนักเป็นกลาง.", "id": "set2-77"}, {"topic": "Endocrinology", "q": "Which diabetes drug class is associated with euglycemic diabetic ketoacidosis, especially perioperatively?", "choices": ["A sulfonylurea", "Metformin", "An SGLT2 inhibitor", "A DPP-4 inhibitor", "Insulin"], "ans": 2, "exp": "SGLT2 inhibitor อาจทำให้เกิด euglycemic DKA (โดยเฉพาะช่วงผ่าตัด/อดอาหาร/เจ็บป่วย) จึงแนะนำหยุด 3–4 วันก่อนผ่าตัดใหญ่. ต้องนึกถึงแม้ระดับน้ำตาลไม่สูงมาก.", "id": "set2-78"}, {"topic": "Endocrinology", "q": "A patient with type 1 diabetes should receive which insulin regimen as the physiologic standard?", "choices": ["Sliding scale insulin only", "Premixed insulin twice daily only", "Metformin therapy", "Basal-bolus (basal + rapid-acting with meals)", "A GLP-1 agonist alone"], "ans": 3, "exp": "T1DM ต้องใช้ insulin เสมอ; basal-bolus (basal long-acting + rapid-acting ก่อนอาหาร) เลียนแบบสรีรวิทยาได้ดีสุด. Sliding scale เดี่ยวไม่พอ; oral agents ไม่ใช้เป็นหลักใน T1DM.", "id": "set2-79"}, {"topic": "Endocrinology", "q": "A woman has secondary amenorrhea; workup shows high FSH/LH and low estrogen before age 40. What is the diagnosis?", "choices": ["Pregnancy", "Hypothalamic amenorrhea", "Polycystic ovary syndrome", "Prolactinoma", "Primary ovarian insufficiency (premature)"], "ans": 4, "exp": "High FSH/LH + low estrogen (hypergonadotropic hypogonadism) ก่อนอายุ 40 = primary ovarian insufficiency. ต่างจาก hypothalamic (FSH/LH ต่ำ). พิจารณา estrogen replacement + หา autoimmune/genetic cause.", "id": "set2-80"}, {"topic": "Endocrinology", "q": "A patient has a low serum cortisol; ACTH stimulation shows an appropriate cortisol rise. This suggests:", "choices": ["Secondary (central) adrenal insufficiency", "Primary adrenal insufficiency", "Cushing syndrome", "Pheochromocytoma", "Conn syndrome"], "ans": 0, "exp": "Cortisol ต่ำแต่ตอบสนองต่อ ACTH stimulation ดี ชี้ secondary/central adrenal insufficiency (pituitary ACTH ขาด, ต่อมหมวกไตยังทำงานได้) — มัก no hyperpigmentation, K ปกติ. Primary จะไม่ตอบสนอง ACTH.", "id": "set2-81"}, {"topic": "Endocrinology", "q": "A young woman with hirsutism, acne, oligomenorrhea, and polycystic ovaries on ultrasound has which condition, and what is first-line for menstrual regulation?", "choices": ["Cushing syndrome; surgery", "PCOS; combined oral contraceptive (± metformin)", "Prolactinoma; cabergoline", "Congenital adrenal hyperplasia; steroid", "Ovarian tumor; surgery"], "ans": 1, "exp": "PCOS (Rotterdam: 2/3 ของ oligo-ovulation, hyperandrogenism, polycystic ovaries) รักษา menstrual/hirsutism ด้วย combined OCP; metformin ช่วย insulin resistance; ลดน้ำหนัก; letrozole สำหรับ ovulation induction.", "id": "set2-82"}, {"topic": "Endocrinology", "q": "A patient with primary hyperparathyroidism has asymptomatic hypercalcemia. Which is an indication for parathyroidectomy?", "choices": ["Any measurable elevation of parathyroid hormone whatsoever", "A completely normal serum calcium with no other findings", "Age < 50, Ca > 1 above normal, eGFR < 60, osteoporosis, or stones", "Coexisting vitamin D deficiency that has not been corrected", "Only mild non-specific fatigue without any other feature"], "ans": 2, "exp": "Indication ผ่าตัดใน primary hyperparathyroidism: อายุ < 50, Ca สูงกว่าปกติ > 1 mg/dL, eGFR < 60, osteoporosis (T ≤ -2.5)/fracture, หรือนิ่วไต/hypercalciuria. Asymptomatic ที่ไม่เข้าเกณฑ์ ติดตามได้.", "id": "set2-83"}, {"topic": "Endocrinology", "q": "A patient with hypocalcemia, high phosphate, and LOW PTH after neck surgery has:", "choices": ["Primary hyperparathyroidism", "Secondary hyperparathyroidism", "Vitamin D deficiency", "Hypoparathyroidism", "Pseudohypoparathyroidism"], "ans": 3, "exp": "หลังผ่าตัดคอ + Ca ต่ำ + PO4 สูง + PTH ต่ำ = hypoparathyroidism (มัก iatrogenic). รักษาด้วย calcium + calcitriol. Secondary hyperparathyroidism (CKD/vit D ต่ำ) จะมี PTH สูง.", "id": "set2-84"}, {"topic": "Endocrinology", "q": "A patient has fasting triglycerides of 1200 mg/dL. What is the main acute risk and treatment?", "choices": ["Ischemic stroke; start a high-intensity statin urgently", "Myocardial infarction; give aspirin and dual antiplatelets", "Acute gout flare; start allopurinol with colchicine cover", "No significant acute risk; simply observe and reassure", "Acute pancreatitis; fibrate/omega-3 + control DM/alcohol"], "ans": 4, "exp": "TG สูงมาก (> 500–1000) เสี่ยง acute pancreatitis. รักษาด้วย fibrate/omega-3, คุมเบาหวาน/งดแอลกอฮอล์/ลดน้ำตาล/ลดน้ำหนัก. Statin ลด LDL แต่ไม่ใช่ตัวหลักลด TG สูงมาก.", "id": "set2-85"}, {"topic": "Endocrinology", "q": "A patient with newly diagnosed T2DM and A1c 11% with symptoms (polyuria, weight loss). What is appropriate initial therapy?", "choices": ["Insulin (± metformin) for marked hyperglycemia/symptoms", "Lifestyle alone for 3 months", "A sulfonylurea only", "Acarbose", "Observation only"], "ans": 0, "exp": "A1c สูงมาก (> 10%) + อาการ/catabolic (น้ำหนักลด) ควรเริ่ม insulin (± metformin) เพื่อคุมน้ำตาลเร็ว แล้วค่อยปรับลดเมื่อดีขึ้น. Lifestyle เดี่ยวไม่พอในภาวะน้ำตาลสูงมีอาการ.", "id": "set2-86"}, {"topic": "Endocrinology", "q": "A patient develops flushing, diarrhea, and right-sided heart valve disease; urine 5-HIAA is elevated. What is the diagnosis?", "choices": ["Pheochromocytoma", "Carcinoid syndrome", "Cushing syndrome", "Medullary thyroid cancer", "VIPoma"], "ans": 1, "exp": "Flushing + diarrhea + right-heart valvular disease + urine 5-HIAA สูง = carcinoid syndrome (serotonin จาก neuroendocrine tumor, มัก GI + liver metastasis). รักษาด้วย somatostatin analog (octreotide).", "id": "set2-87"}, {"topic": "Endocrinology", "q": "A patient with poorly controlled diabetes has bilateral lower-limb sensory loss in a 'stocking' distribution. What is the pattern of neuropathy?", "choices": ["Focal mononeuropathy", "Lumbar radiculopathy", "Distal symmetric polyneuropathy", "Autonomic neuropathy only", "Plexopathy"], "ans": 2, "exp": "Diabetic peripheral neuropathy ที่พบบ่อยสุดคือ distal symmetric (length-dependent) polyneuropathy แบบ stocking-glove. เสี่ยงแผลที่เท้า จึงต้องตรวจเท้า/สอนดูแลเท้า.", "id": "set2-88"}, {"topic": "Endocrinology", "q": "A patient on long-term glucocorticoids is at risk of which complications requiring monitoring?", "choices": ["Hypoglycemia, weight loss, hyperkalemia, and bradycardia over time", "Hypercalcemia, polyuria, renal stones, and a shortened QT interval", "Hyponatremia, hyperpigmentation, and marked postural hypotension", "Hyperglycemia, osteoporosis, hypertension, infection, adrenal suppression", "Hypertension with hypokalemia and a metabolic alkalosis only"], "ans": 3, "exp": "Long-term corticosteroid เสี่ยง hyperglycemia, osteoporosis, HT, น้ำหนักขึ้น/central obesity, ติดเชื้อ, cataract, และ HPA axis suppression (ห้ามหยุดกะทันหัน → adrenal crisis). ต้อง taper และให้ stress dose.", "id": "set2-89"}, {"topic": "Endocrinology", "q": "A patient with type 2 diabetes and obesity would benefit most (for weight and glycemia) from which class?", "choices": ["A sulfonylurea", "Insulin therapy", "A thiazolidinedione", "A DPP-4 inhibitor", "GLP-1 RA (or dual GIP/GLP-1, e.g., tirzepatide)"], "ans": 4, "exp": "GLP-1 RA (semaglutide/liraglutide) และ dual GIP/GLP-1 (tirzepatide) ลดทั้งน้ำตาลและน้ำหนักเด่นชัด เหมาะกับ T2DM + obesity. Sulfonylurea/insulin/TZD ทำให้น้ำหนักขึ้น.", "id": "set2-90"}, {"topic": "Endocrinology", "q": "A diabetic patient has an A1c goal individualized. Which patient is appropriate for a LESS stringent target (e.g., < 8%)?", "choices": ["Elderly with multiple comorbidities and hypoglycemia risk", "Young, newly diagnosed, no complications", "A pregnant patient", "A patient wanting tight control", "A young athlete"], "ans": 0, "exp": "เป้า A1c ปรับตามผู้ป่วย: ผ่อนเป้า (< 8%) ในผู้สูงอายุ/โรคร่วมมาก/เสี่ยง hypoglycemia/ life expectancy สั้น. เข้มขึ้น (< 6.5%) ในคนอายุน้อย สุขภาพดี ไม่มีภาวะแทรกซ้อน.", "id": "set2-91"}, {"topic": "Endocrinology", "q": "A patient has weight gain, proximal myopathy, easy bruising, and hyperglycemia; ACTH is elevated and high-dose dexamethasone suppresses cortisol. Where is the lesion?", "choices": ["An adrenal adenoma", "Pituitary source (Cushing disease)", "Ectopic ACTH from lung cancer", "Exogenous steroid use", "Adrenal carcinoma"], "ans": 1, "exp": "ACTH-dependent Cushing ที่ high-dose dexamethasone suppress ได้ = pituitary source (Cushing disease). Ectopic ACTH (เช่น SCLC) มักไม่ suppress และ ACTH สูงมาก.", "id": "set2-92"}, {"topic": "Endocrinology", "q": "A patient with hypothyroidism on levothyroxine still has high TSH despite adherence. What common issue should be checked?", "choices": ["An overdose of levothyroxine causing suppressed TSH levels", "Coexisting hyperthyroidism from an autonomous thyroid nodule", "Taking it with food/calcium/iron (poor absorption) or underdosing", "An unrecognized adrenal crisis complicating the picture", "A completely normal and expected laboratory finding here"], "ans": 2, "exp": "TSH ยังสูงทั้งที่กินยา — ตรวจการดูดซึม: levothyroxine ควรกินตอนท้องว่าง ห่างจากอาหาร/calcium/iron/PPI; หรือขนาดยาไม่พอ. ปรับขนาดตาม TSH ทุก 6–8 สัปดาห์.", "id": "set2-93"}, {"topic": "Endocrinology", "q": "A patient presents with tetany and carpopedal spasm; ionized calcium is low. Which acute treatment is appropriate for symptomatic hypocalcemia?", "choices": ["Oral calcium only", "Vitamin D alone", "Phosphate supplement", "IV calcium gluconate", "A bisphosphonate"], "ans": 3, "exp": "Symptomatic hypocalcemia (tetany, Trousseau/Chvostek, seizure, QT ยาว) รักษาด้วย IV calcium gluconate + แก้ Mg ถ้าต่ำ + ตามด้วย oral calcium/calcitriol. หาสาเหตุ (hypoparathyroid, vit D).", "id": "set2-94"}, {"topic": "Endocrinology", "q": "A patient with Graves disease is treated with radioactive iodine. What is the most common long-term outcome to counsel about?", "choices": ["Permanent hyperthyroidism", "Thyroid cancer", "No change at all", "Adrenal failure", "Hypothyroidism requiring levothyroxine"], "ans": 4, "exp": "RAI สำหรับ Graves มักทำให้เกิด hypothyroidism ในระยะยาว ต้องได้ levothyroxine. RAI เป็นข้อห้ามในการตั้งครรภ์/ให้นม และอาจทำให้ Graves ophthalmopathy แย่ลงชั่วคราว (พิจารณา steroid คลุม).", "id": "set2-95"}, {"topic": "Endocrinology", "q": "A patient with an incidental adrenal mass (incidentaloma) requires evaluation for which functional problems?", "choices": ["Hormone hypersecretion (cortisol, catecholamines, aldosterone) and malignancy", "Thyroid function tests with an iodine uptake scan only", "Serum prolactin and growth hormone dynamic testing only", "Bone density scanning and vitamin D level assessment only", "Serial imaging of nodule size without any hormonal testing"], "ans": 0, "exp": "Adrenal incidentaloma ต้องประเมิน functional: cortisol excess (dexamethasone suppression), pheochromocytoma (metanephrines), และ aldosterone (ARR ถ้ามี HT/hypoK) + ลักษณะ malignant (size > 4 cm, imaging phenotype).", "id": "set2-96"}, {"topic": "Endocrinology", "q": "A malnourished alcoholic patient is started on IV dextrose and develops confusion; you should also give which vitamin to prevent Wernicke encephalopathy?", "choices": ["Vitamin C", "Thiamine (B1) before or with glucose", "Folate only", "Vitamin D", "Vitamin K"], "ans": 1, "exp": "ผู้ป่วยขาดสารอาหาร/แอลกอฮอล์ ต้องให้ thiamine (B1) ก่อนหรือพร้อมกับ glucose เพื่อป้องกัน/รักษา Wernicke encephalopathy (การให้ glucose ก่อนอาจกระตุ้นอาการ). Triad: confusion, ophthalmoplegia, ataxia.", "id": "set2-97"}, {"topic": "Endocrinology", "q": "A patient with a large non-functioning pituitary macroadenoma presents with bitemporal hemianopia. What is the mechanism?", "choices": ["Cavernous sinus invasion", "Raised intracranial pressure", "Compression of the optic chiasm", "Retinal detachment", "Occipital lobe stroke"], "ans": 2, "exp": "Pituitary macroadenoma กด optic chiasm ทำให้เกิด bitemporal hemianopia (เสียลานสายตาด้านนอกทั้งสองข้าง). ประเมิน visual field + MRI + hormone panel; ผ่าตัด transsphenoidal ถ้ากดเส้นประสาท.", "id": "set2-98"}, {"topic": "Endocrinology", "q": "A patient with hypothyroidism and coexisting untreated adrenal insufficiency is given levothyroxine first. What can occur?", "choices": ["Nothing happens", "A thyroid storm", "Hyperkalemia resolves", "Precipitation of an adrenal crisis", "Only hypoglycemia"], "ans": 3, "exp": "ถ้ามี adrenal insufficiency ร่วม การเริ่ม levothyroxine ก่อนให้ steroid จะเพิ่ม metabolic demand และ cortisol clearance → กระตุ้น adrenal crisis. ต้องให้ glucocorticoid ก่อน/พร้อมกับ thyroid replacement.", "id": "set2-99"}, {"topic": "Endocrinology", "q": "A patient with diabetes has an A1c that seems discordantly low despite high glucose readings. Which condition can falsely lower A1c?", "choices": ["Iron deficiency anemia", "Post-splenectomy state", "Vitamin B12 deficiency", "Renal failure (raises it)", "Hemolytic anemia or blood loss (short RBC lifespan)"], "ans": 4, "exp": "A1c ต่ำผิดปกติเมื่อ RBC lifespan สั้นลง (hemolysis, เสียเลือด, ตั้งครรภ์). ในทางกลับกัน iron deficiency/asplenia ทำให้ A1c สูงลวง. ในกรณีเหล่านี้ใช้ fructosamine หรือ glucose monitoring แทน.", "id": "set2-100"}]}, {"id": "set3", "title": "ชุดที่ 3 — GI/Hepatology + Hematology", "questions": [{"topic": "GI/Hepatology", "q": "A 48-year-old obese man has retrosternal burning after large meals, worse when lying down, with no alarm features. What is the most appropriate initial step?", "choices": ["Lifestyle modification and an empiric PPI trial", "Immediate upper endoscopy for everyone", "24-hour esophageal pH monitoring first", "A barium swallow study as first step", "Early Nissen fundoplication surgery"], "ans": 0, "exp": "GERD ที่ไม่มี alarm features รักษาเริ่มด้วย lifestyle modification + empiric PPI. Endoscopy เมื่อมี alarm (กลืนลำบาก/น้ำหนักลด/เลือดออก/ซีด/อายุมาก). (แนวข้อสอบ NLE2)", "id": "set3-1"}, {"topic": "GI/Hepatology", "q": "Which alarm feature in a patient with dyspepsia mandates upper endoscopy?", "choices": ["Being younger than thirty years of age", "Weight loss, dysphagia, GI bleeding, or anemia", "Occasional mild bloating after meals", "Symptoms appearing after drinking coffee", "A family history of simple GERD"], "ans": 1, "exp": "Alarm features ที่ต้อง endoscopy: น้ำหนักลด, กลืนลำบาก/เจ็บ, เลือดออก (melena/hematemesis)/ซีด, อาเจียนเรื้อรัง, คลำก้อน, อายุ ≥ 50 เริ่มใหม่, ประวัติมะเร็งในครอบครัว.", "id": "set3-2"}, {"topic": "GI/Hepatology", "q": "A patient with a duodenal ulcer tests positive for H. pylori. What is the appropriate treatment?", "choices": ["A proton pump inhibitor alone without antibiotics", "Antacids alone for symptom control only", "Triple/quadruple therapy (PPI + antibiotics) to eradicate H. pylori", "Surgical management with a partial gastrectomy", "An H2-receptor blocker alone without antibiotics"], "ans": 2, "exp": "PUD จาก H. pylori รักษาด้วย eradication therapy (PPI + amoxicillin + clarithromycin หรือ bismuth quadruple 14 วัน) + PPI. ยืนยันการกำจัดด้วย urea breath test/stool antigen หลังหยุดยา.", "id": "set3-3"}, {"topic": "GI/Hepatology", "q": "Which is the most appropriate non-invasive test to confirm H. pylori eradication after treatment?", "choices": ["Serology for H. pylori antibodies", "Rapid urease test during endoscopy", "Bacterial culture of a gastric biopsy", "Urea breath test or stool antigen test", "A random serum antibody titre check"], "ans": 3, "exp": "ยืนยันการกำจัด H. pylori ด้วย urea breath test หรือ stool antigen (non-invasive, สะท้อน active infection). Serology ยังบวกได้แม้หายแล้วจึงไม่เหมาะยืนยันการกำจัด. หยุด PPI ≥ 2 สัปดาห์ก่อนตรวจ.", "id": "set3-4"}, {"topic": "GI/Hepatology", "q": "A patient presents with sudden severe epigastric pain, a rigid abdomen, and free air under the diaphragm on upright CXR. What is the diagnosis?", "choices": ["Acute pancreatitis", "Acute cholecystitis", "Acute appendicitis", "Acute gastroenteritis", "Perforated peptic ulcer"], "ans": 4, "exp": "ปวดท้องเฉียบพลันรุนแรง + peritonitis + free air ใต้ diaphragm = perforated peptic ulcer. รักษาผ่าตัด (simple closure + omental/Graham patch) + resuscitation + IV PPI/antibiotics.", "id": "set3-5"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis presents with hematemesis. Besides resuscitation, which combination is appropriate for suspected variceal bleeding?", "choices": ["Vasoactive drug + prophylactic antibiotic + endoscopic band ligation", "A proton pump inhibitor infusion alone", "A beta-blocker infusion to lower portal pressure", "Tranexamic acid alone to stop the bleeding", "Observation with close monitoring only"], "ans": 0, "exp": "Variceal bleeding: vasoactive (octreotide/terlipressin) + prophylactic antibiotic (ceftriaxone — ลด SBP/mortality) + endoscopic variceal ligation. ป้องกันซ้ำด้วย NSBB + EVL.", "id": "set3-6"}, {"topic": "GI/Hepatology", "q": "In an actively bleeding cirrhotic patient, why are prophylactic antibiotics given?", "choices": ["They are given only to treat established SBP", "They reduce bacterial infection, rebleeding, and mortality", "They directly prevent hepatic encephalopathy", "They are given to treat the varices themselves", "They have no proven benefit in this setting"], "ans": 1, "exp": "ผู้ป่วย cirrhosis ที่มี GI bleeding ให้ prophylactic antibiotic (ceftriaxone) ลดการติดเชื้อ (รวม SBP), ลด rebleeding และลด mortality — เป็นมาตรฐานการดูแล.", "id": "set3-7"}, {"topic": "GI/Hepatology", "q": "A patient with an upper GI bleed is stable with Hb 8. What transfusion strategy is preferred?", "choices": ["A liberal strategy keeping Hb above 10", "Transfuse only when Hb falls below 5", "Restrictive strategy (transfuse to a target Hb ~7)", "Never transfuse regardless of the level", "Use only fresh whole blood transfusions"], "ans": 2, "exp": "UGIB ใช้ restrictive transfusion strategy (เป้า Hb ~7, หรือ ~8 ในโรคหัวใจ) ให้ผลลัพธ์ดีกว่า liberal (โดยเฉพาะ variceal — การให้เลือดเกินเพิ่ม portal pressure/rebleeding).", "id": "set3-8"}, {"topic": "GI/Hepatology", "q": "A cirrhotic patient with ascites develops fever and abdominal pain; ascitic fluid PMN is 320/mm³. What is the diagnosis and treatment?", "choices": ["Secondary peritonitis; proceed to surgery", "Tuberculous peritonitis; start anti-TB drugs", "Malignant ascites; begin chemotherapy", "Spontaneous bacterial peritonitis; give cefotaxime", "Pancreatic ascites; give octreotide"], "ans": 3, "exp": "Ascitic fluid PMN ≥ 250 = spontaneous bacterial peritonitis (SBP). รักษาด้วย cefotaxime + IV albumin (ลด hepatorenal). ป้องกันซ้ำด้วย norfloxacin ในกลุ่มเสี่ยง.", "id": "set3-9"}, {"topic": "GI/Hepatology", "q": "A cirrhotic patient becomes confused with asterixis after constipation. What is the first-line treatment for hepatic encephalopathy?", "choices": ["Long-term dietary protein restriction", "Sedation to calm the confused patient", "A benzodiazepine to settle the patient", "A diuretic to reduce the ascites", "Lactulose (± rifaximin) and treat precipitants"], "ans": 4, "exp": "Hepatic encephalopathy รักษาด้วย lactulose (เป้าถ่าย 2–3 ครั้ง/วัน ลด ammonia) ± rifaximin + หา/แก้ precipitant (ท้องผูก, เลือดออก, ติดเชื้อ, electrolyte, ยา sedative). ไม่จำกัดโปรตีนระยะยาว.", "id": "set3-10"}, {"topic": "GI/Hepatology", "q": "How is the serum-ascites albumin gradient (SAAG) used?", "choices": ["SAAG ≥ 1.1 g/dL indicates portal hypertension", "SAAG < 1.1 g/dL indicates portal hypertension", "The SAAG value measures ascitic infection", "The SAAG value measures underlying malignancy", "The SAAG is not a clinically useful test"], "ans": 0, "exp": "SAAG = serum albumin − ascites albumin. ≥ 1.1 g/dL บ่งชี้ portal hypertension (cirrhosis, HF, Budd-Chiari); < 1.1 บ่งชี้สาเหตุอื่น (malignancy, TB, nephrotic, pancreatic).", "id": "set3-11"}, {"topic": "GI/Hepatology", "q": "A patient with chronic hepatitis B and cirrhosis needs HCC surveillance. What is the recommended approach?", "choices": ["CT of the abdomen once every year", "Ultrasound ± AFP every 6 months", "Upper endoscopy once every year", "No surveillance is needed at all", "MRI of the liver every single month"], "ans": 1, "exp": "ผู้ป่วย cirrhosis หรือ HBV เสี่ยง HCC ควร surveillance ด้วย ultrasound ± AFP ทุก 6 เดือน. รอยโรคสงสัยยืนยันด้วย triple-phase CT/MRI (arterial enhancement + washout).", "id": "set3-12"}, {"topic": "GI/Hepatology", "q": "A patient has HBsAg positive, anti-HBc IgG positive, HBeAg positive, and high HBV DNA. What does this indicate?", "choices": ["Immunity acquired from prior vaccination", "A fully resolved past HBV infection", "Chronic active hepatitis B with high infectivity", "Acute hepatitis A virus infection", "The serologic window period"], "ans": 2, "exp": "HBsAg + high HBV DNA + HBeAg = chronic active HBV ที่ติดต่อง่าย. Anti-HBs เดี่ยว = ภูมิจากวัคซีน; anti-HBc IgM = acute; anti-HBs + anti-HBc = หายและมีภูมิ. รักษา antiviral (tenofovir/entecavir) เมื่อเข้าเกณฑ์.", "id": "set3-13"}, {"topic": "GI/Hepatology", "q": "A person has anti-HBs positive but anti-HBc negative. What does this indicate?", "choices": ["Chronic hepatitis B infection", "Acute hepatitis B infection", "Resolved natural HBV infection", "Immunity acquired from vaccination", "The serologic window period"], "ans": 3, "exp": "Anti-HBs positive + anti-HBc negative = ภูมิจากวัคซีน (ไม่เคยติดเชื้อธรรมชาติ). ถ้าเคยติดเชื้อแล้วหาย จะมีทั้ง anti-HBs + anti-HBc positive. (แนวข้อสอบ NLE2)", "id": "set3-14"}, {"topic": "GI/Hepatology", "q": "A patient with chronic hepatitis C (genotype-agnostic) should be offered which treatment with >95% cure?", "choices": ["Interferon plus ribavirin therapy", "Lifelong lamivudine monotherapy", "No treatment is needed at all", "Systemic corticosteroid therapy", "Direct-acting antivirals (DAA)"], "ans": 4, "exp": "Chronic HCV รักษาด้วย direct-acting antivirals (DAA) ระยะสั้น 8–12 สัปดาห์ หายกว่า 95% (SVR). Interferon เป็นของเดิมที่เลิกใช้แล้ว.", "id": "set3-15"}, {"topic": "GI/Hepatology", "q": "A patient develops jaundice, dark urine, and RUQ pain 3 weeks after starting a herbal weight-loss supplement; viral panel negative. Which test is most critical initially?", "choices": ["Liver function tests", "A fasting lipid profile", "Serum creatinine level", "Serum TSH level", "A complete blood count only"], "ans": 0, "exp": "สงสัย drug/herb-induced liver injury — ตรวจ liver function tests (AST/ALT/bilirubin/ALP) เพื่อประเมินอวัยวะที่ถูกกระทบและรูปแบบ (hepatocellular vs cholestatic). หยุด agent ต้นเหตุ. (แนวข้อสอบ NLE2)", "id": "set3-16"}, {"topic": "GI/Hepatology", "q": "A patient meets 2 of 3 criteria for acute pancreatitis. What is the cornerstone of early management?", "choices": ["Prophylactic antibiotics for every patient", "Aggressive IV fluid resuscitation, analgesia, and early enteral feeding", "Immediate surgery to remove the pancreas", "Keeping the patient NPO for two weeks", "Immediate ERCP for every patient"], "ans": 1, "exp": "Acute pancreatitis รักษาด้วย aggressive IV fluid (goal-directed), analgesia, early enteral feeding. ไม่ให้ prophylactic antibiotic (ให้เมื่อ infected necrosis); ERCP เฉพาะเมื่อมี cholangitis/นิ่วอุดตัน.", "id": "set3-17"}, {"topic": "GI/Hepatology", "q": "Which are the two most common causes of acute pancreatitis?", "choices": ["Abdominal trauma and drugs", "Hyperlipidemia and mumps", "Gallstones and alcohol", "Scorpion sting and post-ERCP", "Autoimmune and idiopathic causes"], "ans": 2, "exp": "สาเหตุที่พบบ่อยที่สุดของ acute pancreatitis คือ gallstones และ alcohol. อื่นๆ (GET SMASHED): hyperTG, ERCP, drugs, trauma, mumps, autoimmune, scorpion. ตรวจ lipase > 3 เท่า + imaging.", "id": "set3-18"}, {"topic": "GI/Hepatology", "q": "A patient has painless obstructive jaundice with a palpable non-tender gallbladder (Courvoisier sign). What is the most concerning diagnosis?", "choices": ["A gallstone impacted in the cystic duct", "Acute viral hepatitis", "Gilbert syndrome", "Pancreatic head / periampullary carcinoma", "Hemolysis of red cells"], "ans": 3, "exp": "Courvoisier sign (ถุงน้ำดีโตคลำได้ ไม่เจ็บ + jaundice) บ่งชี้ malignant obstruction (pancreatic head/periampullary CA) มากกว่านิ่ว. ประเมินด้วย imaging (CT/MRCP/EUS); Whipple ถ้า resectable.", "id": "set3-19"}, {"topic": "GI/Hepatology", "q": "A patient with progressive dysphagia to solids then liquids, weight loss, and a history of smoking/alcohol most likely has:", "choices": ["Achalasia of the esophagus", "Gastroesophageal reflux disease", "A congenital esophageal web", "Diffuse esophageal spasm", "Esophageal carcinoma"], "ans": 4, "exp": "Progressive dysphagia (solids → liquids) + น้ำหนักลด + สูบบุหรี่/เหล้า = esophageal carcinoma (upper/mid = SCC). Achalasia มัก dysphagia ต่อทั้ง solid+liquid ตั้งแต่ต้นและไม่ค่อยน้ำหนักลดเร็ว.", "id": "set3-20"}, {"topic": "GI/Hepatology", "q": "A patient has dysphagia to both solids and liquids; barium shows a dilated esophagus with a 'bird's beak' narrowing at the GE junction. What is the diagnosis?", "choices": ["Achalasia", "Esophageal carcinoma", "A GERD-related stricture", "A Schatzki ring", "Zenker diverticulum"], "ans": 0, "exp": "Dysphagia ต่อทั้ง solid+liquid + bird's beak (dilated esophagus, narrow GE junction) = achalasia (LES ไม่คลาย + aperistalsis). ยืนยันด้วย manometry; รักษา pneumatic dilatation/Heller myotomy/POEM. (แนวข้อสอบ NLE2)", "id": "set3-21"}, {"topic": "GI/Hepatology", "q": "A young patient has chronic bloody diarrhea, tenesmus, and continuous inflammation from the rectum proximally limited to the mucosa on colonoscopy. What is the diagnosis?", "choices": ["Crohn disease", "Ulcerative colitis", "Ischemic colitis", "Amoebic colitis", "Celiac disease"], "ans": 1, "exp": "Continuous inflammation จาก rectum ขึ้นไป, จำกัดที่ mucosa, bloody diarrhea = ulcerative colitis. Crohn = skip lesions, transmural, ทุกส่วนของ GI, fistula/granuloma.", "id": "set3-22"}, {"topic": "GI/Hepatology", "q": "Which feature is characteristic of Crohn disease rather than ulcerative colitis?", "choices": ["Continuous colonic mucosal involvement", "Disease limited to the rectum and colon", "Transmural skip lesions with fistulas and granulomas", "Bloody diarrhea present in every case", "No small bowel involvement at all"], "ans": 2, "exp": "Crohn: transmural, skip lesions, ได้ทุกส่วน (mouth-anus), fistula/stricture/perianal disease, non-caseating granuloma. UC: continuous, mucosal, จำกัด colon เริ่มจาก rectum.", "id": "set3-23"}, {"topic": "GI/Hepatology", "q": "A 35-year-old returning traveler has bloody, foul diarrhea; stool shows motile trophozoites with ingested RBCs. What is the treatment?", "choices": ["Ciprofloxacin monotherapy", "Ceftriaxone monotherapy", "Albendazole therapy", "Metronidazole, then a luminal agent", "Oral vancomycin therapy"], "ans": 3, "exp": "Trophozoite ที่กิน RBC = Entamoeba histolytica (amoebic dysentery/liver abscess). รักษาด้วย metronidazole/tinidazole ตามด้วย luminal agent (paromomycin/diloxanide) กำจัด cyst. (แนวข้อสอบ NLE2)", "id": "set3-24"}, {"topic": "GI/Hepatology", "q": "A patient develops profuse watery diarrhea after recent antibiotic use; stool tests positive for C. difficile toxin. What is the first-line treatment?", "choices": ["Intravenous metronidazole alone", "Loperamide to stop the diarrhea", "Ciprofloxacin therapy", "Probiotics alone without antibiotics", "Oral vancomycin or fidaxomicin"], "ans": 4, "exp": "C. difficile infection รักษา first-line ด้วย oral vancomycin หรือ fidaxomicin (metronidazole เป็นทางเลือกรองในรายไม่รุนแรงที่เข้าถึงยาหลักไม่ได้). หยุด antibiotic ต้นเหตุ; หลีกเลี่ยง antimotility.", "id": "set3-25"}, {"topic": "GI/Hepatology", "q": "A patient has chronic diarrhea, weight loss, iron deficiency, and a rash (dermatitis herpetiformis); anti-tissue transglutaminase is positive. What is the diagnosis?", "choices": ["Celiac disease", "Crohn disease", "Tropical sprue", "Lactose intolerance", "Whipple disease"], "ans": 0, "exp": "Malabsorption + anti-tTG positive + dermatitis herpetiformis = celiac disease. ยืนยันด้วย duodenal biopsy (villous atrophy); รักษาด้วย gluten-free diet.", "id": "set3-26"}, {"topic": "GI/Hepatology", "q": "A patient has right lower quadrant pain migrating from the periumbilical area, anorexia, and low-grade fever with McBurney tenderness. What is the diagnosis?", "choices": ["Acute gastroenteritis", "Acute appendicitis", "Acute diverticulitis", "Acute cholecystitis", "Mesenteric adenitis"], "ans": 1, "exp": "ปวด periumbilical แล้วย้ายมา RLQ (McBurney) + anorexia + ไข้ต่ำ = acute appendicitis. ยืนยัน US/CT; รักษา appendectomy (uncomplicated ที่ยืนยันด้วย CT อาจใช้ antibiotics-first ในบางราย).", "id": "set3-27"}, {"topic": "GI/Hepatology", "q": "An elderly patient has left lower quadrant pain, fever, and a CT showing sigmoid diverticula with pericolic inflammation. What is the diagnosis?", "choices": ["Acute appendicitis", "Ulcerative colitis", "Acute diverticulitis", "Ischemic colitis", "Colorectal cancer"], "ans": 2, "exp": "LLQ pain + ไข้ + sigmoid diverticula + pericolic fat stranding = acute diverticulitis. Uncomplicated รักษา bowel rest ± antibiotics; complicated (abscess/perforation) → drainage/surgery.", "id": "set3-28"}, {"topic": "GI/Hepatology", "q": "A 55-year-old has iron-deficiency anemia and change in bowel habits. What is the essential investigation?", "choices": ["Upper endoscopy alone as the work-up", "CT of the abdomen alone", "A stool culture for pathogens", "Colonoscopy to exclude colorectal cancer", "Reassurance without investigation"], "ans": 3, "exp": "IDA + เปลี่ยนแปลงการขับถ่ายในผู้ใหญ่ ≥ 45–50 ปี ต้อง colonoscopy เพื่อตัด colorectal cancer (เลือดออกเรื้อรัง). Right-sided CA มัก present ด้วย anemia/occult bleeding.", "id": "set3-29"}, {"topic": "GI/Hepatology", "q": "At what age should average-risk adults begin colorectal cancer screening according to current recommendations?", "choices": ["At age 40 years", "At age 50 years", "At age 60 years", "At age 65 years", "At age 45 years"], "ans": 4, "exp": "USPSTF 2021 ลดอายุเริ่มคัดกรอง colorectal cancer เป็น 45 ปี (จากเดิม 50) ในคนความเสี่ยงปกติ — colonoscopy ทุก 10 ปี หรือ FIT ทุกปี.", "id": "set3-30"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis has AKI unresponsive to volume with bland urine sediment. Which is a key treatment for hepatorenal syndrome?", "choices": ["Terlipressin (or noradrenaline) plus albumin", "A loop diuretic to increase urine output", "A dopamine infusion for renal perfusion", "An NSAID for symptomatic relief", "A nephrotoxic aminoglycoside antibiotic"], "ans": 0, "exp": "Hepatorenal syndrome รักษาด้วย vasoconstrictor (terlipressin หรือ noradrenaline) + albumin เพื่อเพิ่ม effective circulating volume; แก้ precipitant; ปลูกถ่ายตับเป็น definitive.", "id": "set3-31"}, {"topic": "GI/Hepatology", "q": "A patient has episodic upper abdominal pain after fatty meals with a positive Murphy sign and fever. Ultrasound shows a thickened gallbladder wall with stones. What is the diagnosis?", "choices": ["Biliary colic", "Acute cholecystitis", "Ascending cholangitis", "Acute pancreatitis", "Acute hepatitis"], "ans": 1, "exp": "RUQ pain + Murphy sign + ไข้ + gallstone + wall thickening = acute cholecystitis. รักษา NPO, IV fluid/antibiotics, analgesia + laparoscopic cholecystectomy (early). Biliary colic ไม่มีไข้/อักเสบ.", "id": "set3-32"}, {"topic": "GI/Hepatology", "q": "A patient has fever, jaundice, and RUQ pain (Charcot triad). What is the diagnosis and key intervention?", "choices": ["Cholecystitis; perform cholecystectomy", "Viral hepatitis; supportive care only", "Ascending cholangitis; ERCP decompression + antibiotics", "Acute pancreatitis; give IV fluids", "Liver abscess; percutaneous drainage"], "ans": 2, "exp": "Charcot triad (fever + jaundice + RUQ pain) = ascending cholangitis (มัก choledocholithiasis). ต้อง IV antibiotics + biliary decompression (ERCP) ด่วน. Reynolds pentad (+ hypotension + confusion) = รุนแรง.", "id": "set3-33"}, {"topic": "GI/Hepatology", "q": "A patient with alcoholic liver disease has an AST:ALT ratio of about 2:1 and both are moderately elevated (< 300). What does this suggest?", "choices": ["Acute viral hepatitis", "Ischemic hepatitis", "Autoimmune hepatitis", "Alcoholic hepatitis", "Biliary obstruction"], "ans": 3, "exp": "AST:ALT > 2:1 กับ transaminase สูงปานกลาง (มัก < 300) เข้าได้กับ alcoholic liver disease/hepatitis. Viral hepatitis มัก ALT > AST และสูงมากได้.", "id": "set3-34"}, {"topic": "GI/Hepatology", "q": "A young woman has amenorrhea, high transaminases, positive ANA/anti-smooth muscle antibody, and high IgG. What is the diagnosis?", "choices": ["Acute viral hepatitis", "Wilson disease", "Hereditary hemochromatosis", "Primary biliary cholangitis", "Autoimmune hepatitis"], "ans": 4, "exp": "Autoimmune hepatitis: หญิงสาว, transaminase สูง, ANA/anti-smooth muscle Ab positive, IgG สูง. ยืนยันด้วย biopsy (interface hepatitis); รักษาด้วย corticosteroid ± azathioprine.", "id": "set3-35"}, {"topic": "GI/Hepatology", "q": "A young patient has liver disease, neuropsychiatric symptoms, and Kayser-Fleischer rings. What is the diagnosis?", "choices": ["Wilson disease", "Hereditary hemochromatosis", "Alpha-1 antitrypsin deficiency", "Autoimmune hepatitis", "Chronic hepatitis B"], "ans": 0, "exp": "Wilson disease (copper สะสม): liver disease + neuropsychiatric + Kayser-Fleischer rings; ceruloplasmin ต่ำ, urinary copper สูง. รักษาด้วย chelator (penicillamine/trientine) + zinc.", "id": "set3-36"}, {"topic": "GI/Hepatology", "q": "A patient has bronze skin, diabetes, arthralgia, and elevated ferritin/transferrin saturation. What is the diagnosis?", "choices": ["Wilson disease", "Hereditary hemochromatosis", "Acute porphyria", "Alcoholic liver disease", "Chronic hepatitis C"], "ans": 1, "exp": "Hereditary hemochromatosis (iron overload, HFE mutation): bronze diabetes + arthralgia + hepatomegaly/HCC risk; ferritin + transferrin saturation สูง. รักษาด้วย phlebotomy.", "id": "set3-37"}, {"topic": "GI/Hepatology", "q": "A patient has watery diarrhea, and stool osmotic gap is high, improving with fasting. What type of diarrhea is this?", "choices": ["Secretory diarrhea", "Inflammatory diarrhea", "Osmotic diarrhea", "Infectious diarrhea", "Fatty (malabsorptive) diarrhea"], "ans": 2, "exp": "Osmotic diarrhea (เช่น lactose intolerance, laxative) มี stool osmotic gap สูง และดีขึ้นเมื่ออดอาหาร. Secretory diarrhea (เช่น cholera, VIPoma) ไม่หยุดเมื่ออดอาหารและ gap ต่ำ.", "id": "set3-38"}, {"topic": "GI/Hepatology", "q": "A patient has recurrent peptic ulcers in unusual locations with diarrhea and very high gastrin. What is the diagnosis?", "choices": ["Common peptic ulcer disease", "H. pylori-related ulceration", "Gastroesophageal reflux disease", "Zollinger-Ellison syndrome (gastrinoma)", "Menetrier disease"], "ans": 3, "exp": "แผลหลายตำแหน่ง/ตำแหน่งผิดปกติ + diarrhea + gastrin สูงมาก = Zollinger-Ellison syndrome (gastrinoma) มักสัมพันธ์ MEN1. ยืนยันด้วย secretin stimulation test.", "id": "set3-39"}, {"topic": "GI/Hepatology", "q": "A patient with severe acute pancreatitis develops persistent fever and clinical deterioration at 2 weeks; CT shows gas in a necrotic collection. What does this indicate?", "choices": ["A pancreatic pseudocyst", "Splenic vein thrombosis", "Resolving pancreatitis", "Pancreatic ascites", "Infected pancreatic necrosis"], "ans": 4, "exp": "ไข้ต่อเนื่อง + gas ใน necrotic collection = infected pancreatic necrosis → ให้ antibiotics + drainage/necrosectomy (step-up). Prophylactic antibiotic ไม่แนะนำ แต่ให้เมื่อมีการติดเชื้อยืนยัน.", "id": "set3-40"}, {"topic": "GI/Hepatology", "q": "A patient presents with hematochezia; after resuscitation, which is the most common cause of significant lower GI bleeding in older adults?", "choices": ["Diverticulosis", "Bleeding hemorrhoids", "An anal fissure", "Ischemic colitis", "Infectious colitis"], "ans": 0, "exp": "สาเหตุ LGIB ที่มีนัยสำคัญในผู้สูงอายุที่พบบ่อยคือ diverticulosis (และ angiodysplasia). ประเมินด้วย colonoscopy หลัง resuscitation; หา malignancy ด้วย.", "id": "set3-41"}, {"topic": "GI/Hepatology", "q": "A patient with cirrhosis has no prior variceal bleeding but endoscopy shows large esophageal varices. What is appropriate primary prophylaxis?", "choices": ["No treatment until the first bleed", "Non-selective beta-blocker (or endoscopic band ligation)", "A proton pump inhibitor", "Prophylactic antibiotics", "A TIPS procedure upfront"], "ans": 1, "exp": "Primary prophylaxis ของ variceal bleeding ใน large varices = non-selective beta-blocker (propranolol/carvedilol) หรือ endoscopic variceal ligation. TIPS ใช้ในรายเลือดออกซ้ำ/ดื้อ.", "id": "set3-42"}, {"topic": "GI/Hepatology", "q": "A patient has chronic epigastric pain, steatorrhea, and new diabetes with pancreatic calcifications. What is the diagnosis?", "choices": ["Acute pancreatitis", "Pancreatic carcinoma", "Chronic pancreatitis", "Gallstone disease", "Celiac disease"], "ans": 2, "exp": "ปวดเรื้อรัง + steatorrhea (exocrine insufficiency) + DM (endocrine) + pancreatic calcification = chronic pancreatitis (มักจากแอลกอฮอล์). รักษาด้วย pancreatic enzyme replacement, คุมปวด, งดเหล้า.", "id": "set3-43"}, {"topic": "GI/Hepatology", "q": "A patient with a right-lobe liver abscess and recent travel/dysentery, positive amoebic serology. What is the treatment?", "choices": ["Surgical resection of the abscess", "Ceftriaxone monotherapy", "Percutaneous drainage first-line always", "Metronidazole, then a luminal agent", "Albendazole therapy"], "ans": 3, "exp": "Amoebic liver abscess (Entamoeba histolytica, มัก lobe ขวา) รักษาด้วย metronidazole ตามด้วย luminal agent. Drainage สงวนไว้เมื่อใหญ่มาก/ไม่ตอบสนอง/สงสัย pyogenic.", "id": "set3-44"}, {"topic": "GI/Hepatology", "q": "A patient with obstructive jaundice has a dilated common bile duct with a stone on MRCP. What is the appropriate intervention?", "choices": ["Cholecystectomy performed first", "Observation without intervention", "Antibiotics alone without drainage", "A Whipple procedure", "ERCP with stone extraction"], "ans": 4, "exp": "Choledocholithiasis (นิ่วใน CBD) รักษาด้วย ERCP + sphincterotomy/stone extraction; ตามด้วย cholecystectomy ถ้ามี gallstone. ถ้ามี cholangitis ต้อง decompress ด่วน.", "id": "set3-45"}, {"topic": "GI/Hepatology", "q": "A patient develops acute severe abdominal pain out of proportion to exam findings, with a history of AF; lactate is rising. What is the diagnosis?", "choices": ["Acute mesenteric ischemia", "A perforated peptic ulcer", "Acute diverticulitis", "Acute pancreatitis", "Acute gastroenteritis"], "ans": 0, "exp": "ปวดท้องรุนแรงเกินกว่าตรวจพบ (pain out of proportion) + AF (embolic source) + lactate สูง = acute mesenteric ischemia (มัก SMA embolism). ต้อง CT angiography + revascularization ด่วน; delay = bowel necrosis.", "id": "set3-46"}, {"topic": "GI/Hepatology", "q": "A patient with Barrett esophagus is at increased risk of which malignancy?", "choices": ["Esophageal squamous cell carcinoma", "Esophageal adenocarcinoma", "Gastric lymphoma", "Small bowel carcinoid", "Pancreatic carcinoma"], "ans": 1, "exp": "Barrett esophagus (intestinal metaplasia จาก chronic GERD) เพิ่มเสี่ยง esophageal adenocarcinoma (lower third). เฝ้าระวังด้วย endoscopy + biopsy หา dysplasia.", "id": "set3-47"}, {"topic": "GI/Hepatology", "q": "A patient with jaundice has predominantly elevated unconjugated (indirect) bilirubin with normal LFTs and no hemolysis, worse with fasting/stress. What is the likely diagnosis?", "choices": ["Acute viral hepatitis", "Biliary obstruction", "Gilbert syndrome", "Established cirrhosis", "Pancreatic carcinoma"], "ans": 2, "exp": "Indirect hyperbilirubinemia ที่ LFT ปกติ ไม่มี hemolysis, เป็นมากเวลาอด/เครียด = Gilbert syndrome (UGT1A1 ลดลง) — benign ไม่ต้องรักษา.", "id": "set3-48"}, {"topic": "GI/Hepatology", "q": "A patient with alcohol use disorder takes paracetamol 8 tabs/day for a week and presents with markedly elevated transaminases (AST/ALT in thousands). What is the mechanism of injury?", "choices": ["Cholestatic injury from bile duct blockage", "A viral cytopathic effect on hepatocytes", "An autoimmune attack on the liver", "Hepatotoxic NAPQI accumulation with glutathione depletion", "Ischemic injury from hypoperfusion only"], "ans": 3, "exp": "Paracetamol เกินขนาด (ยิ่งในผู้ดื่มสุรา/อดอาหาร) สร้าง NAPQI มากขึ้นและ glutathione พร่อง → centrilobular hepatic necrosis (transaminase สูงเป็นพัน). รักษาด้วย N-acetylcysteine ตาม nomogram/เร็วที่สุด. (แนวข้อสอบ NLE2)", "id": "set3-49"}, {"topic": "GI/Hepatology", "q": "A patient presents with acute liver failure from paracetamol overdose. What is the specific antidote?", "choices": ["Naloxone", "Flumazenil", "Vitamin K", "Fomepizole", "N-acetylcysteine"], "ans": 4, "exp": "Paracetamol toxicity รักษาด้วย N-acetylcysteine (เติม glutathione precursor) ยิ่งให้เร็วยิ่งดี (ภายใน 8 ชม.). ประเมินด้วย paracetamol level + Rumack-Matthew nomogram; ดู King's College criteria สำหรับ transplant.", "id": "set3-50"}, {"topic": "GI/Hepatology", "q": "A patient has chronic constipation alternating with diarrhea, abdominal pain relieved by defecation, and normal investigations with no alarm features. What is the diagnosis?", "choices": ["Irritable bowel syndrome", "Colorectal cancer", "Ulcerative colitis", "Celiac disease", "Diverticulitis"], "ans": 0, "exp": "ปวดท้องเรื้อรังสัมพันธ์การขับถ่าย + เปลี่ยนความถี่/ลักษณะอุจจาระ โดยไม่มี alarm feature และตรวจปกติ = irritable bowel syndrome (Rome criteria). รักษาตามอาการ + diet (low-FODMAP) + ให้ความมั่นใจ.", "id": "set3-51"}, {"topic": "Hematology", "q": "A patient has microcytic hypochromic anemia with low ferritin and high RDW. What is the diagnosis and next step?", "choices": ["Thalassemia trait; do hemoglobin typing", "Iron deficiency anemia; find the source of blood loss", "Anemia of chronic disease; treat inflammation", "Sideroblastic anemia; give pyridoxine (B6)", "Lead poisoning; start chelation therapy"], "ans": 1, "exp": "Microcytic + ferritin ต่ำ = iron deficiency anemia. ในผู้ใหญ่ต้องหาสาเหตุเสียเลือด (GI → endoscopy; menorrhagia ในหญิง). รักษาด้วย ferrous + แก้สาเหตุ.", "id": "set3-52"}, {"topic": "Hematology", "q": "A Southeast Asian woman has microcytic anemia with NORMAL ferritin, target cells, basophilic stippling, and 'golf ball' inclusions on brilliant cresyl blue stain. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Hereditary spherocytosis", "Hemoglobin H disease", "Megaloblastic anemia", "Autoimmune hemolytic anemia"], "ans": 2, "exp": "Microcytic ที่ ferritin ปกติ + target cell + HbH inclusion (golf ball ด้วย supravital stain) = Hemoglobin H disease (alpha-thalassemia, 3-gene deletion). ห้ามให้ธาตุเหล็กพร่ำเพรื่อ. (แนวข้อสอบ NLE2)", "id": "set3-53"}, {"topic": "Hematology", "q": "How can iron deficiency anemia be distinguished from thalassemia trait when both are microcytic?", "choices": ["The MCV value on its own", "The reticulocyte count on its own", "The total white cell count", "RDW and ferritin (low in IDA, normal/high in thalassemia)", "The platelet count"], "ans": 3, "exp": "IDA: ferritin ต่ำ, RDW กว้าง, Mentzer index (MCV/RBC) > 13. Thalassemia trait: ferritin ปกติ/สูง, RDW ปกติ, RBC count สูง, Mentzer < 13, ยืนยันด้วย Hb typing.", "id": "set3-54"}, {"topic": "Hematology", "q": "A patient with rheumatoid arthritis has normocytic anemia, low serum iron, low TIBC, and high ferritin. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Thalassemia trait", "Hemolytic anemia", "Vitamin B12 deficiency", "Anemia of chronic disease"], "ans": 4, "exp": "Anemia of chronic disease/inflammation: iron ต่ำ, TIBC ต่ำ, ferritin สูง (acute phase, hepcidin สูง). ต่างจาก IDA ที่ TIBC สูง ferritin ต่ำ. รักษาที่โรคต้นเหตุ.", "id": "set3-55"}, {"topic": "Hematology", "q": "A patient has macrocytic anemia with hypersegmented neutrophils and neurological symptoms (paresthesia, ataxia). What is the deficiency?", "choices": ["Vitamin B12 (cobalamin)", "Folate (vitamin B9)", "Iron", "Vitamin C", "Vitamin K"], "ans": 0, "exp": "Macrocytic + hypersegmented neutrophils + neuro (subacute combined degeneration) = B12 deficiency. Folate deficiency ให้ภาพ megaloblastic เหมือนกันแต่ไม่มี neuro. ให้ B12 ก่อน folate เพื่อไม่บดบัง neuro.", "id": "set3-56"}, {"topic": "Hematology", "q": "A patient of Thai descent develops acute hemolysis after taking an antimalarial or eating fava beans; blood smear shows bite cells and Heinz bodies. What is the diagnosis?", "choices": ["Hereditary spherocytosis", "G6PD deficiency", "Autoimmune hemolytic anemia", "Thalassemia", "Sickle cell disease"], "ans": 1, "exp": "Hemolysis หลังยา/ถั่วปากอ้า/ติดเชื้อ + bite cells + Heinz bodies (X-linked) = G6PD deficiency (พบบ่อยในไทย). หลีกเลี่ยง oxidative triggers; ตรวจ G6PD level หลัง acute episode (อาจปกติลวงช่วง hemolysis).", "id": "set3-57"}, {"topic": "Hematology", "q": "A patient has anemia with high reticulocytes, high LDH, high indirect bilirubin, low haptoglobin, and a positive direct Coombs test. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Thalassemia trait", "Autoimmune hemolytic anemia", "Aplastic anemia", "Anemia of chronic disease"], "ans": 2, "exp": "Hemolysis markers (retic สูง, LDH สูง, indirect bili สูง, haptoglobin ต่ำ) + direct Coombs positive = autoimmune hemolytic anemia. Warm (IgG) vs cold (IgM). รักษา warm AIHA ด้วย corticosteroid. (แนวข้อสอบ NLE2)", "id": "set3-58"}, {"topic": "Hematology", "q": "A patient with anemia has spherocytes on smear, a negative Coombs test, splenomegaly, and a family history; osmotic fragility is increased. What is the diagnosis?", "choices": ["Autoimmune hemolytic anemia", "G6PD deficiency", "Thalassemia", "Hereditary spherocytosis", "Sickle cell disease"], "ans": 3, "exp": "Spherocytes + Coombs negative + ประวัติครอบครัว + osmotic fragility เพิ่ม = hereditary spherocytosis (membrane defect). ต่างจาก AIHA (Coombs positive). รักษา folate ± splenectomy ในรายรุนแรง.", "id": "set3-59"}, {"topic": "Hematology", "q": "A patient receiving packed red cells develops fever, chills, back pain, hypotension, and dark urine 15 minutes into transfusion. What is the diagnosis and immediate action?", "choices": ["Febrile non-hemolytic reaction; slow the rate", "TACO fluid overload; give a diuretic", "Allergic reaction; give an antihistamine", "TRALI; support with ventilation", "Acute hemolytic reaction (ABO mismatch); stop transfusion now"], "ans": 4, "exp": "อาการเฉียบพลัน (ไข้ ปวดหลัง hypotension hemoglobinuria) = acute hemolytic transfusion reaction (ABO incompatibility). หยุดให้เลือดทันที, IV fluid รักษาไต, ตรวจซ้ำ. (แนวข้อสอบ NLE2)", "id": "set3-60"}, {"topic": "Hematology", "q": "A patient develops dyspnea and bilateral pulmonary infiltrates within 6 hours of transfusion, with normal cardiac filling. What is the diagnosis?", "choices": ["Transfusion-related acute lung injury (TRALI)", "Transfusion-associated circulatory overload", "Anaphylactic reaction", "Acute hemolytic reaction", "Febrile non-hemolytic reaction"], "ans": 0, "exp": "Non-cardiogenic pulmonary edema ภายใน 6 ชม.หลังให้เลือด (donor antibody ต่อ leukocyte) = TRALI. ต่างจาก TACO (volume overload, cardiogenic). รักษาแบบ supportive/ventilation; TACO ใช้ diuretic.", "id": "set3-61"}, {"topic": "Hematology", "q": "A stable patient needs platelet transfusion prophylaxis. At what platelet count is prophylactic transfusion generally indicated?", "choices": ["Below 100,000 platelets", "Below 10,000 (or < 50,000 if bleeding/procedure)", "Below 50,000 platelets", "Below 150,000 platelets", "Never given prophylactically"], "ans": 1, "exp": "Platelet transfusion เชิงป้องกันเมื่อ < 10,000 (เสี่ยงเลือดออกเอง); ให้ที่ < 50,000 ถ้ามีเลือดออก/ก่อนหัตถการ; < 100,000 สำหรับ neurosurgery/ตา.", "id": "set3-62"}, {"topic": "Hematology", "q": "A patient has isolated thrombocytopenia with mucocutaneous bleeding, normal WBC/Hb, and a normal-sized spleen; other causes excluded. What is the diagnosis?", "choices": ["Thrombotic thrombocytopenic purpura", "Disseminated intravascular coagulation", "Immune thrombocytopenic purpura (ITP)", "Aplastic anemia", "Acute leukemia"], "ans": 2, "exp": "Isolated thrombocytopenia (line อื่นปกติ) + mucocutaneous bleeding + exclude สาเหตุอื่น = ITP (autoimmune). รักษาเมื่อเลือดออก/นับต่ำมากด้วย corticosteroid/IVIG.", "id": "set3-63"}, {"topic": "Hematology", "q": "A patient with sepsis has bleeding from venipuncture sites; labs show prolonged PT/aPTT, low fibrinogen, high D-dimer, low platelets, and schistocytes. What is the diagnosis?", "choices": ["Immune thrombocytopenic purpura", "Thrombotic thrombocytopenic purpura", "Hemophilia", "Disseminated intravascular coagulation (DIC)", "Vitamin K deficiency"], "ans": 3, "exp": "Consumptive coagulopathy (PT/aPTT ยาว, fibrinogen ต่ำ, D-dimer สูง, platelet ต่ำ, schistocyte) ในภาวะ sepsis = DIC. รักษาที่สาเหตุ + component (FFP/cryo/platelet) ตามการเลือดออก.", "id": "set3-64"}, {"topic": "Hematology", "q": "A patient has microangiopathic hemolytic anemia, thrombocytopenia, fever, neurologic changes, and renal involvement with very low ADAMTS13. What is the treatment?", "choices": ["Platelet transfusion", "Corticosteroids alone", "Heparin anticoagulation", "Observation only", "Plasma exchange (plasmapheresis)"], "ans": 4, "exp": "TTP (pentad: MAHA + thrombocytopenia + fever + neuro + renal; ADAMTS13 ต่ำ) รักษาด้วย plasma exchange ด่วน ± steroid/rituximab. ห้ามให้ platelet transfusion (ยกเว้นเลือดออกคุกคามชีวิต) เพราะเพิ่ม thrombosis.", "id": "set3-65"}, {"topic": "Hematology", "q": "A boy has recurrent hemarthrosis and deep muscle bleeds; aPTT is prolonged, PT normal, and factor VIII is low. What is the diagnosis?", "choices": ["Hemophilia A", "von Willebrand disease", "Vitamin K deficiency", "Immune thrombocytopenia", "Hemophilia B"], "ans": 0, "exp": "Hemarthrosis/deep bleeding + isolated prolonged aPTT + factor VIII ต่ำ (X-linked) = hemophilia A. Factor IX ต่ำ = hemophilia B. รักษาด้วย factor replacement.", "id": "set3-66"}, {"topic": "Hematology", "q": "A patient has mucosal/skin bleeding, prolonged bleeding time, prolonged aPTT, and low ristocetin cofactor activity. What is the diagnosis?", "choices": ["Hemophilia A", "von Willebrand disease", "Immune thrombocytopenia", "Disseminated intravascular coagulation", "Glanzmann thrombasthenia"], "ans": 1, "exp": "vWD (โรคเลือดออกทางพันธุกรรมที่พบบ่อยสุด): mucocutaneous bleeding + platelet-type + aPTT อาจยาว (vWF พา factor VIII) + ristocetin cofactor ต่ำ. รักษา desmopressin/vWF concentrate.", "id": "set3-67"}, {"topic": "Hematology", "q": "A patient on heparin develops a drop in platelets 5–10 days after starting, with new thrombosis. What is the diagnosis and action?", "choices": ["DIC; give more heparin", "ITP; start corticosteroids", "HIT; stop heparin and start a non-heparin anticoagulant", "TTP; begin plasma exchange", "Normal finding; continue heparin"], "ans": 2, "exp": "HIT (platelet ลด > 50% วันที่ 5–10 + thrombosis, anti-PF4 antibody) — หยุด heparin ทุกชนิดทันที และเปลี่ยนเป็น non-heparin anticoagulant (argatroban/fondaparinux/DOAC). ห้ามให้ platelet/warfarin เดี่ยวช่วงเฉียบพลัน.", "id": "set3-68"}, {"topic": "Hematology", "q": "A patient has prolonged PT with normal aPTT and bleeding; this improves with vitamin K. Which factor is affected earliest?", "choices": ["Factor VIII", "Factor IX", "Fibrinogen", "Factor VII (extrinsic pathway)", "Factor XIII"], "ans": 3, "exp": "Isolated prolonged PT = extrinsic pathway (factor VII มี half-life สั้นสุด จึงเสียก่อนใน vitamin K deficiency/warfarin/liver disease). aPTT = intrinsic (VIII, IX).", "id": "set3-69"}, {"topic": "Hematology", "q": "An elderly patient has fatigue, bone pain, anemia, hypercalcemia, renal failure, and lytic bone lesions. Serum protein electrophoresis shows an M-spike. What is the diagnosis?", "choices": ["Chronic lymphocytic leukemia", "Lymphoma", "Metastatic carcinoma", "MGUS", "Multiple myeloma"], "ans": 4, "exp": "CRAB (hyperCalcemia, Renal failure, Anemia, Bone lytic lesions) + M-protein + plasma cells = multiple myeloma. ตรวจ serum/urine electrophoresis, free light chain, bone marrow. (แนวข้อสอบ NLE2)", "id": "set3-70"}, {"topic": "Hematology", "q": "In multiple myeloma, urine testing classically reveals which protein?", "choices": ["Bence Jones protein (free light chains)", "Albumin", "Myoglobin", "Hemoglobin", "Transferrin"], "ans": 0, "exp": "Multiple myeloma หลั่ง free light chains ที่ตรวจพบในปัสสาวะเป็น Bence Jones protein (urine dipstick มัก negative เพราะจับ albumin เป็นหลัก → ต้อง electrophoresis). (แนวข้อสอบ NLE2)", "id": "set3-71"}, {"topic": "Hematology", "q": "A young adult has painless cervical lymphadenopathy, fever, night sweats, weight loss, and Reed-Sternberg cells on biopsy. What is the diagnosis?", "choices": ["Non-Hodgkin lymphoma", "Hodgkin lymphoma", "Tuberculous lymphadenitis", "Chronic lymphocytic leukemia", "Reactive lymphadenopathy"], "ans": 1, "exp": "Painless lymphadenopathy + B symptoms + Reed-Sternberg cells = Hodgkin lymphoma (แพร่แบบต่อเนื่อง, พยากรณ์ดี). Staging ด้วย PET/CT; รักษา chemo (ABVD) ± RT.", "id": "set3-72"}, {"topic": "Hematology", "q": "A child presents with pallor, bruising, fever, and bone pain; blood shows > 20% lymphoblasts. What is the most likely diagnosis?", "choices": ["Acute myeloid leukemia", "Chronic myeloid leukemia", "Acute lymphoblastic leukemia", "Aplastic anemia", "Immune thrombocytopenia"], "ans": 2, "exp": "เด็ก + bone marrow failure (ซีด/เลือดออก/ติดเชื้อ) + lymphoblasts > 20% = acute lymphoblastic leukemia (ALL, พบบ่อยในเด็ก). AML พบผู้ใหญ่ (Auer rods). เป็นภาวะเร่งด่วน.", "id": "set3-73"}, {"topic": "Hematology", "q": "An adult with fatigue and gum infiltration has a bone marrow with myeloblasts containing Auer rods. What is the diagnosis?", "choices": ["Acute lymphoblastic leukemia", "Chronic myeloid leukemia", "Chronic lymphocytic leukemia", "Acute myeloid leukemia", "Myelofibrosis"], "ans": 3, "exp": "Auer rods ใน myeloblasts = acute myeloid leukemia. APL (AML-M3, t(15;17)) เสี่ยง DIC รักษาด้วย ATRA. เป็นภาวะเร่งด่วน.", "id": "set3-74"}, {"topic": "Hematology", "q": "A middle-aged patient has marked leukocytosis with all granulocyte stages and a Philadelphia chromosome (BCR-ABL). What is the treatment?", "choices": ["Cytotoxic chemotherapy alone", "Splenectomy", "Observation only", "Corticosteroids", "Tyrosine kinase inhibitor (imatinib)"], "ans": 4, "exp": "CML (Philadelphia chromosome, BCR-ABL, leukocytosis + all maturation stages, basophilia, splenomegaly) รักษาด้วย tyrosine kinase inhibitor (imatinib/dasatinib) — เปลี่ยน prognosis อย่างมาก.", "id": "set3-75"}, {"topic": "Hematology", "q": "An elderly patient has lymphocytosis with smudge cells on smear and mature-appearing lymphocytes. What is the diagnosis?", "choices": ["Chronic lymphocytic leukemia", "Acute lymphoblastic leukemia", "Chronic myeloid leukemia", "Hodgkin lymphoma", "Reactive lymphocytosis"], "ans": 0, "exp": "ผู้สูงอายุ + mature lymphocytosis + smudge cells = chronic lymphocytic leukemia (CLL). มักดำเนินโรคช้า; รักษาเมื่อมีอาการ/cytopenia/rapid progression.", "id": "set3-76"}, {"topic": "Hematology", "q": "A patient with polycythemia has elevated hematocrit, low erythropoietin, splenomegaly, and a JAK2 mutation. What is the diagnosis and a key treatment?", "choices": ["Secondary polycythemia; give oxygen", "Polycythemia vera; phlebotomy plus aspirin", "Relative polycythemia; rehydrate", "Dehydration; give IV fluids", "CML; start imatinib"], "ans": 1, "exp": "Polycythemia vera (JAK2 V617F, EPO ต่ำ, splenomegaly) รักษาด้วย phlebotomy (เป้า Hct < 45%) + low-dose aspirin ± hydroxyurea ในรายเสี่ยงสูง. เสี่ยง thrombosis.", "id": "set3-77"}, {"topic": "Hematology", "q": "A patient with cancer on chemotherapy develops fever and an absolute neutrophil count < 500. What is the immediate management?", "choices": ["Oral antibiotics the next day", "G-CSF alone without antibiotics", "Empiric broad-spectrum IV antibiotics within 1 hour", "Antifungal therapy alone", "Observation without treatment"], "ans": 2, "exp": "Febrile neutropenia เป็นภาวะฉุกเฉิน — ให้ empiric broad-spectrum IV antibiotic (คลุม Pseudomonas เช่น piperacillin-tazobactam/cefepime/carbapenem) ภายใน 1 ชม.หลังเจาะ culture.", "id": "set3-78"}, {"topic": "Hematology", "q": "A patient starting chemotherapy for a bulky lymphoma develops hyperkalemia, hyperphosphatemia, hyperuricemia, and hypocalcemia. What is the diagnosis and prevention?", "choices": ["DIC; give heparin", "SIADH; restrict fluids", "Hypercalcemia; give a bisphosphonate", "Tumor lysis syndrome; hydration + allopurinol/rasburicase", "Sepsis; give antibiotics"], "ans": 3, "exp": "Tumor lysis syndrome (high K/PO4/uric acid, low Ca) หลัง chemo tumor ใหญ่. ป้องกัน/รักษาด้วย aggressive hydration + allopurinol (หรือ rasburicase ในรายเสี่ยงสูง) + แก้ electrolyte.", "id": "set3-79"}, {"topic": "Hematology", "q": "A patient with pancytopenia has a hypocellular bone marrow with no abnormal cells or fibrosis. What is the diagnosis?", "choices": ["Acute leukemia", "Myelodysplastic syndrome", "Myelofibrosis", "Megaloblastic anemia", "Aplastic anemia"], "ans": 4, "exp": "Pancytopenia + hypocellular marrow (ไม่มี blast/fibrosis) = aplastic anemia (idiopathic/ยา/ไวรัส/toxin). รักษาด้วย immunosuppression (ATG+ciclosporin) หรือ stem cell transplant; supportive transfusion.", "id": "set3-80"}, {"topic": "Hematology", "q": "An older patient has macrocytic anemia and cytopenias with dysplastic cells and ring sideroblasts in marrow. What is the diagnosis?", "choices": ["Myelodysplastic syndrome", "Aplastic anemia", "Acute myeloid leukemia", "Vitamin B12 deficiency", "Thalassemia"], "ans": 0, "exp": "Cytopenia + dysplasia (± ring sideroblasts) ในผู้สูงอายุ = myelodysplastic syndrome (clonal, เสี่ยงเปลี่ยนเป็น AML). รักษาตามความเสี่ยง (supportive, ESA, hypomethylating agent, transplant).", "id": "set3-81"}, {"topic": "Hematology", "q": "A pregnant woman with unprovoked DVT needs anticoagulation. Which agent is preferred?", "choices": ["Warfarin", "Low-molecular-weight heparin", "A direct oral anticoagulant", "Aspirin", "No treatment"], "ans": 1, "exp": "ในการตั้งครรภ์ใช้ LMWH (ไม่ผ่านรก, ปลอดภัย). Warfarin เป็น teratogen; DOAC หลีกเลี่ยงในการตั้งครรภ์/ให้นม (ข้อมูลจำกัด).", "id": "set3-82"}, {"topic": "Hematology", "q": "A patient with a first provoked DVT (after surgery, now resolved) should receive anticoagulation for how long?", "choices": ["For about 6 weeks", "Indefinitely", "For about 3 months", "For 1 year in all cases", "No treatment needed"], "ans": 2, "exp": "VTE ที่ provoked จากปัจจัยชั่วคราว (ผ่าตัด) รักษา 3 เดือน. Unprovoked หรือ persistent risk (มะเร็ง/thrombophilia) พิจารณา anticoagulation ต่อเนื่องระยะยาว.", "id": "set3-83"}, {"topic": "Hematology", "q": "A patient with active cancer develops VTE. Which anticoagulant class has strong evidence and is commonly preferred?", "choices": ["Warfarin", "Aspirin", "No treatment", "LMWH or a DOAC (edoxaban/apixaban/rivaroxaban)", "An IVC filter alone"], "ans": 3, "exp": "Cancer-associated VTE ใช้ LMWH หรือ DOAC (edoxaban/apixaban/rivaroxaban) ได้ผลดีกว่า warfarin. ระวัง DOAC ใน GI/GU malignancy (เลือดออก) — เลือกตามผู้ป่วย.", "id": "set3-84"}, {"topic": "Hematology", "q": "A patient with recurrent unprovoked thromboses and miscarriages has prolonged aPTT that does not correct with mixing, plus positive anticardiolipin antibodies. What is the diagnosis?", "choices": ["Hemophilia", "von Willebrand disease", "Disseminated intravascular coagulation", "Protein C deficiency", "Antiphospholipid syndrome"], "ans": 4, "exp": "Recurrent thrombosis + pregnancy loss + lupus anticoagulant (aPTT ไม่ correct เมื่อ mix) + anticardiolipin/anti-β2GP1 = antiphospholipid syndrome. รักษาด้วย anticoagulation (warfarin) ระยะยาว.", "id": "set3-85"}, {"topic": "Hematology", "q": "A patient has anemia, jaundice, splenomegaly, and a peripheral smear with sickle-shaped cells during a painful crisis. What is the mainstay of acute management?", "choices": ["Analgesia, hydration, oxygen, and treat the precipitant", "Iron supplementation", "Immediate splenectomy", "Exchange transfusion for all pain", "Iron chelation therapy"], "ans": 0, "exp": "Sickle cell vaso-occlusive crisis: analgesia (มัก opioid), hydration, oxygen, รักษา infection/precipitant. Hydroxyurea ลดความถี่ crisis; exchange transfusion ในภาวะรุนแรง (stroke, acute chest, priapism).", "id": "set3-86"}, {"topic": "Hematology", "q": "A blood smear shows target cells, and Hb electrophoresis shows increased HbA2 in a mildly microcytic patient. What is the diagnosis?", "choices": ["Iron deficiency anemia", "Beta-thalassemia trait", "Alpha-thalassemia", "Sideroblastic anemia", "Lead poisoning"], "ans": 1, "exp": "Microcytosis เล็กน้อย + target cells + HbA2 สูง (> 3.5%) = beta-thalassemia trait. RBC count มักสูง, ferritin ปกติ. ให้คำปรึกษาพันธุกรรม; ห้ามให้ธาตุเหล็กถ้าไม่ขาดจริง.", "id": "set3-87"}, {"topic": "Hematology", "q": "A patient needs urgent warfarin reversal due to major bleeding. What is appropriate?", "choices": ["Vitamin K alone", "Fresh frozen plasma alone, slowly", "Prothrombin complex concentrate (PCC) + IV vitamin K", "Protamine sulfate", "Platelet transfusion"], "ans": 2, "exp": "Major bleeding on warfarin: ให้ 4-factor prothrombin complex concentrate (PCC) + IV vitamin K (FFP ถ้าไม่มี PCC). Protamine ใช้ reverse heparin; idarucizumab reverse dabigatran; andexanet reverse anti-Xa DOAC.", "id": "set3-88"}, {"topic": "Hematology", "q": "A patient has anemia with a low reticulocyte count and normal MCV. What does the low reticulocyte indicate?", "choices": ["An adequate marrow response", "Active ongoing hemolysis", "Recent acute blood loss", "Inadequate marrow production (hypoproliferative)", "Iron overload"], "ans": 3, "exp": "Reticulocyte count ต่ำในภาวะ anemia = marrow ตอบสนองไม่พอ (hypoproliferative: CKD/EPO ต่ำ, ACD, aplastic, marrow infiltration). Reticulocyte สูง = hemolysis/blood loss (marrow ตอบสนองดี).", "id": "set3-89"}, {"topic": "Hematology", "q": "A patient develops warm autoimmune hemolytic anemia. What is the first-line treatment?", "choices": ["Splenectomy", "Rituximab first-line", "Plasma exchange", "Iron supplementation", "Corticosteroids"], "ans": 4, "exp": "Warm AIHA (IgG, spherocytes, direct Coombs positive) รักษา first-line ด้วย corticosteroid; rituximab/splenectomy เป็น second-line. หา secondary cause (lymphoma, SLE, ยา).", "id": "set3-90"}, {"topic": "Hematology", "q": "A patient has cold agglutinin disease with hemolysis worse in cold. Which antibody type mediates this?", "choices": ["IgM (cold antibody)", "IgG (warm antibody)", "IgA antibody", "IgE antibody", "IgD antibody"], "ans": 0, "exp": "Cold agglutinin disease เกิดจาก IgM ที่จับ RBC ในอุณหภูมิเย็น → complement-mediated hemolysis. สัมพันธ์ Mycoplasma/EBV/lymphoma. รักษาหลีกเลี่ยงความเย็น + รักษาสาเหตุ (steroid ได้ผลน้อยกว่า warm).", "id": "set3-91"}, {"topic": "Hematology", "q": "A patient has a normocytic anemia, rouleaux formation, elevated ESR, and back pain. Which malignancy should be suspected?", "choices": ["Acute leukemia", "Multiple myeloma", "Lymphoma", "Polycythemia vera", "Chronic myeloid leukemia"], "ans": 1, "exp": "Rouleaux (จาก M-protein) + ESR สูง + back/bone pain + anemia = multiple myeloma. ตรวจ serum/urine protein electrophoresis + free light chains + skeletal survey/MRI.", "id": "set3-92"}, {"topic": "Hematology", "q": "A patient with splenomegaly and a 'dry tap' on bone marrow aspiration with teardrop cells on smear likely has:", "choices": ["Chronic lymphocytic leukemia", "Immune thrombocytopenia", "Primary myelofibrosis", "Iron deficiency anemia", "Aplastic anemia"], "ans": 2, "exp": "Dry tap (marrow fibrosis) + teardrop (dacrocytes) + splenomegaly (extramedullary hematopoiesis) = primary myelofibrosis (JAK2). รักษา JAK inhibitor (ruxolitinib), supportive, transplant ในรายเหมาะสม.", "id": "set3-93"}, {"topic": "Hematology", "q": "A patient develops petechiae and thrombocytopenia after starting a new drug; counts recover after stopping it. What is the mechanism?", "choices": ["Aplastic anemia", "Disseminated intravascular coagulation", "Thrombotic thrombocytopenic purpura", "Drug-induced immune thrombocytopenia", "Splenic sequestration"], "ans": 3, "exp": "Thrombocytopenia ที่ฟื้นหลังหยุดยา = drug-induced immune thrombocytopenia (เช่น quinine, sulfa, vancomycin, heparin). จัดการโดยหยุดยาต้นเหตุ.", "id": "set3-94"}, {"topic": "Hematology", "q": "A patient with iron deficiency anemia is treated with oral iron. When should the reticulocyte count begin to rise if therapy is effective?", "choices": ["Within a few hours", "Only after 3 months", "It never rises at all", "Only with IV iron", "Within about 5–7 days"], "ans": 4, "exp": "หลังเริ่ม iron ที่ได้ผล reticulocyte จะเริ่มขึ้นภายใน ~5–7 วัน และ Hb ค่อยขึ้นในสัปดาห์ถัดไป; ให้ต่อ 3–6 เดือนเพื่อเติม iron store. ถ้าไม่ตอบสนองให้ทบทวนการวินิจฉัย/การดูดซึม/เลือดออกต่อเนื่อง.", "id": "set3-95"}, {"topic": "Hematology", "q": "Which vaccination timing is critical for a patient scheduled for elective splenectomy?", "choices": ["Encapsulated-organism vaccines ≥ 2 weeks before surgery", "Give the vaccines only after surgery", "No vaccines are needed at all", "Only the influenza vaccine is needed", "Only after a subsequent infection"], "ans": 0, "exp": "ก่อน splenectomy ควรให้วัคซีนต่อ encapsulated organisms (pneumococcus, Hib, meningococcus) อย่างน้อย 2 สัปดาห์ก่อนผ่าตัด เพื่อลดเสี่ยง overwhelming post-splenectomy infection; ให้ prophylactic antibiotic ในบางราย.", "id": "set3-96"}, {"topic": "Hematology", "q": "A patient has a hemoglobin of 6 g/dL with active bleeding and hemodynamic instability. What is the most appropriate transfusion decision?", "choices": ["Withhold transfusion despite instability", "Transfuse packed red cells to restore oxygen delivery", "Give platelets only, not red cells", "Give fresh frozen plasma only", "Give crystalloid fluids only"], "ans": 1, "exp": "Anemia รุนแรงที่มีเลือดออก + hemodynamic instability = ให้ PRC เพื่อเพิ่ม oxygen-carrying capacity (พร้อม resuscitation + หยุดเลือด). เกณฑ์ restrictive (Hb 7) ใช้กับผู้ป่วยคงที่.", "id": "set3-97"}, {"topic": "Hematology", "q": "A patient has isolated prolonged aPTT that fully corrects on a 1:1 mixing study. What does this suggest?", "choices": ["A factor inhibitor is present", "A lupus anticoagulant is present", "A factor deficiency (e.g., VIII, IX, XI)", "Disseminated intravascular coagulation", "A normal laboratory variant"], "ans": 2, "exp": "aPTT ยาวที่ correct เมื่อ mix 1:1 = factor deficiency (เติม factor จาก normal plasma แล้วปกติ). ถ้าไม่ correct = inhibitor (เช่น lupus anticoagulant หรือ factor inhibitor).", "id": "set3-98"}, {"topic": "Hematology", "q": "A patient with beta-thalassemia major on chronic transfusions is at risk of which complication requiring monitoring?", "choices": ["Iron deficiency anemia", "Vitamin B12 excess", "A bleeding tendency", "Iron overload (hemosiderosis) requiring chelation", "Polycythemia"], "ans": 3, "exp": "Thalassemia major ที่รับเลือดเรื้อรังเสี่ยง iron overload (หัวใจ/ตับ/ต่อมไร้ท่อ) — ต้องติดตาม ferritin/MRI T2* และให้ iron chelation (deferasirox/deferoxamine).", "id": "set3-99"}, {"topic": "Hematology", "q": "A patient has anemia and is found to have colon cancer as the bleeding source. Which anemia morphology is most expected?", "choices": ["A macrocytic pattern", "Normocytic with high reticulocytes", "A megaloblastic pattern", "A hemolytic pattern", "Microcytic hypochromic (iron deficiency)"], "ans": 4, "exp": "เลือดออกเรื้อรังจาก colon cancer → chronic blood loss → iron deficiency anemia (microcytic hypochromic). IDA ในผู้ใหญ่ต้องหาสาเหตุ GI เสมอ.", "id": "set3-100"}]}, {"id": "set4", "title": "ชุดที่ 4 — Infectious Disease + Rheumatology", "questions": [{"topic": "Infectious disease", "q": "A patient with suspected sepsis is being managed. According to current bundles, which should be done first alongside cultures?", "choices": ["Blood cultures then early antibiotics and fluids", "Delay all antibiotics until cultures have resulted", "Give only antipyretics and reassess later", "Start vasopressors before any fluid resuscitation", "Give corticosteroids to every septic patient"], "ans": 0, "exp": "Sepsis: เจาะ hemoculture ก่อน แล้วให้ empiric broad-spectrum antibiotic เร็ว (ภายใน 1 ชม.ใน septic shock) + IV crystalloid + วัด lactate + source control. SSC 2026 เน้น balanced crystalloid และประเมิน fluid responsiveness.", "id": "set4-1"}, {"topic": "Infectious disease", "q": "A febrile patient in septic shock remains hypotensive after adequate fluid resuscitation. What is the first-line vasopressor?", "choices": ["Dopamine", "Norepinephrine", "Epinephrine", "Phenylephrine", "Vasopressin alone"], "ans": 1, "exp": "Septic shock ที่ยัง hypotensive หลัง fluid ให้ norepinephrine เป็น first-line vasopressor (เป้า MAP ≥ 65). เพิ่ม vasopressin/epinephrine เป็นตัวที่สอง; SSC 2026 อนุญาตเริ่ม norepinephrine ทาง peripheral ได้.", "id": "set4-2"}, {"topic": "Infectious disease", "q": "A patient with fever, headache, neck stiffness, and photophobia has CSF with high neutrophils, high protein, and low glucose. What is the diagnosis and immediate treatment?", "choices": ["Viral meningitis; supportive care only", "Tuberculous meningitis; start anti-TB drugs", "Bacterial meningitis; ceftriaxone + vancomycin", "Fungal meningitis; give amphotericin B", "Migraine headache; give simple analgesia"], "ans": 2, "exp": "CSF neutrophil สูง + protein สูง + glucose ต่ำ = bacterial meningitis. ให้ empiric ceftriaxone + vancomycin (± ampicillin ถ้าเสี่ยง Listeria) + dexamethasone ก่อน/พร้อม ATB. อย่ารอผลถ้าต้องเลื่อน CT.", "id": "set4-3"}, {"topic": "Infectious disease", "q": "When should a CT head be performed before lumbar puncture in suspected meningitis?", "choices": ["In every case before a lumbar puncture", "It is never needed before a lumbar puncture", "Only when the patient is febrile", "Focal deficit, papilledema, or reduced GCS", "Only in pediatric patients"], "ans": 3, "exp": "ทำ CT ก่อน LP เมื่อมี focal deficit, papilledema, immunocompromised, seizure ใหม่, หรือ GCS ลด (เสี่ยง herniation). ในกรณีนี้อย่า delay antibiotic — ให้ ATB + dexamethasone ก่อนแล้วค่อย LP.", "id": "set4-4"}, {"topic": "Infectious disease", "q": "An HIV patient with CD4 count 120 should receive prophylaxis against which opportunistic infection?", "choices": ["Cryptococcus neoformans", "Mycobacterium avium complex", "Cytomegalovirus", "Toxoplasma gondii only", "Pneumocystis jirovecii (co-trimoxazole)"], "ans": 4, "exp": "CD4 < 200 → ให้ co-trimoxazole prophylaxis กัน PCP (และ toxoplasma เมื่อ < 100 + IgG positive). CD4 < 50 พิจารณา MAC prophylaxis (แนวทางปัจจุบันเน้นเริ่ม ART เร็วมากกว่า).", "id": "set4-5"}, {"topic": "Infectious disease", "q": "What is the recommended first-line antiretroviral regimen for most treatment-naive adults with HIV?", "choices": ["A dolutegravir-based regimen", "A zidovudine-based regimen", "Efavirenz plus two NRTIs only", "Protease inhibitor monotherapy", "No treatment until CD4 < 200"], "ans": 0, "exp": "First-line ART = dolutegravir (INSTI)-based เช่น TDF/3TC/DTG; เริ่มเร็ว (rapid start) โดยไม่รอ CD4. แนวคิด U=U. ระวัง DTG กับ antacid/Ca/Fe/Zn (เว้นระยะ).", "id": "set4-6"}, {"topic": "Infectious disease", "q": "A patient with HIV (CD4 50) has headache, fever, and a positive serum cryptococcal antigen with high opening pressure on LP. What is the treatment?", "choices": ["Fluconazole monotherapy alone", "Amphotericin B + flucytosine, then fluconazole", "Ceftriaxone as for bacterial meningitis", "Acyclovir as for viral meningitis", "Empiric anti-tuberculous therapy"], "ans": 1, "exp": "Cryptococcal meningitis ใน HIV: induction ด้วย amphotericin B + flucytosine แล้ว consolidation/maintenance fluconazole + จัดการ raised intracranial pressure (serial LP). เริ่ม ART หลังไปสักระยะเพื่อลด IRIS.", "id": "set4-7"}, {"topic": "Infectious disease", "q": "A returning traveler from an endemic area has cyclical fever, chills, and anemia; thick and thin blood films are ordered. What is the purpose of each film?", "choices": ["Both films give identical information", "The thick film is used only to speciate", "Thick film to detect, thin film to speciate", "The thin film is used only for detection", "Neither film is clinically useful"], "ans": 2, "exp": "Malaria: thick film (sensitive, ตรวจหาเชื้อ) + thin film (speciate + quantify parasitemia). P. falciparum รุนแรง (cerebral, ไตวาย, hypoglycemia) → artesunate IV. (แนวข้อสอบ NLE2)", "id": "set4-8"}, {"topic": "Infectious disease", "q": "A patient has severe P. falciparum malaria with impaired consciousness and high parasitemia. What is the treatment of choice?", "choices": ["Oral chloroquine", "Oral doxycycline", "Primaquine alone", "IV artesunate", "Supportive care only"], "ans": 3, "exp": "Severe falciparum malaria รักษาด้วย IV artesunate (ดีกว่า quinine) + supportive; ตามด้วย full oral ACT course. Primaquine ใช้กำจัด hypnozoite ใน vivax/ovale (ตรวจ G6PD ก่อน).", "id": "set4-9"}, {"topic": "Infectious disease", "q": "A rice-farmer presents with fever, severe calf myalgia, conjunctival suffusion, jaundice, and acute kidney injury after wading in floodwater. What is the diagnosis?", "choices": ["Dengue fever", "Scrub typhus", "Melioidosis", "Malaria", "Leptospirosis"], "ans": 4, "exp": "ประวัติลุยน้ำ/นา + ไข้ + ปวดน่อง + conjunctival suffusion + ตัวเหลือง + ไตวาย (Weil disease) = leptospirosis. รักษาด้วย penicillin/doxycycline/ceftriaxone; ระวัง Jarisch-Herxheimer.", "id": "set4-10"}, {"topic": "Infectious disease", "q": "A febrile patient from a rural area has an eschar (painless ulcer with black crust) and regional lymphadenopathy. What is the diagnosis and treatment?", "choices": ["Scrub typhus; give doxycycline", "Dengue; supportive care", "Leptospirosis; give penicillin", "Malaria; give artesunate", "Typhoid; give ceftriaxone"], "ans": 0, "exp": "ไข้ + eschar (แผลบุหรี่จี้) + lymphadenopathy = scrub typhus (Orientia tsutsugamushi). ตอบสนองเร็วต่อ doxycycline (azithromycin เป็นทางเลือก). Eschar เป็น clue สำคัญ.", "id": "set4-11"}, {"topic": "Infectious disease", "q": "A diabetic farmer from northeastern Thailand has community-acquired sepsis with multiple abscesses; culture grows a bipolar 'safety pin' gram-negative bacillus. What is the diagnosis?", "choices": ["Disseminated tuberculosis", "Melioidosis (Burkholderia pseudomallei)", "Leptospirosis", "Typhoid fever", "Systemic anthrax"], "ans": 1, "exp": "Melioidosis (Burkholderia pseudomallei, ดิน/น้ำอีสาน, เบาหวานเสี่ยง): sepsis + abscess หลายอวัยวะ, bipolar staining. รักษา intensive ด้วย ceftazidime/meropenem แล้ว eradication ด้วย co-trimoxazole นาน.", "id": "set4-12"}, {"topic": "Infectious disease", "q": "A patient has high fever for 5 days, retro-orbital pain, myalgia, and a positive tourniquet test with low WBC and platelets. During defervescence, what is the key concern?", "choices": ["Secondary bacterial superinfection", "A guaranteed uneventful recovery", "Plasma leakage, shock, and bleeding", "New-onset hyperglycemia", "An obstructing renal stone"], "ans": 2, "exp": "Dengue: ช่วงไข้ลด (defervescence, วันที่ 4–6) เป็น critical phase — เสี่ยง plasma leakage/shock และเลือดออก. เฝ้าระวัง warning signs, ให้ isotonic fluid ระวัง over/under, ห้าม NSAID/ASA.", "id": "set4-13"}, {"topic": "Infectious disease", "q": "Which are recognized dengue warning signs indicating risk of progression to severe disease?", "choices": ["An isolated skin rash only", "A high fever on its own", "A headache on its own", "Warning signs of severe dengue", "Muscle aches on their own"], "ans": 3, "exp": "Dengue warning signs (WHO): ปวดท้อง/กดเจ็บ, อาเจียนต่อเนื่อง, มีน้ำรั่ว, เลือดออกเยื่อบุ, ซึม/กระสับกระส่าย, ตับโต > 2 ซม., Hct เพิ่ม + platelet ลดเร็ว → ต้อง admit/เฝ้าใกล้ชิด.", "id": "set4-14"}, {"topic": "Infectious disease", "q": "A patient has sustained high fever, relative bradycardia, abdominal pain, and rose spots after travel; blood culture grows Salmonella Typhi. What is the treatment?", "choices": ["Metronidazole", "Vancomycin", "Doxycycline", "Penicillin", "Ceftriaxone or azithromycin"], "ans": 4, "exp": "Enteric (typhoid) fever: ไข้สูงต่อเนื่อง + relative bradycardia + rose spots; hemoculture ยืนยัน. รักษาด้วย ceftriaxone หรือ azithromycin (ระวัง fluoroquinolone resistance).", "id": "set4-15"}, {"topic": "Infectious disease", "q": "A young adult has fever, severe joint pain in the hands/wrists, maculopapular rash after mosquito exposure; the arthralgia is debilitating and prolonged. What is the most likely diagnosis?", "choices": ["Chikungunya", "Dengue fever", "Malaria", "Zika virus", "Typhoid fever"], "ans": 0, "exp": "ไข้ + ปวดข้อรุนแรง (โดยเฉพาะข้อเล็ก) เด่นและยืดเยื้อ + ผื่น หลังยุงกัด = chikungunya. Dengue ปวดกล้ามเนื้อ/กระบอกตาเด่นกว่า; Zika มักอาการน้อย + ผื่น/เยื่อบุตาแดง. (แนวข้อสอบ NLE2)", "id": "set4-16"}, {"topic": "Infectious disease", "q": "A patient develops a seizure and CT shows multiple small calcified brain lesions without edema; he is from a pork-consuming rural area. What is the etiology?", "choices": ["Cerebral toxoplasmosis", "Neurocysticercosis (Taenia solium)", "Primary CNS lymphoma", "A tuberculous granuloma", "A cerebral metastasis"], "ans": 1, "exp": "Calcified brain lesions หลายจุด + seizure ในพื้นที่ระบาด/กินหมูดิบ = neurocysticercosis (Taenia solium). รักษาตาม stage: albendazole/praziquantel + steroid + antiseizure (ระวังในระยะ active/มี edema). (แนวข้อสอบ NLE2)", "id": "set4-17"}, {"topic": "Infectious disease", "q": "An HIV patient (CD4 80) has ring-enhancing brain lesions and positive Toxoplasma serology. What is the initial treatment?", "choices": ["Acyclovir", "Amphotericin B", "Pyrimethamine plus sulfadiazine", "Ceftriaxone", "Anti-tuberculous therapy"], "ans": 2, "exp": "Ring-enhancing lesions ใน HIV (CD4 < 100) + Toxoplasma IgG positive → รักษา empiric toxoplasmic encephalitis ด้วย pyrimethamine + sulfadiazine + leucovorin. ถ้าไม่ตอบสนอง คิดถึง CNS lymphoma (biopsy).", "id": "set4-18"}, {"topic": "Infectious disease", "q": "A patient has cellulitis with rapidly spreading erythema, pain out of proportion, bullae, crepitus, and systemic toxicity. What is the diagnosis and treatment?", "choices": ["Simple cellulitis; give oral antibiotics", "Erysipelas; give penicillin", "A simple abscess; drainage only", "Necrotizing fasciitis; urgent debridement", "Contact dermatitis; give a steroid"], "ans": 3, "exp": "Necrotizing fasciitis: ปวดเกินกว่าที่เห็น + bullae/crepitus + systemic toxicity เป็นภาวะฉุกเฉิน — surgical debridement ด่วน + broad-spectrum antibiotic (คลุม anaerobe/GAS) + clindamycin (ลด toxin). LRINEC score ช่วยประเมิน.", "id": "set4-19"}, {"topic": "Infectious disease", "q": "A patient has a localized skin abscess with fluctuance. What is the primary treatment?", "choices": ["Antibiotics alone without drainage", "A warm compress only", "A topical corticosteroid", "An antifungal agent", "Incision and drainage (± antibiotics)"], "ans": 4, "exp": "Skin abscess รักษาหลักด้วย incision and drainage; ให้ antibiotic เพิ่มเมื่อมี cellulitis รอบข้าง, systemic sign, immunocompromised, หรือหลายตำแหน่ง (คลุม MRSA ตามความเสี่ยง).", "id": "set4-20"}, {"topic": "Infectious disease", "q": "A patient with fever, new murmur, and Janeway lesions has infective endocarditis. Which empiric consideration is important for IV drug users?", "choices": ["Cover Staphylococcus aureus", "Cover only viridans streptococci", "Cover only enterococci", "No antibiotics are required", "Cover only fungal organisms"], "ans": 0, "exp": "IV drug users มัก right-sided endocarditis จาก Staphylococcus aureus (tricuspid, septic pulmonary emboli). Empiric ต้องคลุม S. aureus (รวม MRSA). Viridans strep พบใน native valve subacute; enterococci ใน GI/GU.", "id": "set4-21"}, {"topic": "Infectious disease", "q": "A patient with prolonged fever > 3 weeks and no diagnosis after initial work-up has FUO. Which categories should be systematically considered?", "choices": ["Only underlying malignancy", "Infection, malignancy, or autoimmune disease", "Only an underlying infection", "Only drug-induced fever", "A purely psychogenic cause"], "ans": 1, "exp": "FUO (> 38.3°C, > 3 สัปดาห์, หาไม่พบหลังตรวจเบื้องต้น) — พิจารณา 4 กลุ่ม: infection (TB, abscess, IE), malignancy (lymphoma), autoimmune/CTD (SLE, adult Still, GCA), และ miscellaneous (drug fever, DVT). ประวัติ+ตรวจซ้ำสำคัญ.", "id": "set4-22"}, {"topic": "Infectious disease", "q": "A patient steps on a nail and later develops lockjaw, risus sardonicus, and muscle spasms. What is the diagnosis?", "choices": ["Rabies", "Botulism", "Tetanus", "Meningitis", "Strychnine poisoning"], "ans": 2, "exp": "Puncture wound + trismus (lockjaw) + risus sardonicus + spasm = tetanus (Clostridium tetani, tetanospasmin). รักษา wound care + metronidazole + tetanus immunoglobulin + ควบคุม spasm (benzodiazepine) + vaccine.", "id": "set4-23"}, {"topic": "Infectious disease", "q": "A patient bitten by a stray dog with an unknown vaccination status. What is the appropriate post-exposure management for rabies (category III)?", "choices": ["Wound care alone with no vaccine", "Antibiotics alone without vaccine", "Observe the patient without action", "Wound wash + rabies vaccine + immunoglobulin", "Vaccine only if symptoms appear"], "ans": 3, "exp": "Rabies category III (bite/แผลเลือดออก/เยื่อบุ): ล้างแผลด้วยน้ำสบู่ทันที + rabies vaccine + rabies immunoglobulin (infiltrate รอบแผล) + พิจารณา tetanus/antibiotic. Rabies เมื่อมีอาการแล้วเสียชีวิตเกือบ 100%.", "id": "set4-24"}, {"topic": "Infectious disease", "q": "A young sexually active woman has dysuria, purulent cervical discharge; NAAT is positive for Neisseria gonorrhoeae. What is recommended treatment (also covering common co-infection)?", "choices": ["Penicillin", "Metronidazole", "Ciprofloxacin alone", "Acyclovir", "Ceftriaxone plus doxycycline/azithromycin"], "ans": 4, "exp": "Gonorrhea รักษาด้วย ceftriaxone IM + คลุม Chlamydia (doxycycline หรือ azithromycin) เพราะ co-infection บ่อย. รักษาคู่นอน + คัดกรอง STI อื่น (HIV/syphilis).", "id": "set4-25"}, {"topic": "Infectious disease", "q": "A patient has a painless genital ulcer (chancre) with a positive dark-field/serology. What is the treatment for primary syphilis?", "choices": ["Benzathine penicillin G", "Ceftriaxone", "Doxycycline for everyone", "Routine azithromycin", "Metronidazole"], "ans": 0, "exp": "Primary syphilis (painless chancre, Treponema pallidum): รักษาด้วย benzathine penicillin G IM single dose; doxycycline เป็นทางเลือกในผู้แพ้ penicillin (ยกเว้นตั้งครรภ์/neurosyphilis ต้อง desensitize).", "id": "set4-26"}, {"topic": "Infectious disease", "q": "A patient with genital vesicles and painful ulcers on an erythematous base has recurrent episodes; Tzanck smear shows multinucleated giant cells. What is the diagnosis and treatment?", "choices": ["Syphilis; give penicillin", "Genital herpes (HSV); give acyclovir", "Chancroid; give azithromycin", "Granuloma inguinale; give doxycycline", "LGV; give doxycycline"], "ans": 1, "exp": "Painful grouped vesicles/ulcers + recurrence + multinucleated giant cells = genital herpes (HSV). รักษาด้วย acyclovir/valacyclovir (episodic หรือ suppressive). Syphilis ให้ ulcer ไม่เจ็บ.", "id": "set4-27"}, {"topic": "Infectious disease", "q": "A patient develops watery diarrhea and vomiting after a buffet; symptoms began within hours and resolve within a day. What is the most likely mechanism?", "choices": ["An invasive bacterial infection", "Acute viral hepatitis", "A preformed bacterial toxin", "A parasitic infection", "C. difficile colitis"], "ans": 2, "exp": "อาการเร็ว (1–6 ชม.) หลังกินอาหาร + อาเจียนเด่น + หายไว = preformed toxin (S. aureus, B. cereus). รักษาแบบ supportive (rehydration); ไม่ต้อง antibiotic.", "id": "set4-28"}, {"topic": "Infectious disease", "q": "A patient develops descending flaccid paralysis, diplopia, dysphagia, and dry mouth after eating home-canned food. What is the diagnosis?", "choices": ["Guillain-Barré syndrome", "Myasthenia gravis", "Tetanus", "Botulism", "Acute stroke"], "ans": 3, "exp": "Descending symmetric flaccid paralysis + bulbar/autonomic (diplopia, dry mouth) หลังอาหารกระป๋อง/หมักเอง = botulism (Clostridium botulinum toxin). รักษาด้วย antitoxin + supportive/ventilation.", "id": "set4-29"}, {"topic": "Infectious disease", "q": "A patient with prosthetic material or endocarditis risk needs antibiotic prophylaxis before which procedure (per current guidelines)?", "choices": ["All dental cleanings for everyone", "Before every colonoscopy", "Before every catheterization", "It is never indicated", "High-risk cardiac lesions before dental work"], "ans": 4, "exp": "Antibiotic prophylaxis ก่อนหัตถการทันตกรรม (ที่ manipulate gingiva/mucosa) ให้เฉพาะกลุ่มเสี่ยงสูง (prosthetic valve, ประวัติ IE, congenital heart บางชนิด, transplant valvulopathy) เท่านั้น.", "id": "set4-30"}, {"topic": "Infectious disease", "q": "A patient with cough > 2 weeks, weight loss, and night sweats has a positive sputum Xpert MTB/RIF showing rifampicin resistance. What does this indicate?", "choices": ["Rifampicin-resistant (MDR) tuberculosis", "Ordinary drug-susceptible TB", "Latent TB infection", "Non-tuberculous mycobacteria", "Laboratory contamination"], "ans": 0, "exp": "Xpert MTB/RIF ที่พบ rifampicin resistance บ่งชี้ RR/MDR-TB — ต้องส่ง DST เพิ่มและเริ่มสูตร second-line (เช่น BPaLM 6 เดือน: bedaquiline, pretomanid, linezolid, moxifloxacin) ตามแนวทาง.", "id": "set4-31"}, {"topic": "Infectious disease", "q": "A patient starting anti-TB therapy develops tingling in the feet. Which drug is responsible and how is it prevented?", "choices": ["Rifampicin; give a steroid", "Isoniazid; give pyridoxine (vitamin B6)", "Ethambutol; give vitamin A", "Pyrazinamide; give allopurinol", "Streptomycin; give magnesium"], "ans": 1, "exp": "Isoniazid ทำให้ peripheral neuropathy จากการรบกวน pyridoxine metabolism — ป้องกัน/รักษาด้วย pyridoxine (vitamin B6) โดยเฉพาะในกลุ่มเสี่ยง (DM, สุรา, ตั้งครรภ์, CKD, HIV).", "id": "set4-32"}, {"topic": "Infectious disease", "q": "A close contact of an active pulmonary TB case has a positive tuberculin skin test but a normal CXR and no symptoms. What is the management?", "choices": ["Give full four-drug TB treatment", "Give no treatment at all", "Treat latent TB infection", "Repeat the test in five years", "Give antibiotics for five days"], "ans": 2, "exp": "Latent TB infection (positive test, ไม่มีอาการ, CXR ปกติ) — หลังตัด active disease ให้ latent TB treatment (isoniazid 6–9 เดือน หรือ 3HP rifapentine+isoniazid รายสัปดาห์ 3 เดือน) ลดการกลายเป็น active.", "id": "set4-33"}, {"topic": "Infectious disease", "q": "A hospitalized patient develops a central-line-associated bloodstream infection. Besides antibiotics, what is a key management step?", "choices": ["Increase intravenous fluids only", "Add systemic corticosteroids", "Give antipyretics only", "Source control: remove the infected catheter", "Keep the line and continue it"], "ans": 3, "exp": "CLABSI: source control สำคัญ — remove infected catheter (โดยเฉพาะ S. aureus/Candida/Pseudomonas) + antibiotic ตามเชื้อ. Source control เป็นหลักการสำคัญของการรักษาการติดเชื้อทุกชนิด.", "id": "set4-34"}, {"topic": "Infectious disease", "q": "A young adult has sore throat, posterior cervical lymphadenopathy, splenomegaly, and atypical lymphocytes; a heterophile (Monospot) test is positive. What is the diagnosis?", "choices": ["Streptococcal pharyngitis", "Diphtheria", "Acute HIV seroconversion", "CMV infection only", "Infectious mononucleosis (EBV)"], "ans": 4, "exp": "Sore throat + posterior cervical nodes + splenomegaly + atypical lymphocytes + Monospot positive = infectious mononucleosis (EBV). หลีกเลี่ยง contact sport (เสี่ยง splenic rupture); เลี่ยง amoxicillin (ผื่น).", "id": "set4-35"}, {"topic": "Infectious disease", "q": "A patient with animal (dog/cat) bite wound needs antibiotic prophylaxis. Which agent covers Pasteurella and oral flora?", "choices": ["Amoxicillin-clavulanate", "Azithromycin", "Ciprofloxacin alone", "Metronidazole alone", "Vancomycin"], "ans": 0, "exp": "Bite wounds (Pasteurella multocida, anaerobe, oral flora) → amoxicillin-clavulanate เป็น first-line prophylaxis/treatment + wound care + ประเมิน tetanus/rabies.", "id": "set4-36"}, {"topic": "Infectious disease", "q": "A patient presents with fever and a petechial/purpuric rash that is rapidly spreading with hypotension. Which diagnosis must be treated immediately?", "choices": ["A benign viral exanthem", "Meningococcemia (N. meningitidis)", "Dengue fever only", "Contact dermatitis", "A simple drug rash"], "ans": 1, "exp": "ไข้ + petechial/purpuric rash แพร่เร็ว + hypotension = meningococcemia (fulminant) — ให้ ceftriaxone ทันที + resuscitation; แจ้ง infection control + prophylaxis ผู้สัมผัสใกล้ชิด.", "id": "set4-37"}, {"topic": "Infectious disease", "q": "A patient with community-acquired pneumonia is found to have Legionella. Which clue and treatment are relevant?", "choices": ["Rusty sputum; give penicillin", "Currant-jelly sputum; give ceftriaxone", "Bradycardia, hyponatremia; give a macrolide", "No specific clinical clue exists", "Treat with metronidazole"], "ans": 2, "exp": "Legionella: pneumonia + hyponatremia + diarrhea + relative bradycardia + สัมผัสน้ำ/แอร์; ตรวจ urine antigen. รักษาด้วย macrolide (azithromycin) หรือ respiratory fluoroquinolone.", "id": "set4-38"}, {"topic": "Infectious disease", "q": "A pregnant woman is found to have asymptomatic bacteriuria. Why should it be treated?", "choices": ["It is never treated in pregnancy", "Only to relieve urinary symptoms", "To prevent gestational diabetes", "To prevent pyelonephritis and preterm birth", "There is no clear reason to treat"], "ans": 3, "exp": "Asymptomatic bacteriuria ในหญิงตั้งครรภ์ต้องรักษา (ตามผล culture, ยาที่ปลอดภัย) เพื่อลด pyelonephritis และผลลัพธ์การตั้งครรภ์ไม่ดี (preterm/low birth weight).", "id": "set4-39"}, {"topic": "Infectious disease", "q": "A patient with fever and right upper quadrant pain has a single large liver abscess; aspiration grows Klebsiella pneumoniae. What is appropriate management?", "choices": ["Observation without treatment", "Metronidazole alone in all cases", "Surgical resection only", "An antifungal agent", "Antibiotics plus percutaneous drainage"], "ans": 4, "exp": "Pyogenic liver abscess (มัก Klebsiella/enteric, biliary source) รักษาด้วย antibiotics + percutaneous drainage (โดยเฉพาะ abscess ใหญ่). ต่างจาก amoebic ที่ตอบสนอง metronidazole โดยมัก drainage เมื่อจำเป็น.", "id": "set4-40"}, {"topic": "Infectious disease", "q": "A patient develops an IRIS reaction after starting ART. What is IRIS?", "choices": ["Worsening infection as immunity recovers", "A drug allergy to antiretrovirals", "Treatment failure of the ART regimen", "A brand-new HIV infection", "A completely normal response"], "ans": 0, "exp": "IRIS = อาการของการติดเชื้อฉวยโอกาสแย่ลง/ปรากฏชัดหลังเริ่ม ART เพราะภูมิฟื้น (พบใน TB, cryptococcus). จัดการรักษาการติดเชื้อต่อ + ต้าน inflammation (steroid ในบางราย); มัก ไม่หยุด ART.", "id": "set4-41"}, {"topic": "Infectious disease", "q": "A healthcare worker sustains a needlestick from an HIV-positive source. What is the appropriate action?", "choices": ["Observe the worker without action", "Start HIV post-exposure prophylaxis now", "Give a hepatitis vaccine only", "Give immunoglobulin alone", "No action is needed at all"], "ans": 1, "exp": "Needlestick จากแหล่ง HIV+: เริ่ม PEP (3-drug ART) เร็วที่สุด (ภายในชั่วโมง-72 ชม.) นาน 28 วัน + baseline/follow-up testing (HIV/HBV/HCV) + ประเมิน HBV prophylaxis.", "id": "set4-42"}, {"topic": "Infectious disease", "q": "A patient with severe sepsis of unclear source. Which principle is essential besides antibiotics and fluids?", "choices": ["Deliberately delay all imaging", "Avoid taking any cultures", "Source control of the infection", "Give corticosteroids to everyone", "Give antipyretics only"], "ans": 2, "exp": "Source control (ระบายหนอง, เอาอุปกรณ์ติดเชื้อออก, แก้ obstruction เช่น obstructed biliary/urinary) เป็นหัวใจของการรักษา sepsis ควบคู่ antibiotic + resuscitation; ถ้าไม่ควบคุมแหล่ง ยาจะไม่ได้ผล.", "id": "set4-43"}, {"topic": "Infectious disease", "q": "A patient has recurrent oral thrush and esophageal candidiasis without another cause. What underlying condition should be tested for?", "choices": ["Diabetes mellitus only", "Iron deficiency anemia", "Hypothyroidism", "HIV infection", "Vitamin C deficiency"], "ans": 3, "exp": "Esophageal candidiasis / recurrent thrush เป็น AIDS-defining/immunocompromise clue — ควรตรวจ HIV (และประเมิน DM, corticosteroid, ยากดภูมิ). รักษา candidiasis ด้วย fluconazole.", "id": "set4-44"}, {"topic": "Infectious disease", "q": "A patient develops fever and a diffuse erythematous rash with desquamation, hypotension, and multiorgan involvement associated with tampon use. What is the diagnosis?", "choices": ["Anaphylactic reaction", "Dengue fever", "Scarlet fever", "Kawasaki disease", "Staphylococcal toxic shock syndrome"], "ans": 4, "exp": "Toxic shock syndrome (S. aureus superantigen TSST-1): ไข้ + diffuse rash + desquamation (ฝ่ามือ/เท้า) + hypotension + multiorgan + สัมพันธ์ tampon/wound. รักษา remove source + fluids + antibiotic (clindamycin ลด toxin + anti-staph).", "id": "set4-45"}, {"topic": "Infectious disease", "q": "A patient from an area with poor sanitation has acute watery 'rice-water' stools with rapid dehydration. What is the priority treatment?", "choices": ["Aggressive fluid/electrolyte replacement", "Give antibiotics before rehydration", "Give an antimotility agent", "Observation without rehydration", "An antifungal agent"], "ans": 0, "exp": "Cholera (rice-water stool, dehydration เร็ว): หัวใจคือ rapid fluid/electrolyte replacement (ORS หรือ IV) ป้องกันช็อก; antibiotic (doxycycline/azithromycin) ลดระยะเวลา/ปริมาณอุจจาระเป็นตัวเสริม.", "id": "set4-46"}, {"topic": "Infectious disease", "q": "A patient with HIV has CD4 30 and painless progressive visual loss; funduscopy shows hemorrhages and exudates ('pizza pie'). What is the diagnosis?", "choices": ["Toxoplasma retinitis", "CMV retinitis", "Cryptococcal eye disease", "HSV keratitis", "Diabetic retinopathy"], "ans": 1, "exp": "CD4 < 50 + retinitis (hemorrhage + exudate, pizza-pie) = CMV retinitis. รักษาด้วย ganciclovir/valganciclovir + เริ่ม/optimize ART. ต้องรีบเพื่อรักษาการมองเห็น.", "id": "set4-47"}, {"topic": "Infectious disease", "q": "Which patient should receive influenza antiviral (oseltamivir) treatment even beyond 48 hours ideally as early as possible?", "choices": ["A healthy adult with mild symptoms", "Anyone who has a common cold", "A hospitalized or high-risk patient", "Only pediatric patients", "No one at all"], "ans": 2, "exp": "Oseltamivir ให้ประโยชน์สูงสุดภายใน 48 ชม. แต่ยังแนะนำในผู้ป่วยที่ admit/รุนแรง/กลุ่มเสี่ยงสูง (ตั้งครรภ์, โรคเรื้อรัง, สูงอายุ) แม้เกิน 48 ชม. Healthy mild case มักไม่จำเป็น.", "id": "set4-48"}, {"topic": "Infectious disease", "q": "A patient with pyelonephritis and an obstructing ureteric stone with pus remains septic despite antibiotics. What is the essential intervention?", "choices": ["Increase the antibiotic dose only", "Give more IV fluids only", "Observation without intervention", "Urgent urinary decompression + antibiotics", "An antifungal agent"], "ans": 3, "exp": "Obstructed infected urinary system (pyonephrosis) เป็น urologic emergency — ต้อง decompress ด่วน (ureteric stent หรือ percutaneous nephrostomy) ควบคู่ antibiotic. Antibiotic เดี่ยวไม่พอถ้าไม่ระบายแหล่งติดเชื้อ.", "id": "set4-49"}, {"topic": "Infectious disease", "q": "A patient has a chronic non-healing ulcer with 'sulfur granules' draining from a jaw/neck sinus tract. What is the diagnosis?", "choices": ["Tuberculosis", "Nocardiosis", "Melioidosis", "Sporotrichosis", "Actinomycosis"], "ans": 4, "exp": "Sulfur granules + chronic draining sinus (มัก cervicofacial หลังทำฟัน) = actinomycosis (Actinomyces israelii). รักษาด้วย penicillin ขนาดสูงระยะยาว ± surgical drainage.", "id": "set4-50"}, {"topic": "Infectious disease", "q": "A patient with fever, headache, and altered mental status has CSF lymphocytic pleocytosis with normal glucose; MRI shows temporal lobe involvement. What is the likely diagnosis and treatment?", "choices": ["Herpes simplex encephalitis; give IV acyclovir", "Bacterial meningitis; give ceftriaxone", "Tuberculous meningitis; start anti-TB drugs", "Cryptococcal meningitis; give amphotericin B", "Migraine headache; give analgesia"], "ans": 0, "exp": "Encephalitis + temporal lobe involvement + lymphocytic CSF (glucose ปกติ) = HSV encephalitis. เริ่ม IV acyclovir ทันที (อย่ารอผล PCR) เพราะการรักษาเร็วลดการตาย/พิการ.", "id": "set4-51"}, {"topic": "Infectious disease", "q": "A patient traveling develops profuse watery diarrhea without blood or high fever ('traveler's diarrhea'). What is the most common cause and management?", "choices": ["Entamoeba histolytica; give metronidazole", "ETEC; oral rehydration ± antibiotic", "C. difficile colitis; give vancomycin", "Rotavirus; prevent with vaccine", "Cholera; give IV fluids only"], "ans": 1, "exp": "Traveler's diarrhea ส่วนใหญ่จาก enterotoxigenic E. coli (ETEC). หลักคือ oral rehydration; antibiotic (azithromycin/fluoroquinolone) เมื่อปานกลาง-รุนแรง; loperamide เสริมได้ถ้าไม่มีเลือด/ไข้สูง.", "id": "set4-52"}, {"topic": "Rheumatology", "q": "A young woman has a malar rash, photosensitivity, oral ulcers, arthritis, and proteinuria. Which antibodies are most specific for the diagnosis?", "choices": ["ANA alone", "Rheumatoid factor", "Anti-dsDNA and anti-Smith", "Anti-CCP antibody", "Anti-histone antibody"], "ans": 2, "exp": "อาการหลายระบบ = SLE. ANA sensitive (คัดกรอง) แต่ anti-dsDNA และ anti-Smith จำเพาะสุด. Anti-dsDNA สัมพันธ์ lupus nephritis/activity; complement ต่ำเวลากำเริบ.", "id": "set4-53"}, {"topic": "Rheumatology", "q": "Which medication should essentially all SLE patients receive unless contraindicated?", "choices": ["Cyclophosphamide", "Methotrexate", "Rituximab", "Hydroxychloroquine", "Azathioprine"], "ans": 3, "exp": "Hydroxychloroquine เป็นยาพื้นฐานสำหรับ SLE ทุกราย (ลดกำเริบ, ปกป้องอวัยวะ, ปรับ prognosis). เพิ่ม steroid/immunosuppressant ตามความรุนแรง/nephritis. ต้องตรวจตาเป็นระยะ.", "id": "set4-54"}, {"topic": "Rheumatology", "q": "A patient develops a lupus-like syndrome (arthralgia, serositis) after long-term hydralazine or procainamide; anti-histone antibody is positive. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Rheumatoid arthritis", "Sjogren syndrome", "Systemic sclerosis", "Drug-induced lupus"], "ans": 4, "exp": "Drug-induced lupus (hydralazine, procainamide, isoniazid): arthralgia/serositis, anti-histone positive, มัก spares kidney/CNS, หายเมื่อหยุดยา. ต่าง SLE ที่ anti-dsDNA/Smith positive.", "id": "set4-55"}, {"topic": "Rheumatology", "q": "A patient has symmetric small-joint polyarthritis (MCP, PIP, wrists) with > 1 hour of morning stiffness. Which antibody is most specific?", "choices": ["Anti-CCP antibody", "Antinuclear antibody", "Rheumatoid factor", "Anti-dsDNA antibody", "Anti-Ro antibody"], "ans": 0, "exp": "RA: symmetric small-joint arthritis + morning stiffness > 1 ชม. Anti-CCP จำเพาะกว่า RF (RF พบได้ในโรคอื่น). ESR/CRP ประเมิน activity; X-ray = erosion/joint space narrowing.", "id": "set4-56"}, {"topic": "Rheumatology", "q": "What is the first-line disease-modifying agent for rheumatoid arthritis?", "choices": ["NSAIDs", "Methotrexate", "Long-term prednisolone", "Rituximab", "Paracetamol"], "ans": 1, "exp": "RA ควรเริ่ม DMARD เร็ว โดย methotrexate เป็น first-line (± bridging steroid). ถ้าไม่ตอบสนอง เพิ่ม/เปลี่ยนเป็น biologic (anti-TNF) หรือ JAK inhibitor. NSAID/steroid คุมอาการเท่านั้น.", "id": "set4-57"}, {"topic": "Rheumatology", "q": "A patient has acute monoarthritis of the first MTP joint that is red, hot, and exquisitely tender. Synovial fluid shows needle-shaped negatively birefringent crystals. What is the diagnosis?", "choices": ["Pseudogout", "Septic arthritis", "Gout", "Rheumatoid arthritis", "Reactive arthritis"], "ans": 2, "exp": "Podagra (MTP1) + needle-shaped negatively birefringent MSU crystals = gout. รักษาเฉียบพลันด้วย NSAID/colchicine/steroid. ไม่เริ่ม/หยุด urate-lowering ระหว่างกำเริบ.", "id": "set4-58"}, {"topic": "Rheumatology", "q": "What is the goal serum urate when starting urate-lowering therapy (allopurinol) for recurrent gout?", "choices": ["Below 8 mg/dL", "Below 10 mg/dL", "No specific target", "Below 6 mg/dL", "Below 2 mg/dL"], "ans": 3, "exp": "Urate-lowering therapy (allopurinol/febuxostat) เป้า serum urate < 6 mg/dL (< 5 ถ้ามี tophi). เริ่มขนาดต่ำค่อยเพิ่ม + prophylaxis (colchicine/NSAID) ช่วงเริ่มเพื่อกัน flare.", "id": "set4-59"}, {"topic": "Rheumatology", "q": "A patient's synovial fluid shows rhomboid-shaped positively birefringent crystals with chondrocalcinosis on X-ray. What is the diagnosis?", "choices": ["Gout", "Septic arthritis", "Osteoarthritis", "Reactive arthritis", "Pseudogout (CPPD disease)"], "ans": 4, "exp": "Rhomboid, positively birefringent crystals + chondrocalcinosis = CPPD (pseudogout). มักโดนข้อใหญ่ (knee, wrist); สัมพันธ์ hyperparathyroidism, hemochromatosis, hypomagnesemia.", "id": "set4-60"}, {"topic": "Rheumatology", "q": "A patient has an acutely hot, swollen, painful single joint with fever. What is the most important immediate step?", "choices": ["Aspiration for culture, then antibiotics", "Start allopurinol immediately", "NSAIDs and discharge home", "Obtain an MRI first", "Refer for physiotherapy"], "ans": 0, "exp": "Acute monoarthritis + ไข้ = ต้องตัด septic arthritis เสมอ — ทำ arthrocentesis (cell count, Gram stain, culture, crystals) ด่วน แล้วเริ่ม empiric antibiotic + joint drainage. Septic arthritis เป็นภาวะฉุกเฉิน (ทำลายข้อ).", "id": "set4-61"}, {"topic": "Rheumatology", "q": "The most common organism causing septic arthritis in adults is:", "choices": ["Neisseria gonorrhoeae", "Staphylococcus aureus", "Streptococcus pneumoniae", "Escherichia coli", "Pseudomonas aeruginosa"], "ans": 1, "exp": "Septic arthritis ในผู้ใหญ่ส่วนใหญ่เกิดจาก Staphylococcus aureus. ในผู้ใหญ่วัยเจริญพันธุ์ที่ active ทางเพศ ให้คิดถึง Neisseria gonorrhoeae (มักหลายข้อ + tenosynovitis + ผื่น).", "id": "set4-62"}, {"topic": "Rheumatology", "q": "An older woman has bilateral knee pain worse with activity, relieved by rest, with bony enlargement (Heberden/Bouchard nodes) and no systemic symptoms. What is the diagnosis?", "choices": ["Rheumatoid arthritis", "Gout", "Osteoarthritis", "Systemic lupus erythematosus", "Septic arthritis"], "ans": 2, "exp": "Osteoarthritis: ปวดข้อเมื่อใช้งาน ดีขึ้นเมื่อพัก, ข้อฝืดเช้าสั้น (< 30 นาที), Heberden (DIP)/Bouchard (PIP) nodes, ไม่มี systemic inflammation. รักษา exercise, ลดน้ำหนัก, paracetamol/NSAID, ข้อเทียมเมื่อรุนแรง.", "id": "set4-63"}, {"topic": "Rheumatology", "q": "A young man has chronic inflammatory low back pain (better with exercise, worse with rest), reduced spinal mobility, and sacroiliitis; HLA-B27 positive. What is the diagnosis?", "choices": ["Mechanical low back pain", "Osteoarthritis of the spine", "A herniated disc", "Ankylosing spondylitis", "Osteoporosis"], "ans": 3, "exp": "Inflammatory back pain (ดีขึ้นเมื่อขยับ, ตอนเช้าฝืด) + sacroiliitis + HLA-B27 = ankylosing spondylitis (bamboo spine). รักษา NSAID + exercise; anti-TNF/IL-17 ในรายดื้อ.", "id": "set4-64"}, {"topic": "Rheumatology", "q": "A patient develops arthritis, urethritis, and conjunctivitis after a GI/GU infection. What is the diagnosis?", "choices": ["Rheumatoid arthritis", "Gout", "Psoriatic arthritis", "Septic arthritis", "Reactive arthritis"], "ans": 4, "exp": "Reactive arthritis (asymmetric oligoarthritis + urethritis + conjunctivitis) หลังติดเชื้อ GI (Salmonella/Shigella/Campylobacter) หรือ GU (Chlamydia); HLA-B27 สัมพันธ์. รักษา NSAID; รักษาเชื้อต้นเหตุ.", "id": "set4-65"}, {"topic": "Rheumatology", "q": "A patient with psoriasis develops asymmetric arthritis with dactylitis ('sausage digit') and nail pitting. What is the diagnosis?", "choices": ["Psoriatic arthritis", "Rheumatoid arthritis", "Gout", "Osteoarthritis", "Reactive arthritis"], "ans": 0, "exp": "Psoriatic arthritis: arthritis + psoriasis + dactylitis + nail changes (pitting, onycholysis), อาจโดน DIP; X-ray pencil-in-cup. รักษา NSAID, DMARD (methotrexate), biologic (anti-TNF/IL-17).", "id": "set4-66"}, {"topic": "Rheumatology", "q": "A woman has Raynaud phenomenon, skin thickening, dysphagia, and pulmonary involvement; anti-Scl-70 is positive. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Systemic sclerosis (scleroderma)", "Rheumatoid arthritis", "Dermatomyositis", "Sjogren syndrome"], "ans": 1, "exp": "Systemic sclerosis: skin thickening + Raynaud + GERD/dysphagia + ILD/PAH. Diffuse (anti-Scl-70) vs limited/CREST (anti-centromere). ระวัง scleroderma renal crisis (รักษา ACEI).", "id": "set4-67"}, {"topic": "Rheumatology", "q": "A scleroderma patient develops malignant hypertension and acute kidney injury (renal crisis). What is the treatment of choice?", "choices": ["A beta-blocker", "A calcium channel blocker", "An ACE inhibitor", "A diuretic", "A corticosteroid"], "ans": 2, "exp": "Scleroderma renal crisis (HT รุนแรง + AKI + MAHA) รักษาด้วย ACE inhibitor (captopril) เป็นตัวเลือกหลัก แม้ Cr สูง. หลีกเลี่ยง high-dose steroid ซึ่งกระตุ้น renal crisis.", "id": "set4-68"}, {"topic": "Rheumatology", "q": "A patient has dry eyes and dry mouth (sicca) with positive anti-Ro (SSA)/anti-La (SSB). What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Rheumatoid arthritis", "Systemic sclerosis", "Sjogren syndrome", "Sarcoidosis"], "ans": 3, "exp": "Sjogren syndrome: keratoconjunctivitis sicca + xerostomia + anti-Ro/La; ยืนยันด้วย Schirmer test/lip biopsy. เสี่ยง lymphoma (MALT). รักษาตามอาการ (น้ำตาเทียม, pilocarpine).", "id": "set4-69"}, {"topic": "Rheumatology", "q": "A patient has proximal muscle weakness, elevated CK, and a heliotrope rash with Gottron papules. What is the diagnosis?", "choices": ["Polymyositis", "Polymyalgia rheumatica", "Myasthenia gravis", "Fibromyalgia", "Dermatomyositis"], "ans": 4, "exp": "Proximal muscle weakness + CK สูง + heliotrope rash + Gottron papules = dermatomyositis. สัมพันธ์ malignancy (ควรคัดกรองมะเร็ง). รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-70"}, {"topic": "Rheumatology", "q": "An older patient has new bilateral temporal headache, jaw claudication, scalp tenderness, and a markedly elevated ESR. What is the immediate treatment to prevent blindness?", "choices": ["Immediate high-dose corticosteroid", "NSAIDs", "Methotrexate", "Observation only", "Antibiotics"], "ans": 0, "exp": "Giant cell (temporal) arteritis: ปวดขมับ + jaw claudication + ESR สูง เสี่ยงตาบอด (anterior ischemic optic neuropathy) — ให้ high-dose corticosteroid ทันทีโดยไม่รอ temporal artery biopsy. สัมพันธ์ polymyalgia rheumatica.", "id": "set4-71"}, {"topic": "Rheumatology", "q": "An older patient has bilateral shoulder and hip girdle pain and stiffness with a high ESR but normal CK and no true weakness. What is the diagnosis?", "choices": ["Polymyositis", "Polymyalgia rheumatica", "Fibromyalgia", "Rheumatoid arthritis", "Hypothyroid myopathy"], "ans": 1, "exp": "Polymyalgia rheumatica: ปวด/ฝืด shoulder+hip girdle, ESR สูง, CK ปกติ, ไม่มี weakness จริง. ตอบสนองดีต่อ low-dose prednisolone. สัมพันธ์ GCA (เฝ้าระวังอาการตา).", "id": "set4-72"}, {"topic": "Rheumatology", "q": "A young Asian/Middle-Eastern patient has recurrent painful oral and genital ulcers with uveitis. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Reactive arthritis", "Behcet disease", "Crohn disease", "Herpes infection"], "ans": 2, "exp": "Behcet disease: recurrent oral + genital ulcers + uveitis (± skin lesions, pathergy). รักษาตามอวัยวะที่โดน (colchicine, steroid, immunosuppressant/biologic).", "id": "set4-73"}, {"topic": "Rheumatology", "q": "A patient has palpable purpura, abdominal pain, arthralgia, and hematuria after a URI; biopsy shows IgA deposition. What is the diagnosis?", "choices": ["Immune thrombocytopenic purpura", "Meningococcemia", "Systemic lupus erythematosus", "IgA vasculitis (Henoch-Schonlein purpura)", "Cryoglobulinemia"], "ans": 3, "exp": "IgA vasculitis (HSP, พบในเด็ก): palpable purpura (ขาส่วนล่าง) + abdominal pain + arthritis + IgA nephropathy. มัก self-limited; supportive ± steroid ในรายรุนแรง.", "id": "set4-74"}, {"topic": "Rheumatology", "q": "A patient has asthma, eosinophilia, and vasculitis with mononeuritis multiplex; p-ANCA may be positive. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Polyarteritis nodosa", "Giant cell arteritis", "Takayasu arteritis", "Eosinophilic granulomatosis (Churg-Strauss)"], "ans": 4, "exp": "Asthma + eosinophilia + vasculitis (mononeuritis multiplex) = eosinophilic granulomatosis with polyangiitis (Churg-Strauss), p-ANCA/MPO. รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-75"}, {"topic": "Rheumatology", "q": "A middle-aged man has systemic vasculitis with renal and GI involvement, hypertension, and is hepatitis B associated; ANCA is typically negative and there is no glomerulonephritis with pulmonary hemorrhage. What is the diagnosis?", "choices": ["Polyarteritis nodosa", "Granulomatosis with polyangiitis", "Microscopic polyangiitis", "Giant cell arteritis", "Behcet disease"], "ans": 0, "exp": "Polyarteritis nodosa (PAN): medium-vessel vasculitis, สัมพันธ์ HBV, โดนไต (renal artery, ไม่ใช่ GN)/GI/ผิวหนัง/เส้นประสาท, ANCA negative, spares ปอด. รักษา steroid ± cyclophosphamide (+ antiviral ถ้า HBV).", "id": "set4-76"}, {"topic": "Rheumatology", "q": "A young Asian woman has arm claudication, unequal pulses/blood pressures, and bruits over large arteries. What is the diagnosis?", "choices": ["Giant cell arteritis", "Takayasu arteritis", "Polyarteritis nodosa", "Buerger disease", "Kawasaki disease"], "ans": 1, "exp": "Takayasu arteritis ('pulseless disease'): large-vessel vasculitis ในหญิงเอเชียอายุน้อย — ชีพจร/ความดันไม่เท่ากัน, bruit, claudication แขน. รักษาด้วย corticosteroid ± immunosuppressant.", "id": "set4-77"}, {"topic": "Rheumatology", "q": "A patient has widespread chronic musculoskeletal pain, fatigue, poor sleep, and multiple tender points but normal inflammatory markers and imaging. What is the diagnosis?", "choices": ["Polymyalgia rheumatica", "Rheumatoid arthritis", "Fibromyalgia", "Systemic lupus erythematosus", "Hypothyroidism"], "ans": 2, "exp": "Fibromyalgia: ปวดกล้ามเนื้อทั่วตัวเรื้อรัง + เหนื่อยล้า + นอนไม่ดี + tender points โดย inflammatory markers/imaging ปกติ. รักษาด้วยออกกำลัง, ปรับการนอน, ยา (duloxetine, pregabalin, amitriptyline).", "id": "set4-78"}, {"topic": "Rheumatology", "q": "A patient with SLE has recurrent arterial/venous thrombosis and pregnancy losses with positive lupus anticoagulant. What is the diagnosis and long-term treatment?", "choices": ["Simple DVT; short-course anticoagulation", "Immune thrombocytopenia; corticosteroids", "TTP; plasma exchange", "Antiphospholipid syndrome; long-term anticoagulation", "Factor V Leiden; aspirin"], "ans": 3, "exp": "Antiphospholipid syndrome (thrombosis + pregnancy loss + antiphospholipid antibody, อาจ secondary ต่อ SLE) รักษาด้วย long-term anticoagulation (warfarin) หลัง thrombosis; ในตั้งครรภ์ใช้ heparin + aspirin.", "id": "set4-79"}, {"topic": "Rheumatology", "q": "A patient has Raynaud phenomenon alone with no other features; nailfold capillaroscopy is normal and antibodies negative. What is the classification and management?", "choices": ["Secondary Raynaud; treat the underlying cause", "Systemic sclerosis; give immunosuppression", "Buerger disease; stop smoking", "Vasculitis; give corticosteroids", "Primary Raynaud; calcium channel blocker"], "ans": 4, "exp": "Primary Raynaud (ไม่มีโรคพื้นฐาน, capillaroscopy/serology ปกติ) รักษาด้วยหลีกเลี่ยงความเย็น/บุหรี่ ± dihydropyridine CCB (nifedipine). Secondary (systemic sclerosis, SLE) ต้องหาและรักษาโรคพื้นฐาน.", "id": "set4-80"}, {"topic": "Rheumatology", "q": "A patient with rheumatoid arthritis, splenomegaly, and neutropenia has which syndrome?", "choices": ["Felty syndrome", "Sjogren syndrome", "Caplan syndrome", "Still disease", "Sweet syndrome"], "ans": 0, "exp": "Felty syndrome = RA + splenomegaly + neutropenia (เสี่ยงติดเชื้อ). Caplan = RA + pneumoconiosis; adult Still = ไข้สูง + ผื่นสีแซลมอน + arthritis + ferritin สูงมาก.", "id": "set4-81"}, {"topic": "Rheumatology", "q": "A young adult has daily high spiking fevers, an evanescent salmon-colored rash, arthritis, and a very high ferritin with negative RF/ANA. What is the diagnosis?", "choices": ["Systemic lupus erythematosus", "Adult-onset Still disease", "Rheumatoid arthritis", "Reactive arthritis", "Systemic sepsis"], "ans": 1, "exp": "Adult-onset Still disease: quotidian fever + salmon rash + arthritis + leukocytosis + ferritin สูงมาก, RF/ANA negative. เป็น diagnosis of exclusion; รักษาด้วย NSAID/steroid ± IL-1/IL-6 inhibitor.", "id": "set4-82"}, {"topic": "Rheumatology", "q": "A patient on long-term corticosteroids for a rheumatic disease needs prophylaxis against which complication?", "choices": ["Hyperkalemia", "Hypoglycemia", "Osteoporosis and peptic ulcer risk", "Bradycardia", "Hyperthyroidism"], "ans": 2, "exp": "Long-term steroid เสี่ยง glucocorticoid-induced osteoporosis — ให้ calcium/vitamin D ± bisphosphonate; ระวัง hyperglycemia, HT, infection, PUD (โดยเฉพาะร่วม NSAID), adrenal suppression (ห้ามหยุดกะทันหัน).", "id": "set4-83"}, {"topic": "Rheumatology", "q": "A patient starting methotrexate for RA should also receive which supplement to reduce side effects?", "choices": ["Vitamin D", "Iron", "Vitamin B12", "Folic acid", "Calcium"], "ans": 3, "exp": "Methotrexate ให้ folic acid ร่วมเพื่อลด mucositis/GI/hepatotoxicity/cytopenia. ติดตาม CBC/LFT; หลีกเลี่ยงในตั้งครรภ์ (teratogen) และระวังใน renal impairment.", "id": "set4-84"}, {"topic": "Rheumatology", "q": "Before starting a biologic anti-TNF agent, screening for which latent infection is essential?", "choices": ["HIV infection only", "Malaria", "Dengue", "Syphilis", "Latent TB and hepatitis B"], "ans": 4, "exp": "ก่อนเริ่ม anti-TNF ต้องคัดกรอง latent TB (TST/IGRA + CXR) และ hepatitis B (เสี่ยง reactivation) เพราะ anti-TNF เพิ่มความเสี่ยงติดเชื้อฉวยโอกาส/reactivation.", "id": "set4-85"}, {"topic": "Rheumatology", "q": "A patient with gout has a flare while on stable allopurinol. What should be done with the allopurinol?", "choices": ["Continue it and treat the flare separately", "Stop the allopurinol", "Double the dose immediately", "Switch to colchicine only", "Stop urate-lowering therapy forever"], "ans": 0, "exp": "ระหว่าง gout flare ไม่ควรหยุด (หรือเริ่ม) urate-lowering therapy ที่ใช้อยู่เดิม — ให้คงยาไว้และรักษา flare แยก (NSAID/colchicine/steroid) เพราะการเปลี่ยนระดับ urate กระตุ้น flare.", "id": "set4-86"}, {"topic": "Rheumatology", "q": "A patient with lupus nephritis class IV needs induction therapy. Which regimen is appropriate?", "choices": ["Hydroxychloroquine alone", "Steroid plus mycophenolate/cyclophosphamide", "An NSAID", "Methotrexate", "Antibiotics"], "ans": 1, "exp": "Proliferative lupus nephritis (class III/IV) induction ด้วย high-dose corticosteroid + mycophenolate mofetil หรือ cyclophosphamide (± belimumab/voclosporin). ทุกรายให้ hydroxychloroquine + คุมความดัน/proteinuria.", "id": "set4-87"}, {"topic": "Rheumatology", "q": "A patient has osteoarthritis of the knee. What is the recommended first-line management?", "choices": ["Opioid analgesics", "Immediate joint replacement", "Exercise, weight loss, and an NSAID", "Long-term corticosteroids", "Colchicine"], "ans": 2, "exp": "OA เข่า first-line = exercise/strengthening, ลดน้ำหนัก, และ analgesia (topical NSAID, paracetamol/oral NSAID). Intra-articular steroid ช่วงกำเริบ; joint replacement เมื่อรุนแรง/ล้มเหลวจากการรักษาอนุรักษ์.", "id": "set4-88"}, {"topic": "Rheumatology", "q": "A patient with an acute gout flare has CKD and cannot take NSAIDs. What is an appropriate alternative?", "choices": ["A high-dose NSAID anyway", "Allopurinol to abort the flare", "Aspirin", "Colchicine or a corticosteroid", "Febuxostat to abort the flare"], "ans": 3, "exp": "ใน gout flare ที่มี CKD/ห้าม NSAID ใช้ colchicine (ปรับขนาดตาม renal) หรือ corticosteroid (oral/intra-articular). Urate-lowering (allopurinol/febuxostat) ไม่ใช้ abort flare.", "id": "set4-89"}, {"topic": "Rheumatology", "q": "A patient has a positive ANA at low titer but no symptoms. How should this be interpreted?", "choices": ["The patient definitely has lupus", "Start immunosuppression at once", "Ignore all future symptoms", "Repeat the test every week", "A low-titer ANA is nonspecific"], "ans": 4, "exp": "ANA titer ต่ำพบได้ในคนปกติและโรคอื่น — ไม่จำเพาะ; ต้องแปลผลร่วมอาการทางคลินิก. ตรวจ specific antibody (anti-dsDNA/Smith) เมื่อสงสัย SLE. ไม่เริ่มรักษาเพียงเพราะ ANA บวก.", "id": "set4-90"}, {"topic": "Rheumatology", "q": "A patient with granulomatosis with polyangiitis (GPA) has upper airway, lung, and kidney disease with c-ANCA. What is induction treatment?", "choices": ["Steroid plus rituximab/cyclophosphamide", "NSAIDs", "Antibiotics only", "Colchicine", "Methotrexate alone"], "ans": 0, "exp": "GPA (ANCA-associated vasculitis) รุนแรง (ไต/ปอด) induction ด้วย corticosteroid + rituximab หรือ cyclophosphamide; maintenance ด้วย rituximab/azathioprine. คัดกรอง infection ก่อน immunosuppress.", "id": "set4-91"}, {"topic": "Rheumatology", "q": "A patient with rheumatoid arthritis is at increased risk of which extra-articular/systemic complication?", "choices": ["A reduced cardiovascular risk", "Cardiovascular disease and neck instability", "Hyperthyroidism", "Polycythemia", "Hypercalcemia"], "ans": 1, "exp": "RA เพิ่มความเสี่ยง cardiovascular disease (inflammation เร่ง atherosclerosis) และ atlantoaxial subluxation (ระวังตอน intubation/ผ่าตัด). ควบคุมโรค + ประเมิน CV risk.", "id": "set4-92"}, {"topic": "Rheumatology", "q": "A patient has an acute swollen knee; aspiration shows WBC 80,000 with neutrophil predominance and no crystals. What is the most likely diagnosis?", "choices": ["Osteoarthritis", "Gout", "Septic arthritis", "Reactive arthritis", "Hemarthrosis"], "ans": 2, "exp": "Synovial WBC สูงมาก (> 50,000, มัก > 50–100k) neutrophil เด่น ไม่มี crystal = septic arthritis จนกว่าจะพิสูจน์เป็นอื่น — ต้อง culture + antibiotic + drainage ด่วน. Crystal disease อาจ WBC สูงได้แต่มี crystal.", "id": "set4-93"}, {"topic": "Rheumatology", "q": "A patient with dermatomyositis is diagnosed. What additional evaluation is important, especially in adults?", "choices": ["Bone density testing only", "An echocardiogram only", "No further work-up needed", "Age-appropriate malignancy screening", "Thyroid testing only"], "ans": 3, "exp": "Dermatomyositis (และ polymyositis) ในผู้ใหญ่สัมพันธ์ occult malignancy — ต้องทำ age-appropriate cancer screening (และตามอาการ) เพราะอาจเป็น paraneoplastic.", "id": "set4-94"}, {"topic": "Rheumatology", "q": "A patient develops gout tophi and chronic arthropathy. What long-term strategy prevents joint damage?", "choices": ["NSAIDs only during flares", "Colchicine only", "Dietary change alone", "Surgery for all patients", "Urate-lowering to target with prophylaxis"], "ans": 4, "exp": "Chronic tophaceous gout ต้องใช้ urate-lowering therapy ต่อเนื่องจนถึงเป้า (< 5–6 mg/dL เพื่อละลาย tophi) + prophylaxis ช่วงเริ่ม + ปรับ lifestyle. การรักษาเฉพาะ flare ไม่ป้องกันความเสียหายข้อ.", "id": "set4-95"}, {"topic": "Rheumatology", "q": "A patient with SLE plans pregnancy. Which drug is safe to continue and which is contraindicated?", "choices": ["Continue HCQ; stop teratogenic agents", "Continue methotrexate", "Stop all medications", "Continue mycophenolate", "Start warfarin routinely"], "ans": 0, "exp": "ในตั้งครรภ์ SLE: hydroxychloroquine ปลอดภัยและควรใช้ต่อ (ลด flare); methotrexate/mycophenolate/cyclophosphamide เป็น teratogen ต้องหยุด/เปลี่ยน (azathioprine ใช้ได้). วางแผนช่วงโรคสงบ.", "id": "set4-96"}, {"topic": "Rheumatology", "q": "A patient with reactive arthritis or spondyloarthritis has which associated genetic marker?", "choices": ["HLA-DR4", "HLA-B27", "HLA-DQ2", "HLA-B51", "HLA-DR3"], "ans": 1, "exp": "Spondyloarthritis group (ankylosing spondylitis, reactive, psoriatic, IBD-associated) สัมพันธ์ HLA-B27. (HLA-DR4 → RA; HLA-B51 → Behcet; HLA-DQ2 → celiac).", "id": "set4-97"}, {"topic": "Rheumatology", "q": "A patient presents with acute anterior uveitis (painful red eye, photophobia). Which systemic association should be considered?", "choices": ["Osteoarthritis", "Fibromyalgia", "HLA-B27 spondyloarthritis", "Gout", "Osteoporosis"], "ans": 2, "exp": "Acute anterior uveitis สัมพันธ์ HLA-B27 spondyloarthritis (ankylosing spondylitis, IBD, reactive, psoriatic) รวมถึง sarcoidosis/Behcet. ต้องส่งจักษุแพทย์ด่วน + ประเมินโรคระบบ.", "id": "set4-98"}, {"topic": "Rheumatology", "q": "A patient with long-standing RA develops amyloidosis. Which type and consequence should be considered?", "choices": ["AL amyloid with cardiac involvement", "No amyloid risk at all", "Beta-2 microglobulin amyloid only", "AA amyloid; nephrotic syndrome, renal failure", "Purely localized amyloid"], "ans": 3, "exp": "Chronic inflammatory disease (RA, IBD, chronic infection) เสี่ยง AA (secondary) amyloidosis จาก serum amyloid A → มัก renal involvement (proteinuria/nephrotic). ควบคุม inflammation เป็นการป้องกัน.", "id": "set4-99"}, {"topic": "Rheumatology", "q": "A patient with vasculitis affecting the kidneys and lungs (pulmonary-renal syndrome) has p-ANCA/MPO without granulomas. What is the diagnosis?", "choices": ["Granulomatosis with polyangiitis", "Goodpasture syndrome", "Polyarteritis nodosa", "Behcet disease", "Microscopic polyangiitis"], "ans": 4, "exp": "Microscopic polyangiitis: small-vessel vasculitis, pulmonary-renal syndrome (RPGN + alveolar hemorrhage), p-ANCA/MPO positive, ไม่มี granuloma (ต่าง GPA). รักษา steroid + rituximab/cyclophosphamide.", "id": "set4-100"}]}, {"id": "set5", "title": "ชุดที่ 5 — Neurology + Integrated", "questions": [{"topic": "Neurology", "q": "A 26-year-old woman has recurrent unilateral throbbing headaches lasting 12–24 hours with nausea, photophobia, and phonophobia; the neurological exam is normal. What is the most likely diagnosis?", "choices": ["Migraine", "Tension-type headache", "Cluster headache", "Trigeminal neuralgia", "Giant cell arteritis"], "ans": 0, "exp": "ปวดศีรษะข้างเดียว ตุบๆ + คลื่นไส้ + กลัวแสง/เสียง + exam ปกติ = migraine. รักษาเฉียบพลันด้วย NSAID/triptan; ป้องกันด้วย propranolol/topiramate/amitriptyline เมื่อบ่อย. (แนวข้อสอบ NLE2)", "id": "set5-1"}, {"topic": "Neurology", "q": "A patient has the sudden 'worst headache of my life' (thunderclap); CT may be negative early. What is the next step if CT is non-diagnostic?", "choices": ["Discharge the patient home", "Lumbar puncture for xanthochromia", "MRI of the spine", "Reassurance without work-up", "Empiric antibiotics"], "ans": 1, "exp": "Thunderclap headache = สงสัย subarachnoid hemorrhage. ถ้า CT ปกติ (โดยเฉพาะหลัง 6 ชม.) ทำ LP หา xanthochromia/RBC. ยืนยัน aneurysm ด้วย CT/DSA angiography.", "id": "set5-2"}, {"topic": "Neurology", "q": "A patient presents within 2 hours of acute left-sided weakness and facial droop; CT shows no hemorrhage and BP is 170/90. What is the appropriate treatment?", "choices": ["Aspirin alone as treatment", "Immediate full anticoagulation", "IV thrombolysis if no contraindication", "Observation without treatment", "Rapid BP lowering with nifedipine"], "ans": 2, "exp": "Acute ischemic stroke ภายใน 4.5 ชม. + CT ไม่มีเลือดออก + ไม่มีข้อห้าม → IV thrombolysis (alteplase 0.9 หรือ tenecteplase 0.25 mg/kg — class I). ถ้า BP > 185/110 ต้องลดก่อน. พิจารณา thrombectomy ถ้า LVO.", "id": "set5-3"}, {"topic": "Neurology", "q": "A stroke patient with a large-vessel occlusion presents at 8 hours with salvageable tissue on perfusion imaging. What is appropriate?", "choices": ["No further treatment is offered", "Thrombolysis alone without thrombectomy", "Immediate full anticoagulation", "Mechanical thrombectomy (extended window up to 24 h)", "Decompressive craniectomy"], "ans": 3, "exp": "AHA/ASA 2026: mechanical thrombectomy ขยายถึง 24 ชม.ในผู้ป่วย LVO ที่ advanced imaging (CTP/MRI) แสดง salvageable tissue (DAWN/DEFUSE-3). เป็นการเปลี่ยนแปลงสำคัญจากเดิม ~6 ชม.", "id": "set5-4"}, {"topic": "Neurology", "q": "A patient with acute ischemic stroke who is NOT eligible for thrombolysis should receive which within 48 hours?", "choices": ["Warfarin anticoagulation", "A heparin infusion", "No treatment at all", "Thrombolysis anyway", "Aspirin (an antiplatelet)"], "ans": 4, "exp": "Stroke ที่ไม่ได้ยาละลายลิ่ม ให้ aspirin ภายใน 24–48 ชม. Early anticoagulation ไม่แนะนำ routine (เสี่ยง hemorrhagic transformation) แม้มี AF (เริ่มภายหลังตามขนาด infarct).", "id": "set5-5"}, {"topic": "Neurology", "q": "A seizing patient has been convulsing for more than 5 minutes. What is the first-line drug?", "choices": ["An IV/IM benzodiazepine", "IV phenytoin", "IV valproate", "IV propofol", "IV levetiracetam"], "ans": 0, "exp": "Status epilepticus (ชัก > 5 นาที/ไม่ฟื้นระหว่างชัก): first-line = benzodiazepine (lorazepam IV, midazolam IM). จากนั้น load ด้วย levetiracetam/phenytoin/valproate; หา/แก้สาเหตุ (น้ำตาล, Na, ติดเชื้อ). ดูแล ABC.", "id": "set5-6"}, {"topic": "Neurology", "q": "A patient develops ascending symmetric weakness and areflexia days after a diarrheal illness; CSF shows high protein with normal cells. What is the diagnosis and treatment?", "choices": ["Myasthenia gravis; give pyridostigmine", "Guillain-Barre syndrome; IVIG or plasma exchange", "Acute stroke; give thrombolysis", "Botulism; give the antitoxin", "Multiple sclerosis; give steroids"], "ans": 1, "exp": "Ascending symmetric weakness + areflexia + albuminocytologic dissociation หลังติดเชื้อ (Campylobacter) = Guillain-Barre. รักษาด้วย IVIG หรือ plasma exchange; เฝ้าระวังการหายใจ (FVC) + autonomic instability. ไม่ใช้ steroid.", "id": "set5-7"}, {"topic": "Neurology", "q": "A patient has fatigable weakness with ptosis and diplopia worsening through the day; anti-AChR antibodies are positive. What is the diagnosis?", "choices": ["Guillain-Barre syndrome", "Lambert-Eaton syndrome", "Myasthenia gravis", "Multiple sclerosis", "Motor neuron disease"], "ans": 2, "exp": "Fatigable weakness (ptosis, diplopia แย่ตอนเย็น/ใช้งาน) + anti-AChR = myasthenia gravis. รักษาด้วย pyridostigmine + immunosuppression; ตรวจ thymoma (CT chest). ระวัง myasthenic crisis (หายใจล้มเหลว).", "id": "set5-8"}, {"topic": "Neurology", "q": "A patient with myasthenia gravis develops respiratory distress and severe weakness (myasthenic crisis). What is the treatment?", "choices": ["Increase pyridostigmine only", "Corticosteroids alone", "Antibiotics only", "Airway support plus IVIG or plasma exchange", "Observation only"], "ans": 3, "exp": "Myasthenic crisis (หายใจล้มเหลว) ต้อง secure airway/ventilate + IVIG หรือ plasma exchange + รักษา precipitant (ติดเชื้อ/ยา). ระวังยาที่กระตุ้น (aminoglycoside, beta-blocker).", "id": "set5-9"}, {"topic": "Neurology", "q": "A young woman has episodes of optic neuritis and limb weakness separated in time and space; MRI shows white-matter lesions. What is the diagnosis?", "choices": ["Acute stroke", "Guillain-Barre syndrome", "Myasthenia gravis", "Migraine", "Multiple sclerosis"], "ans": 4, "exp": "MS: CNS demyelination หลายตำแหน่ง หลายช่วงเวลา (optic neuritis, weakness, sensory, INO); MRI = periventricular white-matter lesions; CSF oligoclonal bands. รักษา acute relapse ด้วย steroid; disease-modifying therapy ระยะยาว.", "id": "set5-10"}, {"topic": "Neurology", "q": "An elderly patient has a resting tremor, bradykinesia, rigidity, and postural instability. What is the diagnosis?", "choices": ["Parkinson disease", "Essential tremor", "Cerebellar disease", "Huntington disease", "Wilson disease"], "ans": 0, "exp": "Parkinson disease: resting tremor (pill-rolling) + bradykinesia + rigidity (cogwheel) + postural instability, asymmetric onset. รักษาด้วย levodopa/carbidopa, dopamine agonist. Essential tremor เป็น action tremor (ดีขึ้นด้วยแอลกอฮอล์/propranolol).", "id": "set5-11"}, {"topic": "Neurology", "q": "A patient has trigeminal neuralgia with brief electric-shock-like facial pain triggered by touch. What is the first-line medication?", "choices": ["Paracetamol", "Carbamazepine", "Opioid analgesics", "Gabapentin alone", "Amitriptyline"], "ans": 1, "exp": "Trigeminal neuralgia (paroxysmal electric-shock facial pain ตาม trigeminal) first-line = carbamazepine (หรือ oxcarbazepine). ผ่าตัด microvascular decompression ในรายดื้อยา.", "id": "set5-12"}, {"topic": "Neurology", "q": "A patient with a cluster headache has severe unilateral periorbital pain with ipsilateral lacrimation and rhinorrhea in bouts. What is the acute treatment?", "choices": ["An oral triptan tablet", "Paracetamol", "High-flow oxygen or SC sumatriptan", "Carbamazepine", "Antibiotics"], "ans": 2, "exp": "Cluster headache: ปวดรอบตาข้างเดียวรุนแรง + autonomic (น้ำตา/คัดจมูก) เป็นชุด. รักษาเฉียบพลันด้วย high-flow oxygen 100% และ/หรือ SC sumatriptan; ป้องกันด้วย verapamil.", "id": "set5-13"}, {"topic": "Neurology", "q": "A patient has a peripheral facial (Bell) palsy affecting the forehead. What distinguishes it from a central (stroke) facial palsy?", "choices": ["There is no clinical difference", "Peripheral spares the forehead", "Both types spare the forehead", "Central palsy spares the forehead", "Both involve the forehead equally"], "ans": 3, "exp": "Peripheral (LMN, Bell) palsy โดนทั้งใบหน้ารวมหน้าผาก; central (UMN, stroke) spares forehead (เพราะ bilateral cortical innervation ส่วนบน). Bell palsy รักษาด้วย corticosteroid (± antiviral) เร็ว + eye care.", "id": "set5-14"}, {"topic": "Neurology", "q": "A patient with new headache, papilledema, and focal deficit should be evaluated for what before lumbar puncture?", "choices": ["No investigation is needed", "Blood glucose only", "An ECG only", "A chest X-ray only", "Raised ICP lesion; obtain CT or MRI"], "ans": 4, "exp": "Headache + papilledema + focal deficit = สงสัย raised ICP/mass — ต้อง neuroimaging (CT/MRI) ก่อน LP เพื่อเลี่ยง herniation. หาสาเหตุ (tumor, abscess, hemorrhage).", "id": "set5-15"}, {"topic": "Neurology", "q": "A patient develops a sudden severe headache with neck stiffness and photophobia but no fever; CT confirms blood in the subarachnoid space. What is the most common underlying cause?", "choices": ["Ruptured berry (saccular) aneurysm", "A hypertensive intracerebral bleed", "An AV malformation only", "Head trauma only", "A brain tumor"], "ans": 0, "exp": "Non-traumatic subarachnoid hemorrhage ส่วนใหญ่จาก ruptured saccular (berry) aneurysm. ต้อง CT/DSA angiography หา aneurysm + secure (coiling/clipping) + ป้องกัน vasospasm (nimodipine).", "id": "set5-16"}, {"topic": "Neurology", "q": "A diabetic patient has burning, tingling, and numbness in a stocking distribution. What is the pattern and a first-line drug?", "choices": ["A radiculopathy; refer for surgery", "Diabetic polyneuropathy; give pregabalin", "Mononeuritis multiplex; give a steroid", "A myopathy; caused by a statin", "A plexopathy; observation only"], "ans": 1, "exp": "Diabetic distal symmetric polyneuropathy (stocking-glove) รักษา neuropathic pain ด้วย pregabalin/gabapentin, duloxetine, หรือ TCA. คุมน้ำตาล + ดูแลเท้าเพื่อป้องกันแผล.", "id": "set5-17"}, {"topic": "Neurology", "q": "A patient has an acute ischemic stroke with atrial fibrillation. When is anticoagulation typically started?", "choices": ["Immediately, within the first few hours", "It should never be given at all", "Delayed anticoagulation by infarct size", "Only same-day warfarin", "Only if the patient is bleeding"], "ans": 2, "exp": "ใน cardioembolic stroke (AF) การเริ่ม anticoagulation ล่าช้าตามขนาด infarct (เช่น '1-3-6-12 day rule') เพื่อลด hemorrhagic transformation. ระยะเฉียบพลันให้ aspirin ก่อน.", "id": "set5-18"}, {"topic": "Neurology", "q": "A patient has a lacunar stroke presenting as pure motor hemiparesis. Which vessels/mechanism are typically involved?", "choices": ["A large-artery embolism", "Cerebral venous thrombosis", "A cardioembolic source", "Small-vessel lacunar occlusion", "An underlying vasculitis"], "ans": 3, "exp": "Lacunar infarcts (pure motor, pure sensory, ataxic hemiparesis) เกิดจาก small-vessel disease (lipohyalinosis) สัมพันธ์ chronic HT/DM. ป้องกันด้วยคุมปัจจัยเสี่ยง + antiplatelet.", "id": "set5-19"}, {"topic": "Neurology", "q": "A comatose patient with pinpoint pupils, slow shallow breathing (RR 6), and evidence of IV drug use should receive which antidote?", "choices": ["Flumazenil", "Atropine", "Glucose alone", "Thiamine alone", "Naloxone"], "ans": 4, "exp": "Pinpoint pupils + respiratory depression + IVDU = opioid overdose → naloxone (opioid antagonist) + airway/ventilation support. (แนวข้อสอบ NLE2)", "id": "set5-20"}, {"topic": "Neurology", "q": "A patient presents with vertigo, and you need to distinguish peripheral from central causes. Which finding suggests a central (dangerous) cause?", "choices": ["Vertical/direction-changing nystagmus", "Fatigable horizontal nystagmus", "Positive Dix-Hallpike with brief vertigo", "Improvement with the Epley maneuver", "Tinnitus with hearing loss"], "ans": 0, "exp": "Central vertigo: nystagmus เปลี่ยนทิศ/แนวตั้ง, ไม่ fatigable, มี neuro signs อื่น (dysarthria, ataxia, diplopia), HINTS exam abnormal → นึกถึง posterior stroke. Peripheral (BPPV/vestibular neuritis) มัก fatigable + Epley ช่วย.", "id": "set5-21"}, {"topic": "Neurology", "q": "A patient with a brain abscess (ring-enhancing lesion with edema) and fever. Besides antibiotics, what is often required?", "choices": ["No further intervention is needed", "Neurosurgical drainage and aspiration", "Give thrombolysis", "Start anticoagulation", "Give chemotherapy"], "ans": 1, "exp": "Brain abscess (ring-enhancing + edema + fever + source เช่น หูชั้นกลาง/ฟัน/endocarditis) มักต้อง neurosurgical aspiration + prolonged antibiotics ตามเชื้อ + จัดการ raised ICP.", "id": "set5-22"}, {"topic": "Neurology", "q": "A patient with wrist drop after prolonged pressure on the arm has which nerve palsy?", "choices": ["The median nerve", "The ulnar nerve", "The radial nerve", "The axillary nerve", "The musculocutaneous nerve"], "ans": 2, "exp": "Wrist drop (extensor weakness) จากการกดทับที่ spiral groove (Saturday night palsy) = radial nerve palsy. Median → carpal tunnel; ulnar → claw hand/clumsy grip.", "id": "set5-23"}, {"topic": "Neurology", "q": "A patient with delirium is acutely confused with fluctuating attention. What is the most important first step?", "choices": ["Sedate the patient immediately", "Start a long-term antipsychotic", "Use physical restraints first-line", "Identify and treat the underlying cause", "Discharge the patient home"], "ans": 3, "exp": "Delirium (acute, fluctuating attention/consciousness) เป็นภาวะเฉียบพลันจากสาเหตุกาย — หาและแก้สาเหตุ (UTI/pneumonia, electrolyte, ยา, hypoxia, ถอนสุรา). จัดการสิ่งแวดล้อม; ยาเป็นทางเลือกสุดท้ายเมื่อจำเป็น.", "id": "set5-24"}, {"topic": "Neurology", "q": "An alcoholic patient develops confusion, ophthalmoplegia, and ataxia. What is the diagnosis and treatment?", "choices": ["Acute stroke; give thrombolysis", "Delirium tremens; give a benzodiazepine", "Hepatic encephalopathy; give lactulose", "Hypoglycemia; give glucose only", "Wernicke encephalopathy; give IV thiamine"], "ans": 4, "exp": "Wernicke encephalopathy (confusion + ophthalmoplegia + ataxia) จาก thiamine deficiency — ให้ IV thiamine ทันที (ก่อน glucose). ถ้าไม่รักษาอาจเป็น Korsakoff (memory ถาวร).", "id": "set5-25"}, {"topic": "Misc", "q": "A patient in shock has cold clammy extremities, JVP elevated, and pulmonary edema after an MI. What type of shock is this?", "choices": ["Cardiogenic shock", "Hypovolemic shock", "Distributive (septic) shock", "Obstructive shock", "Anaphylactic shock"], "ans": 0, "exp": "หลัง MI + pump failure (JVP สูง, pulmonary edema, cold extremities) = cardiogenic shock. รักษาด้วย inotrope/vasopressor + แก้สาเหตุ (revascularization); mechanical support ในรายรุนแรง.", "id": "set5-26"}, {"topic": "Misc", "q": "A patient with fever and hypotension has warm extremities and a wide pulse pressure with a high cardiac output. What type of shock is this?", "choices": ["Cardiogenic shock", "Distributive (septic) shock", "Hypovolemic shock", "Obstructive shock", "Neurogenic shock only"], "ans": 1, "exp": "Distributive (septic) shock: vasodilation → warm extremities, wide pulse pressure, high/normal CO, low SVR. รักษาด้วย fluid + norepinephrine + antibiotics + source control.", "id": "set5-27"}, {"topic": "Misc", "q": "A trauma patient has distended neck veins, hypotension, and muffled heart sounds. What is the diagnosis and treatment?", "choices": ["Tension pneumothorax; needle decompression", "Hemorrhagic shock; give transfusion", "Cardiac tamponade; do pericardiocentesis", "Septic shock; give antibiotics", "Neurogenic shock; give a vasopressor"], "ans": 2, "exp": "Beck triad (hypotension + distended neck veins + muffled heart sounds) = cardiac tamponade (obstructive shock). รักษาด้วย pericardiocentesis/pericardial window. Tension pneumothorax ก็ทำให้ neck vein distend แต่มี absent breath sound + tracheal deviation.", "id": "set5-28"}, {"topic": "Misc", "q": "A patient develops urticaria, wheeze, and hypotension minutes after a drug. What is the first-line treatment?", "choices": ["IV hydrocortisone", "IV antihistamine", "Nebulized salbutamol only", "Intramuscular adrenaline (epinephrine)", "IV fluids only"], "ans": 3, "exp": "Anaphylaxis รักษาลำดับแรกด้วย IM adrenaline ที่ต้นขาด้านนอกทันที + จัดท่า + O2 + IV fluid; antihistamine/steroid เป็น adjunct. หยุด trigger; สังเกตอาการ biphasic.", "id": "set5-29"}, {"topic": "Misc", "q": "At what age should average-risk adults begin colorectal cancer screening (a commonly tested prevention point)?", "choices": ["At age 40 years", "At age 50 years", "At age 55 years", "At age 60 years", "At age 45 years"], "ans": 4, "exp": "USPSTF 2021 แนะนำเริ่มคัดกรอง colorectal cancer อายุ 45 ปีในคนความเสี่ยงปกติ (colonoscopy ทุก 10 ปี หรือ FIT ทุกปี).", "id": "set5-30"}, {"topic": "Misc", "q": "Which cancer screening is recommended for a woman in her 30s (cervical cancer)?", "choices": ["Pap smear with HPV co-testing", "No screening is needed", "A mammogram only", "A colonoscopy", "A CA-125 blood test"], "ans": 0, "exp": "Cervical cancer screening: Pap smear ± HPV testing ตามช่วงอายุ (มักเริ่ม 25–30, HPV-based เป็นหลักในช่วง 30–65). วัคซีน HPV เป็นการป้องกันปฐมภูมิ.", "id": "set5-31"}, {"topic": "Misc", "q": "A terminally ill patient has severe cancer pain. According to the WHO analgesic ladder and modern practice, how should opioids be used?", "choices": ["Avoid opioids entirely", "Titrate opioids; add a laxative", "Use only paracetamol", "Only when death is imminent", "A fixed low dose regardless of pain"], "ans": 1, "exp": "Cancer pain ปานกลาง-รุนแรง ใช้ opioid titrate ตามอาการ (ไม่มี ceiling สำหรับ pure agonist) + ให้ laxative ป้องกันท้องผูก + จัดการ breakthrough pain. เป้าคือคุณภาพชีวิต ไม่ใช่เร่ง/ชะลอความตาย.", "id": "set5-32"}, {"topic": "Misc", "q": "Which framework is used for delivering bad news to patients?", "choices": ["The ABCDE approach", "The FAST tool", "The SPIKES protocol", "The SAMPLE history", "The AMPLE history"], "ans": 2, "exp": "SPIKES: Setting, Perception, Invitation, Knowledge, Emotion (empathy), Strategy/Summary — ใช้สื่อสารข่าวร้ายอย่างเป็นระบบและเห็นอกเห็นใจ.", "id": "set5-33"}, {"topic": "Misc", "q": "A patient presents with a pearly, telangiectatic papule on the face that occasionally bleeds. What is the most likely diagnosis?", "choices": ["Squamous cell carcinoma", "Malignant melanoma", "Seborrheic keratosis", "Basal cell carcinoma", "Actinic keratosis"], "ans": 3, "exp": "Pearly papule + telangiectasia + occasional bleeding บนใบหน้า (sun-exposed) = basal cell carcinoma (พบบ่อยสุด, โตช้า, metastasis น้อย). รักษาด้วย excision. (แนวข้อสอบ NLE2)", "id": "set5-34"}, {"topic": "Misc", "q": "A pigmented skin lesion shows Asymmetry, irregular Border, Color variation, Diameter > 6 mm, and Evolution. What should be done?", "choices": ["Reassure without biopsy", "Blind cryotherapy", "A topical corticosteroid", "Observe for one year", "Excisional biopsy to exclude melanoma"], "ans": 4, "exp": "ABCDE ที่ผิดปกติ = สงสัย melanoma → excisional biopsy (full thickness) เพื่อวินิจฉัยและวัด Breslow thickness (กำหนด prognosis/wide excision margin + SLNB).", "id": "set5-35"}, {"topic": "Misc", "q": "A 20-year-old has a single 'herald patch' followed by a 'Christmas tree' distribution of scaly oval plaques on the trunk. What is the diagnosis?", "choices": ["Pityriasis rosea", "Tinea corporis", "Secondary syphilis", "Psoriasis", "Atopic dermatitis"], "ans": 0, "exp": "Herald patch ตามด้วยผื่นรูปไข่เรียงตาม cleavage lines (Christmas tree) = pityriasis rosea (self-limited). ควรตัด secondary syphilis ออกถ้ามีปัจจัยเสี่ยง (โดนฝ่ามือ/เท้า). (แนวข้อสอบ NLE2)", "id": "set5-36"}, {"topic": "Misc", "q": "A patient develops a target-shaped (iris) lesions and mucosal involvement after a drug or infection. What is the diagnosis?", "choices": ["Acute urticaria", "Erythema multiforme", "Pityriasis rosea", "Psoriasis", "Eczema"], "ans": 1, "exp": "Target/iris lesions = erythema multiforme (มัก HSV/ยา); ถ้ามี mucosal + skin detachment มากขึ้น → Stevens-Johnson syndrome/TEN (หยุดยาต้นเหตุ + supportive/burn-unit care).", "id": "set5-37"}, {"topic": "Misc", "q": "A patient on a new drug (e.g., allopurinol, sulfa, anticonvulsant) develops fever, rash, and skin sloughing with positive Nikolsky sign. What is the diagnosis and first step?", "choices": ["Cellulitis; give antibiotics", "Psoriasis; give a steroid", "Stevens-Johnson/TEN; stop the drug", "Eczema; apply an emollient", "Urticaria; give an antihistamine"], "ans": 2, "exp": "SJS/TEN (fever + mucocutaneous + epidermal detachment, Nikolsky positive) เป็นภาวะฉุกเฉิน — หยุดยาต้นเหตุทันที + supportive care (fluid, wound, temperature) ใน burn/ICU; ประเมิน SCORTEN.", "id": "set5-38"}, {"topic": "Misc", "q": "Which ECG/electrolyte pattern is seen in hyperkalemia?", "choices": ["U waves with flattened T waves", "A prolonged QT interval", "A delta wave", "Peaked T waves, wide QRS, sine wave", "An Osborn wave"], "ans": 3, "exp": "Hyperkalemia: peaked T → PR ยาว/P หาย → wide QRS → sine wave → arrest. Hypokalemia: U wave, flat T, ST depression. รักษา hyperK: calcium → insulin/glucose/salbutamol → removal.", "id": "set5-39"}, {"topic": "Misc", "q": "A patient with vomiting and nasogastric suction develops which acid-base disorder?", "choices": ["Metabolic acidosis", "Respiratory acidosis", "Respiratory alkalosis", "No acid-base change", "Hypochloremic, hypokalemic alkalosis"], "ans": 4, "exp": "เสีย HCl จากการอาเจียน/NG suction → hypochloremic hypokalemic metabolic alkalosis (chloride-responsive). รักษาด้วย isotonic saline + KCl.", "id": "set5-40"}, {"topic": "Misc", "q": "A patient with a suspected drug overdose is unconscious. Which is part of the initial 'coma cocktail'/approach for reversible causes?", "choices": ["Check glucose, thiamine, and naloxone", "Give empiric antibiotics", "Immediate CT scan only", "Give corticosteroids", "Give diuretics"], "ans": 0, "exp": "ผู้ป่วยหมดสติไม่ทราบสาเหตุ: ABC + ตรวจ/แก้ hypoglycemia (dextrose + thiamine), พิจารณา naloxone ถ้าสงสัย opioid, ประเมิน toxidrome + neuroimaging ตามข้อบ่งชี้.", "id": "set5-41"}, {"topic": "Misc", "q": "A patient with a high fever, muscle rigidity, altered mental status, and autonomic instability after starting an antipsychotic has which condition?", "choices": ["Serotonin syndrome", "Neuroleptic malignant syndrome", "Malignant hyperthermia", "Thyroid storm", "Heat stroke"], "ans": 1, "exp": "Neuroleptic malignant syndrome (หลัง antipsychotic/dopamine blocker): hyperthermia + lead-pipe rigidity + altered mental status + autonomic instability + CK สูง. หยุดยา + cooling + supportive ± dantrolene/bromocriptine.", "id": "set5-42"}, {"topic": "Misc", "q": "A patient on an SSRI plus another serotonergic drug develops agitation, hyperreflexia, clonus, and hyperthermia. What is the diagnosis?", "choices": ["Neuroleptic malignant syndrome", "Malignant hyperthermia", "Serotonin syndrome", "Anticholinergic toxicity", "Systemic sepsis"], "ans": 2, "exp": "Serotonin syndrome: agitation + neuromuscular hyperactivity (clonus, hyperreflexia — เด่นที่ขา) + autonomic + hyperthermia, onset เร็วหลังเพิ่ม serotonergic. หยุดยา + supportive ± cyproheptadine. ต่าง NMS ที่ rigidity/bradyreflexia และ onset ช้า.", "id": "set5-43"}, {"topic": "Misc", "q": "A patient with organophosphate poisoning has salivation, lacrimation, urination, defecation, miosis, and bradycardia. What is the antidote?", "choices": ["Naloxone", "Flumazenil", "Physostigmine", "Atropine (± pralidoxime)", "Glucagon"], "ans": 3, "exp": "Organophosphate (cholinergic/SLUDGE + miosis + bronchorrhea/bradycardia) รักษาด้วย atropine (block muscarinic) + pralidoxime (reactivate acetylcholinesterase) + decontamination + airway.", "id": "set5-44"}, {"topic": "Misc", "q": "A previously healthy young adult collapses; ECG shows a shockable rhythm. What is the immediate priority?", "choices": ["Obtain IV access first", "Intubate the patient first", "Give amiodarone first", "Take a full history first", "High-quality CPR, early defibrillation"], "ans": 4, "exp": "Cardiac arrest ด้วย shockable rhythm (VF/pVT): หัวใจของการรักษาคือ high-quality CPR + early defibrillation (ยิ่งเร็วยิ่งรอด) + epinephrine/amiodarone ตาม ACLS; หา reversible causes (H's & T's).", "id": "set5-45"}, {"topic": "Misc", "q": "A patient with chronic anticholinergic overdose is 'hot as a hare, dry as a bone, red as a beet, mad as a hatter, blind as a bat'. Which finding fits?", "choices": ["Dilated pupils, dry skin, retention", "Miosis with excess salivation", "Bradycardia with sweating", "Pinpoint pupils", "Marked bronchorrhea"], "ans": 0, "exp": "Anticholinergic toxidrome: mydriasis, dry/flushed skin, hyperthermia, urinary retention, delirium, tachycardia (ตรงข้าม cholinergic). รักษา supportive ± physostigmine ในบางราย.", "id": "set5-46"}, {"topic": "Misc", "q": "A palliative patient near end of life has distressing dyspnea. Which is appropriate for symptom relief?", "choices": ["Withhold all medication", "Low-dose opioids titrated for dyspnea", "Only oxygen regardless of cause", "Aggressive diuresis for all", "Antibiotics for all"], "ans": 1, "exp": "Dyspnea ในผู้ป่วยระยะท้ายบรรเทาด้วย low-dose opioid (titrate) ± anxiolytic + จัดท่า/พัดลม/oxygen ตามอาการ. เป้าหมายคือความสบาย (comfort) ตาม goals of care.", "id": "set5-47"}, {"topic": "Misc", "q": "A patient has a decision-making capacity question. Which four elements are assessed for capacity?", "choices": ["Age, education, wealth, and family", "Only the patient's understanding", "Understanding, appreciation, reasoning, choice", "Only the physician's own opinion", "The diagnosis alone"], "ans": 2, "exp": "Decision-making capacity ประเมิน 4 องค์ประกอบ: understanding, appreciation, reasoning, และ ability to communicate a choice. Capacity เป็นเรื่องเฉพาะการตัดสินใจและอาจเปลี่ยนตามเวลา.", "id": "set5-48"}, {"topic": "Mixed/Integrated", "q": "A patient with COPD presents drowsy after receiving high-flow oxygen; ABG shows pH 7.25, PaCO2 80, HCO3 34. What is the best intervention?", "choices": ["Increase the oxygen further", "Give IV bicarbonate", "Sedate the patient", "NIV with controlled oxygen", "Give diuretics"], "ans": 3, "exp": "Acute-on-chronic hypercapnic respiratory failure ใน COPD → NIV (BiPAP) + O2 แบบควบคุม (เป้า SpO2 88–92%). O2 สูงเกินลด hypoxic drive/เพิ่ม V/Q mismatch ทำให้ CO2 คั่ง.", "id": "set5-49"}, {"topic": "Mixed/Integrated", "q": "A patient with diabetes has an A1c of 9%, BP 150/90, and albuminuria. Which single drug addresses both renal protection and could be added for cardiovascular/renal benefit?", "choices": ["Amlodipine", "A beta-blocker", "Hydralazine", "A thiazide alone", "An ACE inhibitor/ARB plus an SGLT2i"], "ans": 4, "exp": "เบาหวาน + HT + albuminuria: ACEI/ARB เป็นแกน (ลด proteinuria/ชะลอไต + คุมความดัน) และเพิ่ม SGLT2i เพื่อ CV/renal protection. คุม A1c/lipid ร่วม.", "id": "set5-50"}, {"topic": "Mixed/Integrated", "q": "A patient presents with confusion, Na 110, and seizures. What is the most appropriate immediate treatment?", "choices": ["Careful 3% hypertonic saline", "Rapid full correction with normal saline", "Fluid restriction alone", "Give desmopressin", "Urgent dialysis"], "ans": 0, "exp": "Severe symptomatic hyponatremia (seizure) ให้ 3% hypertonic saline อย่างระมัดระวัง (เพิ่ม Na ~4–6 mEq/L เพื่อหยุดชัก, ไม่เกิน 8–10/24 ชม.) กัน osmotic demyelination. หาสาเหตุร่วม.", "id": "set5-51"}, {"topic": "Mixed/Integrated", "q": "A young woman has fatigue, weight gain, cold intolerance, and menorrhagia; TSH is elevated. Which anemia pattern may coexist?", "choices": ["Microcytic anemia from thalassemia", "Macrocytic anemia of hypothyroidism", "A hemolytic anemia", "A sideroblastic anemia", "An aplastic anemia"], "ans": 1, "exp": "Hypothyroidism อาจทำให้เกิด macrocytic/normocytic anemia (และ menorrhagia อาจเพิ่ม IDA). รักษา hypothyroidism ด้วย levothyroxine + ประเมิน iron/B12 ถ้ามี.", "id": "set5-52"}, {"topic": "Mixed/Integrated", "q": "A patient on warfarin for AF presents with an INR of 8 but no bleeding. What is appropriate management?", "choices": ["Continue the same warfarin dose", "Give fresh frozen plasma", "Hold warfarin ± oral vitamin K", "Give prothrombin complex concentrate", "Increase the warfarin dose"], "ans": 2, "exp": "INR สูงมาก (> 4.5–10) โดยไม่มีเลือดออก: หยุด warfarin ชั่วคราว ± vitamin K ขนาดต่ำ (oral) แล้วตรวจ INR ซ้ำ. PCC/FFP สงวนไว้เมื่อมี major bleeding.", "id": "set5-53"}, {"topic": "Mixed/Integrated", "q": "A patient with cirrhosis has new confusion, asterixis, and constipation. Besides lactulose, what is essential?", "choices": ["Sedate the patient", "A high-protein diet", "Escalate the diuretic dose", "Identify and treat the precipitant", "Paracentesis for all patients"], "ans": 3, "exp": "Hepatic encephalopathy: lactulose + หา/แก้ precipitant (เลือดออก GI, ติดเชื้อ/SBP, electrolyte, ท้องผูก, ยา sedative). rifaximin เสริม; หลีกเลี่ยง sedative.", "id": "set5-54"}, {"topic": "Mixed/Integrated", "q": "A patient with acute chest pain has a normal ECG and a normal high-sensitivity troponin at 0 and 3 hours. What does this suggest?", "choices": ["A definite STEMI", "Proceed to immediate PCI", "Pericarditis is confirmed", "Aortic dissection is confirmed", "Low likelihood of MI; seek other causes"], "ans": 4, "exp": "ECG ปกติ + hs-troponin ไม่เปลี่ยนแปลงที่ 0/3 ชม. ช่วย rule out acute MI (โอกาสต่ำ). ประเมินสาเหตุอื่นของ chest pain (GERD, MSK, PE, dissection ตามบริบท) + risk stratify.", "id": "set5-55"}, {"topic": "Mixed/Integrated", "q": "A patient with newly diagnosed HIV has a CD4 of 350. When should antiretroviral therapy be started?", "choices": ["As soon as possible, regardless of CD4 count", "Only when the CD4 falls below 200", "Only if the patient is symptomatic", "After a six-month delay", "Never while asymptomatic"], "ans": 0, "exp": "แนวทางปัจจุบันแนะนำเริ่ม ART ทันที (rapid start) ในผู้ติดเชื้อ HIV ทุกรายโดยไม่ขึ้นกับ CD4 เพื่อสุขภาพและลดการแพร่ (U=U).", "id": "set5-56"}, {"topic": "Mixed/Integrated", "q": "A patient with severe community-acquired pneumonia has hyponatremia, diarrhea, and confusion. Which pathogen is suggested?", "choices": ["Streptococcus pneumoniae", "Legionella pneumophila", "Mycoplasma pneumoniae", "Klebsiella pneumoniae", "Staphylococcus aureus"], "ans": 1, "exp": "Pneumonia + hyponatremia + diarrhea + confusion/relative bradycardia = Legionella (urine antigen). รักษาด้วย macrolide/respiratory fluoroquinolone.", "id": "set5-57"}, {"topic": "Mixed/Integrated", "q": "A diabetic patient has foot ulcer with surrounding cellulitis and probing to bone. What complication should be evaluated?", "choices": ["An acute gout flare", "A deep vein thrombosis", "Osteomyelitis (MRI, bone culture)", "Cellulitis only", "A Charcot joint only"], "ans": 2, "exp": "Diabetic foot ulcer ที่ probe-to-bone positive/ไม่หาย → สงสัย osteomyelitis (MRI ไวสุด; bone biopsy/culture นำการรักษา) + revascularization ถ้ามี PAD + prolonged antibiotics ± debridement.", "id": "set5-58"}, {"topic": "Mixed/Integrated", "q": "A patient with atrial fibrillation and mechanical heart valve requires anticoagulation. Which is appropriate?", "choices": ["Apixaban", "Aspirin only", "Dabigatran", "Warfarin (not a DOAC)", "No anticoagulation"], "ans": 3, "exp": "Mechanical heart valve ต้องใช้ warfarin เท่านั้น; DOAC เป็นข้อห้าม (RE-ALIGN trial แสดง dabigatran แย่กว่า). เป้า INR ตามชนิด/ตำแหน่งลิ้น.", "id": "set5-59"}, {"topic": "Mixed/Integrated", "q": "A patient presents with painless jaundice, weight loss, and a dilated bile duct with a pancreatic head mass. What is the next step?", "choices": ["Reassurance without work-up", "Empiric antibiotics", "ERCP for stones only", "Observation only", "Staging CT and EUS-guided biopsy"], "ans": 4, "exp": "Painless obstructive jaundice + pancreatic head mass = สงสัย pancreatic adenocarcinoma → contrast CT (staging/resectability) + tissue diagnosis (EUS-FNA); Whipple ถ้า resectable. Courvoisier sign สนับสนุน malignancy.", "id": "set5-60"}, {"topic": "Mixed/Integrated", "q": "A patient with heart failure on furosemide develops muscle weakness and ECG U waves. What is the electrolyte problem and risk?", "choices": ["Hypokalemia (worsened by digoxin)", "Hyperkalemia", "Hypernatremia", "Hypercalcemia", "Hypomagnesemia only"], "ans": 0, "exp": "Loop diuretic ทำให้ hypokalemia (U wave, weakness) เพิ่มเสี่ยง arrhythmia และ digoxin toxicity. แก้ K + Mg; พิจารณา K-sparing (MRA) ที่เป็นเสาหลักใน HFrEF อยู่แล้ว.", "id": "set5-61"}, {"topic": "Mixed/Integrated", "q": "A patient with chronic kidney disease has fatigue and pallor; Hb 8.5, iron studies adequate. What is appropriate treatment?", "choices": ["Blood transfusion for all patients", "An ESA after ensuring iron stores", "High-dose IV iron only", "Vitamin B12 supplementation", "Observation only"], "ans": 1, "exp": "Anemia of CKD (EPO ต่ำ) รักษาด้วย ESA เมื่อ iron เพียงพอ, เป้า Hb ~10–11.5 (ไม่สูงเกิน — เสี่ยง CV/stroke). Transfusion เฉพาะเมื่อจำเป็น.", "id": "set5-62"}, {"topic": "Mixed/Integrated", "q": "A patient with rheumatoid arthritis on methotrexate develops a dry cough and dyspnea with new infiltrates. What must be considered?", "choices": ["Simple acute bronchitis", "Bronchial asthma", "Methotrexate pneumonitis or infection", "Gastroesophageal reflux", "An anxiety disorder"], "ans": 2, "exp": "Methotrexate อาจทำให้เกิด pneumonitis (hypersensitivity) และเพิ่มเสี่ยงการติดเชื้อ (รวม PCP/atypical) — ผู้ป่วย immunosuppressed ที่มีอาการทางเดินหายใจต้องประเมินทั้งสอง (หยุดยา, imaging, work-up).", "id": "set5-63"}, {"topic": "Mixed/Integrated", "q": "A patient presents with acute severe hypertension, headache, and pulmonary edema. Which is a hypertensive emergency requiring IV therapy?", "choices": ["Asymptomatic BP of 160/100", "White-coat hypertension", "Isolated systolic HT, no symptoms", "Hypertension with acute organ damage", "Masked hypertension"], "ans": 3, "exp": "Hypertensive emergency = BP สูง + acute target-organ damage → IV antihypertensive แบบควบคุม. Asymptomatic BP สูง (urgency) ใช้ยากินและติดตาม ไม่ต้องลดเร็ว.", "id": "set5-64"}, {"topic": "Mixed/Integrated", "q": "A patient with type 2 diabetes and a recent MI needs a glucose-lowering agent with cardiovascular benefit. Which is appropriate?", "choices": ["A sulfonylurea", "Basal insulin only", "A thiazolidinedione", "Acarbose", "A GLP-1 agonist or SGLT2 inhibitor"], "ans": 4, "exp": "T2DM + ASCVD/หลัง MI: เลือก GLP-1 RA หรือ SGLT2i ที่มีหลักฐานลด CV events โดยไม่ขึ้นกับ A1c. หลีกเลี่ยง TZD (HF), ระวัง hypoglycemia จาก sulfonylurea/insulin.", "id": "set5-65"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and a heart murmur has multiple septic emboli and blood cultures positive for Staph aureus. What is the diagnosis and key imaging?", "choices": ["Infective endocarditis; echocardiography", "Rheumatic fever; ASO titer", "Acute myocarditis; cardiac MRI", "Acute pericarditis; ECG", "Pulmonary embolism; CTPA"], "ans": 0, "exp": "IE (ไข้ + murmur + emboli + positive blood culture) — ทำ echocardiography หา vegetation (TEE ไวกว่า TTE) + ให้ IV antibiotics ตามเชื้อ 4–6 สัปดาห์; ผ่าตัดตามข้อบ่งชี้ (HF, abscess, large vegetation, resistant infection).", "id": "set5-66"}, {"topic": "Mixed/Integrated", "q": "A patient with cirrhosis develops rapidly worsening renal function with a bland urinalysis and no response to volume expansion. What is the diagnosis?", "choices": ["Acute tubular necrosis", "Hepatorenal syndrome", "Acute glomerulonephritis", "Prerenal from dehydration", "Postrenal obstruction"], "ans": 1, "exp": "AKI ใน cirrhosis ที่ bland urine + ไม่ตอบสนอง albumin/volume + ตัดสาเหตุอื่น = hepatorenal syndrome. รักษาด้วย terlipressin/noradrenaline + albumin; liver transplant เป็น definitive.", "id": "set5-67"}, {"topic": "Mixed/Integrated", "q": "A patient with sepsis has lactate 5 mmol/L. What does an elevated lactate indicate and guide?", "choices": ["A completely normal finding", "Liver failure alone", "Tissue hypoperfusion guiding resuscitation", "Renal failure alone", "It can be ignored"], "ans": 2, "exp": "Lactate สูงใน sepsis สะท้อน tissue hypoperfusion/ความรุนแรง ใช้เป็นเป้า resuscitation (lactate clearance). ให้ fluid + norepinephrine + antibiotics + source control และติดตาม lactate ซ้ำ.", "id": "set5-68"}, {"topic": "Mixed/Integrated", "q": "A patient with a swollen, painful calf after a long flight has a positive D-dimer and compression ultrasound confirms DVT. What is the treatment?", "choices": ["Aspirin", "An IVC filter for all", "Thrombolysis for all", "Anticoagulation (a DOAC first-line)", "Observation only"], "ans": 3, "exp": "DVT รักษาด้วย anticoagulation (DOAC เป็น first-line ในรายไม่มีข้อห้าม); LMHW ในมะเร็ง/ตั้งครรภ์. IVC filter เฉพาะเมื่อมีข้อห้ามต่อ anticoagulation.", "id": "set5-69"}, {"topic": "Mixed/Integrated", "q": "A patient with an anaphylactic reaction has been given IM adrenaline but remains hypotensive. What is the next step?", "choices": ["Only observe the patient", "Give an oral antihistamine", "Discharge the patient", "Give a beta-blocker", "Repeat IM adrenaline plus IV fluids"], "ans": 4, "exp": "Anaphylaxis ที่ยัง hypotensive: ให้ IM adrenaline ซ้ำทุก 5–15 นาที + IV fluid bolus + พิจารณา adrenaline infusion; airway/O2. Adjunct: antihistamine, steroid. สังเกต biphasic reaction.", "id": "set5-70"}, {"topic": "Mixed/Integrated", "q": "A patient with type 1 diabetes presents with DKA. During treatment, potassium is 3.2 mEq/L. What should be done before continuing insulin?", "choices": ["Replace potassium before insulin", "Give even more insulin", "Give sodium bicarbonate", "Stop all IV fluids", "Give calcium gluconate"], "ans": 0, "exp": "ใน DKA ถ้า K < 3.3 ต้องเติม K ก่อน/ระหว่างก่อนให้ insulin เต็มที่ เพราะ insulin จะดัน K เข้าเซลล์ทำให้ hypokalemia รุนแรง (arrhythmia). ให้ fluid + monitor K ทุก 2–4 ชม.", "id": "set5-71"}, {"topic": "Mixed/Integrated", "q": "A patient develops sudden monocular vision loss ('curtain coming down') that resolves in minutes. What is this and what does it warrant?", "choices": ["A migraine aura", "Amaurosis fugax; assess carotids", "Retinal detachment", "Optic neuritis", "A cataract"], "ans": 1, "exp": "Amaurosis fugax (transient monocular blindness) = retinal TIA — ประเมิน carotid stenosis + stroke risk factors + antiplatelet/statin; carotid endarterectomy ถ้า stenosis รุนแรงมีอาการ.", "id": "set5-72"}, {"topic": "Mixed/Integrated", "q": "A patient with fever, productive cough, and consolidation has CURB-65 of 3. What is the appropriate disposition?", "choices": ["Discharge with oral antibiotics", "No treatment needed", "Admit (± ICU) for IV antibiotics", "Outpatient follow-up in a week", "Antivirals only"], "ans": 2, "exp": "CURB-65 = 3 บ่งชี้ pneumonia รุนแรง → admit (พิจารณา ICU) + IV antibiotic (β-lactam + macrolide หรือ respiratory FQ). CURB-65 0–1 มัก OPD.", "id": "set5-73"}, {"topic": "Mixed/Integrated", "q": "A patient on ACE inhibitor develops a persistent dry cough. What is the appropriate change?", "choices": ["Stop all antihypertensives", "Add a beta-blocker", "Increase the ACE inhibitor", "Switch to an ARB", "Add a long-term antitussive"], "ans": 3, "exp": "ACE inhibitor cough (จาก bradykinin) → เปลี่ยนเป็น ARB (ไม่ทำให้ไอ) โดยยังคงประโยชน์ต่อไต/หัวใจ. ระวัง angioedema (ต้องหยุดและไม่ใช้ ACEI อีก).", "id": "set5-74"}, {"topic": "Mixed/Integrated", "q": "A patient with a first unprovoked seizure has a normal exam, normal labs, and normal imaging/EEG. What is the general approach?", "choices": ["Start a lifelong drug immediately for all", "No follow-up is needed", "Proceed to immediate surgery", "Sedate the patient", "Individualized decision to start therapy"], "ans": 4, "exp": "First unprovoked seizure: ประเมินหาสาเหตุ (imaging, EEG, labs). การเริ่มยาขึ้นกับความเสี่ยงกลับเป็นซ้ำ (EEG/MRI abnormal เพิ่มเสี่ยง) — มักเริ่มหลัง seizure ที่สอง หรือรายที่เสี่ยงสูง; ให้คำแนะนำเรื่องขับรถ/ความปลอดภัย.", "id": "set5-75"}, {"topic": "Mixed/Integrated", "q": "A patient with hypertension, hypokalemia, and metabolic alkalosis has an elevated aldosterone and suppressed renin. What is the diagnosis?", "choices": ["Primary aldosteronism", "Pheochromocytoma", "Cushing syndrome", "Renal artery stenosis", "Bartter syndrome"], "ans": 0, "exp": "HT + hypokalemia + metabolic alkalosis + aldosterone สูง/renin ต่ำ = primary aldosteronism. ยืนยัน confirmatory + adrenal imaging/AVS; รักษา MRA หรือผ่าตัด (unilateral adenoma).", "id": "set5-76"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute flank pain, hematuria, and imaging shows a 4 mm ureteric stone without obstruction/infection. What is appropriate management?", "choices": ["Immediate surgery", "Analgesia, hydration, and an alpha-blocker", "Antibiotics for all", "Urgent dialysis", "Chemotherapy"], "ans": 1, "exp": "นิ่วท่อไตขนาดเล็ก (< 5–10 mm) ไม่มี obstruction/ติดเชื้อ: analgesia (NSAID), hydration, medical expulsive therapy (tamsulosin) รอนิ่วหลุด + ติดตาม. Intervention ถ้านิ่วใหญ่/อุดตัน/ติดเชื้อ/ปวดคุมไม่ได้.", "id": "set5-77"}, {"topic": "Mixed/Integrated", "q": "A patient with a suspected pulmonary embolism is hemodynamically stable with a high pretest probability. What is the best test?", "choices": ["Serum D-dimer", "Chest X-ray", "CT pulmonary angiography", "Bedside echocardiography", "Sputum culture"], "ans": 2, "exp": "High pretest probability PE → CT pulmonary angiography (gold standard) โดยไม่ต้องรอ D-dimer. D-dimer มีประโยชน์เฉพาะ low/intermediate probability เพื่อ rule out.", "id": "set5-78"}, {"topic": "Mixed/Integrated", "q": "A patient with fever, jaundice, RUQ pain, hypotension, and confusion (Reynolds pentad) needs which urgent intervention?", "choices": ["Cholecystectomy first", "Observation only", "A Whipple procedure", "ERCP decompression plus antibiotics", "Paracentesis"], "ans": 3, "exp": "Reynolds pentad (Charcot triad + hypotension + confusion) = suppurative ascending cholangitis รุนแรง → resuscitate + IV antibiotics + urgent biliary decompression (ERCP). Source control สำคัญ.", "id": "set5-79"}, {"topic": "Mixed/Integrated", "q": "A patient with hyperthyroidism and new AF should receive which for rate control (and consideration for stroke prevention)?", "choices": ["Digoxin only", "Amiodarone first-line", "Adenosine", "No treatment", "Beta-blocker for rate control"], "ans": 4, "exp": "Hyperthyroid + AF: beta-blocker คุม rate/อาการ + รักษา hyperthyroid (ATD). ประเมิน anticoagulation ตาม CHA2DS2-VASc. AF มักกลับเป็น sinus เมื่อ euthyroid.", "id": "set5-80"}, {"topic": "Mixed/Integrated", "q": "A patient with severe anemia (Hb 5) from chronic GI bleeding is hemodynamically stable. What is the appropriate transfusion approach?", "choices": ["Restrictive transfusion; treat the source", "Withhold transfusion", "Transfuse up to Hb 12", "Give platelets", "Give iron only"], "ans": 0, "exp": "Chronic GI bleeding + anemia รุนแรง: ให้ PRC ตาม restrictive target (~7, หรือ 8 ในโรคหัวใจ) + iron + endoscopic investigation/treatment ของแหล่งเลือดออก (colonoscopy/EGD).", "id": "set5-81"}, {"topic": "Mixed/Integrated", "q": "A patient with newly diagnosed hypertension is young (<40) with resistant BP and an abdominal bruit. What secondary cause should be evaluated?", "choices": ["Primary aldosteronism only", "Renal artery stenosis (fibromuscular)", "Cushing syndrome only", "Pheochromocytoma only", "White-coat hypertension"], "ans": 1, "exp": "HT อายุน้อย + resistant + abdominal bruit → renal artery stenosis (young women: fibromuscular dysplasia; older: atherosclerotic). ประเมินด้วย duplex/CTA/MRA; ระวัง Cr เพิ่มหลัง ACEI.", "id": "set5-82"}, {"topic": "Mixed/Integrated", "q": "A patient with community-acquired pneumonia fails to improve after 3 days of appropriate antibiotics and develops a loculated effusion with low pH. What is needed?", "choices": ["Continue the same antibiotics only", "Observation only", "Chest tube drainage of the empyema", "Diuretic therapy", "Corticosteroids"], "ans": 2, "exp": "Complicated parapneumonic effusion/empyema (pH < 7.2, loculated, หนอง) ที่ไม่ตอบสนอง antibiotic ต้อง chest tube drainage (± intrapleural fibrinolytic/VATS). Source control สำคัญ.", "id": "set5-83"}, {"topic": "Mixed/Integrated", "q": "A patient with fatigue and pallor has a macrocytic anemia; further testing shows low B12 and anti-intrinsic factor antibodies. What is the diagnosis?", "choices": ["Folate deficiency", "Iron deficiency", "Thalassemia trait", "Pernicious anemia (B12 deficiency)", "Hemolytic anemia"], "ans": 3, "exp": "Macrocytic anemia + B12 ต่ำ + anti-intrinsic factor/parietal cell antibody = pernicious anemia (autoimmune gastritis). รักษาด้วย B12 (IM/oral high-dose); สัมพันธ์ autoimmune อื่นและ gastric cancer risk.", "id": "set5-84"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute pancreatitis with a calcium of 6.5 mg/dL and tetany. What does hypocalcemia here indicate?", "choices": ["A sign of mild disease", "Underlying hyperparathyroidism", "A completely normal finding", "Vitamin D excess", "A marker of severity (fat saponification)"], "ans": 4, "exp": "Hypocalcemia ใน acute pancreatitis (จาก fat saponification/calcium sequestration) เป็นตัวบ่งชี้ความรุนแรง (Ranson criterion). แก้ symptomatic hypocalcemia + จัดการ pancreatitis.", "id": "set5-85"}, {"topic": "Mixed/Integrated", "q": "A patient with a chronic cough, weight loss, and hemoptysis has a lung mass; biopsy shows small cell carcinoma with SIADH. What is the paraneoplastic electrolyte finding?", "choices": ["Hyponatremia", "Hypercalcemia", "Hyperkalemia", "Hypernatremia", "Hypophosphatemia"], "ans": 0, "exp": "Small cell lung cancer หลั่ง ADH ectopic → SIADH → euvolemic hyponatremia. (Squamous cell → hypercalcemia จาก PTHrP). รักษา SIADH ด้วยจำกัดน้ำ + รักษามะเร็ง.", "id": "set5-86"}, {"topic": "Mixed/Integrated", "q": "A patient with acute kidney injury has hyperkalemia with ECG changes and pulmonary edema unresponsive to medical therapy. What is indicated?", "choices": ["More diuretics only", "Urgent hemodialysis", "More IV fluids", "Observation only", "Corticosteroids"], "ans": 1, "exp": "AKI ที่มี refractory hyperkalemia + pulmonary edema (overload) ที่ไม่ตอบสนองยา = ข้อบ่งชี้ urgent dialysis (AEIOU). ให้ calcium/insulin-glucose ระหว่างเตรียม dialysis.", "id": "set5-87"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and neck stiffness has a petechial rash and rapid deterioration. What empiric treatment should not be delayed?", "choices": ["Antiviral therapy", "Antifungal therapy", "Immediate ceftriaxone + dexamethasone", "Observation only", "An antihistamine"], "ans": 2, "exp": "Meningococcal meningitis/septicemia (fever + neck stiffness + petechiae) — ให้ ceftriaxone ทันที (± dexamethasone) โดยไม่รอผล LP ถ้าจะ delay; แจ้ง prophylaxis ผู้สัมผัส.", "id": "set5-88"}, {"topic": "Mixed/Integrated", "q": "A patient develops warfarin-associated major GI bleeding with INR 6. What is the appropriate reversal?", "choices": ["Oral vitamin K only", "Protamine sulfate", "Fresh frozen plasma slowly only", "Prothrombin complex + vitamin K", "Platelet transfusion"], "ans": 3, "exp": "Major bleeding on warfarin: 4-factor PCC (rapid reversal) + IV vitamin K (sustained). FFP ถ้าไม่มี PCC. Protamine ใช้กับ heparin; DOAC มี specific reversal (idarucizumab/andexanet).", "id": "set5-89"}, {"topic": "Mixed/Integrated", "q": "A patient with chronic alcohol use is admitted and develops tremor, agitation, hallucinations, and autonomic instability 2–3 days after stopping. What is the diagnosis and treatment?", "choices": ["Wernicke; give thiamine only", "Sepsis; give antibiotics", "Hepatic encephalopathy; give lactulose", "Serotonin syndrome; give cyproheptadine", "Delirium tremens; benzodiazepine + thiamine"], "ans": 4, "exp": "Delirium tremens (2–3 วันหลังหยุดสุรา): agitation, hallucination, autonomic instability, seizure — รักษาด้วย benzodiazepine (symptom-triggered) + thiamine + fluids/electrolyte. เป็นภาวะที่เสียชีวิตได้.", "id": "set5-90"}, {"topic": "Mixed/Integrated", "q": "A patient with metabolic acidosis has a high anion gap; history reveals antifreeze ingestion and calcium oxalate crystals in urine. What is the diagnosis and antidote?", "choices": ["Ethylene glycol; give fomepizole", "Methanol; give ethanol", "Salicylate; give bicarbonate", "Isoniazid; give pyridoxine", "Uremia; give dialysis"], "ans": 0, "exp": "Ethylene glycol (antifreeze) → high anion gap metabolic acidosis + calcium oxalate crystals + AKI. รักษาด้วย fomepizole (block alcohol dehydrogenase) ± hemodialysis. Methanol ให้ตาบอด + fomepizole เช่นกัน.", "id": "set5-91"}, {"topic": "Mixed/Integrated", "q": "A patient with fever and right-sided flank pain, pyuria, and an obstructing stone is septic. What is the priority?", "choices": ["Antibiotics alone", "Urgent decompression plus antibiotics", "Immediate lithotripsy", "Observation only", "Diuretic therapy"], "ans": 1, "exp": "Obstructing stone + infection (infected obstructed system) เป็น urologic emergency → decompress ด่วน (ureteric stent/percutaneous nephrostomy) + antibiotic + resuscitation. Definitive stone treatment ทำภายหลัง.", "id": "set5-92"}, {"topic": "Mixed/Integrated", "q": "A patient develops acute onset dyspnea, hypoxia, and clear lungs after major long-bone fracture, with petechiae and confusion. What is the diagnosis?", "choices": ["Thrombotic pulmonary embolism", "Bacterial pneumonia", "Fat embolism syndrome", "ARDS from sepsis", "Anaphylaxis"], "ans": 2, "exp": "Fat embolism syndrome (24–72 ชม.หลัง long-bone/pelvic fracture): triad = hypoxemia + neurologic (confusion) + petechial rash. รักษาแบบ supportive (oxygen/ventilation) + early fracture fixation เพื่อป้องกัน.", "id": "set5-93"}, {"topic": "Mixed/Integrated", "q": "A patient with a large anterior STEMI develops a new harsh holosystolic murmur and acute pulmonary edema 4 days later. What mechanical complication is likely?", "choices": ["Acute pericarditis", "Reinfarction only", "Aortic dissection", "Papillary muscle or septal rupture", "Pulmonary embolism"], "ans": 3, "exp": "หลัง MI 3–7 วัน + murmur holosystolic ใหม่ + acute decompensation = mechanical complication (ventricular septal rupture หรือ acute mitral regurgitation จาก papillary muscle rupture) — emergency echo + surgical/hemodynamic support.", "id": "set5-94"}, {"topic": "Mixed/Integrated", "q": "A patient with obesity, snoring, and daytime sleepiness has resistant hypertension. Which condition should be screened for?", "choices": ["Hypothyroidism only", "Pheochromocytoma only", "Diabetes insipidus", "Addison disease", "Obstructive sleep apnea"], "ans": 4, "exp": "Resistant HT + obesity + snoring + daytime somnolence → obstructive sleep apnea (secondary/contributing cause of HT). ยืนยันด้วย sleep study; รักษาด้วย CPAP + ลดน้ำหนัก.", "id": "set5-95"}, {"topic": "Mixed/Integrated", "q": "A patient with a positive fecal occult blood test and iron deficiency anemia is 55 years old. What is the essential next investigation?", "choices": ["Colonoscopy", "Reassurance only", "Upper endoscopy only", "CT abdomen only", "Repeat FIT in a year"], "ans": 0, "exp": "FOBT/FIT บวก + IDA ในผู้ใหญ่ ≥ 45–50 ปี ต้อง colonoscopy เพื่อประเมิน colorectal cancer/polyp (± EGD ถ้า colonoscopy ปกติ). อย่าเหมาเป็น hemorrhoid โดยไม่ตรวจ.", "id": "set5-96"}, {"topic": "Mixed/Integrated", "q": "A patient with hypertension is found to have a potassium of 6.8 with peaked T waves while on an ACE inhibitor and spironolactone. What is the immediate priority?", "choices": ["Give more spironolactone", "IV calcium, then shift/remove potassium", "Increase the ACE inhibitor", "Observation only", "Give potassium"], "ans": 1, "exp": "Severe hyperkalemia (ECG changes) จากยา RAAS + K-sparing: ให้ calcium gluconate stabilize membrane → insulin/glucose + salbutamol shift → diuretic/resin/dialysis removal + หยุด ACEI/spironolactone.", "id": "set5-97"}, {"topic": "Mixed/Integrated", "q": "A patient with severe asthma exacerbation has a rising PaCO2 and is tiring despite maximal therapy. What does this indicate?", "choices": ["The patient is improving", "This is a mild attack", "Impending respiratory failure; ICU care", "This is anxiety only", "A metabolic alkalosis"], "ans": 2, "exp": "ใน severe asthma การที่ PaCO2 สูงขึ้น (แทนที่จะต่ำ) + ผู้ป่วยเหนื่อยล้า/silent chest = impending respiratory failure → ICU, เตรียม intubation, ให้ IV magnesium, systemic steroid, continuous nebulizer.", "id": "set5-98"}, {"topic": "Mixed/Integrated", "q": "A patient presents with jaundice; labs show elevated ALP and GGT with mild transaminase rise and pruritus. What pattern is this?", "choices": ["A hepatocellular pattern", "A hemolytic pattern", "Isolated indirect hyperbilirubinemia", "Cholestatic pattern; image biliary tree", "A completely normal pattern"], "ans": 3, "exp": "ALP + GGT สูงเด่น + pruritus = cholestatic pattern (obstruction/biliary disease) → imaging (US/MRCP) หา obstruction (stone, stricture, mass). ต่างจาก hepatocellular (AST/ALT สูงเด่น).", "id": "set5-99"}, {"topic": "Mixed/Integrated", "q": "A patient with type 2 diabetes presents for a routine visit. Which vaccination is particularly important to offer?", "choices": ["No vaccines are needed", "Only the rabies vaccine", "Only the tetanus vaccine", "Only the HPV vaccine", "Influenza, pneumococcal, HBV, COVID-19"], "ans": 4, "exp": "ผู้ป่วยเบาหวาน/โรคเรื้อรังควรได้วัคซีนป้องกัน influenza (ทุกปี), pneumococcal, hepatitis B, และ COVID-19 เพื่อลดภาวะแทรกซ้อนจากการติดเชื้อ. เป็นส่วนหนึ่งของ preventive care.", "id": "set5-100"}]}, {"id": "obgyn1", "title": "Ob-gyne ชุดที่ 1 — Obstetrics I (Physiology, ANC, Fetal Assessment, Labor & EFM)", "subject": "obgyn", "questions": [{"topic": "Obstetrics", "q": "A 30-year-old G2P1 woman at 32 weeks of gestation attends a routine prenatal visit and feels well. Her CBC shows hemoglobin 10.8 g/dL with a normal MCV and normal serum ferritin. Which physiological change best explains this hemoglobin value?", "choices": ["Plasma volume expansion exceeds red cell mass", "Increased red cell destruction", "Severe iron deficiency", "Suppressed bone marrow production", "Chronic occult blood loss"], "ans": 0, "exp": "Physiologic anemia of pregnancy: plasma volume เพิ่ม ~40-50% มากกว่า red cell mass (~20-30%) → hemodilution ทำให้ Hb ลดลงโดย ferritin/MCV ปกติ. เกณฑ์ anemia: Hb <11 (T1,3), <10.5 (T2)."}, {"topic": "Obstetrics", "q": "A healthy 28-year-old primigravida at 30 weeks of gestation asks how her heart has adapted to pregnancy. Compared with her pre-pregnancy state, which change in cardiac output is expected?", "choices": ["Decreased by 20 percent", "Increased by 30-50 percent", "Unchanged from baseline", "Decreased then normalized", "Increased by 5 percent only"], "ans": 1, "exp": "Cardiac output เพิ่ม 30-50% (จาก stroke volume + heart rate ~15-20 bpm) สูงสุด GA 28-32 wk และเพิ่มอีกตอนคลอด/หลังคลอด (autotransfusion). SVR ลดลง. เป็นช่วงเสี่ยงในโรคหัวใจ."}, {"topic": "Obstetrics", "q": "A 26-year-old woman at 12 weeks of gestation with mild dyspnea has an arterial blood gas showing pH 7.44, PaCO2 30 mmHg, and HCO3 19 mEq/L. Which acid-base state is this in a normal pregnancy?", "choices": ["Primary metabolic acidosis", "Primary metabolic alkalosis", "Compensated respiratory alkalosis", "Primary respiratory acidosis", "A mixed acid-base disorder"], "ans": 2, "exp": "Progesterone กระตุ้นศูนย์หายใจ → minute ventilation เพิ่ม → ขับ CO2 เกิด chronic respiratory alkalosis (PaCO2 ~30) ไตชดเชยด้วย HCO3 ต่ำ (~18-20). ค่าปกติในครรภ์."}, {"topic": "Obstetrics", "q": "A 25-year-old G1P0 at 34 weeks of gestation has routine labs showing a serum creatinine of 1.0 mg/dL. How should this be interpreted?", "choices": ["Completely normal for pregnancy", "Diagnostic of preeclampsia", "Consistent with dehydration", "Abnormally elevated for pregnancy", "Expected in third trimester"], "ans": 3, "exp": "GFR เพิ่ม ~50% ในครรภ์ → Cr ปกติ <0.8 mg/dL. Cr 1.0 ที่ปกติในคนทั่วไป จึงบ่งชี้การทำงานของไตที่แย่กว่าที่ควรในหญิงตั้งครรภ์ → ต้องประเมินเพิ่มเติม."}, {"topic": "Obstetrics", "q": "A 24-year-old primigravida with a pre-pregnancy BMI of 22 kg/m2 asks how much weight she should gain. Per Institute of Medicine guidance, what is the recommended total gestational weight gain?", "choices": ["5-9 kg", "7-11.5 kg", "18-20 kg", "12.5-18 kg", "11.5-16 kg"], "ans": 4, "exp": "น้ำหนักเพิ่มตาม BMI: ผอม 12.5-18, ปกติ (18.5-24.9) 11.5-16, น้ำหนักเกิน 7-11.5, อ้วน 5-9 kg. BMI 22 = ปกติ → 11.5-16 kg."}, {"topic": "Obstetrics", "q": "A 29-year-old G2P1 at 36 weeks develops near-syncope whenever she lies supine, relieved by turning onto her side. Her supine BP is 88/54 mmHg. What is the most appropriate immediate step?", "choices": ["Left lateral positioning", "High-flow oxygen only", "Intravenous vasopressor", "Large fluid bolus first", "Elevate legs while supine"], "ans": 0, "exp": "Supine hypotensive syndrome: มดลูกกด IVC ในท่านอนหงาย → venous return ลด → BP ตก. แก้ทันทีด้วยการตะแคงซ้าย (เลื่อนมดลูกออกจาก IVC)."}, {"topic": "Obstetrics", "q": "A 27-year-old woman with irregular cycles is unsure of her last menstrual period and presents at about 9 weeks. Which method most accurately estimates gestational age?", "choices": ["Biparietal diameter", "Crown-rump length", "Abdominal circumference", "Femur length", "Amniotic fluid index"], "ans": 1, "exp": "Crown-rump length ไตรมาสแรก (ถึง ~13+6 wk) แม่นสุด (±5-7 วัน). เมื่อ LMP ไม่แน่นอน/ต่างจาก US เกินเกณฑ์ ให้ยึด US ไตรมาสแรก."}, {"topic": "Obstetrics", "q": "A 23-year-old primigravida presents for her first prenatal visit at 8 weeks. Per the WHO 2016 model, what is the recommended minimum number of antenatal care contacts?", "choices": ["Six contacts", "Ten contacts", "Eight contacts", "Four contacts", "Twelve contacts"], "ans": 2, "exp": "[อัปเดต] WHO 2016 เปลี่ยนจาก 4 เป็น ≥8 contacts เพื่อลดการตายปริกำเนิด: ครั้งแรก <12 wk ตามด้วย 20,26,30,34,36,38,40 wk."}, {"topic": "Obstetrics", "q": "A 22-year-old woman at her first prenatal visit is screened for syphilis. Which test is used for this screening?", "choices": ["HBsAg", "Anti-HIV antibody", "Hemoglobin typing", "VDRL or RPR", "Urine culture"], "ans": 3, "exp": "VDRL/RPR (non-treponemal) คัดกรองซิฟิลิสทุกราย. Congenital syphilis รักษาด้วย penicillin (แพ้ต้อง desensitize)."}, {"topic": "Obstetrics", "q": "A 26-year-old G2P1 at 30 weeks receives vaccination counseling. What is the optimal gestational window for the Tdap vaccine in each pregnancy?", "choices": ["Before 12 weeks", "16-20 weeks", "Contraindicated in pregnancy", "After delivery only", "27-36 weeks"], "ans": 4, "exp": "Tdap ทุกครรภ์ที่ GA 27-36 wk เพื่อให้แม่สร้างแอนติบอดีผ่านรกป้องกันไอกรนในทารก. วัคซีนเชื้อเป็น (MMR, VZV) ห้ามในครรภ์."}, {"topic": "Obstetrics", "q": "A 33-year-old woman at 12 weeks undergoes first-trimester combined aneuploidy screening. Which combination of markers is used?", "choices": ["NT, PAPP-A, free beta-hCG", "AFP, hCG, estriol", "BPD, FL, AC", "Inhibin A and AFP", "NST and BPP"], "ans": 0, "exp": "First-trimester combined (11-13+6 wk) = NT + PAPP-A + free β-hCG (จับ Down ~85%). Down: PAPP-A ต่ำ, β-hCG สูง, NT หนา. Quad test ทำไตรมาส 2."}, {"topic": "Obstetrics", "q": "A 30-year-old G1P0 at 17 weeks has quadruple screening showing a markedly elevated maternal serum AFP. This most suggests which fetal condition?", "choices": ["Trisomy 21", "Open neural tube defect", "Trisomy 18", "Trisomy 13", "Turner syndrome"], "ans": 1, "exp": "MSAFP สูงใน open neural tube defect (spina bifida, anencephaly) และ abdominal wall defect. Down: AFP/estriol ต่ำ, hCG/inhibin A สูง; trisomy 18 ต่ำทุกตัว."}, {"topic": "Obstetrics", "q": "A 38-year-old G3P2 at 11 weeks asks about cell-free fetal DNA testing (NIPT). Which statement is correct?", "choices": ["It is diagnostic and definitive", "It only determines fetal sex", "It is a highly sensitive screening test", "It requires amniocentesis", "It replaces the anomaly scan"], "ans": 2, "exp": "[อัปเดต] NIPT sensitivity สูงมาก (>99% สำหรับ T21) แต่เป็น screening — ผลบวกต้องยืนยันด้วย diagnostic (amniocentesis/CVS). ACOG เสนอได้ทุกระดับความเสี่ยง."}, {"topic": "Obstetrics", "q": "A 36-year-old G2P1 chooses diagnostic karyotyping by amniocentesis. What is the earliest gestational age at which amniocentesis is typically performed?", "choices": ["6-9 weeks", "At or after 28 weeks", "10-13 weeks", "At or after 15 weeks", "After delivery only"], "ans": 3, "exp": "Amniocentesis ทำเมื่อ GA ≥15 wk (early amnio <15 เพิ่มความเสี่ยง). CVS ทำได้ 10-13 wk. ทั้งคู่เป็น diagnostic เสี่ยงแท้ง ~0.1-0.3%."}, {"topic": "Obstetrics", "q": "A 34-year-old G1P0 at 33 weeks undergoes an NST. Over 20 minutes there are two accelerations of at least 15 bpm lasting at least 15 seconds each. How is this interpreted?", "choices": ["Nonreactive tracing", "Positive contraction stress test", "Sinusoidal pattern", "Absent variability", "Reactive tracing"], "ans": 4, "exp": "NST reactive (≥32 wk) = acceleration ≥2 ครั้ง เพิ่ม ≥15 bpm นาน ≥15 วินาที ใน 20 นาที → fetal wellbeing. <32 wk ใช้เกณฑ์ 10×10."}, {"topic": "Obstetrics", "q": "A 32-year-old G2P1 at 36 weeks with gestational hypertension has a biophysical profile of 4/10 with oligohydramnios. What does this indicate?", "choices": ["Concerning for fetal compromise", "Normal fetus", "Fetal sleep cycle only", "Maternal dehydration only", "Reassuring result"], "ans": 0, "exp": "BPP 8-10 ปกติ, 6 equivocal, ≤4 ผิดปกติ เสี่ยง fetal asphyxia → พิจารณาคลอดตามอายุครรภ์. Oligohydramnios เพิ่มความน่ากังวลเสมอ."}, {"topic": "Obstetrics", "q": "A 31-year-old G3P2 at 38 weeks has an ultrasound reporting an amniotic fluid index of 4 cm. This is consistent with which condition?", "choices": ["Normal fluid", "Oligohydramnios", "Polyhydramnios", "Fetal macrosomia", "Twin gestation"], "ans": 1, "exp": "Oligohydramnios: AFI <5 cm หรือ single deepest pocket <2 cm. สาเหตุ: uteroplacental insufficiency (FGR), PROM, renal agenesis, post-term. AFI >25 = polyhydramnios."}, {"topic": "Obstetrics", "q": "A laboring woman's care team reviews the cardinal movements of labor. Which sequence is correct?", "choices": ["Descent, engagement, flexion, extension", "Flexion, engagement, extension, rotation", "Engagement, descent, flexion, internal rotation, extension", "Internal rotation, engagement, flexion, descent", "Engagement, extension, flexion, descent"], "ans": 2, "exp": "กลไกการคลอด: Engagement → Descent → Flexion → Internal rotation → Extension → External rotation → Expulsion. Flexion ทำให้ diameter เล็กสุด (suboccipitobregmatic) ผ่านเชิงกราน."}, {"topic": "Obstetrics", "q": "A 28-year-old G1P0 is in labor. Per current ACOG/Consortium definitions, the active phase of the first stage begins at what cervical dilation?", "choices": ["Two centimeters", "Three centimeters", "Four centimeters", "Six centimeters", "Eight centimeters"], "ans": 3, "exp": "[อัปเดต] active phase เริ่มที่ 6 cm (เดิม 4 cm) เพราะ latent phase อาจยาวได้ปกติ → ลดการวินิจฉัย arrest ผิดและลดผ่าคลอดเกินจำเป็น."}, {"topic": "Obstetrics", "q": "A 29-year-old G2P1 in labor reaches 6 cm with ruptured membranes, then shows no cervical change over 4 hours despite adequate contractions (over 200 Montevideo units). What is the diagnosis?", "choices": ["Prolonged latent phase", "Precipitous labor", "Second stage arrest", "Normal progress", "Active phase arrest"], "ans": 4, "exp": "Active phase arrest: ≥6 cm, ถุงน้ำแตก, ไม่มี cervical change ≥4 ชม.ทั้งที่ contraction เพียงพอ (≥200 MVU) → ข้อบ่งชี้พิจารณาผ่าคลอด."}, {"topic": "Obstetrics", "q": "A 24-year-old nulliparous woman without epidural has been pushing in the second stage. Beyond approximately what duration is the second stage considered prolonged (per ACOG)?", "choices": ["Three hours", "Four hours", "Thirty minutes", "One hour", "Two hours"], "ans": 0, "exp": "Stage 2: ครรภ์แรกยอมได้ ~3 ชม. (มี epidural +1), ครรภ์หลัง ~2 ชม. (มี epidural +1) ตราบใดที่มี progress และ FHR ปกติ."}, {"topic": "Obstetrics", "q": "Immediately after delivery of the infant, the team performs active management of the third stage to reduce hemorrhage. Which component is most important?", "choices": ["Waiting 60 minutes for the placenta", "Oxytocin administration", "Ergometrine before infant delivery", "Immediate vigorous cord traction", "Fundal massage before placenta"], "ans": 1, "exp": "Active management: (1) oxytocin หลังคลอดไหล่หน้า/ทารก, (2) controlled cord traction, (3) uterine massage. องค์ประกอบสำคัญสุดคือ oxytocin."}, {"topic": "Obstetrics", "q": "During the third stage, the physician notes cord lengthening, a firm globular uterus, and a sudden gush of blood. What do these signs indicate?", "choices": ["Uterine inversion", "Uterine atony", "Placental separation", "Cord prolapse", "Retained placenta"], "ans": 2, "exp": "สัญญาณรกลอกตัว: สายสะดือยาวขึ้น, มดลูกกลมแข็งลอยสูง, เลือดออกกะทันหัน. เมื่อพบจึงทำ controlled cord traction."}, {"topic": "Obstetrics", "q": "A 28-year-old G1P0 at 40 weeks on oxytocin has an EFM baseline of 140 bpm with moderate variability and recurrent gradual decelerations beginning after each contraction peak and returning to baseline after the contraction ends. What is the most likely cause?", "choices": ["Fetal head compression", "Normal sleep cycle", "Umbilical cord compression", "Uteroplacental insufficiency", "Maternal fever"], "ans": 3, "exp": "Late deceleration = FHR ลดค่อยเป็นค่อยไป จุดต่ำสุดหลัง peak → uteroplacental insufficiency. Early = head compression; Variable รูปตัว V = cord compression."}, {"topic": "Obstetrics", "q": "A term fetus on EFM shows absent baseline variability with recurrent late decelerations. By the NICHD 3-tier system, this is which category?", "choices": ["Category II", "Reactive", "Category I", "Indeterminate", "Category III"], "ans": 4, "exp": "Category III = absent variability + recurrent late/variable decel หรือ bradycardia; หรือ sinusoidal → แก้ไขทันทีและเตรียมคลอดเร่งด่วน. Category I ปกติ, II พบบ่อยสุด."}, {"topic": "Obstetrics", "q": "A laboring woman develops recurrent variable decelerations. Which intrauterine resuscitation measure is INAPPROPRIATE?", "choices": ["Increase the oxytocin rate", "Left lateral positioning", "Maternal oxygen", "Intravenous fluid bolus", "Exclude cord prolapse"], "ans": 0, "exp": "Intrauterine resuscitation: ตะแคงซ้าย, O2, IV fluid, 'หยุด/ลด oxytocin', ตรวจแยก cord prolapse, พิจารณา tocolytic. การเพิ่ม oxytocin ทำให้ tachysystole → ทารกแย่ลง."}, {"topic": "Obstetrics", "q": "An EFM tracing shows moderate baseline variability of 6-25 bpm. What does moderate variability most reliably indicate?", "choices": ["Fetal sleep state present", "Normal fetal oxygenation status", "Maternal fever developing", "Rapid cervical dilation", "Early placental separation"], "ans": 1, "exp": "Moderate variability (6-25 bpm) เป็นตัวบ่งชี้ดีที่สุดว่าทารกมี oxygenation/acid-base ปกติ (ไม่มี metabolic acidosis ขณะนั้น). Absent/minimal + deceleration จึงน่ากังวล."}, {"topic": "Obstetrics", "q": "To monitor labor progress and guide intervention, the team plots cervical dilation, descent, fetal heart rate, and contractions over time. Which tool is this?", "choices": ["Bishop score", "Apgar score", "Partograph", "Ballard score", "Silverman score"], "ans": 2, "exp": "Partograph (WHO Labour Care Guide 2020) บันทึกการเปิดปากมดลูก การเคลื่อนต่ำ FHR contraction ช่วยตรวจจับ labor ผิดปกติแต่เนิ่นๆ. Bishop ประเมินความพร้อมชักนำคลอด."}, {"topic": "Obstetrics", "q": "When evaluating labor dystocia, the physician considers the '3 Ps.' Which option lists them correctly?", "choices": ["Pain, Position, Pressure", "Progress, Passage, Pain", "Placenta, Presentation, Pelvis", "Power, Passage, Passenger", "Parity, Position, Power"], "ans": 3, "exp": "3P: Power (contraction), Passage (ช่องเชิงกราน/CPD), Passenger (ทารก - ขนาด/ท่า). ช่วยหาสาเหตุ dystocia และวางแผน."}, {"topic": "Obstetrics", "q": "A couple attends preconception counseling and both are found to be carriers of alpha-thalassemia-1 trait. For which condition is their fetus at risk?", "choices": ["Beta-thalassemia major alone", "Hemoglobin E trait", "Hemoglobin H disease", "G6PD deficiency", "Hemoglobin Bart's hydrops fetalis"], "ans": 4, "exp": "α-thal 1 ทั้งคู่: โอกาส 1/4 ลูกเป็น homozygous (--/--) = Hb Bart's hydrops fetalis (บวมน้ำ เสียชีวิต, แม่เสี่ยง preeclampsia). เป็นข้อบ่งชี้ prenatal diagnosis."}, {"topic": "Obstetrics", "q": "A 25-year-old woman planning pregnancy with no prior affected child asks about supplementation. What is the recommended daily dose of folic acid?", "choices": ["400-600 micrograms", "4 milligrams", "1 milligram weekly", "10 milligrams", "No supplement needed"], "ans": 0, "exp": "หญิงทั่วไป โฟเลต 400-600 µg/วัน เริ่ม ≥1 เดือนก่อนตั้งครรภ์. ผู้เคยมีลูก NTD/ใช้ยากันชักบางชนิดใช้ 4 mg/วัน. ลด neural tube defect."}, {"topic": "Obstetrics", "q": "A 27-year-old woman at 9 weeks has a mildly suppressed TSH without symptoms. Which mechanism best explains this early-pregnancy finding?", "choices": ["Graves disease in all cases", "hCG stimulation of the TSH receptor", "Pituitary failure", "Iodine deficiency", "Decreased thyroid-binding globulin"], "ans": 1, "exp": "hCG มี α-subunit คล้าย TSH กระตุ้น TSH receptor อ่อนๆ ในไตรมาสแรก → free T4 เพิ่มเล็กน้อย → กด TSH ชั่วคราว มักหายเอง. TBG เพิ่ม (total T4/T3 สูง แต่ free ปกติ)."}, {"topic": "Obstetrics", "q": "A 28-year-old G2P1 without high-risk features is scheduled for gestational diabetes screening. At what gestational age is routine screening performed?", "choices": ["8-12 weeks", "16-20 weeks", "24-28 weeks", "32-36 weeks", "After delivery"], "ans": 2, "exp": "คัดกรอง GDM ที่ GA 24-28 wk (ช่วง insulin resistance เด่น). ความเสี่ยงสูงคัดกรองตั้งแต่ฝากครรภ์ครั้งแรกและตรวจซ้ำ 24-28 ถ้าครั้งแรกปกติ."}, {"topic": "Obstetrics", "q": "A 26-year-old Rh(D)-negative woman with no anti-D antibodies is at 28 weeks. When should routine antenatal anti-D immunoglobulin be given?", "choices": ["During labor only", "After delivery only", "At 12 weeks only", "At 28 weeks", "Never without antibodies"], "ans": 3, "exp": "Anti-D routine ที่ GA 28 wk และภายใน 72 ชม.หลังคลอดถ้าทารก Rh positive. ให้เพิ่มหลังเหตุการณ์เสี่ยง FMH (แท้ง, ectopic, เจาะน้ำคร่ำ, trauma, ECV)."}, {"topic": "Obstetrics", "q": "A 24-year-old G1P0 at 32 weeks has a symphysis-fundal height of 27 cm. What is the most appropriate first consideration?", "choices": ["Fetal macrosomia", "Polyhydramnios alone", "Molar pregnancy alone", "Twin gestation alone", "Fetal growth restriction"], "ans": 4, "exp": "SFH(cm) ≈ อายุครรภ์ ±2-3 (20-36 wk). SFH น้อยกว่า >3 cm บ่งชี้ FGR/oligohydramnios/dating ผิด → ทำ US ประเมิน EFW และน้ำคร่ำ."}, {"topic": "Obstetrics", "q": "A 30-year-old G2P1 at 40 weeks is considered for induction, and a Bishop score is calculated. A high Bishop score indicates which of the following?", "choices": ["Favorable cervix for induction", "A healthy neonate", "The level of labor pain", "Severe preeclampsia", "Fetal lung maturity"], "ans": 0, "exp": "Bishop score ประเมินปากมดลูก 5 องค์ประกอบ. ≥8 = favorable โอกาสชักนำคลอดสำเร็จสูง. <6 อาจต้อง cervical ripening ก่อน."}, {"topic": "Obstetrics", "q": "A 29-year-old G1P0 at 41 weeks with an unfavorable cervix (Bishop score 3) requires induction. Which agent is appropriate for cervical ripening?", "choices": ["Terbutaline tocolysis", "Prostaglandin (misoprostol)", "Oxytocin infusion", "Indomethacin", "Magnesium sulfate"], "ans": 1, "exp": "Cervical ripening ใช้ prostaglandin (misoprostol/dinoprostone) หรือ Foley balloon. Oxytocin ใช้เมื่อปากมดลูกพร้อม. ห้าม misoprostol ในผู้เคยผ่าคลอด (เสี่ยง rupture)."}, {"topic": "Obstetrics", "q": "A 28-year-old G2P1 is evaluated for induction of labor. Which of the following is a valid indication?", "choices": ["Every nulliparous patient", "Breech presentation", "Post-term pregnancy", "Complete placenta previa", "Prior classical cesarean"], "ans": 2, "exp": "ข้อบ่งชี้ induction: post-term ≥41 wk, PROM, HT/preeclampsia, GDM คุมไม่ดี, IUGR, IUFD, chorioamnionitis. Previa totalis/ท่าขวาง/แผล classical = ข้อห้าม."}, {"topic": "Obstetrics", "q": "Immediately after birth, a neonate is assessed with the Apgar score. Which five components make up the score?", "choices": ["Alertness, Pulse, Grip, Activity, Rate", "Airway, Pulse, Growth, Activity, Reflex", "Apnea, Pulse, Grimace, Airway, Reflex", "Appearance, Pulse, Grimace, Activity, Respiration", "Appearance, Pressure, Grimace, Age, Rate"], "ans": 3, "exp": "Apgar = Appearance, Pulse, Grimace, Activity, Respiration ประเมินที่ 1 และ 5 นาที แต่ละอย่าง 0-2 คะแนน. ใช้ประเมินสภาพและการตอบสนองต่อการกู้ชีพ."}, {"topic": "Obstetrics", "q": "A 24-year-old G1P0 at 39 weeks is in labor with the cervix dilated 4 cm, unchanged over 3 hours. How should this be classified?", "choices": ["Second stage arrest", "Active phase arrest", "Prolonged third stage", "Precipitous labor", "Latent phase"], "ans": 4, "exp": "active phase เริ่มที่ 6 cm ดังนั้น 4 cm ยังเป็น latent phase. Prolonged latent phase ไม่ใช่ arrest และไม่ควรผ่าคลอดด้วยเหตุนี้เพียงอย่างเดียว — รอ, oxytocin/amniotomy ได้."}, {"topic": "Obstetrics", "q": "A laboring woman receives epidural analgesia. Which side effect should the physician anticipate?", "choices": ["Maternal hypotension", "Fetal malformation", "Permanent loss of contractions", "Marked rise in cesarean rate", "Uterine rupture"], "ans": 0, "exp": "Epidural อาจทำให้ maternal hypotension (sympathetic block) → ให้ IV fluid, เฝ้า BP/FHR. อาจทำให้ stage 2 ยาวขึ้นเล็กน้อย แต่ไม่เพิ่มผ่าคลอดอย่างมีนัยสำคัญ และไม่ทำให้ทารกพิการ."}, {"topic": "Obstetrics", "q": "During a vaginal delivery, the physician considers episiotomy. Per current evidence, when is episiotomy indicated?", "choices": ["Routinely in all deliveries", "Only when specifically indicated", "To reduce labor pain", "To always prevent laceration", "For cosmetic reasons"], "ans": 1, "exp": "ไม่แนะนำ routine episiotomy (restrictive use). ทำเมื่อมีข้อบ่งชี้: เร่งคลอด (fetal distress), shoulder dystocia, operative delivery. Mediolateral ลด severe tear เทียบ midline."}, {"topic": "Obstetrics", "q": "After delivery, a perineal laceration extends into the anal sphincter but not through the rectal mucosa. What degree is this?", "choices": ["First degree", "Second degree", "Third degree", "Cervical laceration", "Fourth degree"], "ans": 2, "exp": "1st = ผิวหนัง/mucosa, 2nd = ถึง muscle (ไม่ถึงหูรูด), 3rd = ถึง anal sphincter, 4th = ทะลุ rectal mucosa. 3rd/4th (OASIS) ต้องซ่อมพิถีพิถัน เฝ้าระวัง fecal incontinence."}, {"topic": "Obstetrics", "q": "One hour after an uncomplicated delivery, the physician palpates the uterus. Which finding indicates good uterine tone?", "choices": ["Soft and above the umbilicus", "Boggy and deviated right", "Not palpable at all", "Firm at or below the umbilicus", "Below the symphysis pubis"], "ans": 3, "exp": "หลังคลอดมดลูกควรกลมแข็งอยู่ระดับสะดือหรือต่ำกว่า. ถ้านุ่ม (boggy) และสูงขึ้น = uterine atony (สาเหตุ PPH บ่อยสุด) → นวดมดลูก + uterotonic."}, {"topic": "Obstetrics", "q": "In the mechanism of labor, engagement of the fetal head is defined as which event?", "choices": ["The head passes the pelvic outlet", "Complete cervical dilation", "Internal rotation of the fetal head", "Rupture of the membranes", "Biparietal diameter passes the pelvic inlet"], "ans": 4, "exp": "Engagement = biparietal diameter ผ่านระดับ pelvic inlet (leading part ที่ ischial spine = station 0). ครรภ์แรกมักเกิดก่อนเจ็บครรภ์; ครรภ์หลังตอนเจ็บครรภ์."}, {"topic": "Obstetrics", "q": "During a vaginal examination, the fetal presenting bony part is at the level of the ischial spines. What station is this?", "choices": ["Station zero", "At the pelvic inlet", "At the pelvic outlet", "Floating high", "Dilated zero centimeters"], "ans": 0, "exp": "Station เทียบกับ ischial spines: 0 = ระดับ spines (engaged), ลบ = อยู่เหนือ, บวก = ต่ำกว่า (+5 = crowning). ใช้ติดตาม descent ในระยะที่ 2."}, {"topic": "Obstetrics", "q": "A woman with regular 28-day cycles reports her last menstrual period began January 1. Using Naegele's rule, what is her estimated date of delivery?", "choices": ["September 8", "October 8", "October 1", "September 24", "November 1"], "ans": 1, "exp": "Naegele: EDD = LMP + 7 วัน - 3 เดือน. 1 ม.ค. +7 = 8 ม.ค. -3 เดือน = 8 ต.ค. → EDD 8 ตุลาคม. ใช้เมื่อรอบสม่ำเสมอ 28 วัน; ไม่แน่นอนยึด US."}, {"topic": "Obstetrics", "q": "A woman with a twin pregnancy is counseled about chorionicity. When and how is chorionicity best determined?", "choices": ["Third trimester by palpation", "By serum beta-hCG", "First trimester by ultrasound", "After delivery by placenta", "By amniocentesis always"], "ans": 2, "exp": "ประเมิน chorionicity ในไตรมาสแรก (แม่นสุด 11-14 wk): lambda/twin-peak = dichorionic, T-sign = monochorionic. สำคัญสุดเพราะ monochorionic เสี่ยง TTTS."}, {"topic": "Obstetrics", "q": "A healthy 26-year-old at 34 weeks has a white cell count of 14,000/mm3 with neutrophil predominance and no symptoms of infection. How is this interpreted?", "choices": ["Requires antibiotics now", "Always indicates infection", "Indicates leukemia", "A normal physiologic change", "Lymphocyte elevation only"], "ans": 3, "exp": "WBC เพิ่มได้ปกติในครรภ์ (มัก 9,000-15,000, คลอดถึง 25,000) เป็น neutrophilia โดยไม่ติดเชื้อ. แปลผลต้องใช้ร่วมกับอาการทางคลินิก."}, {"topic": "Obstetrics", "q": "A 29-year-old G1P0 at 41 weeks with a reactive NST and AFI of 6 cm is counseled. What is the most appropriate recommendation?", "choices": ["Wait until 43 weeks", "Immediate cesarean delivery", "Discontinue prenatal care", "Administer tocolytics", "Induction of labor"], "ans": 4, "exp": "ที่ GA 41 wk แนะนำ induction เพื่อลด stillbirth, meconium aspiration, macrosomia ที่เพิ่มหลัง 41 wk. หลักฐานสนับสนุน induction ที่ 41 wk ดีกว่ารอ."}, {"topic": "Obstetrics", "q": "A 30-year-old at 36 weeks is at increased risk of venous thromboembolism. Which physiological change accounts for this hypercoagulable state?", "choices": ["Increased clotting factors and stasis", "Increased protein S levels", "Increased fibrinolysis", "Very high platelet count", "Increased antithrombin"], "ans": 0, "exp": "ครรภ์เป็น hypercoagulable state: เพิ่ม fibrinogen, factor VII/VIII/X/vWF; ลด protein S/fibrinolysis; venous stasis. เสี่ยง VTE เพิ่ม 4-5 เท่า สูงสุดหลังคลอด."}, {"topic": "Obstetrics", "q": "A 32-year-old at 34 weeks reports decreased fetal movements, counting only 5 movements over 2 hours. What is the most appropriate action?", "choices": ["Observe at home 1 week", "Evaluation with NST/BPP", "Reassure as normal", "Deliver immediately", "Give hematinics"], "ans": 1, "exp": "Fetal movement count ผิดปกติ (<10 ครั้ง/2 ชม.) เป็นสัญญาณเตือน ควรมาประเมิน NST/BPP เพื่อค้นหา fetal compromise ไม่ควรรอสังเกตนานที่บ้าน."}, {"topic": "Obstetrics", "q": "A growth-restricted fetus undergoes umbilical artery Doppler, which shows absent end-diastolic flow. What does this indicate?", "choices": ["A normal healthy fetus", "Twin pregnancy", "Severe placental insufficiency", "Excess amniotic fluid", "Intrauterine infection"], "ans": 2, "exp": "Absent/reversed end-diastolic flow บ่งชี้ placental resistance สูงมาก = severe placental insufficiency สัมพันธ์ perinatal mortality สูง → ข้อบ่งชี้พิจารณาคลอด."}, {"topic": "Obstetrics", "q": "A pregnant woman is scheduled for GBS screening by vaginal-rectal culture. Per current ACOG guidance, at what gestational age is this performed?", "choices": ["28-30 weeks", "32-34 weeks", "During labor only", "36 0/7 to 37 6/7 weeks", "At delivery only"], "ans": 3, "exp": "[อัปเดต] ACOG 2020 เลื่อน GBS screening เป็น 36 0/7 - 37 6/7 wk (เดิม 35-37) ให้ culture ครอบคลุมนานขึ้น. ผลบวก → intrapartum penicillin."}, {"topic": "Obstetrics", "q": "A GBS-colonized woman is in labor. Which antibiotic is preferred for intrapartum prophylaxis?", "choices": ["Vancomycin", "Metronidazole", "Doxycycline", "Gentamicin", "Penicillin G"], "ans": 4, "exp": "Penicillin G IV เป็นตัวแรก (ampicillin ทางเลือก). แพ้ penicillin: cefazolin, clindamycin (เชื้อไว), vancomycin (ดื้อ). ให้ ≥4 ชม.ก่อนคลอด."}, {"topic": "Obstetrics", "q": "A 32-year-old multipara delivers within 2 hours of the onset of regular contractions. What is this called?", "choices": ["Precipitous labor", "Prolonged labor", "Arrest of labor", "Protracted labor", "Latent labor"], "ans": 0, "exp": "Precipitous labor = คลอดภายใน <3 ชม.นับจากเริ่มเจ็บครรภ์ พบบ่อยในครรภ์หลัง. เสี่ยง laceration, PPH (atony), amniotic fluid embolism."}, {"topic": "Obstetrics", "q": "A 30-year-old G2P1 with a breech fetus at 37 weeks is offered external cephalic version. At what gestational age is ECV typically performed?", "choices": ["28 weeks", "About 37 weeks", "32 weeks", "41 weeks", "During active labor"], "ans": 1, "exp": "ECV มักทำที่ ~37 wk (term): ถ้าเร็วไปทารกอาจกลับท่าก้น, ถ้าเกิดภาวะแทรกซ้อนก็คลอดทารกครบกำหนดได้. ทำภายใต้ US เตรียมผ่าคลอดฉุกเฉิน; anti-D ถ้า Rh negative."}, {"topic": "Obstetrics", "q": "In a vigorous term newborn, the physician delays cord clamping for 30-60 seconds. What is the main benefit?", "choices": ["Reduced jaundice", "Reduced birth weight", "Increased iron stores", "Prevention of GBS", "Less respiratory effort"], "ans": 2, "exp": "Delayed cord clamping เพิ่ม blood volume, hemoglobin, iron store (ลด anemia); ในทารกก่อนกำหนดลด IVH/NEC. ข้อเสียเล็กน้อยคือ jaundice ที่ต้อง phototherapy เพิ่มเล็กน้อย."}, {"topic": "Obstetrics", "q": "A postpartum woman is followed. What is the correct sequence of lochia color change?", "choices": ["Alba, serosa, rubra", "Serosa, alba, rubra", "Rubra, alba, serosa", "Rubra, serosa, alba", "No color change"], "ans": 3, "exp": "Lochia: rubra (แดง, 1-4 วัน) → serosa (ชมพู-น้ำตาล, 4-10 วัน) → alba (ขาว-เหลือง, 2-6 สัปดาห์). กลับเป็นแดงสด/มีกลิ่นบ่งชี้ปัญหา (retained products, endometritis)."}, {"topic": "Obstetrics", "q": "A healthy pregnant woman has trace glucosuria on urine dipstick. What is the most common explanation?", "choices": ["Diabetes in all cases", "Excessive sugar intake", "Renal failure", "Urinary tract infection", "Lowered renal glucose threshold"], "ans": 4, "exp": "GFR เพิ่มในครรภ์ → renal glucose threshold ลด เกิด glucosuria ได้แม้น้ำตาลในเลือดปกติ. อย่างไรก็ตามควรคัดกรอง GDM ตามปกติ."}, {"topic": "Obstetrics", "q": "A woman in the transverse lie at 39 weeks presents in labor. What is the appropriate mode of delivery?", "choices": ["Cesarean section", "Vaginal delivery", "Forceps delivery", "Vacuum extraction", "Await spontaneous rotation"], "ans": 0, "exp": "Transverse lie คลอดทางช่องคลอดไม่ได้ (ไม่มีส่วนนำเหมาะ) → ผ่าคลอด. เสี่ยง cord prolapse/uterine rupture ถ้าปล่อยไว้."}, {"topic": "Obstetrics", "q": "A term newborn of a mother with poorly controlled gestational diabetes is at greatest risk of which early complication?", "choices": ["Hyperbilirubinemia only", "Neonatal hypoglycemia", "Cataract", "Necrotizing enterocolitis", "Congenital heart block"], "ans": 1, "exp": "ทารกจากแม่ GDM มี fetal hyperinsulinemia → เสี่ยง neonatal hypoglycemia (ต้องตรวจน้ำตาลหลังเกิด), macrosomia, shoulder dystocia, RDS, hyperbilirubinemia, polyhydramnios."}, {"topic": "Obstetrics", "q": "A 25-year-old G1P0 at 38 weeks in labor has an EFM showing early decelerations that mirror the contractions. What is the underlying cause?", "choices": ["Uteroplacental insufficiency", "Umbilical cord compression", "Fetal head compression", "Fetal anemia", "Maternal fever"], "ans": 2, "exp": "Early deceleration = FHR ลดพร้อม contraction แบบ mirror image เกิดจาก fetal head compression (vagal reflex) เป็นภาวะปกติ ไม่ต้องแทรกแซง. ต่างจาก late (uteroplacental) และ variable (cord)."}, {"topic": "Obstetrics", "q": "A 27-year-old at 39 weeks has ruptured membranes with clear fluid but no contractions after 18 hours. She is GBS positive. What is the most appropriate management?", "choices": ["Expectant care for 1 week", "Tocolysis", "Immediate cesarean delivery", "Induction with GBS prophylaxis", "Corticosteroids"], "ans": 3, "exp": "Term PROM ที่ไม่เข้าสู่ระยะคลอดเอง → induction (ลด chorioamnionitis/neonatal infection) พร้อม GBS intrapartum prophylaxis. ไม่ต้อง steroid/tocolytic เพราะครบกำหนด."}, {"topic": "Obstetrics", "q": "A 26-year-old at 8 weeks by LMP has a transvaginal ultrasound showing a gestational sac with a fetal pole but no cardiac activity; measurements correspond to 8 weeks. What best describes this finding requiring confirmation?", "choices": ["Definite viable pregnancy", "Complete spontaneous abortion", "Tubal ectopic pregnancy", "Complete molar pregnancy", "Early pregnancy loss likely"], "ans": 4, "exp": "CRL ที่วัดได้สอดคล้อง 8 wk แต่ไม่มี cardiac activity บ่งชี้ early pregnancy loss (missed abortion) — ควรยืนยันตามเกณฑ์ (CRL ≥7 mm ไม่มี cardiac activity) หรือ US ซ้ำก่อนจัดการ."}, {"topic": "Obstetrics", "q": "A woman at 39 weeks with a fetus in breech presentation and adequate pelvis is counseled on delivery. What is the most widely recommended approach for a term breech today?", "choices": ["Planned cesarean delivery", "Vaginal breech delivery always", "Await spontaneous version", "Forceps-assisted delivery", "Oxytocin augmentation"], "ans": 0, "exp": "ตาม Term Breech Trial การผ่าคลอดในทารกท่าก้นครบกำหนดลด perinatal morbidity → เป็นแนวทางที่นิยม. ทางเลือกป้องกันคือ ECV ที่ ~37 wk."}, {"topic": "Obstetrics", "q": "A 28-year-old at 30 weeks reports worsening heartburn and constipation. Which hormone primarily accounts for these gastrointestinal changes?", "choices": ["Estrogen", "Progesterone", "Human chorionic gonadotropin", "Prolactin", "Oxytocin"], "ans": 1, "exp": "Progesterone คลายกล้ามเนื้อเรียบ → ลด LES tone (GERD) และลด motility (ท้องผูก, gallstone). มดลูกที่โตยังดันกระเพาะอาหารร่วมด้วย."}, {"topic": "Obstetrics", "q": "A pregnant woman asks how her blood pressure changes across pregnancy. Which pattern is expected in a normal pregnancy?", "choices": ["Rises steadily throughout", "Lowest at term", "Lowest in the second trimester", "Highest in the second trimester", "Unchanged throughout"], "ans": 2, "exp": "SVR ลดลง → BP ค่อยๆ ลด ต่ำสุดกลางไตรมาส 2 (~24 wk) แล้วกลับสู่ระดับเดิมใกล้ครบกำหนด. BP สูงหลัง 20 wk ต้องระวัง gestational hypertension/preeclampsia."}, {"topic": "Obstetrics", "q": "A woman with mitral stenosis is at highest risk of pulmonary edema at which point?", "choices": ["First trimester", "Before pregnancy", "At 12 weeks", "Immediately postpartum", "Six months postpartum"], "ans": 3, "exp": "ช่วงเสี่ยง: GA 28-32 wk (CO สูงสุด) และหลังคลอดทันที (autotransfusion จากมดลูกหดตัว + IVC decompression → preload เพิ่มฉับพลัน) อาจกระตุ้น pulmonary edema."}, {"topic": "Obstetrics", "q": "After delivery of the placenta, the uterus contracts and shifts blood back into the circulation, transiently increasing preload. What is this phenomenon called?", "choices": ["External transfusion", "Hemodilution", "Fetal transfusion", "Reverse shunt", "Autotransfusion"], "ans": 4, "exp": "Autotransfusion: มดลูกหดบีบเลือด ~500 mL กลับเข้าระบบไหลเวียน + IVC decompression → venous return/CO เพิ่มชั่วคราว. เสี่ยงในผู้ป่วยโรคหัวใจ."}, {"topic": "Obstetrics", "q": "A woman at 30 weeks is counseled about respiratory physiology. Which combination of changes is expected in normal pregnancy?", "choices": ["Tidal volume up, FRC down", "Both increased", "Tidal volume down, FRC up", "Both decreased", "No change"], "ans": 0, "exp": "ในครรภ์ tidal volume เพิ่ม 30-40% (progesterone) แต่ FRC ลด ~20% (มดลูกดันกะบังลม). FRC ที่ลดทำให้ hypoxia เร็วขณะ apnea (สำคัญตอน intubation)."}, {"topic": "Obstetrics", "q": "A fetus is evaluated with a contraction stress test that shows late decelerations after 50% of contractions. How is this test interpreted?", "choices": ["Negative, reassuring", "Positive, concerning", "Equivocal only", "Reactive", "Invalid"], "ans": 1, "exp": "CST positive = มี late deceleration ตามหลัง ≥50% ของ contraction บ่งชี้ uteroplacental insufficiency. CST negative (ไม่มี late) = ผลดี. ปัจจุบันใช้ NST/BPP มากกว่า."}, {"topic": "Obstetrics", "q": "A 24-year-old primigravida at 39 weeks is fully dilated and has been pushing for 2.5 hours with epidural; the head is at station +1 and the FHR is category I. What is the most appropriate management?", "choices": ["Immediate cesarean for arrest", "Stop labor efforts", "Allow continued pushing", "Administer tocolytics", "Apply forceps immediately"], "ans": 2, "exp": "ครรภ์แรกที่มี epidural ยอมให้ stage 2 นานถึง ~4 ชม.ตราบใดที่มี progress และ FHR ปกติ. 2.5 ชม. + FHR category I → ให้เบ่งต่อได้พร้อมติดตาม descent."}, {"topic": "Obstetrics", "q": "A woman receiving oxytocin augmentation develops contractions every 90 seconds with recurrent decelerations. What is the most important complication of oxytocin to monitor?", "choices": ["Hypoglycemia", "Rash", "Hypertension", "Uterine tachysystole", "Diarrhea"], "ans": 3, "exp": "Oxytocin overstimulation → tachysystole (>5 ครั้ง/10 นาที) → ลด placental perfusion → FHR decel/distress และเสี่ยง uterine rupture. ปรับ/หยุดยาตาม contraction และ FHR."}, {"topic": "Obstetrics", "q": "A woman asks which vaccine is safe during pregnancy. Which of the following can be given during pregnancy?", "choices": ["Live attenuated influenza (nasal)", "Measles-mumps-rubella", "Varicella vaccine", "Oral polio vaccine", "Inactivated influenza vaccine"], "ans": 4, "exp": "Inactivated influenza vaccine ให้ได้ทุกไตรมาส. ห้ามวัคซีนเชื้อเป็น (LAIV, MMR, VZV) ในครรภ์ → ให้หลังคลอด."}, {"topic": "Obstetrics", "q": "At what gestational age is a detailed fetal anomaly scan optimally performed?", "choices": ["18-22 weeks", "11-13 weeks", "8-10 weeks", "28-30 weeks", "36-38 weeks"], "ans": 0, "exp": "Anomaly scan ทำที่ GA 18-22 wk (อวัยวะพัฒนาพอตรวจได้ครบ, น้ำคร่ำเพียงพอ). ช่วง 11-13 wk ทำ NT scan (คัดกรองโครโมโซม)."}, {"topic": "Obstetrics", "q": "A woman is taught to count fetal movements starting in the third trimester. At approximately what gestational age is this typically begun?", "choices": ["24 weeks", "28 weeks", "20 weeks", "34 weeks", "36 weeks"], "ans": 1, "exp": "แนะนำเริ่มนับลูกดิ้นตั้งแต่ ~GA 28 wk เป็นวิธีเฝ้าระวังที่มารดาทำเอง. ถ้าลูกดิ้นน้อยควรมาประเมิน NST/BPP."}, {"topic": "Obstetrics", "q": "Which milk-related reflex is primarily mediated by oxytocin during breastfeeding?", "choices": ["Milk production", "Colostrum synthesis", "Milk ejection (let-down)", "Prolactin release", "Suppression of lactation"], "ans": 2, "exp": "Prolactin สร้างน้ำนม; Oxytocin กระตุ้น milk ejection/let-down (myoepithelial cells หดตัว) เมื่อทารกดูดนม และช่วยมดลูกหดรัดตัว (ปวดมดลูกขณะให้นม)."}, {"topic": "Obstetrics", "q": "After delivery of the placenta, the rapid fall in estrogen and progesterone allows which process to begin?", "choices": ["Suppression of lactation", "Uterine atony", "Increased VTE risk", "Onset of lactogenesis", "Immediate menstruation"], "ans": 3, "exp": "ระหว่างครรภ์ estrogen/progesterone สูงยับยั้งผล prolactin. หลังคลอดรกฮอร์โมนลดเร็ว → ปลดการยับยั้ง → prolactin กระตุ้น lactogenesis II (น้ำนมมาเต็มที่ ~วันที่ 3-4)."}, {"topic": "Obstetrics", "q": "How long does WHO recommend exclusive breastfeeding?", "choices": ["Three months", "Twelve months", "Nine months", "Two years", "Six months"], "ans": 4, "exp": "WHO แนะนำ exclusive breastfeeding 6 เดือน แล้วเสริมอาหารตามวัยควบคู่นมแม่ถึง 2 ปีขึ้นไป. นมแม่ให้ภูมิคุ้มกัน (IgA), ลด infection/NEC, เป็น natural contraception (LAM)."}, {"topic": "Obstetrics", "q": "A postpartum woman relies on the lactational amenorrhea method (LAM). Which set of conditions must be met for it to be effective?", "choices": ["Exclusive breastfeeding with amenorrhea under 6 months", "Any breastfeeding at any infant age", "Mixed feeding with formula supplements", "Breastfeeding beyond twelve months postpartum", "Breastfeeding with resumed menstruation"], "ans": 0, "exp": "LAM ได้ผล (~98%) เมื่อครบ 3 เงื่อนไข: exclusive breastfeeding, amenorrhea (ประจำเดือนยังไม่มา), ทารก <6 เดือน. เมื่อเงื่อนไขใดหายไปต้องเริ่มวิธีอื่น."}, {"topic": "Obstetrics", "q": "An 18-year-old primigravida at 8 weeks by LMP denies bleeding or pain. TVS shows an intrauterine sac of 15 mm mean diameter with no yolk sac or fetal pole. What is the most appropriate next step?", "choices": ["Immediate dilation and curettage", "Repeat ultrasound in 7-14 days", "Misoprostol to complete the loss", "Methotrexate for ectopic pregnancy", "Pelvic MRI for confirmation"], "ans": 1, "exp": "Sac 15 mm ยังไม่ถึงเกณฑ์วินิจฉัย pregnancy loss แน่นอน (empty sac ต้อง MSD ≥25 mm) → reassure และ repeat US ใน 7-14 วันเพื่อประเมิน interval growth/cardiac activity ก่อนจัดการ."}, {"topic": "Obstetrics", "q": "A 40-year-old at 38 weeks with gestational diabetes has an NST with baseline 140 bpm and no accelerations over 40 minutes. What is the most appropriate next step?", "choices": ["Repeat NST in 1 week", "Immediate cesarean delivery", "Perform a biophysical profile", "Discharge home", "Start tocolysis"], "ans": 2, "exp": "NST non-reactive ต้องประเมินต่อด้วย biophysical profile (หรือ CST) เพื่อยืนยัน fetal wellbeing ก่อนตัดสินใจ ไม่ใช่ผ่าคลอดทันทีหรือส่งกลับบ้าน. Non-reactive อาจเป็นเพียง sleep cycle."}, {"topic": "Obstetrics", "q": "A 32-year-old G3P2 delivers and the physician documents the placenta to check completeness. Why is this important?", "choices": ["To determine fetal sex", "To assess Apgar", "To confirm gestational age", "To detect retained fragments", "To measure fluid"], "ans": 3, "exp": "ตรวจความสมบูรณ์ของรก/เยื่อหุ้มและจำนวนหลอดเลือดสายสะดือ (2A+1V). รกไม่ครบ (retained fragment) เสี่ยง PPH/infection → อาจต้องสำรวจโพรงมดลูก."}, {"topic": "Obstetrics", "q": "A twin pregnancy is dichorionic-diamniotic and uncomplicated. At approximately what gestational age is delivery recommended?", "choices": ["34 weeks", "36 weeks", "42 weeks", "40 weeks", "38 weeks"], "ans": 4, "exp": "DCDA ปกติแนะนำคลอด ~38 wk (ไม่เกิน 38-39 เพราะเสี่ยง stillbirth). MCDA ~34-37, MCMA ~32-34 (ผ่าคลอด เพราะ cord entanglement)."}, {"topic": "Obstetrics", "q": "During the fourth stage of labor (first hour postpartum), what is the most important complication to monitor for?", "choices": ["Postpartum hemorrhage", "Depression", "Urinary infection", "Delayed lactation", "Epidural hypotension"], "ans": 0, "exp": "Stage 4 (1-2 ชม.แรก) เสี่ยงสูงสุดต่อ early PPH โดยเฉพาะ uterine atony. ต้องตรวจ fundus (กลมแข็ง), ปริมาณเลือด, vital signs, perineum เป็นระยะ."}, {"topic": "Obstetrics", "q": "A 26-year-old at 12 weeks presents with dysuria, frequency, and urgency; urinalysis shows nitrites and leukocytes, without fever or flank pain. Which antibiotic is most appropriate?", "choices": ["Ciprofloxacin", "Amoxicillin", "Doxycycline", "Gentamicin", "Trimethoprim-sulfamethoxazole"], "ans": 1, "exp": "Cystitis ในครรภ์รักษาด้วยยาปลอดภัย: amoxicillin, cephalexin, nitrofurantoin (เลี่ยงใกล้คลอด/G6PD), fosfomycin. หลีกเลี่ยง fluoroquinolone, doxycycline, และ TMP-SMX (ระวังไตรมาสแรก/ใกล้คลอด)."}, {"topic": "Obstetrics", "q": "A pregnant woman with hyperthyroidism from Graves disease needs an antithyroid drug in the first trimester. Which is preferred?", "choices": ["Methimazole", "Propranolol alone", "Propylthiouracil", "Radioactive iodine", "Levothyroxine"], "ans": 2, "exp": "ไตรมาสแรกใช้ PTU (methimazole เสี่ยง aplasia cutis/embryopathy), แล้วเปลี่ยนเป็น methimazole ไตรมาส 2-3 (PTU เสี่ยง hepatotoxicity). ห้าม radioactive iodine (ทำลายต่อมทารก)."}, {"topic": "Obstetrics", "q": "A woman with hypothyroidism becomes pregnant. How should her levothyroxine dose be adjusted?", "choices": ["Decrease the dose by half", "Stop levothyroxine entirely", "Switch to propylthiouracil", "Increase by about 30 percent", "Keep the dose unchanged"], "ans": 3, "exp": "ความต้องการ thyroid hormone เพิ่มในครรภ์ → เพิ่ม levothyroxine ~25-30% ทันทีที่ทราบว่าตั้งครรภ์ และตรวจ TSH ทุก 4-6 สัปดาห์. Maternal hypothyroidism สัมพันธ์กับ pregnancy loss/พัฒนาการสมอง."}, {"topic": "Obstetrics", "q": "A woman at 41 weeks with meconium-stained amniotic fluid delivers. What neonatal complication is of greatest concern?", "choices": ["Hyperbilirubinemia", "Hypoglycemia", "Polycythemia", "Necrotizing enterocolitis", "Meconium aspiration syndrome"], "ans": 4, "exp": "Meconium-stained fluid (พบบ่อยใน post-term) เสี่ยง meconium aspiration syndrome (respiratory distress, chemical pneumonitis, pulmonary hypertension) ถ้าทารกสำลัก. ดูแลตาม NRP ในทารก non-vigorous."}, {"topic": "Obstetrics", "q": "A woman with epilepsy on valproate is counseled before pregnancy. Which fetal risk is greatest with valproate?", "choices": ["Neural tube defect", "Cardiac defect only", "Limb defect", "Cataract", "Deafness"], "ans": 0, "exp": "Valproate เสี่ยงสูงสุดต่อ neural tube defect และ neurodevelopmental impairment → เลี่ยงในหญิงวัยเจริญพันธุ์ (เปลี่ยนเป็น lamotrigine/levetiracetam), ให้ folate สูง, ใช้ monotherapy ขนาดต่ำสุด."}, {"topic": "Obstetrics", "q": "A pregnant woman with asthma asks about her medications. What is the guiding principle for asthma management in pregnancy?", "choices": ["Stop all medications", "Continue inhaled controllers", "Use only oral steroids", "Give oxygen alone", "Switch to herbal therapy"], "ans": 1, "exp": "คุมโรคหืดให้ดีสำคัญกว่าความเสี่ยงจากยา (หืดกำเริบ → ทารกขาดออกซิเจน). ยาสูดพ่น (inhaled corticosteroid, SABA) ปลอดภัยและควรใช้ต่อ เป้าหมายควบคุมอาการเหมือนคนทั่วไป."}, {"topic": "Obstetrics", "q": "A woman with a monochorionic twin pregnancy requires close monitoring for which specific complication?", "choices": ["Rh isoimmunization", "Placenta previa", "Twin-twin transfusion syndrome", "Gestational diabetes only", "No special risk"], "ans": 2, "exp": "Monochorionic (แชร์รก + vascular anastomoses) เสี่ยง TTTS (donor ซีด/oligohydramnios/โตช้า, recipient เลือดข้น/polyhydramnios). ต้อง US ทุก 2 สัปดาห์ตั้งแต่ 16 wk; severe TTTS รักษาด้วย fetoscopic laser."}, {"topic": "Obstetrics", "q": "A 30-year-old with a persistent occiput posterior position has a prolonged second stage. What is a reasonable option in a suitable candidate?", "choices": ["Immediate cesarean in all cases", "Tocolysis to slow labor", "Maximal-dose oxytocin infusion", "Manual rotation or operative delivery", "Vigorous fundal pressure applied"], "ans": 3, "exp": "Persistent OP ทำให้ prolonged 2nd stage. หลายรายหมุนเป็น OA เอง; ถ้าไม่ก้าวหน้าพิจารณา manual rotation หรือ operative vaginal delivery โดยผู้เชี่ยวชาญ, หรือ cesarean ถ้ามี CPD/ล้มเหลว. ห้ามกด fundus."}, {"topic": "Obstetrics", "q": "A 34-year-old at 39 weeks in labor develops a fetal baseline of 175 bpm; the mother's temperature is 38.5°C. What is the most likely explanation?", "choices": ["Fetal heart block", "Fetal anemia", "Normal variant", "Cord prolapse", "Chorioamnionitis"], "ans": 4, "exp": "Fetal tachycardia (>160) + ไข้มารดา บ่งชี้ chorioamnionitis (พบบ่อยหลังถุงน้ำแตกนาน). รักษาด้วยยาปฏิชีวนะ + เร่งคลอด (คลอดทางช่องคลอดได้)."}, {"topic": "Obstetrics", "q": "A fetal heart rate baseline is documented as 105 bpm. How should this be classified?", "choices": ["Fetal bradycardia", "Normal baseline", "Marked variability", "Fetal tachycardia", "Sinusoidal pattern"], "ans": 0, "exp": "FHR baseline ปกติ 110-160 bpm. <110 = bradycardia (สาเหตุ: hypoxia, heart block, hypothermia). >160 = tachycardia. ประเมินร่วมกับ variability และ deceleration."}, {"topic": "Obstetrics", "q": "A 29-year-old G1P0 at 41+3 weeks declines induction. What antenatal surveillance is most appropriate while awaiting labor?", "choices": ["No further monitoring needed", "NST with amniotic fluid assessment", "Oral hematinic supplements", "Immediate cesarean delivery", "Prophylactic tocolytic therapy"], "ans": 1, "exp": "เมื่อ expectant เกิน 41 wk ต้องทำ antenatal surveillance (NST + AFI หรือ BPP) 1-2 ครั้ง/สัปดาห์ เพื่อเฝ้าระวัง fetal compromise เพราะความเสี่ยง stillbirth เพิ่มเมื่อครรภ์เกินกำหนด."}, {"topic": "Obstetrics", "q": "A 30-year-old at 37 weeks is counseled that antenatal corticosteroids are given when preterm delivery is anticipated before which gestational age?", "choices": ["24 weeks", "37 weeks", "34 weeks", "40 weeks", "42 weeks"], "ans": 2, "exp": "Antenatal corticosteroid (betamethasone/dexamethasone) ให้เมื่อเสี่ยงคลอดก่อน GA 34 wk (ช่วง 24-34) เพื่อลด RDS/IVH/NEC/การตาย; อาจพิจารณาถึง late preterm ในบางราย. ประสิทธิผลสูงสุดเมื่อคลอดใน 7 วัน."}, {"topic": "Obstetrics", "q": "A 27-year-old G1P0 at 39 weeks is fully dilated. As the head descends onto the perineum and begins to distend it, the presenting part is at which station?", "choices": ["Station minus five", "Station zero", "At the pelvic inlet", "Station plus five", "Above the ischial spines"], "ans": 3, "exp": "Station +5 = ส่วนนำโผล่พ้น perineum (crowning) ใกล้คลอด. 0 = ระดับ ischial spines (engaged), -5 = อยู่สูงที่ pelvic inlet. ใช้ติดตาม fetal descent."}, {"topic": "Obstetrics", "q": "A 30-year-old G2P1 delivers vaginally. Which uterotonic is used first-line for routine active management of the third stage?", "choices": ["Carboprost", "Misoprostol", "Methylergonovine", "Tranexamic acid", "Oxytocin"], "ans": 4, "exp": "Oxytocin 10 U IM เป็น uterotonic ตัวแรกใน active management of third stage เพื่อป้องกัน PPH. Methylergonovine (ห้ามในความดันสูง) และ carboprost (ห้ามในหืด) เป็นทางเลือกเมื่อ atony ดื้อ."}]}, {"id": "obgyn2", "title": "Ob-gyne ชุดที่ 2 — Obstetrics II (Bleeding, Hypertension, Diabetes, Preterm, Infections, Emergencies & Postpartum)", "subject": "obgyn", "questions": [{"topic": "Obstetrics", "q": "A 24-year-old G2P1 at 8 weeks of gestation reports mild vaginal spotting. On speculum exam the cervical os is closed, and transvaginal ultrasound shows a live intrauterine pregnancy. What is the diagnosis?", "choices": ["Threatened abortion", "Inevitable abortion", "Incomplete abortion", "Missed abortion", "Complete abortion"], "ans": 0, "exp": "Threatened abortion = เลือดออก <20 wk โดยปากมดลูกปิดและทารกยังมีชีวิต. ดูแลแบบ expectant. ~50% ตั้งครรภ์ต่อได้. ต่างจาก inevitable (os เปิด) และ missed (ทารกเสียชีวิต os ปิด)."}, {"topic": "Obstetrics", "q": "A 27-year-old woman at 10 weeks presents with heavy bleeding and cramping; the cervical os is open, some tissue has passed, and ultrasound shows retained products. What is the diagnosis?", "choices": ["Threatened abortion", "Incomplete abortion", "Complete abortion", "Missed abortion", "Septic abortion"], "ans": 1, "exp": "Incomplete abortion = os เปิด ขับเนื้อเยื่อบางส่วน แต่มีเศษค้าง ทำให้เลือดออกต่อเนื่อง. รักษาด้วย expectant, misoprostol, หรือ surgical evacuation (MVA/D&C) โดยเฉพาะถ้าเลือดออกมาก."}, {"topic": "Obstetrics", "q": "A 30-year-old woman with three consecutive first-trimester losses is evaluated. Which is the most common treatable cause of recurrent pregnancy loss?", "choices": ["Diabetes mellitus", "Thyrotoxicosis", "Antiphospholipid syndrome", "Uterine fibroids", "Cervical insufficiency"], "ans": 2, "exp": "Antiphospholipid syndrome (APS) เป็นสาเหตุ recurrent pregnancy loss ที่รักษาได้และพบบ่อย. รักษาด้วย aspirin + heparin เพิ่มอัตราคลอดมีชีพ. สาเหตุอื่น: septate uterus, parental translocation, DM/thyroid."}, {"topic": "Obstetrics", "q": "In an ectopic pregnancy, which anatomical site is most commonly involved?", "choices": ["The uterine cervix", "The ovarian surface", "The uterine cornua", "Ampulla of the fallopian tube", "The abdominal cavity"], "ans": 3, "exp": "Ectopic พบบ่อยสุดที่ท่อนำไข่ (~95%) โดยเฉพาะ ampulla (~70%). ปัจจัยเสี่ยง: PID/STI, เคยผ่าตัดท่อ, เคย ectopic, IUD, ART, สูบบุหรี่."}, {"topic": "Obstetrics", "q": "A 25-year-old woman with 6 weeks of amenorrhea has right lower quadrant pain; beta-hCG is 2,500 mIU/mL and transvaginal ultrasound shows no intrauterine gestational sac. What is the most likely diagnosis?", "choices": ["Normal early pregnancy", "Complete molar pregnancy", "Threatened abortion", "Missed abortion", "Ectopic pregnancy"], "ans": 4, "exp": "β-hCG เกิน discriminatory zone (~1,500-2,000) แต่ไม่พบ intrauterine sac → ectopic จนกว่าจะพิสูจน์เป็นอื่น. ประเมินเสถียรภาพ: คงที่ → methotrexate; แตก/ไม่คงที่ → ผ่าตัดฉุกเฉิน."}, {"topic": "Obstetrics", "q": "A hemodynamically stable woman has an unruptured ectopic pregnancy. Which finding makes her a suitable candidate for methotrexate?", "choices": ["Beta-hCG below 5,000 mIU/mL", "Mass over six centimeters", "Fetal cardiac activity present", "Large hemoperitoneum", "Unstable vital signs"], "ans": 0, "exp": "เกณฑ์ MTX: stable, ท่อยังไม่แตก, mass <3.5-4 cm, β-hCG <5,000, ไม่มี cardiac activity, ติดตามได้. ติดตาม hCG วันที่ 4 และ 7 (ต้องลด ≥15%). แตก/ไม่คงที่ต้องผ่าตัด."}, {"topic": "Obstetrics", "q": "In a normal early intrauterine pregnancy, what is the expected rise in beta-hCG over 48 hours?", "choices": ["Remains unchanged", "At least 49-66 percent", "Halves every 48 hours", "Increases tenfold in 24 hours", "No predictable pattern"], "ans": 1, "exp": "ครรภ์ในมดลูกปกติช่วงต้น β-hCG เพิ่ม ≥49-66% ใน 48 ชม. การเพิ่มช้าผิดปกติหรือ plateau บ่งชี้ ectopic/nonviable; การลดลงบ่งชี้ failing pregnancy."}, {"topic": "Obstetrics", "q": "A complete hydatidiform mole has which genetic and clinical profile?", "choices": ["Triploid with fetal tissue", "Normal 46,XY karyotype", "Paternal-only 46,XX with no fetus", "Trisomy 21 present", "Monosomy X present"], "ans": 2, "exp": "Complete mole: มัก 46,XX จากพ่อทั้งหมด (androgenesis) ไม่มีเนื้อเยื่อทารก. hCG สูงมาก, มดลูกโตกว่าอายุครรภ์, snowstorm, theca lutein cysts, เสี่ยงกลายเป็น GTN สูง. Partial mole = triploid (69,XXX) มีเนื้อเยื่อทารก."}, {"topic": "Obstetrics", "q": "What is the initial treatment of a hydatidiform mole?", "choices": ["Hysterectomy in all cases", "Await spontaneous expulsion", "Immediate chemotherapy", "Suction curettage with hCG follow-up", "Pelvic radiotherapy"], "ans": 3, "exp": "รักษา molar pregnancy ด้วย suction curettage แล้วติดตาม serial β-hCG จนเป็นลบต่อเนื่อง. คุมกำเนิดระหว่างติดตาม. ถ้า hCG plateau/สูงขึ้น = GTN → เคมีบำบัด."}, {"topic": "Obstetrics", "q": "A 32-year-old woman at 32 weeks has painless, bright-red vaginal bleeding; the uterus is soft and nontender. What should be avoided until the placental location is confirmed?", "choices": ["Ultrasound examination", "Blood typing", "Fetal heart monitoring", "Intravenous access", "Digital vaginal examination"], "ans": 4, "exp": "เลือดออกแดงสด ไม่ปวด มดลูกนุ่ม = placenta previa. ห้าม digital/speculum PV เพราะอาจกระตุ้นเลือดออกรุนแรง — ใช้ ultrasound วินิจฉัยตำแหน่งรกก่อน. รกคลุมปากมดลูกต้องผ่าคลอด."}, {"topic": "Obstetrics", "q": "Which is the most important risk factor for placenta accreta spectrum?", "choices": ["Previa with prior cesarean", "First pregnancy alone", "Young maternal age", "Nulliparity", "Twin gestation"], "ans": 0, "exp": "[อัปเดต] Placenta accreta spectrum เพิ่มตามอัตราผ่าคลอด. ปัจจัยเสี่ยงหลักคือ placenta previa + ประวัติ cesarean. วางแผนคลอดโดยทีมสหสาขา, เตรียมเลือด, มักต้อง cesarean hysterectomy."}, {"topic": "Obstetrics", "q": "A 34-year-old woman at 34 weeks with hypertension presents with painful vaginal bleeding, a tense tender uterus, and an abnormal fetal heart rate. What is the diagnosis?", "choices": ["Placenta previa", "Placental abruption", "Chorioamnionitis", "Vasa previa", "Uterine rupture"], "ans": 1, "exp": "Placental abruption: ปวดท้อง มดลูก tense/tender เลือดออก (อาจ concealed) + fetal distress. เสี่ยง: HT/preeclampsia, trauma, สูบบุหรี่/โคเคน, PPROM. แทรกซ้อน: DIC, Couvelaire uterus, fetal death."}, {"topic": "Obstetrics", "q": "What is the most important hematologic complication of severe placental abruption?", "choices": ["Reactive polycythemia", "Acute leukemia", "Disseminated intravascular coagulation", "Hemophilia A", "Thrombocytosis"], "ans": 2, "exp": "Abruption รุนแรงปล่อย thromboplastin → กระตุ้น coagulation → DIC (fibrinogen ลด, PT/PTT ยาว, เกล็ดต่ำ). เป็นสาเหตุ obstetric DIC ที่พบบ่อย. รักษาโดยคลอดและให้ blood products."}, {"topic": "Obstetrics", "q": "A 25-year-old at 24 weeks has BP 150/95 confirmed 4 hours apart with a urine protein/creatinine ratio of 0.4. What is the diagnosis?", "choices": ["Chronic hypertension", "Gestational hypertension", "Normal pregnancy", "Preeclampsia", "Eclampsia"], "ans": 3, "exp": "BP ≥140/90 หลัง 20 wk + proteinuria (protein/Cr ≥0.3) = preeclampsia. ถ้าไม่มี proteinuria แต่มี severe features/end-organ damage ก็วินิจฉัย preeclampsia ได้."}, {"topic": "Obstetrics", "q": "Which finding qualifies as a severe feature of preeclampsia?", "choices": ["Blood pressure 145/92", "Platelets of 250,000", "Proteinuria 300 mg/day", "Weight gain of 1 kg weekly", "Platelet count below 100,000"], "ans": 4, "exp": "Severe features: BP ≥160/110, platelet <100,000, Cr >1.1, transaminase สูง ≥2 เท่า, pulmonary edema, อาการทางสมอง/ตา, ปวด RUQ. เปลี่ยนแนวทางเป็นให้ MgSO4 และพิจารณาคลอดที่ 34 wk."}, {"topic": "Obstetrics", "q": "Which agent is the drug of choice for both prevention and treatment of eclamptic seizures?", "choices": ["Magnesium sulfate", "Diazepam", "Phenytoin", "Levetiracetam", "Labetalol"], "ans": 0, "exp": "Magnesium sulfate เป็นตัวเลือกแรกในการป้องกัน (severe features) และรักษา eclamptic seizure — เหนือกว่า diazepam/phenytoin. Loading 4-6 g IV แล้ว 1-2 g/hr. เฝ้าระวัง toxicity."}, {"topic": "Obstetrics", "q": "A woman on magnesium sulfate for preeclampsia is being monitored. What is the earliest sign of magnesium toxicity?", "choices": ["Cardiac arrest", "Loss of deep tendon reflexes", "Respiratory failure", "Increased urine output", "Rising blood pressure"], "ans": 1, "exp": "ลำดับ Mg toxicity: loss of DTR (~8-10) เป็นสัญญาณเตือนแรก → respiratory depression (~12) → cardiac arrest (>15). Antidote = calcium gluconate. ตรวจ reflex, RR, urine output เป็นระยะ."}, {"topic": "Obstetrics", "q": "What does HELLP syndrome comprise?", "choices": ["Hypertension, edema, low platelets", "Hyperglycemia, edema, low platelets", "Hemolysis, elevated liver enzymes, low platelets", "High lipids, elevated lactate, leukopenia", "Hemorrhage, encephalopathy, liver lesion"], "ans": 2, "exp": "HELLP = Hemolysis (schistocytes, LDH สูง), Elevated Liver enzymes (AST/ALT), Low Platelets (<100,000). รูปแบบรุนแรงของ preeclampsia (บางรายไม่มีความดันสูง). เสี่ยง liver rupture, DIC, abruption. รักษา: MgSO4, คุมความดัน, คลอด."}, {"topic": "Obstetrics", "q": "What is the only definitive treatment of preeclampsia?", "choices": ["Magnesium sulfate", "Antihypertensive drugs", "Intravenous fluids", "Delivery of the placenta", "Strict bed rest"], "ans": 3, "exp": "Preeclampsia เกิดจากพยาธิสภาพของรก จึงรักษาหายด้วยการคลอด. MgSO4/ยาลดความดันเป็นการควบคุมชั่วคราว. Timing: ไม่มี severe features → 37 wk; มี severe features → 34 wk (หรือเร็วกว่าถ้าไม่คงที่)."}, {"topic": "Obstetrics", "q": "A woman at high risk of preeclampsia is counseled on prophylaxis. What is the recommended aspirin regimen?", "choices": ["300 mg starting at 28 weeks", "500 mg in the third trimester", "81 mg after delivery", "162 mg at term only", "81 mg starting at 12-28 weeks"], "ans": 4, "exp": "[อัปเดต] Low-dose aspirin 81 mg/วัน เริ่ม GA 12-28 wk (ดีที่สุดก่อน 16) ต่อจนคลอด ในผู้มี high-risk factor ≥1 หรือ moderate-risk ≥2. ลดความเสี่ยง preeclampsia และภาวะแทรกซ้อน."}, {"topic": "Obstetrics", "q": "A woman with preeclampsia has a BP of 165/112. Which antihypertensive is appropriate for acute control in pregnancy?", "choices": ["Labetalol", "Enalapril", "Losartan", "Long-term nitroprusside", "Atenolol"], "ans": 0, "exp": "ยาลดความดันเฉียบพลัน (≥160/110): IV labetalol, IV hydralazine, oral nifedipine. หลีกเลี่ยง ACEI/ARB (teratogen, fetal renal), nitroprusside (cyanide). ลด BP แต่คง placental perfusion."}, {"topic": "Obstetrics", "q": "A 26-year-old at 26 weeks has a 50 g glucose challenge test result of 155 mg/dL. What is the next step?", "choices": ["Diagnose GDM, start insulin now", "Perform a 100 g tolerance test", "Check the HbA1c level only", "No further action needed", "Proceed directly to cesarean"], "ans": 1, "exp": "Two-step: 50 g GCT ≥140 (บางที่ 130/135) → ทำ 100 g OGTT ยืนยัน. GCT อย่างเดียวไม่วินิจฉัย GDM. วินิจฉัยเมื่อ 100 g OGTT ผิดปกติ ≥2 ค่า (Carpenter-Coustan)."}, {"topic": "Obstetrics", "q": "How many abnormal values on a 100 g oral glucose tolerance test are required to diagnose gestational diabetes (Carpenter-Coustan)?", "choices": ["One value", "Three values", "Two or more values", "All four values", "This test is not used"], "ans": 2, "exp": "100 g OGTT (Carpenter-Coustan): FBS ≥95, 1hr ≥180, 2hr ≥155, 3hr ≥140. วินิจฉัยเมื่อผิดปกติ ≥2 ค่า. ต่างจาก one-step 75 g OGTT ที่วินิจฉัยเมื่อ ≥1 ค่า (92/180/153)."}, {"topic": "Obstetrics", "q": "A woman is newly diagnosed with gestational diabetes. What is the first-line management?", "choices": ["Start insulin therapy immediately", "Start metformin therapy first", "Start glyburide therapy first", "Medical nutrition therapy, exercise", "Proceed directly to cesarean"], "ans": 3, "exp": "GDM เริ่มด้วยควบคุมอาหาร + ออกกำลังกาย + ตรวจน้ำตาลปลายนิ้ว (เป้า FBS <95, 1hr <140, 2hr <120). คุมไม่ได้จึงเริ่มยา insulin เป็นตัวแรก. คุมน้ำตาลลด macrosomia, shoulder dystocia, neonatal hypoglycemia."}, {"topic": "Obstetrics", "q": "A neonate born to a mother with gestational diabetes is at risk of all the following EXCEPT which?", "choices": ["Macrosomia", "Neonatal hypoglycemia", "Polyhydramnios", "Shoulder dystocia", "Neural tube defect"], "ans": 4, "exp": "GDM (เริ่มหลังไตรมาสแรก) → macrosomia, shoulder dystocia, neonatal hypoglycemia, polyhydramnios, RDS. ส่วน neural tube/cardiac/caudal regression พบใน pregestational DM (น้ำตาลสูงตั้งแต่ organogenesis) ไม่ใช่ GDM ทั่วไป."}, {"topic": "Obstetrics", "q": "A woman had gestational diabetes. What postpartum follow-up is recommended?", "choices": ["75 g OGTT at 4-12 weeks postpartum", "No further testing is needed", "Weekly HbA1c measurement", "Daily urine glucose testing", "Lifelong insulin therapy"], "ans": 0, "exp": "หญิง GDM ควรตรวจ 75 g OGTT ที่ 4-12 สัปดาห์หลังคลอดเพื่อคัดกรอง type 2 DM/prediabetes (เสี่ยงเป็น DM2 สูง). แนะนำคุมน้ำหนัก ออกกำลังกาย และตรวจน้ำตาลเป็นระยะ."}, {"topic": "Obstetrics", "q": "A 32-year-old woman in preterm labor at 30 weeks is at risk of imminent delivery. Which agent is given specifically for fetal neuroprotection?", "choices": ["Terbutaline", "Magnesium sulfate", "Indomethacin", "Betamethasone", "Nifedipine"], "ans": 1, "exp": "[อัปเดต] คลอดก่อน 32 wk ให้ magnesium sulfate เพื่อ fetal neuroprotection (ลด cerebral palsy). ควบคู่ betamethasone (lung maturity), tocolytic, GBS prophylaxis. Betamethasone เป็น steroid ลด RDS ไม่ใช่ neuroprotection."}, {"topic": "Obstetrics", "q": "A woman in preterm labor at 28 weeks receives corticosteroids. What is their main purpose?", "choices": ["Reduce infection", "Stop contractions", "Accelerate fetal lung maturity", "Lower blood pressure", "Control electrolytes"], "ans": 2, "exp": "Antenatal corticosteroid (betamethasone/dexamethasone) ให้ GA 24-34 wk เร่ง surfactant (lung maturity) ลด RDS, IVH, NEC, การตาย. ประสิทธิผลสูงสุดเมื่อคลอดใน 2-7 วัน."}, {"topic": "Obstetrics", "q": "Which tocolytic should be avoided at 32 weeks or beyond due to the risk of premature ductus arteriosus closure?", "choices": ["Nifedipine", "Terbutaline", "Atosiban", "Indomethacin", "Magnesium sulfate"], "ans": 3, "exp": "Indomethacin (NSAID) ใช้ tocolysis ได้ผลดีแต่จำกัดที่ <32 wk และใช้สั้น เพราะเสี่ยง premature closure of ductus arteriosus และ oligohydramnios. Nifedipine/atosiban เป็นทางเลือกที่นิยม."}, {"topic": "Obstetrics", "q": "A woman at 30 weeks has preterm premature rupture of membranes without infection and a reassuring fetus. What is the appropriate management?", "choices": ["Immediate delivery of the fetus", "Long-term tocolysis for one month", "Emergency cervical cerclage placement", "Aggressive antihypertensive therapy", "Expectant care with steroids/antibiotics"], "ans": 4, "exp": "PPROM <34 wk ไม่มีข้อบ่งชี้คลอด → expectant: corticosteroid, latency antibiotics (ampicillin + erythromycin/azithromycin), MgSO4 (<32 wk), เฝ้าระวัง chorioamnionitis/abruption/cord prolapse. คลอด ~34 wk หรือมีภาวะแทรกซ้อน."}, {"topic": "Obstetrics", "q": "A woman with painless second-trimester cervical dilation and recurrent mid-trimester losses is diagnosed with which condition?", "choices": ["Cervical insufficiency", "Preeclampsia", "Post-term pregnancy", "Placenta previa", "Gestational diabetes"], "ans": 0, "exp": "Cervical insufficiency = ปากมดลูกเปิด/สั้นโดยไม่เจ็บครรภ์ในไตรมาส 2 → แท้ง/คลอดก่อนกำหนดซ้ำ. รักษาด้วย cervical cerclage (history/US/exam-indicated), มักถอดที่ ~37 wk."}, {"topic": "Obstetrics", "q": "When is vaginal progesterone used to prevent preterm birth?", "choices": ["In every pregnancy routinely", "When the cervix is short", "Always in twin pregnancies", "Only after delivery occurs", "Only in preeclampsia cases"], "ans": 1, "exp": "Vaginal progesterone ป้องกัน preterm birth ในผู้ที่ cervix สั้น (<25 mm) จาก US ไตรมาส 2. 17-OHPC เคยใช้ในผู้มีประวัติคลอดก่อนกำหนด (หลักฐานลดลง). ไม่ได้ผลชัดในครรภ์แฝด."}, {"topic": "Obstetrics", "q": "An Rh(D)-negative unsensitized woman delivers an Rh-positive infant. When should anti-D immunoglobulin be given?", "choices": ["No dose needed", "Only if the infant is anemic", "Within 72 hours of delivery", "One month postpartum", "Before delivery only"], "ans": 2, "exp": "หญิง Rh negative ที่ไม่ sensitized คลอดทารก Rh positive ต้องได้ anti-D ภายใน 72 ชม.หลังคลอด (+ dose ที่ 28 wk และหลังเหตุการณ์เสี่ยง). ตรวจ Kleihauer-Betke ถ้าสงสัย FMH ปริมาณมาก."}, {"topic": "Obstetrics", "q": "In a sensitized pregnancy, which method is used to assess for fetal anemia?", "choices": ["The amniotic fluid index", "A nonstress test", "The biophysical profile", "Middle cerebral artery peak systolic velocity", "Symphysis-fundal height"], "ans": 3, "exp": "ในครรภ์ alloimmunized ใช้ MCA peak systolic velocity Doppler — ทารกซีด เลือดไหลเร็วขึ้น → MCA-PSV สูง (>1.5 MoM = ซีดปานกลาง-รุนแรง) → intrauterine transfusion. ทดแทนการเจาะน้ำคร่ำวัด bilirubin เดิม."}, {"topic": "Obstetrics", "q": "Which congenital infection is the most common and a frequent cause of congenital sensorineural hearing loss?", "choices": ["Rubella", "Syphilis", "Toxoplasmosis", "Parvovirus B19", "Cytomegalovirus"], "ans": 4, "exp": "CMV เป็น congenital infection ที่พบบ่อยสุด และเป็นสาเหตุ sensorineural hearing loss แต่กำเนิดบ่อย. อาจมี microcephaly, periventricular calcification, IUGR, petechiae. Rubella → cataract/PDA/หูหนวก."}, {"topic": "Obstetrics", "q": "Which classic triad is associated with congenital toxoplasmosis?", "choices": ["Hydrocephalus, intracranial calcification, chorioretinitis", "Cataract, PDA, and deafness (rubella)", "Limb defects, cardiac lesions, cleft lip", "Microcephaly, petechiae, hepatomegaly (CMV)", "Sacral agenesis and clubfoot"], "ans": 0, "exp": "Classic triad ของ congenital toxoplasmosis: hydrocephalus, intracranial calcification (แบบกระจาย), chorioretinitis. ป้องกันโดยเลี่ยงเนื้อดิบ, ล้างผัก, เลี่ยงอุจจาระแมว."}, {"topic": "Obstetrics", "q": "A pregnant woman is HIV-positive. What management best reduces vertical transmission?", "choices": ["No treatment needed", "Antiretroviral therapy for all patients", "Treatment of the neonate only", "ART only in the third trimester", "Cesarean for all patients"], "ans": 1, "exp": "หญิงตั้งครรภ์ HIV ทุกรายควรได้ ART ลด vertical transmission เหลือ <1-2%. viral load >1,000 ใกล้คลอด → scheduled C/S + IV zidovudine. ทารกได้ ARV prophylaxis; หลีกเลี่ยงให้นม (ในไทย)."}, {"topic": "Obstetrics", "q": "An infant is born to a mother who is HBsAg-positive. What should the infant receive within 12 hours of birth?", "choices": ["Broad-spectrum antibiotics", "Magnesium sulfate infusion", "Hepatitis B immunoglobulin and vaccine", "Anti-D immunoglobulin dose", "MMR vaccine given at birth"], "ans": 2, "exp": "ทารกจากแม่ HBsAg positive ต้องได้ทั้ง HBIG และ hepatitis B vaccine ภายใน 12 ชม. เพื่อป้องกัน perinatal transmission (>90%). แม่ที่ HBV DNA สูงควรได้ tenofovir ไตรมาส 3."}, {"topic": "Obstetrics", "q": "A pregnant woman with confirmed syphilis is allergic to penicillin. What is the appropriate management?", "choices": ["Use doxycycline instead", "Give erythromycin", "Withhold treatment", "Desensitize and give penicillin", "Wait until after delivery"], "ans": 3, "exp": "Penicillin เป็นยาเดียวที่รักษาซิฟิลิสในครรภ์และป้องกัน congenital syphilis ได้ผล. แพ้ penicillin ต้อง desensitize แล้วให้ penicillin (ไม่ใช้ doxycycline ในครรภ์ หรือ erythromycin ที่ผ่านรกไม่ดีพอ)."}, {"topic": "Obstetrics", "q": "A pregnant woman at 39 weeks with a transverse lie presents in labor. What is the appropriate mode of delivery?", "choices": ["Vaginal delivery", "Vacuum extraction", "Forceps delivery", "Await spontaneous rotation", "Cesarean section"], "ans": 4, "exp": "Transverse lie คลอดทางช่องคลอดไม่ได้ — เมื่อเจ็บครรภ์/ครบกำหนดต้องผ่าคลอด. เสี่ยง cord prolapse/uterine rupture. บางรายอาจ ECV ก่อนเจ็บครรภ์."}, {"topic": "Obstetrics", "q": "After delivery of the head, the anterior shoulder becomes impacted (turtle sign). What is the appropriate first maneuver?", "choices": ["McRoberts with suprapubic pressure", "Strong downward traction on head", "Wait quietly for five minutes", "Firm fundal pressure downward", "Immediate cesarean delivery"], "ans": 0, "exp": "Shoulder dystocia (HELPERR): ขั้นแรกที่ได้ผลและทำง่ายคือ McRoberts maneuver + suprapubic pressure. ห้าม fundal pressure (ยิ่งติดแน่น/rupture) และห้ามดึงศีรษะแรง (brachial plexus injury)."}, {"topic": "Obstetrics", "q": "Which is the most common fetal complication of shoulder dystocia?", "choices": ["Cephalhematoma", "Brachial plexus injury", "Cataract", "Cleft palate alone", "Hydrocephalus alone"], "ans": 1, "exp": "Shoulder dystocia เสี่ยง brachial plexus injury (Erb palsy - C5-6, 'waiter's tip'), กระดูกไหปลาร้า/แขนหัก, hypoxic injury ถ้าคลอดช้า. การจัดการที่ถูกต้อง (ไม่ดึงแรง/ไม่กด fundus) ลดการบาดเจ็บ. ส่วนใหญ่หายได้เอง."}, {"topic": "Obstetrics", "q": "After membrane rupture, sudden fetal bradycardia occurs and the umbilical cord is palpable in the vagina. What is the most appropriate first action?", "choices": ["Administer an oxytocin infusion", "Observe expectantly for now", "Elevate presenting part, urgent cesarean", "Push the cord back inside", "Give analgesia for the pain"], "ans": 2, "exp": "Umbilical cord prolapse: ส่วนนำกดสายสะดือ → ยกส่วนนำขึ้นด้วยมือ (ไม่ดันสายสะดือกลับ), จัดท่า knee-chest/Trendelenburg, ให้ O2, tocolytic ถ้าจำเป็น, และผ่าคลอดฉุกเฉิน."}, {"topic": "Obstetrics", "q": "A woman with a prior classical cesarean in labor develops sudden severe abdominal pain, an abnormal FHR, and loss of station. What is the diagnosis?", "choices": ["Placental abruption", "Cord prolapse", "Amniotic fluid embolism", "Uterine rupture", "Chorioamnionitis"], "ans": 3, "exp": "Uterine rupture: เสี่ยงในแผล classical/VBAC. อาการ: ปวดฉับพลันรุนแรง, FHR bradycardia (ไวสุด), ส่วนนำลอยขึ้น (loss of station), เลือดออก, ช็อก → ผ่าตัดเปิดหน้าท้องฉุกเฉิน."}, {"topic": "Obstetrics", "q": "During delivery a woman suddenly develops respiratory failure, cardiovascular collapse, and disseminated intravascular coagulation. What is the most likely diagnosis?", "choices": ["Thrombotic pulmonary embolism", "Eclampsia", "Myocardial infarction", "Drug anaphylaxis", "Amniotic fluid embolism"], "ans": 4, "exp": "Amniotic fluid embolism (AFE): เกิดเฉียบพลันระหว่าง/หลังคลอด — hypoxia/respiratory failure, cardiovascular collapse, DIC. เป็น clinical diagnosis, พยากรณ์แย่, รักษาประคับประคอง. เป็นสาเหตุ maternal mortality สำคัญ."}, {"topic": "Obstetrics", "q": "What is the most common cause of postpartum hemorrhage?", "choices": ["Uterine atony", "Retained placenta", "Uterine inversion", "Laceration", "Coagulopathy"], "ans": 0, "exp": "สาเหตุ PPH (4T): Tone (atony), Trauma, Tissue (retained placenta), Thrombin (coagulopathy). Uterine atony พบบ่อยสุด (~70-80%). ปัจจัยเสี่ยง: มดลูกยืดมาก, คลอดนาน/เร็ว, chorioamnionitis, MgSO4."}, {"topic": "Obstetrics", "q": "A postpartum woman has a soft, boggy uterus and heavy bleeding. Which uterotonic is given first?", "choices": ["Methylergonovine", "Oxytocin", "Carboprost", "Misoprostol", "Tranexamic acid"], "ans": 1, "exp": "Uterine atony: นวดมดลูก + oxytocin เป็น uterotonic ตัวแรก. ถ้าไม่ได้ผลเพิ่ม methylergonovine (ห้ามความดันสูง), carboprost (ห้ามหืด), misoprostol. ให้ TXA ร่วม; ดื้อ → balloon, B-Lynch, ligation, hysterectomy."}, {"topic": "Obstetrics", "q": "A postpartum woman with uterine atony has a history of asthma. Which uterotonic should be avoided?", "choices": ["Oxytocin", "Tranexamic acid", "Carboprost", "Misoprostol", "Methylergonovine"], "ans": 2, "exp": "Carboprost (15-methyl PGF2α) ทำให้ bronchospasm → ห้ามในหืด. Methylergonovine ห้ามในความดันสูง/preeclampsia. Oxytocin ปลอดภัยที่สุดเป็นตัวแรก. ต้องจำ contraindication ของแต่ละ uterotonic."}, {"topic": "Obstetrics", "q": "When should tranexamic acid be given for postpartum hemorrhage to gain the most benefit?", "choices": ["After 24 hours", "Before delivery", "Only during cesarean", "Within 3 hours of birth", "After 4 units of blood"], "ans": 3, "exp": "[อัปเดต WHO/FIGO - WOMAN trial] TXA 1 g IV ให้เร็วภายใน 3 ชม.หลังคลอดในผู้วินิจฉัย PPH ลด maternal mortality. ให้ซ้ำอีก 1 g ถ้ายังเลือดออกหลัง 30 นาที. ให้หลัง 3 ชม.ประโยชน์ลดลง."}, {"topic": "Obstetrics", "q": "Which surgical procedure is the last resort for postpartum hemorrhage unresponsive to other measures?", "choices": ["B-Lynch suture", "Uterine artery ligation", "Balloon tamponade", "Uterine massage", "Hysterectomy"], "ans": 4, "exp": "ลำดับ PPH ดื้อ: uterotonics → TXA → balloon/embolization → surgical (B-Lynch, uterine/internal iliac ligation) → peripartum hysterectomy เป็นทางเลือกสุดท้ายเพื่อช่วยชีวิต (โดยเฉพาะ accreta, atony คุมไม่ได้)."}, {"topic": "Obstetrics", "q": "What is the preferred initial fluid for resuscitation of postpartum hemorrhage?", "choices": ["Isotonic crystalloid", "Colloid", "5% dextrose", "Albumin", "Hypertonic saline"], "ans": 0, "exp": "[อัปเดต WHO/FIGO] แนะนำ isotonic crystalloid (NSS, Ringer's lactate) เป็นสารน้ำเริ่มต้น มากกว่า colloid. ควบคู่การให้เลือด/blood products และแก้ coagulopathy (massive transfusion protocol)."}, {"topic": "Obstetrics", "q": "Which condition must be met to perform operative vaginal delivery (forceps or vacuum)?", "choices": ["Cervix dilated to only 6 cm", "Fully dilated cervix with engaged head", "No maternal or fetal indication", "A presenting part still floating", "A breech presentation"], "ans": 1, "exp": "เงื่อนไข operative vaginal delivery: ปากมดลูกเปิดหมด, ถุงน้ำแตก, ทราบตำแหน่ง/station (engaged), ไม่มี CPD, กระเพาะปัสสาวะว่าง, มี anesthesia, มี indication, พร้อมผ่าคลอดถ้าล้มเหลว."}, {"topic": "Obstetrics", "q": "A woman with one prior low-transverse cesarean desires VBAC. What is the most important risk to counsel her about?", "choices": ["Placenta previa", "Gestational diabetes", "Uterine rupture", "Preeclampsia", "Cord prolapse"], "ans": 2, "exp": "VBAC พิจารณาได้ในผู้เคยผ่า low transverse 1 ครั้ง. ความเสี่ยงสำคัญคือ uterine rupture ~0.5-1% (สูงขึ้นถ้า prostaglandin induction, หลายแผล, classical). ต้องคลอดในที่ที่ผ่าคลอดฉุกเฉินได้ทันที."}, {"topic": "Obstetrics", "q": "Which is a clear indication for cesarean delivery?", "choices": ["First pregnancy", "Maternal age of 35", "Well-controlled GDM", "Complete placenta previa", "Twin DCDA pregnancy"], "ans": 3, "exp": "ข้อบ่งชี้ absolute cesarean: complete placenta previa, transverse lie, cord prolapse (มีชีวิต), fetal distress ที่คลอดไม่ทัน, prior classical incision, active genital herpes, CPD ชัดเจน. อายุ/GDM/แฝด DCDA ไม่ใช่ข้อบ่งชี้เสมอไป."}, {"topic": "Obstetrics", "q": "A woman on postpartum day 3 has a fever of 38.5°C, uterine tenderness, and foul-smelling lochia. What is the treatment?", "choices": ["Nitrofurantoin for UTI", "Incision and drainage", "Dicloxacillin for mastitis", "Heparin for DVT", "Clindamycin plus gentamicin"], "ans": 4, "exp": "Postpartum endometritis เป็นสาเหตุไข้หลังคลอดที่พบบ่อยสุด (เสี่ยงหลังผ่าคลอด, ถุงน้ำแตกนาน). อาการ: ไข้ มดลูกกดเจ็บ น้ำคาวปลามีกลิ่น. เป็น polymicrobial → clindamycin + gentamicin IV จนไม่มีไข้ 24-48 ชม."}, {"topic": "Obstetrics", "q": "A breastfeeding woman has a red, warm, tender area on one breast with fever. What is the appropriate management?", "choices": ["Dicloxacillin, continue breastfeeding", "Radical mastectomy of the breast", "Stop breastfeeding completely", "Immediate surgery in all cases", "Observation without any treatment"], "ans": 0, "exp": "Lactational mastitis (มัก S. aureus): รักษาด้วย dicloxacillin/cephalexin + ประคบ + ระบายน้ำนม และ 'ให้นมต่อ'/ปั๊มออก (ไม่หยุด เพราะ stasis แย่ลง). คลำได้ก้อน fluctuant/ไม่ดีขึ้น = abscess → I&D/aspiration."}, {"topic": "Obstetrics", "q": "A woman 2 weeks postpartum has a depressed mood, tearfulness, and insomnia persisting over 2 weeks that impair infant care. What is the diagnosis?", "choices": ["Baby blues", "Postpartum depression", "Normal adjustment", "Postpartum psychosis", "Hypothyroidism only"], "ans": 1, "exp": "Postpartum depression: อาการซึมเศร้าเข้าเกณฑ์ major depression เกิดหลังคลอดถึง 12 เดือน นาน >2 สัปดาห์ กระทบการทำหน้าที่. ต่างจาก baby blues (หายใน ~2 สัปดาห์) และ psychosis (หลงผิด/ประสาทหลอน - ฉุกเฉิน). คัดกรอง EPDS; รักษา psychotherapy ± SSRI."}, {"topic": "Obstetrics", "q": "An intrauterine fetal death has been retained for several weeks. What complication should be monitored?", "choices": ["Polycythemia", "Hypertension", "Consumptive coagulopathy", "Diabetes", "Twin gestation alone"], "ans": 2, "exp": "IUFD ที่ค้างนาน (>4 สัปดาห์) เสี่ยง consumptive coagulopathy/DIC จาก thromboplastin ที่ปล่อยจากทารกที่เสียชีวิต → fibrinogen ลด. ควรตรวจ coagulation และวางแผนคลอด (induction). ยืนยัน IUFD ด้วย US."}, {"topic": "Obstetrics", "q": "A pregnant woman with heart disease is at greatest risk of heart failure at which time?", "choices": ["During the first trimester", "Only before pregnancy begins", "Around 12 weeks gestation", "At 28-32 weeks and postpartum", "At six months postpartum"], "ans": 3, "exp": "ช่วงเสี่ยงสูงในหญิงตั้งครรภ์โรคหัวใจ: GA 28-32 wk (CO/blood volume สูงสุด) และหลังคลอดทันที (autotransfusion). โรคที่เป็นข้อห้ามตั้งครรภ์: Eisenmenger, severe pulmonary HT, severe symptomatic stenosis."}, {"topic": "Obstetrics", "q": "A pregnant woman is switched from her seizure medication because of high teratogenic risk. Which drug has the greatest risk of neural tube defects?", "choices": ["Lamotrigine", "Levetiracetam", "Carbamazepine", "Phenobarbital", "Valproate"], "ans": 4, "exp": "Valproate เสี่ยงสูงสุดต่อ neural tube defect และ neurodevelopmental impairment → เลี่ยงในหญิงวัยเจริญพันธุ์ (เปลี่ยนเป็น lamotrigine/levetiracetam), ให้ folate สูง, ใช้ monotherapy."}, {"topic": "Obstetrics", "q": "A woman with persistent occiput posterior position has a prolonged second stage. Which is a reasonable option in a suitable candidate?", "choices": ["Manual rotation or operative delivery", "Immediate cesarean in all cases", "Maximal-dose oxytocin infusion", "Vigorous fundal pressure", "Tocolysis to slow labor"], "ans": 0, "exp": "Persistent OP → prolonged 2nd stage. หลายรายหมุนเป็น OA เอง; ถ้าไม่ก้าวหน้าพิจารณา manual rotation หรือ operative vaginal delivery, หรือ cesarean ถ้ามี CPD/ล้มเหลว. ห้ามกด fundus."}, {"topic": "Obstetrics", "q": "A woman at 30 weeks sustains blunt abdominal trauma in a motor vehicle collision. Besides fetal monitoring, what should be given if she is Rh-negative?", "choices": ["Nothing is needed", "Anti-D immunoglobulin", "Antibiotics only", "Insulin", "Magnesium sulfate"], "ans": 1, "exp": "Trauma เสี่ยง placental abruption (แม้ไม่มีบาดเจ็บภายนอกชัด) → monitor FHR/contraction ≥4-6 ชม., ตรวจ Kleihauer-Betke, และให้ anti-D ถ้ามารดา Rh negative (FMH). ประเมินมารดาตามหลัก trauma."}, {"topic": "Obstetrics", "q": "A woman 1 week postpartum has persistent high fever unresponsive to antibiotics with no identifiable source. What is the likely diagnosis?", "choices": ["Simple endometritis", "Urinary tract infection", "Septic pelvic thrombophlebitis", "Mastitis", "Normal puerperium"], "ans": 2, "exp": "Septic pelvic thrombophlebitis: ไข้ที่ไม่ตอบสนองต่อยาปฏิชีวนะหลังคลอด/ผ่าตัดโดยไม่พบแหล่งติดเชื้อ (diagnosis of exclusion). จากลิ่มเลือดติดเชื้อในหลอดเลือดดำอุ้งเชิงกราน. รักษาด้วยยาปฏิชีวนะ + anticoagulation."}, {"topic": "Obstetrics", "q": "A woman 2 weeks postpartum has unilateral leg swelling, calf pain, and tenderness. What test should be performed?", "choices": ["Skin swab and culture", "Breast ultrasound", "Endometrial biopsy", "Compression ultrasound of the leg", "No investigation needed"], "ans": 3, "exp": "หลังคลอดเสี่ยง VTE สูงสุด. ขาบวมข้างเดียว ปวดน่อง กดเจ็บ = DVT → compression/Doppler ultrasound. ยืนยันแล้วให้ anticoagulation. ระวัง pulmonary embolism (เหนื่อย เจ็บอก) ซึ่งเป็นสาเหตุ maternal death สำคัญ."}, {"topic": "Obstetrics", "q": "After delivery of the placenta the fundus is not palpable and the mother is in shock with hemorrhage; a mass is seen at the introitus. What is the first step?", "choices": ["Give a uterotonic immediately", "Apply firm cord traction", "Perform immediate hysterectomy", "Observe expectantly for now", "Stop uterotonics, replace the uterus"], "ans": 4, "exp": "Uterine inversion เป็นภาวะฉุกเฉิน. ขั้นแรก: เรียกช่วยเหลือ, หยุด uterotonic (ให้มดลูกคลาย), ดันมดลูกกลับด้วยมือ (Johnson maneuver) อาจใช้ tocolytic/ยาสลบช่วย, กู้ชีพด้วยสารน้ำ/เลือด. กลับเข้าที่แล้วจึงให้ uterotonic."}, {"topic": "Obstetrics", "q": "A woman with prolonged rupture of membranes has maternal fever, maternal and fetal tachycardia, and uterine tenderness. What is the diagnosis and appropriate management?", "choices": ["Chorioamnionitis, antibiotics and delivery", "Normal labor, observe", "Preeclampsia, magnesium sulfate", "Abruption, immediate cesarean", "UTI, oral antibiotics"], "ans": 0, "exp": "Intraamniotic infection (chorioamnionitis): ไข้มารดา + fetal/maternal tachycardia, มดลูกกดเจ็บ, น้ำคร่ำมีกลิ่น. รักษาด้วย ampicillin + gentamicin และเร่งคลอด (คลอดทางช่องคลอดได้ ไม่ใช่ข้อบ่งชี้ผ่าคลอด). เสี่ยง PPH, neonatal sepsis."}, {"topic": "Obstetrics", "q": "An Rh-negative unsensitized woman has a first-trimester miscarriage. What should she receive?", "choices": ["Nothing is required", "Anti-D immunoglobulin", "Oxytocin only", "Antibiotics only", "Iron supplements only"], "ans": 1, "exp": "เหตุการณ์ที่ทำให้ FMH และต้องให้ anti-D (Rh negative unsensitized): แท้ง/ectopic/molar, เจาะน้ำคร่ำ/CVS, เลือดออก (abruption/previa), trauma, ECV, IUFD. + dose ประจำที่ 28 wk และหลังคลอด."}, {"topic": "Obstetrics", "q": "A woman at 37 weeks has term PROM with clear fluid and is GBS-positive but not in labor. What is the appropriate management?", "choices": ["Expectant care for 1 week", "Immediate cesarean", "Induction with GBS prophylaxis", "Tocolysis", "Corticosteroids"], "ans": 2, "exp": "Term PROM ที่ไม่เข้าสู่ระยะคลอดเอง → induction (ลด chorioamnionitis/neonatal infection) + GBS intrapartum prophylaxis. ไม่ต้อง steroid/tocolytic เพราะครบกำหนด."}, {"topic": "Obstetrics", "q": "Which drug is a known teratogen that should be avoided in pregnancy?", "choices": ["Insulin", "Methyldopa", "Penicillin", "Isotretinoin", "Paracetamol"], "ans": 3, "exp": "Isotretinoin (retinoid) เป็น teratogen รุนแรง (craniofacial/cardiac/CNS anomalies) → ห้ามในครรภ์ ต้องคุมกำเนิดเข้มงวด. teratogen อื่น: warfarin, ACEI/ARB, valproate, tetracycline, methotrexate. Insulin/methyldopa/paracetamol/penicillin ปลอดภัย."}, {"topic": "Obstetrics", "q": "A woman with GDM controlled on insulin is at 38 weeks. What is the recommended timing of delivery?", "choices": ["Wait until 42 weeks", "Await spontaneous labor indefinitely", "Immediate cesarean at 38 weeks", "At 34 weeks", "About 39 weeks"], "ans": 4, "exp": "GDM ที่ใช้ยา (insulin)/คุมไม่ดี แนะนำคลอด ~GA 39 wk (สมดุลระหว่าง stillbirth/macrosomia กับ prematurity). GDM คุมได้ดีด้วยอาหารรอได้ถึง 40-41 wk. ประเมิน EFW พิจารณา C/S ถ้า macrosomia มาก."}, {"topic": "Obstetrics", "q": "In a diabetic mother, cesarean delivery is offered to prevent shoulder dystocia when the estimated fetal weight reaches what threshold?", "choices": ["4,500 grams or more", "4,000 grams or more", "3,500 grams or more", "3,000 grams or more", "No threshold exists"], "ans": 0, "exp": "ACOG แนะนำพิจารณา cesarean เพื่อป้องกัน shoulder dystocia เมื่อ EFW ≥4,500 g ในมารดาเบาหวาน และ ≥5,000 g ในมารดาไม่เบาหวาน (US ทำนาย macrosomia คลาดเคลื่อน). วินิจฉัย macrosomia = EFW >4,000-4,500 g."}, {"topic": "Obstetrics", "q": "A woman with isolated gestational hypertension without severe features should be delivered at what gestational age?", "choices": ["34 weeks", "37 weeks", "40 weeks", "42 weeks", "Await spontaneous labor"], "ans": 1, "exp": "Gestational hypertension/preeclampsia without severe features แนะนำคลอดที่ GA 37 wk. Preeclampsia with severe features คลอดที่ 34 wk (หรือเร็วกว่าถ้าไม่คงที่). ก่อนถึงกำหนดต้องเฝ้าระวังการดำเนินโรค."}, {"topic": "Obstetrics", "q": "A woman at 12 weeks has severe nausea and vomiting with 6% weight loss and ketonuria. Besides supportive care, what should be done?", "choices": ["Discharge home without workup", "Empiric broad-spectrum antibiotics", "Ultrasound to exclude molar/multiple", "Immediate exploratory surgery", "Upper GI endoscopy now"], "ans": 2, "exp": "Hyperemesis gravidarum: คลื่นไส้อาเจียนรุนแรง น้ำหนักลด >5%, ketonuria. สัมพันธ์ hCG สูง → ควร US แยก molar/แฝด. รักษา: สารน้ำ, B6 ± doxylamine, antiemetic, thiamine (ป้องกัน Wernicke)."}, {"topic": "Obstetrics", "q": "A woman at 36 weeks has severe pruritus of the palms and soles worst at night with elevated bile acids. What is the diagnosis and its main risk?", "choices": ["PUPPP with no fetal risk", "Eczema needing topical cream", "Scabies needing a scabicide", "Intrahepatic cholestasis, stillbirth risk", "Normal pregnancy-related itch"], "ans": 3, "exp": "Intrahepatic cholestasis of pregnancy: คันรุนแรง (ฝ่ามือ/ฝ่าเท้า เด่นกลางคืน) ไม่มีผื่น, bile acid สูง. เสี่ยง sudden fetal death/stillbirth, meconium, preterm. รักษา ursodeoxycholic acid, คลอด ~37 wk (เร็วกว่าถ้า bile acid สูงมาก)."}, {"topic": "Obstetrics", "q": "A woman on magnesium sulfate becomes drowsy with absent reflexes and a respiratory rate of 10. What is the immediate management?", "choices": ["Increase the magnesium dose", "Administer furosemide now", "Administer naloxone now", "Administer flumazenil now", "Stop magnesium, give calcium"], "ans": 4, "exp": "ซึม, loss of DTR, RR ต่ำ = magnesium toxicity → หยุด MgSO4 ทันที และให้ calcium gluconate IV (antidote). ประเมิน airway/breathing, ตรวจ serum Mg และ renal function."}, {"topic": "Obstetrics", "q": "A woman with chronic hypertension presents for care. Which antihypertensive is safe and commonly used in pregnancy?", "choices": ["Labetalol", "Enalapril", "Losartan", "Atenolol", "Spironolactone"], "ans": 0, "exp": "ยาลดความดันปลอดภัยในครรภ์: methyldopa, labetalol, nifedipine. ห้าม ACEI/ARB (teratogen, fetal renal/oligohydramnios) และ atenolol (สัมพันธ์ FGR). Chronic HT ควรได้ aspirin ป้องกัน superimposed preeclampsia."}, {"topic": "Obstetrics", "q": "A woman with two prior low-transverse cesareans presents in labor at 39 weeks and desires vaginal delivery. What is the most appropriate recommendation?", "choices": ["Fully support VBAC", "Recommend repeat cesarean", "Prostaglandin induction", "Vacuum delivery", "Await spontaneous labor"], "ans": 1, "exp": "การเคยผ่าคลอด ≥2 ครั้งเพิ่มความเสี่ยง uterine rupture → ส่วนใหญ่แนะนำ repeat elective cesarean. ห้าม induction ด้วย prostaglandin ในผู้มีแผลผ่าคลอด (เพิ่ม rupture)."}, {"topic": "Obstetrics", "q": "A pregnant woman with SLE is anti-Ro/SSA positive. Which fetal complication is of particular concern?", "choices": ["Macrosomia", "Cleft palate alone", "Congenital heart block", "Hydrocephalus alone", "Erb palsy"], "ans": 2, "exp": "Anti-Ro/SSA ผ่านรกทำลาย fetal cardiac conduction → congenital complete heart block (neonatal lupus). เฝ้าระวัง fetal heart rate/echo ช่วง 16-26 wk. SLE ที่ active เสี่ยง preeclampsia, FGR, pregnancy loss (โดยเฉพาะมี APS)."}, {"topic": "Obstetrics", "q": "A woman at 40 weeks in labor has an active genital herpes lesion. What is the appropriate mode of delivery?", "choices": ["Normal vaginal delivery", "Antibiotics then vaginal delivery", "Vacuum extraction", "Cesarean section", "Await lesion healing"], "ans": 3, "exp": "Active genital HSV lesion/prodrome ขณะเจ็บครรภ์ = ข้อบ่งชี้ผ่าคลอด ลดความเสี่ยง neonatal herpes (รุนแรง). ผู้มีประวัติ HSV ควรได้ acyclovir suppression ตั้งแต่ ~36 wk เพื่อลดการกำเริบ."}, {"topic": "Obstetrics", "q": "A 39-week frank breech with an estimated fetal weight of 3,000 g and adequate pelvis presents in labor. What is the most widely recommended approach today?", "choices": ["Vaginal breech delivery always", "Oxytocin augmentation", "Forceps-assisted delivery", "Await spontaneous version", "Planned cesarean delivery"], "ans": 4, "exp": "ตาม Term Breech Trial การผ่าคลอดในทารกท่าก้นครบกำหนดลด perinatal morbidity → นิยม. ทางเลือกป้องกันคือ ECV ที่ ~37 wk. การคลอดท่าก้นทางช่องคลอดยังทำได้ในเงื่อนไขจำกัดโดยผู้เชี่ยวชาญ."}, {"topic": "Obstetrics", "q": "A woman at 8 weeks has asymptomatic bacteriuria on screening urine culture. What is the appropriate management?", "choices": ["Treat with a pregnancy-safe antibiotic", "No treatment since asymptomatic", "Give a diuretic", "Wait for symptoms", "Refer for surgery"], "ans": 0, "exp": "Asymptomatic bacteriuria ในครรภ์ต้องรักษา (ต่างจากคนทั่วไป) เพราะเสี่ยง pyelonephritis และ preterm/LBW. คัดกรองด้วย urine culture ไตรมาสแรก, เลือกยาปลอดภัย, และ test of cure."}, {"topic": "Obstetrics", "q": "A pregnant woman with microcytic anemia (Hb 8), a family history of thalassemia, and normal iron studies should undergo which next step?", "choices": ["Give oral iron and stop", "Hemoglobin typing, test partner", "Proceed to cesarean delivery", "Immediate blood transfusion", "Check thyroid function only"], "ans": 1, "exp": "Microcytic anemia + ประวัติครอบครัว ต้องแยกธาลัสซีเมียจากขาดเหล็ก → Hb typing (± DNA) และประเมินคู่สมรส. คู่เสี่ยง → prenatal diagnosis (ทารกเสี่ยง Bart's hydrops/β-thal major). หัวใจของโครงการควบคุมธาลัสซีเมียไทย."}, {"topic": "Obstetrics", "q": "In which condition does blood infiltrate the myometrium, giving the uterus a purplish appearance (Couvelaire uterus)?", "choices": ["Placenta previa alone", "Uterine atony", "Severe placental abruption", "Molar pregnancy alone", "Ectopic pregnancy alone"], "ans": 2, "exp": "Couvelaire uterus (uteroplacental apoplexy) เกิดใน severe abruption — เลือดแทรกชั้นกล้ามเนื้อและ serosa ทำให้มดลูกม่วงคล้ำ. อาจสัมพันธ์ atony/PPH. ส่วนใหญ่มดลูกยังหดตัวได้ ไม่จำเป็นต้องตัดมดลูกเสมอ."}, {"topic": "Obstetrics", "q": "A pregnant woman with a history of VTE or thrombophilia needs prophylaxis. Which agent is appropriate?", "choices": ["Warfarin throughout pregnancy", "No treatment needed", "High-dose aspirin", "Low-molecular-weight heparin", "Vitamin K"], "ans": 3, "exp": "เสี่ยง VTE สูง → thromboprophylaxis ด้วย LMWH/heparin (ไม่ผ่านรก ปลอดภัยในครรภ์). หลีกเลี่ยง warfarin (teratogen, fetal bleeding) ยกเว้นบางกรณี (mechanical valve). ปรับแผนช่วงคลอดเรื่อง neuraxial anesthesia."}, {"topic": "Obstetrics", "q": "A woman at 30 weeks in preterm labor is started on nifedipine as a tocolytic. What side effect should be monitored?", "choices": ["Increased urine output", "Ductus arteriosus closure", "Palpitations from beta-agonism", "Respiratory depression", "Hypotension and headache"], "ans": 4, "exp": "Nifedipine (calcium channel blocker) ยับยั้งการหดตัวมดลูก (นิยมเพราะให้ทางปาก ผลข้างเคียงน้อย). ผลข้างเคียง: hypotension, ปวดศีรษะ, หน้าแดง, ใจสั่น. เลี่ยงใช้ร่วม MgSO4 ขนาดสูงพร้อมกัน."}, {"topic": "Obstetrics", "q": "A GBS-positive woman is in labor. What should she receive?", "choices": ["Intrapartum penicillin prophylaxis", "No specific intervention", "Elective cesarean section", "Antiviral therapy", "Magnesium sulfate infusion"], "ans": 0, "exp": "GBS positive → intrapartum antibiotic prophylaxis (penicillin G IV เป็นตัวแรก) เมื่อเข้าสู่ระยะคลอด/ถุงน้ำแตก เพื่อป้องกัน early-onset GBS disease. ให้ ≥4 ชม.ก่อนคลอด. ยกเว้นผ่าคลอดก่อนเจ็บครรภ์และถุงน้ำยังไม่แตก."}, {"topic": "Obstetrics", "q": "A woman had a prior infant with invasive GBS disease. What is the appropriate approach in this pregnancy?", "choices": ["Culture first always", "Intrapartum prophylaxis without culture", "No antibiotics", "Cesarean section", "Treatment from the first trimester"], "ans": 1, "exp": "ข้อบ่งชี้ให้ GBS prophylaxis โดยไม่ต้องรอ culture: เคยมีบุตร invasive GBS, GBS bacteriuria ครรภ์นี้, ผลคัดกรอง positive, หรือสถานะไม่ทราบ + ปัจจัยเสี่ยง (<37 wk, ถุงน้ำแตก ≥18 ชม., ไข้)."}, {"topic": "Obstetrics", "q": "A woman at 28 weeks with severe early-onset FGR has absent umbilical artery end-diastolic flow. What is the most appropriate management?", "choices": ["Routine follow-up in 4 weeks", "Give hematinic supplements", "Admit for close fetal surveillance", "Immediate cesarean in all cases", "Discontinue all prenatal care"], "ans": 2, "exp": "Severe early-onset FGR + absent EDF บ่งชี้ placental insufficiency รุนแรง เสี่ยง fetal demise → admit, surveillance ใกล้ชิด (Doppler, BPP), ให้ steroid และ MgSO4 (<32 wk) เตรียมคลอด. Timing สมดุลระหว่าง prematurity กับความเสี่ยง fetal death."}, {"topic": "Obstetrics", "q": "A woman received a full course of betamethasone at 29 weeks and is now at risk of delivery again at 33 weeks. What should be considered?", "choices": ["Repeat multiple full courses", "No further steroids at all", "Switch to hydrocortisone instead", "A single rescue steroid course", "Give magnesium instead of steroid"], "ans": 3, "exp": "หากให้ course แรก >14 วันก่อน และยังเสี่ยงคลอดใน 7 วันที่ GA <34 wk พิจารณา single rescue course ได้ — แต่ไม่แนะนำหลายรอบ (multiple courses) เพราะสัมพันธ์กับ FGR/ปัญหาพัฒนาการ."}, {"topic": "Obstetrics", "q": "A woman at 41 weeks has a non-reactive NST followed by a BPP of 4/10 with oligohydramnios. What is the appropriate management?", "choices": ["Repeat testing next week", "Give hematinics", "Wait until 43 weeks", "Give tocolytics", "Proceed with delivery"], "ans": 4, "exp": "BPP ≤4/10 + oligohydramnios ในครรภ์เกินกำหนด บ่งชี้ fetal compromise → พิจารณาให้คลอด (induction/cesarean ตามสภาพปากมดลูก/FHR). การรอเพิ่มความเสี่ยง stillbirth. ทารกครบกำหนดแล้วจึงคลอดได้."}, {"topic": "Obstetrics", "q": "A woman at 34 weeks presents with BP 160/110, a severe headache, blurred vision, and brisk reflexes. What is the appropriate urgent management?", "choices": ["Admit, magnesium, plan delivery", "Discharge with follow-up next week", "Analgesia and simple observation", "Give low-dose aspirin only", "Reassurance and ultrasound only"], "ans": 0, "exp": "Preeclampsia with severe features (BP ≥160/110 + อาการทางสมอง/ตา = เสี่ยง eclampsia) → admit, MgSO4, ยาลดความดัน (labetalol/hydralazine/nifedipine), steroid ถ้า <34 wk, และวางแผนคลอด (severe features ที่ ≥34 wk → คลอด)."}, {"topic": "Obstetrics", "q": "A woman at 33 weeks with preterm labor is a candidate for magnesium sulfate neuroprotection. This is recommended when delivery is anticipated before which gestational age?", "choices": ["37 weeks", "32 weeks", "34 weeks", "28 weeks", "24 weeks"], "ans": 1, "exp": "[อัปเดต] MgSO4 ให้เพื่อ fetal neuroprotection (ลด cerebral palsy) เมื่อคาดว่าจะคลอดก่อน GA 32 wk — คนละบทบาทกับ MgSO4 ใน preeclampsia (ป้องกันชัก ทุกอายุครรภ์ที่ severe)."}, {"topic": "Obstetrics", "q": "A neonate born to a mother with poorly controlled gestational diabetes is at risk of which early complication?", "choices": ["Hyperbilirubinemia only", "Necrotizing enterocolitis", "Neonatal hypoglycemia", "Cataract", "Congenital heart block"], "ans": 2, "exp": "ทารกจากแม่ GDM มี fetal hyperinsulinemia → neonatal hypoglycemia (ตรวจน้ำตาลหลังเกิด), macrosomia, shoulder dystocia, RDS, hyperbilirubinemia, polyhydramnios."}, {"topic": "Obstetrics", "q": "A woman at 26 weeks presents for routine care. Which screening is due at 24-28 weeks?", "choices": ["The fetal anomaly scan", "Group B streptococcus culture", "Nuchal translucency scan", "Gestational diabetes screening", "The quadruple serum test"], "ans": 3, "exp": "ช่วง GA 24-28 wk เป็นกำหนดคัดกรอง GDM และตรวจ Hb ซ้ำ. Anomaly scan 18-22 wk, NT 11-14 wk, GBS 36-37+6 wk."}, {"topic": "Obstetrics", "q": "A woman at 28 weeks has a fundal height of 34 cm; ultrasound shows an amniotic fluid index of 28 cm. What condition should be considered?", "choices": ["Oligohydramnios", "Growth restriction", "Fetal demise", "Normal fluid volume", "Polyhydramnios"], "ans": 4, "exp": "AFI >25 cm = polyhydramnios ทำให้ SFH มากกว่าอายุครรภ์. สาเหตุ: เบาหวาน, ความผิดปกติทารกที่รบกวนการกลืน (esophageal/duodenal atresia, anencephaly), hydrops, แฝด/TTTS. ตรวจ anomaly scan + คัดกรองเบาหวาน."}, {"topic": "Obstetrics", "q": "A woman with severe preeclampsia at 30 weeks has stable vital signs after magnesium and antihypertensives. What is the next appropriate step before delivery?", "choices": ["Administer antenatal corticosteroids", "Immediate delivery regardless", "Start oral iron therapy", "Discharge home on medication", "Give prophylactic antibiotics"], "ans": 0, "exp": "Preeclampsia with severe features <34 wk ที่เสถียร → ให้ antenatal corticosteroid (lung maturity) ก่อนคลอด และคลอดที่ ~34 wk (หรือเร็วกว่าถ้าไม่คงที่/มีภาวะแทรกซ้อน). MgSO4 ป้องกันชักต่อเนื่อง."}, {"topic": "Obstetrics", "q": "A woman with a molar pregnancy is being followed after evacuation. What is essential during follow-up?", "choices": ["Immediate next pregnancy", "Serial beta-hCG with contraception", "Prophylactic chemotherapy", "Annual ultrasound only", "No specific follow-up"], "ans": 1, "exp": "หลัง evacuation ต้องติดตาม serial β-hCG จนเป็นลบต่อเนื่อง เพื่อตรวจจับ GTN. คุมกำเนิดระหว่างติดตาม (ห้ามตั้งครรภ์ เพราะทำให้แปลผล hCG ไม่ได้). hCG plateau/สูงขึ้น = GTN → เคมีบำบัด."}, {"topic": "Obstetrics", "q": "A woman at 34 weeks with twins is counseled on the most important factor determining monitoring intensity. What is it?", "choices": ["Maternal age", "Fetal sex", "Chorionicity", "Maternal weight", "Parity"], "ans": 2, "exp": "Chorionicity สำคัญที่สุดในการดูแลครรภ์แฝด: monochorionic เสี่ยง TTTS/sFGR/TAPS ต้อง US ถี่กว่า. ประเมินในไตรมาสแรก (lambda = dichorionic, T-sign = monochorionic)."}, {"topic": "Obstetrics", "q": "A woman with type 1 diabetes had poor glycemic control in early pregnancy. Which fetal anomaly is characteristically associated?", "choices": ["Meconium aspiration", "Erb palsy", "Cataract", "Caudal regression syndrome", "Congenital heart block"], "ans": 3, "exp": "Pregestational DM ที่น้ำตาลสูงช่วง organogenesis เพิ่ม cardiac defects (บ่อยสุด), neural tube defects, และ caudal regression syndrome (จำเพาะกับเบาหวาน). เน้น preconception glycemic control + folate. ต่างจาก GDM (macrosomia/hypoglycemia)."}, {"topic": "Obstetrics", "q": "A woman with hyperthyroidism from Graves disease is pregnant in the first trimester. Which antithyroid drug is preferred at this stage?", "choices": ["Methimazole", "Radioactive iodine", "Levothyroxine", "Propranolol alone", "Propylthiouracil"], "ans": 4, "exp": "ไตรมาสแรกใช้ PTU (methimazole เสี่ยง aplasia cutis/embryopathy), แล้วเปลี่ยนเป็น methimazole ไตรมาส 2-3 (PTU เสี่ยง hepatotoxicity). ห้าม radioactive iodine (ทำลายต่อมทารก). เฝ้าระวัง neonatal thyrotoxicosis จาก TSI ผ่านรก."}]}, {"id": "obgyn3", "title": "Ob-gyne ชุดที่ 3 — Gynecology I (Menstrual Cycle, Amenorrhea & PCOS, AUB, Endometriosis, Menopause)", "subject": "obgyn", "questions": [{"topic": "Gynecology", "q": "During embryologic development, the Müllerian (paramesonephric) ducts give rise to which structures?", "choices": ["Tubes, uterus, cervix, upper vagina", "The ovaries and gonads", "The male genital structures", "The lower two-thirds of vagina", "The bladder and urethra"], "ans": 0, "exp": "Müllerian ducts พัฒนาเป็นท่อนำไข่ มดลูก ปากมดลูก และช่องคลอดส่วนบน 1/3. ช่องคลอดส่วนล่างมาจาก urogenital sinus. รังไข่มาจาก gonadal ridge. ในชาย AMH ทำให้ Müllerian ฝ่อ."}, {"topic": "Gynecology", "q": "A 16-year-old with normal breasts and pubic hair has never menstruated. She has an absent uterus and upper vagina but a 46,XX karyotype with normal ovaries. What is the diagnosis?", "choices": ["Androgen insensitivity syndrome", "Müllerian agenesis (MRKH)", "Turner syndrome", "Polycystic ovary syndrome", "Imperforate hymen"], "ans": 1, "exp": "Müllerian agenesis (MRKH): 46,XX, รังไข่/ฮอร์โมนปกติ (ลักษณะทางเพศปกติ) แต่ไม่มีมดลูก/ช่องคลอดส่วนบน → primary amenorrhea. ต่างจาก AIS (46,XY, ไม่มีขนหัวหน่าว, มี testis)."}, {"topic": "Gynecology", "q": "A 17-year-old with normal breasts but absent pubic and axillary hair has intra-abdominal testes and a 46,XY karyotype. What is the diagnosis?", "choices": ["Müllerian agenesis (MRKH)", "Turner syndrome", "Complete androgen insensitivity", "5-alpha reductase deficiency", "Kallmann syndrome"], "ans": 2, "exp": "Complete AIS: 46,XY มี testis สร้าง testosterone/AMH ปกติ แต่ receptor ไม่ทำงาน → external genitalia เป็นหญิง, มีเต้านม (aromatization) แต่ไม่มีขน (androgen-dependent) และไม่มีมดลูก (AMH). แนะนำ gonadectomy หลัง puberty."}, {"topic": "Gynecology", "q": "Which Müllerian anomaly is most associated with recurrent pregnancy loss and treated by hysteroscopic resection?", "choices": ["Bicornuate uterus", "Uterine didelphys", "Unicornuate uterus", "Septate uterus", "Arcuate uterus"], "ans": 3, "exp": "Septate uterus (ผนังกั้นในโพรงมดลูก) สัมพันธ์ recurrent pregnancy loss มากที่สุด (septum เลือดเลี้ยงน้อย ฝังตัวไม่ดี). รักษาด้วย hysteroscopic septum resection. เกิดจากความล้มเหลวของ resorption (ต่างจาก bicornuate = fusion defect)."}, {"topic": "Gynecology", "q": "What is the correct sequence of pubertal development in girls?", "choices": ["Menarche, thelarche, pubarche", "Pubarche, menarche, thelarche", "Growth spurt, menarche, thelarche", "Menarche, growth spurt, thelarche", "Thelarche, pubarche, growth spurt, menarche"], "ans": 4, "exp": "ลำดับ puberty หญิง: thelarche (เต้านม-แรก) → pubarche/adrenarche (ขน) → growth spurt → menarche (สุดท้าย). Menarche เกิดหลัง thelarche ~2-3 ปี. ลำดับผิดปกติบ่งชี้พยาธิสภาพ."}, {"topic": "Gynecology", "q": "Precocious puberty in a girl is defined as development of secondary sexual characteristics before what age?", "choices": ["Eight years", "Six years", "Fourteen years", "Ten years", "Twelve years"], "ans": 0, "exp": "Precocious puberty หญิง = ลักษณะทางเพศทุติยภูมิก่อนอายุ 8 ปี (หรือ menarche ก่อน 9-10). แบ่ง central (GnRH-dependent, มัก idiopathic) และ peripheral (cyst, McCune-Albright, CAH). ประเมิน bone age, GnRH stimulation, imaging."}, {"topic": "Gynecology", "q": "In the menstrual cycle, which event triggers ovulation?", "choices": ["An isolated FSH surge", "An LH surge from rising estrogen", "A mid-cycle progesterone surge", "A rise in hCG", "A sudden fall in estrogen"], "ans": 1, "exp": "Estrogen สูงจาก dominant follicle ปลาย follicular phase มี positive feedback → LH surge → ovulation (~36 ชม.หลัง surge). หลัง ovulation corpus luteum สร้าง progesterone (luteal phase คงที่ 14 วัน)."}, {"topic": "Gynecology", "q": "What is the approximately fixed length of the luteal phase of the menstrual cycle?", "choices": ["Seven days", "Ten days", "Fourteen days", "Highly variable", "Twenty-one days"], "ans": 2, "exp": "Luteal phase (หลัง ovulation ถึงก่อนประจำเดือน) คงที่ ~14 วัน (อายุขัย corpus luteum). ความแปรผันของรอบเดือนมาจาก follicular phase. รอบ 35 วัน → ovulation ~วันที่ 21."}, {"topic": "Gynecology", "q": "During the secretory phase of the endometrium, which hormone is the main driver?", "choices": ["Estrogen", "hCG", "FSH", "Progesterone", "LH"], "ans": 3, "exp": "หลัง ovulation corpus luteum สร้าง progesterone เปลี่ยน endometrium เป็น secretory (ต่อมขดตัว หลั่ง glycogen เตรียม implantation). ไม่ตั้งครรภ์ → corpus luteum ฝ่อ → progesterone ลด → ประจำเดือน."}, {"topic": "Gynecology", "q": "How is primary amenorrhea defined?", "choices": ["Absence of menses for three months", "No menses following a delivery", "Absence of menses for six months", "Scanty, infrequent menstrual flow", "No menses by 15 with normal development"], "ans": 4, "exp": "Primary amenorrhea = ไม่เคยมีประจำเดือนเมื่ออายุ 15 ปี (มีลักษณะทางเพศ) หรือ 13 ปี (ไม่มีลักษณะทางเพศ). Secondary = เคยมีแล้วขาด ≥3 เดือน (รอบสม่ำเสมอ) หรือ ≥6 เดือน. แยกการตั้งครรภ์ก่อนเสมอ."}, {"topic": "Gynecology", "q": "In evaluating a woman with secondary amenorrhea, which test should always be done first?", "choices": ["A pregnancy test (beta-hCG)", "Serum prolactin", "Serum FSH", "Serum TSH", "Pelvic ultrasound alone"], "ans": 0, "exp": "การตั้งครรภ์เป็นสาเหตุ secondary amenorrhea ที่พบบ่อยที่สุด จึงตรวจ β-hCG ก่อนเสมอ. จากนั้น TSH และ prolactin แล้วประเมิน estrogen status ด้วย progestin challenge."}, {"topic": "Gynecology", "q": "A woman with secondary amenorrhea has withdrawal bleeding after a progestin challenge test. What does this indicate?", "choices": ["Significant estrogen deficiency", "Adequate estrogen with anovulation", "Primary ovarian failure", "An outflow tract obstruction", "An early pregnancy"], "ans": 1, "exp": "Withdrawal bleeding หลัง progestin = มี endometrium ที่ถูก prime ด้วย estrogen เพียงพอ และ outflow tract เปิด → anovulation (มี estrogen แต่ไม่มี ovulation/progesterone) เช่น PCOS. ไม่ออก → estrogen ต่ำ หรือ outflow obstruction."}, {"topic": "Gynecology", "q": "How many of the three Rotterdam criteria are required to diagnose polycystic ovary syndrome?", "choices": ["One of three", "Three of three", "Two of three", "Not based on count", "Hyperandrogenism alone"], "ans": 2, "exp": "Rotterdam: ต้องมี 2 ใน 3 — oligo/anovulation, hyperandrogenism (คลินิก/ชีวเคมี), polycystic ovaries (US ≥12 follicles/volume >10 mL). [อัปเดต] 2023 ยอมใช้ AMH สูงแทน US ในผู้ใหญ่. ต้องแยกสาเหตุอื่นก่อน."}, {"topic": "Gynecology", "q": "Which long-term risk is associated with polycystic ovary syndrome?", "choices": ["Cervical cancer", "Ovarian germ cell tumor", "Thalassemia", "Endometrial hyperplasia and cancer", "Congenital heart disease"], "ans": 3, "exp": "PCOS สัมพันธ์ insulin resistance → DM2, metabolic syndrome. Chronic anovulation → unopposed estrogen → endometrial hyperplasia/มะเร็งเยื่อบุโพรงมดลูก. จึงควรคุมรอบเดือน (progestin/OC) ป้องกัน."}, {"topic": "Gynecology", "q": "What is the first-line ovulation induction agent for a woman with PCOS who desires pregnancy?", "choices": ["Clomiphene citrate", "Metformin", "Gonadotropin", "GnRH agonist", "Letrozole"], "ans": 4, "exp": "[อัปเดต] Letrozole (aromatase inhibitor) เป็นตัวเลือกแรกใน ovulation induction ใน PCOS (อัตราคลอดมีชีพสูงกว่า clomiphene). ลดน้ำหนักเป็นการรักษาพื้นฐานสำคัญ."}, {"topic": "Gynecology", "q": "In the PALM-COEIN classification of abnormal uterine bleeding, what does 'PALM' represent?", "choices": ["Structural causes", "Non-structural causes", "Coagulation disorders", "Malignancy only", "Ovulatory dysfunction"], "ans": 0, "exp": "PALM = structural causes (Polyp, Adenomyosis, Leiomyoma, Malignancy/hyperplasia) ตรวจด้วย imaging/histology. COEIN = non-structural (Coagulopathy, Ovulatory dysfunction, Endometrial, Iatrogenic, Not classified)."}, {"topic": "Gynecology", "q": "A 14-year-old has had heavy menstrual bleeding since menarche. What are the most likely causes?", "choices": ["Endometrial carcinoma", "Anovulation or coagulopathy", "Endometrial polyp", "Uterine fibroids", "Pregnancy"], "ans": 1, "exp": "AUB วัยรุ่นมักจาก anovulatory cycle (HPO axis ยังไม่สมบูรณ์) → unopposed estrogen → heavy/irregular bleeding. เลือดออกมากตั้งแต่ menarche ควรคัดกรอง bleeding disorder (von Willebrand พบบ่อยสุด)."}, {"topic": "Gynecology", "q": "A 58-year-old postmenopausal woman has vaginal bleeding. What must be excluded first, and how?", "choices": ["Atrophic vaginitis by cream trial", "Fibroid by surgery", "Endometrial cancer by biopsy/TVS", "Pregnancy by hCG", "UTI by urinalysis"], "ans": 2, "exp": "Postmenopausal bleeding ต้องแยกมะเร็งเยื่อบุโพรงมดลูกก่อนเสมอ (แม้สาเหตุบ่อยสุดจริงคือ atrophy). ประเมินด้วย TVS (endometrial thickness >4 mm → ตรวจต่อ) และ/หรือ endometrial biopsy (gold standard)."}, {"topic": "Gynecology", "q": "In a postmenopausal woman with bleeding, what endometrial thickness on ultrasound warrants further evaluation?", "choices": ["Over 10 mm", "Over 15 mm", "Over 20 mm", "Over 4 mm", "Any thickness"], "ans": 3, "exp": "Postmenopausal bleeding + endometrial thickness (TVS) >4 mm → ควรตรวจเพิ่ม (biopsy/hysteroscopy) เพราะเสี่ยงมะเร็ง/hyperplasia. ≤4 mm ความเสี่ยงต่ำมาก. ถ้าเลือดออกซ้ำแม้ endometrium บางก็ควรตรวจชิ้นเนื้อ."}, {"topic": "Gynecology", "q": "What is the mechanism and first-line treatment of primary dysmenorrhea?", "choices": ["Endometriosis, treated surgically", "Infection, treated with antibiotics", "Fibroid, treated by myomectomy", "Adenomyosis, treated by hysterectomy", "Excess prostaglandins, treated with NSAIDs"], "ans": 4, "exp": "Primary dysmenorrhea (ไม่มีพยาธิสภาพ) เกิดจาก prostaglandin สูง → uterine hypercontractility/ischemia. รักษาด้วย NSAIDs (ยับยั้ง prostaglandin) และ/หรือ combined OC. ต่างจาก secondary (มีพยาธิสภาพ)."}, {"topic": "Gynecology", "q": "A woman has dysmenorrhea, dyspareunia, dyschezia, and infertility. What is the most likely diagnosis?", "choices": ["Endometriosis", "Polycystic ovary syndrome", "Uterine fibroids", "Pelvic inflammatory disease", "Adenomyosis"], "ans": 0, "exp": "Endometriosis มีอาการ '3D': Dysmenorrhea, Dyspareunia, Dyschezia + infertility. ตำแหน่งพบบ่อย: รังไข่ (endometrioma/chocolate cyst), cul-de-sac, uterosacral ligament."}, {"topic": "Gynecology", "q": "What is the gold standard for diagnosing endometriosis?", "choices": ["Ultrasound", "Laparoscopy", "Serum CA-125", "MRI", "Pelvic examination"], "ans": 1, "exp": "Laparoscopy เป็น gold standard (เห็นรอยโรค: powder-burn lesions, endometrioma, adhesions ± histology). US พบ endometrioma แต่ไม่เห็น peritoneal implants. CA-125 ไม่จำเพาะ. ปัจจุบันเริ่มรักษา empirically ได้."}, {"topic": "Gynecology", "q": "What is the goal of medical therapy for endometriosis?", "choices": ["Increase estrogen levels", "Increase ovulation", "Create a hypoestrogenic state", "Give antibiotics", "Increase prostaglandins"], "ans": 2, "exp": "Endometriosis เป็น estrogen-dependent → รักษาด้วยยาที่ลด estrogen: OC, progestin (dienogest, LNG-IUS), GnRH agonist/antagonist (hypoestrogenic - ระวังกระดูก, ใช้ add-back), NSAIDs. ดื้อยา/มีบุตรยาก → ผ่าตัด."}, {"topic": "Gynecology", "q": "A 42-year-old multipara has a symmetrically enlarged, soft, tender uterus with menorrhagia and worsening dysmenorrhea. What is the diagnosis?", "choices": ["Uterine fibroid", "Endometrial polyp", "Ovarian cyst", "Adenomyosis", "Cervical cancer"], "ans": 3, "exp": "Adenomyosis = เยื่อบุโพรงมดลูกในชั้นกล้ามเนื้อ → มดลูกโตสมมาตร นุ่ม กดเจ็บ (globular/boggy), menorrhagia + dysmenorrhea. วินิจฉัย US/MRI (junctional zone หนา). รักษาชัดเจน = hysterectomy."}, {"topic": "Gynecology", "q": "A woman has severe premenstrual mood symptoms confined to the luteal phase. Which treatment is effective?", "choices": ["Antibiotics", "Analgesics alone", "Thyroid hormone alone", "Sleeping pills alone", "SSRIs and/or combined OC"], "ans": 4, "exp": "PMDD (อาการทางอารมณ์รุนแรงในระยะ luteal) รักษาด้วย SSRIs (fluoxetine/sertraline - ต่อเนื่องหรือเฉพาะ luteal) และ combined OC (โดยเฉพาะ drospirenone). ร่วมกับปรับพฤติกรรม."}, {"topic": "Gynecology", "q": "How is menopause defined?", "choices": ["Amenorrhea for 12 months", "Irregular menstrual cycles", "Age 45 or older", "Low FSH", "Reduced menstrual flow"], "ans": 0, "exp": "Menopause = ขาดประจำเดือนต่อเนื่อง ≥12 เดือน (วินิจฉัยย้อนหลัง) จากรังไข่หยุดทำงาน (estrogen ต่ำ, FSH สูง). อายุเฉลี่ย ~51 ปี. ก่อน 40 ปี = premature ovarian insufficiency."}, {"topic": "Gynecology", "q": "Which symptoms comprise the genitourinary syndrome of menopause?", "choices": ["Hot flashes and night sweats", "Vaginal dryness, dyspareunia, dysuria", "Headache and dizziness", "Heavy menstrual bleeding", "Acne and hirsutism"], "ans": 1, "exp": "GSM (เดิม vulvovaginal atrophy) จาก estrogen ต่ำ: ช่องคลอดแห้ง แสบ คัน, dyspareunia, ปัสสาวะบ่อย/แสบขัด/ติดเชื้อซ้ำ. รักษาดีด้วย low-dose vaginal estrogen หรือ moisturizer/lubricant."}, {"topic": "Gynecology", "q": "According to the NAMS 2022 position statement, hormone therapy has a favorable benefit-risk ratio in which group?", "choices": ["Any age regardless of health", "A history of breast cancer", "Under 60 or within 10 years of menopause", "Over 65 years of age", "A history of prior VTE"], "ans": 2, "exp": "[อัปเดต NAMS 2022] HT มี benefit-risk ดีในหญิงอายุ <60 ปี หรือภายใน 10 ปีหลัง menopause ที่ไม่มีข้อห้าม ('timing hypothesis'). เริ่มช้า (>60/>10 ปี) เสี่ยง CHD, stroke, VTE, dementia เพิ่ม."}, {"topic": "Gynecology", "q": "A woman with an intact uterus receives estrogen therapy. What must be added to prevent endometrial cancer?", "choices": ["Nothing additional", "Testosterone", "Calcium only", "A progestogen", "Aspirin"], "ans": 3, "exp": "หญิงมีมดลูกใช้ systemic estrogen ต้องได้ progestogen ร่วม (combined HT) เพราะ unopposed estrogen → endometrial hyperplasia/มะเร็ง. ตัดมดลูกแล้วใช้ estrogen เดี่ยวได้. LNG-IUS เป็นทางเลือกให้ progestin."}, {"topic": "Gynecology", "q": "A postmenopausal woman has only genitourinary symptoms (vaginal dryness, dyspareunia). What is the most appropriate treatment?", "choices": ["High-dose systemic estrogen", "Pelvic surgery", "SSRIs", "Bisphosphonate", "Low-dose vaginal estrogen"], "ans": 4, "exp": "GSM อย่างเดียว (ไม่มี vasomotor) → low-dose vaginal estrogen (ออกฤทธิ์เฉพาะที่ ดูดซึมน้อย ปลอดภัย ไม่ต้องเพิ่ม progestogen). ไม่ต้องใช้ systemic HT. ทางเลือก: vaginal moisturizer/lubricant."}, {"topic": "Gynecology", "q": "Which is a contraindication to menopausal hormone therapy?", "choices": ["History of breast cancer", "Age of 52 years alone", "Hot flashes", "Osteoporosis", "Vaginal dryness alone"], "ans": 0, "exp": "ข้อห้าม HT: มะเร็งเต้านม/estrogen-dependent cancer, VTE/PE, stroke/CHD, เลือดออกทางช่องคลอดไม่ทราบสาเหตุ, active liver disease, ตั้งครรภ์. ประเมิน benefit-risk รายบุคคล ใช้ขนาดต่ำสุดระยะสั้นสุด."}, {"topic": "Gynecology", "q": "Which newer non-hormonal agent (2023) treats vasomotor symptoms of menopause?", "choices": ["Bisphosphonate", "Fezolinetant", "Metformin", "Raloxifene", "Calcium supplement"], "ans": 1, "exp": "[อัปเดต] Fezolinetant (NK3 receptor antagonist, FDA 2023) รักษา moderate-severe vasomotor symptoms โดยไม่ใช้ฮอร์โมน — ออกฤทธิ์ที่ hypothalamic thermoregulatory center (KNDy neurons). เหมาะกับผู้มีข้อห้าม HT. ทางเลือกอื่น: SSRI/SNRI, gabapentin."}, {"topic": "Gynecology", "q": "A 35-year-old with amenorrhea for 8 months has high FSH, low estrogen, and hot flashes. What is the diagnosis?", "choices": ["Polycystic ovary syndrome", "Hyperprolactinemia", "Premature ovarian insufficiency", "Hypothalamic amenorrhea", "Asherman syndrome"], "ans": 2, "exp": "Premature ovarian insufficiency (POI) = รังไข่หยุดทำงานก่อน 40 ปี: amenorrhea + FSH สูง (hypergonadotropic) + estrogen ต่ำ + อาการขาด estrogen. สาเหตุ: idiopathic, Turner, fragile X, autoimmune, เคมี/รังสี. ให้ HT จนถึงวัยหมดประจำเดือนปกติ."}, {"topic": "Gynecology", "q": "A thin athlete training intensely has amenorrhea with low FSH, low LH, and low estrogen. What is the diagnosis?", "choices": ["Polycystic ovary syndrome", "Premature ovarian insufficiency", "Prolactinoma", "Functional hypothalamic amenorrhea", "Turner syndrome"], "ans": 3, "exp": "Functional hypothalamic amenorrhea (FHA): พลังงานไม่พอ (น้ำหนักลด/ออกกำลังหนัก/เครียด) → กด GnRH → LH/FSH ต่ำ (hypogonadotropic) → estrogen ต่ำ, anovulation. ส่วนหนึ่งของ female athlete triad. รักษาโดยแก้พลังงาน/พฤติกรรม."}, {"topic": "Gynecology", "q": "A woman with galactorrhea and amenorrhea has a high prolactin level. What is the next investigation?", "choices": ["Serum testosterone level", "Hysteroscopy", "Serum FSH level", "Pelvic ultrasound", "Pituitary MRI"], "ans": 4, "exp": "Hyperprolactinemia → galactorrhea + amenorrhea (prolactin กด GnRH). แยกสาเหตุ: prolactinoma (MRI pituitary), ยา, hypothyroidism (TSH), การตั้งครรภ์. รักษา prolactinoma ด้วย dopamine agonist (cabergoline/bromocriptine)."}, {"topic": "Gynecology", "q": "A woman develops amenorrhea and light menses after a postpartum dilation and curettage. Progestin challenge yields no bleeding despite normal estrogen. What is the diagnosis?", "choices": ["Asherman syndrome", "Premature ovarian insufficiency", "Prolactinoma", "Polycystic ovary syndrome", "Hypothalamic amenorrhea"], "ans": 0, "exp": "Asherman syndrome = พังผืดในโพรงมดลูก (intrauterine adhesions) มักหลังขูดมดลูก/ติดเชื้อ → endometrium ถูกทำลาย ประจำเดือนน้อย/ขาด (outflow/endometrial), มีบุตรยาก, แท้งซ้ำ. วินิจฉัย/รักษาด้วย hysteroscopy. Progestin challenge จะไม่มีเลือดออก."}, {"topic": "Gynecology", "q": "A woman develops rapid, severe hirsutism with a deepening voice and clitoromegaly. What should be suspected?", "choices": ["Simple PCOS", "Androgen-secreting tumor", "Idiopathic hirsutism", "Hypothyroidism", "Menopause"], "ans": 1, "exp": "Virilization เกิดเร็วและรุนแรง (hirsutism + clitoromegaly + เสียงห้าว + amenorrhea) บ่งชี้ androgen สูงมากจาก androgen-secreting tumor (ovarian - Sertoli-Leydig, adrenal). ตรวจ testosterone (>150-200), DHEAS, imaging. ต่างจาก PCOS ที่ค่อยเป็นค่อยไป."}, {"topic": "Gynecology", "q": "A 45-year-old with chronic menorrhagia has an enlarged, irregular uterus and fibroids on ultrasound. What is the definitive treatment?", "choices": ["Iron supplementation alone", "Antibiotic therapy", "Hysterectomy", "Watchful waiting", "Chemotherapy"], "ans": 2, "exp": "Leiomyoma ที่มีอาการ: definitive treatment คือ hysterectomy (ผู้ไม่ต้องการมีบุตร) หรือ myomectomy (เก็บมดลูก). ทางเลือก medical: LNG-IUS, tranexamic acid, GnRH agonist, UAE. เลือกตามอาการ/ขนาด/ความต้องการมีบุตร."}, {"topic": "Gynecology", "q": "Which type of fibroid causes the most bleeding and is most associated with infertility?", "choices": ["Subserosal", "Intramural", "Cervical", "Submucosal", "Pedunculated subserosal"], "ans": 3, "exp": "Submucosal fibroid (ยื่นเข้าโพรงมดลูก) รบกวน endometrium มากสุด → menorrhagia รุนแรงและรบกวนการฝังตัว (infertility/แท้ง). รักษาด้วย hysteroscopic myomectomy. Intramural พบบ่อยสุด; subserosal ทำให้อาการกดเบียด."}, {"topic": "Gynecology", "q": "A 28-year-old with a 4 cm simple ovarian cyst and no symptoms is evaluated. What is the appropriate management?", "choices": ["Immediate surgery", "Chemotherapy", "CA-125 then surgery", "Hysterectomy", "Follow-up ultrasound"], "ans": 4, "exp": "Simple cyst เล็ก (<5-7 cm) ในวัยเจริญพันธุ์ที่ไม่มีอาการ มักเป็น functional cyst (หายเอง) → ติดตามด้วย US ซ้ำใน 6-12 สัปดาห์. ลักษณะน่ากังวล (solid, septation, ascites, ใหญ่, CA-125 สูงในวัยหมดประจำเดือน) จึงผ่าตัด."}, {"topic": "Gynecology", "q": "A benign ovarian tumor containing hair, teeth, and sebaceous material describes which lesion?", "choices": ["Mature cystic teratoma", "Serous cystadenoma", "Endometrioma", "Corpus luteum cyst", "Ovarian fibroma"], "ans": 0, "exp": "Mature cystic teratoma (dermoid cyst) = germ cell tumor ไม่ร้ายที่พบบ่อยในวัยเจริญพันธุ์ ประกอบด้วยเนื้อเยื่อจาก 3 germ layers (ผม ฟัน ไขมัน). เสี่ยง torsion. รักษา cystectomy. ต่างจาก immature teratoma (มะเร็ง)."}, {"topic": "Gynecology", "q": "A 25-year-old has acute severe pelvic pain, nausea, an adnexal mass, and reduced ovarian Doppler flow. What is the diagnosis and management?", "choices": ["PID, give antibiotics", "Ovarian torsion, urgent surgery", "Ectopic, give methotrexate", "Ruptured cyst, observe", "Appendicitis, appendectomy"], "ans": 1, "exp": "Ovarian torsion (รังไข่บิดขั้ว): ปวดเฉียบพลันรุนแรงเป็นพักๆ + คลื่นไส้ + adnexal mass, Doppler ลดลง (ปกติไม่ตัดออก). ฉุกเฉิน → ผ่าตัดด่วน (laparoscopy) คลายการบิด (detorsion) + cystectomy. ยิ่งช้ารังไข่ยิ่งตาย."}, {"topic": "Gynecology", "q": "How is the risk of malignancy in an adnexal mass assessed?", "choices": ["Patient age alone", "Blood pressure readings alone", "Age, ultrasound features, CA-125", "Body weight and BMI", "Serum FSH level only"], "ans": 2, "exp": "ประเมิน adnexal mass ด้วยหลายปัจจัย: อายุ/สถานะประจำเดือน, ลักษณะ US (solid, thick septation, papillary, ascites), และ CA-125. เครื่องมือช่วย RMI, IOTA rules เพื่อตัดสินใจส่งต่อ gyn-oncologist."}, {"topic": "Gynecology", "q": "A 15-year-old with cyclic lower abdominal pain has never menstruated; exam shows a bulging bluish membrane at the introitus. What is the diagnosis?", "choices": ["Müllerian agenesis", "Polycystic ovary syndrome", "Ovarian tumor", "Imperforate hymen", "Ectopic pregnancy"], "ans": 3, "exp": "Imperforate hymen: เยื่อพรหมจารีปิดสนิท → เลือดประจำเดือนคั่ง (hematocolpos) → ปวดเป็นรอบ (cyclic) โดยไม่มีประจำเดือนออก, เยื่อโป่งสีน้ำเงิน. รักษาด้วย hymenotomy. เป็น outflow obstruction ที่ลักษณะทางเพศปกติ."}, {"topic": "Gynecology", "q": "A 14-year-old with short stature, a webbed neck, and no secondary sexual characteristics has a 45,X karyotype. What is the diagnosis?", "choices": ["Klinefelter syndrome", "Down syndrome", "Müllerian agenesis", "Androgen insensitivity", "Turner syndrome"], "ans": 4, "exp": "Turner syndrome (45,X): ตัวเตี้ย, webbed neck, streak gonads (gonadal dysgenesis) → primary amenorrhea + ไม่มีลักษณะทางเพศ (FSH สูง). สัมพันธ์ coarctation, bicuspid aortic valve, horseshoe kidney. รักษา: GH + estrogen replacement."}, {"topic": "Gynecology", "q": "Delayed puberty in a girl is defined as the absence of breast development by what age?", "choices": ["Thirteen years", "Eleven years", "Fifteen years", "Sixteen years", "Eighteen years"], "ans": 0, "exp": "Delayed puberty หญิง = ไม่มี thelarche เมื่ออายุ 13 ปี หรือไม่มี menarche เมื่อ 15 ปี. ประเมิน FSH/LH: สูง = gonadal (Turner, POI); ต่ำ = hypothalamic-pituitary (constitutional delay, Kallmann, eating disorder)."}, {"topic": "Gynecology", "q": "Which condition combines hypogonadotropic hypogonadism with an impaired sense of smell?", "choices": ["Cushing syndrome", "Kallmann syndrome", "Turner syndrome", "Polycystic ovary syndrome", "Sheehan syndrome"], "ans": 1, "exp": "Kallmann syndrome = isolated GnRH deficiency (hypogonadotropic hypogonadism, LH/FSH ต่ำ) + anosmia/hyposmia (ความล้มเหลวของการเคลื่อน GnRH/olfactory neurons) → delayed puberty/primary amenorrhea. รักษาด้วยฮอร์โมนทดแทน/gonadotropin."}, {"topic": "Gynecology", "q": "A 30-year-old with acute heavy uterine bleeding causing anemia, no pregnancy, and no structural lesion is treated with which first-line therapy?", "choices": ["Immediate hysterectomy", "Iron supplements alone", "High-dose estrogen or combined OC", "Watchful waiting", "Long-term GnRH agonist"], "ans": 2, "exp": "Acute AUB (ovulatory dysfunction) ไม่มี structural cause → hormonal: high-dose estrogen หรือ combined OC (taper) + tranexamic acid. ประเมิน hemodynamic/ให้เลือดถ้าจำเป็น. ผ่าตัด (D&C) เมื่อไม่ตอบสนองยา."}, {"topic": "Gynecology", "q": "Which option best manages chronic heavy menstrual bleeding while also providing contraception?", "choices": ["Tranexamic acid during menses", "Lifelong GnRH agonist", "NSAIDs", "Levonorgestrel intrauterine system", "Hysterectomy only"], "ans": 3, "exp": "LNG-IUS เป็นทางเลือกแรกที่ดีสำหรับ chronic heavy menstrual bleeding — ลดเลือด >80-90%, คุมกำเนิด, ป้องกัน endometrial hyperplasia. ทางเลือกอื่น: combined OC, progestin, TXA, NSAIDs, ablation, hysterectomy."}, {"topic": "Gynecology", "q": "A postmenopausal woman is assessed for osteoporosis prevention. Which approach is recommended?", "choices": ["No evaluation needed", "Antibiotics", "High-dose estrogen for all", "Surgery", "DXA, calcium/vitamin D, exercise"], "ans": 4, "exp": "Estrogen ที่ลดหลังหมดประจำเดือนเร่งการสูญเสียมวลกระดูก. แนะนำ: ตรวจ BMD (DXA), calcium/vitamin D, weight-bearing exercise, เลิกบุหรี่. ยา: bisphosphonate (first-line), denosumab, SERM, และ HT ในกลุ่มที่มีข้อบ่งชี้."}, {"topic": "Gynecology", "q": "A woman has gradual hirsutism, oligomenorrhea, and an elevated 17-hydroxyprogesterone. What is the diagnosis?", "choices": ["Non-classic congenital adrenal hyperplasia", "Polycystic ovary syndrome", "Idiopathic hirsutism", "An androgen-secreting tumor", "Cushing syndrome"], "ans": 0, "exp": "Non-classic CAH (21-hydroxylase deficiency) เลียนแบบ PCOS แต่แยกด้วย 17-OHP สูง (โดยเฉพาะหลัง ACTH stimulation). ขาดเอนไซม์บางส่วน → สร้าง androgen เกิน. รักษา glucocorticoid ± OC/antiandrogen. ควรตรวจ 17-OHP เมื่อประเมิน hyperandrogenism."}, {"topic": "Gynecology", "q": "Which antiandrogen is used adjunctively to treat hirsutism?", "choices": ["Progesterone", "Spironolactone", "Metformin", "Levothyroxine", "Clomiphene"], "ans": 1, "exp": "Spironolactone (antiandrogen - บล็อก androgen receptor และลดการสร้าง androgen) ใช้รักษา hirsutism ร่วมกับ combined OC. ต้องคุมกำเนิดร่วม (teratogenic). ผลเห็นช้า ~6 เดือน. combined OC เพิ่ม SHBG ลด free androgen."}, {"topic": "Gynecology", "q": "A 48-year-old has increasingly spaced menses, hot flashes, insomnia, and mood swings. What stage is she in?", "choices": ["Menopause", "Premature ovarian insufficiency", "Perimenopause", "Reproductive age", "Postmenopause"], "ans": 2, "exp": "Perimenopause (menopausal transition): รอบเดือนแปรปรวน (ห่างขึ้น/ข้ามรอบ), FSH ผันผวน, เริ่มมีอาการ vasomotor. ยังตกไข่/ตั้งครรภ์ได้ (ต้องคุมกำเนิด). Menopause = หลังขาดประจำเดือน 12 เดือนเต็ม."}, {"topic": "Gynecology", "q": "Menstruation occurs due to a fall in which hormone?", "choices": ["Estrogen rising", "FSH falling", "LH surging", "Progesterone falling", "hCG rising"], "ans": 3, "exp": "ไม่ตั้งครรภ์ → corpus luteum ฝ่อ (luteolysis) → progesterone และ estrogen ลดลง → spiral arteries หดตัว, endometrium ขาดเลือดหลุดลอกเป็นประจำเดือน. การลด progesterone ยังปลด negative feedback → FSH เพิ่มเริ่มรอบใหม่."}, {"topic": "Gynecology", "q": "The follicular phase of the menstrual cycle is dominated by which hormone?", "choices": ["Progesterone", "Testosterone", "hCG", "Inhibin A", "Estrogen"], "ans": 4, "exp": "Follicular phase: FSH กระตุ้น follicle สร้าง estrogen (estradiol) เพิ่ม → กระตุ้น endometrium proliferate. Estrogen สูงปลาย follicular กระตุ้น LH surge. Dominant follicle ถูกเลือกจากมี FSH receptor มากสุด."}, {"topic": "Gynecology", "q": "How can ovulation be confirmed in a woman being evaluated for infertility?", "choices": ["Mid-luteal serum progesterone", "Early-cycle serum FSH", "Early-cycle serum LH", "Day-3 serum estradiol", "Serum TSH level"], "ans": 0, "exp": "Mid-luteal (วันที่ ~21 ในรอบ 28 วัน) serum progesterone สูง (>3 ng/mL) ยืนยันการตกไข่. วิธีอื่น: LH surge (OPK), BBT เพิ่ม, US ติดตาม follicle. ใช้ประเมิน ovulatory function."}, {"topic": "Gynecology", "q": "A 25-year-old has an ovarian mass with a homogeneous 'ground-glass' appearance and severe dysmenorrhea. What is the likely diagnosis?", "choices": ["Dermoid cyst", "Endometrioma", "Serous cystadenoma", "Corpus luteum cyst", "Hydrosalpinx"], "ans": 1, "exp": "Endometrioma (chocolate cyst) มี US เป็น cyst ที่มี homogeneous low-level internal echoes ('ground-glass') จากเลือดเก่า. สัมพันธ์ endometriosis (dysmenorrhea, dyspareunia, infertility). ต่างจาก dermoid (echogenic) และ simple cyst (anechoic)."}, {"topic": "Gynecology", "q": "What is a key limitation of CA-125 in reproductive-age women?", "choices": ["It is 100% specific", "It is always low in cancer", "It rises in many benign conditions", "It is never elevated in benign disease", "It screens the general population"], "ans": 2, "exp": "CA-125 ไม่จำเพาะ — สูงได้ในภาวะไม่ร้าย (endometriosis, PID, fibroid, adenomyosis, ประจำเดือน, ตั้งครรภ์). จึงไม่เหมาะคัดกรองมะเร็งรังไข่ในคนทั่วไป. มีประโยชน์มากกว่าในวัยหมดประจำเดือนและติดตามการรักษามะเร็งรังไข่."}, {"topic": "Gynecology", "q": "What is Mittelschmerz?", "choices": ["Menstrual cramping", "Postcoital bleeding", "Postmenopausal pain", "Mid-cycle ovulation pain", "Premenstrual symptoms"], "ans": 3, "exp": "Mittelschmerz = ปวดท้องน้อยข้างเดียวช่วงกลางรอบเดือน (ตกไข่) จาก follicle แตกและมีของเหลว/เลือดระคายเยื่อบุช่องท้อง. ไม่อันตราย หายเองใน 1-2 วัน. แยกจากสาเหตุปวดเฉียบพลันอื่น (torsion, appendicitis, ectopic)."}, {"topic": "Gynecology", "q": "How does adenomyosis differ from leiomyoma on physical examination?", "choices": ["Adenomyosis gives an irregular hard uterus", "They are identical", "Fibroids give a soft uterus", "Adenomyosis does not enlarge the uterus", "Adenomyosis gives a symmetric, soft, tender uterus"], "ans": 4, "exp": "Adenomyosis: มดลูกโตสมมาตร (globular) นุ่ม (boggy) กดเจ็บ (โดยเฉพาะช่วงมีประจำเดือน). Leiomyoma: มดลูกโตไม่สมมาตร เป็นก้อนแข็ง (nodular). ทั้งคู่ menorrhagia แต่ adenomyosis dysmenorrhea เด่นกว่า."}, {"topic": "Gynecology", "q": "A 22-year-old with irregular menses, acne, hirsutism, and overweight has polycystic ovaries. What is the most important baseline management?", "choices": ["Lifestyle modification", "Antibiotics", "GnRH agonist", "Ovarian surgery", "Hysterectomy"], "ans": 0, "exp": "การรักษาพื้นฐานของ PCOS คือ lifestyle modification (ลดน้ำหนัก 5-10%, อาหาร, ออกกำลังกาย) ช่วยฟื้นการตกไข่ ลด androgen ปรับ insulin resistance. เสริมด้วย combined OC, metformin, letrozole (มีบุตร)."}, {"topic": "Gynecology", "q": "A woman with recurrent pregnancy loss should be evaluated for which of the following?", "choices": ["Serum CA-125 level", "Antiphospholipid antibodies and uterine cavity", "Serum prolactin level", "Fetal karyotype alone", "No evaluation is needed"], "ans": 1, "exp": "ประเมิน recurrent pregnancy loss: antiphospholipid antibodies (รักษาได้), TSH/prolactin, ควบคุมเบาหวาน, ประเมินโพรงมดลูก (septate - US 3D/hysteroscopy/HSG), parental karyotype. ~50% ไม่พบสาเหตุ."}, {"topic": "Gynecology", "q": "A woman has dysmenorrhea beginning after age 25 that progressively worsens with dyspareunia. What should be suspected?", "choices": ["Primary dysmenorrhea", "Normal menstruation", "Secondary dysmenorrhea", "Pregnancy", "Polycystic ovary syndrome"], "ans": 2, "exp": "Dysmenorrhea ที่เริ่มช้า (หลังวัยรุ่น) รุนแรงขึ้นเรื่อยๆ + อาการอื่น (dyspareunia, dyschezia, menorrhagia) บ่งชี้ secondary dysmenorrhea จากพยาธิสภาพ (endometriosis, adenomyosis, fibroid, PID). ต่างจาก primary (เริ่มตั้งแต่ menarche)."}, {"topic": "Gynecology", "q": "A 30-year-old with a prolactinoma causing amenorrhea is treated with which first-line therapy?", "choices": ["Immediate surgery", "Radiation therapy", "Estrogen therapy", "Dopamine agonist", "Observation"], "ans": 3, "exp": "Prolactinoma (แม้ macroadenoma) รักษาด้วย dopamine agonist (cabergoline ตัวแรก) — ลดขนาดก้อนและ prolactin, ฟื้นการตกไข่/ประจำเดือน. ผ่าตัด (transsphenoidal) เมื่อดื้อยา, ทนยาไม่ได้, หรือมีการกดเบียด (visual field defect)."}, {"topic": "Gynecology", "q": "What is the mechanism of hot flashes (vasomotor symptoms) in menopause?", "choices": ["An excess of circulating estrogen", "Underlying thyrotoxicosis", "An elevated prolactin level", "Recurrent hypoglycemia", "Estrogen deficiency affecting thermoregulation"], "ans": 4, "exp": "Hot flashes เกิดจากการขาด estrogen กระทบ hypothalamic thermoregulatory center (KNDy neurons/NK3) → thermoneutral zone แคบลง → vasodilation/เหงื่อออก. HT ได้ผลดีสุด; fezolinetant ออกฤทธิ์ที่ NK3 pathway."}, {"topic": "Gynecology", "q": "A woman has chronic intermenstrual bleeding. What should be specifically evaluated?", "choices": ["Endometrial/cervical polyp, cervix", "No evaluation is needed alone", "Serum TSH level only", "Pregnancy test only", "Bone mineral density"], "ans": 0, "exp": "Intermenstrual bleeding เรื้อรังควรประเมิน structural: endometrial/cervical polyp, พยาธิสภาพปากมดลูก (คัดกรองมะเร็ง/HPV), การติดเชื้อ (cervicitis-chlamydia). Postcoital bleeding เน้นปากมดลูก. ตรวจ β-hCG เสมอในวัยเจริญพันธุ์."}, {"topic": "Gynecology", "q": "A 40-year-old with menorrhagia is found to have an endometrial polyp. What is the appropriate treatment?", "choices": ["Hysterectomy", "Hysteroscopic polypectomy", "Antibiotics", "Observation always", "Chemotherapy"], "ans": 1, "exp": "Endometrial polyp ที่มีอาการ (AUB) รักษาด้วย hysteroscopic polypectomy (วินิจฉัยและรักษา + ส่งชิ้นเนื้อแยก atypia/มะเร็ง โดยเฉพาะวัยหมดประจำเดือน). Polyp เล็กไม่มีอาการอาจติดตามได้."}, {"topic": "Gynecology", "q": "What are the components of the female athlete triad?", "choices": ["Obesity, hypertension, diabetes", "Hirsutism, acne, obesity", "Amenorrhea, osteoporosis, low energy", "Anemia, fatigue, infection", "Galactorrhea, amenorrhea, headache"], "ans": 2, "exp": "Female athlete triad: (1) low energy availability (± eating disorder), (2) menstrual dysfunction (FHA), (3) low bone density/osteoporosis. พลังงานไม่พอ → กด GnRH → hypoestrogenism → กระดูกบาง. รักษาโดยเพิ่มพลังงาน/ลดออกกำลังหนักเกิน."}, {"topic": "Gynecology", "q": "Which test best reflects ovarian reserve in a woman planning pregnancy?", "choices": ["CA-125", "TSH only", "Serum prolactin", "Anti-Müllerian hormone", "Hysterosalpingography"], "ans": 3, "exp": "AMH สร้างจาก granulosa cells ของ small antral follicles สะท้อน ovarian reserve — ลดลงเมื่อเข้าใกล้ menopause. ใช้ประเมินใน infertility/IVF และทำนายเวลาเข้าสู่ menopause. [อัปเดต] ใช้แทน US ในการวินิจฉัย PCOS ในผู้ใหญ่ได้."}, {"topic": "Gynecology", "q": "A 35-year-old with a large fibroid wants to preserve her uterus and shrink it before surgery. Which drug helps?", "choices": ["Clomiphene", "Metformin", "Estrogen", "Antibiotics", "GnRH agonist"], "ans": 4, "exp": "GnRH agonist (leuprolide) สร้างภาวะ hypoestrogenic ชั่วคราว → ลดขนาด fibroid และแก้ anemia ก่อนผ่าตัด. ใช้ระยะสั้น (menopausal symptoms/กระดูกบาง; fibroid โตกลับหลังหยุด). ทางเลือกใหม่: GnRH antagonist, SPRM."}, {"topic": "Gynecology", "q": "A woman has mild premenstrual symptoms that are not disabling. What is the initial management?", "choices": ["Lifestyle modification, monitoring", "SSRIs started immediately", "Total abdominal hysterectomy", "A GnRH agonist course", "Broad-spectrum antibiotics"], "ans": 0, "exp": "PMS เล็กน้อยจัดการด้วย lifestyle: ออกกำลังกาย, ลดคาเฟอีน/เกลือ/แอลกอฮอล์, จัดการความเครียด, calcium/B6. อาการรุนแรง (PMDD) จึงพิจารณา SSRIs หรือ combined OC. บันทึกอาการยืนยันความสัมพันธ์กับ luteal phase."}, {"topic": "Gynecology", "q": "A postmenopausal woman with an intact uterus needs HT for vasomotor symptoms. Which regimen is appropriate?", "choices": ["Estrogen alone", "Estrogen plus progestogen", "Testosterone", "Progestogen alone", "No hormone therapy"], "ans": 1, "exp": "หญิงมีมดลูกต้องใช้ combined (estrogen + progestogen) เพื่อป้องกัน endometrial hyperplasia/cancer. ตัดมดลูกแล้วใช้ estrogen เดี่ยว. Continuous combined ให้ amenorrhea; sequential ให้ withdrawal bleeding (เหมาะ perimenopause)."}, {"topic": "Gynecology", "q": "A woman with prolonged unopposed estrogen exposure is at risk of which endometrial condition?", "choices": ["Simple endometrial atrophy", "Chronic pelvic infection", "Endometrial hyperplasia and cancer", "Endometrial polyp formation", "No increased cancer risk"], "ans": 2, "exp": "Unopposed estrogen → endometrial proliferation ต่อเนื่อง → hyperplasia (โดยเฉพาะ atypical/EIN) → มะเร็งเยื่อบุโพรงมดลูก. กลุ่มเสี่ยง: PCOS/anovulation, obesity, estrogen-only HT (มีมดลูก), tamoxifen, granulosa cell tumor."}, {"topic": "Gynecology", "q": "A woman not desiring future fertility has atypical endometrial hyperplasia (EIN). What is the recommended treatment?", "choices": ["Observation", "Radiation", "Antibiotics", "Total hysterectomy", "Combined OC"], "ans": 3, "exp": "Atypical hyperplasia/EIN เสี่ยงมะเร็งร่วมสูง (~40%) → ผู้ไม่ต้องการเก็บมดลูก แนะนำ total hysterectomy. ต้องการเก็บมดลูก/มีบุตร → high-dose progestin (LNG-IUS/oral) + ติดตามชิ้นเนื้อ. Hyperplasia without atypia รักษาด้วย progestin."}, {"topic": "Gynecology", "q": "How is endometrial hyperplasia without atypia treated?", "choices": ["Immediate hysterectomy in all", "A course of antibiotics", "Adjuvant chemotherapy", "Observation with no treatment", "Progestin therapy and follow-up"], "ans": 4, "exp": "Hyperplasia without atypia เสี่ยงมะเร็งต่ำ (~1-3%) → progestin (oral หรือ LNG-IUS) + แก้ปัจจัยเสี่ยง (ลดน้ำหนัก, หยุด unopposed estrogen) + ติดตามชิ้นเนื้อ. ต่างจาก atypical ที่แนะนำ hysterectomy."}, {"topic": "Gynecology", "q": "A woman has amenorrhea for over 6 months after stopping oral contraceptives. What should be done?", "choices": ["Evaluate as secondary amenorrhea", "Wait indefinitely", "No action needed", "Restart the pill", "Perform surgery"], "ans": 0, "exp": "ประจำเดือนมักกลับใน 3 เดือนหลังหยุดยาคุม. ขาด >3-6 เดือนต้องประเมิน secondary amenorrhea ตามปกติ (แยกการตั้งครรภ์, thyroid, hyperprolactinemia, PCOS ที่ถูกบดบัง, POI). ยาคุมไม่ทำให้มีบุตรยากถาวร."}, {"topic": "Gynecology", "q": "Central (GnRH-dependent) precocious puberty is treated with which agent?", "choices": ["Dopamine agonist", "GnRH agonist", "Estrogen", "Testosterone", "Metformin"], "ans": 1, "exp": "Central precocious puberty รักษาด้วย GnRH agonist (leuprolide) — การให้ต่อเนื่องกด pituitary (downregulation) → หยุดการดำเนินของ puberty และคงความสูงตอนโต. หาสาเหตุด้วย MRI สมอง (แยก CNS lesion โดยเฉพาะเด็กเล็ก/ชาย)."}, {"topic": "Gynecology", "q": "Follicular and corpus luteum cysts are classified as which type of ovarian cyst?", "choices": ["Neoplastic", "Endometriotic alone", "Functional (physiologic)", "Malignant", "Infectious"], "ans": 2, "exp": "Follicular cyst (follicle ไม่แตก) และ corpus luteum cyst (corpus luteum ไม่ฝ่อ) เป็น functional/physiologic cyst — พบบ่อยในวัยเจริญพันธุ์ มักหายเองใน 1-2 รอบเดือน. Corpus luteum cyst อาจแตกทำให้ปวด/เลือดออก. Combined OC ลดการเกิดใหม่."}, {"topic": "Gynecology", "q": "A woman with regular, predictable monthly cycles most likely has which of the following?", "choices": ["Anovulation", "Pregnancy", "Polycystic ovary syndrome", "Ovulatory cycles", "Menopause"], "ans": 3, "exp": "รอบเดือนสม่ำเสมอและคาดเดาได้ มักบ่งชี้ ovulatory cycles (luteal phase คงที่). รอบไม่สม่ำเสมอ/ห่างมาก มักเป็น anovulatory (PCOS). Molimina (อาการก่อนประจำเดือน) สนับสนุนว่ามีการตกไข่."}, {"topic": "Gynecology", "q": "A woman with an endometrioma and infertility is counseled. Which is a reasonable option depending on age and reserve?", "choices": ["Hysterectomy", "Chemotherapy", "Antibiotics", "Observation only", "Cystectomy and/or IVF"], "ans": 4, "exp": "Endometrioma สัมพันธ์ infertility. การจัดการขึ้นกับอาการ/ขนาด/อายุ/ovarian reserve: laparoscopic cystectomy (บรรเทาปวด/ยืนยัน แต่เสี่ยงลด reserve), หรือมุ่งสู่ IVF โดยตรง (โดยเฉพาะ reserve ต่ำ/เคยผ่าตัด). ชั่งน้ำหนักเป็นรายบุคคล."}, {"topic": "Gynecology", "q": "A woman with very high testosterone (>200 ng/dL) and rapid virilization needs which investigation?", "choices": ["Imaging of the ovaries and adrenals", "No further investigation", "Serum TSH alone", "A trial of combined pills", "Diagnostic hysterectomy"], "ans": 0, "exp": "Testosterone สูงมาก + virilization เริ่มเร็ว บ่งชี้ androgen-secreting tumor → imaging: TVS/MRI รังไข่ (Sertoli-Leydig, hilus cell) และ CT/MRI ต่อมหมวกไต (DHEAS สูงมาก = ต่อมหมวกไต). ต่างจาก PCOS."}, {"topic": "Gynecology", "q": "A woman has had heavy menses since her teens with easy bruising and epistaxis. What should be tested?", "choices": ["Serum CA-125 level", "Coagulation and von Willebrand panel", "Serum prolactin level", "Serum TSH alone", "Pelvic ultrasound alone"], "ans": 1, "exp": "Heavy menstrual bleeding ตั้งแต่ menarche + อาการเลือดออกง่ายอื่น (epistaxis, ช้ำง่าย) บ่งชี้ coagulopathy (C ใน PALM-COEIN) โดย von Willebrand disease พบบ่อยสุด → ตรวจ vWF, CBC, PT/aPTT. รักษา: TXA, desmopressin, hormonal."}, {"topic": "Gynecology", "q": "Long-term use of combined oral contraceptives reduces the risk of which cancers?", "choices": ["Breast cancer", "Cervical cancer", "Ovarian and endometrial cancer", "Liver cancer", "Colon cancer"], "ans": 2, "exp": "Combined OC ลดความเสี่ยงมะเร็งรังไข่ (ยับยั้งการตกไข่) และเยื่อบุโพรงมดลูก (progestin ปกป้อง) อย่างมีนัยสำคัญ คงอยู่หลายปีหลังหยุด. (เพิ่ม VTE เล็กน้อย, สัมพันธ์มะเร็งปากมดลูก/เต้านมเล็กน้อยระหว่างใช้ ซึ่งลดหลังหยุด)."}, {"topic": "Gynecology", "q": "A woman needs both contraception and treatment of heavy menses with dysmenorrhea. Which single method addresses both?", "choices": ["A copper intrauterine device", "Partner vasectomy", "Barrier condoms", "Levonorgestrel intrauterine system", "The calendar rhythm method"], "ans": 3, "exp": "LNG-IUS คุมกำเนิดประสิทธิภาพสูง (LARC) + ลดปริมาณประจำเดือน (รักษา HMB) + บรรเทา dysmenorrhea/endometriosis จึงตอบทั้งคุมกำเนิดและรักษา. ต่างจาก copper IUD ที่อาจทำให้ประจำเดือนมากขึ้น."}, {"topic": "Gynecology", "q": "Isolated premature breast development in a young child without other pubertal signs is best described as which condition?", "choices": ["Always precocious puberty alone", "Sign of malignancy", "Cause of early menses", "Requiring surgery", "Usually benign premature thelarche"], "ans": 4, "exp": "Premature thelarche = เต้านมโตเดี่ยวๆ (มัก <2-3 ปี) โดยไม่มีสัญญาณ puberty อื่น (bone age ปกติ) มักไม่อันตราย (self-limited) ติดตามได้. ต่างจาก true precocious puberty (หลายสัญญาณ + bone age เร่ง) ที่ต้องประเมิน/รักษา."}, {"topic": "Gynecology", "q": "A woman under 40 has amenorrhea with FSH confirmed elevated on two occasions. What is the diagnosis?", "choices": ["Premature ovarian insufficiency", "Polycystic ovary syndrome", "Pregnancy", "Hypothalamic amenorrhea", "Prolactinoma"], "ans": 0, "exp": "FSH สูง (menopausal range) ซ้ำ 2 ครั้งห่าง ≥1 เดือน ในหญิง <40 ปีที่ขาดประจำเดือน = POI. หาสาเหตุ (karyotype-Turner, FMR1 premutation, autoimmune) และให้ estrogen replacement จนถึงวัยหมดประจำเดือนปกติ (ป้องกันกระดูก/หัวใจ)."}, {"topic": "Gynecology", "q": "A 48-year-old with abnormal bleeding in perimenopause requires which key assessment?", "choices": ["No assessment is needed", "Endometrial evaluation for cancer", "Immediate hormone therapy", "Immediate surgical treatment", "Serum CA-125 testing"], "ans": 1, "exp": "AUB ในหญิง ≥45 ปี (หรือน้อยกว่าที่มีปัจจัยเสี่ยง: obesity, PCOS, unopposed estrogen, tamoxifen) ต้องประเมิน endometrium (biopsy/TVS) แยก hyperplasia/มะเร็ง — ไม่ควรถือว่าเป็นเพียง perimenopausal change."}, {"topic": "Gynecology", "q": "On pelvic exam, uterosacral nodularity and a fixed, retroverted uterus suggest which condition?", "choices": ["Fibroid", "Polycystic ovary syndrome", "Deep infiltrating endometriosis", "Pregnancy", "Ovarian cyst only"], "ans": 2, "exp": "Uterosacral nodularity/tenderness + fixed retroverted uterus (จากพังผืด) บ่งชี้ deep infiltrating endometriosis ร่วมกับอาการ 3D. Endometrioma อาจคลำได้ที่ปีกมดลูก. ยืนยันด้วย imaging/laparoscopy."}, {"topic": "Gynecology", "q": "A woman with only mild galactorrhea, normal menses, and a normal prolactin level should receive what management?", "choices": ["Transsphenoidal pituitary surgery", "Systemic chemotherapy course", "Total abdominal hysterectomy", "Reassurance after excluding red flags", "A dopamine agonist now"], "ans": 3, "exp": "Galactorrhea ที่ prolactin ปกติ + ประจำเดือนปกติ มักเป็น physiologic/idiopathic ไม่จำเป็นต้องรักษาถ้าไม่มีก้อน/อาการ. แยกน้ำจากเต้าที่มีเลือด/ข้างเดียว (สงสัยพยาธิสภาพเต้านม → imaging). Reassure + ตรวจ TSH."}, {"topic": "Gynecology", "q": "A woman has superficial (entry) dyspareunia. Which cause is common?", "choices": ["Deep pelvic endometriosis", "A uterine fibroid", "Ovarian carcinoma", "Polycystic ovary syndrome", "Vulvovaginal atrophy or vaginismus"], "ans": 4, "exp": "Superficial (entry) dyspareunia มักจากปากช่องคลอด/ช่องคลอดส่วนต้น: vulvovaginal atrophy (GSM), vaginismus, vulvodynia, การติดเชื้อ. ส่วน deep dyspareunia มักจาก endometriosis, PID, adnexal pathology. ซักประวัติแยกตำแหน่ง/timing."}, {"topic": "Gynecology", "q": "A woman wants a reversible, highly effective method to space births. What should be recommended?", "choices": ["A LARC method (implant/IUD)", "Permanent tubal ligation", "Condoms used alone", "Calendar-based awareness", "DMPA injections only"], "ans": 0, "exp": "ผู้ต้องการเว้นระยะและเก็บโอกาสมีบุตร แนะนำ LARC (implant/IUD) — ประสิทธิภาพสูงเทียบเท่าทำหมันแต่กลับคืนได้ (fertility กลับเร็วหลังถอด). ไม่ควรแนะนำ tubal ligation (ถาวร). shared decision-making."}, {"topic": "Gynecology", "q": "A woman with only genitourinary atrophic symptoms in menopause is treated with which agent?", "choices": ["Metronidazole", "Low-dose vaginal estrogen", "Acyclovir", "Fluconazole", "Systemic antibiotics"], "ans": 1, "exp": "Atrophic vaginitis (GSM) จากขาด estrogen — ช่องคลอดแห้ง บาง แดง เจ็บ pH สูง. รักษาด้วย vaginal estrogen ขนาดต่ำ (ได้ผลดีสุด) หรือ moisturizer/lubricant. ไม่ใช่การติดเชื้อจึงไม่ใช้ยาปฏิชีวนะ/ยาต้านเชื้อรา (แต่แยกการติดเชื้อร่วม)."}, {"topic": "Gynecology", "q": "A woman on estrogen-progestogen continuous combined HT experiences which intended effect?", "choices": ["Regular scheduled menses", "No need for progestogen", "No withdrawal bleeding (amenorrhea)", "Increased cancer risk", "Reduced estrogen level"], "ans": 2, "exp": "Continuous combined HT (estrogen + progestogen ทุกวัน) เหมาะกับผู้หมดประจำเดือนแล้ว — เป้าหมายให้ amenorrhea (ไม่มี scheduled bleeding) และปกป้อง endometrium. อาจมี unscheduled spotting ช่วงแรก. Sequential regimen มี withdrawal bleeding (เหมาะ perimenopause)."}, {"topic": "Gynecology", "q": "A 45-year-old wants to know whether she has reached menopause. Which test may help when unclear?", "choices": ["Serum CA-125 level", "Serum TSH level", "Serum prolactin level", "Elevated FSH with low estradiol", "A serum hCG level"], "ans": 3, "exp": "การวินิจฉัย menopause เป็น clinical (ขาดประจำเดือน 12 เดือน). กรณีไม่ชัด (อายุน้อย/ตัดมดลูก) การพบ FSH สูง + estradiol ต่ำสนับสนุน ovarian failure. FSH ในช่วง perimenopause ผันผวนจึงแปลผลระวัง. สงสัย POI (<40) ต้องตรวจ FSH ยืนยัน 2 ครั้ง."}, {"topic": "Gynecology", "q": "A woman with granulosa cell tumor producing estrogen should have which additional assessment?", "choices": ["No assessment is needed", "Routine cervical screening", "HPV testing of cervix", "Serum pregnancy testing", "Endometrial evaluation for hyperplasia"], "ans": 4, "exp": "Granulosa cell tumor สร้าง estrogen → unopposed estrogen เสี่ยง endometrial hyperplasia/มะเร็งร่วม (~5-25%). เมื่อวินิจฉัย (โดยเฉพาะมี abnormal bleeding) ต้องประเมิน endometrium (biopsy). Marker: inhibin/AMH. มักโตช้าและกลับเป็นซ้ำได้."}, {"topic": "Gynecology", "q": "A woman has postcoital bleeding. Which structure should be specifically evaluated?", "choices": ["The cervix", "The ovary", "The thyroid", "The fallopian tube", "The breast"], "ans": 0, "exp": "Postcoital bleeding เน้นประเมินปากมดลูก: มะเร็งปากมดลูก (แยกเสมอ - speculum, Pap/HPV, biopsy), cervicitis (chlamydia/gonorrhea), cervical polyp, ectropion. ควรตรวจภายในและคัดกรองมะเร็งปากมดลูก."}, {"topic": "Gynecology", "q": "A 30-year-old woman has amenorrhea; the pregnancy test is negative, and TSH and prolactin are normal. A progestin challenge gives no bleeding, but an estrogen-progestin challenge produces bleeding. What does this indicate?", "choices": ["An outflow tract obstruction", "A hypothalamic-pituitary-ovarian problem", "Polycystic ovary syndrome", "An ongoing pregnancy", "Asherman syndrome"], "ans": 1, "exp": "Progestin challenge ไม่มีเลือดออก (estrogen ต่ำ หรือ outflow obstruction) แต่ estrogen-progestin challenge มีเลือดออก → outflow/endometrium ปกติ แต่ขาด endogenous estrogen → ปัญหาที่ HPO axis. ตรวจ FSH: สูง = ovarian (POI); ต่ำ/ปกติ = hypothalamic-pituitary."}, {"topic": "Gynecology", "q": "A young woman has isolated Tanner stage IV breast and pubic hair development, cyclic pain, and no menses with a bluish bulging introital membrane. What is the definitive management?", "choices": ["Combined oral contraceptives", "Total abdominal hysterectomy", "Cruciate incision of the hymen", "Dilation and curettage", "Simple needle aspiration"], "ans": 2, "exp": "Imperforate hymen ที่มี hematocolpos รักษาด้วยการผ่าเปิดเยื่อพรหมจารี (hymenotomy/cruciate incision) เพื่อระบายเลือดที่คั่ง — ไม่ใช่การเจาะดูด (aspiration) ซึ่งเสี่ยงติดเชื้อและกลับเป็นซ้ำ. ลักษณะทางเพศปกติ (ต่างจาก MRKH)."}, {"topic": "Gynecology", "q": "A woman has vaginal dryness and dyspareunia in menopause without vasomotor symptoms. Besides vaginal estrogen, what is a non-hormonal option?", "choices": ["Systemic hormone therapy", "Oral antibiotics", "Bisphosphonate therapy", "Vaginal moisturizer or lubricant", "Combined oral contraceptive"], "ans": 3, "exp": "GSM อย่างเดียว ทางเลือก non-hormonal คือ vaginal moisturizer (ใช้สม่ำเสมอ) และ lubricant (ตอนมีเพศสัมพันธ์). ถ้าอาการมากใช้ low-dose vaginal estrogen (ได้ผลดีสุด). ไม่จำเป็นต้อง systemic HT ถ้าไม่มีอาการทั่วร่างกาย."}, {"topic": "Gynecology", "q": "A woman with polycystic ovaries, oligomenorrhea, and hirsutism is being worked up. Before diagnosing PCOS, which conditions must be excluded?", "choices": ["No exclusion is necessary", "Only pregnancy", "Only anemia", "Only osteoporosis", "Thyroid disease, hyperprolactinemia, CAH"], "ans": 4, "exp": "PCOS เป็น diagnosis of exclusion — ต้องแยก thyroid dysfunction (TSH), hyperprolactinemia (prolactin), non-classic CAH (17-OHP), Cushing, androgen-secreting tumor (testosterone/DHEAS สูงมาก + virilization) ก่อนใช้ Rotterdam criteria."}]}, {"id": "obgyn4", "title": "Ob-gyne ชุดที่ 4 — Gynecology II (Infertility, Contraception, STI & PID, Benign Tumors, Prolapse, Breast)", "subject": "obgyn", "questions": [{"topic": "Gynecology", "q": "A 28-year-old woman has not conceived after 12 months of regular unprotected intercourse. How is infertility defined in a woman under 35?", "choices": ["No conception after 12 months", "No conception after 3 months", "One miscarriage", "No conception after 6 months", "Lifelong subfertility"], "ans": 0, "exp": "Infertility = ไม่ตั้งครรภ์หลังมีเพศสัมพันธ์สม่ำเสมอไม่คุมกำเนิด 12 เดือน (อายุ <35) หรือ 6 เดือน (≥35). ควรประเมินเร็วขึ้นถ้ามีปัจจัยเสี่ยง (ประจำเดือนผิดปกติ, PID, endometriosis)."}, {"topic": "Gynecology", "q": "A couple presents for infertility evaluation. Which three domains should be assessed initially?", "choices": ["CBC, LFT, renal panel", "Semen, ovulation, tubal patency", "TSH, prolactin, FSH only", "CA-125, ultrasound, MRI", "Karyotype of both partners"], "ans": 1, "exp": "ประเมิน infertility 3 ด้าน: (1) male factor - semen analysis, (2) ovulation - mid-luteal progesterone, (3) tubal/uterine - HSG. เสริม ovarian reserve (AMH/FSH). Male และ ovulatory เป็นสาเหตุที่พบบ่อย."}, {"topic": "Gynecology", "q": "Which infertility factor is common and should be evaluated early because the test is simple and inexpensive?", "choices": ["Uterine factor", "Cervical factor", "Male factor (semen analysis)", "Immunologic factor", "Psychologic factor"], "ans": 2, "exp": "Male factor เป็นสาเหตุ ~30-40% และตรวจง่าย non-invasive ด้วย semen analysis จึงควรตรวจตั้งแต่ต้น (ก่อนหัตถการ invasive ในฝ่ายหญิง). ประเมิน volume, concentration, motility, morphology."}, {"topic": "Gynecology", "q": "A woman with PCOS and anovulatory infertility desires pregnancy. What is the current first-line ovulation induction agent?", "choices": ["Clomiphene citrate", "Gonadotropin injection", "In vitro fertilization", "Letrozole", "Metformin alone"], "ans": 3, "exp": "[อัปเดต] Letrozole เป็น first-line ovulation induction ใน PCOS (อัตราคลอดมีชีพสูงกว่า clomiphene). ไม่ตอบสนอง → gonadotropin หรือ ovarian drilling หรือ IVF. ลดน้ำหนักเป็นพื้นฐาน."}, {"topic": "Gynecology", "q": "Which assisted reproductive technique is used for severe male factor infertility?", "choices": ["Intrauterine insemination", "Standard in vitro fertilization", "Ovulation induction", "Timed intercourse", "Intracytoplasmic sperm injection"], "ans": 4, "exp": "ICSI (ฉีดอสุจิตัวเดียวเข้าไข่โดยตรง) ใช้ใน severe male factor (oligo/astheno/teratozoospermia รุนแรง, azoospermia ที่ได้อสุจิจาก TESE) หรือ IVF ล้มเหลว fertilization. IUI เหมาะ mild male factor/unexplained."}, {"topic": "Gynecology", "q": "Which contraceptive methods are the most effective (long-acting reversible contraception)?", "choices": ["IUD and contraceptive implant", "Condoms", "Oral contraceptive pills", "Calendar method", "DMPA injection"], "ans": 0, "exp": "LARC = IUD (copper/LNG-IUS) และ implant (etonogestrel) มีประสิทธิภาพสูงสุด (failure <1%) เพราะ user-independent. แนะนำเป็นทางเลือกแรก. Implant มีประสิทธิภาพสูงสุด."}, {"topic": "Gynecology", "q": "Which is a contraindication (MEC category 4) to combined oral contraceptives?", "choices": ["Age of 25 years", "Migraine with aura", "Acne", "Heavy menstrual bleeding", "Polycystic ovary syndrome"], "ans": 1, "exp": "ข้อห้าม combined OC (estrogen): migraine with aura (เสี่ยง stroke), อายุ ≥35 + สูบบุหรี่ ≥15 มวน, ประวัติ VTE/stroke/CHD, มะเร็งเต้านม, ความดันสูงคุมไม่ได้, <21 วันหลังคลอด, โรคตับรุนแรง."}, {"topic": "Gynecology", "q": "A breastfeeding woman wants contraception. Which option is safe and appropriate early postpartum?", "choices": ["Combined OC immediately", "High-dose estrogen", "Progestin-only pill or LARC", "No available options", "Calendar method"], "ans": 2, "exp": "หญิงให้นมควรเลี่ยง estrogen ช่วงแรก (อาจลดน้ำนม + เสี่ยง VTE) → progestin-only pill, DMPA, implant, IUD ปลอดภัย. Combined OC ใช้ได้หลัง ~6 สัปดาห์เมื่อ VTE risk ลดและน้ำนมมั่นคง."}, {"topic": "Gynecology", "q": "Which is the most effective method of emergency contraception?", "choices": ["Levonorgestrel 1.5 mg", "Condom afterward", "Ulipristal acetate", "Copper IUD", "Yuzpe combined pills"], "ans": 3, "exp": "Copper IUD เป็น emergency contraception ที่ได้ผลดีที่สุด (failure <0.1%) ภายใน 5 วัน + คุมกำเนิดต่อระยะยาว. รองลงมา: ulipristal acetate (>levonorgestrel โดยเฉพาะ BMI สูง/ใกล้ตกไข่), levonorgestrel 1.5 mg."}, {"topic": "Gynecology", "q": "By which primary mechanism does the copper IUD prevent pregnancy?", "choices": ["Suppressing ovulation", "Closing the cervix", "Causing uterine contractions", "Lowering estrogen", "A spermicidal inflammatory reaction"], "ans": 4, "exp": "Copper IUD ปล่อยทองแดงสร้าง sterile inflammatory reaction ที่เป็นพิษต่ออสุจิ/ไข่ → ป้องกันการปฏิสนธิ. ไม่ใช้ฮอร์โมน (ไม่ยับยั้งการตกไข่). คุมได้ 10 ปี. ผลข้างเคียง: ประจำเดือนมาก/ปวดมากขึ้น."}, {"topic": "Gynecology", "q": "A woman using DMPA should be counseled about which side effect?", "choices": ["Amenorrhea and delayed fertility return", "Immediate return of fertility", "Increased ovarian cancer risk", "Low blood pressure", "Permanent hair loss"], "ans": 0, "exp": "DMPA (ฉีดทุก 3 เดือน): amenorrhea/irregular bleeding, น้ำหนักเพิ่ม, การกลับมาของ fertility ล่าช้า (~6-12 เดือน), มวลกระดูกลดชั่วคราว (กลับคืนได้). ข้อดี: ไม่มี estrogen, ลด menorrhagia, ป้องกัน endometrial cancer."}, {"topic": "Gynecology", "q": "Which is a method of permanent contraception in a woman?", "choices": ["Vasectomy (male sterilization)", "Tubal ligation or salpingectomy", "DMPA injection", "An intrauterine device", "A contraceptive implant"], "ans": 1, "exp": "การทำหมันถาวรในหญิง = tubal ligation หรือ bilateral salpingectomy (นิยม salpingectomy เพราะลดความเสี่ยงมะเร็งรังไข่ serous). Vasectomy เป็นการทำหมันชาย. ต้องให้คำปรึกษาว่าเป็นวิธีถาวร."}, {"topic": "Gynecology", "q": "A woman has thin, gray, malodorous discharge with a pH above 4.5, a positive whiff test, and clue cells. What is the diagnosis and treatment?", "choices": ["Candidiasis, give fluconazole", "Trichomoniasis, treat the partner", "Bacterial vaginosis, give metronidazole", "Gonorrhea, give ceftriaxone", "Normal discharge, no treatment"], "ans": 2, "exp": "Bacterial vaginosis (Gardnerella): ตกขาวเทา บาง กลิ่นคาว, pH >4.5, whiff test +, clue cells (Amsel ≥3/4). รักษา metronidazole (หรือ clindamycin). ไม่ต้องรักษาคู่. BV ในครรภ์สัมพันธ์ preterm."}, {"topic": "Gynecology", "q": "A woman has thick, white, curd-like discharge with intense itching, normal pH, and pseudohyphae on KOH. What is the diagnosis and treatment?", "choices": ["Bacterial vaginosis, give metronidazole", "Atrophic vaginitis, give estrogen", "Trichomoniasis, give metronidazole", "Vulvovaginal candidiasis, give azole", "Chlamydia, give doxycycline"], "ans": 3, "exp": "Vulvovaginal candidiasis (Candida albicans): ตกขาวขาวข้นคล้าย cottage cheese, คันแดง, pH ปกติ (<4.5), KOH พบ pseudohyphae. รักษา azole (fluconazole oral single dose หรือ topical). ไม่ใช่ STI. เสี่ยง: เบาหวาน, ยาปฏิชีวนะ, ครรภ์."}, {"topic": "Gynecology", "q": "A woman has yellow-green frothy discharge with a pH above 4.5, motile trichomonads, and a strawberry cervix. What is the diagnosis and treatment?", "choices": ["Candidiasis, give fluconazole", "Bacterial vaginosis, give clindamycin", "Gonorrhea, give ceftriaxone", "Normal discharge, no treatment", "Trichomoniasis, treat the partner"], "ans": 4, "exp": "Trichomoniasis (T. vaginalis, STI): ตกขาวเหลืองเขียวเป็นฟอง, pH >4.5, motile flagellates, strawberry cervix. รักษา metronidazole (หรือ tinidazole) + 'รักษาคู่นอน' + งดเพศสัมพันธ์จนหาย. สัมพันธ์ preterm และเพิ่มความเสี่ยง HIV."}, {"topic": "Gynecology", "q": "A 22-year-old has lower abdominal pain, fever, discharge, and cervical motion tenderness. What is the diagnosis and the most common pathogens?", "choices": ["PID from gonorrhea and chlamydia", "UTI from E. coli", "Appendicitis, mixed flora", "Endometriosis, no organism", "Ectopic, no organism"], "ans": 0, "exp": "PID: cervical motion tenderness (chandelier sign) + ปวดท้องน้อย/ไข้/ตกขาว. เชื้อหลัก: N. gonorrhoeae และ C. trachomatis (± anaerobes). รักษา empiric: ceftriaxone + doxycycline + metronidazole. รักษาเร็วป้องกันภาวะแทรกซ้อน (infertility, ectopic)."}, {"topic": "Gynecology", "q": "Which is a long-term complication of pelvic inflammatory disease?", "choices": ["Cervical carcinoma", "Tubal infertility and ectopic pregnancy", "Osteoporosis", "Gestational diabetes", "Preeclampsia"], "ans": 1, "exp": "PID ทำลายท่อนำไข่ (scarring) → tubal factor infertility, ectopic pregnancy, chronic pelvic pain, tubo-ovarian abscess. Fitz-Hugh-Curtis (perihepatitis) เป็นภาวะแทรกซ้อนจากการลามขึ้นตับ."}, {"topic": "Gynecology", "q": "What is Fitz-Hugh-Curtis syndrome?", "choices": ["An ovarian cyst", "Gallstones", "Perihepatitis from PID", "Liver cancer", "Appendicitis"], "ans": 2, "exp": "Fitz-Hugh-Curtis syndrome = perihepatitis จากการลุกลามของเชื้อ PID (chlamydia/gonorrhea) ไปที่แคปซูลตับ → ปวด RUQ + 'violin-string' adhesions. อาการเลียนแบบ cholecystitis. รักษาเหมือน PID."}, {"topic": "Gynecology", "q": "A painless genital ulcer with a firm, indurated base (chancre) is caused by which organism?", "choices": ["Herpes simplex virus", "Human papillomavirus", "Haemophilus ducreyi", "Treponema pallidum", "Candida albicans"], "ans": 3, "exp": "แผล chancre — ไม่เจ็บ ขอบแข็ง ก้นสะอาด ในซิฟิลิสระยะแรก (Treponema pallidum). ต่างจาก HSV (แผลเจ็บเป็นกลุ่ม) และ chancroid (H. ducreyi - เจ็บ ก้นสกปรก). ตรวจ dark-field/serology. รักษา penicillin."}, {"topic": "Gynecology", "q": "Painful grouped vesicles that ulcerate and recur on the genitalia are caused by which organism?", "choices": ["Treponema pallidum", "Human papillomavirus", "Chlamydia trachomatis", "Candida albicans", "Herpes simplex virus"], "ans": 4, "exp": "Genital herpes (HSV-2 ส่วนใหญ่): ตุ่มน้ำเป็นกลุ่มบนฐานแดง แตกเป็นแผลตื้นเจ็บ, ต่อมน้ำเหลืองโต, ไข้ในการติดเชื้อครั้งแรก, และกลับเป็นซ้ำ (latency). รักษา acyclovir/valacyclovir (ไม่หายขาด). Active lesion ตอนคลอด → C/S."}, {"topic": "Gynecology", "q": "Condyloma acuminata (genital warts) are caused by which HPV types?", "choices": ["HPV 6 and 11", "HPV 16 and 18", "HPV 31 and 33", "HPV 45 only", "Herpes simplex virus"], "ans": 0, "exp": "Condyloma acuminata เกิดจาก HPV ความเสี่ยงต่ำ 6 และ 11 (~90%). HPV 16, 18 เป็นชนิดความเสี่ยงสูงก่อมะเร็ง. วัคซีน quadrivalent/9-valent ครอบคลุม 6, 11. รักษาหูด: imiquimod, podophyllin, cryotherapy, ผ่าตัด."}, {"topic": "Gynecology", "q": "A 45-year-old with menorrhagia has multiple fibroids and wants to preserve her uterus. Which option is appropriate?", "choices": ["Total hysterectomy", "Myomectomy or medical therapy", "Pelvic radiotherapy", "Systemic chemotherapy", "No treatment at all"], "ans": 1, "exp": "หญิงต้องการเก็บมดลูก: myomectomy หรือ medical therapy (LNG-IUS, TXA, NSAIDs, GnRH agonist, UAE). Hysterectomy เป็น definitive สำหรับผู้ไม่ต้องการเก็บมดลูก. เลือกตามอาการ/ขนาด/ความต้องการมีบุตร."}, {"topic": "Gynecology", "q": "A young woman has a smooth, well-circumscribed, mobile, non-tender breast lump. What is the most likely diagnosis?", "choices": ["Breast cancer", "Breast abscess", "Fibroadenoma", "Fibrocystic change", "Fat necrosis"], "ans": 2, "exp": "Fibroadenoma — เนื้องอกเต้านมไม่ร้ายที่พบบ่อยในหญิงสาว: ก้อนเรียบ ขอบชัด เคลื่อนที่ได้ ('breast mouse') ไม่เจ็บ. วินิจฉัยด้วย triple assessment. ก้อนเล็กที่ยืนยันแล้วอาจติดตามได้."}, {"topic": "Gynecology", "q": "A woman has cyclical breast pain with lumpiness that varies with her menstrual cycle. What is the most likely diagnosis?", "choices": ["Breast cancer", "Paget disease", "Fibroadenoma", "Fibrocystic change", "Breast abscess"], "ans": 3, "exp": "Fibrocystic change: เจ็บเต้านมเป็นๆ หายๆ สัมพันธ์รอบเดือน, คลำได้ก้อน/ปุ่มหลายจุดสองข้าง, อาจมี cyst. เป็น benign. จัดการ supportive. ก้อน dominant/น่าสงสัยควรประเมินด้วย imaging/biopsy."}, {"topic": "Gynecology", "q": "Which finding is a red flag for breast cancer?", "choices": ["A soft, mobile lump", "Symmetrical breasts", "Cyclical breast pain", "A small lump that resolves alone", "A hard, fixed lump with skin dimpling"], "ans": 4, "exp": "Red flags มะเร็งเต้านม: ก้อนแข็ง ขอบไม่ชัด ติดแน่น (fixed) ไม่เจ็บ, ผิวบุ๋ม/เปลือกส้ม (peau d'orange), หัวนมบุ๋ม/มีน้ำเลือด, ผื่นหัวนม (Paget), ต่อมน้ำเหลืองรักแร้โต. ประเมินด้วย triple assessment."}, {"topic": "Gynecology", "q": "A 55-year-old with uterine prolapse who is not a surgical candidate is best managed with which non-surgical option?", "choices": ["Pessary and pelvic floor exercise", "Vaginal hysterectomy", "Systemic chemotherapy", "A course of antibiotics", "Pelvic radiotherapy"], "ans": 0, "exp": "Pelvic organ prolapse ที่ไม่ผ่าตัด: vaginal pessary + pelvic floor exercise (Kegel), ลดน้ำหนัก, รักษาท้องผูก/ไอเรื้อรัง. ผ่าตัด (colporrhaphy, sacrocolpopexy, hysterectomy) สำหรับรายมีอาการมากและต้องการแก้ถาวร."}, {"topic": "Gynecology", "q": "A woman leaks urine with coughing, sneezing, and lifting, without urgency. What is the diagnosis and initial treatment?", "choices": ["Urge incontinence; an antimuscarinic", "Stress incontinence; pelvic floor exercise", "Overflow incontinence; catheterization", "A UTI; a course of antibiotics", "A fistula; surgical repair"], "ans": 1, "exp": "Stress urinary incontinence — ปัสสาวะเล็ดเมื่อความดันในช่องท้องเพิ่ม (ไอ จาม) จาก urethral hypermobility/sphincter weakness. รักษาเบื้องต้น: Kegel, ลดน้ำหนัก, pessary; ไม่ดีขึ้น → midurethral sling. ต่างจาก urge (OAB)."}, {"topic": "Gynecology", "q": "A woman has urgency, frequency, and inability to hold urine (overactive bladder). What is the treatment?", "choices": ["A midurethral sling procedure", "A course of antibiotics", "Bladder training and an antimuscarinic", "Intermittent catheterization", "A hysterectomy"], "ans": 2, "exp": "Urge incontinence/overactive bladder: รักษาด้วย bladder training, ลดคาเฟอีน, Kegel, และยา antimuscarinic (oxybutynin, solifenacin) หรือ β3-agonist (mirabegron). ดื้อยา → botulinum toxin/neuromodulation. ต่างจาก SUI ที่รักษาด้วย sling."}, {"topic": "Gynecology", "q": "A 30-year-old with a tubo-ovarian abscess unresponsive to antibiotics requires which additional management?", "choices": ["Observation", "Analgesics alone", "Chemotherapy", "Drainage plus antibiotics", "Hormone therapy alone"], "ans": 3, "exp": "Tubo-ovarian abscess (TOA): เริ่มด้วยยาปฏิชีวนะ IV. ถ้าใหญ่ (>7-9 cm), ไม่ตอบสนองใน 48-72 ชม., หรือสงสัยแตก → drainage (image-guided/ผ่าตัด). TOA ที่แตกเป็นฉุกเฉินต้องผ่าตัด."}, {"topic": "Gynecology", "q": "Which organism should be routinely screened for in sexually active women under 25?", "choices": ["HIV only", "Syphilis only", "No screening needed", "HPV only", "Chlamydia and gonorrhea"], "ans": 4, "exp": "แนะนำคัดกรอง Chlamydia (± gonorrhea) เป็นประจำในหญิง <25 ปีที่มีเพศสัมพันธ์ (มักไม่มีอาการแต่นำสู่ PID/infertility). ร่วมคัดกรอง HIV, syphilis ตามความเสี่ยง. รักษา chlamydia: doxycycline, รักษาคู่."}, {"topic": "Gynecology", "q": "A 30-year-old with chlamydial cervicitis should receive which current first-line treatment?", "choices": ["Doxycycline and treat the partner", "Metronidazole", "Penicillin", "Fluconazole", "Acyclovir"], "ans": 0, "exp": "[อัปเดต] Chlamydia รักษาด้วย doxycycline 100 mg วันละ 2 ครั้ง 7 วัน (CDC first-line, azithromycin single dose ยังใช้ได้เช่นในครรภ์). รักษาคู่นอน, งดเพศสัมพันธ์ 7 วัน, ตรวจ/รักษา gonorrhea ร่วม (co-infection บ่อย)."}, {"topic": "Gynecology", "q": "A pregnant woman is diagnosed with gonorrhea. What is the treatment?", "choices": ["Doxycycline", "Ceftriaxone intramuscularly", "Ciprofloxacin", "Metronidazole", "No treatment needed"], "ans": 1, "exp": "Gonorrhea รักษาด้วย ceftriaxone IM single dose. ในครรภ์ห้าม doxycycline/fluoroquinolone. เพิ่ม azithromycin/amoxicillin ถ้าสงสัย chlamydia co-infection. รักษาคู่นอน. Neonatal gonococcal conjunctivitis ป้องกันด้วย erythromycin eye ointment."}, {"topic": "Gynecology", "q": "Which contraceptive method also protects against sexually transmitted infections?", "choices": ["IUD", "Oral contraceptive pills", "Condom", "DMPA", "Implant"], "ans": 2, "exp": "ถุงยางอนามัย (condom) เป็นวิธีเดียวที่ทั้งคุมกำเนิดและป้องกัน STI/HIV (barrier). วิธีฮอร์โมน/IUD ไม่ป้องกัน STI. แนะนำ 'dual protection' (ถุงยาง + วิธีประสิทธิภาพสูง) โดยเฉพาะผู้เสี่ยง STI."}, {"topic": "Gynecology", "q": "A woman requests medical abortion in the first trimester. Which drug regimen is most effective?", "choices": ["Methotrexate alone", "Tranexamic acid", "Oxytocin infusion", "Mifepristone then misoprostol", "Magnesium sulfate"], "ans": 3, "exp": "Medical abortion ไตรมาสแรกที่ได้ผลดีที่สุด: mifepristone (antiprogestin) ตามด้วย misoprostol (prostaglandin). ถ้าไม่มี mifepristone ใช้ misoprostol เดี่ยว (ประสิทธิภาพต่ำกว่า). ติดตามให้ complete + คุมกำเนิดต่อ."}, {"topic": "Gynecology", "q": "Before inserting an IUD, which condition must be excluded?", "choices": ["Underlying heart disease", "Diabetes mellitus", "Thyroid disease", "Renal disease", "Pregnancy and active pelvic infection"], "ans": 4, "exp": "ก่อนใส่ IUD ต้องแยกการตั้งครรภ์และ active pelvic infection (PID/purulent cervicitis) เพราะเพิ่มความเสี่ยง PID. ไม่จำเป็นต้องคัดกรอง STI ทุกรายก่อนใส่ แต่ตามความเสี่ยง. Distorted cavity (fibroid) เป็นข้อพิจารณา."}, {"topic": "Gynecology", "q": "A woman conceives with an IUD in place and the strings are visible. What is the recommended management?", "choices": ["Remove the IUD if strings are visible", "Always leave it in place", "Immediate surgery", "Long-term antibiotics", "Terminate the pregnancy always"], "ans": 0, "exp": "ตั้งครรภ์ทั้งที่มี IUD และเห็นสาย → ถอด IUD (ถ้าทำได้ง่ายและอายุครรภ์น้อย) ลดความเสี่ยง แท้ง/preterm/chorioamnionitis/septic abortion. ไม่เห็นสาย/ถอดยาก → ประเมิน US. แยก ectopic เสมอ."}, {"topic": "Gynecology", "q": "A woman had unprotected intercourse 3 days ago and wants effective emergency contraception plus ongoing contraception. What should be recommended?", "choices": ["Levonorgestrel pill", "Copper IUD", "No action needed", "Calendar method", "Condom next time"], "ans": 1, "exp": "Copper IUD เป็น EC ที่ได้ผลดีที่สุด (ภายใน 5 วัน) และให้การคุมกำเนิดต่อระยะยาว จึงเหมาะกับผู้ต้องการคุมต่อ. ทางเลือกยา: ulipristal acetate (ดีกว่า levonorgestrel โดยเฉพาะ BMI สูง). ยิ่งเร็วยิ่งได้ผล."}, {"topic": "Gynecology", "q": "A woman with hydrosalpinx plans to undergo IVF. What should be done to improve success?", "choices": ["Proceed directly with IVF", "Long-term antibiotic therapy", "Salpingectomy or tubal occlusion before IVF", "A hysterectomy first", "Observation without action"], "ans": 2, "exp": "Hydrosalpinx ลดอัตราสำเร็จ IVF (ของเหลวเป็นพิษต่อ embryo/รบกวน implantation, ไหลย้อนเข้าโพรงมดลูก). แนะนำ laparoscopic salpingectomy หรือ proximal tubal occlusion ก่อน IVF เพื่อเพิ่มอัตราตั้งครรภ์."}, {"topic": "Gynecology", "q": "A woman has recurrent vulvovaginal candidiasis (four or more episodes per year). What is the management?", "choices": ["No treatment is needed", "Surgical intervention", "A course of antibiotics", "Induction then maintenance antifungal", "Estrogen therapy"], "ans": 3, "exp": "Recurrent VVC (≥4 ครั้ง/ปี): รักษา induction (azole นานขึ้น) แล้ว maintenance (fluconazole 150 mg สัปดาห์ละครั้ง ~6 เดือน). หาปัจจัยส่งเสริม: เบาหวานคุมไม่ดี, ภูมิคุ้มกันต่ำ, non-albicans (เพาะเชื้อ)."}, {"topic": "Gynecology", "q": "A woman has a painful, fluctuant mass at the posterior vaginal introitus that has recurred. What is the appropriate surgical management?", "choices": ["Antibiotics alone in all cases", "A hysterectomy", "Observation without drainage", "Systemic chemotherapy", "Marsupialization or a Word catheter"], "ans": 4, "exp": "Bartholin gland abscess/cyst ที่มีอาการ: incision & drainage + Word catheter (คา ~4 สัปดาห์ให้เกิดทางระบายถาวร) หรือ marsupialization (สำหรับที่เป็นซ้ำ). ให้ยาปฏิชีวนะถ้ามี cellulitis/เสี่ยง STI. หญิง >40 ปีที่เป็นก้อนแข็งควร biopsy แยกมะเร็ง."}, {"topic": "Gynecology", "q": "A woman on combined oral contraceptives misses one pill. What should she do?", "choices": ["Take it immediately and continue as usual", "Stop all pills for the cycle", "Start an entirely new pack", "Seek urgent medical care", "Take emergency contraception"], "ans": 0, "exp": "ลืมยาคุมรวม 1 เม็ด (<48 ชม.): กินเม็ดที่ลืมทันทีที่นึกได้ แล้วกินต่อตามปกติ ไม่ต้องใช้วิธีสำรอง. ถ้าลืม ≥2 เม็ด: กินเม็ดล่าสุด, ทิ้งเม็ดอื่นที่ลืม, ใช้ถุงยางสำรอง 7 วัน, พิจารณา EC ถ้ามีเพศสัมพันธ์เสี่ยง."}, {"topic": "Gynecology", "q": "A 35-year-old woman who smokes 20 cigarettes daily wants contraception. Which method should be avoided?", "choices": ["A copper intrauterine device", "Combined oral contraceptives", "A contraceptive implant", "The progestin-only pill", "Barrier condoms"], "ans": 1, "exp": "หญิงอายุ ≥35 + สูบบุหรี่ ≥15 มวน/วัน = ข้อห้าม (MEC 4) ของ combined OC เพราะเพิ่มความเสี่ยง cardiovascular/VTE/MI. ทางเลือกปลอดภัย: progestin-only, DMPA, implant, IUD, ถุงยาง (ไม่มี estrogen)."}, {"topic": "Gynecology", "q": "A 60-year-old woman has a chronic itchy vulval lesion with white, thinned, parchment-like skin. What is the treatment?", "choices": ["Topical vaginal estrogen", "A course of antibiotics", "High-potency topical corticosteroid", "Radical vulvectomy", "Systemic chemotherapy"], "ans": 2, "exp": "Lichen sclerosus — ผิวขาวบางคล้ายกระดาษที่ vulva, คันมาก. รักษาด้วย high-potency topical corticosteroid (clobetasol), ติดตามระยะยาว. สำคัญเพราะเพิ่มความเสี่ยง vulvar SCC (~4-5%) → เฝ้าระวังและ biopsy บริเวณน่าสงสัย."}, {"topic": "Gynecology", "q": "A 60-year-old has a chronic vulvar ulcer, biopsy showing squamous cell carcinoma. In older women, which is a common risk factor?", "choices": ["HPV only", "Fibroadenoma", "Endometriosis", "Lichen sclerosus", "Polycystic ovary syndrome"], "ans": 3, "exp": "Vulvar cancer (ส่วนใหญ่ SCC) มี 2 pathway: HPV-related (อายุน้อย) และ non-HPV related สัมพันธ์กับ lichen sclerosus/chronic inflammation ในผู้สูงอายุ. แผลเรื้อรังที่ vulva ควร biopsy เสมอ."}, {"topic": "Gynecology", "q": "A daughter exposed to DES in utero is at increased risk of which malignancy?", "choices": ["Squamous cervical carcinoma", "Ovarian carcinoma", "Endometrial carcinoma", "Breast carcinoma", "Clear cell adenocarcinoma of the vagina"], "ans": 4, "exp": "In utero DES exposure สัมพันธ์กับ clear cell adenocarcinoma ของช่องคลอด/ปากมดลูก (DES daughters), รวมถึงความผิดปกติของอวัยวะสืบพันธุ์ (T-shaped uterus). DES เลิกใช้แล้วแต่เป็นความรู้คลาสสิก."}, {"topic": "Gynecology", "q": "A 25-year-old with a confirmed 1.5 cm fibroadenoma that is stable is best managed how?", "choices": ["Observation, or excision if it grows", "A total mastectomy", "Systemic chemotherapy", "Radiotherapy", "Anti-hormonal therapy"], "ans": 0, "exp": "Fibroadenoma ที่ยืนยัน triple assessment ในหญิงสาว ขนาดเล็กและคงที่ ติดตามได้ (มักคงที่/ฝ่อ). Excision ถ้าโต, ใหญ่ (>2-3 cm), มีอาการ, ผลไม่สอดคล้อง หรือผู้ป่วยต้องการ. ไม่ใช่มะเร็ง."}, {"topic": "Gynecology", "q": "A breastfeeding woman has a fluctuant breast mass consistent with abscess. What is the management?", "choices": ["Continue breastfeeding only", "Drainage plus antibiotics", "Observation only", "Stop breastfeeding permanently", "Mastectomy"], "ans": 1, "exp": "Breast abscess (ภาวะแทรกซ้อนของ mastitis): drainage (needle aspiration/incision & drainage) + ยาปฏิชีวนะครอบคลุม S. aureus (รวม MRSA ถ้าเสี่ยง) และให้นม/ปั๊มออกต่อ. หญิงไม่ให้นมที่เป็นซ้ำ ระวัง underlying malignancy."}, {"topic": "Gynecology", "q": "How is neonatal gonococcal ophthalmia prevented?", "choices": ["Maternal antibiotics after delivery", "A saline eye rinse", "Erythromycin eye ointment to the newborn", "Neonatal vaccination", "Elective cesarean delivery"], "ans": 2, "exp": "Neonatal gonococcal conjunctivitis ป้องกันด้วยการป้ายตาทารกแรกเกิดด้วย erythromycin ophthalmic ointment ทุกราย. แม่ที่ติด gonorrhea ควรรักษาก่อนคลอด. ทารกติดเชื้อต้องรักษา ceftriaxone systemic."}, {"topic": "Gynecology", "q": "A menopausal woman has atrophic vaginitis. What is the treatment?", "choices": ["Metronidazole", "Systemic antibiotics", "Fluconazole", "Vaginal estrogen or a moisturizer", "Acyclovir"], "ans": 3, "exp": "Atrophic vaginitis (GSM) จากขาด estrogen — ช่องคลอดแห้ง บาง แดง เจ็บ pH สูง. รักษาด้วย vaginal estrogen ขนาดต่ำ หรือ moisturizer/lubricant. ไม่ใช่การติดเชื้อจึงไม่ใช้ยาปฏิชีวนะ/ยาต้านเชื้อรา (แต่แยกการติดเชื้อร่วม)."}, {"topic": "Gynecology", "q": "A woman wants to track ovulation at home for conception. Which method is used?", "choices": ["A home progesterone test", "A home prolactin test", "A home FSH test", "Daily pelvic ultrasound", "Ovulation predictor kit and basal body temperature"], "ans": 4, "exp": "วิธีติดตามการตกไข่ที่บ้าน: ovulation predictor kit (ตรวจ LH surge ในปัสสาวะ - ตกไข่ ~24-36 ชม.หลัง surge) และ basal body temperature (เพิ่มขึ้นหลังตกไข่จาก progesterone). ช่วยกำหนด fertile window."}, {"topic": "Gynecology", "q": "A 28-year-old pregnant woman has a 5 cm simple ovarian cyst without symptoms in the first trimester. What is the most likely diagnosis?", "choices": ["Corpus luteum cyst of pregnancy", "Ovarian carcinoma", "A dermoid cyst", "An endometrioma", "A hydrosalpinx"], "ans": 0, "exp": "ในไตรมาสแรก simple cyst มักเป็น corpus luteum cyst (สร้าง progesterone พยุงการตั้งครรภ์จนรกทำงาน ~10-12 wk) มักหายเองไตรมาส 2. ติดตามด้วย US. ก้อนใหญ่ >5-6 cm/มี solid component/มีอาการจึงผ่าตัด (เลี่ยงไตรมาสแรก)."}, {"topic": "Gynecology", "q": "A woman with hirsutism wants a cosmetic (non-medication) option. Which is appropriate?", "choices": ["A hysterectomy", "Laser hair removal or electrolysis", "Systemic chemotherapy", "Pelvic radiotherapy", "Bilateral oophorectomy"], "ans": 1, "exp": "การจัดการ hirsutism แบบ cosmetic: laser hair removal, electrolysis (ถาวรกว่า), การโกน/ถอน/แว็กซ์, eflornithine cream. ใช้ร่วมการรักษาต้นเหตุ (combined OC ± spironolactone). Medical therapy เห็นผลช้า ~6 เดือน."}, {"topic": "Gynecology", "q": "A pregnant woman with a history of recurrent genital herpes should receive which intervention to reduce recurrence at delivery?", "choices": ["No intervention needed", "Cesarean for all such patients", "Acyclovir suppression from about 36 weeks", "Herpes vaccination", "A course of antibiotics"], "ans": 2, "exp": "หญิงตั้งครรภ์ที่มีประวัติ genital HSV ควรได้ antiviral suppression (acyclovir/valacyclovir) ตั้งแต่ ~36 wk เพื่อลดการกำเริบและ viral shedding → ลดการต้องผ่าคลอดและ neonatal herpes. Active lesion/prodrome ตอนเจ็บครรภ์จึงผ่าคลอด."}, {"topic": "Gynecology", "q": "A woman has superficial (entry) dyspareunia. Which cause is most common?", "choices": ["Deep pelvic endometriosis", "A uterine fibroid", "Ovarian carcinoma", "Vulvovaginal atrophy or vaginismus", "Adenomyosis"], "ans": 3, "exp": "Superficial (entry) dyspareunia มักจากปากช่องคลอด/ช่องคลอดส่วนต้น: vulvovaginal atrophy (GSM), vaginismus, vulvodynia, การติดเชื้อ (candida/herpes). Deep dyspareunia มักจาก endometriosis, PID, adnexal pathology."}, {"topic": "Gynecology", "q": "A woman wants a reversible, highly effective method to space births. What should be recommended?", "choices": ["Tubal ligation", "DMPA only", "Calendar method", "Condoms alone", "A LARC method (implant/IUD)"], "ans": 4, "exp": "ผู้ต้องการเว้นระยะและเก็บโอกาสมีบุตร แนะนำ LARC (implant/IUD) — ประสิทธิภาพสูงเทียบเท่าทำหมันแต่กลับคืนได้. ไม่ควรแนะนำ tubal ligation (ถาวร). shared decision-making."}, {"topic": "Gynecology", "q": "A 45-year-old with a fibroid compressing the bladder wants to avoid major surgery. Which option is appropriate?", "choices": ["Uterine artery embolization or myomectomy", "Observation without treatment", "Systemic chemotherapy", "Pelvic radiotherapy", "A course of antibiotics"], "ans": 0, "exp": "Fibroid ที่มีอาการกดเบียด (bulk symptoms) ในผู้ต้องการเลี่ยง hysterectomy: uterine artery embolization (เก็บมดลูก แต่ไม่แนะนำถ้าต้องการมีบุตร), myomectomy, หรือ MRI-guided focused ultrasound. Medical (GnRH agonist) ลดขนาดชั่วคราว."}, {"topic": "Gynecology", "q": "A woman has a single-duct, spontaneous, bloody nipple discharge. What is the appropriate approach?", "choices": ["Reassurance without work-up", "Imaging and evaluation for papilloma/cancer", "Expressing the discharge manually", "A dopamine agonist", "A course of antibiotics"], "ans": 1, "exp": "น้ำจากหัวนม 'ข้างเดียว, ท่อเดียว, เป็นเลือด, spontaneous' เป็น pathologic discharge — สาเหตุบ่อยคือ intraductal papilloma (benign) แต่ต้องแยกมะเร็ง → mammogram/US ± ductography/biopsy. ต่างจาก galactorrhea (bilateral, milky, prolactin)."}, {"topic": "Gynecology", "q": "At approximately what age is screening mammography generally started in the average-risk population?", "choices": ["Age 20", "Age 30", "Age 40-50, every 1-2 years", "Age 65", "No screening needed"], "ans": 2, "exp": "การคัดกรองมะเร็งเต้านมด้วย mammography เริ่มช่วงอายุ 40-50 ปี ทุก 1-2 ปี (แนวทางต่างกันเล็กน้อย: USPSTF ล่าสุด 40, ACS 45). ผู้เสี่ยงสูง (BRCA, ประวัติครอบครัว) เริ่มเร็วกว่าและอาจเสริม MRI."}, {"topic": "Gynecology", "q": "After a spontaneous or induced abortion, when can contraception be started?", "choices": ["One must wait three months first", "Only condoms may be used", "Contraception is contraindicated", "IUD or hormonal method can start immediately", "Only the calendar method is allowed"], "ans": 3, "exp": "หลังแท้ง การตกไข่กลับมาเร็ว (~2-3 สัปดาห์) จึงควรเริ่มคุมกำเนิดทันที. IUD ใส่ได้ทันทีหลัง evacuation, implant/ยาฮอร์โมนเริ่มได้เลย — ป้องกันการตั้งครรภ์ที่ไม่พึงประสงค์ซ้ำ."}, {"topic": "Gynecology", "q": "A woman with complete uterine procidentia who is a surgical candidate is best managed with which option?", "choices": ["A course of antibiotics", "Systemic chemotherapy", "Estrogen therapy alone", "Observation without treatment", "Vaginal hysterectomy and repair"], "ans": 4, "exp": "Complete procidentia มีอาการมาก — ผ่าตัด (vaginal hysterectomy + apical suspension/colporrhaphy หรือ colpocleisis ในผู้สูงอายุที่ไม่มีเพศสัมพันธ์). ผู้ที่ผ่าตัดไม่ได้ใช้ pessary. Vaginal estrogen ช่วยสภาพเนื้อเยื่อ."}, {"topic": "Gynecology", "q": "What is the benefit of pelvic floor muscle exercise (Kegel)?", "choices": ["Helps stress incontinence and mild prolapse", "Treats ovarian carcinoma", "Treats polycystic ovary syndrome", "Shrinks uterine fibroids", "Reduces menopausal hot flashes"], "ans": 0, "exp": "Kegel exercise เสริมความแข็งแรงของ pelvic floor → ช่วย stress urinary incontinence, mild-moderate prolapse, หลังคลอด. เป็น first-line conservative treatment. ทำถูกวิธีสม่ำเสมอ (อาจใช้ biofeedback/physical therapy ช่วย)."}, {"topic": "Gynecology", "q": "A woman with mixed urinary incontinence (both stress and urge) should receive which initial management?", "choices": ["Immediate surgical repair", "Lifestyle and pelvic floor training", "A course of antibiotics", "A permanent indwelling catheter", "A hysterectomy"], "ans": 1, "exp": "Mixed urinary incontinence — จัดการเบื้องต้นด้วย conservative: lifestyle (ลดน้ำหนัก/คาเฟอีน), Kegel, bladder training และรักษาส่วนที่รำคาญมากสุดก่อน (antimuscarinic ถ้า urge เด่น; sling ถ้า stress เด่นและดื้อ). ประเมิน urodynamics ในรายซับซ้อน."}, {"topic": "Gynecology", "q": "A woman with stress incontinence unresponsive to conservative treatment is best managed with which surgery?", "choices": ["Hysterectomy", "Antimuscarinic drugs", "Midurethral sling", "Catheterization", "Estrogen therapy"], "ans": 2, "exp": "SUI ที่ดื้อ conservative → ผ่าตัดมาตรฐานคือ midurethral sling (TVT/TOT) พยุงท่อปัสสาวะ. ทางเลือกอื่น: Burch colposuspension, urethral bulking agents. เลือกตามผู้ป่วยและความเชี่ยวชาญ."}, {"topic": "Gynecology", "q": "A pregnant woman is non-immune to rubella. What is the appropriate management?", "choices": ["Give the MMR vaccine now in pregnancy", "Give antiviral therapy", "Terminate the pregnancy", "Avoid exposure and give MMR postpartum", "No action is needed"], "ans": 3, "exp": "MMR เป็นวัคซีนเชื้อเป็น ห้ามในครรภ์. หญิงที่ไม่มีภูมิ rubella ควรหลีกเลี่ยงผู้ติดเชื้อ และรับ MMR หลังคลอด (ให้นมได้) เพื่อป้องกันครรภ์ถัดไป. Rubella ไตรมาสแรก → congenital rubella (cataract, PDA, หูหนวก)."}, {"topic": "Gynecology", "q": "A woman with anovulation due to hypogonadotropic (hypothalamic) causes needs ovulation induction. Which is appropriate?", "choices": ["Letrozole alone", "Metformin therapy", "IVF in every case", "No treatment option exists", "Pulsatile GnRH or gonadotropins"], "ans": 4, "exp": "Hypogonadotropic hypogonadism (hypothalamic, LH/FSH ต่ำ) — clomiphene/letrozole มักไม่ได้ผล. ใช้ pulsatile GnRH หรือ gonadotropins (FSH+LH) กระตุ้น follicle โดยตรง. ใน FHA ควรแก้ต้นเหตุ (เพิ่มพลังงาน) ก่อน."}, {"topic": "Gynecology", "q": "A woman with mild PID and stable vital signs is treated as an outpatient with which regimen?", "choices": ["Ceftriaxone plus doxycycline", "Metronidazole alone", "Penicillin alone", "Fluconazole", "Acyclovir"], "ans": 0, "exp": "PID ไม่รุนแรง (ผู้ป่วยนอก): ceftriaxone IM + doxycycline oral 14 วัน + metronidazole (anaerobes) 14 วัน. ข้อบ่งชี้ admit/IV: ตั้งครรภ์, อาการรุนแรง/ไข้สูง/อาเจียน, TOA, ไม่ตอบสนอง oral, สงสัยต้องผ่าตัด. ติดตามดีขึ้นใน 72 ชม."}, {"topic": "Gynecology", "q": "A pregnant woman is diagnosed with PID (rare). What is the appropriate management?", "choices": ["Outpatient oral therapy", "Admission with IV antibiotics", "Immediate surgery", "No treatment needed", "Antiviral therapy"], "ans": 1, "exp": "PID ในครรภ์พบน้อยแต่ถ้าเป็นถือว่ารุนแรง เสี่ยงทั้งแม่และทารก (preterm, pregnancy loss) → admit ให้ยาปฏิชีวนะ IV, หลีกเลี่ยง doxycycline (สูตรปลอดภัยในครรภ์). แยกภาวะอื่น (appendicitis, ectopic)."}, {"topic": "Gynecology", "q": "A woman has recurrent bacterial vaginosis. Besides retreatment, what is helpful?", "choices": ["No further action needed", "Antifungal therapy", "Suppressive therapy and avoid douching", "Estrogen therapy", "Surgical management"], "ans": 2, "exp": "Recurrent BV: extended/suppressive therapy (metronidazole gel 2 ครั้ง/สัปดาห์ หลายเดือน), หลีกเลี่ยงการสวนล้างช่องคลอด (douching) ที่รบกวนสมดุลแบคทีเรีย. การรักษาคู่นอนไม่ช่วยลดการเป็นซ้ำ."}, {"topic": "Gynecology", "q": "A submucosal fibroid causing infertility and recurrent loss is best treated with which procedure?", "choices": ["Observation", "Uterine artery embolization", "Hysterectomy", "Hysteroscopic myomectomy", "Chemotherapy"], "ans": 3, "exp": "Submucosal fibroid (ยื่นเข้าโพรงมดลูก) รบกวนการฝังตัว/เพิ่มการแท้ง → ในผู้ต้องการมีบุตร รักษาด้วย hysteroscopic myomectomy เพิ่มโอกาสตั้งครรภ์. UAE ไม่แนะนำในผู้ต้องการมีบุตร."}, {"topic": "Gynecology", "q": "How should a man prepare for semen analysis?", "choices": ["Abstain for only 24 hours", "No preparation is needed", "Abstain for a full month", "Ejaculate one hour beforehand", "Abstain for 2-5 days before collection"], "ans": 4, "exp": "Semen analysis: งดการหลั่ง 2-5 วันก่อนเก็บ (สั้นเกิน → count ต่ำ; ยาวเกิน → motility ลด), เก็บครบถ้วนส่งภายใน ~1 ชม. (เก็บอุ่น). ประเมิน volume, concentration, motility, morphology (WHO). ผิดปกติควรตรวจซ้ำ."}, {"topic": "Gynecology", "q": "A woman on systemic hormone therapy should be monitored for which of the following?", "choices": ["Symptoms, bleeding, breast/CV risk", "Body weight alone", "Serum prolactin alone", "Serum TSH alone", "No monitoring is needed"], "ans": 0, "exp": "ผู้ใช้ systemic HT ควรประเมินซ้ำเป็นระยะ: ความจำเป็นในการใช้ต่อ (ขนาดต่ำสุด/สั้นสุด), unscheduled vaginal bleeding (ต้องประเมิน endometrium), benefit-risk (เต้านม, cardiovascular, VTE). คัดกรองมะเร็งเต้านมตามปกติ. shared decision-making."}, {"topic": "Gynecology", "q": "A woman has deep dyspareunia with dysmenorrhea and infertility. What is suspected, and how is it confirmed?", "choices": ["Vaginismus, by exam", "Endometriosis, by laparoscopy", "UTI, by urine culture", "Candida, by KOH", "Atrophy, by estrogen trial"], "ans": 1, "exp": "Deep dyspareunia + dysmenorrhea + infertility เป็นภาพคลาสสิกของ endometriosis (โดยเฉพาะ deep infiltrating). ยืนยันด้วย laparoscopy (gold standard) ± imaging (TVS/MRI). สามารถเริ่มรักษา empirically ในหลายกรณี."}, {"topic": "Gynecology", "q": "A woman with a symptomatic 6 cm ovarian dermoid cyst is best treated with which procedure?", "choices": ["Observation", "Hysterectomy with BSO", "Ovarian cystectomy", "Chemotherapy", "Radiation"], "ans": 2, "exp": "Mature cystic teratoma (dermoid) เป็น benign. ขนาดใหญ่ (>5-6 cm)/มีอาการ/เสี่ยง torsion → ovarian cystectomy (laparoscopic ถ้าได้ เก็บรังไข่ในวัยเจริญพันธุ์ ระวัง spillage - chemical peritonitis). อาจ bilateral (~10-15%)."}, {"topic": "Gynecology", "q": "A pregnant woman has a suspicious breast mass. What is the appropriate safe evaluation?", "choices": ["Defer until after delivery", "Hormone therapy", "A CT scan", "Ultrasound primarily, with core biopsy", "Terminate the pregnancy"], "ans": 3, "exp": "ก้อนเต้านมในครรภ์ต้องประเมินเหมือนคนทั่วไป (อย่าเลื่อน — pregnancy-associated breast cancer พยากรณ์แย่). Ultrasound เป็นการตรวจเริ่มต้นที่ปลอดภัย; mammogram ทำได้ (กำบังหน้าท้อง); core biopsy ยืนยัน. Triple assessment ใช้ได้ในครรภ์."}, {"topic": "Gynecology", "q": "A woman stopping contraception to conceive should be counseled about which point?", "choices": ["Wait 6 months to conceive", "Pills cause permanent infertility", "Detox is needed first", "Avoid pregnancy for 1 year", "Fertility returns quickly; start folate"], "ans": 4, "exp": "หลังหยุดยาคุม fertility กลับมาเร็ว (1-3 เดือน) ยกเว้น DMPA (อาจช้าถึง 6-12 เดือน). ยาคุมไม่ทำให้มีบุตรยากถาวร. ควรเริ่ม folic acid 400-600 µg/วันก่อนตั้งครรภ์และ preconception counseling."}, {"topic": "Gynecology", "q": "Drug-induced hyperprolactinemia with galactorrhea is most commonly caused by which drug class?", "choices": ["Antipsychotics and metoclopramide", "NSAIDs", "Statins", "Antihistamines", "Antibiotics"], "ans": 0, "exp": "Drug-induced hyperprolactinemia พบบ่อยจากยาต้าน dopamine: antipsychotics (risperidone, haloperidol), metoclopramide/domperidone, บางส่วน TCA/SSRI, opioids, estrogen. ตรวจประวัติยาก่อนคิดถึง prolactinoma. หยุด/เปลี่ยนยาถ้าทำได้แล้วประเมินซ้ำ."}, {"topic": "Gynecology", "q": "A woman needs non-hormonal contraception without an intrauterine device. Which is appropriate?", "choices": ["A contraceptive implant", "Condom, diaphragm, or fertility awareness", "Combined oral contraceptives", "DMPA injection", "The levonorgestrel IUS"], "ans": 1, "exp": "ทางเลือก non-hormonal (ไม่ใช่ device ในโพรงมดลูก): barrier (ถุงยาง, diaphragm + spermicide), fertility awareness-based methods (การนับวัน/มูก/BBT). ถุงยางยังป้องกัน STI. Copper IUD เป็น non-hormonal แต่เป็น device."}, {"topic": "Gynecology", "q": "A pregnant woman with large genital warts is best treated with which method?", "choices": ["Cesarean delivery for all", "Radiotherapy", "Pregnancy-safe methods (TCA, cryotherapy, surgery)", "No treatment ever", "Oral antiviral therapy"], "ans": 2, "exp": "Genital warts ในครรภ์อาจโตขึ้น. รักษาด้วยวิธีปลอดภัยในครรภ์: TCA, cryotherapy, surgical removal/laser. หลีกเลี่ยง podophyllin/imiquimod. ผ่าคลอดพิจารณาเฉพาะเมื่อหูดใหญ่มากอุดกั้นช่องคลอด/เสี่ยงเลือดออก (ไม่ใช่เพื่อป้องกัน transmission)."}, {"topic": "Gynecology", "q": "A woman with a cervical polyp causing intermenstrual bleeding is best managed with which procedure?", "choices": ["Observation only", "Antibiotics", "Hysterectomy", "Polypectomy with histology", "Chemotherapy"], "ans": 3, "exp": "Cervical polyp ที่มีอาการ (เลือดออก/postcoital) ควรตัดออก (polypectomy) และส่งชิ้นเนื้อตรวจพยาธิ (ส่วนใหญ่ benign แต่แยก malignancy/dysplasia). ประเมิน endometrium/ปากมดลูกร่วมถ้ามีเลือดออกผิดปกติ."}, {"topic": "Gynecology", "q": "A 30-year-old couple with 2 years of unexplained infertility is best managed with which first step?", "choices": ["IVF immediately", "Hysterectomy", "Observation only", "Tubal surgery", "Ovulation induction with IUI"], "ans": 4, "exp": "Unexplained infertility (ตรวจครบปกติ) — รักษาเป็นขั้นบันได: เริ่ม ovulation induction (letrozole/clomiphene) + IUI หลายรอบ; ไม่สำเร็จจึง IVF. อายุมารดา/ระยะเวลามีผลต่อการก้าวไป IVF เร็วขึ้น (≥35-38 ปี)."}, {"topic": "Gynecology", "q": "A woman worried about bone loss from DMPA should be counseled that which is true?", "choices": ["Bone loss is reversible after stopping", "It is absolutely contraindicated", "DXA is needed monthly", "Only the elderly can use it", "Switch to high-dose estrogen"], "ans": 0, "exp": "DMPA ทำให้ BMD ลดชั่วคราว (reversible) กลับคืนหลังหยุด — ไม่ควรจำกัดระยะเวลาการใช้เพียงเพราะเรื่องกระดูก (WHO/ACOG). แนะนำ calcium/vitamin D, ออกกำลังกาย, เลิกบุหรี่. ประโยชน์คุมกำเนิดมีมากกว่าความเสี่ยง."}, {"topic": "Gynecology", "q": "A woman postpartum wants an IUD. When can it be inserted?", "choices": ["Never in the postpartum period", "Immediately after placenta or at 4-6 weeks", "Only during menstruation", "Only after one year", "Only after weaning"], "ans": 1, "exp": "IUD ใส่ได้ทั้ง immediate postpartum (ภายใน 10 นาที-48 ชม.หลังคลอดรก — สะดวก แต่ expulsion สูงกว่าเล็กน้อย) หรือ interval (หลัง 4-6 สัปดาห์). ปลอดภัยในหญิงให้นม. เป็น LARC ที่ดีสำหรับ postpartum contraception."}, {"topic": "Gynecology", "q": "A pelvic mass with ascites and a very high CA-125 in a postmenopausal woman should be referred to whom?", "choices": ["General internist", "General surgeon", "Gynecologic oncologist", "Dermatologist", "No referral needed"], "ans": 2, "exp": "Pelvic/adnexal mass ที่น่าสงสัยมะเร็ง (solid, ascites, CA-125 สูงในวัยหมดประจำเดือน, RMI สูง) ควรส่ง gynecologic oncologist เพื่อวางแผน surgical staging/cytoreduction (เพิ่ม survival). อย่าเจาะ/ผ่าก้อนแบบไม่วางแผน (เสี่ยง spillage)."}, {"topic": "Gynecology", "q": "A woman with an ovarian cyst aspirated to clear fluid with complete resolution is managed how?", "choices": ["Mastectomy", "Chemotherapy", "Hormone therapy", "Reassure and follow up", "Radiation"], "ans": 3, "exp": "Simple cyst ที่เจาะดูดได้ของเหลวใส (ไม่มีเลือด) และก้อนยุบหมด เป็น benign → reassure และติดตาม. ถ้าของเหลวเป็นเลือด/ก้อนไม่ยุบ/กลับเป็นซ้ำ ต้องประเมินต่อ (imaging/biopsy) แยก intracystic pathology/มะเร็ง."}, {"topic": "Gynecology", "q": "A pregnant woman treated for syphilis develops fever, chills, and myalgia hours after penicillin. What is this reaction?", "choices": ["Drug anaphylaxis alone", "A new infection", "Preeclampsia", "Chorioamnionitis alone", "Jarisch-Herxheimer reaction"], "ans": 4, "exp": "Jarisch-Herxheimer reaction — ไข้ หนาวสั่น ปวดเมื่อย ภายในไม่กี่ชั่วโมงหลังเริ่มรักษาซิฟิลิสด้วย penicillin (จาก endotoxin เมื่อ spirochete ตาย). ในครรภ์อาจกระตุ้น contraction/fetal distress ชั่วคราว → เฝ้าระวัง. รักษาประคับประคอง ไม่ต้องหยุด penicillin."}, {"topic": "Gynecology", "q": "For the lactational amenorrhea method (LAM) to be effective, which conditions must be met?", "choices": ["Exclusive breastfeeding, amenorrhea, under 6 months", "Any breastfeeding at any time", "No specific conditions required", "Mixed feeding is acceptable", "Concurrent pills are required"], "ans": 0, "exp": "LAM ได้ผลดี (~98%) เมื่อครบ 3 เงื่อนไข: exclusive breastfeeding, amenorrhea (ประจำเดือนยังไม่มา), ทารก <6 เดือน. เมื่อเงื่อนไขใดหายไปต้องเริ่มวิธีอื่น. การให้นมบ่อยกด GnRH → ยับยั้งการตกไข่."}, {"topic": "Gynecology", "q": "A 38-year-old wants to assess ovarian reserve before planning pregnancy. Which test is used?", "choices": ["Serum CA-125 level", "AMH and antral follicle count", "Serum prolactin level", "Serum TSH alone", "Hysterosalpingography"], "ans": 1, "exp": "Ovarian reserve testing: AMH (จำนวน follicle ที่เหลือ - ตรวจได้ทุกวัน), antral follicle count (US), day-3 FSH/estradiol. ช่วยทำนายการตอบสนอง IVF และให้คำปรึกษาเรื่องอายุ. AMH ต่ำ = diminished reserve."}, {"topic": "Gynecology", "q": "A woman with bilateral tubal blockage on HSG who desires pregnancy is best managed with which option?", "choices": ["Timed intercourse", "Ovulation drugs alone", "IVF, bypassing the tubes", "IUI", "No option available"], "ans": 2, "exp": "Bilateral tubal blockage (tubal factor) — ไข่กับอสุจิพบกันไม่ได้ในท่อ → IVF เหมาะสม (ผสมนอกร่างกายแล้วย้ายตัวอ่อนกลับ ไม่ต้องพึ่งท่อ). Tubal surgery ในบางรายที่ท่อเสียหายน้อย. IUI ต้องการท่อเปิดอย่างน้อยข้างหนึ่ง."}, {"topic": "Gynecology", "q": "A woman with a simple ovarian cyst 8 cm and pain is best managed how?", "choices": ["Follow up only", "Antibiotics", "Chemotherapy", "Consider surgery (cystectomy)", "Hysterectomy"], "ans": 3, "exp": "Simple cyst ที่ใหญ่ (>7-10 cm)/มีอาการ/ไม่หายตามการติดตาม เสี่ยง torsion → พิจารณาผ่าตัด (laparoscopic cystectomy - เก็บรังไข่). Cyst เล็ก (<5 cm) ไม่มีอาการมักติดตามได้. ประเมินลักษณะน่ากังวลและ CA-125 ตามเหมาะสม."}, {"topic": "Gynecology", "q": "A woman with recurrent Bartholin abscess after simple I&D is best managed with which procedure?", "choices": ["Repeat simple I&D", "Antibiotics alone", "Hysterectomy", "Observation", "Marsupialization"], "ans": 4, "exp": "Bartholin abscess ที่เป็นซ้ำหลัง simple I&D → marsupialization (เย็บเปิดผนัง cyst สร้างทางระบายถาวร) หรือ Word catheter. หญิง >40 ปีที่เป็นก้อนแข็งควร biopsy แยกมะเร็ง Bartholin gland."}, {"topic": "Gynecology", "q": "A woman with combined OC who wants help for acne and hirsutism benefits from which type of progestin?", "choices": ["Anti-androgenic progestin", "Androgenic progestin", "Progestin-only method", "Copper IUD", "DMPA"], "ans": 0, "exp": "Combined OC ที่มี anti-androgenic progestin (drospirenone, cyproterone) ช่วยสิว/hirsutism (เพิ่ม SHBG ลด free androgen + ต้าน androgen receptor). เหมาะกับ PCOS ที่มี hyperandrogenism. Copper IUD/progestin-only บางชนิดไม่ช่วย/อาจแย่ลง."}, {"topic": "Gynecology", "q": "An HIV-positive pregnant woman with a viral load over 1,000 copies near term should deliver by which route?", "choices": ["Normal vaginal delivery", "Scheduled cesarean with IV zidovudine", "Await spontaneous labor", "Vacuum extraction", "Emergency cesarean only in labor"], "ans": 1, "exp": "หญิง HIV ที่ viral load >1,000 copies/mL ใกล้คลอด → scheduled cesarean ที่ ~38 wk (ก่อนเจ็บครรภ์/ถุงน้ำแตก) + IV zidovudine ลด vertical transmission. viral load <1,000 คุมได้ดี คลอดทางช่องคลอดได้. ทารกได้ ARV prophylaxis, หลีกเลี่ยงให้นม (ในไทย)."}, {"topic": "Gynecology", "q": "A woman has bilateral milky nipple discharge with a high prolactin level. What should be evaluated?", "choices": ["Underlying breast cancer", "A normal physiologic finding", "Causes of hyperprolactinemia", "A breast infection", "A fibroadenoma"], "ans": 2, "exp": "Bilateral galactorrhea + prolactin สูง = hyperprolactinemia. หาสาเหตุ: prolactinoma (MRI), ยา (antipsychotics, metoclopramide), hypothyroidism (TSH), การตั้งครรภ์. ต่างจากน้ำหัวนมข้างเดียว/มีเลือด (ประเมินพยาธิสภาพเต้านม)."}, {"topic": "Gynecology", "q": "A woman with PCOS on combined OC gains which benefit for the endometrium?", "choices": ["An increased cancer risk", "Permanent amenorrhea", "Increased androgen levels", "Protection from endometrial hyperplasia", "No effect at all"], "ans": 3, "exp": "ใน PCOS ที่ chronic anovulation ทำให้ endometrium ได้รับ unopposed estrogen เสี่ยง hyperplasia/มะเร็ง. Combined OC (หรือ cyclic progestin/LNG-IUS) ให้ progestin ปกป้อง endometrium, คุมรอบเดือน, ลด androgen."}, {"topic": "Gynecology", "q": "A woman with an ovarian cyst in menopause, 3 cm, simple, with a normal CA-125, is best managed how?", "choices": ["Immediate surgery", "A hysterectomy", "Systemic chemotherapy", "No follow-up needed", "Ultrasound and CA-125 follow-up"], "ans": 4, "exp": "Simple unilocular cyst เล็ก (<5-10 cm) ในวัยหมดประจำเดือนที่ CA-125 ปกติ ความเสี่ยงมะเร็งต่ำ → ติดตามด้วย US + CA-125. ลักษณะน่ากังวล (solid, septation, ascites, ใหญ่, CA-125 สูง) จึงส่ง gyn-oncology. ใช้ IOTA/RMI ช่วย."}, {"topic": "Gynecology", "q": "A woman has chronic pelvic pain for more than 6 months. Which gynecologic cause is most common?", "choices": ["Endometriosis or adhesions", "Ovarian cancer", "Fibroadenoma", "Osteoporosis", "Gestational diabetes"], "ans": 0, "exp": "Chronic pelvic pain (>6 เดือน) — สาเหตุทางนรีเวชบ่อยสุด: endometriosis, pelvic adhesions (หลัง PID/ผ่าตัด), adenomyosis, chronic PID. ต้องประเมินสาเหตุนอกนรีเวชด้วย (IBS, interstitial cystitis, musculoskeletal). แนวทางสหสาขา."}, {"topic": "Gynecology", "q": "A woman with a breast cyst aspirated to bloody fluid, with the mass not fully resolving, requires which next step?", "choices": ["Reassurance only", "Imaging and biopsy", "Hormone therapy", "Repeat aspiration only", "Antibiotics"], "ans": 1, "exp": "Cyst ที่เจาะได้ของเหลว 'เป็นเลือด' หรือก้อนไม่ยุบหมด/กลับเป็นซ้ำ ต้องประเมินต่อ (imaging + biopsy) แยก intracystic pathology/มะเร็ง. ต่างจาก simple cyst ที่ของเหลวใสและยุบหมด (benign, reassure)."}, {"topic": "Gynecology", "q": "A woman using a combined pill misses two consecutive pills at midcycle. What should she do?", "choices": ["Continue as if nothing happened", "Start a completely new pack", "Take the most recent missed pill and use backup", "Stop the pill permanently", "Nothing needs to be done"], "ans": 2, "exp": "ลืมยาคุมรวม ≥2 เม็ด (≥48 ชม.): กินเม็ดล่าสุดที่ลืมทันที, ทิ้งเม็ดอื่นที่ลืม, กินต่อตามปกติ, ใช้ถุงยางสำรอง 7 วัน, และพิจารณา emergency contraception ถ้ามีเพศสัมพันธ์ในช่วงเสี่ยง."}, {"topic": "Gynecology", "q": "A woman with lichen sclerosus should be monitored for which long-term risk?", "choices": ["Ovarian cancer", "Endometrial cancer", "Cervical cancer", "Vulvar squamous cell carcinoma", "Breast cancer"], "ans": 3, "exp": "Lichen sclerosus เพิ่มความเสี่ยง vulvar SCC (~4-5%) → ต้องเฝ้าระวังระยะยาว และ biopsy บริเวณที่หนา/แผล/เปลี่ยนแปลง. รักษาด้วย high-potency topical corticosteroid ช่วยลดอาการและความเสี่ยง."}, {"topic": "Gynecology", "q": "A woman has recurrent painful genital ulcers that are grouped vesicles. What is the recommended treatment?", "choices": ["Penicillin injection", "Metronidazole", "Fluconazole", "Doxycycline", "Acyclovir or valacyclovir"], "ans": 4, "exp": "Genital herpes (HSV) รักษาด้วย antiviral (acyclovir/valacyclovir/famciclovir) — ลดความรุนแรง/ระยะเวลาและใช้ suppressive therapy ลดการกำเริบ (ไม่หายขาด เพราะ latency ใน ganglia). ในครรภ์ที่มี active lesion ตอนคลอด → C/S."}]}, {"id": "obgyn5", "title": "Ob-gyne ชุดที่ 5 — Gynecologic Oncology & Guideline Updates (Cervix, Endometrium, Ovary, GTD)", "subject": "obgyn", "questions": [{"topic": "Gynecologic Oncology", "q": "A 45-year-old woman is diagnosed with cervical cancer. What is the main underlying cause?", "choices": ["High-risk HPV, especially 16 and 18", "Long-term cigarette smoking", "Oral contraceptive use", "A BRCA gene mutation", "Herpes simplex virus infection"], "ans": 0, "exp": "HPV ความเสี่ยงสูง โดยเฉพาะ HPV 16 และ 18 เป็นสาเหตุหลัก (~70%). persistent infection → precancer (CIN) → มะเร็ง. ปัจจัยเสริม: สูบบุหรี่, HIV, เพศสัมพันธ์อายุน้อย/หลายคู่, ไม่คัดกรอง."}, {"topic": "Gynecologic Oncology", "q": "Which is the most common histologic type of cervical cancer?", "choices": ["Adenocarcinoma", "Squamous cell carcinoma", "Small cell carcinoma", "Clear cell carcinoma", "Sarcoma"], "ans": 1, "exp": "Squamous cell carcinoma พบบ่อยสุด (~70%) เกิดที่ transformation zone. Adenocarcinoma (~25%) จาก glandular cells, คัดกรองด้วย cytology ยากกว่า, สัมพันธ์ HPV 18. ทั้งคู่สัมพันธ์ HPV."}, {"topic": "Gynecologic Oncology", "q": "At what age is the HPV vaccine most effective when given?", "choices": ["After age 45", "Age 20-30", "Age 9-14, before sexual debut", "Only after sexual debut", "Only in infected persons"], "ans": 2, "exp": "วัคซีน HPV มีประสิทธิภาพสูงสุดเมื่อฉีดอายุ 9-14 ปี ก่อนเริ่มมีเพศสัมพันธ์ (ก่อนสัมผัส HPV). ให้ประโยชน์ถึง 26 ปี (พิจารณาถึง 45). เป็น primary prevention ตามเป้า WHO 90-70-90."}, {"topic": "Gynecologic Oncology", "q": "According to the WHO 2022 (SAGE) update, what is the new recommendation on HPV vaccine dosing?", "choices": ["Three doses are always required", "Five doses are now needed", "The vaccine is no longer recommended", "A single dose protects like two doses", "It is only for adults"], "ans": 3, "exp": "[อัปเดต] WHO SAGE 2022: single-dose schedule ให้การป้องกันเทียบเท่า 2 เข็มในอายุ 9-20 ปี — ประเทศเลือกใช้ 1 หรือ 2 เข็มได้ (การศึกษาในไทยสนับสนุน). เพิ่มความครอบคลุม/ลดต้นทุน. (ภูมิคุ้มกันบกพร่อง/HIV ยังแนะนำหลายเข็ม)."}, {"topic": "Gynecologic Oncology", "q": "Per RTCOG/Thai guidance, which is the preferred primary screening method for women aged 30 and over?", "choices": ["A yearly Pap smear", "No screening at all", "Monthly VIA inspection", "Serum CA-125 testing", "Primary HPV testing every 5 years"], "ans": 4, "exp": "[อัปเดต] RTCOG/ไทย: คัดกรองอายุ 25-65 ปี ด้วย cytology ทุก 2 ปี หรือ HPV testing ทุก 5 ปี หรือ co-testing ทุก 5 ปี; อายุ ≥30 ปีเน้น HPV testing ทุก 5 ปี (ไวกว่า). สปสช.บรรจุ HPV DNA test + self-collection."}, {"topic": "Gynecologic Oncology", "q": "Which approach has the NHSO (สปสช.) adopted to expand cervical cancer screening coverage?", "choices": ["HPV DNA testing with self-collection", "A blood-based screening test", "No change from before", "MRI-based screening", "Surgical screening"], "ans": 0, "exp": "[อัปเดต] ตั้งแต่ปี 2563 สปสช.บรรจุ HPV DNA test และรองรับ self-collected HPV sampling (เก็บตัวอย่างเอง) เพื่อเพิ่มการเข้าถึง/ความครอบคลุม โดยเฉพาะผู้ไม่สะดวกตรวจภายใน. เป็นกลยุทธ์สู่การกำจัดมะเร็งปากมดลูก."}, {"topic": "Gynecologic Oncology", "q": "A woman has an HSIL Pap smear result. What is the next step?", "choices": ["Repeat Pap in 5 years", "Colposcopy and biopsy", "Immediate hysterectomy", "Antibiotic therapy", "Radiotherapy"], "ans": 1, "exp": "ผลคัดกรองความเสี่ยงสูง (HSIL, HPV 16/18, หรือ high-risk HPV + abnormal cytology) → colposcopy + biopsy. พบ CIN2/3 → รักษาด้วย excision (LEEP/conization) หรือ ablation. ไม่ผ่าตัดใหญ่ก่อนยืนยันชิ้นเนื้อ."}, {"topic": "Gynecologic Oncology", "q": "How is CIN 2/3 (high-grade cervical precancer) treated?", "choices": ["Antiviral therapy", "Chemotherapy", "LEEP or conization", "Hysterectomy always", "Observation for 5 years"], "ans": 2, "exp": "CIN 2/3 (precancer) รักษาด้วย excisional (LEEP/conization - ได้ margin) หรือ ablative (cryotherapy/laser). ไม่จำเป็นต้อง hysterectomy (สงวนมดลูก). CIN 1 มักติดตาม (regress เอง). รักษา precancer ป้องกันมะเร็ง."}, {"topic": "Gynecologic Oncology", "q": "What is a key change in the FIGO 2018 cervical cancer staging system?", "choices": ["Uses clinical examination only", "Abolishes staging entirely", "Uses serum CA-125", "Adds imaging and nodal status (IIIC)", "Uses tumor size only"], "ans": 3, "exp": "[อัปเดต FIGO 2018] อนุญาตให้ใช้ imaging (MRI/CT/PET) และผลพยาธิร่วมประเมิน, เพิ่ม lymph node involvement เป็น stage IIIC (IIIC1 pelvic, IIIC2 para-aortic), และปรับเกณฑ์ขนาดใน stage IB (IB1<2, IB2 2-4, IB3 ≥4 cm)."}, {"topic": "Gynecologic Oncology", "q": "How is locally advanced cervical cancer (stage IIB-IVA) treated?", "choices": ["Radical surgery alone", "Chemotherapy alone", "Observation only", "Hormone therapy alone", "Concurrent chemoradiation with brachytherapy"], "ans": 4, "exp": "มะเร็งปากมดลูก locally advanced รักษาด้วย concurrent chemoradiation (external beam RT + cisplatin) ตามด้วย brachytherapy. Early stage (IA, IB1-IB2, IIA1) รักษาด้วยผ่าตัด (radical hysterectomy + pelvic node) หรือ RT ได้ผลเทียบเท่า."}, {"topic": "Gynecologic Oncology", "q": "Which gynecologic cancer characteristically presents as postmenopausal bleeding?", "choices": ["Endometrial cancer", "Ovarian cancer", "Vulvar cancer", "Fallopian tube cancer", "Early cervical cancer"], "ans": 0, "exp": "มะเร็งเยื่อบุโพรงมดลูก (endometrial cancer) มีอาการเด่นเป็น postmenopausal bleeding (~90%) จึงมักวินิจฉัยระยะแรก. Postmenopausal bleeding ทุกรายต้องประเมิน endometrium. พบบ่อยในประเทศพัฒนาแล้ว."}, {"topic": "Gynecologic Oncology", "q": "Which is a risk factor for type I endometrial cancer?", "choices": ["Oral contraceptive use", "Unopposed estrogen exposure", "Breastfeeding", "Cigarette smoking", "Regular exercise"], "ans": 1, "exp": "Endometrial cancer type I (endometrioid, estrogen-dependent) เสี่ยงจาก unopposed estrogen: obesity, PCOS/anovulation, nulliparity, tamoxifen, estrogen-only HT, DM, Lynch syndrome. Combined OC/multiparity/ให้นมเป็นปัจจัยป้องกัน."}, {"topic": "Gynecologic Oncology", "q": "What is the gold standard for diagnosing endometrial cancer?", "choices": ["Transvaginal ultrasound", "Pap smear", "Endometrial biopsy", "Serum CA-125", "MRI"], "ans": 2, "exp": "Endometrial biopsy (histology) เป็น gold standard — office sampling หรือ D&C/hysteroscopy. TVS (endometrial thickness) ใช้คัดกรองเบื้องต้น แต่ยืนยันด้วยชิ้นเนื้อ. Pap ไม่ใช้วินิจฉัย endometrial cancer."}, {"topic": "Gynecologic Oncology", "q": "What is a key change in the FIGO 2023 endometrial cancer staging system?", "choices": ["Uses anatomy only", "Abolishes staging entirely", "Uses serum CA-125", "Adds grade, LVSI, molecular class", "Uses uterine size only"], "ans": 3, "exp": "[อัปเดต FIGO 2023] ผนวก histologic type, grade, substantial LVSI, และ molecular classification (POLEmut/MMRd/NSMP/p53abn). POLEmut = พยากรณ์ดีสุด, p53abn = แย่สุด. สะท้อนพยากรณ์/การรักษาแม่นยำขึ้น."}, {"topic": "Gynecologic Oncology", "q": "What is the standard treatment of early-stage endometrial cancer?", "choices": ["Chemotherapy alone", "Radiotherapy alone", "Hormone therapy alone", "Observation only", "Hysterectomy, BSO, and surgical staging"], "ans": 4, "exp": "การรักษาหลักคือผ่าตัด: total hysterectomy + bilateral salpingo-oophorectomy + surgical staging (± node/sentinel node). เสริม adjuvant RT/chemo ตามระยะ/ความเสี่ยง/molecular. ผู้ต้องการมีบุตรระยะต้น grade ต่ำ อาจ high-dose progestin ชั่วคราว."}, {"topic": "Gynecologic Oncology", "q": "Which gynecologic cancer has the highest mortality, often diagnosed at a late stage?", "choices": ["Ovarian cancer", "Cervical cancer", "Vaginal cancer", "Endometrial cancer", "Vulvar cancer"], "ans": 0, "exp": "Ovarian cancer มีอัตราตายสูงสุด เพราะมักวินิจฉัยระยะท้าย — อาการไม่จำเพาะ ('silent killer': ท้องอืด อิ่มเร็ว ปัสสาวะบ่อย) และไม่มีวิธีคัดกรองที่ได้ผลในคนทั่วไป. Epithelial (high-grade serous) พบบ่อยสุด."}, {"topic": "Gynecologic Oncology", "q": "Which genetic mutation most increases the risk of epithelial ovarian cancer?", "choices": ["HPV integration", "BRCA1/BRCA2 mutation", "Cigarette exposure", "Thalassemia trait", "GDM"], "ans": 1, "exp": "BRCA1/BRCA2 mutation เพิ่มความเสี่ยงมะเร็งรังไข่ (และเต้านม) มาก — เป็นข้อบ่งชี้ risk-reducing salpingo-oophorectomy. Lynch syndrome ก็เพิ่มความเสี่ยง. ปัจจัยป้องกัน: combined OC, ตั้งครรภ์/ให้นม, ทำหมัน/salpingectomy."}, {"topic": "Gynecologic Oncology", "q": "Which tumor marker is used to monitor epithelial ovarian cancer?", "choices": ["AFP", "hCG", "CA-125", "LDH", "CEA only"], "ans": 2, "exp": "CA-125 ใช้ติดตามการรักษา/กลับเป็นซ้ำของ epithelial ovarian cancer (โดยเฉพาะ serous). ไม่จำเพาะ จึงไม่ใช้คัดกรองคนทั่วไป. Germ cell: dysgerminoma-LDH, yolk sac-AFP, choriocarcinoma-hCG. HE4+CA-125 (ROMA) ช่วยประเมิน."}, {"topic": "Gynecologic Oncology", "q": "An 18-year-old has a rapidly enlarging ovarian mass with a high AFP. Which tumor is likely?", "choices": ["Serous cystadenocarcinoma", "A Brenner tumor", "A granulosa cell tumor", "Yolk sac (endodermal sinus) tumor", "Mucinous cystadenoma"], "ans": 3, "exp": "หญิงสาว + ก้อนรังไข่โตเร็ว + AFP สูง = yolk sac (endodermal sinus) tumor (germ cell). Germ cell markers: dysgerminoma-LDH, choriocarcinoma-hCG, immature teratoma. Germ cell tumors ตอบสนองเคมี (BEP) ดี, ผ่าตัดเก็บ fertility ได้."}, {"topic": "Gynecologic Oncology", "q": "An ovarian tumor producing estrogen causing precocious puberty or postmenopausal bleeding, with elevated inhibin, is which type?", "choices": ["Dysgerminoma", "Yolk sac tumor", "Serous cystadenoma", "Krukenberg tumor", "Granulosa cell tumor"], "ans": 4, "exp": "Granulosa cell tumor (sex cord-stromal) สร้าง estrogen → precocious puberty (เด็ก), menorrhagia/hyperplasia (ผู้ใหญ่), postmenopausal bleeding. Marker: inhibin, AMH. Call-Exner bodies. โตช้าและกลับเป็นซ้ำได้."}, {"topic": "Gynecologic Oncology", "q": "An ovarian tumor producing androgens causing virilization is which type?", "choices": ["Sertoli-Leydig cell tumor", "Granulosa cell tumor", "Serous cystadenoma", "Dysgerminoma", "Dermoid cyst"], "ans": 0, "exp": "Sertoli-Leydig cell tumor (sex cord-stromal) สร้าง androgen → virilization: hirsutism, เสียงห้าว, clitoromegaly, amenorrhea. พบในหญิงสาว. ต่างจาก granulosa (estrogen). รักษาด้วยผ่าตัด (มัก unilateral, prognosis ดีระยะต้น)."}, {"topic": "Gynecologic Oncology", "q": "What is a Krukenberg tumor?", "choices": ["A primary ovarian carcinoma", "Metastasis to the ovary with signet-ring cells", "A benign ovarian tumor", "A functional ovarian cyst", "A germ cell tumor"], "ans": 1, "exp": "Krukenberg tumor = มะเร็งแพร่กระจายมารังไข่ทั้งสองข้าง (metastatic) จาก primary GI (โดยเฉพาะกระเพาะอาหาร) มี mucin-producing signet-ring cells. เมื่อพบก้อนรังไข่ที่สงสัย metastasis ต้องหา primary GI."}, {"topic": "Gynecologic Oncology", "q": "How is advanced ovarian cancer treated?", "choices": ["Radiotherapy alone", "Hormone therapy alone", "Debulking plus platinum chemotherapy", "Observation only", "A course of antibiotics"], "ans": 2, "exp": "Epithelial ovarian cancer ระยะลุกลาม: cytoreductive surgery (debulking optimal <1 cm) + platinum-based chemo (carboplatin+paclitaxel). [อัปเดต] PARP inhibitor maintenance ใน BRCA/HRD. Neoadjuvant chemo ก่อนผ่าตัดในบางราย."}, {"topic": "Gynecologic Oncology", "q": "Which drug class is used as maintenance in ovarian cancer with BRCA mutation/HRD?", "choices": ["Aromatase inhibitor", "Cisplatin alone", "Metformin", "PARP inhibitor", "Tamoxifen"], "ans": 3, "exp": "[อัปเดต] PARP inhibitor (olaparib, niraparib) เป็น maintenance หลัง platinum chemo ในมะเร็งรังไข่ BRCA mutation/HRD — อาศัย synthetic lethality (เซลล์ซ่อม DNA บกพร่องตายเมื่อยับยั้ง PARP). เพิ่ม progression-free survival."}, {"topic": "Gynecologic Oncology", "q": "What is the genetic profile of a complete hydatidiform mole?", "choices": ["Triploid with fetal tissue", "Trisomy 21", "Normal 46,XY", "Monosomy X", "Paternal-only 46,XX with no fetus"], "ans": 4, "exp": "Complete mole: มัก 46,XX จากพ่อทั้งหมด (androgenesis) ไม่มีเนื้อเยื่อทารก. hCG สูงมาก, snowstorm, theca lutein cysts, เสี่ยงกลายเป็น GTN สูงกว่า partial mole (triploid 69,XXX มีเนื้อเยื่อทารก)."}, {"topic": "Gynecologic Oncology", "q": "Which finding may be seen in a molar pregnancy?", "choices": ["Uterus larger than dates with very high hCG", "Persistent low blood pressure", "A high spiking fever", "Recurrent hypoglycemia", "Profuse watery diarrhea"], "ans": 0, "exp": "Molar pregnancy: เลือดออก, มดลูกโตกว่าอายุครรภ์, hCG สูงมาก, hyperemesis รุนแรง, theca lutein cysts, และภาวะจาก hCG สูง (hyperthyroidism, preeclampsia ก่อน 20 wk). US: snowstorm/ไม่พบทารก (complete)."}, {"topic": "Gynecologic Oncology", "q": "What is the initial treatment and follow-up of a hydatidiform mole?", "choices": ["Hysterectomy always", "Suction curettage with serial hCG", "Radiotherapy", "Immediate chemotherapy", "Await spontaneous abortion"], "ans": 1, "exp": "รักษา molar ด้วย suction curettage แล้วติดตาม serial β-hCG จนเป็นลบต่อเนื่อง (ตรวจต่อ ~6 เดือน) เพื่อจับ GTN. คุมกำเนิดระหว่างติดตาม (การตั้งครรภ์ใหม่ทำให้แปลผล hCG ไม่ได้). Rh negative ให้ anti-D."}, {"topic": "Gynecologic Oncology", "q": "After molar evacuation, beta-hCG plateaus or rises. What does this indicate?", "choices": ["Normal expected recovery", "A new intrauterine pregnancy", "GTN needing chemotherapy", "Developing preeclampsia", "An intrauterine infection"], "ans": 2, "exp": "β-hCG plateau (คงที่ ≥3 ค่า/3 สัปดาห์) หรือ rising หลัง evacuation บ่งชี้ persistent GTN (invasive mole/choriocarcinoma) → ประเมินระยะ (FIGO/WHO score) และรักษาด้วยเคมีบำบัด. แยกการตั้งครรภ์ใหม่ก่อน. GTN ตอบสนองเคมีดีมาก."}, {"topic": "Gynecologic Oncology", "q": "How does choriocarcinoma respond to treatment?", "choices": ["Resistant to all treatment", "It cannot be treated at all", "Responds only to hormone therapy", "Very responsive to chemotherapy, even if metastatic", "Requires radiotherapy only"], "ans": 3, "exp": "Choriocarcinoma ตอบสนองเคมีบำบัดดีมาก — low-risk GTN: single-agent (methotrexate/actinomycin D); high-risk: multi-agent (EMA-CO). อัตราหายสูงแม้แพร่กระจาย (ปอด สมอง) โดยติดตาม hCG. เป็นตัวอย่างมะเร็งที่รักษาหายด้วยเคมีบำบัดแม้ระยะแพร่กระจาย."}, {"topic": "Gynecologic Oncology", "q": "A 60-year-old has a chronic vulvar ulcer with squamous cell carcinoma on biopsy. In older women, which is a risk factor?", "choices": ["HPV only", "The oral contraceptive pill", "Pregnancy", "PCOS", "Lichen sclerosus"], "ans": 4, "exp": "Vulvar cancer (ส่วนใหญ่ SCC) 2 pathway: HPV-related (อายุน้อย) และ non-HPV related สัมพันธ์กับ lichen sclerosus/chronic inflammation ในผู้สูงอายุ. แผลเรื้อรังที่ vulva ต้อง biopsy. รักษาด้วยผ่าตัด (wide excision/vulvectomy + node) ± RT."}, {"topic": "Gynecologic Oncology", "q": "An ovarian fibroma with ascites and a pleural effusion that resolve after tumor removal describes which syndrome?", "choices": ["Meigs syndrome", "Sheehan syndrome", "Krukenberg syndrome", "Fitz-Hugh-Curtis syndrome", "Asherman syndrome"], "ans": 0, "exp": "Meigs syndrome = triad ของ ovarian fibroma (benign) + ascites + pleural effusion ซึ่งหายหมดหลังผ่าตัด. สำคัญเพราะเลียนแบบมะเร็งรังไข่ระยะลุกลาม (ก้อน + ascites + effusion + CA-125 สูงเล็กน้อย) แต่เป็น benign."}, {"topic": "Gynecologic Oncology", "q": "Primary and secondary prevention of cervical cancer are best represented by which pair?", "choices": ["Screening, then treatment", "HPV vaccine, then screening", "Treatment, then vaccine", "Surgery, then radiation", "No prevention available"], "ans": 1, "exp": "Primary prevention = วัคซีน HPV (ป้องกันการติดเชื้อ). Secondary = การคัดกรอง (Pap/HPV) ตรวจจับและรักษา precancer (CIN) ก่อนเป็นมะเร็ง. Tertiary = การรักษามะเร็ง. เป้า WHO 90-70-90."}, {"topic": "Gynecologic Oncology", "q": "A woman with Lynch syndrome (HNPCC) has an increased risk of which gynecologic cancers?", "choices": ["Cervical cancer", "Breast cancer", "Endometrial and ovarian cancer", "Vaginal cancer", "No increased risk"], "ans": 2, "exp": "Lynch syndrome (MMR gene mutation) เพิ่มความเสี่ยงมะเร็งลำไส้ใหญ่, เยื่อบุโพรงมดลูก ('sentinel cancer'), และรังไข่. แนะนำเฝ้าระวัง (endometrial sampling) และพิจารณา risk-reducing hysterectomy + BSO หลังมีบุตรครบ. ตรวจ MMR/MSI ในชิ้นเนื้อ."}, {"topic": "Gynecologic Oncology", "q": "A woman with a BRCA1 mutation wants to reduce ovarian cancer risk. What should be considered?", "choices": ["No intervention needed", "Hysterectomy alone", "Preventive chemotherapy", "Risk-reducing salpingo-oophorectomy after childbearing", "Preventive radiotherapy"], "ans": 3, "exp": "[อัปเดต] ผู้มี BRCA1/2 แนะนำ risk-reducing bilateral salpingo-oophorectomy หลังมีบุตรครบ (BRCA1 ~35-40 ปี) ลดความเสี่ยงมะเร็งรังไข่/ท่อนำไข่ ~80% และลดมะเร็งเต้านม. ทางเลือกใหม่: salpingectomy ก่อนแล้ว oophorectomy ทีหลัง กำลังศึกษา."}, {"topic": "Gynecologic Oncology", "q": "Which HPV types does the 9-valent vaccine add beyond the quadrivalent vaccine?", "choices": ["None additional", "Only 6 and 11", "Herpes types", "Only 16 and 18", "31, 33, 45, 52, 58"], "ans": 4, "exp": "9-valent ครอบคลุม HPV 6, 11 (หูด) + 16, 18 (มะเร็ง) เหมือน quadrivalent และเพิ่ม high-risk 31, 33, 45, 52, 58 → ป้องกันมะเร็งปากมดลูกครอบคลุมขึ้น (~90%). Bivalent ครอบคลุม 16, 18."}, {"topic": "Gynecologic Oncology", "q": "Which malignant ovarian germ cell tumor is the most common and radiosensitive?", "choices": ["Dysgerminoma", "Yolk sac tumor", "Choriocarcinoma", "Immature teratoma", "Embryonal carcinoma"], "ans": 0, "exp": "Dysgerminoma เป็น malignant germ cell tumor ที่พบบ่อยสุด พบในหญิงสาว, marker LDH (± hCG เล็กน้อย), ไวต่อทั้งเคมี (BEP) และรังสี. เทียบเท่า seminoma. มัก unilateral ระยะต้น, ผ่าตัดเก็บ fertility + เคมี, พยากรณ์ดี."}, {"topic": "Gynecologic Oncology", "q": "Which epithelial ovarian cancer is the most common and most aggressive?", "choices": ["Mucinous carcinoma", "High-grade serous carcinoma", "Endometrioid carcinoma", "Clear cell carcinoma", "Brenner tumor"], "ans": 1, "exp": "High-grade serous carcinoma พบบ่อยสุด (~70% ของ epithelial) และร้ายแรง — วินิจฉัยระยะลุกลาม, สัมพันธ์ BRCA/TP53, หลายรายเริ่มจาก fallopian tube (STIC). ตอบสนอง platinum. ชนิดอื่น: mucinous, endometrioid/clear cell (สัมพันธ์ endometriosis)."}, {"topic": "Gynecologic Oncology", "q": "Many high-grade serous 'ovarian' cancers are now thought to originate where?", "choices": ["Endometrium alone", "Vagina", "Fallopian tube (STIC)", "Cervix", "Breast tissue"], "ans": 2, "exp": "หลักฐานปัจจุบันชี้ว่า high-grade serous 'ovarian' cancer จำนวนมากเริ่มจาก fimbrial end ของ fallopian tube (serous tubal intraepithelial carcinoma - STIC) แล้วลุกลามมารังไข่/เยื่อบุช่องท้อง. จึง opportunistic/risk-reducing salpingectomy ช่วยลดความเสี่ยง."}, {"topic": "Gynecologic Oncology", "q": "How is high-grade vulvar intraepithelial neoplasia (VIN) treated?", "choices": ["No treatment needed", "A total hysterectomy", "Systemic chemotherapy", "Wide local excision or laser", "Pelvic radiotherapy"], "ans": 3, "exp": "VIN high-grade เป็น precancer ของ vulva. รักษาด้วย wide local excision (โดยเฉพาะ differentiated VIN เสี่ยงมะเร็งสูง), laser ablation, หรือ topical imiquimod (usual type). ติดตามใกล้ชิดเพราะเสี่ยง vulvar SCC. เลิกบุหรี่/รักษา lichen sclerosus ช่วยลดความเสี่ยง."}, {"topic": "Gynecologic Oncology", "q": "What is the classic triad of fallopian tube carcinoma (hydrops tubae profluens)?", "choices": ["Pain, fever, and vaginal bleeding", "Back pain, leg swelling, fatigue", "Nausea, vomiting, and diarrhea", "No classic triad exists", "Watery/bloody discharge, pain, adnexal mass"], "ans": 4, "exp": "มะเร็งท่อนำไข่ (พบน้อย, ส่วนใหญ่ serous, สัมพันธ์ BRCA) — triad 'hydrops tubae profluens': ตกขาว/เลือดออกเป็นน้ำเป็นระยะ + ปวดท้องน้อย + ก้อนที่ปีกมดลูก (ยุบหลังของเหลวระบาย). ปัจจุบันจัดรวมกับมะเร็งรังไข่/peritoneal."}, {"topic": "Gynecologic Oncology", "q": "Which landmark trial supports tranexamic acid use in postpartum hemorrhage?", "choices": ["WOMAN trial", "Term Breech Trial", "ARRIVE trial", "Hypitat trial", "MAGPIE trial"], "ans": 0, "exp": "[อัปเดต] WOMAN trial แสดงว่า TXA (1 g IV ภายใน 3 ชม.) ลดการตายจากเลือดออกใน PPH → WHO/FIGO แนะนำเป็นการรักษามาตรฐาน. (MAGPIE = MgSO4 ใน preeclampsia; ARRIVE = induction 39 wk; Term Breech Trial = ผ่าคลอดท่าก้น)."}, {"topic": "Gynecologic Oncology", "q": "Which trial supports the use of magnesium sulfate to prevent eclampsia in preeclampsia?", "choices": ["Aspirin in GDM", "MAGPIE trial", "Insulin in GDM", "WOMAN trial", "Steroid in preterm"], "ans": 1, "exp": "MAGPIE trial แสดงว่า magnesium sulfate ลดความเสี่ยง eclamptic seizure ในหญิง preeclampsia อย่างมีนัยสำคัญ → หลักฐานสนับสนุน MgSO4 เป็นยาป้องกัน/รักษาชักมาตรฐาน (เหนือกว่า diazepam/phenytoin)."}, {"topic": "Gynecologic Oncology", "q": "A woman has biopsy-confirmed CIN 1 (low-grade). What is the appropriate management for most patients?", "choices": ["Immediate LEEP", "Radiation", "Observation (surveillance)", "Hysterectomy", "Chemotherapy"], "ans": 2, "exp": "CIN 1 ส่วนใหญ่ (~60%) regress เองใน 1-2 ปี (สะท้อนการติดเชื้อ HPV ชั่วคราว) → ติดตาม (surveillance ด้วย co-testing). รักษา (excision/ablation) ถ้า CIN 1 คงอยู่นาน (≥2 ปี) หรือมี high-grade cytology นำมาก่อน. ต่างจาก CIN 2/3."}, {"topic": "Gynecologic Oncology", "q": "Using the one-step 75 g OGTT, how many abnormal values are needed to diagnose gestational diabetes?", "choices": ["One value at 200", "Two abnormal values", "All three values", "One abnormal value", "This test is not used"], "ans": 3, "exp": "One-step 75 g OGTT (IADPSG/WHO): วินิจฉัย GDM เมื่อผิดปกติเพียง ≥1 ค่า — FBS ≥92, 1hr ≥180, 2hr ≥153. ให้อัตราวินิจฉัยสูงกว่า two-step (100 g ต้อง ≥2 ค่า). เป็นประเด็นที่ ACOG ทบทวน."}, {"topic": "Gynecologic Oncology", "q": "A Brenner tumor of the ovary is usually of which nature?", "choices": ["Always malignant", "A germ cell tumor", "Androgen-secreting", "A metastasis", "Mostly benign"], "ans": 4, "exp": "Brenner tumor เป็น surface epithelial-stromal tumor ที่มี transitional-type epithelium ('coffee-bean' nuclei) — ส่วนใหญ่ benign, มักพบโดยบังเอิญ, solid, เล็ก. Borderline/malignant Brenner พบน้อย."}, {"topic": "Gynecologic Oncology", "q": "What is a recognized complication of radical hysterectomy for cervical cancer?", "choices": ["Bladder dysfunction and ureteral injury", "No complications occur", "Sensorineural deafness", "Sudden blindness", "Diffuse hair loss"], "ans": 0, "exp": "Radical hysterectomy (มดลูก + parametrium + upper vagina + pelvic node) มีภาวะแทรกซ้อน: bladder dysfunction (จากการเลาะ autonomic nerve), ureteral injury/fistula, lymphedema/lymphocyst, เลือดออก. Nerve-sparing ลดภาวะกระเพาะปัสสาวะ."}, {"topic": "Gynecologic Oncology", "q": "What is the advantage of sentinel lymph node biopsy in gynecologic cancers?", "choices": ["It has no real benefit", "Reduces full node dissection and lymphedema", "It increases metastasis", "It replaces surgery entirely", "It replaces chemotherapy"], "ans": 1, "exp": "Sentinel lymph node mapping (dye/tracer หา node แรก) ใช้ในมะเร็งเยื่อบุมดลูก, ปากมดลูกระยะต้น, vulva — ประเมิน node status แม่นยำโดยไม่ต้องเลาะทั้งหมด จึงลด lymphedema. SLN บวก → full lymphadenectomy/adjuvant."}, {"topic": "Gynecologic Oncology", "q": "How is an immature teratoma of the ovary (malignant germ cell) treated?", "choices": ["Observation only", "Radiotherapy alone", "Surgery (fertility-sparing) plus chemotherapy", "Hormone therapy alone", "A course of antibiotics"], "ans": 2, "exp": "Immature teratoma เป็น malignant germ cell tumor. รักษาด้วยผ่าตัด — มัก fertility-sparing (unilateral salpingo-oophorectomy + staging) เพราะพบในหญิงสาวและมัก unilateral — ตามด้วย BEP chemotherapy ในรายที่ grade สูง/ระยะลุกลาม. พยากรณ์ดี."}, {"topic": "Gynecologic Oncology", "q": "An MMR-deficient endometrial cancer prompts which additional consideration?", "choices": ["No further action needed", "Hormone therapy", "Prophylactic radiotherapy", "Genetic counseling for Lynch syndrome", "Prophylactic mastectomy"], "ans": 3, "exp": "Endometrial cancer ที่ MMR-deficient (โดยเฉพาะไม่ได้เกิดจาก MLH1 methylation) ควรประเมิน Lynch syndrome (genetic counseling/germline testing) — endometrial มักเป็น sentinel cancer ของ Lynch. [อัปเดต] MMRd/MSI-high ยังทำนายการตอบสนองต่อ immunotherapy."}, {"topic": "Gynecologic Oncology", "q": "Which new therapy is effective in MMR-deficient/MSI-high endometrial cancer?", "choices": ["Hormone therapy", "Aspirin therapy", "A course of antibiotics", "A bisphosphonate", "An immune checkpoint inhibitor"], "ans": 4, "exp": "[อัปเดต] เนื้องอก MMR-deficient/MSI-high (รวม endometrial cancer จำนวนมาก) มี tumor mutational burden สูงและตอบสนองต่อ immune checkpoint inhibitor (anti-PD-1 เช่น pembrolizumab/dostarlimab) — ทางเลือกในระยะลุกลาม/กลับเป็นซ้ำ. การตรวจ MMR/MSI สำคัญทั้ง Lynch และเลือก immunotherapy."}, {"topic": "Gynecologic Oncology", "q": "According to Thai (RTCOG) guidance, at what age should cervical cancer screening begin?", "choices": ["Age 25", "Age 18", "Age 35", "Age 30", "Age 40"], "ans": 0, "exp": "[อัปเดต] RTCOG/ไทย แนะนำเริ่มคัดกรองมะเร็งปากมดลูกที่อายุ 25 ปี (สอดคล้องแนวโน้มสากลที่เลื่อนจาก 21 เป็น 25). วิธี: cytology ทุก 2 ปี หรือ HPV/co-testing ทุก 5 ปี (≥30 ปีเน้น HPV)."}, {"topic": "Gynecologic Oncology", "q": "A woman is HPV-positive (non-16/18) with normal cytology. What is the appropriate management?", "choices": ["Immediate colposcopy", "Repeat co-testing in 1 year", "LEEP", "Hysterectomy", "No follow-up"], "ans": 1, "exp": "HPV positive (non-16/18) + cytology ปกติ → ความเสี่ยงทันทีต่ำ, repeat testing ใน ~1 ปี (surveillance). HPV 16/18 positive → colposcopy แม้ cytology ปกติ. cytology ผิดปกติร่วม → colposcopy. จัดการแบบ risk-based (ASCCP)."}, {"topic": "Gynecologic Oncology", "q": "Cervical cancer screening can generally be stopped after age 65 under which condition?", "choices": ["Screening should never stop", "Only after a hysterectomy", "Adequate prior negative screening with no CIN history", "Only if never sexually active", "Only after menopause"], "ans": 2, "exp": "หยุดคัดกรองเมื่ออายุ >65 ปี ในผู้ที่มีผลก่อนหน้าปกติเพียงพอและไม่มีประวัติ CIN2+ ใน 25 ปี. ผู้ตัดมดลูก (รวมปากมดลูก) จาก benign และไม่มีประวัติ high-grade ก็ไม่ต้องคัดกรองต่อ. ผู้ไม่เคยคัดกรอง/ประวัติผิดปกติยังต้องตรวจ."}, {"topic": "Gynecologic Oncology", "q": "A woman with stage IA1 cervical cancer who desires fertility is best managed with which option?", "choices": ["Radical hysterectomy always", "No treatment", "Chemotherapy", "Cone biopsy with negative margins", "Radiotherapy"], "ans": 3, "exp": "มะเร็งปากมดลูกระยะ IA1 (invasion <3 mm, ไม่มี LVSI) ในผู้ต้องการมีบุตร รักษาแบบ fertility-sparing ด้วย cervical conization (cone biopsy) ถ้า margin ปลอดภัย. ระยะสูงขึ้น (IA2-IB1) อาจใช้ radical trachelectomy + node. ไม่ต้องการมีบุตร: simple/radical hysterectomy."}, {"topic": "Gynecologic Oncology", "q": "A postmenopausal woman with bleeding and endometrial carcinoma on biopsy needs which next step?", "choices": ["Observation without treatment", "Hormone therapy alone", "A course of antibiotics", "Serum CA-125 alone", "Staging and surgical planning by a specialist"], "ans": 4, "exp": "เมื่อยืนยัน endometrial carcinoma → ประเมินการแพร่กระจาย (imaging ตามข้อบ่งชี้) และวางแผนผ่าตัด staging: hysterectomy + BSO + surgical staging (± node/sentinel) โดยผู้เชี่ยวชาญ. adjuvant ตามระยะ/grade/molecular. ส่งต่อ gyn-oncologist ในรายเสี่ยงสูง."}, {"topic": "Gynecologic Oncology", "q": "What characterizes type II endometrial cancer (serous/clear cell)?", "choices": ["Non-estrogen-dependent, worse prognosis", "Estrogen-dependent, good prognosis", "Associated with HPV", "Occurs in adolescents", "Is benign"], "ans": 0, "exp": "Type II (serous, clear cell, carcinosarcoma) — ไม่ขึ้นกับ estrogen, พบในผู้สูงอายุ/ผอมกว่า, มัก high-grade, p53-abnormal, พยากรณ์แย่กว่า type I, แพร่กระจายเร็ว (คล้ายมะเร็งรังไข่ serous). ต้องการการรักษาเข้มข้นกว่า (staging เต็ม + chemo)."}, {"topic": "Gynecologic Oncology", "q": "In a molar pregnancy, what causes large bilateral theca lutein cysts?", "choices": ["A concurrent pelvic infection", "Stimulation by very high hCG", "Coexisting ovarian cancer", "Underlying endometriosis", "An unrecognized twin gestation"], "ans": 1, "exp": "Theca lutein cysts (มัก bilateral, multicystic) เกิดจากการกระตุ้นรังไข่ด้วย hCG ที่สูงมากใน molar (หรือ multiple gestation, OHSS). มักหายเองหลัง hCG ลดลง — conservative (ไม่ต้องผ่าตัดยกเว้นแตก/torsion)."}, {"topic": "Gynecologic Oncology", "q": "A 55-year-old has a solid ovarian mass with CA-125 of 500 and ascites. What preoperative step is appropriate?", "choices": ["No assessment", "Immediate chemotherapy without diagnosis", "Imaging and referral to gyn-oncologist", "Drain ascites only", "Hormone therapy"], "ans": 2, "exp": "ก้อนรังไข่สงสัยมะเร็งในวัยหมดประจำเดือน (solid, CA-125 สูง, ascites) — ประเมินก่อนผ่าตัดด้วย imaging (CT/MRI ประเมิน extent, แยก primary GI) และส่ง gyn-oncologist เพื่อวางแผน cytoreduction + staging หรือ neoadjuvant chemo. การผ่าตัดโดยผู้เชี่ยวชาญเพิ่ม survival."}, {"topic": "Gynecologic Oncology", "q": "How should ovarian cancer screening be approached in average-risk women?", "choices": ["Yearly CA-125 and ultrasound", "Yearly Pap smear", "Yearly MRI", "Screening is not recommended", "Prophylactic surgery"], "ans": 3, "exp": "ไม่แนะนำคัดกรองมะเร็งรังไข่ในหญิงความเสี่ยงปกติ (CA-125/TVS ไม่ลด mortality และ false positive สูง → ผ่าตัดโดยไม่จำเป็น). ผู้เสี่ยงสูง (BRCA/Lynch) พิจารณา RRSO มากกว่าคัดกรอง. ต่างจากมะเร็งปากมดลูก/เต้านมที่มีการคัดกรองที่ได้ผล."}, {"topic": "Gynecologic Oncology", "q": "How is low-risk GTN (WHO score below 7) treated?", "choices": ["Multi-agent EMA-CO chemotherapy", "Pelvic radiotherapy", "Hysterectomy alone", "Hormone therapy", "Single-agent methotrexate or actinomycin D"], "ans": 4, "exp": "Low-risk GTN (FIGO/WHO score ≤6): single-agent chemotherapy — methotrexate (± folinic acid) หรือ actinomycin D — อัตราหายเกือบ 100%. High-risk (≥7) ใช้ multi-agent (EMA-CO). ติดตาม β-hCG จนเป็นลบและคุมกำเนิด ~1 ปี."}, {"topic": "Gynecologic Oncology", "q": "What does the WHO '90-70-90' strategy for cervical cancer elimination represent?", "choices": ["Vaccinate 90%, screen 70%, treat 90%", "Three stages of cervical cancer", "Expected survival rates", "The number of vaccine doses", "Vaccine drug pricing tiers"], "ans": 0, "exp": "WHO 90-70-90 (ภายในปี 2030): เด็กหญิงได้วัคซีน HPV ครบก่อน 15 ปี 90%, ผู้หญิงได้รับการคัดกรองด้วยวิธีประสิทธิภาพสูง (HPV test) ที่ 35 และ 45 ปี 70%, และผู้พบความผิดปกติ/มะเร็งได้รับการรักษา 90%."}, {"topic": "Gynecologic Oncology", "q": "A pregnant woman is found to have advanced cervical cancer in the first trimester. What must guide management?", "choices": ["Normal vaginal delivery in all cases", "Multidisciplinary care weighing maternal vs fetal needs", "Wait until term in every case", "Immediate chemotherapy for all", "No treatment at all"], "ans": 1, "exp": "มะเร็งปากมดลูกในครรภ์ซับซ้อน ต้องดูแลโดยทีมสหสาขา (gyn-onc, MFM, neonatology) และให้คำปรึกษาผู้ป่วย. ตัดสินใจตามระยะโรค/อายุครรภ์/ความต้องการ — อาจต้องเลือกระหว่างรักษาทันที (อาจยุติการตั้งครรภ์) หรือเลื่อนเพื่อให้ทารกโตพอ."}, {"topic": "Gynecologic Oncology", "q": "A woman with a granulosa cell tumor producing estrogen needs which additional evaluation?", "choices": ["No further evaluation needed", "Routine cervical screening", "Endometrial assessment for hyperplasia", "HPV testing", "A pregnancy test"], "ans": 2, "exp": "Granulosa cell tumor สร้าง estrogen → unopposed estrogen เสี่ยง endometrial hyperplasia/มะเร็งร่วม (~5-25%). เมื่อวินิจฉัย (โดยเฉพาะมี abnormal bleeding) ต้องประเมิน endometrium (biopsy). Marker: inhibin/AMH. โตช้าและกลับเป็นซ้ำได้."}, {"topic": "Gynecologic Oncology", "q": "Vaginal clear cell adenocarcinoma is associated with which factor?", "choices": ["HPV", "Smoking", "BRCA mutation", "In-utero DES exposure", "Oral contraceptives"], "ans": 3, "exp": "Vaginal clear cell adenocarcinoma สัมพันธ์กับ in utero DES exposure (มารดาได้ DES ขณะตั้งครรภ์). พบในหญิงสาว. มะเร็งช่องคลอด SCC (พบบ่อยกว่า) สัมพันธ์ HPV. DES เลิกใช้แล้วแต่เป็นความรู้คลาสสิก."}, {"topic": "Gynecologic Oncology", "q": "Which symptoms should raise suspicion for ovarian cancer, even though nonspecific?", "choices": ["A persistent headache", "A widespread skin rash", "Pleuritic chest pain", "Diffuse joint pain", "Bloating and early satiety"], "ans": 4, "exp": "อาการมะเร็งรังไข่มักคลุมเครือ ('silent'): ท้องอืด/ท้องโต, แน่นท้อง/อิ่มเร็ว (early satiety), ปวดท้องน้อย, ปัสสาวะบ่อย/รีบ ที่เป็นเรื้อรังและใหม่ในหญิง >50 ปี ควรประเมิน (US + CA-125). Ascites/ก้อนบ่งชี้ระยะลุกลาม."}, {"topic": "Gynecologic Oncology", "q": "In FIGO 2023 endometrial molecular classification, which subtype has the best prognosis?", "choices": ["POLE-mutated", "p53-abnormal", "MMR-deficient", "NSMP", "All are equal"], "ans": 0, "exp": "[อัปเดต FIGO 2023] Molecular 4 กลุ่ม: POLEmut = พยากรณ์ดีสุด (แม้ grade สูง, อาจ de-escalate การรักษา); MMRd/NSMP = ปานกลาง; p53abn = แย่สุด (มัก serous, รักษาเข้มข้น). ช่วยวางแผนการรักษาแม่นยำขึ้น."}, {"topic": "Gynecologic Oncology", "q": "A 32-year-old with early grade 1 endometrial cancer wants to preserve fertility. What is an option?", "choices": ["Hysterectomy alone", "High-dose progestin with close monitoring", "Systemic chemotherapy", "Pelvic radiotherapy", "No treatment option exists"], "ans": 1, "exp": "หญิงสาว endometrial cancer ระยะต้น (grade 1, endometrioid, ไม่มี myometrial invasion/แพร่กระจาย) ที่ต้องการ fertility อาจ fertility-sparing ด้วย high-dose progestin (megestrol/medroxyprogesterone หรือ LNG-IUS) + endometrial sampling ทุก 3-6 เดือน. มีบุตรครบ → hysterectomy. คัดเลือกผู้ป่วยเข้มงวด."}, {"topic": "Gynecologic Oncology", "q": "A suspicious ovarian mass (solid, papillary, ascites) is best managed by which approach?", "choices": ["Simple cyst aspiration", "Routine follow-up in one year", "Refer to a gyn-oncologist for staging", "A course of antibiotics", "Hormone therapy"], "ans": 2, "exp": "ก้อนรังไข่สงสัยมะเร็งควรส่ง gyn-oncologist เพื่อ surgical staging/cytoreduction (เพิ่ม survival). ไม่ควรเจาะดูด/ผ่าก้อนแบบไม่วางแผน (เสี่ยง spillage → upstage). ประเมินก่อนผ่าด้วย imaging + tumor markers (CA-125 ± HE4/ROMA, germ cell markers ตามอายุ)."}, {"topic": "Gynecologic Oncology", "q": "A large mucinous ovarian tumor ruptures, leaving gelatinous mucin in the abdomen. What is this called?", "choices": ["Meigs syndrome", "Krukenberg tumor", "Simple ascites", "Pseudomyxoma peritonei", "Endometriosis"], "ans": 3, "exp": "Pseudomyxoma peritonei = การสะสม mucinous material ('jelly belly') ในช่องท้อง — ปัจจุบันเชื่อว่าส่วนใหญ่มาจาก appendiceal mucinous neoplasm มากกว่ารังไข่. รักษาด้วย cytoreductive surgery + HIPEC. โตช้าแต่กลับเป็นซ้ำ."}, {"topic": "Gynecologic Oncology", "q": "How is high-grade or serous endometrial cancer managed compared with type I?", "choices": ["Managed identically to type I", "Observation without treatment", "Hormone therapy alone", "No surgery at all", "Full staging plus chemotherapy"], "ans": 4, "exp": "Type II (serous/clear cell/carcinosarcoma, p53abn) แพร่กระจายเร็วคล้ายมะเร็งรังไข่ — ต้อง comprehensive staging (hysterectomy + BSO + node + omentectomy + washing) และมัก adjuvant chemotherapy (± RT) แม้ระยะดูต้น. ต่างจาก type I grade ต่ำ. FIGO 2023 molecular guiding treatment."}, {"topic": "Gynecologic Oncology", "q": "What is the aim of the WHO 2016 antenatal care model?", "choices": ["Improve ANC to reduce perinatal death", "To reduce healthcare cost", "To reduce the number of visits", "To abolish antenatal care", "Only for high-risk women"], "ans": 0, "exp": "[อัปเดต] WHO 2016 ANC เพิ่มเป็น ≥8 contacts (จาก 4) โดยเน้นทั้งการดูแลทางการแพทย์และ positive pregnancy experience → ลด perinatal mortality และเพิ่มการเข้าถึง. ไทยปรับใช้แนวทางฝากครรภ์คุณภาพตามหลักนี้."}, {"topic": "Gynecologic Oncology", "q": "A borderline ovarian tumor (low malignant potential) has which characteristic?", "choices": ["Rapid spread with poor prognosis", "Atypia without stromal invasion, good prognosis", "A distant metastatic deposit", "A completely benign lesion", "A malignant germ cell tumor"], "ans": 1, "exp": "Borderline ovarian tumor: มี epithelial atypia แต่ 'ไม่มี stromal invasion' (destructive). พบในหญิงอายุน้อยกว่า, มักระยะต้น, พยากรณ์ดีมาก. รักษาด้วยผ่าตัด (fertility-sparing ระยะต้น); โดยทั่วไปไม่ต้องเคมี. ติดตามระยะยาว."}, {"topic": "Gynecologic Oncology", "q": "A woman previously treated for GTN is now pregnant again. What follow-up is appropriate?", "choices": ["No special care", "Terminate the pregnancy", "Early ultrasound and postpartum hCG", "Prophylactic chemotherapy", "Cesarean for all"], "ans": 2, "exp": "ผู้เคยเป็น GTN/molar เสี่ยง molar/GTN ซ้ำเพิ่ม — ครรภ์ถัดไปควรทำ early US (ไตรมาสแรก) ยืนยันครรภ์ปกติ, ตรวจ placental pathology, และตรวจ β-hCG ~6 สัปดาห์หลังสิ้นสุดครรภ์เพื่อเฝ้าระวังการกลับเป็นซ้ำ."}, {"topic": "Gynecologic Oncology", "q": "Vaginal intraepithelial neoplasia (VAIN) is related to which factor and managed how?", "choices": ["Not HPV-related; always surgery", "Hormonal; treat with estrogen", "Bacterial; treat with antibiotics", "HPV-related; laser/topical/excision with follow-up", "It is never treated"], "ans": 3, "exp": "VAIN เป็น precancer ของช่องคลอด สัมพันธ์ HPV (คล้าย CIN/VIN), มักพบร่วม/หลัง cervical neoplasia. รักษาตามระดับ: observation (low-grade), laser/topical (5-FU, imiquimod)/excision (high-grade). ติดตามเพราะเสี่ยง vaginal cancer. ตัดมดลูกแล้วยังเฝ้าระวัง vaginal cuff."}, {"topic": "Gynecologic Oncology", "q": "Advanced ovarian cancer not amenable to optimal primary debulking is best managed with which approach?", "choices": ["No treatment at all", "Observation without treatment", "Radiotherapy alone", "Hormone therapy", "Neoadjuvant chemo, interval debulking"], "ans": 4, "exp": "เมื่อผ่าตัด optimal cytoreduction ตั้งแต่แรกไม่ได้ (หรือผู้ป่วยไม่พร้อม) → neoadjuvant chemotherapy (carboplatin+paclitaxel 3 cycles) ลดขนาดก้อน แล้ว interval debulking surgery + เคมีต่อ. ผลเทียบเท่า primary debulking ในกลุ่มเหมาะสม, ลด surgical morbidity. ยืนยันวินิจฉัยด้วย biopsy ก่อน."}, {"topic": "Gynecologic Oncology", "q": "When transvaginal ultrasound is inconclusive in postmenopausal bleeding, which test best clarifies the diagnosis?", "choices": ["Hysteroscopy with biopsy", "CA-125", "MRI for all", "Pap smear", "Urinalysis"], "ans": 0, "exp": "เมื่อ TVS ไม่ชัด/endometrium ประเมินยาก หรือ office biopsy ไม่พอ/เลือดออกซ้ำ → hysteroscopy + biopsy/D&C ช่วยวินิจฉัยรอยโรคเฉพาะที่ (polyp, focal lesion, มะเร็ง) ได้ดีกว่า blind sampling. Postmenopausal bleeding ต้องได้ข้อวินิจฉัยทางเนื้อเยื่อ."}, {"topic": "Gynecologic Oncology", "q": "How is stage IB2 cervical cancer (tumor 2-4 cm) treated?", "choices": ["Conization alone", "Radical surgery or chemoradiation", "Observation without treatment", "Hormone therapy", "A course of antibiotics"], "ans": 1, "exp": "มะเร็งปากมดลูกระยะต้น (IB1-IB2, IIA1) รักษาด้วย radical hysterectomy + pelvic lymphadenectomy หรือ definitive chemoradiation — ผลเทียบเท่ากัน. ระยะก้อนใหญ่ (IB3 ≥4 cm) หรือลุกลามกว่านิยม chemoradiation เพื่อเลี่ยงการรักษาซ้ำซ้อน."}, {"topic": "Gynecologic Oncology", "q": "According to the LACC trial, minimally invasive radical hysterectomy for early cervical cancer showed what?", "choices": ["Better than open surgery", "Surgery is contraindicated", "Worse survival than open surgery", "No difference", "Not relevant"], "ans": 2, "exp": "[อัปเดต LACC trial] minimally invasive radical hysterectomy ให้ disease-free/overall survival 'แย่กว่า' open (abdominal) radical hysterectomy ในมะเร็งปากมดลูกระยะต้น → แนวทางปัจจุบันแนะนำ open approach เป็นมาตรฐาน. เป็นการเปลี่ยน practice สำคัญ."}, {"topic": "Gynecologic Oncology", "q": "A young woman with a suspected germ cell ovarian tumor should have which tumor markers checked?", "choices": ["Serum CA-125 alone", "Serum CEA", "Serum PSA", "AFP, beta-hCG, and LDH", "Serum CA 19-9"], "ans": 3, "exp": "หญิงสาวที่สงสัย germ cell tumor: AFP (yolk sac, embryonal), β-hCG (choriocarcinoma, dysgerminoma บางส่วน), LDH (dysgerminoma). อาจเพิ่ม inhibin/AMH (sex cord-stromal). CA-125 เหมาะ epithelial (สูงอายุ). เลือก marker ตามอายุ/ลักษณะก้อน."}, {"topic": "Gynecologic Oncology", "q": "Endometrioid ovarian carcinoma is most associated with which condition?", "choices": ["HPV", "Thalassemia", "GDM", "Smoking", "Endometriosis"], "ans": 4, "exp": "Endometrioid (และ clear cell) ovarian carcinoma สัมพันธ์กับ endometriosis (malignant transformation). Endometrioid ยังพบร่วม synchronous endometrial cancer ได้ (~15-20%) — ควรประเมิน endometrium. สะท้อนความเชื่อมโยง endometriosis กับมะเร็งบางชนิด."}, {"topic": "Gynecologic Oncology", "q": "Magnesium sulfate for fetal neuroprotection is recommended when delivery is anticipated before which gestational age?", "choices": ["32 weeks", "37 weeks", "34 weeks", "28 weeks", "24 weeks"], "ans": 0, "exp": "[อัปเดต] MgSO4 เพื่อ fetal neuroprotection (ลด cerebral palsy) เมื่อคาดว่าจะคลอดก่อน GA 32 wk — คนละบทบาทกับ MgSO4 ใน preeclampsia (ป้องกันชัก ทุกอายุครรภ์ที่ severe). ร่วมกับ steroid และ GBS prophylaxis/tocolytic."}, {"topic": "Gynecologic Oncology", "q": "A 54-year-old with bothersome hot flashes and no contraindications is best treated with which option (NAMS 2022)?", "choices": ["No treatment", "Systemic hormone therapy", "Antibiotics", "Bisphosphonate alone", "Surgery"], "ans": 1, "exp": "[อัปเดต NAMS 2022] หญิงอายุ 54 ปี (<60, <10 ปีหลังหมดประจำเดือน) ที่มี bothersome VMS และไม่มีข้อห้าม → systemic hormone therapy ได้ผลดีสุด, benefit-risk ดี (มีมดลูกใช้ estrogen+progestogen). ทางเลือก non-hormonal (SSRI/SNRI, gabapentin, fezolinetant) สำหรับผู้มีข้อห้าม."}, {"topic": "Gynecologic Oncology", "q": "How is stage IVB cervical cancer (distant metastasis) treated?", "choices": ["Radical surgical resection", "Hormone therapy", "Systemic therapy with palliative intent", "Observation only", "Conization alone"], "ans": 2, "exp": "มะเร็งปากมดลูกระยะ IVB (แพร่กระจายไกล) รักษาด้วย systemic therapy: platinum chemo + bevacizumab และ [อัปเดต] immunotherapy (pembrolizumab สำหรับ PD-L1 positive) — palliative เพื่อยืดชีวิต/คุมอาการ. RT ประคับประคอง (เลือดออก/ปวด). พยากรณ์ไม่ดี."}, {"topic": "Gynecologic Oncology", "q": "GTN with lung metastasis has which prognosis and treatment?", "choices": ["Very poor and untreatable", "Radiotherapy alone", "Requires lung resection", "Still very chemosensitive with good prognosis", "Hormone therapy"], "ans": 3, "exp": "GTN (โดยเฉพาะ choriocarcinoma) แม้แพร่กระจาย (ปอดพบบ่อยสุด) ยังตอบสนองเคมีบำบัดดีมากและรักษาหายได้สูง. ใช้ FIGO/WHO risk score แบ่ง low-risk (single-agent) vs high-risk (EMA-CO). ติดตามด้วย β-hCG. ตัวอย่างมะเร็งแพร่กระจายที่พยากรณ์ดี."}, {"topic": "Gynecologic Oncology", "q": "A woman on tamoxifen for breast cancer should be monitored for which gynecologic cancer?", "choices": ["Cervical cancer", "Ovarian cancer", "Vaginal cancer", "No increased risk", "Endometrial cancer"], "ans": 4, "exp": "Tamoxifen (SERM) ต้าน estrogen ที่เต้านมแต่ 'กระตุ้น' estrogen ที่ endometrium → เพิ่มความเสี่ยง endometrial hyperplasia/polyp/มะเร็ง. ผู้ใช้ tamoxifen ที่มี abnormal bleeding ต้องประเมิน endometrium. ไม่แนะนำ routine screening ในผู้ไม่มีอาการ แต่ให้ความรู้เรื่องสัญญาณเตือน."}, {"topic": "Gynecologic Oncology", "q": "What is the principle of 'synthetic lethality' underlying PARP inhibitors in BRCA-mutated ovarian cancer?", "choices": ["BRCA-mutant cells die when PARP is also inhibited", "It kills all cells indiscriminately", "It enhances DNA repair", "It stimulates the immune system", "It blocks hormone receptors"], "ans": 0, "exp": "Synthetic lethality: เซลล์มะเร็ง BRCA-mutant ซ่อม double-strand break (homologous recombination) ไม่ได้ — เมื่อให้ PARP inhibitor (ยับยั้งการซ่อม single-strand break) เซลล์สะสมความเสียหาย DNA จนตาย ขณะที่เซลล์ปกติ (BRCA wild-type) รอด. จำเพาะต่อเซลล์มะเร็ง BRCA/HRD."}, {"topic": "Gynecologic Oncology", "q": "After fertility-sparing treatment (conization for stage IA1 cervical cancer), what follow-up is needed?", "choices": ["No follow-up needed", "Cytology/HPV and colposcopy periodically", "Adjuvant radiotherapy", "Immediate hysterectomy", "Preventive chemotherapy"], "ans": 1, "exp": "หลัง fertility-sparing (conization IA1, margin negative) ต้องติดตามใกล้ชิดด้วย co-testing (cytology + HPV) และ colposcopy เป็นระยะ เพื่อจับการกลับเป็นซ้ำ/persistent disease. มีบุตรครบ/พบผิดปกติ → definitive treatment. ให้คำปรึกษาความเสี่ยง preterm จาก conization."}, {"topic": "Gynecologic Oncology", "q": "Which finding indicates cervical cancer has extended to the pelvic sidewall (stage IIIB)?", "choices": ["A small confined cervical lesion", "A watery vaginal discharge", "Hydronephrosis from ureteral obstruction", "Minor intermenstrual spotting", "Menstrual cramping pain"], "ans": 2, "exp": "มะเร็งปากมดลูก stage III: IIIA (1/3 ล่างช่องคลอด), IIIB (pelvic sidewall และ/หรือ hydronephrosis/non-functioning kidney จากกด ureter), IIIC (node). Hydronephrosis จากการอุดกั้นเป็นเกณฑ์ stage IIIB. รักษาด้วย concurrent chemoradiation."}, {"topic": "Gynecologic Oncology", "q": "A woman with ovarian cancer stage IA, grade 1, who desires fertility is best managed with which option?", "choices": ["Hysterectomy and BSO in all", "No treatment at all", "Chemotherapy alone", "Fertility-sparing surgery with staging", "Radiotherapy alone"], "ans": 3, "exp": "มะเร็งรังไข่ระยะ IA, grade ต่ำ (โดยเฉพาะ germ cell, sex cord-stromal, low-grade epithelial/borderline) ที่ต้องการมีบุตร อาจ fertility-sparing: unilateral salpingo-oophorectomy + comprehensive staging (เก็บมดลูก/รังไข่อีกข้าง). คัดเลือกผู้ป่วย/ให้คำปรึกษา. ระยะสูง/grade สูงต้องผ่าตัดครบ + เคมี."}, {"topic": "Gynecologic Oncology", "q": "A woman not desiring fertility has atypical endometrial hyperplasia (EIN). What is recommended?", "choices": ["No treatment", "Chemotherapy", "Radiation", "Antibiotics", "Total hysterectomy"], "ans": 4, "exp": "Atypical hyperplasia/EIN เสี่ยงมะเร็งร่วม/ลุกลามสูง (~40%) → ผู้ไม่ต้องการเก็บมดลูก แนะนำ total hysterectomy. ต้องการเก็บมดลูก/มีบุตร → high-dose progestin (LNG-IUS/oral) + ติดตามชิ้นเนื้อ. ให้คำปรึกษาความเสี่ยงชัดเจน."}, {"topic": "Gynecologic Oncology", "q": "A 40-year-old pregnant woman wants aneuploidy screening with the highest detection rate. What is recommended?", "choices": ["Cell-free fetal DNA (NIPT)", "Quadruple test", "AFP alone", "Ultrasound alone", "No screening"], "ans": 0, "exp": "NIPT (cfDNA) มี detection rate สูงสุดสำหรับ trisomy 21 (>99%) และ 18/13 ในกลุ่มเสี่ยงสูง (อายุมาก) — screening ที่ดีที่สุด. ผลบวกต้องยืนยันด้วย diagnostic (amniocentesis/CVS). อายุ ≥35-40 ปีอาจพิจารณา diagnostic โดยตรง."}, {"topic": "Gynecologic Oncology", "q": "What is the primary prevention level represented by low-dose aspirin for preeclampsia and the WHO 90-70-90 vaccination component?", "choices": ["Tertiary prevention", "Primary prevention", "Not prevention", "End-stage treatment", "Diagnosis"], "ans": 1, "exp": "Aspirin ป้องกัน preeclampsia = primary prevention (ให้กลุ่มเสี่ยงก่อนเกิดโรค). WHO 90-70-90 วัคซีน = primary prevention มะเร็งปากมดลูก; คัดกรอง+รักษา precancer = secondary. แนวคิดการป้องกันเชิงรุกเป็นหัวใจของเวชศาสตร์ป้องกันทางสูติ-นรีเวช."}, {"topic": "Gynecologic Oncology", "q": "A GBS-colonized woman should receive prophylaxis to prevent which neonatal condition?", "choices": ["Congenital rubella syndrome", "A neural tube defect", "Early-onset neonatal GBS sepsis", "Neonatal hyperbilirubinemia", "Fetal macrosomia"], "ans": 2, "exp": "[อัปเดต] คัดกรอง GBS (36-37+6 wk) และให้ intrapartum penicillin prophylaxis ในผู้ positive เพื่อป้องกัน early-onset neonatal GBS disease (sepsis, pneumonia, meningitis ในสัปดาห์แรก) ซึ่งรุนแรง. ลด early-onset GBS ได้มาก."}, {"topic": "Gynecologic Oncology", "q": "A woman with a very high testosterone level and rapid virilization should be evaluated with which investigation?", "choices": ["No evaluation is needed", "A trial of combined pills", "Serum TSH alone", "Imaging of the ovaries and adrenals", "Diagnostic hysterectomy"], "ans": 3, "exp": "Testosterone สูงมาก (>150-200) + virilization เริ่มเร็ว บ่งชี้ androgen-secreting tumor → imaging: TVS/MRI รังไข่ (Sertoli-Leydig, hilus cell) และ CT/MRI ต่อมหมวกไต (DHEAS สูงมาก = ต่อมหมวกไต). ต่างจาก PCOS."}, {"topic": "Gynecologic Oncology", "q": "CA-125 elevation in a reproductive-age woman with an ovarian mass should be interpreted how?", "choices": ["It always indicates cancer", "It has no clinical meaning", "It reliably excludes cancer", "It is used for general screening", "May rise in benign conditions too"], "ans": 4, "exp": "CA-125 ในวัยเจริญพันธุ์แปลผลต้องระวัง — สูงได้ในภาวะ benign (endometriosis, PID, fibroid, ประจำเดือน, ตั้งครรภ์). จึงมีประโยชน์จำกัดในการแยกมะเร็งในกลุ่มนี้ — ใช้ร่วมกับลักษณะ US, อายุ, และเครื่องมือ (IOTA/RMI). จำเพาะขึ้นในวัยหมดประจำเดือน."}, {"topic": "Gynecologic Oncology", "q": "Why does primary HPV testing allow a longer (5-year) screening interval than cytology?", "choices": ["Higher sensitivity for high-grade precancer", "It is substantially cheaper", "It is usable at any age", "It is entirely painless", "No sample is required"], "ans": 0, "exp": "[อัปเดต] Primary HPV testing มี sensitivity สูงกว่า cytology ในการตรวจจับ high-grade precancer (CIN2+) และ negative predictive value สูง จึงยืดช่วงคัดกรองเป็นทุก 5 ปีได้อย่างปลอดภัย (เทียบ Pap ทุก 2-3 ปี). รองรับ self-collection เพิ่มการเข้าถึง."}, {"topic": "Gynecologic Oncology", "q": "A woman on postpartum GTN follow-up should use which measure during monitoring?", "choices": ["Attempt pregnancy soon", "Reliable contraception during follow-up", "Await natural conception", "Prophylactic chemotherapy", "No contraception needed"], "ans": 1, "exp": "ระหว่างติดตาม β-hCG ต้องคุมกำเนิด (หลีกเลี่ยงตั้งครรภ์) เพราะการตั้งครรภ์ใหม่ทำให้แปลผล hCG ไม่ได้ และแยก GTN ที่กลับเป็นซ้ำไม่ได้. คุมกำเนิด ~1 ปีหลัง hCG เป็นลบ (นิยม combined OC/LARC)."}, {"topic": "Gynecologic Oncology", "q": "A woman with a pelvic mass and ascites plus a very high CA-125 in menopause should be referred to whom?", "choices": ["General internist", "General surgeon", "Gynecologic oncologist", "Dermatologist", "No referral needed"], "ans": 2, "exp": "Pelvic/adnexal mass ที่น่าสงสัยมะเร็ง (solid, ascites, CA-125 สูงในวัยหมดประจำเดือน, RMI สูง) ควรส่ง gynecologic oncologist เพื่อวางแผน surgical staging/cytoreduction (การผ่าตัดโดยผู้เชี่ยวชาญเพิ่ม survival). อย่าเจาะ/ผ่าก้อนแบบไม่วางแผน."}, {"topic": "Gynecologic Oncology", "q": "Which histologic feature characterizes a Krukenberg tumor?", "choices": ["Call-Exner bodies", "Psammoma bodies", "Schiller-Duval bodies", "Signet-ring cells", "Coffee-bean nuclei"], "ans": 3, "exp": "Krukenberg tumor (metastasis to ovary จาก GI, มักกระเพาะอาหาร) มี mucin-producing 'signet-ring cells'. (Call-Exner bodies = granulosa cell; Schiller-Duval bodies = yolk sac; psammoma bodies = serous; coffee-bean nuclei = Brenner)."}, {"topic": "Gynecologic Oncology", "q": "A woman with endometrial cancer that is MMR-deficient due to MLH1 promoter methylation most likely has which situation?", "choices": ["Definite Lynch syndrome", "p53 abnormality", "BRCA mutation", "POLE mutation", "Sporadic (non-hereditary) tumor"], "ans": 4, "exp": "MMR-deficient จาก MLH1 promoter hypermethylation มักเป็น sporadic (ไม่ใช่ Lynch). MMRd ที่ไม่ได้เกิดจาก methylation จึงต้องประเมิน Lynch (germline testing). ทั้งสองกรณี MMRd/MSI-high ตอบสนอง immunotherapy (checkpoint inhibitor)."}]}, {"id": "surg1", "title": "Surgery ชุดที่ 1 — General & GI Surgery (Acute Abdomen, HPB, Bowel, Hernia, Anorectal, Pediatric GI)", "subject": "surg", "questions": [{"topic": "General/GI Surgery", "q": "A 22-year-old man presents with 18 hours of periumbilical pain that migrated to the right lower quadrant, with anorexia and low-grade fever. He has tenderness at McBurney point with guarding. What is the most likely diagnosis?", "choices": ["Acute appendicitis", "Mesenteric adenitis", "Acute cholecystitis", "Ureteric colic", "Meckel diverticulitis"], "ans": 0, "exp": "อาการคลาสสิกของ acute appendicitis: ปวดรอบสะดือย้ายมา RLQ, เบื่ออาหาร, ไข้ต่ำๆ, กดเจ็บที่ McBurney point + guarding. เกิดจากการอุดตันของ appendiceal lumen. การวินิจฉัยส่วนใหญ่เป็นทางคลินิก (± US/CT). รักษาด้วย appendectomy."}, {"topic": "General/GI Surgery", "q": "A 40-year-old obese woman has 6 hours of severe right upper quadrant pain radiating to the scapula after a fatty meal, with fever and a positive Murphy sign. Ultrasound shows gallstones and a thickened gallbladder wall. What is the diagnosis?", "choices": ["Biliary colic", "Acute cholecystitis", "Perforated ulcer", "Acute pancreatitis", "Ascending cholangitis"], "ans": 1, "exp": "Acute cholecystitis: ปวด RUQ ต่อเนื่อง >6 ชม. หลังอาหารมัน, ไข้, Murphy sign บวก, US พบ gallstone + ผนังถุงน้ำดีหนา/pericholecystic fluid. รักษา: ยาปฏิชีวนะ + early laparoscopic cholecystectomy. ต่างจาก biliary colic (ปวดเป็นพักๆ ไม่มีไข้/อักเสบ)."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with gallstones presents with right upper quadrant pain, high fever with rigors, and jaundice. What triad does this represent, and what is the diagnosis?", "choices": ["Cushing triad, raised ICP", "Beck triad, tamponade", "Charcot triad, ascending cholangitis", "Virchow triad, thrombosis", "Reynolds pentad, sepsis"], "ans": 2, "exp": "Charcot triad (ปวด RUQ + ไข้หนาวสั่น + ดีซ่าน) = ascending cholangitis จากการอุดตันและติดเชื้อของท่อน้ำดี. เพิ่ม hypotension + confusion = Reynolds pentad (suppurative cholangitis รุนแรง). รักษา: ยาปฏิชีวนะ + biliary drainage (ERCP)."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man with a history of heavy alcohol use has severe epigastric pain radiating to the back with vomiting. Serum lipase is five times the upper limit of normal. What is the diagnosis?", "choices": ["Myocardial infarction", "Perforated peptic ulcer", "Acute cholecystitis", "Acute pancreatitis", "Ruptured aortic aneurysm"], "ans": 3, "exp": "Acute pancreatitis: ปวด epigastric ทะลุหลัง + อาเจียน + lipase/amylase สูง ≥3 เท่า. สาเหตุบ่อย: gallstone, alcohol. ประเมินความรุนแรง (Ranson/APACHE), รักษาประคับประคอง (IV fluid, งดอาหาร, ยาแก้ปวด). ระวัง necrotizing pancreatitis, pseudocyst."}, {"topic": "General/GI Surgery", "q": "A 68-year-old man has colicky abdominal pain, distension, vomiting, and no passage of flatus or stool. Abdominal X-ray shows dilated small bowel loops with air-fluid levels. What is the diagnosis?", "choices": ["Acute pancreatitis", "Large bowel obstruction", "Paralytic ileus", "Mesenteric ischemia", "Small bowel obstruction"], "ans": 4, "exp": "Small bowel obstruction: ปวดบิดเป็นพักๆ, ท้องอืด, อาเจียน (เร็ว/มาก), ไม่ผายลม/ถ่าย. X-ray: dilated small bowel + air-fluid levels, ไม่มีลมในลำไส้ใหญ่. สาเหตุบ่อยสุด: adhesion (เคยผ่าตัด), hernia. รักษา: NPO, NG tube, IV fluid; ผ่าตัดถ้า strangulation/ไม่ดีขึ้น."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man presents with a painful, irreducible groin lump, vomiting, and signs of bowel obstruction. The lump is tender with overlying skin erythema. What is the diagnosis?", "choices": ["Incarcerated/strangulated hernia", "Reducible inguinal hernia", "Hydrocele", "Femoral lymphadenopathy", "Saphena varix"], "ans": 0, "exp": "Strangulated hernia: ก้อนที่ขาหนีบ ดันกลับไม่ได้ (irreducible), เจ็บ, ผิวแดง + อาการลำไส้อุดตัน/ขาดเลือด → ต้องผ่าตัดฉุกเฉิน (เสี่ยง bowel necrosis). Incarcerated = ดันกลับไม่ได้แต่ยังไม่ขาดเลือด. Reducible = ดันกลับได้."}, {"topic": "General/GI Surgery", "q": "A 3-month-old boy has a soft, reducible bulge in the inguinal canal that appears when he cries. The testis is normally descended. What is the most appropriate management?", "choices": ["Manual reduction and a truss", "Elective surgical repair (herniorrhaphy)", "Immediate emergency repair", "Observation until age 5", "Aspiration of the sac"], "ans": 1, "exp": "Pediatric indirect inguinal hernia (จาก patent processus vaginalis) — ไม่หายเอง เสี่ยง incarceration (สูงในทารก) → แนะนำ elective herniorrhaphy โดยเร็ว. ถ้า incarcerated ที่ reduce ได้ → ผ่าตัดกึ่งเร่งด่วน; reduce ไม่ได้ → ผ่าตัดฉุกเฉิน."}, {"topic": "General/GI Surgery", "q": "A 65-year-old man presents with hematemesis and melena. He takes NSAIDs daily. He is tachycardic with a blood pressure of 90/60 mmHg. What is the most appropriate initial management?", "choices": ["Immediate endoscopy first for this patient", "Barium meal study for this patient", "Resuscitate with IV fluids/blood, then endoscopy", "Oral antacids only", "Emergency laparotomy for this patient"], "ans": 2, "exp": "Upper GI bleeding (peptic ulcer จาก NSAID): จัดการเบื้องต้นคือ 'resuscitation' ก่อน — IV access 2 เส้น, สารน้ำ/เลือด, ประเมิน ABC, ให้ PPI. เมื่อ hemodynamic เสถียรจึงทำ endoscopy (วินิจฉัย + ห้ามเลือด). ไม่ทำ barium (รบกวน scope)."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has sudden severe epigastric pain and a rigid, board-like abdomen. Upright chest X-ray shows free air under the diaphragm. What is the diagnosis?", "choices": ["Acute pancreatitis", "Acute cholecystitis", "Small bowel obstruction", "Perforated peptic ulcer", "Ruptured spleen"], "ans": 3, "exp": "Perforated peptic ulcer: ปวด epigastric เฉียบพลันรุนแรง + peritonitis (board-like rigidity) + free air under diaphragm (pneumoperitoneum) จาก upright CXR. เป็น surgical emergency → resuscitation + IV antibiotic/PPI + ผ่าตัดซ่อม (omental patch)."}, {"topic": "General/GI Surgery", "q": "A 70-year-old man has a change in bowel habit, weight loss, and iron-deficiency anemia. Colonoscopy shows an obstructing mass in the sigmoid colon. What is the most likely diagnosis?", "choices": ["Diverticulitis", "Ulcerative colitis", "Ischemic colitis", "Colonic volvulus", "Colorectal carcinoma"], "ans": 4, "exp": "Colorectal carcinoma: การเปลี่ยนแปลงการขับถ่าย + น้ำหนักลด + iron-deficiency anemia (จากเลือดออกเรื้อรัง) ในผู้สูงอายุ. Left-sided (sigmoid) มัก obstruct/เปลี่ยน bowel habit; right-sided มัก anemia/ก้อน. วินิจฉัยด้วย colonoscopy + biopsy; staging CT. รักษา: ผ่าตัด ± chemo."}, {"topic": "General/GI Surgery", "q": "A 25-year-old man has bright red rectal bleeding on the toilet paper and severe pain during defecation. Examination shows a tear at the posterior midline of the anal canal. What is the diagnosis?", "choices": ["Anal fissure", "Rectal cancer", "Internal hemorrhoids", "Perianal abscess", "Anal fistula"], "ans": 0, "exp": "Anal fissure: แผลฉีกที่ anal canal (posterior midline บ่อยสุด) → เจ็บมากขณะถ่าย + เลือดแดงสด. สัมพันธ์ท้องผูก/อุจจาระแข็ง. รักษา: เพิ่มไฟเบอร์/น้ำ, sitz bath, topical GTN/CCB (คลาย internal sphincter); เรื้อรัง → lateral internal sphincterotomy."}, {"topic": "General/GI Surgery", "q": "A 40-year-old man has a painful, fluctuant, erythematous swelling next to the anus with fever. What is the most appropriate management?", "choices": ["Oral antibiotics alone", "Incision and drainage", "Sitz baths only", "Topical steroid", "High-fiber diet only"], "ans": 1, "exp": "Perianal abscess: ก้อนบวมแดงเจ็บข้างทวารหนัก + ไข้. รักษาด้วย incision & drainage ทันที (ยาปฏิชีวนะอย่างเดียวไม่พอ). ~30-50% กลายเป็น anal fistula ตามมา. ในเบาหวาน/ภูมิคุ้มกันต่ำระวัง necrotizing infection (Fournier gangrene)."}, {"topic": "General/GI Surgery", "q": "A 55-year-old woman has painless, intermittent bright red rectal bleeding coating the stool, with prolapsing lumps that reduce spontaneously. What is the most likely diagnosis?", "choices": ["Anal fissure", "Rectal prolapse", "Internal hemorrhoids", "Colorectal cancer", "Diverticular bleed"], "ans": 2, "exp": "Internal hemorrhoids: เลือดแดงสดเคลือบอุจจาระ 'ไม่เจ็บ' + ก้อนยื่นที่ reduce เองได้ (grade II). รักษาตาม grade: เพิ่มไฟเบอร์/น้ำ (I-II), rubber band ligation (II-III), hemorrhoidectomy (III-IV). ต้องแยกมะเร็ง (colonoscopy ถ้าเสี่ยง/อายุมาก)."}, {"topic": "General/GI Surgery", "q": "A 30-year-old woman is diagnosed with acute appendicitis. What is the definitive treatment?", "choices": ["Intravenous antibiotics only", "Interval colonoscopy", "Bowel rest and observation", "Appendectomy", "Percutaneous drainage"], "ans": 3, "exp": "การรักษามาตรฐานของ acute appendicitis คือ appendectomy (laparoscopic หรือ open). ยาปฏิชีวนะให้ perioperative. กรณี appendiceal mass/abscess ที่มาช้า อาจให้ยาปฏิชีวนะ ± drainage แล้วพิจารณา interval appendectomy. Uncomplicated บางรายรักษาด้วยยาปฏิชีวนะได้แต่ recurrence สูง."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man has sudden severe abdominal pain out of proportion to exam findings; he has atrial fibrillation. Lactate is markedly elevated. What is the most likely diagnosis?", "choices": ["Diverticulitis", "Acute pancreatitis", "Small bowel obstruction", "Peptic ulcer", "Acute mesenteric ischemia"], "ans": 4, "exp": "Acute mesenteric ischemia (มัก SMA embolism ในผู้มี AF): 'ปวดท้องรุนแรงเกินกว่าที่ตรวจพบ' (pain out of proportion) + lactate สูง (metabolic acidosis). เป็น surgical emergency — CT angiography, resuscitation, revascularization/resection. ล่าช้าทำให้ bowel necrosis และตายสูง."}, {"topic": "General/GI Surgery", "q": "A 75-year-old man presents with abdominal distension, and abdominal X-ray shows a massively dilated loop in a 'coffee bean' shape arising from the pelvis. What is the diagnosis?", "choices": ["Sigmoid volvulus", "Paralytic ileus", "Cecal volvulus", "Small bowel obstruction", "Toxic megacolon"], "ans": 0, "exp": "Sigmoid volvulus: พบในผู้สูงอายุ/ท้องผูกเรื้อรัง — X-ray เห็น 'coffee bean/omega sign' ชี้จากอุ้งเชิงกราน. รักษาเบื้องต้น: sigmoidoscopic detorsion + rectal tube (ถ้าไม่มี ischemia); เป็นซ้ำบ่อย → sigmoid colectomy. ถ้ามี peritonitis/gangrene → ผ่าตัดฉุกเฉิน."}, {"topic": "General/GI Surgery", "q": "A 45-year-old woman has recurrent left lower quadrant pain, fever, and altered bowel habits. CT shows sigmoid diverticula with pericolic fat stranding. What is the diagnosis?", "choices": ["Ischemic colitis", "Acute diverticulitis", "Colorectal cancer", "Ulcerative colitis", "Appendicitis"], "ans": 1, "exp": "Acute diverticulitis (มัก sigmoid): ปวด LLQ + ไข้ + เปลี่ยน bowel habit; CT พบ diverticula + fat stranding ± abscess. Uncomplicated รักษาด้วยยาปฏิชีวนะ ± NPO. Complicated (abscess → drainage; perforation/peritonitis → ผ่าตัด Hartmann). Colonoscopy หลังหายเพื่อแยกมะเร็ง."}, {"topic": "General/GI Surgery", "q": "A 58-year-old man with cirrhosis and a history of alcohol use has massive hematemesis. Endoscopy reveals bleeding esophageal varices. What is the definitive endoscopic treatment?", "choices": ["Emergency laparotomy", "Balloon tamponade only", "Endoscopic band ligation", "Beta-blocker only", "Barium swallow"], "ans": 2, "exp": "Bleeding esophageal varices (portal hypertension จาก cirrhosis): รักษา resuscitation + vasoactive drug (octreotide/terlipressin) + antibiotic prophylaxis + 'endoscopic band ligation' (definitive endoscopic). Balloon tamponade (Sengstaken) เป็น bridge ชั่วคราว. ดื้อ → TIPS. ป้องกันซ้ำด้วย band + beta-blocker."}, {"topic": "General/GI Surgery", "q": "A 62-year-old man has progressive dysphagia to solids then liquids, with significant weight loss. He has a long history of GERD. What is the most likely diagnosis?", "choices": ["Esophageal web", "Achalasia", "Diffuse esophageal spasm", "Esophageal carcinoma", "Peptic stricture"], "ans": 3, "exp": "Esophageal carcinoma: dysphagia ที่ลุกลามจาก solid → liquid (mechanical obstruction ที่แย่ลงเรื่อยๆ) + น้ำหนักลด. Adenocarcinoma สัมพันธ์ GERD/Barrett; SCC สัมพันธ์บุหรี่/เหล้า. วินิจฉัย endoscopy + biopsy, staging. ต่างจาก achalasia (dysphagia ทั้ง solid/liquid พร้อมกัน, ไม่ลุกลาม)."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has epigastric pain relieved by eating and antacids, worse at night. Endoscopy shows a duodenal ulcer, and biopsy is positive for Helicobacter pylori. What is the appropriate treatment?", "choices": ["Surgery (vagotomy) for this patient", "Antacids alone", "Long-term steroids for this patient", "H2 blocker only", "Triple therapy (PPI plus two antibiotics)"], "ans": 4, "exp": "Duodenal ulcer + H. pylori: รักษาด้วย eradication triple therapy (PPI + clarithromycin + amoxicillin, หรือสูตร bismuth-based) 14 วัน แล้ว test of cure. ผ่าตัด (vagotomy) ปัจจุบันแทบไม่ใช้ ยกเว้นภาวะแทรกซ้อน (perforation, bleeding, obstruction) ที่ไม่ตอบสนอง."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man is found to have a gastric ulcer on endoscopy. What must be done because of the risk of malignancy?", "choices": ["Biopsy the ulcer edges", "Repeat endoscopy in 1 year", "Immediate gastrectomy", "Start antacids and discharge", "Barium meal only"], "ans": 0, "exp": "Gastric ulcer (ต่างจาก duodenal) มีความเสี่ยงเป็นมะเร็ง → ต้อง biopsy ขอบแผลหลายจุดเสมอ และ 'repeat endoscopy' หลังรักษา 6-8 สัปดาห์เพื่อยืนยันการหายและแยกมะเร็ง. รักษา H. pylori + PPI. Duodenal ulcer ไม่จำเป็นต้อง biopsy routine."}, {"topic": "General/GI Surgery", "q": "A 20-year-old man is stabbed in the left upper abdomen and presents with hypotension, left shoulder pain (Kehr sign), and peritonitis. What organ is most likely injured?", "choices": ["Liver", "Spleen", "Stomach", "Pancreas", "Left kidney"], "ans": 1, "exp": "Splenic injury: บาดเจ็บ LUQ + hypotension + Kehr sign (ปวดร้าวไหล่ซ้ายจากเลือดระคายกะบังลม). ม้ามเป็นอวัยวะที่บาดเจ็บบ่อยใน blunt/penetrating LUQ trauma. Unstable → laparotomy; stable blunt → non-operative ± angioembolization. หลังตัดม้ามต้องให้วัคซีน encapsulated organisms."}, {"topic": "General/GI Surgery", "q": "A 48-year-old woman has intermittent right upper quadrant pain and ultrasound shows gallstones but no wall thickening or fever. She is otherwise well. What is the diagnosis?", "choices": ["Gallbladder cancer", "Acute cholecystitis", "Biliary colic", "Choledocholithiasis", "Cholangitis"], "ans": 2, "exp": "Biliary colic: ปวด RUQ/epigastric เป็นพักๆ หลังอาหารมัน หายเองใน <6 ชม., ไม่มีไข้/อักเสบ, US พบ gallstone ผนังปกติ. เกิดจากนิ่วอุดชั่วคราวที่ cystic duct. รักษา: elective laparoscopic cholecystectomy (มีอาการ). ต่างจาก cholecystitis (อักเสบต่อเนื่อง + ไข้ + Murphy)."}, {"topic": "General/GI Surgery", "q": "A 30-year-old woman presents with a firm, non-tender, mobile breast lump. Which feature is most reassuring for a benign fibroadenoma?", "choices": ["Fixed to chest wall", "Bloody nipple discharge", "Skin dimpling present", "Well-circumscribed and mobile", "Axillary lymphadenopathy"], "ans": 3, "exp": "Fibroadenoma: ก้อนเรียบ ขอบชัด เคลื่อนที่ได้ ไม่เจ็บ ในหญิงสาว — ลักษณะ benign. ประเมินด้วย triple assessment. Red flags มะเร็ง: ติดแน่น (fixed), ผิวบุ๋ม, หัวนมมีเลือด, ต่อมน้ำเหลืองรักแร้โต. (หมวดนี้ทับกับ breast surgery — เน้น surgical evaluation)."}, {"topic": "General/GI Surgery", "q": "A 65-year-old man has painless obstructive jaundice with a palpable, non-tender gallbladder (Courvoisier sign). What is the most likely underlying cause?", "choices": ["Gallstone in the cystic duct", "Gilbert syndrome", "Acute cholecystitis", "Viral hepatitis", "Pancreatic head carcinoma"], "ans": 4, "exp": "Courvoisier's law: ดีซ่านแบบอุดกั้นที่ 'ไม่เจ็บ' + คลำถุงน้ำดีโตไม่เจ็บ → ไม่น่าเกิดจากนิ่ว (ถุงน้ำดีมักหดจากการอักเสบเรื้อรัง) แต่บ่งชี้การอุดกั้นจาก malignancy โดยเฉพาะ pancreatic head carcinoma (หรือ cholangiocarcinoma). วินิจฉัยด้วย CT/MRCP + CA 19-9."}, {"topic": "General/GI Surgery", "q": "A 5-year-old boy has intermittent painless rectal bleeding. A technetium-99m scan is positive. What is the most likely diagnosis?", "choices": ["Meckel diverticulum", "Anal fissure", "Intussusception", "Juvenile polyp", "Hirschsprung disease"], "ans": 0, "exp": "Meckel diverticulum: 'rule of 2s' (2% ประชากร, 2 ฟุตจาก ileocecal, 2 นิ้ว, มัก <2 ปี). มี ectopic gastric mucosa → painless rectal bleeding ในเด็ก. วินิจฉัยด้วย Meckel (technetium-99m pertechnetate) scan. รักษา: surgical resection ถ้ามีอาการ."}, {"topic": "General/GI Surgery", "q": "A 6-month-old infant has episodic colicky pain, drawing up of the legs, and 'currant jelly' stools. A sausage-shaped mass is palpable. What is the diagnosis?", "choices": ["Meckel diverticulum", "Intussusception", "Pyloric stenosis", "Hirschsprung disease", "Volvulus"], "ans": 1, "exp": "Intussusception (ileocolic บ่อยสุด, ~3-12 เดือน): ปวดบิดเป็นพักๆ, งอขา, 'currant jelly stool' (เลือด+เมือก), คลำได้ก้อน sausage-shaped. วินิจฉัย/รักษาด้วย air/contrast enema reduction; ล้มเหลว/peritonitis → ผ่าตัด. เป็นสาเหตุลำไส้อุดตันที่พบบ่อยในวัยทารก."}, {"topic": "General/GI Surgery", "q": "A 3-week-old firstborn boy has projectile non-bilious vomiting after feeds and a palpable 'olive' mass in the epigastrium. What metabolic abnormality is expected?", "choices": ["Hyponatremic metabolic acidosis initially", "Respiratory acidosis for this patient", "Hypochloremic hypokalemic metabolic alkalosis", "Anion-gap metabolic acidosis as first step", "Normal electrolytes for this patient"], "ans": 2, "exp": "Hypertrophic pyloric stenosis (~3-6 สัปดาห์, first-born ชาย): projectile non-bilious vomiting + คลำ 'olive' mass. การอาเจียนกรด (HCl) → hypochloremic hypokalemic metabolic alkalosis. รักษา: แก้ไขเกลือแร่/สารน้ำก่อน แล้ว pyloromyotomy (ไม่ใช่ฉุกเฉิน)."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man has a reducible bulge in the groin located above and medial to the pubic tubercle. What type of hernia is this?", "choices": ["Femoral hernia", "Umbilical hernia", "Incisional hernia", "Inguinal hernia", "Obturator hernia"], "ans": 3, "exp": "Inguinal hernia อยู่ 'เหนือและด้านใน' ต่อ pubic tubercle. Femoral hernia อยู่ 'ใต้และด้านนอก' ต่อ pubic tubercle (พบในหญิงมากกว่า, เสี่ยง strangulation สูง). การแยกตำแหน่งเทียบ pubic tubercle เป็นจุดสำคัญทางคลินิก."}, {"topic": "General/GI Surgery", "q": "A 70-year-old woman has a tender, irreducible lump below and lateral to the pubic tubercle with bowel obstruction. Which hernia has the highest risk of strangulation?", "choices": ["Direct inguinal hernia", "Spigelian hernia", "Umbilical hernia", "Epigastric hernia", "Femoral hernia"], "ans": 4, "exp": "Femoral hernia (ใต้/ด้านนอกต่อ pubic tubercle, พบในหญิงสูงอายุ) มีคอแคบ (rigid femoral ring) → เสี่ยง incarceration/strangulation สูงสุด → แนะนำผ่าตัดซ่อมแม้ไม่มีอาการ. กรณีนี้มีลำไส้อุดตัน → ผ่าตัดฉุกเฉิน."}, {"topic": "General/GI Surgery", "q": "A 35-year-old man has severe epigastric pain and vomiting; CT shows peripancreatic fluid collections 3 weeks after an episode of acute pancreatitis. He now has a well-defined encapsulated collection. What is the diagnosis?", "choices": ["Pancreatic pseudocyst", "Pancreatic carcinoma", "Pancreatic abscess", "Splenic cyst", "Mesenteric cyst"], "ans": 0, "exp": "Pancreatic pseudocyst: เกิดหลัง acute pancreatitis ~4 สัปดาห์ — collection ที่มีผนัง (ไม่มี epithelium จริง). ส่วนใหญ่หายเอง; ถ้าใหญ่/มีอาการ/ติดเชื้อ → drainage (endoscopic cystogastrostomy ที่นิยม). ต่างจาก abscess (มีการติดเชื้อ/หนอง)."}, {"topic": "General/GI Surgery", "q": "A 40-year-old woman has recurrent episodes of RUQ pain; ultrasound shows a dilated common bile duct with a stone. What is the appropriate management to relieve the obstruction?", "choices": ["Laparoscopic cholecystectomy alone", "ERCP with stone extraction", "Observation", "Oral ursodeoxycholic acid", "Percutaneous drainage only"], "ans": 1, "exp": "Choledocholithiasis (นิ่วใน common bile duct): ปวด RUQ + CBD dilated + นิ่ว, เสี่ยง cholangitis/pancreatitis. รักษาด้วย ERCP + stone extraction (± sphincterotomy) เพื่อเอานิ่วออก, ตามด้วย cholecystectomy (จัดการต้นตอ). US/MRCP ช่วยวินิจฉัย."}, {"topic": "General/GI Surgery", "q": "A 65-year-old man has epigastric pain, early satiety, and weight loss. Endoscopy shows an ulcerated mass in the gastric antrum; biopsy confirms adenocarcinoma. Which risk factor is most associated?", "choices": ["Lactose intolerance alone", "Gilbert syndrome initially", "Helicobacter pylori infection", "Hemochromatosis initially", "Wilson disease in this case"], "ans": 2, "exp": "Gastric adenocarcinoma: ปวด epigastric + อิ่มเร็ว + น้ำหนักลด. ปัจจัยเสี่ยงหลัก: H. pylori (chronic gastritis → intestinal metaplasia), อาหารเค็ม/ปลาเค็ม, บุหรี่, pernicious anemia. อาจมี Virchow node (ต่อมน้ำเหลือง supraclavicular ซ้าย). วินิจฉัย endoscopy + biopsy; รักษา gastrectomy ± chemo."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man with chronic hepatitis B has a new liver mass and an alpha-fetoprotein of 800 ng/mL. What is the most likely diagnosis?", "choices": ["Liver hemangioma", "Focal nodular hyperplasia", "Hepatic adenoma", "Hepatocellular carcinoma", "Pyogenic liver abscess"], "ans": 3, "exp": "Hepatocellular carcinoma (HCC): เกิดบน chronic liver disease (HBV/HCV, cirrhosis) + AFP สูง + mass ที่มี arterial enhancement/washout ทาง CT/MRI (LI-RADS). รักษาตามระยะ/liver function: resection, transplant, ablation, TACE, systemic. คัดกรองด้วย US ± AFP ทุก 6 เดือนในกลุ่มเสี่ยง."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man from a rural area has fever and RUQ pain; ultrasound shows a solitary liver abscess. He recently had bloody diarrhea. Serology for Entamoeba is positive. What is the treatment?", "choices": ["Surgical resection", "Albendazole", "Percutaneous drainage first", "Broad-spectrum antibiotics only", "Metronidazole"], "ans": 4, "exp": "Amoebic liver abscess (Entamoeba histolytica, มักกลีบขวา, หลัง amoebic colitis): รักษาด้วย metronidazole (+ luminal agent เช่น diloxanide เพื่อกำจัด cyst). ส่วนใหญ่ไม่ต้อง drain; drain เมื่อใหญ่มาก/ไม่ตอบสนอง/เสี่ยงแตก. ต่างจาก pyogenic abscess (polymicrobial → antibiotic + drainage)."}, {"topic": "General/GI Surgery", "q": "A 68-year-old man has painless jaundice, weight loss, and a pancreatic head mass on CT. Which tumor marker is most associated?", "choices": ["CA 19-9", "AFP", "CEA", "Beta-hCG", "PSA"], "ans": 0, "exp": "Pancreatic head adenocarcinoma: painless obstructive jaundice + น้ำหนักลด + Courvoisier sign. Tumor marker: CA 19-9 (ใช้ติดตาม ไม่ใช่คัดกรอง). วินิจฉัย CT pancreas protocol ± EUS-guided biopsy. รักษา: Whipple (pancreaticoduodenectomy) ถ้า resectable; ส่วนใหญ่วินิจฉัยระยะท้าย พยากรณ์แย่."}, {"topic": "General/GI Surgery", "q": "A 25-year-old woman has a chronic discharging sinus in the natal cleft with a tuft of hair. What is the diagnosis?", "choices": ["Hidradenitis suppurativa", "Pilonidal disease", "Anal fistula", "Perianal abscess", "Sacral dermoid"], "ans": 1, "exp": "Pilonidal disease: sinus/ฝีบริเวณร่องก้น (natal cleft) มีขนฝังใน, พบในชายหนุ่มขนดก/นั่งนาน. Acute abscess → I&D; chronic sinus → excision (± flap) + สุขอนามัย/กำจัดขน. ต่างจาก anal fistula (เชื่อมกับ anal canal)."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has a chronic discharging opening near the anus connecting to the anal canal. What is the diagnosis and definitive treatment?", "choices": ["Anal fissure, sphincterotomy", "Hemorrhoids, banding", "Anal fistula, fistulotomy", "Pilonidal sinus, excision", "Perianal abscess, drainage"], "ans": 2, "exp": "Anal fistula (fistula-in-ano): ทางเชื่อมระหว่าง anal canal กับผิวหนัง มักตามหลัง perianal abscess. Goodsall's rule ทำนายทิศทาง. รักษา: fistulotomy (low fistula) หรือ seton/LIFT (high/complex เพื่อรักษา sphincter). ประเมิน IBD (Crohn) ในรายซับซ้อน/เป็นซ้ำ."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with severe vomiting develops sudden severe chest and epigastric pain with subcutaneous emphysema. Chest imaging shows a left pleural effusion and mediastinal air. What is the diagnosis?", "choices": ["Mallory-Weiss tear", "Peptic perforation", "Myocardial infarction", "Boerhaave syndrome", "Aortic dissection"], "ans": 3, "exp": "Boerhaave syndrome: esophageal rupture เต็มความหนา (transmural) หลังอาเจียนรุนแรง → ปวดอก/epigastric รุนแรง, subcutaneous emphysema, pleural effusion (ซ้าย), mediastinal air. Mackler triad (อาเจียน + เจ็บอก + emphysema). เป็น surgical emergency — resuscitation + antibiotic + ผ่าตัดซ่อม/drainage. ต่างจาก Mallory-Weiss (แผลเยื่อบุ ไม่ทะลุ, เลือดออก)."}, {"topic": "General/GI Surgery", "q": "A 40-year-old alcoholic man has hematemesis after repeated forceful retching. Endoscopy shows a longitudinal mucosal tear at the gastroesophageal junction. What is the diagnosis?", "choices": ["Boerhaave syndrome", "Peptic ulcer", "Esophageal varices", "Esophageal cancer", "Mallory-Weiss tear"], "ans": 4, "exp": "Mallory-Weiss tear: แผลฉีก 'เยื่อบุ' (mucosal, ไม่ทะลุ) ที่ GE junction หลังอาเจียน/retching ซ้ำ → hematemesis. ส่วนใหญ่หยุดเองได้; เลือดออกมากใช้ endoscopic hemostasis. ต่างจาก Boerhaave (transmural rupture, รุนแรง)."}, {"topic": "General/GI Surgery", "q": "A 30-year-old woman has dysphagia to both solids and liquids, regurgitation, and a 'bird-beak' tapering of the distal esophagus on barium swallow. What is the diagnosis?", "choices": ["Achalasia", "Esophageal carcinoma", "Esophageal web", "Peptic stricture", "Zenker diverticulum"], "ans": 0, "exp": "Achalasia: dysphagia ต่อทั้ง solid และ liquid 'พร้อมกัน' + regurgitation; barium เห็น 'bird-beak' (LES ไม่คลาย + esophagus ขยาย). ยืนยันด้วย manometry (aperistalsis + LES ไม่คลาย). รักษา: pneumatic dilation, Heller myotomy, หรือ POEM. ต่างจากมะเร็ง (dysphagia solid→liquid ลุกลาม + น้ำหนักลด)."}, {"topic": "General/GI Surgery", "q": "A 2-day-old neonate has bilious vomiting and abdominal distension and has not passed meconium. Contrast enema shows a transition zone in the rectosigmoid. What is the diagnosis?", "choices": ["Duodenal atresia", "Hirschsprung disease", "Meconium ileus", "Necrotizing enterocolitis", "Anorectal malformation"], "ans": 1, "exp": "Hirschsprung disease: ไม่มี ganglion cells (aganglionosis) เริ่มจาก rectum ขึ้นไป → ไม่ถ่ายขี้เทาใน 48 ชม., ท้องอืด, bilious vomiting. Contrast เห็น transition zone; ยืนยันด้วย rectal biopsy (ไม่มี ganglion cells). รักษา: ผ่าตัด pull-through. เสี่ยง enterocolitis (อันตราย)."}, {"topic": "General/GI Surgery", "q": "A newborn has bilious vomiting on the first day; abdominal X-ray shows a 'double bubble' sign. What is the most likely diagnosis?", "choices": ["Malrotation with volvulus", "Pyloric stenosis", "Duodenal atresia", "Hirschsprung disease", "Jejunal atresia"], "ans": 2, "exp": "Duodenal atresia: bilious vomiting วันแรก + 'double bubble' (ลมในกระเพาะ + duodenum ส่วนต้น). สัมพันธ์กับ Down syndrome (~30%). รักษา: duodenoduodenostomy. ต้องแยก malrotation with midgut volvulus (bilious vomiting + surgical emergency — ต้อง upper GI contrast ด่วน)."}, {"topic": "General/GI Surgery", "q": "A newborn has bilious vomiting and an upper GI study shows the duodenojejunal junction on the right side with a 'corkscrew' appearance. What is the diagnosis requiring emergency surgery?", "choices": ["Duodenal atresia in this case", "Meconium ileus as first step", "Hirschsprung disease initially", "Malrotation with midgut volvulus", "Pyloric stenosis in this case"], "ans": 3, "exp": "Malrotation with midgut volvulus: bilious vomiting ในทารก + upper GI พบ DJ junction ผิดตำแหน่ง (ขวา) + 'corkscrew' → เป็น surgical emergency (bowel ischemia ได้เร็ว) → Ladd procedure ด่วน. Bilious vomiting ในทารกทุกรายต้องแยกภาวะนี้ก่อน."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man 5 days after bowel anastomosis develops fever, tachycardia, abdominal pain, and feculent drainage from the wound. What is the most likely complication?", "choices": ["Wound infection", "Deep vein thrombosis", "Ileus", "Atelectasis", "Anastomotic leak"], "ans": 4, "exp": "Anastomotic leak: มักเกิดวันที่ 5-7 หลังผ่าตัด — ไข้, ปวดท้อง, tachycardia, มี enteric/feculent content ออกจากแผล/drain, sepsis. ยืนยันด้วย CT with contrast. รักษา: resuscitation, antibiotic, drainage; รุนแรง → re-operation ± stoma. เป็นภาวะแทรกซ้อนร้ายแรงของ bowel surgery."}, {"topic": "General/GI Surgery", "q": "On postoperative day 2 after abdominal surgery, a patient develops fever. Which is the most likely cause at this early stage?", "choices": ["Atelectasis", "Wound infection", "Anastomotic leak", "Deep vein thrombosis", "Urinary tract infection"], "ans": 0, "exp": "สาเหตุไข้หลังผ่าตัดตามเวลา (5 Ws): วันที่ 1-2 = atelectasis (Wind, พบบ่อยสุดช่วงแรก); 3-5 = UTI (Water)/pneumonia; 5-7 = wound infection (Wound)/anastomotic leak; DVT (Walking); drug/line (Wonder drugs). วันที่ 2 → atelectasis. รักษา: incentive spirometry, กายภาพหายใจ, early mobilization."}, {"topic": "General/GI Surgery", "q": "A 7-day-old premature neonate has abdominal distension, bloody stools, and pneumatosis intestinalis on X-ray. What is the diagnosis?", "choices": ["Intussusception", "Necrotizing enterocolitis", "Hirschsprung disease", "Malrotation", "Meconium ileus"], "ans": 1, "exp": "Necrotizing enterocolitis (NEC): พบในทารกคลอดก่อนกำหนด — ท้องอืด, ถ่ายเป็นเลือด, ไม่ทน feed; X-ray เห็น pneumatosis intestinalis (ลมในผนังลำไส้) ± portal venous gas. รักษา: NPO, NG decompression, antibiotic; ผ่าตัดถ้า perforation/necrosis (pneumoperitoneum)."}, {"topic": "General/GI Surgery", "q": "A 55-year-old woman has recurrent right upper quadrant pain and gallstones. During laparoscopic cholecystectomy, the surgeon must identify structures in which anatomical landmark to avoid bile duct injury?", "choices": ["Pouch of Douglas", "Foramen of Winslow", "Calot triangle", "Triangle of Koch", "Hesselbach triangle"], "ans": 2, "exp": "Calot's triangle (cystohepatic triangle): ขอบเขต cystic duct, common hepatic duct, และ liver edge — มี cystic artery. การทำ 'critical view of safety' โดยระบุโครงสร้างใน Calot's triangle ช่วยป้องกัน bile duct injury ระหว่าง cholecystectomy. (Hesselbach = inguinal; Koch = หัวใจ)."}, {"topic": "General/GI Surgery", "q": "A 3-year-old boy has not passed stool well since birth, with chronic constipation and abdominal distension. Rectal biopsy shows absence of ganglion cells. What is the pathophysiology?", "choices": ["Anal stenosis for this patient", "Meconium plug for this patient", "Hypothyroidism for this patient", "Aganglionosis of the distal bowel", "Neuronal dysplasia in this case"], "ans": 3, "exp": "Hirschsprung disease = การไม่มี ganglion cells (aganglionosis) ในชั้น submucosal (Meissner) และ myenteric (Auerbach) plexus เริ่มจาก rectum ขึ้นไป → ลำไส้ส่วนนั้นหดเกร็งไม่คลาย → obstruction เชิงหน้าที่. วินิจฉัยด้วย rectal biopsy. รักษา: pull-through resection ส่วนที่ไม่มี ganglion."}, {"topic": "General/GI Surgery", "q": "A 45-year-old woman has a 3 cm gastric submucosal mass; biopsy shows spindle cells positive for CD117 (c-KIT). What is the diagnosis?", "choices": ["Adenocarcinoma in this case", "Lymphoma for this patient", "Leiomyoma for this patient", "Carcinoid tumor in this case", "Gastrointestinal stromal tumor"], "ans": 4, "exp": "Gastrointestinal stromal tumor (GIST): เนื้องอก mesenchymal จาก interstitial cells of Cajal, มัก CD117 (c-KIT) positive. พบบ่อยที่กระเพาะ. รักษา: surgical resection (ไม่ต้องเลาะ node); imatinib (tyrosine kinase inhibitor) สำหรับ unresectable/metastatic/adjuvant. ความเสี่ยงประเมินจากขนาด + mitotic rate."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man has rectal bleeding and tenesmus. Digital rectal exam reveals a mass 4 cm from the anal verge; biopsy confirms adenocarcinoma. Which imaging best assesses local T-staging?", "choices": ["Pelvic MRI", "Abdominal ultrasound", "Chest X-ray", "Barium enema", "Plain abdominal film"], "ans": 0, "exp": "Rectal cancer local staging (T และ circumferential resection margin, nodes) ประเมินดีที่สุดด้วย 'pelvic MRI' (± endorectal US สำหรับ early T). CT chest/abdomen สำหรับ distant metastasis. การ staging กำหนดว่าต้อง neoadjuvant chemoradiation ก่อนผ่าตัด (TME) หรือไม่."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man with cirrhosis develops progressive abdominal distension with shifting dullness and a fluid wave. What is the most likely cause?", "choices": ["Congestive heart failure alone", "Portal hypertension causing ascites", "Bowel obstruction as first step", "Ovarian mass for this patient", "Nephrotic syndrome as first step"], "ans": 1, "exp": "Ascites ในผู้ป่วย cirrhosis เกิดจาก portal hypertension (+ hypoalbuminemia, Na/water retention). ประเมินด้วย diagnostic paracentesis + SAAG (≥1.1 = portal HT). เฝ้าระวัง spontaneous bacterial peritonitis (SBP - PMN ≥250). รักษา: จำกัดเกลือ + diuretics (spironolactone ± furosemide), LVP, TIPS."}, {"topic": "General/GI Surgery", "q": "A 30-year-old man is stabbed in the epigastrium. He is hemodynamically stable but has peritonitis on examination. What is the most appropriate management?", "choices": ["Observation and serial exams", "Antibiotics alone", "Exploratory laparotomy", "CT then discharge", "Diagnostic peritoneal lavage only"], "ans": 2, "exp": "Penetrating abdominal trauma ที่มี peritonitis, evisceration, หรือ hemodynamic instability = ข้อบ่งชี้ 'exploratory laparotomy' ทันที (ไม่ต้อง imaging เพิ่ม). Stab wound ที่ stable ไม่มี peritonitis อาจ selective non-operative + serial exam/CT. Gunshot ช่องท้องส่วนใหญ่ต้อง laparotomy."}, {"topic": "General/GI Surgery", "q": "A 24-year-old man is diagnosed with an appendiceal mass 6 days into his illness; he is stable without peritonitis. What is the appropriate initial management?", "choices": ["Immediate appendectomy for this patient", "Right hemicolectomy for this patient", "Percutaneous drainage of stool for this patient", "Antibiotics and observation (consider interval appendectomy)", "Barium enema for this patient"], "ans": 3, "exp": "Appendiceal mass/phlegmon ที่มาช้า (>5 วัน) และ stable: รักษาแบบ conservative ด้วยยาปฏิชีวนะ ± drainage ถ้ามี abscess — เพราะผ่าตัดทันทีในช่วงนี้ยากและเสี่ยงบาดเจ็บอวัยวะข้างเคียง. พิจารณา interval appendectomy ภายหลัง (± colonoscopy ในผู้สูงอายุแยกมะเร็ง)."}, {"topic": "General/GI Surgery", "q": "A 70-year-old man has painless massive lower GI bleeding. Colonoscopy is difficult due to bleeding. Which is the most common cause of significant lower GI bleeding in the elderly?", "choices": ["Anal fissure", "Hemorrhoids", "Colorectal polyp", "Ischemic colitis", "Diverticulosis"], "ans": 4, "exp": "Diverticulosis เป็นสาเหตุที่พบบ่อยที่สุดของ lower GI bleeding รุนแรงในผู้สูงอายุ (เลือดออกไม่เจ็บ ปริมาณมาก มักหยุดเอง). สาเหตุอื่น: angiodysplasia, ischemic colitis, มะเร็ง. ประเมิน: resuscitation → colonoscopy; ต่อเนื่อง → CT angiography/embolization หรือผ่าตัด."}, {"topic": "General/GI Surgery", "q": "A 40-year-old man has severe, constant epigastric pain radiating to the back and is leaning forward for relief; serum amylase is elevated. Which scoring system assesses severity at admission?", "choices": ["Ranson criteria", "Glasgow Coma Scale", "CURB-65", "Child-Pugh score", "Alvarado score"], "ans": 0, "exp": "Acute pancreatitis severity ประเมินด้วย Ranson criteria (แรกรับ + 48 ชม.), APACHE II, หรือ BISAP. รุนแรง → เฝ้าระวัง organ failure, necrosis. Child-Pugh = ประเมินตับแข็ง; Alvarado = appendicitis; CURB-65 = pneumonia. การประเมินความรุนแรงกำหนดระดับการดูแล (ICU)."}, {"topic": "General/GI Surgery", "q": "A 6-week-old boy has persistent jaundice, pale stools, and dark urine; direct bilirubin is elevated. Ultrasound shows an absent/contracted gallbladder. What is the diagnosis requiring urgent surgery?", "choices": ["Physiologic jaundice", "Biliary atresia", "Neonatal hepatitis", "Choledochal cyst", "Gilbert syndrome"], "ans": 1, "exp": "Biliary atresia: conjugated (direct) hyperbilirubinemia ต่อเนื่องในทารก + อุจจาระซีด (acholic) + ปัสสาวะเข้ม. เป็นภาวะเร่งด่วน — Kasai portoenterostomy ควรทำก่อนอายุ ~8 สัปดาห์เพื่อผลดี (มิฉะนั้น cirrhosis → ต้อง liver transplant). ทารกที่ prolonged jaundice ต้องตรวจ direct bilirubin เสมอ."}, {"topic": "General/GI Surgery", "q": "A 3-year-old girl has recurrent abdominal pain, jaundice, and a palpable RUQ mass; ultrasound shows a cystic dilation of the common bile duct. What is the diagnosis?", "choices": ["Biliary atresia", "Gallbladder empyema", "Choledochal cyst", "Hepatic cyst", "Pancreatic pseudocyst"], "ans": 2, "exp": "Choledochal cyst: cystic dilation ของ bile duct — classic triad (ปวดท้อง + ดีซ่าน + ก้อน RUQ) พบครบไม่บ่อย. วินิจฉัย US/MRCP. เสี่ยง cholangiocarcinoma → รักษาด้วยผ่าตัด excision + hepaticojejunostomy. พบในเด็ก/หญิงเอเชียมากกว่า."}, {"topic": "General/GI Surgery", "q": "A 62-year-old man who had a gastrectomy develops sweating, palpitations, dizziness, and diarrhea 15-30 minutes after meals. What is the diagnosis?", "choices": ["Afferent loop syndrome", "Anastomotic stricture", "Bile reflux gastritis", "Dumping syndrome", "Recurrent ulcer"], "ans": 3, "exp": "Early dumping syndrome (หลัง gastric surgery): อาหารถึง small bowel เร็ว → osmotic fluid shift → อาการ vasomotor (เหงื่อ, ใจสั่น, มึน) + GI (ปวดบิด, ท้องเสีย) ภายใน 15-30 นาทีหลังอาหาร. Late dumping (1-3 ชม.) จาก reactive hypoglycemia. รักษา: แบ่งมื้อเล็ก, ลด carbohydrate เชิงเดี่ยว, แยกของเหลว."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with dysphagia is found to have a mid-esophageal squamous cell carcinoma. Which is the strongest risk factor?", "choices": ["Chronic GERD", "Obesity", "Barrett esophagus", "Hiatal hernia", "Smoking and alcohol"], "ans": 4, "exp": "Esophageal SCC (มัก upper/mid esophagus) — ปัจจัยเสี่ยงหลักคือ 'บุหรี่และแอลกอฮอล์' (เสริมฤทธิ์กัน), อาหารร้อนจัด, achalasia เรื้อรัง. ต่างจาก adenocarcinoma (distal esophagus, สัมพันธ์ GERD/Barrett/obesity). วินิจฉัย endoscopy + biopsy."}, {"topic": "General/GI Surgery", "q": "A 58-year-old man has heartburn and regurgitation for years and is found to have Barrett esophagus on endoscopy. What is the main clinical significance?", "choices": ["Risk of adenocarcinoma", "No clinical significance", "Risk of squamous carcinoma", "Risk of perforation", "Risk of achalasia"], "ans": 0, "exp": "Barrett esophagus = intestinal metaplasia ของ distal esophagus จาก chronic GERD — เป็น premalignant สำหรับ esophageal 'adenocarcinoma'. ต้อง surveillance endoscopy + biopsy; dysplasia → endoscopic therapy (RFA/EMR). รักษา GERD ด้วย PPI. ควบคุมอาการและเฝ้าระวังมะเร็ง."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man ingested a strong alkaline cleaning agent and has drooling and odynophagia. What is the most appropriate early management?", "choices": ["Induce vomiting for this patient", "Endoscopy to assess injury, do not induce emesis", "Neutralize with acid for this patient", "Immediate laparotomy for this patient", "Barium swallow immediately for this patient"], "ans": 1, "exp": "Caustic ingestion (alkali ทำให้ liquefactive necrosis ลึก): ห้ามทำให้อาเจียน/neutralize/ใส่ NG blindly. ประเมิน airway, NPO, และทำ endoscopy ภายใน 24-48 ชม.เพื่อประเมินความรุนแรง (grade). ภาวะแทรกซ้อน: perforation (เฉียบพลัน), esophageal stricture (ระยะยาว)."}, {"topic": "General/GI Surgery", "q": "A 2-hour-old neonate is noted to have excessive drooling and chokes with feeds; a nasogastric tube coils in the upper esophagus on X-ray. What is the diagnosis?", "choices": ["Choanal atresia", "Pyloric stenosis", "Esophageal atresia", "Duodenal atresia", "Diaphragmatic hernia"], "ans": 2, "exp": "Esophageal atresia (มักมี tracheoesophageal fistula): น้ำลายมาก, สำลักเมื่อ feed, NG tube ขดในหลอดอาหารส่วนต้น. สัมพันธ์กับ VACTERL association. รักษา: ผ่าตัดซ่อม. ต้องระวัง aspiration ก่อนผ่าตัด (upright, suction)."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man with a long-standing duodenal ulcer has recurrent vomiting of undigested food and a succussion splash. What is the complication?", "choices": ["Malignant transformation", "Perforation", "Gastric volvulus", "Gastric outlet obstruction", "Zollinger-Ellison syndrome"], "ans": 3, "exp": "Gastric outlet obstruction: จาก chronic peptic ulcer (pyloric scarring) หรือ malignancy — อาเจียนอาหารเก่าไม่ย่อย, succussion splash, น้ำหนักลด, metabolic alkalosis. รักษา: NG decompression, แก้เกลือแร่, endoscopy (แยกมะเร็ง/ balloon dilation), ผ่าตัดถ้าจำเป็น."}, {"topic": "General/GI Surgery", "q": "A patient underwent splenectomy after trauma. What prophylaxis is essential to prevent overwhelming post-splenectomy infection?", "choices": ["Lifelong warfarin for this patient", "No prophylaxis needed for this patient", "Daily proton pump inhibitor in this case", "Routine antifungals for this patient", "Vaccination against encapsulated organisms"], "ans": 4, "exp": "หลัง splenectomy เสี่ยง overwhelming post-splenectomy infection (OPSI) จากเชื้อ encapsulated (Streptococcus pneumoniae, Haemophilus influenzae type b, Neisseria meningitidis) → ต้องฉีดวัคซีนทั้งสาม (ควรก่อนผ่าตัด 2 สัปดาห์ถ้า elective) + พิจารณา prophylactic antibiotic ในเด็ก และให้ความรู้เรื่องไข้."}, {"topic": "General/GI Surgery", "q": "A 40-year-old shepherd has a large liver cyst with daughter cysts and calcified wall on CT; serology for Echinococcus is positive. What is the appropriate treatment?", "choices": ["Albendazole plus surgery/PAIR", "Metronidazole alone", "Aspiration alone", "Observation", "Broad-spectrum antibiotics"], "ans": 0, "exp": "Hydatid cyst (Echinococcus granulosus, สัมพันธ์เลี้ยงแกะ/สุนัข): CT เห็น daughter cysts/calcification. รักษา: albendazole + surgery (pericystectomy) หรือ PAIR (puncture-aspiration-injection-reaspiration) โดยระวัง spillage (anaphylaxis/dissemination). ห้ามเจาะแบบไม่เตรียม."}, {"topic": "General/GI Surgery", "q": "A 65-year-old woman with a porcelain gallbladder on imaging is counseled about her risk. What is the concern?", "choices": ["Gallstone ileus", "Gallbladder carcinoma", "Cholangitis", "Pancreatitis", "Bile leak"], "ans": 1, "exp": "Porcelain gallbladder (ผนังถุงน้ำดี calcified) สัมพันธ์กับความเสี่ยง gallbladder carcinoma → พิจารณา cholecystectomy. Gallbladder cancer พยากรณ์แย่ (มักวินิจฉัยระยะท้าย). ปัจจัยเสี่ยงอื่น: gallstone เรื้อรัง, large polyp (>1 cm), chronic infection."}, {"topic": "General/GI Surgery", "q": "A young man with ulcerative colitis develops a distended, tender abdomen, fever, and tachycardia; X-ray shows a dilated transverse colon >6 cm. What is the diagnosis?", "choices": ["Sigmoid volvulus", "Small bowel obstruction", "Toxic megacolon", "Diverticulitis", "Ischemic colitis"], "ans": 2, "exp": "Toxic megacolon: ภาวะแทรกซ้อนของ severe colitis (UC, C. difficile) — colon ขยาย >6 cm + systemic toxicity (ไข้, tachycardia, ปวดท้อง). เสี่ยงทะลุ. รักษา: IV steroid/antibiotic, bowel rest, แก้เกลือแร่; ไม่ดีขึ้น/ทะลุ → colectomy ฉุกเฉิน. หลีกเลี่ยง antimotility/opioid."}, {"topic": "General/GI Surgery", "q": "A 30-year-old man with Crohn disease has a chronic enterocutaneous fistula. Which is a key principle of management?", "choices": ["Immediate resection always alone", "No intervention for this patient", "High-dose opioids for this patient", "Optimize nutrition and control sepsis", "Barium enema for this patient"], "ans": 3, "exp": "Enterocutaneous fistula management (SNAP/SOWATS): control Sepsis, optimize Nutrition (มัก TPN), skin/wound care, define Anatomy (fistulogram/CT). ~1/3 ปิดเองด้วย conservative; ปัจจัยที่ปิดยาก (FRIEND: Foreign body, Radiation, IBD, Epithelialization, Neoplasm, Distal obstruction). ผ่าตัดเมื่อ optimize แล้ว."}, {"topic": "General/GI Surgery", "q": "A 70-year-old man 7 days after midline laparotomy has serosanguineous wound discharge and a 'give' sensation; bowel is visible through the wound. What is the diagnosis?", "choices": ["Wound infection for this patient", "Incisional hernia as first step", "Seroma for this patient", "Hematoma for this patient", "Burst abdomen (fascial dehiscence)"], "ans": 4, "exp": "Burst abdomen (fascial dehiscence): แผลผ่าตัดแยกถึงชั้น fascia — สัญญาณเตือนคือ serosanguineous ('pink') discharge วันที่ ~5-8, อาจมี evisceration. เป็น surgical emergency → คลุมด้วยผ้าชุ่ม saline + ผ่าตัดปิดซ่อม. ปัจจัยเสี่ยง: ติดเชื้อ, ไอ, malnutrition, steroid."}, {"topic": "General/GI Surgery", "q": "A 25-year-old man has right lower quadrant pain, and Alvarado score is calculated. Which clinical feature is part of the Alvarado score for appendicitis?", "choices": ["Migratory RLQ pain", "Jaundice", "Hematuria", "Melena", "Splenomegaly"], "ans": 0, "exp": "Alvarado score (MANTRELS) สำหรับ appendicitis: Migration of pain, Anorexia, Nausea, Tenderness RLQ, Rebound, Elevated temp, Leukocytosis, Shift to left. คะแนนสูงสนับสนุนการวินิจฉัย/ผ่าตัด; กลางๆ → imaging (US/CT). ช่วยลด negative appendectomy."}, {"topic": "General/GI Surgery", "q": "A pregnant woman at 20 weeks has right-sided abdominal pain higher than usual; appendicitis is suspected. Which imaging is preferred to avoid radiation?", "choices": ["CT abdomen for this patient", "Ultrasound (then MRI if needed)", "Plain X-ray for this patient", "Barium enema for this patient", "PET scan for this patient"], "ans": 1, "exp": "Appendicitis ในหญิงตั้งครรภ์: ตำแหน่งปวดอาจสูงขึ้นตามมดลูกที่โต. Imaging เลือก ultrasound ก่อน (ไม่มีรังสี), ถ้าไม่ชัดใช้ MRI. หลีกเลี่ยง CT (รังสี). Appendicitis เป็นภาวะ non-obstetric surgical ที่พบบ่อยสุดในครรภ์ — ผ่าตัดเมื่อวินิจฉัย (ล่าช้าเสี่ยง perforation/fetal loss)."}, {"topic": "General/GI Surgery", "q": "A 68-year-old man has an obstructing left-sided colon cancer with distension. He is stable. Which option can relieve obstruction and allow one-stage surgery or bridge to surgery?", "choices": ["Immediate right hemicolectomy for this patient", "Barium enema for this patient", "Endoscopic stenting or resection with primary anastomosis", "Long-term laxatives for this patient", "Observation only"], "ans": 2, "exp": "Obstructing left colon cancer: ทางเลือกได้แก่ resection + primary anastomosis (± on-table lavage), Hartmann procedure (resection + end colostomy), หรือ 'self-expanding metal stent' เป็น bridge to surgery/palliation ในรายที่เหมาะสม. ประเมิน staging และสภาพผู้ป่วย."}, {"topic": "General/GI Surgery", "q": "A 55-year-old woman has multiple hundreds of colonic polyps and a family history of colon cancer at a young age. Genetic testing shows an APC mutation. What is the diagnosis?", "choices": ["Peutz-Jeghers syndrome", "Lynch syndrome in this case", "Juvenile polyposis initially", "Familial adenomatous polyposis", "Sporadic polyps in this case"], "ans": 3, "exp": "Familial adenomatous polyposis (FAP): APC gene mutation → polyps หลายร้อย-พันชิ้นในลำไส้ใหญ่ตั้งแต่วัยรุ่น, มะเร็งลำไส้เกือบ 100% ถ้าไม่รักษา → prophylactic total colectomy. เฝ้าระวัง extracolonic (desmoid, duodenal, thyroid). Lynch = mismatch repair, polyp น้อยกว่าแต่มะเร็งเร็ว."}, {"topic": "General/GI Surgery", "q": "A newborn is born with abdominal contents herniating through a defect to the right of the umbilical cord, without a covering sac. What is the diagnosis?", "choices": ["Prune belly syndrome", "Omphalocele", "Umbilical hernia", "Diaphragmatic hernia", "Gastroschisis"], "ans": 4, "exp": "Gastroschisis: ผนังหน้าท้องแยก 'ด้านขวาของสายสะดือ' ลำไส้โผล่ 'ไม่มีถุงหุ้ม' → เสี่ยงสูญเสียน้ำ/อุณหภูมิ, bowel injury. มักไม่สัมพันธ์ความผิดปกติอื่น. รักษา: คลุม bowel ชุ่ม/พันด้วย silo, สารน้ำ, ผ่าตัดปิด. ต่างจาก omphalocele (ผ่านสายสะดือ, มีถุงหุ้ม, สัมพันธ์ anomaly หลายอย่าง)."}, {"topic": "General/GI Surgery", "q": "A newborn has abdominal contents protruding through the umbilical ring covered by a membranous sac. This condition is associated with other anomalies. What is the diagnosis?", "choices": ["Omphalocele", "Gastroschisis", "Meckel diverticulum", "Umbilical hernia", "Patent urachus"], "ans": 0, "exp": "Omphalocele: อวัยวะโผล่ผ่าน 'umbilical ring' มี 'ถุงหุ้ม' (peritoneum/amnion) และสัมพันธ์กับความผิดปกติอื่น (cardiac, chromosomal - trisomy 13/18, Beckwith-Wiedemann). ต่างจาก gastroschisis (ไม่มีถุง, ด้านขวาสายสะดือ, มัก isolated). ประเมิน anomaly ร่วมและผ่าตัดปิด."}, {"topic": "General/GI Surgery", "q": "A neonate has severe respiratory distress at birth with a scaphoid abdomen and bowel sounds heard in the chest. Chest X-ray shows bowel loops in the left hemithorax. What is the diagnosis?", "choices": ["Pneumothorax", "Congenital diaphragmatic hernia", "Esophageal atresia", "Cystic adenomatoid malformation", "Pleural effusion"], "ans": 1, "exp": "Congenital diaphragmatic hernia (มัก left, Bochdalek): อวัยวะช่องท้องเลื่อนเข้าทรวงอก → respiratory distress, scaphoid abdomen, bowel sounds ในอก, mediastinal shift. ปัญหาหลักคือ pulmonary hypoplasia + pulmonary hypertension. รักษา: stabilize (intubate, ห้าม bag-mask นาน), แก้ pulmonary HT, แล้วผ่าตัดซ่อมเมื่อ stable."}, {"topic": "General/GI Surgery", "q": "A 30-year-old man from an endemic area has chronic right lower quadrant pain, weight loss, and a mass; colonoscopy shows ileocecal ulcers and biopsy shows caseating granulomas. What is the diagnosis?", "choices": ["Lymphoma", "Crohn disease", "Intestinal tuberculosis", "Appendiceal cancer", "Amoebiasis"], "ans": 2, "exp": "Intestinal tuberculosis (ชอบ ileocecal region): ปวด RLQ เรื้อรัง, น้ำหนักลด, ก้อน; biopsy พบ 'caseating' granuloma + AFB/PCR. ต่างจาก Crohn (non-caseating granuloma). รักษาด้วย anti-TB; ผ่าตัดเมื่อมีภาวะแทรกซ้อน (obstruction, perforation, fistula). พบบ่อยในไทย."}, {"topic": "General/GI Surgery", "q": "A 25-year-old man has typhoid fever for 2 weeks and suddenly develops severe abdominal pain with peritonitis and free air on X-ray. Where is the perforation most likely located?", "choices": ["Appendix", "Sigmoid colon", "Stomach", "Terminal ileum", "Duodenum"], "ans": 3, "exp": "Typhoid (enteric fever) perforation มักเกิดที่ 'terminal ileum' (Peyer patches necrosis) ในสัปดาห์ที่ 2-3 → peritonitis + pneumoperitoneum. เป็น surgical emergency: resuscitation, antibiotic ครอบคลุม Salmonella + gut flora, laparotomy ซ่อม/resection. พบในพื้นที่ endemic."}, {"topic": "General/GI Surgery", "q": "A 45-year-old woman has episodic flushing, diarrhea, and wheezing; urinary 5-HIAA is elevated, and imaging shows a small bowel mass with liver metastases. What is the diagnosis?", "choices": ["Pheochromocytoma for this patient", "VIPoma for this patient", "Gastrinoma for this patient", "Insulinoma for this patient", "Carcinoid tumor with carcinoid syndrome"], "ans": 4, "exp": "Carcinoid tumor (neuroendocrine, มัก small bowel/appendix) — carcinoid syndrome (flushing, diarrhea, wheezing, right heart valve disease) เกิดเมื่อมี liver metastasis (serotonin ไม่ถูก first-pass metabolism). วินิจฉัย: urinary 5-HIAA, chromogranin A. รักษา: octreotide, resection."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man is 3 days post-op after abdominal surgery and has not passed flatus, with a distended, non-tender, silent abdomen and no air-fluid levels of obstruction. What is the diagnosis?", "choices": ["Paralytic ileus", "Anastomotic leak", "Mechanical obstruction", "Peritonitis", "Colonic pseudo-obstruction"], "ans": 0, "exp": "Postoperative paralytic ileus: ลำไส้ไม่บีบตัวชั่วคราวหลังผ่าตัด — ท้องอืด, silent bowel sounds, ไม่ผายลม, X-ray มีลมกระจายทั้ง small และ large bowel (ไม่มี transition point). รักษาประคับประคอง (NPO/NG, แก้เกลือแร่ - hypokalemia, ลด opioid, early mobilization). ต่างจาก mechanical obstruction."}, {"topic": "General/GI Surgery", "q": "A patient develops profuse watery diarrhea after a course of broad-spectrum antibiotics; stool tests positive for Clostridioides difficile toxin. What is the treatment?", "choices": ["Loperamide for this patient", "Oral vancomycin or fidaxomicin", "Metronidazole IV alone", "Ciprofloxacin as first step", "Probiotics only"], "ans": 1, "exp": "C. difficile infection (หลังยาปฏิชีวนะ): ท้องเสียเป็นน้ำ, toxin/PCR บวก, อาจ pseudomembranous colitis. รักษา (แนวทางปัจจุบัน): oral vancomycin หรือ fidaxomicin เป็น first-line (metronidazole สำหรับ non-severe ที่ไม่มีทางเลือก). Fulminant/toxic megacolon → colectomy. หยุดยาปฏิชีวนะต้นเหตุ, หลีกเลี่ยง antimotility."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with diabetes has severe perianal pain, fever, and crepitus with rapidly spreading necrosis of the perineum. What is the diagnosis and management?", "choices": ["Perianal abscess, drainage", "Anal fissure, sphincterotomy", "Fournier gangrene, emergency debridement", "Hemorrhoids, banding", "Cellulitis, oral antibiotics"], "ans": 2, "exp": "Fournier gangrene: necrotizing fasciitis ของ perineum/genitalia — พบในเบาหวาน/ภูมิคุ้มกันต่ำ, ลุกลามเร็ว, crepitus, ปวดเกินกว่าที่เห็น, sepsis. เป็น surgical emergency → broad-spectrum antibiotic + 'aggressive surgical debridement' ด่วน + resuscitation. อัตราตายสูงถ้าล่าช้า."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has an asymptomatic 1.5 cm gallbladder polyp found incidentally on ultrasound. What is the appropriate management?", "choices": ["Observation only", "ERCP", "Ursodeoxycholic acid", "Cholecystectomy", "Percutaneous drainage"], "ans": 3, "exp": "Gallbladder polyp: ขนาด ≥1 cm (หรือ ≥6-9 mm + ปัจจัยเสี่ยง เช่น อายุ >50, sessile, PSC) เสี่ยงมะเร็ง → แนะนำ cholecystectomy. Polyp <6 mm ไม่มีปัจจัยเสี่ยง → ติดตาม US. Polyp 1.5 cm → ผ่าตัด."}, {"topic": "General/GI Surgery", "q": "A 40-year-old woman has a firm 2 cm liver lesion found incidentally; it shows a central scar and is hypervascular. She is asymptomatic. What is the most likely benign diagnosis?", "choices": ["Hepatocellular carcinoma", "Hepatic adenoma", "Hemangioma", "Metastasis", "Focal nodular hyperplasia"], "ans": 4, "exp": "Focal nodular hyperplasia (FNH): benign, พบในหญิง, มี 'central scar' (stellate) + hypervascular, ไม่มีความเสี่ยงมะเร็ง/แตก → มักติดตามได้ ไม่ต้องผ่าตัด. ต่างจาก hepatic adenoma (สัมพันธ์ OC, เสี่ยงแตก/malignant → พิจารณาผ่าตัดถ้า >5 cm) และ HCC (บน chronic liver disease)."}, {"topic": "General/GI Surgery", "q": "A 60-year-old man with primary sclerosing cholangitis develops worsening jaundice and weight loss; MRCP shows a hilar biliary stricture. What malignancy should be suspected?", "choices": ["Cholangiocarcinoma", "Hepatocellular carcinoma", "Pancreatic cancer", "Gallbladder polyp", "Gastric cancer"], "ans": 0, "exp": "Cholangiocarcinoma (bile duct cancer): เสี่ยงในผู้มี primary sclerosing cholangitis, choledochal cyst, liver fluke (Opisthorchis - พบในอีสาน), hepatolithiasis. Hilar (Klatskin) tumor → obstructive jaundice + weight loss. Marker: CA 19-9. วินิจฉัย MRCP/ERCP + brush cytology. รักษา: resection ถ้า resectable (มักวินิจฉัยระยะท้าย)."}, {"topic": "General/GI Surgery", "q": "A 3-year-old boy has an empty right scrotum, and the testis is palpable in the inguinal canal. What is the appropriate management?", "choices": ["Observation until puberty", "Orchidopexy", "Herniorrhaphy only", "Orchidectomy", "Hormone therapy only"], "ans": 1, "exp": "Undescended testis (cryptorchidism): ถ้าไม่ลงเองภายใน ~6 เดือน → orchidopexy (นิยมทำก่อนอายุ 1-2 ปี) เพื่อลดความเสี่ยง infertility และให้คลำตรวจได้ (เสี่ยงมะเร็ง testis เพิ่มแม้ผ่าตัดแล้ว). Non-palpable testis → laparoscopy หา. ไม่รอถึง puberty."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man has a reducible bulge at the umbilicus that increases with straining. He is asymptomatic. What is the management for a symptomatic or enlarging umbilical hernia?", "choices": ["Truss application", "Observation always", "Elective surgical repair", "Manual reduction only", "Sclerotherapy"], "ans": 2, "exp": "Umbilical hernia ในผู้ใหญ่ (ต่างจากเด็กที่มักหายเอง ≤4-5 ปี): ที่มีอาการ, ใหญ่ขึ้น, หรือเสี่ยง incarceration → elective repair (mesh). สัมพันธ์กับความดันในช่องท้องสูง (ascites, obesity, ตั้งครรภ์). Incarcerated/strangulated → ผ่าตัดฉุกเฉิน."}, {"topic": "General/GI Surgery", "q": "A malnourished patient started on aggressive feeding develops hypophosphatemia, hypokalemia, and hypomagnesemia. What is this syndrome?", "choices": ["Dumping syndrome", "Short bowel syndrome", "Tumor lysis syndrome", "Refeeding syndrome", "SIADH"], "ans": 3, "exp": "Refeeding syndrome: ในผู้ขาดอาหารรุนแรงที่เริ่มให้อาหารเร็วเกิน → insulin surge ดึง phosphate/potassium/magnesium เข้าเซลล์ → hypophosphatemia (เด่น), hypokalemia, hypomagnesemia → เสี่ยง arrhythmia/หัวใจล้มเหลว. ป้องกัน: เริ่มให้อาหารช้าๆ, เสริม thiamine, ติดตามเกลือแร่."}, {"topic": "General/GI Surgery", "q": "A patient with extensive small bowel resection has chronic diarrhea, malabsorption, and weight loss. What is the diagnosis?", "choices": ["Blind loop syndrome", "Dumping syndrome", "Chronic pancreatitis", "Celiac disease", "Short bowel syndrome"], "ans": 4, "exp": "Short bowel syndrome: หลังตัด small bowel มาก (เหลือ <200 cm) → malabsorption, ท้องเสีย, น้ำหนักลด, ขาดสารอาหาร/vitamin. รักษา: nutritional support (อาจ TPN), ยาลด motility/secretion, ค่อยๆ ปรับ enteral. Ileocecal valve และความยาวที่เหลือมีผลต่อ prognosis."}, {"topic": "General/GI Surgery", "q": "A 58-year-old man undergoing major abdominal cancer surgery needs venous thromboembolism prophylaxis. Which is appropriate perioperatively?", "choices": ["Mechanical plus pharmacologic prophylaxis", "No prophylaxis for this patient", "High-dose aspirin only", "Warfarin loading for this patient", "Therapeutic heparin infusion initially"], "ans": 0, "exp": "ผู้ป่วยผ่าตัดมะเร็งช่องท้อง = high VTE risk → แนะนำ mechanical (intermittent pneumatic compression) + pharmacologic prophylaxis (LMWH/heparin) และมัก extended prophylaxis ~4 สัปดาห์หลังผ่าตัดมะเร็ง. Early mobilization ช่วย. ประเมินความเสี่ยงเลือดออกร่วมด้วย."}, {"topic": "General/GI Surgery", "q": "A surgeon wants to reduce surgical site infection for a clean-contaminated colorectal operation. Which measure is most appropriate?", "choices": ["Antibiotics for 7 days postop for this patient", "Prophylactic antibiotic within 60 minutes before incision", "Shaving with a razor the night before for this patient", "Hypothermia during surgery for this patient", "No antibiotics needed for this patient"], "ans": 1, "exp": "การป้องกัน SSI: ให้ prophylactic antibiotic ครอบคลุมเชื้อที่คาด 'ภายใน 60 นาทีก่อนลงมีด' (ให้ครบก่อน incision), รักษา normothermia/normoglycemia/oxygenation, clipping (ไม่ใช้ razor), skin prep (chlorhexidine). ไม่จำเป็นต้องให้ยาปฏิชีวนะยาวหลังผ่าตัดใน clean case."}, {"topic": "General/GI Surgery", "q": "A 45-year-old man is diagnosed with ascending cholangitis with hypotension and confusion despite antibiotics. What is the most important definitive intervention?", "choices": ["Continue antibiotics only", "Cholecystectomy immediately", "Urgent biliary drainage (ERCP)", "Percutaneous liver biopsy", "Barium study"], "ans": 2, "exp": "Severe/suppurative cholangitis (Reynolds pentad: Charcot triad + hypotension + confusion) → ต้อง 'biliary decompression/drainage ด่วน' (ERCP + sphincterotomy/stent เป็นวิธีเลือก; ถ้าไม่ได้ใช้ PTBD หรือผ่าตัด) ร่วมกับ resuscitation + antibiotic. การให้ยาปฏิชีวนะอย่างเดียวไม่พอเมื่อมีการอุดกั้น."}, {"topic": "General/GI Surgery", "q": "A 30-year-old woman has a periumbilical hernia. During examination you note the defect is at the linea alba above the umbilicus. What type of hernia is this?", "choices": ["Spigelian hernia", "Femoral hernia", "Obturator hernia", "Epigastric hernia", "Lumbar hernia"], "ans": 3, "exp": "Epigastric hernia: ยื่นผ่าน linea alba 'เหนือสะดือ' (ระหว่าง xiphoid กับ umbilicus), มักเล็กและมี preperitoneal fat. Spigelian = ผ่าน semilunar line (ด้านข้าง). Obturator = ผ่าน obturator foramen (พบในหญิงสูงอายุผอม, Howship-Romberg sign). การระบุตำแหน่งช่วยแยกชนิด hernia."}, {"topic": "General/GI Surgery", "q": "A 55-year-old man with cirrhosis has ascites and develops fever and abdominal pain. Paracentesis shows 400 neutrophils/mm3. What is the diagnosis?", "choices": ["Pancreatic ascites", "Secondary peritonitis", "Tuberculous peritonitis", "Malignant ascites", "Spontaneous bacterial peritonitis"], "ans": 4, "exp": "Spontaneous bacterial peritonitis (SBP): ในผู้ป่วย cirrhosis + ascites — ไข้/ปวดท้อง + ascitic PMN ≥250/mm3 (โดยไม่มีแหล่งติดเชื้อในช่องท้องที่ผ่าตัดได้). รักษาด้วย cefotaxime/ceftriaxone + IV albumin (ลด hepatorenal syndrome). ป้องกันซ้ำด้วย norfloxacin. แยกจาก secondary peritonitis (polymicrobial, ต้องผ่าตัด)."}, {"topic": "General/GI Surgery", "q": "A 40-year-old woman has recurrent right upper quadrant pain; HIDA scan shows a gallbladder ejection fraction of 20% with no stones. What is the diagnosis?", "choices": ["Biliary dyskinesia", "Sphincter of Oddi stenosis", "Acute cholecystitis", "Choledocholithiasis", "Chronic pancreatitis"], "ans": 0, "exp": "Biliary dyskinesia (functional gallbladder disorder): อาการ biliary colic แต่ 'ไม่มีนิ่ว' + HIDA scan พบ gallbladder ejection fraction ต่ำ (<35-40%). รักษาด้วย cholecystectomy ในรายที่อาการเข้าได้และ EF ต่ำ. ต้องแยกสาเหตุอื่นของ RUQ pain ก่อน."}, {"topic": "General/GI Surgery", "q": "A 62-year-old man with a colonic adenocarcinoma is found to have three liver metastases confined to one lobe. He is otherwise fit. What is the potential management for resectable liver metastases?", "choices": ["Palliative care only", "Hepatic resection with chemotherapy", "Radiotherapy alone", "Observation for this patient", "Antibiotics for this patient"], "ans": 1, "exp": "Colorectal liver metastases ที่ resectable (จำกัด, ทำงานตับพอ) สามารถรักษาด้วย hepatic resection ± perioperative chemotherapy → ให้โอกาสหายระยะยาว. ประเมินโดยทีม multidisciplinary. Ablation/portal vein embolization ช่วยในบางราย. ต่างจากมะเร็งอื่นที่ metastasis มักหมายถึง palliative."}, {"topic": "General/GI Surgery", "q": "A 20-year-old man has painless rectal bleeding with multiple hamartomatous polyps and mucocutaneous pigmentation of the lips. What is the diagnosis?", "choices": ["Lynch syndrome", "Familial adenomatous polyposis", "Peutz-Jeghers syndrome", "Juvenile polyposis", "Cronkhite-Canada syndrome"], "ans": 2, "exp": "Peutz-Jeghers syndrome (STK11 mutation): hamartomatous polyps ทั่ว GI + mucocutaneous pigmentation (ริมฝีปาก/buccal). เสี่ยง intussusception, เลือดออก, และมะเร็งหลายชนิด (GI, เต้านม, รังไข่, ตับอ่อน). ต้อง surveillance. ต่างจาก FAP (adenomatous polyps, APC)."}, {"topic": "General/GI Surgery", "q": "A 50-year-old man has weight loss and iron-deficiency anemia. Colonoscopy is normal but capsule endoscopy shows an angiodysplasia in the small bowel. What is the significance of angiodysplasia?", "choices": ["A premalignant lesion", "An infectious lesion", "A congenital atresia", "A source of GI bleeding", "A parasitic infection"], "ans": 3, "exp": "Angiodysplasia (vascular ectasia): หลอดเลือดผิดปกติในผนัง GI (มัก right colon, small bowel) เป็นสาเหตุ GI bleeding (ซ่อนเร้น/ชัดเจน) โดยเฉพาะผู้สูงอายุ, สัมพันธ์กับ aortic stenosis (Heyde syndrome), CKD. รักษา: endoscopic coagulation; ดื้อ → embolization/resection."}, {"topic": "General/GI Surgery", "q": "A 68-year-old man with atherosclerosis has crampy left-sided abdominal pain and bloody diarrhea after an episode of hypotension. Colonoscopy shows mucosal edema at the splenic flexure. What is the diagnosis?", "choices": ["Diverticulitis", "Ulcerative colitis", "C. difficile colitis", "Colon cancer", "Ischemic colitis"], "ans": 4, "exp": "Ischemic colitis: มักผู้สูงอายุที่มี atherosclerosis/hypotension (low-flow) → ปวดท้องซ้าย + ถ่ายเป็นเลือด; ตำแหน่งเสี่ยงคือ 'watershed areas' (splenic flexure, rectosigmoid). ส่วนใหญ่ mucosal (หายด้วย supportive: IV fluid, bowel rest, antibiotic); transmural/gangrene → ผ่าตัด. ต่างจาก acute mesenteric ischemia (SMA, รุนแรงกว่า)."}]}, {"id": "surg2", "title": "Surgery ชุดที่ 2 — Trauma, Burns, Critical Care, Breast & Endocrine Surgery", "subject": "surg", "questions": [{"topic": "Trauma & Critical Care", "q": "A 25-year-old man is brought to the trauma bay after a motorcycle crash. According to ATLS, what is the first priority in the primary survey?", "choices": ["Airway with cervical spine control", "Breathing assessment initially", "Exposure of the patient alone", "Circulation control in this case", "Disability assessment initially"], "ans": 0, "exp": "ATLS primary survey เรียงตาม ABCDE: 'Airway with cervical spine protection' มาก่อนเสมอ (ทางเดินหายใจอุดตันฆ่าเร็วสุด) — พร้อมป้องกัน c-spine. ตามด้วย Breathing, Circulation (ห้ามเลือด), Disability (GCS/pupils), Exposure. จัดการปัญหาที่พบทันทีก่อนไปขั้นถัดไป."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient is tachycardic and hypoxic with decreased breath sounds on the left, a trachea deviated to the right, and distended neck veins. What is the most critical immediate intervention?", "choices": ["Endotracheal intubation", "Needle decompression", "Pericardiocentesis", "Chest tube insertion first", "Emergency thoracotomy"], "ans": 1, "exp": "Tension pneumothorax: หายใจลำบาก + เสียงหายใจลด + trachea เบนไปด้านตรงข้าม + neck vein โป่ง + hypotension. เป็น clinical diagnosis (ไม่รอ X-ray) → 'needle decompression' ทันที (2nd ICS midclavicular หรือ 5th ICS anterior axillary) ตามด้วย chest tube. เป็นภาวะฉุกเฉินที่ต้องแก้ทันที."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has hypotension, muffled heart sounds, and distended neck veins after blunt chest trauma. What is the diagnosis (Beck triad)?", "choices": ["Tension pneumothorax", "Flail chest", "Cardiac tamponade", "Massive hemothorax", "Aortic rupture"], "ans": 2, "exp": "Cardiac tamponade — Beck triad: hypotension + muffled heart sounds + distended neck veins (JVP สูง). ยืนยันด้วย FAST (pericardial fluid). รักษา: pericardiocentesis เป็น bridge, definitive คือ pericardial window/thoracotomy. ต่างจาก tension pneumothorax (trachea เบน, เสียงหายใจลด)."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has decreased breath sounds and dullness to percussion on the left with hypotension; over 1500 mL of blood drains after chest tube insertion. What is the diagnosis?", "choices": ["Tension pneumothorax", "Cardiac tamponade", "Pulmonary contusion", "Massive hemothorax", "Simple pneumothorax"], "ans": 3, "exp": "Massive hemothorax: เสียงหายใจลด + percussion ทึบ (dull) + hypotension; chest tube ออกเลือด >1,500 mL ทันที หรือ >200 mL/ชม. × 2-4 ชม. → ข้อบ่งชี้ thoracotomy. รักษา: resuscitation + chest tube + พิจารณาผ่าตัด. ต่างจาก pneumothorax (percussion hyperresonant)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old man has multiple rib fractures with a segment of chest wall that moves paradoxically with respiration. What is the diagnosis?", "choices": ["Diaphragmatic rupture", "Tension pneumothorax", "Massive hemothorax", "Cardiac tamponade", "Flail chest"], "ans": 4, "exp": "Flail chest: ซี่โครงหัก ≥2 ตำแหน่งต่อซี่ใน ≥2 ซี่ติดกัน → segment เคลื่อน 'paradoxical' (บุ๋มตอนหายใจเข้า). ปัญหาหลักคือ pulmonary contusion ข้างใต้ → hypoxia. รักษา: ควบคุมความปวด (ช่วยหายใจ), O2/ventilation support, กายภาพ; รุนแรง → intubation หรือ surgical fixation."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has lost an estimated 30-40% of blood volume, with tachycardia, hypotension, and confusion. What class of hemorrhagic shock is this?", "choices": ["Class III", "Class II", "Class I", "Class IV", "No shock"], "ans": 0, "exp": "Hemorrhagic shock (ATLS): Class I (<15%, ปกติ), Class II (15-30%, tachycardia, narrowed pulse pressure), Class III (30-40%, hypotension, tachycardia, confused, oliguria), Class IV (>40%, ใกล้ตาย). Class III เริ่มมี hypotension ชัด. รักษา: ห้ามเลือด + balanced resuscitation (blood products)."}, {"topic": "Trauma & Critical Care", "q": "A hypotensive blunt trauma patient has a positive FAST scan (free fluid in the abdomen). What is the most appropriate management?", "choices": ["CT abdomen then decide", "Exploratory laparotomy", "Diagnostic peritoneal lavage", "Observation and repeat FAST", "Angioembolization only"], "ans": 1, "exp": "Blunt abdominal trauma ที่ 'hemodynamically unstable' + FAST positive (free fluid) → 'exploratory laparotomy' ทันที (ไม่รอ CT). ผู้ป่วย stable + FAST positive → CT scan เพื่อ grade injury และพิจารณา non-operative management (โดยเฉพาะ solid organ). FAST ประเมิน hemoperitoneum/tamponade เร็วข้างเตียง."}, {"topic": "Trauma & Critical Care", "q": "A restrained driver has a 'seat belt sign' bruise across the lower abdomen. This is most associated with injury to which structures?", "choices": ["Rib and lung initially", "Myocardium in this case", "Small bowel and mesentery", "Liver only", "Kidney only"], "ans": 2, "exp": "Seat belt sign (รอยฟกช้ำตามแนวเข็มขัดที่ท้องน้อย) สัมพันธ์กับ 'small bowel/mesenteric injury' และ lumbar spine fracture (Chance fracture). แม้แรกรับ stable ก็ต้องเฝ้าระวัง/CT เพราะ hollow viscus injury อาจแสดงอาการช้า (peritonitis)."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has pelvic instability and hypotension. What is an appropriate immediate measure to reduce pelvic bleeding?", "choices": ["CT pelvis first", "Immediate laparotomy", "Traction of the legs", "Apply a pelvic binder", "Foley catheter only"], "ans": 3, "exp": "Unstable pelvic fracture + hypotension: 'pelvic binder' (ที่ระดับ greater trochanter) ลดปริมาตรและ stabilize เพื่อลดเลือดออก (venous/bony). ต่อด้วย resuscitation; ถ้ายัง unstable → angioembolization (arterial) หรือ preperitoneal packing. ประเมิน associated injury (urethra - ตรวจก่อนใส่ Foley)."}, {"topic": "Trauma & Critical Care", "q": "A 35-year-old man with severe facial trauma, midface instability, and active bleeding cannot maintain his airway. What is the most appropriate method to secure the airway?", "choices": ["Nasotracheal intubation", "Orotracheal intubation with RSI", "Await CT imaging", "Bag-mask ventilation only", "Cricothyroidotomy if intubation fails"], "ans": 4, "exp": "Severe midface/facial trauma ที่ airway เสี่ยง: หลีกเลี่ยง nasotracheal (เสี่ยง cribriform plate). พยายาม orotracheal intubation (RSI); ถ้าล้มเหลว/ทำไม่ได้ → 'surgical airway (cricothyroidotomy)'. ยึดหลัก 'definitive airway' เมื่อ protect ไม่ได้ (GCS ต่ำ, ทางเดินหายใจเสียหาย)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old man has 50% total body surface area burns and weighs 80 kg. Using the Parkland formula (4 mL/kg/%TBSA), how should the calculated fluid be given?", "choices": ["Half over the first 8 hours, half over next 16 hours", "All as an immediate bolus for this patient", "Evenly over 24 hours for this patient", "Half over the first 4 hours for this patient", "Over 48 hours equally for this patient"], "ans": 0, "exp": "Parkland formula: 4 mL × น้ำหนัก(kg) × %TBSA ของ crystalloid (Ringer's lactate) ใน 24 ชม.แรก — ให้ 'ครึ่งแรกใน 8 ชม.แรก' (นับจากเวลาที่โดนไฟ) และครึ่งหลังใน 16 ชม.ถัดไป. ปรับตาม urine output (0.5 mL/kg/hr ผู้ใหญ่). ตัวอย่าง: 4×80×50 = 16,000 mL."}, {"topic": "Trauma & Critical Care", "q": "A burn victim has full-thickness circumferential burns of the forearm with a cold, pulseless hand. What is the most appropriate intervention?", "choices": ["Elevation only", "Escharotomy", "Fasciotomy", "Amputation", "Observation"], "ans": 1, "exp": "Circumferential full-thickness burn ทำให้ eschar แข็งรัด → compartment syndrome/ischemia (แขน) หรือจำกัดการหายใจ (ทรวงอก). รักษาด้วย 'escharotomy' (กรีด eschar ตามยาว) เพื่อคลายแรงกด. ต่างจาก fasciotomy (กรีดถึง fascia ใน compartment syndrome จาก crush/vascular)."}, {"topic": "Trauma & Critical Care", "q": "A house-fire victim has facial burns, singed nasal hairs, carbonaceous sputum, and hoarseness. What is the priority?", "choices": ["Delay intubation for this patient", "Oral antibiotics for this patient", "Early intubation for airway protection", "High-dose steroids for this patient", "Wait for edema to develop initially"], "ans": 2, "exp": "สัญญาณ inhalation injury (ขนจมูกไหม้, เสมหะดำ, เสียงแหบ, บวมใบหน้า/ในปาก) → airway edema จะแย่ลงเร็ว → 'early intubation' ก่อนบวมจนใส่ท่อไม่ได้. ประเมิน carbon monoxide (ให้ O2 100%) และ cyanide poisoning. อย่ารอ."}, {"topic": "Trauma & Critical Care", "q": "A construction worker sustained a high-voltage electrical injury with entry and exit wounds. Besides cardiac monitoring, what complication requires monitoring of urine output for pigment?", "choices": ["Hypernatremia for this patient", "Hyperkalemia only", "Refeeding syndrome in this case", "Rhabdomyolysis with myoglobinuria", "Fat embolism for this patient"], "ans": 3, "exp": "Electrical injury ทำให้กล้ามเนื้อลึกถูกทำลาย (แผลภายนอกอาจดูน้อยแต่ภายในมาก) → rhabdomyolysis → myoglobinuria → acute kidney injury. เฝ้าระวัง: อัตราการให้สารน้ำสูงกว่า Parkland เพื่อคง urine output, ปัสสาวะสีเข้ม/แดง, hyperkalemia, arrhythmia, compartment syndrome. ตรวจ CK."}, {"topic": "Trauma & Critical Care", "q": "A 45-year-old farmer is bitten by a pit viper 30 minutes ago; the limb is swollen and painful. What is the most appropriate first action?", "choices": ["Apply an arterial tourniquet for this patient", "Incise and suck the wound for this patient", "Give antivenom to everyone for this patient", "Apply ice packs for this patient", "Immobilize the limb and obtain coagulation studies"], "ans": 4, "exp": "Snakebite (pit viper/งูกลุ่มพิษต่อเลือด): ปฐมพยาบาล — ให้ผู้ป่วยนิ่ง, 'immobilize' แขนขาระดับหัวใจ, นำส่ง รพ., และประเมิน envenomation (coagulation studies - VCT/INR, platelet, local swelling). ให้ antivenom เมื่อมี systemic/severe local envenomation (ไม่ใช่ทุกราย). ห้าม tourniquet แน่น/กรีดดูด/ประคบน้ำแข็ง."}, {"topic": "Trauma & Critical Care", "q": "A 5-year-old is pulled from a pool, apneic but with a palpable pulse. What is the most critical next step?", "choices": ["Provide rescue breaths/ventilation", "Start chest compressions", "Establish IV access", "Administer epinephrine", "Perform cricothyroidotomy"], "ans": 0, "exp": "เด็กจมน้ำที่ apneic แต่ 'มีชีพจร' → ปัญหาหลักคือ respiratory (hypoxia) → ให้ 'rescue breaths/ventilation' ทันที (ในเด็ก respiratory arrest นำ cardiac arrest). ถ้าไม่มีชีพจร → เริ่ม CPR. Pediatric arrest ส่วนใหญ่เป็น respiratory/hypoxic origin ต่างจากผู้ใหญ่ (cardiac)."}, {"topic": "Trauma & Critical Care", "q": "A 50-year-old woman has a hard, fixed breast lump with skin dimpling and an enlarged axillary node. What is the appropriate diagnostic approach?", "choices": ["Reassure and repeat in 1 year in this case", "Triple assessment (clinical, imaging, biopsy)", "Antibiotics and observe for this patient", "Aspirate and discard for this patient", "Immediate mastectomy for this patient"], "ans": 1, "exp": "ก้อนเต้านมสงสัยมะเร็ง (แข็ง ติดแน่น ผิวบุ๋ม + axillary node): ประเมินด้วย 'triple assessment' — clinical exam + imaging (mammogram ± US, MRI บางราย) + core needle biopsy (histology). ยืนยันก่อนวางแผนรักษา (surgery ± chemo/RT/endocrine ตาม receptor/stage)."}, {"topic": "Trauma & Critical Care", "q": "A 60-year-old woman has newly diagnosed invasive ductal carcinoma. Which receptors must be assessed to guide systemic therapy?", "choices": ["CEA and CA 15-3", "AFP and hCG", "ER, PR, and HER2", "CA 19-9 only", "PSA and ALP"], "ans": 2, "exp": "Breast cancer ต้องตรวจ ER, PR (hormone receptor) และ HER2 (± Ki-67) เพื่อกำหนดการรักษา: ER/PR positive → endocrine therapy (tamoxifen/aromatase inhibitor); HER2 positive → trastuzumab; triple-negative → chemotherapy. เป็นตัวกำหนด systemic therapy และพยากรณ์โรค."}, {"topic": "Trauma & Critical Care", "q": "A 25-year-old woman has a mobile, well-defined 2 cm breast lump confirmed as a fibroadenoma by triple assessment. What is the appropriate management if it is small and stable?", "choices": ["Mastectomy for this patient", "Chemotherapy for this patient", "Radiotherapy for this patient", "Observation or excision if it grows", "Long-term tamoxifen in this case"], "ans": 3, "exp": "Fibroadenoma ที่ยืนยัน triple assessment ในหญิงสาว ขนาดเล็กและคงที่ → ติดตามได้ (มักคงที่/ฝ่อ). Excision ถ้าโตขึ้น, >2-3 cm, มีอาการ, ผลไม่สอดคล้อง หรือผู้ป่วยต้องการ. เป็น benign ไม่ใช่มะเร็ง."}, {"topic": "Trauma & Critical Care", "q": "A 40-year-old man has bilateral tender breast enlargement. Which is a common cause of gynecomastia to evaluate?", "choices": ["Endometriosis in this case", "Ovarian cyst in this case", "Pyloric stenosis initially", "Cholelithiasis initially", "Drugs and hormonal imbalance"], "ans": 4, "exp": "Gynecomastia (proliferation ของ glandular tissue) จากความไม่สมดุล estrogen:androgen — สาเหตุ: ยา (spironolactone, cimetidine, antipsychotics, anabolic steroid), liver/renal disease, hyperthyroid, hypogonadism, tumor (testicular, adrenal). แยกจาก pseudogynecomastia (ไขมัน) และมะเร็งเต้านมชาย (ก้อนแข็ง eccentric). ประเมินยา/ฮอร์โมน."}, {"topic": "Trauma & Critical Care", "q": "A 45-year-old woman has a solitary 2 cm thyroid nodule. Ultrasound shows suspicious features. What is the most appropriate next investigation?", "choices": ["Fine-needle aspiration cytology", "Thyroid scan for this patient", "Observation only", "Thyroidectomy as first step", "CT neck for this patient"], "ans": 0, "exp": "Thyroid nodule ที่มีลักษณะ US น่าสงสัย (hypoechoic, microcalcification, irregular margin, taller-than-wide) → 'fine-needle aspiration (FNA) cytology' (ตาม Bethesda system) เป็นการตรวจหลักแยก benign/malignant. Thyroid scan ใช้เมื่อ TSH ต่ำ (แยก autonomous 'hot' nodule ซึ่งไม่ค่อยเป็นมะเร็ง)."}, {"topic": "Trauma & Critical Care", "q": "A 35-year-old woman has a thyroid nodule; FNA shows papillary thyroid carcinoma. Which feature is characteristic of this cancer?", "choices": ["Spread mainly via blood", "Lymphatic spread with good prognosis", "Very poor prognosis", "Amyloid deposition", "Secretes catecholamines"], "ans": 1, "exp": "Papillary thyroid carcinoma (พบบ่อยสุด ~80%): แพร่ทาง 'lymphatic' (cervical nodes) แต่พยากรณ์ 'ดีมาก'. Histology: Orphan Annie nuclei, psammoma bodies. รักษา: thyroidectomy ± node dissection ± radioiodine. Follicular = hematogenous spread; Medullary = calcitonin/amyloid (MEN2); Anaplastic = พยากรณ์แย่มาก."}, {"topic": "Trauma & Critical Care", "q": "A patient with a thyroid nodule has an elevated calcitonin level and a family history of thyroid cancer and pheochromocytoma. Which cancer and syndrome is likely?", "choices": ["Papillary carcinoma, MEN1", "Lymphoma, sporadic", "Medullary carcinoma, MEN2", "Follicular carcinoma, MEN1", "Anaplastic carcinoma, MEN2"], "ans": 2, "exp": "Medullary thyroid carcinoma (จาก parafollicular C cells): หลั่ง 'calcitonin' (marker) + CEA, มี amyloid stroma. สัมพันธ์กับ MEN2 (RET mutation) — MTC + pheochromocytoma + parathyroid (2A)/mucosal neuroma (2B). ต้องตรวจ RET, คัดกรอง pheo ก่อนผ่าตัด, total thyroidectomy + central node dissection."}, {"topic": "Trauma & Critical Care", "q": "A patient has hypercalcemia, an elevated PTH, and kidney stones. Imaging localizes a single parathyroid adenoma. What is the diagnosis and treatment?", "choices": ["Secondary hyperparathyroidism, calcium", "Malignancy, chemotherapy", "Hypoparathyroidism, vitamin D", "Primary hyperparathyroidism, parathyroidectomy", "Sarcoidosis, steroids"], "ans": 3, "exp": "Primary hyperparathyroidism: hypercalcemia + PTH สูง (inappropriate) — 'stones, bones, groans, psychiatric moans'. สาเหตุบ่อยสุดคือ single parathyroid adenoma → localize (sestamibi/US) → 'parathyroidectomy' (รักษาหาย). Secondary = จาก CKD (Ca ต่ำ/PO4 สูง → PTH สูงชดเชย)."}, {"topic": "Trauma & Critical Care", "q": "A 40-year-old with episodic headache, palpitations, sweating, and severe hypertension has elevated plasma metanephrines and an adrenal mass. Before surgery, which must be started first?", "choices": ["Beta-blocker first for this patient", "Diuretic first for this patient", "ACE inhibitor first for this patient", "Calcium channel blocker only", "Alpha-blockade first, then beta-blocker"], "ans": 4, "exp": "Pheochromocytoma (catecholamine-secreting adrenal tumor): triad ปวดศีรษะ + ใจสั่น + เหงื่อ + HT เป็นพักๆ; วินิจฉัยด้วย plasma/urine metanephrines. เตรียมผ่าตัดต้อง 'alpha-blockade ก่อน' (phenoxybenzamine/doxazosin) 1-2 สัปดาห์ แล้วค่อยเพิ่ม beta-blocker — ห้ามให้ beta ก่อน alpha (เกิด unopposed alpha → hypertensive crisis)."}, {"topic": "Trauma & Critical Care", "q": "A 6 cm adrenal mass is found incidentally. Which features raise concern for malignancy (adrenocortical carcinoma)?", "choices": ["Large size and irregular features", "Small size and low density", "Bilateral small nodules", "High lipid content", "Homogeneous appearance"], "ans": 0, "exp": "Adrenal incidentaloma: ประเมิน (1) functional (hormone workup: cortisol/dexamethasone, metanephrines, aldosterone:renin) และ (2) malignant potential. ลักษณะเสี่ยงมะเร็ง (adrenocortical carcinoma/metastasis): ขนาดใหญ่ (>4-6 cm), irregular, heterogeneous, high HU (>10) non-contrast, โตเร็ว → ผ่าตัด. Small (<4 cm), lipid-rich, homogeneous มัก benign adenoma."}, {"topic": "Trauma & Critical Care", "q": "A 55-year-old man has severe pain, swelling, and rapidly spreading erythema of the leg with skin necrosis and crepitus, and is septic. What is the diagnosis and management?", "choices": ["Cellulitis, oral antibiotics for this patient", "Necrotizing fasciitis, urgent surgical debridement", "Abscess, drainage for this patient", "DVT, anticoagulation for this patient", "Erysipelas, penicillin for this patient"], "ans": 1, "exp": "Necrotizing fasciitis: ลุกลามเร็ว, ปวดเกินกว่าที่เห็น, ผิวคล้ำ/necrosis/bullae, crepitus, systemic toxicity. เป็น surgical emergency → 'early aggressive surgical debridement' + broad-spectrum antibiotic (รวม clindamycin) + resuscitation. LRINEC score ช่วยประเมิน. ล่าช้าตายสูง. ต่างจาก cellulitis (ผิวเผิน, ตอบสนองยา)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old woman has an asymmetric, irregularly bordered, variably colored skin lesion that has enlarged. Biopsy is planned. Which cancer is suspected?", "choices": ["Basal cell carcinoma", "Seborrheic keratosis", "Melanoma", "Squamous cell carcinoma", "Actinic keratosis"], "ans": 2, "exp": "Melanoma — ABCDE: Asymmetry, Border irregular, Color variegation, Diameter >6 mm, Evolving. วินิจฉัยด้วย 'excisional biopsy' (full thickness) — Breslow thickness กำหนดพยากรณ์/margin. หลีกเลี่ยง shave biopsy. รักษา: wide local excision ± sentinel node ± systemic (immunotherapy/targeted)."}, {"topic": "Trauma & Critical Care", "q": "An elderly man has a slow-growing, pearly papule with rolled borders and central ulceration on the face that rarely metastasizes. What is the diagnosis?", "choices": ["Keratoacanthoma", "Squamous cell carcinoma", "Melanoma", "Basal cell carcinoma", "Actinic keratosis"], "ans": 3, "exp": "Basal cell carcinoma (BCC): มะเร็งผิวหนังที่พบบ่อยสุด — ตุ่ม pearly/waxy, rolled border, telangiectasia, central ulcer ('rodent ulcer'), บริเวณโดนแดด. โตช้า, ลุกลามเฉพาะที่, 'แทบไม่ metastasis'. รักษา: excision (± Mohs บริเวณใบหน้า). SCC โตเร็วกว่าและ metastasis ได้."}, {"topic": "Trauma & Critical Care", "q": "A patient has resistant hypertension, hypokalemia, and metabolic alkalosis; the aldosterone-to-renin ratio is high with an adrenal adenoma. What is the diagnosis?", "choices": ["Cushing syndrome for this patient", "Pheochromocytoma for this patient", "Addison disease for this patient", "Bartter syndrome for this patient", "Primary hyperaldosteronism (Conn syndrome)"], "ans": 4, "exp": "Primary hyperaldosteronism (Conn syndrome): HT ดื้อยา + hypokalemia + metabolic alkalosis + aldosterone:renin ratio สูง. สาเหตุ: adrenal adenoma (Conn) หรือ bilateral hyperplasia. Adenoma ข้างเดียว (ยืนยัน adrenal vein sampling) → adrenalectomy; hyperplasia → spironolactone/eplerenone. เป็นสาเหตุ secondary HT ที่รักษาได้."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient opens eyes to pain, makes incomprehensible sounds, and withdraws from pain. What is his Glasgow Coma Scale score?", "choices": ["GCS 8", "GCS 6", "GCS 12", "GCS 10", "GCS 14"], "ans": 0, "exp": "GCS: Eye opening to pain = 2, Verbal incomprehensible sounds = 2, Motor withdrawal to pain = 4 → รวม = 8. GCS ≤8 = ข้อบ่งชี้ 'definitive airway' (intubation, 'GCS 8 = intubate'). GCS สูงสุด 15, ต่ำสุด 3. ใช้ประเมินระดับความรู้สึกตัวและติดตามการเปลี่ยนแปลง."}, {"topic": "Trauma & Critical Care", "q": "A soldier has severe arterial bleeding from a mangled limb that is not controlled by direct pressure. What is the appropriate immediate measure?", "choices": ["Elevate the limb only", "Apply a tourniquet proximal to the wound", "Apply ice for this patient", "Start IV antibiotics for this patient", "Wait for surgery for this patient"], "ans": 1, "exp": "เลือดออกจากหลอดเลือดแดงที่แขนขา ที่ direct pressure คุมไม่ได้ (exsanguinating) → ใช้ 'tourniquet' เหนือแผลทันที (บันทึกเวลา) เป็นมาตรการช่วยชีวิต. ต่อด้วย resuscitation และ definitive vascular control. ต่างจาก snakebite (ไม่ใช้ tourniquet)."}, {"topic": "Trauma & Critical Care", "q": "A massively bleeding trauma patient receives blood products. Which ratio approximates balanced resuscitation (massive transfusion protocol)?", "choices": ["Crystalloid only", "4:1:1 crystalloid ratio for this patient", "1:1:1 of packed cells, plasma, and platelets", "Plasma alone", "Platelets alone"], "ans": 2, "exp": "Massive transfusion / balanced resuscitation: ให้ packed RBC : FFP : platelet ในอัตราส่วนใกล้ '1:1:1' เพื่อป้องกัน trauma-induced coagulopathy. หลีกเลี่ยงการให้ crystalloid ปริมาณมาก (dilutional coagulopathy). ควบคุม 'lethal triad': hypothermia + acidosis + coagulopathy. ใช้ TXA ภายใน 3 ชม.และ damage control."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient in extremis undergoes abbreviated surgery to control hemorrhage and contamination, with definitive repair delayed. What is this strategy called?", "choices": ["Elective staged repair", "Second-look laparotomy", "Definitive laparotomy", "Damage control surgery", "Conservative management"], "ans": 3, "exp": "Damage control surgery: ในผู้ป่วยวิกฤต (lethal triad) — ทำผ่าตัดสั้นๆ เพื่อ 'ห้ามเลือด + ควบคุมการปนเปื้อน' (packing, temporary closure) แล้วนำไป ICU แก้ physiology (อุ่น, แก้ acidosis/coagulopathy) ก่อนกลับมาผ่าตัด definitive ภายหลัง. ช่วยลดการตายในผู้ป่วยที่ทน prolonged surgery ไม่ไหว."}, {"topic": "Trauma & Critical Care", "q": "A man has a pelvic fracture with blood at the urethral meatus and inability to void. What must be done before urethral catheterization?", "choices": ["Insert Foley immediately", "CT abdomen only", "Suprapubic tap blindly", "No evaluation needed", "Retrograde urethrogram"], "ans": 4, "exp": "Pelvic fracture + blood at meatus + high-riding prostate + ไม่ปัสสาวะ = สงสัย 'urethral injury' → ห้ามใส่ Foley ก่อน (อาจทำให้บาดเจ็บเพิ่ม/สมบูรณ์) → ทำ 'retrograde urethrogram' ก่อน. ถ้ามี urethral injury → suprapubic catheter. Anterior/posterior urethral injury สัมพันธ์กับ pelvic trauma/straddle."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient develops the 'lethal triad'. Which three components make it up?", "choices": ["Hypothermia, acidosis, coagulopathy", "Fever, leukocytosis, tachycardia", "Hypertension, bradycardia, apnea", "Hyperkalemia, acidosis, uremia", "Hypoxia, hypercarbia, acidosis"], "ans": 0, "exp": "Trauma lethal triad (vicious cycle): 'hypothermia + metabolic acidosis + coagulopathy' — เสริมกันทำให้เลือดออกไม่หยุดและตายสูง. การจัดการ: keep warm, balanced blood product resuscitation, TXA, damage control surgery, permissive hypotension (ในบางกรณี), หลีกเลี่ยง crystalloid มากเกิน."}, {"topic": "Trauma & Critical Care", "q": "A child weighing 20 kg has burns; a 60-year-old man has burns. Which burn characteristic makes a burn 'full-thickness' (third-degree)?", "choices": ["Painful and blistering", "Dry, leathery, insensate", "Red and blanching", "Superficial peeling", "Erythema only"], "ans": 1, "exp": "Burn depth: superficial (1st, แดง เจ็บ blanch), superficial partial (blister, เจ็บมาก, blanch), deep partial (เจ็บน้อยลง), full-thickness (3rd, 'dry, leathery, white/charred, insensate' - เส้นประสาทถูกทำลาย, ไม่ blanch). Full-thickness ต้อง excision + skin graft. ประเมินเพื่อวางแผนรักษา/ส่งต่อ."}, {"topic": "Trauma & Critical Care", "q": "Using the 'rule of nines' in an adult, burns to the entire anterior trunk and one whole arm represent approximately what percent TBSA?", "choices": ["9%", "18%", "27%", "45%", "36%"], "ans": 2, "exp": "Rule of nines (ผู้ใหญ่): ศีรษะ 9%, แขนแต่ละข้าง 9%, ลำตัวหน้า 18%, ลำตัวหลัง 18%, ขาแต่ละข้าง 18%, perineum 1%. Anterior trunk (18%) + แขนทั้งข้าง (9%) = 27%. ใช้ประเมิน %TBSA (นับเฉพาะ partial/full-thickness) เพื่อคำนวณสารน้ำและตัดสินใจส่งต่อ burn center."}, {"topic": "Trauma & Critical Care", "q": "A 55-year-old woman has an eczematous, scaly, ulcerated change of the nipple with underlying breast malignancy. What is the diagnosis?", "choices": ["Mastitis for this patient", "Fibrocystic change alone", "Duct ectasia in this case", "Paget disease of the nipple", "Eczema only"], "ans": 3, "exp": "Paget disease of the nipple: ผื่น eczematous/scaly/ulcerated ที่หัวนม (ไม่ตอบสนอง topical) มักสัมพันธ์กับ underlying breast cancer (DCIS/invasive). ต้อง biopsy หัวนม + ประเมินเต้านม (mammogram/MRI). ต่างจาก eczema (มักเริ่มที่ areola, ตอบสนอง steroid)."}, {"topic": "Trauma & Critical Care", "q": "A 45-year-old woman has a rapidly enlarging, erythematous, warm breast with 'peau d'orange' skin. What aggressive cancer must be considered?", "choices": ["Mastitis as first step", "Fibroadenoma initially", "Lipoma for this patient", "Fat necrosis initially", "Inflammatory breast cancer"], "ans": 4, "exp": "Inflammatory breast cancer: เต้านมแดง ร้อน บวม 'peau d'orange' (จาก dermal lymphatic invasion) โตเร็ว — เป็นมะเร็งรุนแรง (T4d) มักไม่มีก้อนชัด. ต้องแยกจาก mastitis (ตอบสนองยาปฏิชีวนะ). ถ้า 'mastitis' ไม่ดีขึ้นใน 1-2 สัปดาห์ ต้อง biopsy. รักษา: neoadjuvant chemo → surgery → RT."}, {"topic": "Trauma & Critical Care", "q": "At what age does routine screening mammography generally begin for average-risk women?", "choices": ["Age 40-50", "Age 20-25", "Age 70", "Age 60", "No screening needed"], "ans": 0, "exp": "คัดกรองมะเร็งเต้านมด้วย mammography เริ่มช่วงอายุ 40-50 ปี ทุก 1-2 ปี (แนวทางต่างกันเล็กน้อย). ผู้เสี่ยงสูง (BRCA, ประวัติครอบครัวชัดเจน, ประวัติฉายรังสีทรวงอก) เริ่มเร็วกว่าและอาจเสริม MRI. Clinical breast exam และ awareness ก็มีบทบาท."}, {"topic": "Trauma & Critical Care", "q": "A woman with breast cancer undergoes sentinel lymph node biopsy. What is its purpose?", "choices": ["To treat the primary tumor for this patient", "To stage the axilla and reduce full dissection", "To detect metastasis in bone as first step", "To remove all axillary nodes as first step", "To biopsy the breast for this patient"], "ans": 1, "exp": "Sentinel lymph node biopsy (SLNB): ระบุ node แรกที่รับน้ำเหลืองจากก้อน (dye/tracer) เพื่อ 'stage axilla' โดยไม่ต้องเลาะ node ทั้งหมด → ลด lymphedema/morbidity. ถ้า SLN บวก (จำนวนมาก) จึงพิจารณา axillary dissection/RT. ทำในผู้ที่ node ตรวจร่างกาย/US ปกติ (clinically node-negative)."}, {"topic": "Trauma & Critical Care", "q": "A 50-year-old woman has ductal carcinoma in situ (DCIS) on biopsy. What best describes DCIS?", "choices": ["Invasive cancer with metastasis alone", "A benign fibroadenoma for this patient", "Malignant cells confined within the ducts", "An infection of the duct as first step", "A normal variant for this patient"], "ans": 2, "exp": "Ductal carcinoma in situ (DCIS): เซลล์มะเร็งอยู่ 'ภายในท่อ' ยังไม่ทะลุ basement membrane (non-invasive, ไม่ metastasis) — เป็น precursor ของ invasive cancer. รักษา: breast-conserving surgery + RT หรือ mastectomy; ± endocrine therapy ถ้า ER positive. มักพบเป็น microcalcification จาก screening mammogram."}, {"topic": "Trauma & Critical Care", "q": "A 60-year-old man has hyperthyroidism from Graves disease and opts for surgery. What is a key preoperative preparation to avoid thyroid storm?", "choices": ["Give IV calcium for this patient", "Withhold all medication as first step", "Give high-dose steroids only", "Start beta-blocker and antithyroid drugs", "No preparation needed for this patient"], "ans": 3, "exp": "เตรียมผ่าตัด Graves (thyroidectomy): ต้องทำให้ euthyroid ก่อนด้วย antithyroid drug (methimazole/PTU) + beta-blocker (คุมอาการ) และให้ 'Lugol's iodine' ก่อนผ่าตัด ~10 วัน (ลด vascularity + Wolff-Chaikoff). ป้องกัน thyroid storm (ภาวะฉุกเฉิน: ไข้สูง, tachycardia, agitation) จากการปล่อยฮอร์โมนขณะผ่าตัด."}, {"topic": "Trauma & Critical Care", "q": "After a total thyroidectomy, a patient develops perioral numbness, tingling, and carpopedal spasm (positive Chvostek sign). What is the cause?", "choices": ["Hypoglycemia", "Hyperkalemia", "Recurrent laryngeal nerve injury", "Hypernatremia", "Hypocalcemia from hypoparathyroidism"], "ans": 4, "exp": "ภาวะแทรกซ้อนหลัง total thyroidectomy: 'hypocalcemia' จากการบาดเจ็บ/เอา parathyroid ออกโดยไม่ได้ตั้งใจ → ชา รอบปาก/ปลายมือ, tetany, Chvostek/Trousseau sign. รักษาด้วย calcium (± vitamin D/calcitriol). ภาวะแทรกซ้อนสำคัญอื่น: recurrent laryngeal nerve injury (เสียงแหบ), เลือดออก (airway compromise - hematoma)."}, {"topic": "Trauma & Critical Care", "q": "After thyroid surgery, a patient has a hoarse voice and difficulty with high-pitched sounds. Which nerve was likely injured?", "choices": ["Recurrent laryngeal nerve", "External branch of superior laryngeal nerve", "Vagus nerve trunk", "Hypoglossal nerve", "Phrenic nerve"], "ans": 0, "exp": "Recurrent laryngeal nerve injury (ข้างเดียว) → เสียงแหบ (vocal cord paralysis ด้าน paramedian); สองข้าง → airway obstruction (ฉุกเฉิน). External branch of superior laryngeal nerve injury → เสียงล้าเวลาออกเสียงสูง/ร้องเพลง (cricothyroid). ต้องระวังเส้นประสาทเหล่านี้ระหว่างผ่าตัดไทรอยด์."}, {"topic": "Trauma & Critical Care", "q": "A patient has recurrent peptic ulcers in unusual locations, diarrhea, and a high fasting gastrin level. What is the diagnosis?", "choices": ["Insulinoma in this case", "Zollinger-Ellison syndrome", "Carcinoid syndrome", "VIPoma for this patient", "Glucagonoma in this case"], "ans": 1, "exp": "Zollinger-Ellison syndrome (gastrinoma): เนื้องอกหลั่ง gastrin (มัก duodenum/pancreas) → กรดมากเกิน → แผลในกระเพาะ/ลำไส้หลายตำแหน่ง/ตำแหน่งผิดปกติ + ท้องเสีย. Fasting gastrin สูง (+ secretin test). สัมพันธ์กับ MEN1. รักษา: high-dose PPI + localize/resect tumor."}, {"topic": "Trauma & Critical Care", "q": "A patient has episodes of confusion and diaphoresis relieved by eating, with low glucose and high insulin/C-peptide during episodes. What is the diagnosis?", "choices": ["Pheochromocytoma", "Gastrinoma", "Insulinoma", "Glucagonoma", "Carcinoid"], "ans": 2, "exp": "Insulinoma (pancreatic neuroendocrine tumor หลั่ง insulin): Whipple triad — อาการ hypoglycemia + glucose ต่ำขณะมีอาการ + หายเมื่อให้น้ำตาล. ตรวจ 72-hour fast: insulin/C-peptide สูงขณะ glucose ต่ำ (แยก exogenous insulin ที่ C-peptide ต่ำ). สัมพันธ์ MEN1. รักษา: enucleation/resection."}, {"topic": "Trauma & Critical Care", "q": "A large retrosternal goiter causes positional dyspnea and a positive Pemberton sign. What is the main concern?", "choices": ["Malignant transformation only", "Hyperthyroidism only", "Hypocalcemia", "Airway/venous compression", "Vocal cord palsy"], "ans": 3, "exp": "Retrosternal (substernal) goiter: กดเบียด trachea (airway - dyspnea, stridor), esophagus (dysphagia), และ SVC/veins → Pemberton sign (ยกแขนเหนือศีรษะ → หน้าแดง/บวม/หายใจลำบาก จาก venous congestion). เป็นข้อบ่งชี้ผ่าตัด (thyroidectomy) แม้ euthyroid. ประเมิน airway ก่อนผ่าตัด."}, {"topic": "Trauma & Critical Care", "q": "A patient has a subcutaneous, mobile, non-tender, soft mass with a central punctum that occasionally discharges cheesy material. What is the diagnosis?", "choices": ["Abscess for this patient", "Lipoma for this patient", "Ganglion cyst initially", "Lymph node as first step", "Epidermoid (sebaceous) cyst"], "ans": 4, "exp": "Epidermoid/sebaceous cyst: ก้อนใต้ผิวหนัง เคลื่อนที่ได้กับผิวหนัง, มี 'central punctum', อาจมี keratin (cheesy) ออก. ติดเชื้อ → แดงเจ็บ (I&D). รักษา: excision ทั้งถุง (ป้องกันเป็นซ้ำ). ต่างจาก lipoma (นุ่ม เคลื่อนใต้ผิว ไม่มี punctum) และ ganglion (ใกล้ข้อ/เอ็น)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old woman has a soft, rubbery, mobile, non-tender subcutaneous mass that has grown slowly. It transilluminates poorly. What is the most likely diagnosis?", "choices": ["Lipoma", "Sarcoma", "Sebaceous cyst", "Abscess", "Lymphoma"], "ans": 0, "exp": "Lipoma: เนื้องอกไขมัน benign — นุ่ม ยืดหยุ่น เคลื่อนที่ได้ ไม่เจ็บ โตช้า. มักไม่ต้องรักษา; excision ถ้าโต/มีอาการ/สงสัย. ลักษณะที่ควรระวัง sarcoma: โตเร็ว, ใหญ่ (>5 cm), ลึกใต้ fascia, ตรึงแน่น, เจ็บ → imaging + biopsy."}, {"topic": "Trauma & Critical Care", "q": "A patient steps on a rusty nail and has a contaminated puncture wound. His last tetanus booster was 8 years ago. What prophylaxis is appropriate?", "choices": ["No prophylaxis needed", "Tetanus toxoid booster", "Tetanus immunoglobulin only", "Antibiotics only", "Full 3-dose primary series"], "ans": 1, "exp": "Tetanus prophylaxis สำหรับแผลสกปรก/ทะลุ (tetanus-prone): ถ้าเคยได้ครบ ≥3 เข็มและเข็มสุดท้าย >5 ปี → ให้ 'tetanus toxoid booster' (Td/Tdap). ถ้าประวัติวัคซีนไม่ครบ/ไม่ทราบ + แผลสกปรก → ให้ทั้ง toxoid + tetanus immunoglobulin (TIG). แผลสะอาดที่เข็มสุดท้าย <10 ปีไม่ต้อง booster."}, {"topic": "Trauma & Critical Care", "q": "A patient is bitten on the hand by a cat, with a deep puncture wound. Besides wound care, which antibiotic covers the likely organism (Pasteurella)?", "choices": ["Ciprofloxacin alone", "Metronidazole", "Amoxicillin-clavulanate", "Vancomycin", "Azithromycin"], "ans": 2, "exp": "Cat/dog bite → Pasteurella multocida (และ anaerobes, Capnocytophaga) → 'amoxicillin-clavulanate' เป็น first-line prophylaxis/treatment. Cat bites (puncture ลึก) เสี่ยงติดเชื้อสูง. ล้างแผล, พิจารณาไม่เย็บปิดแผล bite (โดยเฉพาะมือ), tetanus, และ rabies prophylaxis ตามความเสี่ยง."}, {"topic": "Trauma & Critical Care", "q": "A firefighter rescued from a smoky building is confused with a headache and cherry-red skin; pulse oximetry reads normal. What is the diagnosis?", "choices": ["Cyanide poisoning only", "Simple smoke irritation", "Hypoglycemia", "Carbon monoxide poisoning", "Heat stroke"], "ans": 3, "exp": "Carbon monoxide poisoning: CO จับ hemoglobin (COHb) → tissue hypoxia; pulse oximeter 'อ่านปกติ' (แยก O2Hb กับ COHb ไม่ได้) → ต้องตรวจ carboxyhemoglobin (co-oximetry). อาการ: ปวดศีรษะ, สับสน, cherry-red (พบน้อย). รักษา: 100% O2 (± hyperbaric ในรายรุนแรง/ตั้งครรภ์/หมดสติ). ระวัง cyanide ร่วมในไฟไหม้."}, {"topic": "Trauma & Critical Care", "q": "A 70-year-old man has a firm, indurated, ulcerated skin lesion on the lower lip that has grown over months; he is a chronic smoker. What is the likely diagnosis?", "choices": ["Basal cell carcinoma", "Melanoma", "Keratoacanthoma", "Actinic keratosis", "Squamous cell carcinoma"], "ans": 4, "exp": "Squamous cell carcinoma (SCC): แผล/ก้อนแข็ง มี ulceration/crust บริเวณโดนแดด (ริมฝีปากล่าง, หู, หลังมือ), สัมพันธ์ UV/บุหรี่/immunosuppression/chronic wound (Marjolin ulcer). โตเร็วกว่า BCC และ 'metastasis ได้' (lymph node). วินิจฉัย biopsy; รักษา excision (margin) ± node. Actinic keratosis เป็น precursor."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient becomes hypotensive during resuscitation and is found to have a distended abdomen with rising airway pressures and low urine output. What is the diagnosis?", "choices": ["Abdominal compartment syndrome", "Tension pneumothorax alone", "Cardiac tamponade initially", "Neurogenic shock initially", "Anaphylaxis for this patient"], "ans": 0, "exp": "Abdominal compartment syndrome: intra-abdominal pressure สูง (>20 mmHg) + organ dysfunction — ท้องตึง, airway pressure สูง (ดัน diaphragm), oliguria (กด renal), hypotension (ลด venous return). วัดด้วย bladder pressure. รักษา: decompression (medical → surgical decompressive laparotomy). พบหลัง massive resuscitation/trauma/packing."}, {"topic": "Trauma & Critical Care", "q": "A young man is stabbed in the chest and has a sucking chest wound with air movement through it. What is the initial management of this open pneumothorax?", "choices": ["Immediate thoracotomy", "Occlusive dressing taped on three sides", "Full airtight seal on four sides", "Oral antibiotics", "Observation"], "ans": 1, "exp": "Open pneumothorax ('sucking chest wound'): ปิดด้วย 'occlusive dressing taped on three sides' (flutter/one-way valve — ให้ลมออกได้ ป้องกันไม่ให้เข้า → ป้องกันกลายเป็น tension pneumothorax). ตามด้วย chest tube (ตำแหน่งอื่น) และผ่าตัดปิดแผล. ปิดสี่ด้านสนิทเสี่ยงเกิด tension."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has a widened mediastinum on chest X-ray after a high-speed deceleration injury. What injury must be excluded?", "choices": ["Esophageal rupture", "Rib fracture", "Traumatic aortic injury", "Pneumothorax", "Diaphragmatic hernia"], "ans": 2, "exp": "Widened mediastinum + deceleration injury (high-speed MVC/fall) → สงสัย 'traumatic aortic injury' (มักที่ aortic isthmus ใกล้ ligamentum arteriosum). ยืนยันด้วย CT angiography. รักษา: คุม BP/HR (impulse control) + repair (endovascular/open). เป็นสาเหตุการตายทันทีที่พบบ่อยใน blunt trauma."}, {"topic": "Trauma & Critical Care", "q": "A 40-year-old woman has a large, rapidly growing but well-circumscribed breast mass; histology shows a phyllodes tumor. What is the appropriate management?", "choices": ["Simple aspiration for this patient", "Antibiotics for this patient", "Observation for this patient", "Wide local excision with clear margins", "Radiotherapy alone"], "ans": 3, "exp": "Phyllodes tumor: fibroepithelial breast tumor ที่โตเร็ว, อาจใหญ่, มี benign/borderline/malignant. รักษาด้วย 'wide local excision with clear margins (≥1 cm)' เพราะเสี่ยง local recurrence; malignant phyllodes แพร่ทาง hematogenous (ไม่ค่อยไป node) → ไม่ต้องเลาะ axilla. ต่างจาก fibroadenoma (โตช้า, enucleate ได้)."}, {"topic": "Trauma & Critical Care", "q": "A patient is found unconscious in a cold environment with a core temperature of 29°C and bradycardia. What is the diagnosis and a key management principle?", "choices": ["Sepsis, give antibiotics for this patient", "Heat stroke, cool rapidly for this patient", "Hypoglycemia, give glucose only", "Stroke, give thrombolysis for this patient", "Hypothermia, rewarm gradually and handle gently"], "ans": 4, "exp": "Severe hypothermia (<30°C): bradycardia, ลดระดับความรู้สึกตัว, เสี่ยง arrhythmia (VF). รักษา: 'rewarming' (active internal/external), handle gently (การกระตุ้นทำให้ VF), ทำ CPR ต่อเนื่อง ('not dead until warm and dead'). ระวัง Osborn (J) wave ใน ECG. หลีกเลี่ยงการเคลื่อนย้ายรุนแรง."}, {"topic": "Trauma & Critical Care", "q": "A polytrauma patient is hypotensive with warm, dry skin, bradycardia, and neurologic deficit after a spinal injury. What type of shock is this?", "choices": ["Neurogenic shock", "Hypovolemic shock", "Anaphylactic shock", "Cardiogenic shock", "Septic shock"], "ans": 0, "exp": "Neurogenic shock (จาก spinal cord injury เหนือ T6): สูญเสีย sympathetic tone → vasodilation → hypotension + 'bradycardia' (ไม่ tachycardia) + ผิวอุ่นแห้ง. ต่างจาก hypovolemic (เย็นซีด tachycardia). รักษา: fluid + vasopressor (norepinephrine), atropine ถ้า bradycardia. ต้องแยก hemorrhagic shock ร่วมเสมอ (rule out bleeding ก่อน)."}, {"topic": "Trauma & Critical Care", "q": "A patient develops hypotension, urticaria, wheezing, and facial swelling minutes after an antibiotic. What is the first-line drug?", "choices": ["Intravenous fluids only", "Intramuscular epinephrine", "Intravenous hydrocortisone", "Oral antihistamine", "Nebulized salbutamol only"], "ans": 1, "exp": "Anaphylaxis (distributive shock จาก IgE): hypotension + urticaria + wheeze/angioedema หลังสัมผัส allergen. First-line = 'IM epinephrine' (0.3-0.5 mg, 1:1,000 ที่ต้นขา) ทันที, ซ้ำได้ทุก 5-15 นาที. เสริม: O2, IV fluid, antihistamine, steroid (ป้องกัน biphasic), airway. Epinephrine สำคัญสุด อย่ารีรอ."}, {"topic": "Trauma & Critical Care", "q": "A burn patient has burns to the face, hands, perineum, and a burn crossing a major joint. What does this warrant?", "choices": ["Discharge home", "Observation for 1 hour", "Referral to a burn center", "Outpatient dressing only", "Oral antibiotics only"], "ans": 2, "exp": "เกณฑ์ส่งต่อ burn center: partial thickness >10% TBSA, burns บริเวณ 'face, hands, feet, genitalia/perineum, major joints', full-thickness ทุกอายุ, electrical/chemical/inhalation injury, เด็ก, comorbidity, circumferential. บริเวณเหล่านี้มีผลต่อ function/cosmesis จึงควรส่งต่อผู้เชี่ยวชาญ."}, {"topic": "Trauma & Critical Care", "q": "A worker splashes a strong acid on the skin. What is the most important immediate management?", "choices": ["Neutralize with alkali", "Cover and wait", "Apply ointment", "Copious water irrigation", "Debride immediately"], "ans": 3, "exp": "Chemical burn (acid = coagulative necrosis, alkali = liquefactive ลึกกว่า): ปฐมพยาบาลคือ 'irrigate ด้วยน้ำปริมาณมากนานๆ' (ถอดเสื้อผ้าเปื้อน, ปัดผงแห้งก่อน). ห้าม neutralize (ปฏิกิริยาความร้อน). ยกเว้น hydrofluoric acid → ให้ calcium gluconate เพิ่ม (จับ fluoride, เสี่ยง hypocalcemia/arrhythmia)."}, {"topic": "Trauma & Critical Care", "q": "A 65-year-old man has a firm breast lump beneath the nipple. Male breast cancer should be suspected. Which is a risk factor?", "choices": ["Testicular torsion", "Varicocele", "Prostatitis", "Gynecomastia is protective", "Klinefelter syndrome and BRCA2"], "ans": 4, "exp": "Male breast cancer (พบน้อย, มัก ER-positive ductal): ปัจจัยเสี่ยง — Klinefelter syndrome (47,XXY), BRCA2 mutation, ประวัติครอบครัว, ฉายรังสี, ตับแข็ง/estrogen สูง. ก้อนแข็ง eccentric ใต้หัวนม + retraction. ประเมิน triple assessment. ต่างจาก gynecomastia (นุ่ม central, สองข้าง)."}, {"topic": "Trauma & Critical Care", "q": "A patient has a thyroid gland that is diffusely enlarged and painful with fever after a viral illness; ESR is high and radioiodine uptake is low. What is the diagnosis?", "choices": ["Subacute (de Quervain) thyroiditis", "Hashimoto thyroiditis initially", "Graves disease for this patient", "Thyroid cancer for this patient", "Toxic adenoma for this patient"], "ans": 0, "exp": "Subacute (de Quervain) thyroiditis: ต่อมไทรอยด์เจ็บ + ไข้หลัง viral infection, ESR สูง, 'radioiodine uptake ต่ำ' (ต่างจาก Graves ที่ uptake สูง) — ระยะแรก thyrotoxic (ปล่อยฮอร์โมนที่เก็บ) แล้ว hypothyroid ก่อนหาย. รักษา: NSAIDs/steroid + beta-blocker (อาการ). Self-limited ส่วนใหญ่."}, {"topic": "Trauma & Critical Care", "q": "A child has a midline neck mass that moves upward with tongue protrusion and swallowing. What is the diagnosis?", "choices": ["Lymph node", "Thyroglossal duct cyst", "Branchial cleft cyst", "Cystic hygroma", "Dermoid cyst"], "ans": 1, "exp": "Thyroglossal duct cyst: ก้อน 'กลางคอ' ที่เคลื่อนขึ้นเมื่อ 'แลบลิ้น/กลืน' (ติดกับ hyoid/foramen cecum). รักษา: Sistrunk procedure (excision cyst + midportion of hyoid) ป้องกันเป็นซ้ำ. ต้องยืนยันว่ามี normal thyroid อื่น. ต่างจาก branchial cleft cyst (ด้านข้างคอ, ขอบ SCM)."}, {"topic": "Trauma & Critical Care", "q": "A young adult has a smooth, fluctuant lateral neck mass at the anterior border of the sternocleidomastoid. What is the most likely diagnosis?", "choices": ["Thyroid nodule", "Thyroglossal duct cyst", "Branchial cleft cyst", "Carotid body tumor", "Lymphoma"], "ans": 2, "exp": "Branchial cleft cyst (มัก 2nd cleft): ก้อน 'ด้านข้างคอ' ที่ขอบหน้าของ sternocleidomastoid, อาจติดเชื้อ/เป็น sinus. รักษา: surgical excision. ในผู้ใหญ่ >40 ปีที่มี cystic neck mass ต้องแยก 'cystic metastasis จาก HPV-related oropharyngeal SCC' (biopsy/imaging) ก่อน."}, {"topic": "Trauma & Critical Care", "q": "A 55-year-old man has a painless, firm, enlarging cervical lymph node for weeks with weight loss and night sweats. What is the appropriate next step?", "choices": ["Reassure and observe", "Course of antibiotics", "Aspirate and discard", "Excisional lymph node biopsy", "Warm compress"], "ans": 3, "exp": "Persistent painless cervical lymphadenopathy (>2-4 สัปดาห์) + B symptoms (น้ำหนักลด, ไข้, เหงื่อกลางคืน) สงสัย lymphoma/malignancy → 'excisional biopsy' (ได้ architecture, ดีสำหรับ lymphoma). ในผู้ใหญ่ที่สงสัย metastatic SCC ควรตรวจ primary (ENT) ก่อน + FNA. ต่อมน้ำเหลืองที่แข็ง ติดแน่น โตขึ้นเรื่อยๆ น่ากังวล."}, {"topic": "Trauma & Critical Care", "q": "A diabetic patient has a deep foot ulcer with surrounding cellulitis and probing to bone. What complication must be evaluated?", "choices": ["Venous eczema", "Simple contact dermatitis", "Gout", "Cellulitis only", "Osteomyelitis"], "ans": 4, "exp": "Diabetic foot ulcer ที่ 'probe to bone' positive หรือแผลลึก/เรื้อรัง → เสี่ยง osteomyelitis (ยืนยันด้วย MRI/bone biopsy, X-ray อาจปกติช่วงแรก). รักษา: ควบคุมน้ำตาล, debridement, antibiotic (ตาม culture), off-loading, ประเมิน vascular (ABI). รุนแรง/ischemia → revascularization/amputation."}, {"topic": "Trauma & Critical Care", "q": "A patient has a deep wound contaminated with soil and develops crepitus, foul discharge, and rapidly spreading myonecrosis. Gram stain shows gram-positive rods. What is the diagnosis?", "choices": ["Gas gangrene (Clostridial myonecrosis)", "Contact dermatitis for this patient", "Simple cellulitis for this patient", "Erysipelas for this patient", "Abscess for this patient"], "ans": 0, "exp": "Gas gangrene (Clostridium perfringens myonecrosis): แผลลึกปนเปื้อนดิน → crepitus (gas), กล้ามเนื้อตายเร็ว, discharge เหม็น, systemic toxicity, gram-positive rods. เป็น surgical emergency → 'aggressive debridement/amputation' + penicillin + clindamycin ± hyperbaric O2. ล่าช้าตายสูง."}, {"topic": "Trauma & Critical Care", "q": "A long-bone fracture patient develops respiratory distress, confusion, and a petechial rash 24-48 hours after injury. What is the diagnosis?", "choices": ["Pulmonary embolism", "Fat embolism syndrome", "Pneumonia", "Cardiac tamponade", "Acute lung injury from transfusion"], "ans": 1, "exp": "Fat embolism syndrome: 24-72 ชม.หลัง long-bone/pelvic fracture — triad: respiratory distress (hypoxia) + neurologic (confusion) + petechial rash (axilla/conjunctiva). รักษาประคับประคอง (O2/ventilation) + early fracture fixation (ป้องกัน). ต่างจาก PE (thrombotic, ขาบวม)."}, {"topic": "Trauma & Critical Care", "q": "A patient trapped under rubble is released after hours; he develops dark urine, hyperkalemia, and acute kidney injury. What is the diagnosis?", "choices": ["Hemolytic anemia", "Fat embolism", "Crush syndrome (rhabdomyolysis)", "Compartment syndrome only", "Contrast nephropathy"], "ans": 2, "exp": "Crush syndrome: กล้ามเนื้อถูกกดทับนาน → rhabdomyolysis (myoglobin, CK สูง) → myoglobinuria (ปัสสาวะเข้ม) + AKI + 'hyperkalemia' (เสี่ยง arrhythmia/cardiac arrest เมื่อปล่อย) + hypocalcemia + metabolic acidosis. รักษา: aggressive IV fluid, ติดตาม/รักษา hyperkalemia, พิจารณา fasciotomy (compartment syndrome ร่วม)."}, {"topic": "Trauma & Critical Care", "q": "A patient with severe sepsis has hypotension despite adequate fluid resuscitation, warm extremities, and a high cardiac output. What type of shock is this?", "choices": ["Obstructive shock", "Cardiogenic shock", "Hypovolemic shock", "Septic (distributive) shock", "Neurogenic shock"], "ans": 3, "exp": "Septic shock (distributive): vasodilation → hypotension ที่ไม่ตอบสนอง fluid เพียงพอ, ต้องใช้ vasopressor + lactate สูง. ระยะแรก 'warm shock' (แขนขาอุ่น, high CO). รักษา (Surviving Sepsis): เพาะเชื้อ + antibiotic เร็ว, IV fluid (crystalloid ~30 mL/kg), norepinephrine (first-line vasopressor), source control."}, {"topic": "Trauma & Critical Care", "q": "A patient after acute myocardial infarction is hypotensive with cold, clammy skin, raised JVP, and pulmonary edema. What type of shock is this?", "choices": ["Hypovolemic shock", "Distributive shock", "Neurogenic shock", "Anaphylactic shock", "Cardiogenic shock"], "ans": 4, "exp": "Cardiogenic shock: pump failure (มัก post-MI) → hypotension + สัญญาณ congestion (JVP สูง, pulmonary edema, ผิวเย็นชื้น, oliguria). รักษา: revascularization (post-MI), inotrope/vasopressor, ± mechanical support (IABP/ECMO), หลีกเลี่ยง fluid overload. ต่างจาก hypovolemic (JVP ต่ำ)."}, {"topic": "Trauma & Critical Care", "q": "A woman has newly diagnosed early breast cancer that is HER2-positive. Which targeted therapy is added?", "choices": ["Trastuzumab", "Rituximab", "Tamoxifen", "Imatinib", "Bevacizumab"], "ans": 0, "exp": "HER2-positive breast cancer → เพิ่ม 'trastuzumab' (anti-HER2 monoclonal antibody) ± pertuzumab ร่วมกับ chemotherapy — เพิ่ม survival อย่างมาก. ต้องเฝ้าระวัง cardiotoxicity (ประเมิน LVEF). ER-positive → tamoxifen/AI. Triple-negative → chemotherapy ± immunotherapy."}, {"topic": "Trauma & Critical Care", "q": "A patient with Cushing syndrome is found to have an ACTH-secreting pituitary adenoma. What is this specific condition called?", "choices": ["Conn syndrome", "Cushing disease", "Addison disease", "Nelson syndrome", "Sheehan syndrome"], "ans": 1, "exp": "Cushing 'disease' = Cushing syndrome จาก 'ACTH-secreting pituitary adenoma' (สาเหตุ endogenous ที่พบบ่อยสุด). Cushing 'syndrome' = ภาวะ cortisol เกินจากสาเหตุใดก็ได้ (รวม exogenous steroid, adrenal tumor, ectopic ACTH). วินิจฉัย: dexamethasone suppression, ACTH, MRI pituitary. รักษา: transsphenoidal resection."}, {"topic": "Trauma & Critical Care", "q": "A 3-year-old has a large, painless abdominal mass crossing the midline; it is a neuroblastoma. Which is characteristic?", "choices": ["Is always benign for this patient", "Arises from kidney, does not cross midline for this patient", "Arises from adrenal/sympathetic chain, elevated urinary catecholamines", "Secretes insulin for this patient", "Secretes gastrin for this patient"], "ans": 2, "exp": "Neuroblastoma: เนื้องอกจาก 'neural crest/sympathetic chain/adrenal medulla' ในเด็กเล็ก — ก้อนในท้องที่ข้าม midline, urinary catecholamines (VMA/HVA) สูง, อาจมี 'raccoon eyes'/opsoclonus-myoclonus. ต่างจาก Wilms tumor (จากไต, ไม่ข้าม midline, hematuria). N-myc amplification = พยากรณ์แย่."}, {"topic": "Trauma & Critical Care", "q": "A 4-year-old has a painless, unilateral abdominal mass confined to one side, with hematuria and hypertension. Which tumor is likely?", "choices": ["Neuroblastoma in this case", "Hepatoblastoma initially", "Rhabdomyosarcoma initially", "Wilms tumor (nephroblastoma)", "Lymphoma for this patient"], "ans": 3, "exp": "Wilms tumor (nephroblastoma): มะเร็งไตในเด็ก (~2-5 ปี) — ก้อนในท้อง 'ไม่ข้าม midline', hematuria, hypertension (renin). สัมพันธ์ WAGR/Beckwith-Wiedemann. รักษา: nephrectomy + chemo ± RT, พยากรณ์ดี. หลีกเลี่ยงคลำก้อนแรงๆ (เสี่ยงแตก). ต่างจาก neuroblastoma (ข้าม midline, catecholamine)."}, {"topic": "Trauma & Critical Care", "q": "A patient has recurrent hyperparathyroidism, a pancreatic neuroendocrine tumor, and a pituitary adenoma. Which syndrome is this?", "choices": ["MEN2B", "MEN2A", "Von Hippel-Lindau", "Neurofibromatosis", "MEN1"], "ans": 4, "exp": "MEN1 (Wermer, MEN1 gene) = '3 Ps': Parathyroid hyperplasia (hyperparathyroidism - พบบ่อยสุด/แรกสุด), Pancreatic/duodenal NET (gastrinoma, insulinoma), Pituitary adenoma. MEN2A = medullary thyroid CA + pheochromocytoma + parathyroid (RET). MEN2B = MTC + pheo + mucosal neuroma + marfanoid."}, {"topic": "Trauma & Critical Care", "q": "A woman has a breast abscess while breastfeeding, with a fluctuant tender mass. What is the appropriate management?", "choices": ["Drainage (aspiration/incision) plus antibiotics", "Continue antibiotics only", "Mastectomy for this patient", "Stop breastfeeding permanently as first step", "Observation for this patient"], "ans": 0, "exp": "Breast abscess (มัก S. aureus, ภาวะแทรกซ้อนของ mastitis): คลำได้ก้อน fluctuant → 'drainage' (needle aspiration ภายใต้ US สำหรับก้อนเล็ก หรือ I&D) + antibiotic + ให้นม/ปั๊มออกต่อ. ในหญิงไม่ให้นมที่เป็นซ้ำ ระวัง underlying malignancy (biopsy)."}, {"topic": "Trauma & Critical Care", "q": "A screening mammogram shows clustered, pleomorphic microcalcifications. What do these most commonly indicate?", "choices": ["Simple cyst initially", "Ductal carcinoma in situ", "Lipoma as first step", "Normal breast alone", "Fat necrosis initially"], "ans": 1, "exp": "Clustered pleomorphic/branching microcalcifications บน mammogram เป็นลักษณะที่น่าสงสัย 'DCIS' (หรือ invasive) → ต้อง stereotactic core biopsy. ต่างจาก benign calcification (coarse, popcorn-like ใน fibroadenoma; rim/eggshell ใน cyst). BI-RADS ช่วยจัดระดับความเสี่ยง."}, {"topic": "Trauma & Critical Care", "q": "A patient with locally advanced breast cancer is treated with chemotherapy before surgery. What is this approach called?", "choices": ["Palliative chemotherapy", "Adjuvant chemotherapy", "Neoadjuvant chemotherapy", "Salvage therapy", "Consolidation therapy"], "ans": 2, "exp": "Neoadjuvant chemotherapy = ให้เคมีบำบัด 'ก่อนผ่าตัด' — ลดขนาดก้อน (อาจทำ breast-conserving ได้แทน mastectomy), ประเมินการตอบสนอง (pathologic complete response = พยากรณ์ดี), และรักษา micrometastasis. ใช้ใน locally advanced/inflammatory/triple-negative/HER2-positive. Adjuvant = ให้หลังผ่าตัด."}, {"topic": "Trauma & Critical Care", "q": "A patient presents with acute adrenal crisis (hypotension, hyponatremia, hyperkalemia, hypoglycemia). What is the immediate treatment?", "choices": ["Oral prednisolone next day", "IV insulin", "Beta-blocker", "IV hydrocortisone and fluids", "Vasopressin only"], "ans": 3, "exp": "Adrenal crisis (acute adrenal insufficiency): hypotension ดื้อ fluid + hyponatremia + hyperkalemia + hypoglycemia (± ประวัติหยุด steroid/Addison/adrenal hemorrhage-Waterhouse-Friderichsen). รักษาทันที: 'IV hydrocortisone 100 mg' + IV fluid (normal saline + dextrose) + แก้เกลือแร่. อย่ารอผลตรวจ. หา precipitant (infection)."}, {"topic": "Trauma & Critical Care", "q": "A 30-year-old woman has a painful axillary and groin skin condition with recurrent abscesses, sinus tracts, and scarring. What is the diagnosis?", "choices": ["Simple furuncle", "Sebaceous cyst", "Lymphadenitis", "Pilonidal disease", "Hidradenitis suppurativa"], "ans": 4, "exp": "Hidradenitis suppurativa: การอักเสบเรื้อรังของ apocrine gland-bearing areas (รักแร้, ขาหนีบ, ใต้ราวนม) → ฝีซ้ำ, sinus tract, พังผืด. สัมพันธ์ obesity/สูบบุหรี่. รักษา: หยุดบุหรี่/ลดน้ำหนัก, topical/oral antibiotic, biologics (adalimumab), ผ่าตัด wide excision ในรายรุนแรง."}, {"topic": "Trauma & Critical Care", "q": "A patient has a firm, cystic swelling on the dorsum of the wrist that transilluminates and is attached to a tendon sheath. What is the diagnosis?", "choices": ["Ganglion cyst", "Lipoma", "Rheumatoid nodule", "Sebaceous cyst", "Sarcoma"], "ans": 0, "exp": "Ganglion cyst: ถุงน้ำ (mucin) ใกล้ข้อ/tendon sheath (พบบ่อยที่หลังข้อมือ) — แข็ง/ยืดหยุ่น, transilluminate ได้, สัมพันธ์กับ joint/tendon. ส่วนใหญ่ benign และหายเองได้; รักษา: aspiration (เป็นซ้ำบ่อย) หรือ excision ถ้ามีอาการ. ไม่แนะนำทุบด้วยหนังสือ (โบราณ)."}, {"topic": "Trauma & Critical Care", "q": "A patient with severe hyperthyroidism develops high fever, agitation, tachyarrhythmia, and heart failure after an infection. What is the diagnosis and a key treatment?", "choices": ["Adrenal crisis, hydrocortisone", "Thyroid storm, beta-blocker and antithyroid drugs", "Sepsis, antibiotics only", "Malignant hyperthermia, dantrolene", "Neuroleptic malignant syndrome, bromocriptine"], "ans": 1, "exp": "Thyroid storm (thyrotoxic crisis): ภาวะฉุกเฉิน — ไข้สูง, agitation/delirium, tachyarrhythmia/AF, heart failure, GI symptoms, มักมี precipitant (infection, surgery, iodine). รักษา: beta-blocker (propranolol), antithyroid (PTU), iodine (หลัง PTU ≥1 ชม.), hydrocortisone, cooling, รักษา precipitant. Burch-Wartofsky score ช่วยประเมิน."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient sustains blunt chest trauma and has ECG changes and elevated troponin without coronary disease. What is the likely diagnosis?", "choices": ["Aortic dissection", "Acute coronary thrombosis", "Myocardial (cardiac) contusion", "Pericarditis", "Pulmonary embolism"], "ans": 2, "exp": "Myocardial contusion (blunt cardiac injury): จาก blunt chest trauma (steering wheel) → ECG ผิดปกติ (arrhythmia, ST changes), troponin สูง, wall motion abnormality (echo). รักษา: cardiac monitoring (arrhythmia), supportive. เฝ้าระวัง arrhythmia/heart failure. สัมพันธ์กับ sternal fracture."}, {"topic": "Trauma & Critical Care", "q": "A 50-year-old man has a slowly enlarging, painless mass deep to the fascia of the thigh that is over 5 cm and firm. What must be excluded?", "choices": ["Hematoma", "Simple lipoma", "Abscess", "Soft tissue sarcoma", "Cyst"], "ans": 3, "exp": "ก้อน soft tissue ที่ 'ใหญ่ >5 cm, ลึกใต้ fascia, แข็ง, โตขึ้น, เจ็บ' → ต้องแยก soft tissue sarcoma → MRI + 'core/incisional biopsy' (วางแนวให้ตัดออกได้ในผ่าตัดภายหลัง, หลีกเลี่ยง excisional biopsy ที่ทำไม่ถูกหลัก). รักษา: wide excision ± RT โดยทีมเฉพาะทาง. อย่าคิดว่าเป็น lipoma เสมอ."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient's chest X-ray shows the stomach bubble in the left chest and a nasogastric tube tip in the thorax after blunt trauma. What is the diagnosis?", "choices": ["Tension pneumothorax alone", "Hemothorax for this patient", "Hiatal hernia as first step", "Esophageal rupture initially", "Traumatic diaphragmatic rupture"], "ans": 4, "exp": "Traumatic diaphragmatic rupture (มักด้านซ้าย จาก blunt trauma): อวัยวะช่องท้องเลื่อนเข้าทรวงอก — CXR เห็น gastric bubble/NG tube ในอก, bowel loops. อาจแสดงอาการช้า (herniation). วินิจฉัย CT; รักษาด้วยผ่าตัดซ่อม. เฝ้าระวัง associated injuries."}, {"topic": "Trauma & Critical Care", "q": "A trauma patient has a lung injury with hypoxia and patchy consolidation on CT developing over hours after blunt chest trauma, without pneumothorax. What is the diagnosis?", "choices": ["Pulmonary contusion", "Aspiration pneumonia", "Pulmonary embolism", "ARDS from sepsis", "Atelectasis"], "ans": 0, "exp": "Pulmonary contusion: เลือดออก/edema ในเนื้อปอดจาก blunt chest trauma — hypoxia + infiltrate ที่แย่ลงใน 24-48 ชม. (ไม่ตรงกับ anatomical border). รักษาประคับประคอง: O2/ventilation, ควบคุมสารน้ำ (เลี่ยง overload), analgesia, กายภาพ. เป็นภาวะที่ทำให้ flail chest อันตราย."}, {"topic": "Trauma & Critical Care", "q": "A 45-year-old woman has bloody discharge from a single duct of one breast. What is the appropriate evaluation?", "choices": ["Reassure and observe for this patient", "Imaging and evaluation for papilloma/carcinoma", "Dopamine agonist for this patient", "Antibiotics for this patient", "Squeeze it out regularly for this patient"], "ans": 1, "exp": "Pathologic nipple discharge (ข้างเดียว, ท่อเดียว, เป็นเลือด/serosanguineous, spontaneous) → สาเหตุบ่อยคือ intraductal papilloma (benign) แต่ต้องแยกมะเร็ง (DCIS) → mammogram/US ± ductography/MRI + biopsy/duct excision. ต่างจาก galactorrhea (bilateral, milky, prolactin)."}, {"topic": "Trauma & Critical Care", "q": "A patient after subtotal thyroidectomy develops sudden neck swelling, difficulty breathing, and stridor. What is the immediate management?", "choices": ["Give nebulized adrenaline only", "Await CT neck", "Open the wound to evacuate hematoma", "High-dose steroids only", "Reassure and observe"], "ans": 2, "exp": "Post-thyroidectomy hematoma → airway compression (คอบวมเร็ว, stridor, หายใจลำบาก) = ภาวะฉุกเฉิน → 'เปิดแผลระบายเลือด (evacuate hematoma) ข้างเตียงทันที' เพื่อคลาย airway แล้วจึงกลับห้องผ่าตัด. อย่ารอ imaging. เป็นภาวะแทรกซ้อนที่อันตรายถึงชีวิตในชั่วโมงแรกๆ."}, {"topic": "Trauma & Critical Care", "q": "A young man has painless testicular enlargement; ultrasound shows a solid intratesticular mass and tumor markers (AFP, beta-hCG) are elevated. What is the appropriate surgical approach?", "choices": ["Trans-scrotal biopsy", "Observation", "Fine-needle aspiration", "Radical inguinal orchidectomy", "Testicular-sparing enucleation"], "ans": 3, "exp": "Testicular tumor (germ cell - seminoma/non-seminoma): ก้อนแข็งในลูกอัณฑะ, marker AFP/β-hCG/LDH. การวินิจฉัย/รักษาคือ 'radical inguinal orchidectomy' (ห้ามเจาะ/ผ่าทาง scrotum → เสี่ยง seeding). Staging CT + markers; เสริม chemo/RT/RPLND ตามชนิด/ระยะ. พยากรณ์ดี (โดยเฉพาะ seminoma)."}, {"topic": "Trauma & Critical Care", "q": "A burn patient's fluid resuscitation is being monitored. What is the best endpoint of adequate resuscitation in an adult?", "choices": ["Blood pressure over 140", "Heart rate under 60", "Central venous pressure of 15", "Skin color only", "Urine output 0.5 mL/kg/hr"], "ans": 4, "exp": "เป้าหมายการให้สารน้ำใน burn (ผู้ใหญ่) = urine output ~0.5 mL/kg/hr (เด็ก ~1 mL/kg/hr) — Parkland เป็นเพียงจุดเริ่มต้น ต้องปรับตาม urine output/perfusion. ให้มากเกิน (fluid creep) → ภาวะแทรกซ้อน (compartment syndrome, edema). ใน 24 ชม.แรกใช้ crystalloid."}, {"topic": "Trauma & Critical Care", "q": "A patient has a hard, irregular thyroid nodule fixed to surrounding tissue with hoarseness and a rapidly enlarging neck mass in an elderly patient. Which aggressive cancer is likely?", "choices": ["Anaplastic thyroid carcinoma", "Papillary carcinoma", "Follicular adenoma", "Subacute thyroiditis", "Colloid nodule"], "ans": 0, "exp": "Anaplastic thyroid carcinoma: พบในผู้สูงอายุ — ก้อนคอโตเร็วมาก, แข็ง, ตรึงแน่น, กดเบียด (hoarseness, dyspnea, dysphagia). เป็นมะเร็งที่ 'ร้ายแรงที่สุด/พยากรณ์แย่มาก' (survival เป็นเดือน). มักลุกลามเกินผ่าตัด → ประคับประคอง airway + chemo/RT. ต่างจาก papillary (พยากรณ์ดี)."}, {"topic": "Trauma & Critical Care", "q": "A patient with a large goiter is scheduled for surgery. Which preoperative assessment is important to detect airway compromise?", "choices": ["Check serum calcium only", "Assess for tracheal deviation/compression", "Measure BMI only", "Skin testing for this patient", "No assessment needed for this patient"], "ans": 1, "exp": "ก่อนผ่าตัด goiter ใหญ่/retrosternal ต้องประเมิน airway: tracheal deviation/compression (CT/flow-volume loop), อาการ dyspnea/stridor/positional. ช่วยวางแผน anesthesia (difficult airway) และการผ่าตัด. หลังผ่าตัดเฝ้าระวัง tracheomalacia, hematoma, และ recurrent laryngeal nerve/hypocalcemia."}, {"topic": "Trauma & Critical Care", "q": "A patient is stung/bitten and develops isolated local swelling and pain without systemic symptoms or coagulopathy after a snakebite. What is the appropriate management?", "choices": ["Give antivenom immediately for this patient", "Apply arterial tourniquet for this patient", "Observe with serial coagulation studies and limb monitoring", "Incise and suck the wound for this patient", "Amputate the limb for this patient"], "ans": 2, "exp": "Snakebite ที่มีเฉพาะ local envenomation เล็กน้อย โดยไม่มี systemic/severe local signs → 'สังเกตอาการ' + ติดตาม coagulation (VCT/INR, platelet) และ progression ของ swelling เป็นระยะ (≥24 ชม.). ให้ antivenom เมื่อมีข้อบ่งชี้ (systemic envenomation, severe/progressive local, coagulopathy) — ไม่ให้ทุกราย (เสี่ยง reaction)."}, {"topic": "Trauma & Critical Care", "q": "A previously well patient after major surgery has decreased urine output; labs suggest prerenal acute kidney injury. What is the initial management?", "choices": ["Nephrotoxic contrast study alone", "Immediate dialysis as first step", "Loop diuretic bolus as first step", "Fluid challenge to restore perfusion", "Fluid restriction for this patient"], "ans": 3, "exp": "Postoperative prerenal AKI (จาก hypovolemia/hypoperfusion): oliguria, BUN/Cr ratio สูง, FeNa <1%, urine เข้มข้น. รักษาเบื้องต้น: 'fluid challenge' เพื่อฟื้น renal perfusion + แก้สาเหตุ (เลือดออก, sepsis), หยุด nephrotoxin. ไม่ตอบสนอง/overload/hyperkalemia/uremia → พิจารณา dialysis. Diuretic ไม่แก้ prerenal."}, {"topic": "Trauma & Critical Care", "q": "A woman with a breast lump has a benign-appearing cyst on ultrasound; aspiration yields clear fluid and the lump resolves completely. What is the next step?", "choices": ["Repeated aspiration weekly", "Excisional biopsy", "Mastectomy", "Chemotherapy", "Reassurance and routine follow-up"], "ans": 4, "exp": "Simple breast cyst ที่เจาะดูดได้ของเหลว 'ใส' (ไม่มีเลือด) และก้อนยุบหมด → benign, reassure + ติดตามปกติ. ถ้าของเหลวเป็นเลือด, ก้อนไม่ยุบหมด, หรือกลับเป็นซ้ำ → imaging + biopsy (แยก intracystic/complex lesion). เป็นส่วนหนึ่งของ triple assessment."}]}, {"id": "surg3", "title": "Surgery ชุดที่ 3 — Orthopedics (Fractures, Pediatric Ortho, Spine, Bone Tumors, Hand)", "subject": "surg", "questions": [{"topic": "Orthopedics", "q": "A 40-year-old man sustains a closed tibial fracture. Six hours later he has severe pain worsened by passive toe extension, a tense swollen calf, and paresthesia. What is the diagnosis?", "choices": ["Compartment syndrome", "Fat embolism", "Deep vein thrombosis", "Cellulitis", "Nerve contusion"], "ans": 0, "exp": "Acute compartment syndrome: ปวดรุนแรง 'เกินกว่าที่ควร' + ปวดเมื่อ passive stretch + tense compartment + paresthesia (สัญญาณแรก). Pulselessness/pallor เป็น 'สัญญาณสาย'. วินิจฉัยทางคลินิก (± วัด compartment pressure). รักษา: 'emergency fasciotomy' — อย่ารอ pulse หาย. พบบ่อยหลัง tibial fracture/reperfusion/crush."}, {"topic": "Orthopedics", "q": "A motorcyclist has an open tibial fracture with a 3 cm wound and moderate soft tissue damage but adequate coverage (Gustilo type II). What is the initial management priority?", "choices": ["Delayed surgery in 1 week for this patient", "Antibiotics, tetanus, wound care, and urgent debridement", "Immediate internal fixation only", "Close the wound primarily for this patient", "Apply a cast and discharge for this patient"], "ans": 1, "exp": "Open fracture management: ให้ 'IV antibiotic เร็ว' (ภายใน 1 ชม.), tetanus prophylaxis, คลุมแผลด้วย saline dressing, จัดกระดูก/splint, และ 'urgent surgical debridement + irrigation' + fracture stabilization. Gustilo grading (I <1cm, II 1-10cm, III >10cm/มาก) กำหนดยาปฏิชีวนะ/การดูแล. ไม่เย็บปิด primary ในแผลปนเปื้อน."}, {"topic": "Orthopedics", "q": "A 70-year-old woman falls and has a shortened, externally rotated right leg with groin pain; she cannot bear weight. What is the most likely diagnosis?", "choices": ["Trochanteric bursitis", "Hip dislocation", "Femoral neck fracture", "Pubic ramus fracture", "Lumbar radiculopathy"], "ans": 2, "exp": "Hip (femoral neck/intertrochanteric) fracture ในผู้สูงอายุหลังล้ม: ขา 'สั้นและ external rotation' + ปวดขาหนีบ + ลงน้ำหนักไม่ได้. Displaced femoral neck fracture เสี่ยง avascular necrosis (เลือดเลี้ยง retrograde) → มัก hemiarthroplasty/THA; intertrochanteric → internal fixation (DHS/nail). ผ่าตัดเร็วลด morbidity/mortality."}, {"topic": "Orthopedics", "q": "A young adult falls on an outstretched hand and has tenderness in the anatomical snuffbox, but the initial X-ray is normal. What is the appropriate management?", "choices": ["Immediate surgery for this patient", "Discharge with reassurance as first step", "Ignore if X-ray is normal as first step", "Immobilize and repeat imaging in 10-14 days", "Aspirate the wrist for this patient"], "ans": 3, "exp": "Scaphoid fracture: FOOSH + กดเจ็บ anatomical snuffbox — X-ray แรกอาจปกติ (occult). จัดการ: 'immobilize (thumb spica) แล้ว X-ray/MRI ซ้ำใน 10-14 วัน' หรือ MRI เลย. สำคัญเพราะเลือดเลี้ยง retrograde → เสี่ยง avascular necrosis/nonunion ที่ proximal pole ถ้าพลาดการวินิจฉัย."}, {"topic": "Orthopedics", "q": "A 60-year-old woman falls on an outstretched hand and has a 'dinner fork' deformity of the wrist. What fracture is this?", "choices": ["Smith fracture", "Scaphoid fracture", "Galeazzi fracture", "Monteggia fracture", "Colles fracture"], "ans": 4, "exp": "Colles fracture: distal radius fracture ที่ 'dorsal angulation/displacement' → 'dinner fork deformity', พบหลัง FOOSH ในผู้สูงอายุ (fragility fracture - ควรประเมิน osteoporosis). รักษา: closed reduction + cast; unstable → ORIF/K-wire. Smith = volar displacement ('reverse Colles')."}, {"topic": "Orthopedics", "q": "A 25-year-old man has a first-time anterior shoulder dislocation after a fall. Which nerve is most commonly injured, causing numbness over the deltoid?", "choices": ["Axillary nerve", "Median nerve", "Radial nerve", "Ulnar nerve", "Musculocutaneous nerve"], "ans": 0, "exp": "Anterior shoulder dislocation (พบบ่อยสุด): แขนอยู่ท่า abduction/external rotation, สูญเสีย contour. เส้นประสาทที่เสี่ยงคือ 'axillary nerve' (ชาบริเวณ deltoid 'regimental badge', deltoid อ่อนแรง). ต้องตรวจ neurovascular ก่อน/หลัง reduction. เสี่ยง Bankart/Hill-Sachs lesion, recurrence สูงในคนหนุ่ม."}, {"topic": "Orthopedics", "q": "A child falls and sustains a supracondylar humeral fracture. Which structure is most at risk, requiring urgent neurovascular assessment?", "choices": ["Sciatic nerve for this patient", "Brachial artery and median nerve", "Femoral vein for this patient", "Common peroneal nerve alone", "Vertebral artery in this case"], "ans": 1, "exp": "Supracondylar humeral fracture (พบบ่อยในเด็ก, FOOSH): เสี่ยงบาดเจ็บ 'brachial artery และ median nerve (โดยเฉพาะ anterior interosseous)'. ต้องตรวจ pulse/perfusion + motor/sensory ('OK sign' = AIN). Displaced (Gartland III) → urgent reduction + K-wire. ภาวะแทรกซ้อน: Volkmann ischemic contracture (จาก compartment syndrome/vascular)."}, {"topic": "Orthopedics", "q": "A child has a fracture through the growth plate and metaphysis (Salter-Harris type II). Why is growth plate injury clinically important?", "choices": ["Always heals with malunion", "No clinical significance", "Risk of growth arrest and deformity", "Requires amputation", "Causes osteomyelitis always"], "ans": 2, "exp": "Salter-Harris classification (physeal fractures): I (through physis), II (physis + Metaphysis - พบบ่อยสุด), III (physis + ePiphysis, intra-articular), IV (Through all), V (cRush - พยากรณ์แย่สุด). สำคัญเพราะเสี่ยง 'growth arrest/angular deformity/limb length discrepancy' → ต้องการ reduction ที่ดีและติดตาม. Type III/IV/V เสี่ยงสูงกว่า."}, {"topic": "Orthopedics", "q": "An infant is found to have asymmetric skin folds and a positive Ortolani/Barlow test. What is the diagnosis?", "choices": ["Slipped capital femoral epiphysis", "Septic arthritis", "Perthes disease", "Developmental dysplasia of the hip", "Transient synovitis"], "ans": 3, "exp": "Developmental dysplasia of the hip (DDH): asymmetric skin folds, limited abduction, 'Ortolani (relocate) / Barlow (dislocate)' positive ในทารก. เสี่ยง: female, breech, family history, first-born. คัดกรอง US (<6 เดือน), X-ray (>4-6 เดือน). รักษา: Pavlik harness (<6 เดือน); ช้า → closed/open reduction + cast."}, {"topic": "Orthopedics", "q": "A 6-year-old boy has an insidious limp and hip/knee pain; X-ray shows a sclerotic, fragmented femoral head. What is the diagnosis?", "choices": ["DDH", "Slipped capital femoral epiphysis", "Septic arthritis", "Transient synovitis", "Legg-Calve-Perthes disease"], "ans": 4, "exp": "Legg-Calve-Perthes disease: idiopathic avascular necrosis ของ femoral head ในเด็ก (~4-8 ปี, ชาย) — เดินกะเผลก, ปวดสะโพก/เข่า, X-ray เห็น head sclerosis/fragmentation. รักษา: containment (limit activity, brace, บางราย osteotomy) เพื่อคง sphericity. พยากรณ์ขึ้นกับอายุ/ปริมาณ head ที่ affected."}, {"topic": "Orthopedics", "q": "An obese 13-year-old boy has hip/knee pain and a limp; the affected leg is externally rotated. X-ray shows the femoral head slipping posteroinferiorly. What is the diagnosis?", "choices": ["Slipped capital femoral epiphysis", "Perthes disease as first step", "Septic arthritis as first step", "DDH for this patient", "Transient synovitis initially"], "ans": 0, "exp": "Slipped capital femoral epiphysis (SCFE): วัยรุ่นอ้วน/growth spurt — ปวดสะโพก/'เข่า' (referred), external rotation, จำกัดการงอ/internal rotation. X-ray (frog-leg) เห็น epiphysis เลื่อน. เป็น orthopedic urgency → 'in situ pinning' (fix ป้องกันเลื่อนเพิ่ม/avascular necrosis). อย่าพยายาม reduce แรงๆ."}, {"topic": "Orthopedics", "q": "A 4-year-old refuses to bear weight on the leg, has a fever, and holds the hip flexed/externally rotated with severe pain on any movement. What is the most urgent diagnosis to exclude?", "choices": ["Cellulitis", "Septic arthritis", "Transient synovitis", "Perthes disease", "Growing pains"], "ans": 1, "exp": "Septic arthritis (โดยเฉพาะสะโพก) เป็น 'orthopedic emergency' — ไข้ + ปวดมาก + ไม่ให้ขยับข้อ (pseudoparalysis) + ลงน้ำหนักไม่ได้. Kocher criteria (ไข้, non-weight bearing, ESR/CRP สูง, WBC สูง) ช่วยแยกจาก transient synovitis. รักษา: 'urgent joint aspiration/drainage + IV antibiotic' (ล่าช้าทำลาย cartilage/growth plate)."}, {"topic": "Orthopedics", "q": "A patient develops progressive bilateral leg weakness, saddle anesthesia, urinary retention, and back pain after a disc herniation. What is the diagnosis?", "choices": ["Spinal stenosis", "Sciatica", "Cauda equina syndrome", "Mechanical back pain", "Vertebral fracture"], "ans": 2, "exp": "Cauda equina syndrome: การกดทับ cauda equina (มักจาก central disc herniation) → 'red flags': saddle anesthesia, bladder/bowel dysfunction (retention → overflow), bilateral leg weakness/sciatica, ลด anal tone. เป็น 'surgical emergency' → urgent MRI + decompression (ภายใน 24-48 ชม.) เพื่อป้องกัน permanent deficit."}, {"topic": "Orthopedics", "q": "A 15-year-old has knee pain and a large mass around the distal femur; X-ray shows a 'sunburst' periosteal reaction and Codman triangle. What is the diagnosis?", "choices": ["Osteochondroma", "Ewing sarcoma", "Giant cell tumor", "Osteosarcoma", "Chondrosarcoma"], "ans": 3, "exp": "Osteosarcoma: มะเร็งกระดูกปฐมภูมิที่พบบ่อยสุดในวัยรุ่น (metaphysis รอบเข่า - distal femur/proximal tibia). X-ray: 'sunburst/spiculated periosteal reaction + Codman triangle', bone destruction. วินิจฉัย biopsy; รักษา neoadjuvant chemo + limb-sparing resection. แพร่ไปปอด."}, {"topic": "Orthopedics", "q": "A 12-year-old has bone pain and fever; X-ray of the diaphysis shows an 'onion-skin' periosteal reaction. Biopsy shows small round blue cells with t(11;22). What is the diagnosis?", "choices": ["Osteosarcoma", "Osteomyelitis", "Osteoid osteoma", "Chondrosarcoma", "Ewing sarcoma"], "ans": 4, "exp": "Ewing sarcoma: เด็ก/วัยรุ่น, มัก diaphysis ของ long bone/pelvis — ปวด + ไข้ (เลียนแบบ osteomyelitis/infection). X-ray: 'onion-skin (lamellated) periosteal reaction'. Histology: small round blue cells, 't(11;22)' EWSR1-FLI1. รักษา: chemo + surgery/RT."}, {"topic": "Orthopedics", "q": "An adult has a lytic, expansile lesion at the epiphysis/metaphysis of the distal femur with a 'soap bubble' appearance; it is usually benign but locally aggressive. What is the diagnosis?", "choices": ["Giant cell tumor of bone", "Osteosarcoma initially", "Ewing sarcoma alone", "Enchondroma initially", "Osteoid osteoma alone"], "ans": 0, "exp": "Giant cell tumor of bone (osteoclastoma): มักที่ 'epiphysis' ของ long bone (distal femur, proximal tibia, distal radius) ในผู้ใหญ่วัยหนุ่มสาว — lytic 'soap bubble', ขยาย. Benign แต่ locally aggressive และเป็นซ้ำได้ (บางรายเป็น malignant/metastasize ปอด). รักษา: curettage + adjuvant (± denosumab)/resection."}, {"topic": "Orthopedics", "q": "A 65-year-old man with known prostate cancer has new severe back pain and a lytic vertebral lesion. What is the most likely cause of bone lesions in this age group?", "choices": ["Paget disease", "Metastatic carcinoma", "Primary osteosarcoma", "Osteomyelitis", "Osteoid osteoma"], "ans": 1, "exp": "ในผู้สูงอายุ 'metastatic carcinoma' เป็นสาเหตุมะเร็งกระดูกที่พบบ่อยที่สุด (มากกว่า primary bone tumor). Primary ที่แพร่ไปกระดูกบ่อย: prostate, breast, lung, kidney, thyroid ('BLT with Kosher Pickle'). Prostate มัก osteoblastic (sclerotic). เฝ้าระวัง pathologic fracture และ spinal cord compression."}, {"topic": "Orthopedics", "q": "A patient with breast cancer develops sudden back pain, leg weakness, and a sensory level; MRI shows epidural cord compression from a vertebral metastasis. What is the immediate management?", "choices": ["Physiotherapy for this patient", "Bed rest and analgesia only", "High-dose steroids and urgent oncology/surgery referral", "Wait for radiotherapy in 2 weeks for this patient", "Discharge home for this patient"], "ans": 2, "exp": "Metastatic spinal cord compression (oncologic emergency): back pain + progressive weakness + sensory level + bladder/bowel dysfunction. รักษาทันที: 'high-dose corticosteroid (dexamethasone)' + urgent MRI whole spine + ปรึกษา surgery (decompression/stabilization) และ/หรือ radiotherapy. ยิ่งรักษาเร็วก่อนสูญเสีย function ยิ่งฟื้นดี."}, {"topic": "Orthopedics", "q": "A patient develops fever and localized bone pain; X-ray shows a lytic lesion with periosteal reaction, and MRI confirms osteomyelitis. In children, which organism is most common?", "choices": ["Pseudomonas", "Escherichia coli", "Salmonella", "Staphylococcus aureus", "Mycobacterium tuberculosis"], "ans": 3, "exp": "Acute hematogenous osteomyelitis (มักที่ metaphysis ของ long bone ในเด็ก): เชื้อบ่อยสุดคือ 'Staphylococcus aureus'. Salmonella พบใน sickle cell disease. รักษา: IV antibiotic + surgical drainage/debridement ถ้ามีหนอง/ตอบสนองช้า. X-ray เปลี่ยนช้า (~2 สัปดาห์) → MRI ไวกว่า."}, {"topic": "Orthopedics", "q": "A patient has an elbow injury; on exam there is weakness of finger and wrist extension and a wrist drop. Which nerve is injured (commonly with humeral shaft fracture)?", "choices": ["Ulnar nerve", "Median nerve", "Axillary nerve", "Musculocutaneous nerve", "Radial nerve"], "ans": 4, "exp": "Radial nerve injury (มักกับ 'humeral shaft fracture' หรือ Saturday night palsy): 'wrist drop' (สูญเสีย wrist/finger extension) + ชาหลังมือด้าน radial (first web space). ส่วนใหญ่เป็น neuropraxia → ฟื้นเอง (สังเกต ~3 เดือน), splint. Median = 'hand of benediction'/thenar; Ulnar = 'claw hand'/hypothenar."}, {"topic": "Orthopedics", "q": "A patient with a mid-shaft humeral fracture cannot extend the wrist. This nerve runs in which groove of the humerus?", "choices": ["Spiral (radial) groove", "Bicipital groove", "Ulnar groove", "Deltopectoral groove", "Intercondylar groove"], "ans": 0, "exp": "Radial nerve วิ่งใน 'spiral (radial) groove' ของ humerus จึงเสี่ยงบาดเจ็บใน mid-shaft humeral fracture → wrist drop. เป็นเหตุผลทางกายวิภาคที่ humeral shaft fracture สัมพันธ์กับ radial nerve palsy. ตรวจ radial nerve function ก่อน/หลัง reduction เสมอ."}, {"topic": "Orthopedics", "q": "A patient sleeps with the arm over a chair and wakes with numbness of the little finger and a 'claw hand'. Which nerve is affected?", "choices": ["Long thoracic nerve", "Ulnar nerve", "Radial nerve", "Median nerve", "Axillary nerve"], "ans": 1, "exp": "Ulnar nerve (มักที่ cubital tunnel/elbow หรือ Guyon canal): ชานิ้วก้อย + ครึ่ง ring finger, 'claw hand' (โดยเฉพาะเมื่อ lesion ที่ wrist - ulnar paradox), อ่อนแรง interossei/hypothenar (Froment sign). สัมพันธ์ medial epicondyle fracture. Median = carpal tunnel/thenar; Radial = wrist drop."}, {"topic": "Orthopedics", "q": "A patient with a fibular neck fracture develops foot drop and cannot dorsiflex or evert the foot. Which nerve is injured?", "choices": ["Tibial nerve for this patient", "Sciatic nerve trunk initially", "Common peroneal (fibular) nerve", "Femoral nerve as first step", "Sural nerve for this patient"], "ans": 2, "exp": "Common peroneal (fibular) nerve พันรอบ 'fibular neck' จึงเสี่ยงบาดเจ็บใน fibular neck fracture/tight cast/prolonged pressure → 'foot drop' (สูญเสีย dorsiflexion + eversion) + ชาหลังเท้า/first web space. ผู้ป่วยเดินแบบ high-stepping. Splint + ป้องกันแรงกด; ส่วนใหญ่ฟื้นถ้าเป็น neuropraxia."}, {"topic": "Orthopedics", "q": "A patient falls and lands on the point of the shoulder; there is a step deformity at the acromioclavicular joint. What is the injury?", "choices": ["Shoulder dislocation", "Clavicle fracture midshaft", "Rotator cuff tear", "Acromioclavicular joint separation", "Sternoclavicular dislocation"], "ans": 3, "exp": "Acromioclavicular (AC) joint injury: ล้มกระแทกไหล่โดยตรง → เจ็บ + 'step deformity' ที่ AC joint (clavicle ปลายนอกยกขึ้น). แบ่งตาม Rockwood I-VI. รักษา: ส่วนใหญ่ (I-III) conservative (sling, physio); severe (IV-VI) → surgery. ต่างจาก clavicle midshaft fracture (ก้อนกลางกระดูกไหปลาร้า)."}, {"topic": "Orthopedics", "q": "A patient jams a finger and cannot actively extend the distal interphalangeal joint, which droops. What is the diagnosis?", "choices": ["Boutonniere deformity", "Swan-neck deformity", "Trigger finger", "Dupuytren contracture", "Mallet finger"], "ans": 4, "exp": "Mallet finger: การบาดเจ็บ 'extensor tendon ที่ DIP' (avulsion ± bony) จากแรงงอ DIP ขณะเหยียด → DIP งอตกและเหยียดเองไม่ได้. รักษา: splint DIP ในท่า extension ต่อเนื่อง 6-8 สัปดาห์; bony mallet ที่ subluxed หรือ fragment ใหญ่ → surgery."}, {"topic": "Orthopedics", "q": "A boxer punches a wall and fractures the neck of the 5th metacarpal. What is this fracture called?", "choices": ["Boxer fracture", "Smith fracture", "Bennett fracture", "Rolando fracture", "Colles fracture"], "ans": 0, "exp": "Boxer's fracture: fracture ที่ 'neck ของ 5th metacarpal' จากการชกกำปั้น → knuckle บุ๋ม/angulation. รักษาส่วนใหญ่ closed (buddy strap/cast) ถ้า angulation ยอมรับได้; rotational deformity/มาก → reduction/fixation. ประเมิน 'fight bite' (บาดแผลจากฟันคน → ติดเชื้อ Eikenella)."}, {"topic": "Orthopedics", "q": "A patient has knee pain and swelling after a twisting injury with a 'pop'; the knee gives way and the anterior drawer/Lachman test is positive. What is injured?", "choices": ["Medial meniscus only", "Anterior cruciate ligament", "Posterior cruciate ligament", "Patellar tendon", "Medial collateral ligament"], "ans": 1, "exp": "Anterior cruciate ligament (ACL) tear: บิดเข่า (pivot) + 'pop' + hemarthrosis (บวมเร็ว) + instability (giving way). ตรวจ 'Lachman (ไวสุด) / anterior drawer / pivot shift' positive. ยืนยัน MRI. รักษา: reconstruction ในผู้ที่ active/instability; conservative + physio ในบางราย. มักร่วมกับ meniscus (O'Donoghue triad)."}, {"topic": "Orthopedics", "q": "An athlete feels a sudden 'kick' to the back of the ankle with an inability to plantarflex; the calf squeeze test (Thompson) shows no foot movement. What is the diagnosis?", "choices": ["Plantar fasciitis", "Ankle sprain", "Achilles tendon rupture", "Gastrocnemius strain", "Peroneal tendon subluxation"], "ans": 2, "exp": "Achilles tendon rupture: รู้สึกเหมือนถูก 'เตะ/ตี' ที่ส้น + plantarflexion อ่อน + คลำพบ gap + 'Thompson test positive' (บีบน่องแล้วเท้าไม่ plantarflex). รักษา: functional bracing/immobilization (equinus) หรือ surgical repair (โดยเฉพาะนักกีฬา/young). วินิจฉัยทางคลินิก ± US/MRI."}, {"topic": "Orthopedics", "q": "A middle-aged worker has numbness/tingling of the thumb, index, and middle fingers, worse at night; Tinel and Phalen tests are positive. What is the diagnosis?", "choices": ["Guyon canal syndrome", "Cubital tunnel syndrome", "Cervical radiculopathy", "Carpal tunnel syndrome", "De Quervain tenosynovitis"], "ans": 3, "exp": "Carpal tunnel syndrome (median nerve compression ที่ข้อมือ): ชา/เสียว thumb-index-middle-half ring, แย่ตอนกลางคืน/สะบัดมือดีขึ้น, thenar atrophy (สาย). Tinel/Phalen positive. สัมพันธ์ ตั้งครรภ์, DM, hypothyroid, RA, ใช้มือซ้ำ. รักษา: splint, steroid injection; ดื้อ/มี atrophy → carpal tunnel release."}, {"topic": "Orthopedics", "q": "A patient in a car crash has a flexed, adducted, internally rotated, shortened hip. Which injury and nerve are at risk?", "choices": ["Femoral neck fracture, obturator nerve", "Anterior hip dislocation, femoral nerve", "Pelvic fracture, pudendal nerve", "Knee dislocation, peroneal nerve", "Posterior hip dislocation, sciatic nerve"], "ans": 4, "exp": "Posterior hip dislocation (พบบ่อยสุด, จาก dashboard injury): สะโพก 'flexed, adducted, internally rotated, shortened'. เสี่ยงบาดเจ็บ 'sciatic nerve' (foot drop) และ avascular necrosis ของ femoral head → เป็น orthopedic urgency ต้อง reduce เร็ว (<6 ชม.). Anterior dislocation → abducted/externally rotated."}, {"topic": "Orthopedics", "q": "A young man has a closed femoral shaft fracture. How much blood can be lost internally, potentially causing shock?", "choices": ["Up to 1-1.5 liters", "Under 200 mL", "Exactly 3 liters always", "No significant blood loss", "Only external bleeding"], "ans": 0, "exp": "Femoral shaft fracture สามารถเสียเลือดภายในต้นขาได้มาก (~1-1.5 ลิตร ต่อข้าง) → อาจ hypovolemic shock (โดยเฉพาะ fracture หลายตำแหน่ง/pelvis). รักษา: resuscitation, analgesia, traction splint (ลดเลือดออก/ปวด), แล้ว definitive fixation (intramedullary nail). ประเมิน fat embolism/associated injury."}, {"topic": "Orthopedics", "q": "A patient has an ankle injury with a fracture of the fibula above the level of the syndesmosis (Weber C). What does this imply?", "choices": ["Growth plate injury for this patient", "Likely syndesmotic disruption needing fixation", "Always stable, cast only", "No treatment needed for this patient", "Isolated soft tissue injury for this patient"], "ans": 1, "exp": "Ankle fracture Weber classification (ตามระดับ fibular fracture เทียบ syndesmosis): A (below - stable), B (at level - variable), C (above - มัก syndesmotic injury, unstable → ORIF ± syndesmotic screw). Weber C บ่งชี้ high-energy/unstable. ประเมิน medial malleolus/deltoid ligament (bimalleolar equivalent)."}, {"topic": "Orthopedics", "q": "A forearm injury shows a fracture of the proximal ulna with dislocation of the radial head. What is this pattern called?", "choices": ["Bennett fracture", "Galeazzi fracture-dislocation", "Monteggia fracture-dislocation", "Colles fracture", "Nightstick fracture"], "ans": 2, "exp": "Monteggia: 'proximal ulna fracture + radial head dislocation'. Galeazzi: 'distal radius fracture + distal radioulnar joint dislocation'. (จำ MUGR: Monteggia-Ulna, Galeazzi-Radius). ทั้งคู่ต้องประเมิน joint ที่ dislocate + fix กระดูก (มัก ORIF ในผู้ใหญ่). ต้องตรวจ posterior interosseous nerve ใน Monteggia."}, {"topic": "Orthopedics", "q": "A 5-year-old has a fracture where the bone is bent and cracked on one side only (cortex intact on the other). What is this fracture called?", "choices": ["Torus (buckle) fracture", "Comminuted fracture", "Spiral fracture", "Greenstick fracture", "Pathologic fracture"], "ans": 3, "exp": "Greenstick fracture: กระดูกเด็ก (อ่อน) หักไม่สมบูรณ์ — cortex ด้านหนึ่งหัก อีกด้าน 'งอ' (คล้ายกิ่งไม้สด). Torus/buckle = cortex buckle จาก compression (stable). พบเฉพาะในเด็ก (bone plasticity). รักษา: cast; angulation มาก → reduction."}, {"topic": "Orthopedics", "q": "An infant presents with multiple fractures of different ages, posterior rib fractures, and a metaphyseal 'corner' fracture. What must be considered?", "choices": ["Osteogenesis imperfecta only", "Normal variant", "Rickets only", "Scurvy", "Non-accidental injury (child abuse)"], "ans": 4, "exp": "Non-accidental injury (child abuse): สงสัยเมื่อมี 'fractures หลายตำแหน่ง/หลายอายุ', posterior rib fractures, metaphyseal corner ('bucket-handle') fractures, ประวัติไม่สอดคล้อง, มาช้า. ต้อง skeletal survey, ประเมินภาพรวม, รายงานตามกฎหมาย. แยกจาก osteogenesis imperfecta (blue sclera, family history)."}, {"topic": "Orthopedics", "q": "A 55-year-old man has an acutely painful, swollen, red first metatarsophalangeal joint; aspiration shows negatively birefringent needle-shaped crystals. What is the diagnosis?", "choices": ["Gout", "Septic arthritis", "Pseudogout", "Rheumatoid arthritis", "Osteoarthritis"], "ans": 0, "exp": "Gout (acute): ปวด/บวม/แดงเฉียบพลันที่ 1st MTP (podagra) — aspiration พบ 'needle-shaped, negatively birefringent' monosodium urate crystals. รักษาเฉียบพลัน: NSAIDs/colchicine/steroid; ป้องกันด้วย allopurinol (ไม่เริ่มขณะ acute). Pseudogout = calcium pyrophosphate, rhomboid, positively birefringent (มัก knee)."}, {"topic": "Orthopedics", "q": "A 70-year-old woman sustains a vertebral compression fracture after minimal trauma. What underlying condition should be evaluated and treated?", "choices": ["Multiple myeloma only", "Osteoporosis", "Osteomalacia only", "Paget disease only", "Normal aging, no action"], "ans": 1, "exp": "Fragility fracture (จาก low-energy trauma เช่น vertebral compression, hip, distal radius) ในผู้สูงอายุ → บ่งชี้ 'osteoporosis' → ประเมิน BMD (DXA, T-score ≤-2.5), เสริม calcium/vitamin D, และรักษาด้วย bisphosphonate/denosumab. ต้องแยก secondary causes (myeloma, malignancy) โดยเฉพาะถ้าลักษณะผิดปกติ."}, {"topic": "Orthopedics", "q": "A 60-year-old man has bone pain, an enlarged skull, bowing of the tibia, and a very high alkaline phosphatase with normal calcium. What is the diagnosis?", "choices": ["Osteoporosis", "Osteomalacia", "Paget disease of bone", "Multiple myeloma", "Hyperparathyroidism"], "ans": 2, "exp": "Paget disease of bone: การ remodeling ผิดปกติ (osteoclast/osteoblast) → กระดูกใหญ่/อ่อน/deformity (bowing, skull enlargement, ปวด, หูตึง), 'ALP สูงมาก' แต่ Ca/PO4 ปกติ. เสี่ยง fracture, high-output heart failure, osteosarcoma (rare). รักษา: bisphosphonate. X-ray: cortical thickening, lytic/sclerotic."}, {"topic": "Orthopedics", "q": "A young adult has night pain in the leg relieved dramatically by NSAIDs; X-ray shows a small lucent nidus with surrounding sclerosis. What is the diagnosis?", "choices": ["Osteosarcoma", "Ewing sarcoma", "Osteomyelitis", "Osteoid osteoma", "Enchondroma"], "ans": 3, "exp": "Osteoid osteoma: benign bone tumor ในวัยรุ่น/หนุ่มสาว — 'ปวดตอนกลางคืน + ตอบสนอง NSAIDs ดีมาก' (prostaglandin). X-ray: nidus (lucent) เล็ก <1.5 cm ล้อมด้วย reactive sclerosis. รักษา: NSAIDs หรือ CT-guided radiofrequency ablation. ต่างจาก osteoblastoma (>2 cm)."}, {"topic": "Orthopedics", "q": "A 65-year-old man has bone pain, anemia, renal impairment, hypercalcemia, and lytic 'punched-out' skull lesions. What is the diagnosis?", "choices": ["Metastatic prostate cancer", "Osteoporosis", "Paget disease", "Hyperparathyroidism", "Multiple myeloma"], "ans": 4, "exp": "Multiple myeloma (plasma cell malignancy): 'CRAB' — hyperCalcemia, Renal impairment, Anemia, Bone lesions (lytic 'punched-out', ไม่มี osteoblastic reaction → bone scan อาจ negative). ตรวจ serum/urine protein electrophoresis (M-protein), Bence-Jones, marrow. เสี่ยง pathologic fracture/cord compression. รักษา hematology (chemo)."}, {"topic": "Orthopedics", "q": "A patient from an endemic area has chronic back pain, low-grade fever, and a gibbus deformity; MRI shows vertebral destruction with a paravertebral abscess. What is the diagnosis?", "choices": ["Spinal tuberculosis (Pott disease)", "Ankylosing spondylitis", "Pyogenic osteomyelitis", "Metastasis", "Osteoporotic fracture"], "ans": 0, "exp": "Spinal tuberculosis (Pott disease): มัก thoracolumbar — ปวดหลังเรื้อรัง, ไข้ต่ำ, night sweats, 'gibbus' (angular kyphosis), paravertebral/psoas abscess (cold abscess). MRI + biopsy/culture. รักษา anti-TB นาน; ผ่าตัดถ้ามี cord compression/instability/deformity. พบในไทย."}, {"topic": "Orthopedics", "q": "A patient has an unstable cervical spine injury after a diving accident. During airway management, what must be maintained?", "choices": ["No precautions for this patient", "In-line cervical spine immobilization", "Full neck extension as first step", "Neck flexion for this patient", "Rotation to one side as first step"], "ans": 1, "exp": "ผู้บาดเจ็บที่สงสัย cervical spine injury: ต้อง 'in-line manual immobilization' ขณะจัดการ airway (หลีกเลี่ยงการขยับคอ). ใช้ orotracheal intubation with in-line stabilization. ประเมิน/clear c-spine ตาม NEXUS/Canadian C-spine rules. Unstable injury เสี่ยง spinal cord damage เพิ่มเมื่อขยับ."}, {"topic": "Orthopedics", "q": "A 45-year-old has back pain radiating down the leg past the knee with a positive straight leg raise, worse on coughing. What is the diagnosis?", "choices": ["Mechanical back pain in this case", "Cauda equina syndrome in this case", "Lumbar disc herniation with sciatica", "Ankylosing spondylitis initially", "Vertebral fracture as first step"], "ans": 2, "exp": "Lumbar disc herniation (มัก L4-5, L5-S1) → sciatica (ปวดร้าวตามขาเลยเข่า, dermatomal), 'straight leg raise positive', แย่เมื่อไอ/นั่ง. ส่วนใหญ่หายด้วย conservative (analgesia, physio, activity). Red flags (cauda equina, progressive deficit, infection/tumor) → urgent MRI/surgery."}, {"topic": "Orthopedics", "q": "A 30-year-old man has an acutely painful, swollen knee with fever; joint aspiration shows purulent fluid with 80,000 WBC/mm3. What is the diagnosis and management?", "choices": ["Hemarthrosis, aspiration only", "Gout, colchicine for this patient", "Reactive arthritis, NSAIDs for this patient", "Septic arthritis, urgent drainage and antibiotics", "Osteoarthritis, analgesia for this patient"], "ans": 3, "exp": "Septic arthritis (adult): ข้อบวมแดงร้อนเฉียบพลัน + ไข้ + aspiration พบ WBC สูงมาก (>50,000, PMN เด่น), gram stain/culture. เชื้อบ่อย S. aureus (gonococcal ในคนหนุ่มสาว sexually active). เป็น emergency → 'urgent joint drainage/washout + IV antibiotic' (ล่าช้าทำลาย cartilage). ส่ง crystals แยก gout."}, {"topic": "Orthopedics", "q": "A patient has anterior shoulder pain and weakness on abduction and external rotation; there is a positive drop-arm test. What is the diagnosis?", "choices": ["Biceps tendon rupture", "Adhesive capsulitis", "AC joint arthritis", "Cervical radiculopathy", "Rotator cuff tear"], "ans": 4, "exp": "Rotator cuff tear (มัก supraspinatus): ปวดไหล่ + อ่อนแรง abduction/external rotation, 'drop-arm test positive', painful arc. พบในผู้สูงอายุ/overuse/trauma. วินิจฉัย US/MRI. รักษา: physio/steroid (partial/degenerative); ผ่าตัดซ่อมใน acute traumatic tear/young/large tear. ต่างจาก frozen shoulder (จำกัด passive ด้วย)."}, {"topic": "Orthopedics", "q": "A 55-year-old diabetic woman has progressive shoulder stiffness with loss of both active and passive range of motion, without weakness. What is the diagnosis?", "choices": ["Adhesive capsulitis (frozen shoulder)", "Rotator cuff tear for this patient", "Shoulder dislocation as first step", "Osteoarthritis for this patient", "Septic arthritis for this patient"], "ans": 0, "exp": "Adhesive capsulitis (frozen shoulder): การจำกัดการเคลื่อนไหวไหล่ 'ทั้ง active และ passive' (โดยเฉพาะ external rotation) โดยไม่มีอ่อนแรงจริง, ปวด. สัมพันธ์ DM, thyroid, immobilization. ดำเนินโรค 3 ระยะ (freezing-frozen-thawing) หายได้เองใน 1-3 ปี. รักษา: physio, analgesia, steroid injection; ดื้อ → manipulation/release."}, {"topic": "Orthopedics", "q": "A tennis player has lateral elbow pain worsened by resisted wrist extension. What is the diagnosis?", "choices": ["Cubital tunnel syndrome initially", "Lateral epicondylitis (tennis elbow)", "Medial epicondylitis in this case", "Olecranon bursitis as first step", "Radial head fracture in this case"], "ans": 1, "exp": "Lateral epicondylitis (tennis elbow): ปวด lateral elbow ที่ common extensor origin, แย่เมื่อ resisted wrist/finger extension (grip). Medial epicondylitis (golfer's elbow) = flexor origin, ปวด medial. รักษา: relative rest, NSAIDs, brace, physio/eccentric exercise; ดื้อ → steroid injection/PRP/surgery."}, {"topic": "Orthopedics", "q": "A patient has a finger that catches and locks in flexion, then releases with a painful click. What is the diagnosis?", "choices": ["Ganglion for this patient", "Dupuytren contracture for this patient", "Trigger finger (stenosing tenosynovitis)", "Mallet finger for this patient", "Boutonniere deformity for this patient"], "ans": 2, "exp": "Trigger finger (stenosing flexor tenosynovitis): นิ้วติด/ล็อกในท่างอ แล้วสะดุด 'click' เมื่อเหยียด — จากปมที่ A1 pulley. สัมพันธ์ DM, RA, ใช้มือซ้ำ. รักษา: splint, NSAIDs, 'corticosteroid injection'; ดื้อ → A1 pulley release. ต่างจาก Dupuytren (พังผืด palmar, งอถาวร)."}, {"topic": "Orthopedics", "q": "A 60-year-old man has progressive flexion contracture of the ring and little fingers with palpable palmar cords and nodules. What is the diagnosis?", "choices": ["Rheumatoid hand", "Trigger finger", "Carpal tunnel syndrome", "Dupuytren contracture", "Ganglion"], "ans": 3, "exp": "Dupuytren contracture: การหนาตัว/หดของ palmar fascia → nodule + cord + งอถาวร (มัก ring/little finger). สัมพันธ์ พันธุกรรม (ยุโรปเหนือ), เหล้า, DM, ลมชัก. รักษา: สังเกต (mild); collagenase injection, needle aponeurotomy, หรือ fasciectomy เมื่อ contracture รบกวน (Hueston tabletop test)."}, {"topic": "Orthopedics", "q": "A skier falls with the thumb forced into abduction and has instability of the ulnar collateral ligament of the thumb MCP joint. What is the diagnosis?", "choices": ["Trigger thumb", "Mallet thumb", "Bennett fracture", "De Quervain tenosynovitis", "Gamekeeper's/skier's thumb"], "ans": 4, "exp": "Gamekeeper's/skier's thumb: การบาดเจ็บ 'ulnar collateral ligament ของ thumb MCP' จากแรง abduction/hyperextension (ล้มถือไม้สกี) → instability, อ่อนแรงหยิบจับ. ระวัง 'Stener lesion' (ligament พับ ไม่หายเอง → ต้องผ่าตัด). Complete tear/Stener → surgical repair; partial → cast."}, {"topic": "Orthopedics", "q": "A patient has radial-sided wrist pain over the first dorsal compartment; the Finkelstein test is positive. What is the diagnosis?", "choices": ["De Quervain tenosynovitis", "Wrist osteoarthritis", "Carpal tunnel syndrome", "Scaphoid fracture", "Trigger thumb"], "ans": 0, "exp": "De Quervain tenosynovitis: การอักเสบของ 1st dorsal compartment (APL/EPB tendons) — ปวด radial wrist ที่ base of thumb, 'Finkelstein test positive' (กำนิ้วหัวแม่มือแล้วเบี่ยง ulnar → ปวด). พบในแม่ลูกอ่อน/ใช้มือซ้ำ. รักษา: thumb spica splint, NSAIDs, steroid injection; ดื้อ → release."}, {"topic": "Orthopedics", "q": "A young man twists the knee and has locking and a positive McMurray test with joint-line tenderness. What structure is injured?", "choices": ["Medial collateral ligament", "Meniscus", "Anterior cruciate ligament", "Patellar tendon", "Quadriceps tendon"], "ans": 1, "exp": "Meniscal tear: บิดเข่า → ปวด joint-line, 'locking/catching', บวมช้าๆ (effusion), 'McMurray test positive'. วินิจฉัย MRI. รักษา: peripheral/vascular zone → repair; central/degenerative → conservative หรือ partial meniscectomy. มักร่วมกับ ACL injury."}, {"topic": "Orthopedics", "q": "An adolescent basketball player has pain and a bony prominence at the tibial tuberosity, worse with activity. What is the diagnosis?", "choices": ["Meniscal tear", "Patellar dislocation", "Osgood-Schlatter disease", "ACL tear", "Septic arthritis"], "ans": 2, "exp": "Osgood-Schlatter disease: apophysitis ของ tibial tuberosity (traction จาก patellar tendon) ในวัยรุ่นที่ active (กระโดด/วิ่ง) — ปวด/นูนที่ tibial tuberosity, แย่เมื่อออกกำลัง. เป็น self-limited (หายเมื่อ growth plate ปิด). รักษา: relative rest, ice, stretching, NSAIDs."}, {"topic": "Orthopedics", "q": "A runner has heel pain that is worst on the first steps in the morning, with tenderness at the medial calcaneal tuberosity. What is the diagnosis?", "choices": ["Achilles tendinopathy", "Calcaneal fracture", "Tarsal tunnel syndrome", "Plantar fasciitis", "Gout"], "ans": 3, "exp": "Plantar fasciitis: ปวดส้นเท้า 'ก้าวแรกตอนเช้า/หลังพัก' (start-up pain), กดเจ็บ medial calcaneal tuberosity. สัมพันธ์ overuse, ยืน/วิ่งนาน, obesity, tight calf. รักษา: stretching (plantar fascia/calf), heel cushion/orthotics, NSAIDs; ส่วนใหญ่หายด้วย conservative. Heel spur เป็น incidental."}, {"topic": "Orthopedics", "q": "A newborn has a foot that is rigidly held in equinus, varus, and adduction that cannot be passively corrected. What is the diagnosis?", "choices": ["Metatarsus adductus for this patient", "Calcaneovalgus foot for this patient", "Vertical talus for this patient", "Flat foot for this patient", "Congenital talipes equinovarus (clubfoot)"], "ans": 4, "exp": "Congenital talipes equinovarus (clubfoot): เท้าบิด rigid — equinus (ปลายเท้าจิก), varus (ส้นบิดใน), adductus (หน้าเท้าเข้า), cavus. รักษา: 'Ponseti method' (serial casting + Achilles tenotomy + brace) ตั้งแต่แรกเกิด. ต่างจาก positional deformity (แก้ passive ได้). ประเมิน associated (spina bifida, DDH)."}, {"topic": "Orthopedics", "q": "A patient has a knee dislocation from high-energy trauma that reduced spontaneously. Which injury must be actively excluded?", "choices": ["Popliteal artery injury", "Simple contusion", "Isolated meniscus tear", "Patellar tendon rupture", "Ankle sprain"], "ans": 0, "exp": "Knee dislocation (high-energy) เสี่ยง 'popliteal artery injury' (tethered ที่ adductor hiatus/soleus arch) และ common peroneal nerve — แม้ reduce เองแล้วก็ต้องประเมิน vascular (ABI, serial exam, CT angiography ถ้า abnormal). Vascular injury ที่พลาด → limb loss. multiligament injury มัก ต้อง reconstruction."}, {"topic": "Orthopedics", "q": "A patient has a comminuted fracture that has failed to heal after 9 months with a persistent gap. What is this complication called?", "choices": ["Malunion", "Nonunion", "Delayed union", "Avascular necrosis", "Osteomyelitis"], "ans": 1, "exp": "Nonunion: fracture ที่ไม่ติดหลังเวลาที่คาด (มัก >6-9 เดือน, ไม่มี progression). ปัจจัย: poor blood supply, infection, instability/motion, gap, สูบบุหรี่, NSAIDs. รักษา: stable fixation + bone graft (± แก้ไข infection/biology). Malunion = ติดในตำแหน่งผิด; Delayed union = ช้าแต่ยังดำเนินอยู่."}, {"topic": "Orthopedics", "q": "A patient who took long-term corticosteroids has progressive hip pain; MRI shows a subchondral crescent sign of the femoral head. What is the diagnosis?", "choices": ["Osteoarthritis for this patient", "Septic arthritis for this patient", "Avascular necrosis of the femoral head", "Stress fracture for this patient", "Transient osteoporosis in this case"], "ans": 2, "exp": "Avascular (osteo)necrosis ของ femoral head: ปัจจัยเสี่ยง 'corticosteroid, alcohol', sickle cell, femoral neck fracture/dislocation, SLE, caisson. MRI ไวสุด (crescent sign, สาย). รักษาตามระยะ: core decompression (early, pre-collapse), joint-preserving; collapsed → total hip replacement."}, {"topic": "Orthopedics", "q": "A baby is delivered with shoulder dystocia and now holds the arm adducted, internally rotated, with the forearm pronated ('waiter's tip'). Which brachial plexus injury is this?", "choices": ["Klumpke palsy (C8-T1)", "Radial nerve palsy", "Total plexus palsy", "Erb palsy (C5-C6)", "Axillary nerve palsy"], "ans": 3, "exp": "Erb-Duchenne palsy (upper trunk C5-C6): จาก shoulder dystocia/traction → 'waiter's tip' (arm adducted, internally rotated, forearm pronated, wrist flexed). Klumpke (lower trunk C8-T1) → 'claw hand' ± Horner syndrome. ส่วนใหญ่ Erb ฟื้นเองด้วย physio; ไม่ฟื้น → microsurgery."}, {"topic": "Orthopedics", "q": "A patient falls on an outstretched hand and has elbow pain with inability to fully extend; X-ray shows a subtle radial head fracture with a positive 'sail sign' (fat pad). What is the management for a non-displaced fracture?", "choices": ["Long-arm cast for 8 weeks", "Immediate ORIF always", "Radial head excision", "No follow-up needed", "Early mobilization with a sling"], "ans": 4, "exp": "Radial head fracture (พบบ่อยหลัง FOOSH): X-ray อาจเห็นเพียง 'fat pad/sail sign'. Non-displaced/minimally displaced (Mason I) → 'early mobilization' (sling สั้นๆ) เพื่อป้องกันข้อติด. Displaced/block to motion → ORIF/replacement. หลีกเลี่ยง immobilization นาน (เสี่ยง stiffness)."}, {"topic": "Orthopedics", "q": "A patient falls and cannot actively extend the knee; there is a palpable gap above the patella with a high-riding patella. What is the diagnosis?", "choices": ["Quadriceps tendon rupture", "Patellar tendon rupture", "Patellar fracture", "ACL tear", "Meniscal tear"], "ans": 0, "exp": "Quadriceps tendon rupture (มัก >40 ปี): สูญเสีย active knee extension + gap เหนือ patella + patella baja (ต่ำ)... ขออภัย: quadriceps rupture → patella 'อยู่ต่ำกว่าปกติ'. Patellar tendon rupture (<40 ปี) → gap ใต้ patella + patella alta (สูง). ทั้งคู่สูญเสีย extensor mechanism → surgical repair. (ตำแหน่ง gap ช่วยแยก)."}, {"topic": "Orthopedics", "q": "A patient has a knee injury; the tibia can be pushed backward relative to the femur (positive posterior drawer). Which ligament is torn?", "choices": ["Anterior cruciate ligament", "Posterior cruciate ligament", "Medial collateral ligament", "Lateral collateral ligament", "Patellar tendon"], "ans": 1, "exp": "Posterior cruciate ligament (PCL) tear: มักจาก 'dashboard injury' (tibia กระแทกไปหลัง) หรือ hyperflexion → 'posterior drawer positive', posterior sag sign. ส่วนใหญ่ isolated PCL รักษา conservative (physio, quadriceps strengthening); combined/multiligament → reconstruction. ต่างจาก ACL (anterior drawer/Lachman)."}, {"topic": "Orthopedics", "q": "A patient has valgus knee injury with pain and laxity on the medial side. Which ligament is injured?", "choices": ["Lateral collateral ligament", "Anterior cruciate ligament", "Medial collateral ligament", "Posterior cruciate ligament", "Patellar tendon"], "ans": 2, "exp": "Medial collateral ligament (MCL) injury: จากแรง 'valgus' → ปวด/laxity ด้าน medial (valgus stress test). MCL เป็น extra-articular และหายเองได้ดี → รักษา conservative (hinged brace, physio) เป็นส่วนใหญ่. LCL/posterolateral corner injury (varus) พบน้อยกว่าและมักต้องผ่าตัด."}, {"topic": "Orthopedics", "q": "A patient is on the surgical ward after a hip fracture. Which measure reduces the high risk of venous thromboembolism?", "choices": ["High-dose aspirin only", "Bed rest without prophylaxis", "Therapeutic anticoagulation always", "Mechanical and pharmacologic prophylaxis", "No prophylaxis needed"], "ans": 3, "exp": "ผู้ป่วยผ่าตัด hip/ major orthopedic (hip/knee arthroplasty, hip fracture) = 'high VTE risk' → prophylaxis: pharmacologic (LMWH, DOAC, aspirin ในบางแนวทางของ arthroplasty) + mechanical (IPC/stocking) + early mobilization. Extended prophylaxis (~4-5 สัปดาห์) หลัง hip fracture/arthroplasty."}, {"topic": "Orthopedics", "q": "A patient with a total knee replacement 1 year ago has increasing joint pain, effusion, and a sinus tract. What complication should be suspected?", "choices": ["Aseptic loosening only", "Gout", "Simple bursitis", "Referred pain", "Prosthetic joint infection"], "ans": 4, "exp": "Prosthetic joint infection (PJI): ปวดข้อเทียมเรื้อรัง, บวม, warmth, sinus tract, ± ไข้. วินิจฉัย: ESR/CRP สูง, 'joint aspiration' (cell count, culture), imaging. รักษา: debridement + antibiotic; อาจต้อง 1- หรือ 2-stage revision (เอา prosthesis ออก + spacer). แยกจาก aseptic loosening (ไม่มี infection markers)."}, {"topic": "Orthopedics", "q": "A patient has an ankle inversion injury with lateral swelling and tenderness over the anterior talofibular ligament, able to bear weight partially. What grade sprain and management?", "choices": ["Ligament sprain, functional treatment (RICE, brace)", "Achilles rupture for this patient", "Fracture needing ORIF for this patient", "Complete dislocation needing surgery in this case", "Compartment syndrome for this patient"], "ans": 0, "exp": "Ankle sprain (inversion): มักบาดเจ็บ 'anterior talofibular ligament' (lateral). Ottawa ankle rules ช่วยตัดสินใจ X-ray (แยก fracture). ส่วนใหญ่รักษาแบบ functional: RICE, early mobilization, brace, proprioceptive rehab (ดีกว่า immobilization นาน). Severe/instability เรื้อรัง → พิจารณาผ่าตัด."}, {"topic": "Orthopedics", "q": "A runner has localized shin pain and tenderness; X-ray is initially normal but bone scan/MRI shows a stress fracture of the tibia. What is the management?", "choices": ["Immediate surgery for this patient", "Relative rest and activity modification", "Continue running for this patient", "Long-leg cast for 3 months initially", "Amputation for this patient"], "ans": 1, "exp": "Stress fracture (overuse, เปลี่ยนกิจกรรม/เพิ่มระยะเร็ว): ปวดเฉพาะจุด, X-ray แรกปกติ (MRI/bone scan ไวกว่า). รักษา: 'relative rest + activity modification', แก้ปัจจัย (biomechanics, nutrition, female athlete triad). ตำแหน่ง high-risk (anterior tibia, femoral neck, navicular, 5th MT base) เสี่ยง nonunion → อาจต้อง fixation."}, {"topic": "Orthopedics", "q": "An elderly patient has an intertrochanteric hip fracture. Which fixation is typically used?", "choices": ["Total hip replacement always", "Hemiarthroplasty always", "Dynamic hip screw or intramedullary nail", "Conservative traction only", "External fixator"], "ans": 2, "exp": "Intertrochanteric (extracapsular) hip fracture: เลือดเลี้ยงดี (นอก capsule) → 'internal fixation' ด้วย dynamic hip screw (DHS) หรือ intramedullary nail (cephalomedullary). ต่างจาก 'displaced femoral neck' (intracapsular, เสี่ยง AVN) ที่มัก arthroplasty (hemi/total). ผ่าตัดเร็ว + mobilize ลด complication."}, {"topic": "Orthopedics", "q": "A middle-aged patient has bilateral leg pain on walking that is relieved by leaning forward/sitting, with normal pedal pulses. What is the diagnosis?", "choices": ["Peripheral arterial disease for this patient", "DVT for this patient", "Osteoarthritis of the hip for this patient", "Lumbar spinal stenosis (neurogenic claudication)", "Sciatica from disc for this patient"], "ans": 3, "exp": "Lumbar spinal stenosis → 'neurogenic claudication': ปวด/อ่อนแรงขาเมื่อเดิน/ยืน (extension) ดีขึ้นเมื่อ 'ก้มตัว/นั่ง' (flexion เปิด canal), 'pulses ปกติ' (แยกจาก vascular claudication). MRI ยืนยัน. รักษา: physio, analgesia, epidural steroid; ดื้อ → decompressive laminectomy."}, {"topic": "Orthopedics", "q": "A patient has an inversion ankle injury and cannot bear weight; there is bony tenderness at the base of the 5th metatarsal. Per Ottawa rules, what is indicated?", "choices": ["No imaging needed", "MRI first", "CT first", "Immediate surgery", "Ankle/foot X-ray"], "ans": 4, "exp": "Ottawa ankle/foot rules: ทำ X-ray เมื่อมีปวด malleolar/midfoot zone + (bony tenderness ที่ posterior edge/tip ของ malleolus, base of 5th metatarsal, navicular) หรือ 'ลงน้ำหนักไม่ได้ ≥4 ก้าว'. ช่วยลด X-ray โดยไม่พลาด fracture. Base of 5th MT tenderness → X-ray (แยก avulsion/Jones fracture)."}, {"topic": "Orthopedics", "q": "A patient with knee osteoarthritis has pain and functional limitation not controlled by conservative measures. What is the definitive surgical option?", "choices": ["Total knee arthroplasty", "Meniscectomy", "Arthroscopic washout", "Synovectomy", "Fasciotomy"], "ans": 0, "exp": "Knee osteoarthritis: รักษาเริ่มด้วย conservative (ลดน้ำหนัก, exercise/physio, analgesia - paracetamol/NSAIDs, intra-articular steroid). เมื่อ end-stage + failed conservative + คุณภาพชีวิตแย่ → 'total knee arthroplasty' (definitive). Arthroscopic washout ไม่แนะนำใน OA (ไม่ได้ผล)."}, {"topic": "Orthopedics", "q": "A patient sustains a fall from height landing on the feet, with heel pain and swelling; X-ray shows a calcaneal fracture. What associated injury must be checked?", "choices": ["Rib fracture for this patient", "Spinal (thoracolumbar) fracture", "Skull fracture as first step", "Wrist fracture as first step", "Clavicle fracture initially"], "ans": 1, "exp": "Calcaneal fracture (fall from height, axial load): ต้องประเมิน 'associated injuries ตามแนวแรง' — 'thoracolumbar spine fracture' (บ่อย), contralateral calcaneus, pilon/tibial plateau, pelvis. Intra-articular calcaneal fracture (Bohler angle ลด) มัก CT + surgery. เฝ้าระวัง compartment syndrome ของเท้า."}, {"topic": "Orthopedics", "q": "A teenager has progressive lateral curvature of the spine noted on forward bending (rib hump), without pain. What is the diagnosis?", "choices": ["Scheuermann kyphosis", "Ankylosing spondylitis", "Adolescent idiopathic scoliosis", "Vertebral fracture", "Spinal tumor"], "ans": 2, "exp": "Adolescent idiopathic scoliosis: การโค้งด้านข้างของกระดูกสันหลัง (Cobb angle) พบในวัยรุ่น (หญิง), มัก 'ไม่ปวด', ตรวจพบ rib hump เมื่อก้ม (Adam's forward bend). รักษาตาม Cobb angle/skeletal maturity: สังเกต (<20°), brace (20-40° ที่ยังโต), surgery (>45-50°). ปวด/neurologic ต้องหาสาเหตุอื่น."}, {"topic": "Orthopedics", "q": "A 3-year-old refuses to walk after a minor fall; there is a subtle spiral fracture of the tibia (toddler's fracture). What is a key consideration in a child with a spiral fracture?", "choices": ["Always benign, no concern for this patient", "Requires amputation for this patient", "Always pathologic for this patient", "Consider mechanism and abuse if inconsistent", "Immediate surgery for this patient"], "ans": 3, "exp": "Toddler's fracture (spiral/oblique distal tibia) มักเกิดจาก low-energy twisting ในเด็กหัดเดิน (accidental). อย่างไรก็ตาม 'spiral fracture' โดยเฉพาะในเด็กที่ยังเดินไม่ได้ หรือประวัติไม่สอดคล้อง ต้องพิจารณา 'non-accidental injury'. Toddler's fracture ที่เข้าได้กับประวัติรักษาด้วย cast/observation."}, {"topic": "Orthopedics", "q": "A young man has low back pain and stiffness worse in the morning and improving with exercise, with reduced spinal mobility; HLA-B27 positive. What is the diagnosis?", "choices": ["Spinal stenosis", "Mechanical back pain", "Disc herniation", "Osteoporotic fracture", "Ankylosing spondylitis"], "ans": 4, "exp": "Ankylosing spondylitis (seronegative spondyloarthropathy, HLA-B27): ปวดหลัง 'inflammatory' (แย่ตอนเช้า/พัก, ดีขึ้นเมื่อออกกำลัง, อายุ <40), sacroiliitis, ลด spinal mobility, 'bamboo spine' (สาย). รักษา: NSAIDs + exercise, biologics (anti-TNF/IL-17). เสี่ยง fracture (rigid spine), uveitis. ต่างจาก mechanical back pain."}, {"topic": "Orthopedics", "q": "A patient has a hip fracture and, before surgery, is placed in skin traction. What is the main purpose?", "choices": ["Pain relief and provisional immobilization", "Correct rotation permanently initially", "Definitive treatment for this patient", "Prevent infection for this patient", "Reduce blood loss to zero as first step"], "ans": 0, "exp": "Skin/skeletal traction ก่อนผ่าตัด: ช่วย 'บรรเทาปวดและ immobilize ชั่วคราว' (แต่หลักฐานประโยชน์ routine skin traction จำกัด). ไม่ใช่ definitive treatment. Definitive คือผ่าตัด fixation/arthroplasty เร็ว. Skeletal traction ใช้ใน femoral shaft fracture บางกรณีเป็น temporizing."}, {"topic": "Orthopedics", "q": "A neonate has a lateral neck mass and the head tilted toward one side with the chin rotated to the opposite side. What is the diagnosis?", "choices": ["Cervical lymphadenitis", "Congenital muscular torticollis", "Klippel-Feil syndrome", "Branchial cyst", "Cystic hygroma"], "ans": 1, "exp": "Congenital muscular torticollis: การหดสั้น/fibrosis ของ sternocleidomastoid (อาจคลำได้ก้อน 'sternomastoid tumor') → head tilt เข้าด้าน affected, chin หันออก. สัมพันธ์ breech/birth trauma, DDH. รักษา: 'stretching/physiotherapy' (ส่วนใหญ่หาย); ดื้อ → surgical release. ประเมิน plagiocephaly/DDH ร่วม."}, {"topic": "Orthopedics", "q": "A child has bowed legs, delayed growth, widened wrists, and a rachitic rosary; labs show low vitamin D, low phosphate, and high alkaline phosphatase. What is the diagnosis?", "choices": ["Osteogenesis imperfecta", "Achondroplasia", "Rickets", "Scurvy", "Blount disease"], "ans": 2, "exp": "Rickets: การขาด mineralization ของ growth plate (vitamin D deficiency พบบ่อย) → bowing legs (genu varum), widened wrists/costochondral junction ('rachitic rosary'), frontal bossing, growth delay; ALP สูง, Ca/PO4 ต่ำ. รักษา: vitamin D + calcium (± phosphate ใน hypophosphatemic types). Osteomalacia = ในผู้ใหญ่."}, {"topic": "Orthopedics", "q": "A patient has an olecranon fracture with an inability to actively extend the elbow against gravity. What is the appropriate management for a displaced fracture?", "choices": ["Long-arm cast only", "Sling and early motion initially", "Radial head excision in this case", "Open reduction and internal fixation", "Observation for this patient"], "ans": 3, "exp": "Olecranon fracture ที่ 'displaced' (สูญเสีย extensor mechanism - triceps ดึงแยก) → 'ORIF' (tension band wiring หรือ plate) เพื่อฟื้น extensor function และ articular congruity. Non-displaced/stable → immobilization สั้นๆ + early motion. ประเมิน ulnar nerve."}, {"topic": "Orthopedics", "q": "A young athlete dislocates the patella laterally after a twisting injury. After reduction, what is the initial management for a first-time dislocation?", "choices": ["Long cast for 3 months", "Immediate reconstruction", "Patellectomy", "No treatment", "Bracing/rehabilitation"], "ans": 4, "exp": "Patellar dislocation (มัก lateral, จาก valgus/twist): reduce (extend knee) → 'bracing + rehabilitation' (quadriceps/VMO strengthening) สำหรับ first-time ที่ไม่มี osteochondral fragment. Recurrent/large osteochondral fragment/MPFL rupture → surgery (MPFL reconstruction). ประเมิน predisposing factors (patella alta, trochlear dysplasia)."}, {"topic": "Orthopedics", "q": "A patient develops a hot, swollen, painful great toe joint; aspiration shows positively birefringent, rhomboid-shaped crystals. What is the diagnosis?", "choices": ["Pseudogout (CPPD)", "Septic arthritis", "Gout", "Rheumatoid arthritis", "Reactive arthritis"], "ans": 0, "exp": "Pseudogout (calcium pyrophosphate deposition, CPPD): crystals 'rhomboid, positively birefringent', มัก knee/wrist (แต่พบที่อื่นได้), chondrocalcinosis บน X-ray. สัมพันธ์ hyperparathyroidism, hemochromatosis, hypomagnesemia, สูงอายุ. รักษาเฉียบพลัน: NSAIDs/colchicine/steroid. ต่างจาก gout (urate, needle, negatively birefringent)."}, {"topic": "Orthopedics", "q": "A patient has forefoot pain and a burning sensation with a clicking on compression between the 3rd and 4th toes (Mulder click). What is the diagnosis?", "choices": ["Plantar fasciitis", "Morton neuroma", "Stress fracture", "Hallux valgus", "Gout"], "ans": 1, "exp": "Morton neuroma: perineural fibrosis ของ interdigital nerve (มัก 3rd-4th webspace) → ปวดแสบ/ชานิ้วเท้า, 'Mulder click' เมื่อบีบ. สัมพันธ์รองเท้าคับ/ส้นสูง. รักษา: metatarsal pad, รองเท้ากว้าง, steroid injection; ดื้อ → excision. ต่างจาก stress fracture (bony tenderness)."}, {"topic": "Orthopedics", "q": "A patient has a deformity where the great toe deviates laterally toward the other toes with a prominent medial eminence. What is the diagnosis?", "choices": ["Claw toe", "Hammer toe", "Hallux valgus (bunion)", "Hallux rigidus", "Morton neuroma"], "ans": 2, "exp": "Hallux valgus (bunion): นิ้วหัวแม่เท้าเบนออก (valgus) + medial eminence นูน, สัมพันธ์รองเท้าคับ/พันธุกรรม/หญิง. รักษา: รองเท้ากว้าง, orthotics, spacer (conservative); ปวด/deformity มาก → surgery (osteotomy). Hallux rigidus = OA ของ 1st MTP (จำกัดการงอ/เหยียด)."}, {"topic": "Orthopedics", "q": "A patient has an ingrown toenail with a red, painful, swollen nail fold with granulation tissue. What is the appropriate management for recurrent/severe cases?", "choices": ["No treatment for this patient", "Systemic antifungals for this patient", "Complete toe amputation in this case", "Partial nail avulsion with matricectomy", "Oral steroids for this patient"], "ans": 3, "exp": "Ingrown toenail (onychocryptosis): ขอบเล็บฝังเข้าเนื้อ → อักเสบ/granulation. เบื้องต้น: แช่น้ำอุ่น, ยกขอบเล็บ, สุขอนามัย, antibiotic ถ้าติดเชื้อ. เป็นซ้ำ/รุนแรง → 'partial nail avulsion + matricectomy' (phenol/surgical) เพื่อกำจัด nail matrix ด้านนั้นถาวร. ในเบาหวานระวังภาวะแทรกซ้อน."}, {"topic": "Orthopedics", "q": "A 2-year-old has a limp; imaging shows a hip joint effusion, and he has a low-grade fever after a recent viral illness with normal inflammatory markers. What is the most likely diagnosis?", "choices": ["SCFE", "Septic arthritis", "Perthes disease", "Osteomyelitis", "Transient synovitis"], "ans": 4, "exp": "Transient synovitis (irritable hip): สาเหตุ hip pain/limp ที่พบบ่อยในเด็ก (3-8 ปี) หลัง viral URI — ไข้ต่ำ/ไม่มี, inflammatory markers ปกติ/สูงเล็กน้อย, ยังพอลงน้ำหนักได้บ้าง. เป็น self-limited (NSAIDs, rest). สำคัญคือต้อง 'แยก septic arthritis' (Kocher criteria) ซึ่งเป็น emergency."}, {"topic": "Orthopedics", "q": "A patient with rheumatoid arthritis has ulnar deviation of the fingers, swan-neck and boutonniere deformities. What is the underlying process?", "choices": ["Chronic synovitis eroding joints and tendons", "Infection for this patient", "Crystal deposition for this patient", "Degenerative wear only", "Nerve compression for this patient"], "ans": 0, "exp": "Rheumatoid arthritis: chronic autoimmune 'synovitis' (pannus) → erosion ของ joint/cartilage + laxity ของ ligament/tendon → deformity (ulnar deviation, swan-neck, boutonniere, Z-thumb, MCP subluxation). รักษา: DMARDs (methotrexate)/biologics ควบคุมโรค; surgery (synovectomy, arthroplasty, tendon repair) ในรายที่เสียหาย. ต่างจาก OA (Heberden/Bouchard, DIP)."}, {"topic": "Orthopedics", "q": "A patient in a plaster cast complains of increasing pain, tightness, and numbness of the fingers hours later. What is the immediate action?", "choices": ["Apply a tighter cast", "Split/remove the cast and assess", "Give more analgesia and wait", "Elevate and reassure only", "Order an MRI first"], "ans": 1, "exp": "ปวดเพิ่มขึ้น + tightness + ชา/เย็นปลายมือหลังใส่เฝือก = สงสัย 'cast too tight / compartment syndrome' → 'split หรือถอดเฝือกทันที' (bivalve, ตัด padding ถึงผิว) และประเมิน neurovascular. อย่าให้ยาแก้ปวดแล้วรอ. ป้องกันภาวะแทรกซ้อน ischemia/Volkmann contracture."}, {"topic": "Orthopedics", "q": "A patient sustains a high-energy axial load to the knee; X-ray shows a depressed lateral tibial plateau fracture. What imaging best defines the fracture for surgical planning?", "choices": ["DEXA scan", "Ultrasound", "CT scan", "Bone scan", "Plain X-ray only"], "ans": 2, "exp": "Tibial plateau fracture: 'CT scan' ประเมิน articular depression/split, comminution เพื่อวางแผนผ่าตัด (ORIF ใน displaced/depressed intra-articular). ประเมิน soft tissue (compartment syndrome, ligament/meniscus, popliteal vessel ใน high-energy). Depressed articular surface >กำหนด → surgery เพื่อคง joint congruity."}, {"topic": "Orthopedics", "q": "A patient has midfoot pain after a fall; X-ray shows widening between the 1st and 2nd metatarsal bases with a small avulsion ('fleck sign'). What injury is this?", "choices": ["Calcaneal fracture", "Jones fracture", "March fracture", "Lisfranc injury", "Ankle sprain"], "ans": 3, "exp": "Lisfranc injury (tarsometatarsal joint complex): midfoot pain/swelling, ลงน้ำหนักไม่ได้, 'fleck sign' (avulsion ที่ base 2nd MT) + widening 1st-2nd MT. อาจพลาดได้ง่าย → weight-bearing X-ray/CT. Unstable/displaced → ORIF (missed injury → chronic pain/arthritis). ระวัง compartment syndrome ของเท้า."}, {"topic": "Orthopedics", "q": "A patient has an elbow dislocation (posterior). After reduction, what must be assessed and documented?", "choices": ["Only the X-ray for this patient", "Blood glucose for this patient", "Chest X-ray for this patient", "Abdominal exam for this patient", "Neurovascular status and joint stability"], "ans": 4, "exp": "Elbow dislocation (posterior พบบ่อยสุด): ประเมิน 'neurovascular ก่อน/หลัง reduction' (brachial artery, ulnar/median nerve) + ตรวจ stability + X-ray หลัง reduce (แยก associated fracture - 'terrible triad': radial head + coronoid + LCL). Simple → early motion; complex/unstable → surgery."}, {"topic": "Orthopedics", "q": "A patient with chronic osteomyelitis has a persistent draining sinus; imaging shows a segment of dead bone (sequestrum). What is the definitive treatment principle?", "choices": ["Surgical debridement of dead bone plus antibiotics", "Amputation always for this patient", "Antibiotics alone indefinitely for this patient", "Observation for this patient", "Splinting only"], "ans": 0, "exp": "Chronic osteomyelitis: มี 'sequestrum' (dead bone) และ involucrum, sinus tract. ยาปฏิชีวนะอย่างเดียวไม่พอ (เข้าไม่ถึง dead bone) → ต้อง 'surgical debridement/sequestrectomy' เอา dead/infected bone ออก + antibiotic (ตาม culture) + จัดการ dead space/soft tissue. เสี่ยง Marjolin ulcer (SCC) ใน sinus เรื้อรัง."}, {"topic": "Orthopedics", "q": "A patient falls on an outstretched hand and has a scaphoid fracture at the proximal pole. What complication is this location prone to?", "choices": ["Compartment syndrome alone", "Avascular necrosis and nonunion", "Rapid healing as first step", "Growth arrest as first step", "Infection for this patient"], "ans": 1, "exp": "Scaphoid มีเลือดเลี้ยง 'retrograde' (จาก distal → proximal) จึง fracture ที่ 'proximal pole' เสี่ยง avascular necrosis และ nonunion สูงสุด → มักต้อง fixation (screw) + ติดตาม. Waist fracture (พบบ่อยสุด) ก็เสี่ยงพอควร. Displaced/proximal → surgical fixation."}, {"topic": "Orthopedics", "q": "A patient has a displaced patellar fracture with loss of active knee extension and a palpable gap. What is the management?", "choices": ["Sling and rest for this patient", "Long-leg cast only", "Open reduction and internal fixation", "Patellectomy always as first step", "Observation for this patient"], "ans": 2, "exp": "Patellar fracture ที่ 'displaced' + สูญเสีย extensor mechanism (active extension ไม่ได้/gap) → 'ORIF' (tension band/screw) เพื่อฟื้น extensor function + articular surface. Non-displaced ที่ extensor mechanism ยังทำงาน → immobilization + protected weight bearing. Comminuted รุนแรง → partial patellectomy."}, {"topic": "Orthopedics", "q": "A 60-year-old man with hip osteoarthritis has groin pain and reduced internal rotation. Conservative treatment has failed. What is the definitive option?", "choices": ["Arthroscopy", "Core decompression", "Osteotomy always", "Total hip arthroplasty", "Fusion"], "ans": 3, "exp": "Hip osteoarthritis: ปวดขาหนีบ, ลด internal rotation, X-ray (joint space narrowing, osteophyte, subchondral sclerosis/cyst). รักษาเริ่ม conservative (exercise, ลดน้ำหนัก, analgesia). End-stage + failed conservative → 'total hip arthroplasty' (definitive, ผลดีมาก). ต่างจาก AVN early ที่อาจ core decompression."}, {"topic": "Orthopedics", "q": "A trauma patient has a suspected cervical spine injury. Which criteria can be used to clinically clear the c-spine without imaging in a low-risk patient?", "choices": ["Alvarado score", "Ottawa ankle rules", "Wells score", "Glasgow-Blatchford score", "NEXUS or Canadian C-spine rule"], "ans": 4, "exp": "การ clear cervical spine ทางคลินิก (low-risk, alert, ไม่มึนเมา): ใช้ 'NEXUS criteria' (no midline tenderness, no focal deficit, normal alertness, no intoxication, no distracting injury) หรือ 'Canadian C-spine rule'. ถ้าไม่ผ่านเกณฑ์ → imaging (CT). ช่วยลด imaging ที่ไม่จำเป็นอย่างปลอดภัย."}, {"topic": "Orthopedics", "q": "A young man is in a rear-end collision and develops neck pain and stiffness 1-2 days later with normal imaging. What is the diagnosis and management?", "choices": ["Whiplash-associated disorder, analgesia and early mobilization", "Cervical fracture, halo for this patient", "Cord compression, surgery for this patient", "Meningitis, antibiotics for this patient", "Cervical dislocation, traction for this patient"], "ans": 0, "exp": "Whiplash-associated disorder: soft tissue (cervical) strain จาก acceleration-deceleration (rear-end) → ปวด/ตึงคอ (มักแย่ขึ้น 1-2 วัน), ปวดศีรษะ; imaging ปกติ. รักษา: analgesia, 'early mobilization/exercise' (ดีกว่า immobilization/collar นาน), reassurance. ส่วนใหญ่หายเอง. ต้อง exclude fracture ก่อน (rules/imaging)."}, {"topic": "Orthopedics", "q": "A child has a completely displaced distal radius fracture. Compared with adults, what is a key difference in management?", "choices": ["Heals more slowly than adults for this patient", "Greater remodeling potential allows some residual deformity", "Never needs reduction for this patient", "Always needs plating for this patient", "Cannot be casted for this patient"], "ans": 1, "exp": "Fractures ในเด็กมี 'remodeling potential สูง' (โดยเฉพาะใกล้ physis, angulation ในระนาบการเคลื่อนไหวของข้อ) → ยอมรับ residual angulation ได้มากกว่าผู้ใหญ่ และหายเร็วกว่า. รักษาส่วนใหญ่ closed reduction + cast. หลีกเลี่ยงรบกวน growth plate. Rotational deformity ไม่ remodel."}, {"topic": "Orthopedics", "q": "A patient after major trauma has flaccid paralysis and areflexia below the level of a spinal cord injury in the acute phase. What is this transient state called?", "choices": ["Neurogenic shock", "Cauda equina syndrome", "Spinal shock", "Central cord syndrome", "Brown-Sequard syndrome"], "ans": 2, "exp": "Spinal shock: ภาวะชั่วคราวหลัง spinal cord injury เฉียบพลัน — flaccid paralysis + areflexia + ไม่มี sensation ใต้ระดับ (reflex arc หยุดทำงานชั่วคราว). การกลับมาของ 'bulbocavernosus reflex' บ่งชี้สิ้นสุด spinal shock (แล้วจึงประเมิน deficit ที่แท้จริง). ต่างจาก neurogenic shock (hemodynamic - hypotension/bradycardia)."}, {"topic": "Orthopedics", "q": "A patient has an amputated fingertip/digit brought in on ice. What is a key principle for transport of the amputated part for possible replantation?", "choices": ["Freeze it solid for this patient", "Place directly on dry ice for this patient", "Immerse in warm water for this patient", "Wrap in saline gauze, seal in a bag, place on ice (not direct)", "Discard it for this patient"], "ans": 3, "exp": "การเก็บ amputated part เพื่อ replantation: ห่อด้วย 'saline-moistened gauze', ใส่ถุงกันน้ำ, แล้ววางบน ice (ไม่สัมผัสน้ำแข็ง/dry ice โดยตรง - เสี่ยง frostbite). ไม่แช่น้ำหรือแช่แข็ง. Replantation พิจารณาใน thumb, multiple digits, เด็ก, ระดับ palm/proximal. Warm ischemia time สำคัญ."}, {"topic": "Orthopedics", "q": "A patient has an untreated developmental dysplasia of the hip diagnosed late in childhood with a dislocated hip. What is a consequence of late/untreated DDH?", "choices": ["No long-term effect for this patient", "Spontaneous full recovery for this patient", "Bone tumor for this patient", "Osteomyelitis for this patient", "Early osteoarthritis and limb length discrepancy"], "ans": 4, "exp": "DDH ที่ไม่รักษา/รักษาช้า → acetabular dysplasia, hip dislocation ต่อเนื่อง → 'early degenerative osteoarthritis', limb length discrepancy, กะเผลก (Trendelenburg gait). จึงเน้นคัดกรอง/รักษาแต่เนิ่น (Pavlik <6 เดือน). ช้า → closed/open reduction + osteotomy ตามอายุ. ยิ่งช้ายิ่งผลลัพธ์แย่."}]}, {"id": "surg4", "title": "Surgery ชุดที่ 4 — Neurosurgery, Cardiothoracic & Vascular Surgery", "subject": "surg", "questions": [{"topic": "Neuro/CVT/Vascular", "q": "A young man is hit on the temple, briefly loses consciousness, then has a 'lucid interval' before deteriorating. CT shows a biconvex (lens-shaped) hyperdensity. What is the diagnosis?", "choices": ["Epidural hematoma", "Subdural hematoma", "Subarachnoid hemorrhage", "Diffuse axonal injury", "Cerebral contusion"], "ans": 0, "exp": "Epidural (extradural) hematoma: มัก 'middle meningeal artery' (temporal bone fracture) → 'lucid interval' แล้วทรุด. CT: 'biconvex/lens-shaped' (ไม่ข้าม suture line). เป็น neurosurgical emergency → craniotomy evacuation. พยากรณ์ดีถ้ารักษาเร็ว (ก่อน herniation)."}, {"topic": "Neuro/CVT/Vascular", "q": "An elderly man on anticoagulants has gradual confusion and headache weeks after a minor fall. CT shows a crescent-shaped hyperdensity crossing suture lines. What is the diagnosis?", "choices": ["Subarachnoid hemorrhage", "Subdural hematoma", "Epidural hematoma", "Intracerebral hemorrhage", "Brain tumor"], "ans": 1, "exp": "Subdural hematoma: จาก 'bridging veins' tear — พบในผู้สูงอายุ/anticoagulant/alcoholic (brain atrophy), มักหลัง minor trauma, อาการค่อยเป็นค่อยไป. CT: 'crescent-shaped' (concave), ข้าม suture line ได้ (แต่ไม่ข้าม midline/dural reflection). Acute (hyperdense) vs chronic (hypodense). รักษา: evacuation ถ้ามีอาการ/large."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a sudden severe 'thunderclap' headache ('worst of my life') with neck stiffness. CT shows blood in the basal cisterns. What is the diagnosis?", "choices": ["Epidural hematoma", "Migraine", "Subarachnoid hemorrhage", "Meningitis", "Tension headache"], "ans": 2, "exp": "Subarachnoid hemorrhage (มักจาก 'ruptured berry aneurysm'): 'thunderclap headache' (รุนแรงเฉียบพลันสุดในชีวิต) + meningism + อาจ LOC. CT (blood ใน basal cisterns); ถ้า CT ปกติแต่สงสัย → LP (xanthochromia). หา aneurysm (CTA) → coiling/clipping. ภาวะแทรกซ้อน: rebleed, vasospasm, hydrocephalus."}, {"topic": "Neuro/CVT/Vascular", "q": "A trauma patient with a GCS of 6 is deteriorating with a blown (dilated, fixed) pupil on one side. What does this indicate?", "choices": ["Simple concussion in this case", "Migraine for this patient", "Bell palsy for this patient", "Uncal (transtentorial) herniation", "Horner syndrome as first step"], "ans": 3, "exp": "Unilateral fixed/dilated pupil + ทรุดลง = 'uncal herniation' กด CN III (parasympathetic) และ midbrain → เป็น neurosurgical emergency. จัดการ raised ICP: head up 30°, controlled ventilation, hyperosmolar (mannitol/hypertonic saline), และ 'urgent CT + neurosurgery' (evacuate mass). Cushing triad (HT, bradycardia, irregular breathing) = สัญญาณสาย."}, {"topic": "Neuro/CVT/Vascular", "q": "A head injury patient has raised intracranial pressure. Which triad of signs indicates impending herniation (Cushing reflex)?", "choices": ["Hypotension, tachycardia, fever", "Hypertension, tachycardia, tachypnea", "Hypotension, bradycardia, apnea", "Fever, neck stiffness, rash", "Hypertension, bradycardia, irregular respiration"], "ans": 4, "exp": "Cushing reflex/triad (สัญญาณ raised ICP รุนแรง/impending herniation): 'hypertension (widened pulse pressure) + bradycardia + irregular respiration'. เป็นสัญญาณสาย — ต้องลด ICP ด่วน. หลักการ ICP: keep CPP (=MAP-ICP), หลีกเลี่ยง hypoxia/hypercarbia/hypotension (secondary injury)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has clear fluid draining from the nose after a basilar skull fracture, with periorbital bruising ('raccoon eyes'). What is this fluid?", "choices": ["CSF rhinorrhea", "Saliva", "Nasal mucus", "Blood only", "Lymph"], "ans": 0, "exp": "Basilar skull fracture: 'raccoon eyes' (periorbital ecchymosis), Battle sign (mastoid), hemotympanum, และ 'CSF leak' (rhinorrhea/otorrhea - ตรวจ 'halo/ring sign' หรือ beta-2 transferrin). เสี่ยง meningitis. ส่วนใหญ่ CSF leak หายเอง (bed rest, head up); persistent → repair. หลีกเลี่ยงใส่ NG ทางจมูก (risk intracranial)."}, {"topic": "Neuro/CVT/Vascular", "q": "A middle-aged woman has progressive headache, seizures, and a dural-based, well-circumscribed extra-axial mass that enhances homogeneously on MRI. What is the most likely diagnosis?", "choices": ["Glioblastoma", "Meningioma", "Metastasis", "Acoustic neuroma", "Pituitary adenoma"], "ans": 1, "exp": "Meningioma: benign extra-axial tumor จาก arachnoid cap cells — 'dural-based, well-circumscribed, homogeneous enhancement, dural tail', พบในหญิงวัยกลางคน. ส่วนใหญ่โตช้า. รักษา: สังเกต (เล็ก/ไม่มีอาการ) หรือ surgical resection ± RT. ต่างจาก glioblastoma (intra-axial, infiltrative, ring-enhancing, พยากรณ์แย่)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with lung cancer develops headache, vomiting, and papilledema; MRI shows multiple ring-enhancing lesions at the gray-white junction. What is the most likely diagnosis?", "choices": ["Brain abscess", "Primary glioma", "Brain metastases", "Meningioma", "Multiple sclerosis"], "ans": 2, "exp": "Brain metastases: มะเร็งที่แพร่ไปสมองบ่อย (lung, breast, melanoma, renal, GI) — 'multiple lesions ที่ gray-white junction', ring-enhancing + edema. เป็นสาเหตุ brain tumor ในผู้ใหญ่ที่พบบ่อยกว่า primary. รักษา: steroid (edema), surgery/SRS/WBRT + รักษามะเร็งต้นเหตุ. แยกจาก abscess (ประวัติติดเชื้อ, DWI restriction)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has bitemporal hemianopia, headache, and hormonal disturbance. MRI shows a sellar/suprasellar mass. What is the diagnosis?", "choices": ["Acoustic neuroma", "Meningioma", "Craniopharyngioma only", "Pituitary adenoma", "Glioma"], "ans": 3, "exp": "Pituitary adenoma: sellar mass กด optic chiasm → 'bitemporal hemianopia' + hormonal (prolactinoma - galactorrhea/amenorrhea; acromegaly - GH; Cushing - ACTH; หรือ hypopituitarism). วินิจฉัย MRI + hormone panel. รักษา: prolactinoma → dopamine agonist; อื่นๆ/กดเบียด → transsphenoidal surgery. Pituitary apoplexy = ฉุกเฉิน."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has progressive unilateral hearing loss, tinnitus, and imbalance; MRI shows a mass at the cerebellopontine angle. What is the diagnosis?", "choices": ["Glioma for this patient", "Meningioma for this patient", "Pituitary adenoma for this patient", "Metastasis for this patient", "Acoustic neuroma (vestibular schwannoma)"], "ans": 4, "exp": "Acoustic neuroma (vestibular schwannoma): เนื้องอกจาก CN VIII ที่ cerebellopontine angle → progressive sensorineural hearing loss, tinnitus, imbalance; ใหญ่ขึ้นกด CN V/VII, brainstem. Bilateral สัมพันธ์ NF2. รักษา: สังเกต, SRS, หรือ microsurgery. MRI internal auditory canal."}, {"topic": "Neuro/CVT/Vascular", "q": "An elderly patient has the triad of gait disturbance, urinary incontinence, and dementia; CT shows enlarged ventricles out of proportion to atrophy. What is the diagnosis?", "choices": ["Normal pressure hydrocephalus", "Parkinson disease", "Alzheimer disease", "Brain tumor", "Chronic subdural hematoma"], "ans": 0, "exp": "Normal pressure hydrocephalus (NPH): triad 'wet, wacky, wobbly' (urinary incontinence + dementia + gait apraxia - 'magnetic gait'), ventriculomegaly ไม่สมกับ atrophy. เป็นสาเหตุ dementia ที่ 'รักษาได้' → ตอบสนอง 'VP shunt' (large-volume LP tap test ทำนายการตอบสนอง). Gait มักดีขึ้นชัดสุด."}, {"topic": "Neuro/CVT/Vascular", "q": "A child has an obstructing posterior fossa tumor causing hydrocephalus with headache, vomiting, and papilledema. What is the mechanism of hydrocephalus?", "choices": ["Meningitis only", "Obstruction of CSF flow", "Overproduction of CSF only", "Cerebral atrophy", "Normal variant"], "ans": 1, "exp": "Obstructive (non-communicating) hydrocephalus: การอุดกั้นการไหลของ CSF (เช่น posterior fossa tumor กด 4th ventricle/aqueduct) → CSF คั่งเหนือจุดอุดตัน → raised ICP (headache, vomiting, papilledema, ในทารก head circumference โต/sunset eyes). รักษา: แก้สาเหตุ (resect tumor) + CSF diversion (EVD/VP shunt/ETV)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a spinal cord injury with ipsilateral motor loss and proprioception loss, and contralateral pain/temperature loss below the lesion. What syndrome is this?", "choices": ["Cauda equina syndrome", "Central cord syndrome", "Brown-Sequard syndrome", "Anterior cord syndrome", "Complete transection"], "ans": 2, "exp": "Brown-Sequard syndrome (hemisection ของ cord): 'ipsilateral' motor (corticospinal) + proprioception/vibration (dorsal column) loss + 'contralateral' pain/temperature loss (spinothalamic, cross แล้ว) ใต้ระดับ. มักจาก penetrating trauma. พยากรณ์ค่อนข้างดีในการฟื้น."}, {"topic": "Neuro/CVT/Vascular", "q": "An elderly patient with cervical spondylosis has a hyperextension neck injury; he has weakness worse in the upper limbs than lower limbs. What syndrome is this?", "choices": ["Posterior cord syndrome", "Anterior cord syndrome", "Brown-Sequard syndrome", "Central cord syndrome", "Complete injury"], "ans": 3, "exp": "Central cord syndrome (พบบ่อยสุดใน incomplete cord injury): มักจาก hyperextension ในผู้สูงอายุที่มี cervical spondylosis → 'แขนอ่อนแรงมากกว่าขา' (upper limb fibers อยู่กลาง/medial), ± sensory/bladder. รักษา: ส่วนใหญ่ conservative + rehab; decompression ในรายที่มี compression/ไม่ดีขึ้น. พยากรณ์ฟื้นตัวได้บ้าง."}, {"topic": "Neuro/CVT/Vascular", "q": "A neonate has a lumbar sac protruding from the back containing neural tissue, with lower limb weakness. What is the diagnosis?", "choices": ["Meningocele", "Spina bifida occulta", "Encephalocele", "Sacrococcygeal teratoma", "Myelomeningocele"], "ans": 4, "exp": "Myelomeningocele (open neural tube defect): ถุงยื่นออกมามี 'neural tissue' (spinal cord/nerve roots) → neurologic deficit (ขาอ่อนแรง, bladder/bowel), มัก hydrocephalus/Chiari II. ป้องกันด้วย folic acid. รักษา: ผ่าตัดปิดเร็ว (ลดติดเชื้อ) + จัดการ hydrocephalus. ต่างจาก meningocele (มีแค่ meninges/CSF, มัก neuro ปกติ)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with a middle ear infection develops fever, headache, and a ring-enhancing lesion with central restricted diffusion on MRI. What is the diagnosis?", "choices": ["Brain abscess", "Glioblastoma", "Metastasis", "Meningioma", "Infarct"], "ans": 0, "exp": "Brain abscess: มักจากการลุกลามของการติดเชื้อข้างเคียง (otitis/sinusitis/mastoiditis), hematogenous (endocarditis, cyanotic heart), หรือ penetrating. MRI: ring-enhancing + 'central restricted diffusion (DWI)' (แยกจาก tumor). รักษา: antibiotic + aspiration/excision (ถ้าใหญ่/มีอาการ) + แก้แหล่งติดเชื้อ."}, {"topic": "Neuro/CVT/Vascular", "q": "A 55-year-old man has sudden severe tearing chest pain radiating to the back; CT shows an intimal flap in the ascending aorta. What is the diagnosis and management?", "choices": ["Myocardial infarction, PCI for this patient", "Stanford type A aortic dissection, emergency surgery", "Type B dissection, medical only", "Pulmonary embolism, thrombolysis for this patient", "Pericarditis, NSAIDs for this patient"], "ans": 1, "exp": "Aortic dissection: ปวดอกฉีกขาด (tearing) ร้าวหลัง, BP ต่างสองแขน, widened mediastinum. Stanford 'A' (involves ascending aorta) = 'surgical emergency' (เสี่ยง tamponade, aortic regurgitation, coronary/stroke). Stanford 'B' (descending เท่านั้น) = medical (impulse control: beta-blocker คุม HR/BP) เว้นมี complication. คุม BP/HR ทันที."}, {"topic": "Neuro/CVT/Vascular", "q": "A 70-year-old man has a pulsatile abdominal mass; ultrasound shows a 6 cm abdominal aortic aneurysm. He is asymptomatic. What is the management?", "choices": ["Immediate rupture repair", "Observation indefinitely", "Elective surgical/endovascular repair", "Anticoagulation only", "Antibiotics"], "ans": 2, "exp": "Abdominal aortic aneurysm (AAA): asymptomatic → 'elective repair' เมื่อ diameter ≥5.5 cm (ชาย), โตเร็ว (>0.5 cm/6 เดือน), หรือมีอาการ — ด้วย open หรือ EVAR. <5.5 cm → surveillance (US). Ruptured AAA (ปวดท้อง/หลัง + hypotension + pulsatile mass) = emergency repair. คัดกรอง US ในชายสูงอายุที่สูบบุหรี่."}, {"topic": "Neuro/CVT/Vascular", "q": "A 65-year-old smoker has calf pain on walking that resolves with rest (intermittent claudication) and an ankle-brachial index of 0.6. What is the diagnosis?", "choices": ["Deep vein thrombosis", "Spinal stenosis", "Venous insufficiency", "Peripheral arterial disease", "Compartment syndrome"], "ans": 3, "exp": "Peripheral arterial disease (PAD): intermittent claudication (ปวดน่องเมื่อเดิน หายเมื่อพัก), pulses ลด, ABI <0.9 (0.4-0.9 = claudication). ปัจจัยเสี่ยง: บุหรี่, DM, HT, dyslipidemia. รักษา: 'risk factor modification + supervised exercise + antiplatelet + statin'; critical limb ischemia → revascularization. เลิกบุหรี่สำคัญสุด."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient presents with a sudden, cold, pale, painful, pulseless leg. What are the classic '6 Ps', and what is the management priority?", "choices": ["Chronic PAD, observe for this patient", "DVT, anticoagulate only", "Cellulitis, antibiotics for this patient", "Compartment syndrome, elevate for this patient", "Acute limb ischemia, urgent revascularization and heparin"], "ans": 4, "exp": "Acute limb ischemia (6 Ps: Pain, Pallor, Pulselessness, Paresthesia, Paralysis, Poikilothermia/Perishingly cold): จาก embolism (AF, mural thrombus) หรือ thrombosis. เป็น emergency → 'IV heparin ทันที + urgent revascularization' (embolectomy/thrombolysis/bypass). Paralysis/paresthesia = สัญญาณ threatened limb. Time = limb. เฝ้าระวัง reperfusion/compartment syndrome."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a transient episode of unilateral arm/leg weakness that resolved in 30 minutes; carotid Doppler shows 80% stenosis on the symptomatic side. What is the appropriate management?", "choices": ["Carotid endarterectomy plus medical therapy", "Immediate thrombolysis for this patient", "No treatment for this patient", "Anticoagulation only", "Observation only"], "ans": 0, "exp": "Symptomatic carotid stenosis (TIA/minor stroke) ที่ stenosis 70-99% → 'carotid endarterectomy' (CEA) + best medical therapy (antiplatelet, statin, risk factor) ลดความเสี่ยง stroke, ทำเร็ว (ภายใน ~2 สัปดาห์). Asymptomatic รักษา medical เป็นหลัก. Carotid stenting เป็นทางเลือกในบางราย."}, {"topic": "Neuro/CVT/Vascular", "q": "A postoperative patient develops a swollen, tender, warm calf with a positive Homan sign. Doppler confirms a deep vein thrombosis. What is the treatment?", "choices": ["Antibiotics", "Anticoagulation", "Compression only", "Immediate surgery", "Elevation only"], "ans": 1, "exp": "Deep vein thrombosis (DVT): ขาบวมข้างเดียว ปวด warmth. ยืนยัน compression ultrasound (Wells score guide). รักษา: 'anticoagulation' (LMWH → DOAC/warfarin, หรือ DOAC ตั้งแต่แรก). เฝ้าระวัง pulmonary embolism. Massive iliofemoral/phlegmasia → พิจารณา thrombolysis/thrombectomy. ป้องกัน post-thrombotic syndrome."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient collapses with sudden dyspnea, pleuritic chest pain, and hypoxia after a long flight; CT pulmonary angiography confirms pulmonary embolism. If hemodynamically unstable, what is indicated?", "choices": ["Observation", "Anticoagulation only", "Thrombolysis", "Antibiotics", "Diuretics"], "ans": 2, "exp": "Pulmonary embolism (PE): dyspnea + pleuritic pain + hypoxia + tachycardia (± RV strain). ยืนยัน CTPA. 'Hemodynamically unstable (massive PE)' → 'systemic thrombolysis' (หรือ embolectomy ถ้าห้าม lysis). Stable → anticoagulation. Wells/PERC + D-dimer guide. ป้องกันด้วย VTE prophylaxis."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has varicose veins with a healed ulcer over the medial malleolus and hemosiderin skin staining. What is the underlying cause?", "choices": ["Arterial insufficiency", "Diabetic neuropathy", "Lymphedema", "Chronic venous insufficiency", "Vasculitis"], "ans": 3, "exp": "Chronic venous insufficiency: varicose veins, edema, hemosiderin (brown) staining, lipodermatosclerosis, และ 'venous ulcer ที่ medial malleolus (gaiter area)'. รักษา: compression therapy (mainstay), wound care, leg elevation; venous ablation. ต่างจาก arterial ulcer (ปลายนิ้ว/pressure point, punched-out, ปวด, pulses ลด)."}, {"topic": "Neuro/CVT/Vascular", "q": "A 60-year-old man has a lung mass; biopsy shows non-small cell carcinoma. A tumor at the apex causes shoulder/arm pain and Horner syndrome. What is this called?", "choices": ["SVC syndrome", "Mesothelioma", "Carcinoid", "Metastasis", "Pancoast tumor"], "ans": 4, "exp": "Pancoast (superior sulcus) tumor: มะเร็งปอดที่ยอดปอด ลุกลาม brachial plexus (C8-T1 - ปวด/อ่อนแรงแขนด้าน ulnar), sympathetic chain (Horner: ptosis, miosis, anhidrosis), ± bone. มัก NSCLC. วินิจฉัย/รักษาซับซ้อน (neoadjuvant chemoRT + surgery). ต่างจาก SVC syndrome (facial/arm swelling, distended veins)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with a right hilar lung mass develops facial swelling, distended neck/chest veins, and headache. What is the diagnosis?", "choices": ["Superior vena cava syndrome", "Pulmonary embolism", "Pancoast tumor", "Cardiac tamponade", "Pneumothorax"], "ans": 0, "exp": "Superior vena cava (SVC) syndrome: การอุดกั้น SVC (มักจาก lung cancer - โดยเฉพาะ small cell, lymphoma) → บวมหน้า/คอ/แขน, distended veins, headache, plethora, dyspnea. วินิจฉัย CT. รักษา: จัดการมะเร็ง (chemo/RT), stent ในรายรุนแรง, steroid/diuretic เสริม. ยกศีรษะสูง."}, {"topic": "Neuro/CVT/Vascular", "q": "A tall thin young man has sudden pleuritic chest pain and dyspnea; chest X-ray shows a small primary spontaneous pneumothorax without tension. What is the management for a small, stable pneumothorax?", "choices": ["Antibiotics", "Observation/oxygen or aspiration", "Immediate chest tube always", "Emergency thoracotomy", "Pleurodesis first-line"], "ans": 1, "exp": "Primary spontaneous pneumothorax (tall thin young men, สูบบุหรี่, จาก apical bleb rupture): small + stable → 'observation ± oxygen หรือ needle aspiration'. Large/symptomatic → chest tube. Recurrent/persistent air leak → VATS + pleurodesis/bullectomy. Tension pneumothorax = needle decompression ทันที (คนละภาวะ)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with pneumonia develops a loculated, purulent pleural effusion (empyema). What is the definitive management if the fluid is thick/loculated?", "choices": ["Diuretics for this patient", "Oral antibiotics alone", "Chest tube drainage (and possibly surgery/decortication)", "Observation for this patient", "Repeated aspiration only"], "ans": 2, "exp": "Empyema (pus ใน pleural space, มักจาก pneumonia): pleural fluid pH <7.2/glucose ต่ำ/pus/organisms → ต้อง 'chest tube drainage' + IV antibiotics; loculated/ล้มเหลว → intrapleural fibrinolytics หรือ 'VATS/decortication'. Simple parapneumonic effusion อาจหายด้วยยาปฏิชีวนะ. Stage (exudative→fibrinopurulent→organizing)."}, {"topic": "Neuro/CVT/Vascular", "q": "A child has a harsh pansystolic murmur at the left sternal border; echocardiography shows a ventricular septal defect. Which is true about a small VSD?", "choices": ["Requires transplantation", "Always needs urgent surgery", "Causes cyanosis at birth", "Many close spontaneously", "Is untreatable"], "ans": 3, "exp": "Ventricular septal defect (VSD, congenital heart lesion ที่พบบ่อยสุด): pansystolic murmur ที่ LLSB. Small VSD 'มักปิดเอง' และ asymptomatic. Large VSD → left-to-right shunt → heart failure/pulmonary HT → ผ่าตัดปิด (ป้องกัน Eisenmenger). ไม่ทำให้เขียวแรกเกิด (acyanotic) จนกว่าจะ shunt reversal."}, {"topic": "Neuro/CVT/Vascular", "q": "A cyanotic infant has a boot-shaped heart on X-ray, and 'tet spells' relieved by squatting. Which four features make up this condition?", "choices": ["Atrial septal defect for this patient", "Transposition of great arteries for this patient", "Coarctation of aorta for this patient", "Patent ductus arteriosus for this patient", "Tetralogy of Fallot (VSD, PS, overriding aorta, RVH)"], "ans": 4, "exp": "Tetralogy of Fallot (cyanotic CHD ที่พบบ่อยสุดหลังวัยทารก): VSD + Pulmonary stenosis (RVOT obstruction) + Overriding aorta + Right ventricular hypertrophy → 'boot-shaped heart'. 'Tet spells' (cyanotic, ดีขึ้นเมื่อ squat/knee-chest → เพิ่ม SVR ลด shunt). รักษา: ผ่าตัดซ่อม; spell → knee-chest, O2, morphine, fluid, beta-blocker."}, {"topic": "Neuro/CVT/Vascular", "q": "A 68-year-old man has exertional syncope, angina, and dyspnea with an ejection systolic murmur radiating to the carotids and a slow-rising pulse. What valvular lesion is this?", "choices": ["Aortic stenosis", "Aortic regurgitation", "Mitral regurgitation", "Mitral stenosis", "Tricuspid stenosis"], "ans": 0, "exp": "Aortic stenosis: triad 'syncope, angina, dyspnea (heart failure)' (exertional), ejection systolic murmur ที่ RUSB ร้าวไป carotids, slow-rising pulse (pulsus parvus et tardus), soft S2. สาเหตุ: calcific (สูงอายุ), bicuspid. Symptomatic severe AS → 'aortic valve replacement (SAVR/TAVI)' (พยากรณ์แย่ถ้าไม่ผ่าตัด). หลีกเลี่ยง vasodilator."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a history of rheumatic fever and now has a mid-diastolic murmur with a loud S1 and atrial fibrillation. What valvular lesion is this?", "choices": ["Pulmonary stenosis", "Mitral stenosis", "Aortic stenosis", "Mitral regurgitation", "Aortic regurgitation"], "ans": 1, "exp": "Mitral stenosis (มักจาก 'rheumatic heart disease'): mid-diastolic rumbling murmur ที่ apex (นอนตะแคงซ้าย) + loud S1 + opening snap. ภาวะแทรกซ้อน: atrial fibrillation (LA โต), left atrial thrombus/emboli, pulmonary HT, hemoptysis. รักษา: rate control/anticoagulation (AF), 'balloon valvuloplasty' หรือ valve replacement."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a soft, diastolic decrescendo murmur, wide pulse pressure, and a collapsing (water-hammer) pulse. What valvular lesion is this?", "choices": ["Mitral stenosis", "Aortic stenosis", "Aortic regurgitation", "Mitral regurgitation", "Tricuspid regurgitation"], "ans": 2, "exp": "Aortic regurgitation: early diastolic decrescendo murmur ที่ LSB (นั่งโน้มไปหน้า/หายใจออก), 'wide pulse pressure', 'collapsing/water-hammer pulse', Corrigan/Quincke/de Musset signs. สาเหตุ: bicuspid, rheumatic, endocarditis, aortic root dilation (Marfan, dissection). Severe symptomatic/LV dysfunction → valve replacement."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with infective endocarditis on a native valve develops heart failure from valve destruction despite antibiotics. What is an indication for surgery?", "choices": ["Small vegetation", "Fever alone", "Positive blood culture alone", "Heart failure from valve dysfunction", "Single embolic event resolved"], "ans": 3, "exp": "Infective endocarditis — ข้อบ่งชี้ผ่าตัด (นอกเหนือยาปฏิชีวนะ): 'heart failure จาก severe valve regurgitation/destruction', uncontrolled infection (abscess, persistent bacteremia, fungal/resistant), recurrent emboli หรือ large mobile vegetation (>10 mm). Surgery ซ่อม/เปลี่ยนลิ้น. Duke criteria วินิจฉัย."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with coronary artery disease has left main stenosis and triple-vessel disease with reduced ejection fraction. What is the recommended revascularization?", "choices": ["Medical therapy only", "Single stent for this patient", "No treatment for this patient", "Valve replacement initially", "Coronary artery bypass grafting"], "ans": 4, "exp": "CABG ได้ประโยชน์เหนือ PCI ใน: 'left main disease, triple-vessel (โดยเฉพาะ + DM หรือ LV dysfunction), complex/diffuse disease (high SYNTAX score)'. ใช้ LIMA to LAD (patency ดี) ± vein/radial grafts. ประเมินโดย heart team. Single/simple lesion → PCI."}, {"topic": "Neuro/CVT/Vascular", "q": "A young athlete collapses; echocardiography shows asymmetric septal hypertrophy with LVOT obstruction. What is the diagnosis?", "choices": ["Hypertrophic cardiomyopathy", "Aortic stenosis", "Dilated cardiomyopathy", "Myocarditis", "Pericarditis"], "ans": 0, "exp": "Hypertrophic cardiomyopathy (HCM): asymmetric septal hypertrophy → LVOT obstruction (murmur เพิ่มเมื่อ preload ลด - Valsalva/standing), เป็นสาเหตุ 'sudden cardiac death ในนักกีฬาหนุ่ม'. รักษา: beta-blocker, หลีกเลี่ยงกีฬาหนัก/dehydration, ICD ในกลุ่มเสี่ยง, septal myectomy/alcohol ablation. ตรงข้ามกับ AS (murmur ลดเมื่อ Valsalva)."}, {"topic": "Neuro/CVT/Vascular", "q": "A 60-year-old smoker has a solitary 2.5 cm spiculated lung nodule with an increasing size on serial CT. What is the appropriate next step?", "choices": ["Ignore it for this patient", "Biopsy/resection for tissue diagnosis", "Repeat CT in 2 years as first step", "Antibiotics for this patient", "Observation only"], "ans": 1, "exp": "Solitary pulmonary nodule ที่มีลักษณะ 'high-risk' (ขนาด >8 mm-2 cm, spiculated, โตขึ้น, upper lobe, ผู้สูบบุหรี่/อายุมาก) → ต้องได้ tissue diagnosis (PET-CT staging + biopsy/CT-guided/bronchoscopy หรือ surgical resection). Low-risk small nodule → surveillance CT (Fleischner criteria). โตขึ้นบ่งชี้มะเร็ง."}, {"topic": "Neuro/CVT/Vascular", "q": "A lung cancer patient has hyponatremia (SIADH) and Cushing-like features. Which lung cancer type is most associated with paraneoplastic syndromes?", "choices": ["Carcinoid", "Squamous cell carcinoma", "Small cell lung carcinoma", "Adenocarcinoma", "Large cell carcinoma"], "ans": 2, "exp": "Small cell lung carcinoma (central, สัมพันธ์บุหรี่มากสุด, แพร่เร็ว): paraneoplastic เด่น — 'SIADH (hyponatremia)', ectopic ACTH (Cushing), Lambert-Eaton myasthenic syndrome. รักษาหลักคือ chemo/RT (ไม่ค่อยผ่าตัด เพราะมัก extensive). Squamous → hypercalcemia (PTHrP), central, cavitation."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has an anterior mediastinal mass and muscle weakness that worsens with activity (myasthenia gravis). Which tumor is associated?", "choices": ["Teratoma", "Lymphoma", "Neurogenic tumor", "Thymoma", "Thyroid goiter"], "ans": 3, "exp": "Anterior mediastinal masses '4 Ts': Thymoma/Thymic, Teratoma (germ cell), Terrible lymphoma, Thyroid (retrosternal). 'Thymoma' สัมพันธ์กับ 'myasthenia gravis' (anti-AChR), pure red cell aplasia, hypogammaglobulinemia. รักษา thymoma: resection (thymectomy) ± RT; thymectomy ช่วย MG. Posterior mediastinum → neurogenic tumors."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with a history of asbestos exposure has pleural thickening and a pleural effusion; biopsy shows malignant mesothelioma. What is the key exposure?", "choices": ["Radon only", "Silica", "Coal dust", "Tobacco only", "Asbestos"], "ans": 4, "exp": "Malignant pleural mesothelioma: สัมพันธ์อย่างมากกับ 'asbestos exposure' (latency นานหลายสิบปี) — pleural thickening/effusion, ปวดอก, dyspnea. พยากรณ์แย่. Asbestos ยังเพิ่ม lung cancer (เสริมฤทธิ์บุหรี่). วินิจฉัย pleural biopsy. รักษาส่วนใหญ่ palliative (multimodal ในบางราย)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has massive hemoptysis (>500 mL/24h) and is at risk of asphyxiation. What is the immediate priority?", "choices": ["Airway protection and position bleeding side down", "Immediate lobectomy for this patient", "Oral tranexamic acid only", "Discharge home for this patient", "CT then wait for this patient"], "ans": 0, "exp": "Massive hemoptysis: อันตรายหลักคือ 'asphyxiation' (ไม่ใช่ exsanguination) → ป้องกัน airway: 'ให้ผู้ป่วยนอนตะแคงข้างที่เลือดออกลง' (ป้องกันสำลักเข้าปอดดี), intubate (± protect good lung), resuscitate. หาตำแหน่ง (bronchoscopy/CTA) → 'bronchial artery embolization' (first-line) หรือ surgery. สาเหตุ: TB, bronchiectasis, cancer."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a chest tube for a pneumothorax with continuous bubbling in the water-seal chamber. What does persistent bubbling indicate?", "choices": ["Normal function", "Ongoing air leak", "Tube blockage", "Full lung re-expansion", "Infection"], "ans": 1, "exp": "Chest tube: bubbling ใน water-seal chamber = 'air leak' (จาก pleural space หรือ system). Bubbling ที่หายไปเมื่อหายใจปกติ + ปอดขยาย = ปกติ. 'Continuous/persistent bubbling' = ongoing air leak (จากปอด - bronchopleural fistula) หรือรอยรั่วในระบบ/รอบท่อ. Tidaling (swing) = ท่อทำงาน; ไม่ swing = อุดตัน/ปอดขยายเต็ม."}, {"topic": "Neuro/CVT/Vascular", "q": "A 40-year-old male smoker has painful ischemia of the fingers and toes with superficial thrombophlebitis; angiography shows 'corkscrew' collaterals. What is the diagnosis?", "choices": ["Atherosclerotic PAD for this patient", "Raynaud phenomenon for this patient", "Thromboangiitis obliterans (Buerger disease)", "Vasculitis (GCA) for this patient", "Diabetic angiopathy for this patient"], "ans": 2, "exp": "Thromboangiitis obliterans (Buerger disease): ชายหนุ่มสูบบุหรี่จัด → ischemia ปลายนิ้ว/นิ้วเท้า (rest pain, ulcer, gangrene), migratory superficial thrombophlebitis, Raynaud. Angiography: 'corkscrew collaterals'. รักษาที่สำคัญสุดคือ 'เลิกบุหรี่เด็ดขาด' (มิฉะนั้นลุกลาม/ตัดนิ้ว). ไม่ใช่ atherosclerosis."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient needs long-term hemodialysis. What is the preferred permanent vascular access?", "choices": ["Central venous catheter", "Peripheral IV", "AV graft only", "Arteriovenous fistula", "Peritoneal only"], "ans": 3, "exp": "Arteriovenous fistula (AVF, เช่น radiocephalic/brachiocephalic) เป็น 'access ที่ดีที่สุด' สำหรับ hemodialysis ระยะยาว (patency นาน, ติดเชื้อน้อยกว่า graft/catheter). ต้องเวลา 'maturation' 6-8 สัปดาห์. AV graft ใช้เมื่อ vein ไม่ดี; central catheter ใช้ชั่วคราว (ติดเชื้อ/thrombosis สูง). 'Fistula first'."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a lower limb that is chronically swollen with non-pitting edema and skin thickening after lymph node dissection. What is the diagnosis?", "choices": ["Deep vein thrombosis", "Chronic venous insufficiency", "Cardiac failure", "Cellulitis", "Lymphedema"], "ans": 4, "exp": "Lymphedema: การคั่งของ lymph จากการอุดตัน/ทำลาย lymphatics — บวม 'non-pitting' (ระยะหลัง), skin thickening/fibrosis, 'positive Stemmer sign' (หยิบผิวโคนนิ้วไม่ขึ้น). Secondary: หลัง node dissection/RT (มะเร็ง), filariasis. รักษา: complex decongestive therapy (compression, MLD, exercise, skin care); ไม่มี diuretic ช่วย."}, {"topic": "Neuro/CVT/Vascular", "q": "A young woman has episodic color changes of the fingers (white to blue to red) triggered by cold or stress, without tissue loss. What is the diagnosis?", "choices": ["Primary Raynaud phenomenon", "Cellulitis", "Buerger disease", "Acute limb ischemia", "Frostbite"], "ans": 0, "exp": "Raynaud phenomenon: vasospasm ของนิ้วเมื่อเย็น/เครียด → เปลี่ยนสี 'white (ischemia) → blue (cyanosis) → red (reperfusion)'. Primary (idiopathic, หญิงสาว, สองข้าง, ไม่มี tissue loss) vs secondary (สัมพันธ์ connective tissue disease - scleroderma/SLE, มี ulcer/asymmetry). รักษา: หลีกเลี่ยงเย็น/บุหรี่, calcium channel blocker. หา secondary cause."}, {"topic": "Neuro/CVT/Vascular", "q": "A trauma patient has a penetrating brain injury with a retained fragment. Besides surgery, which prophylaxis is commonly given?", "choices": ["Beta-blocker for this patient", "Antiepileptic (seizure) prophylaxis", "Long-term anticoagulation alone", "Antifungals for this patient", "Statins for this patient"], "ans": 1, "exp": "Penetrating/severe traumatic brain injury: ให้ 'early seizure prophylaxis (phenytoin/levetiracetam) ~7 วัน' เพื่อลด early post-traumatic seizure (ไม่ลด late seizure). ร่วมกับจัดการ raised ICP, ป้องกัน secondary injury (avoid hypoxia/hypotension), surgical debridement, antibiotic. ประเมิน GCS/pupils ต่อเนื่อง."}, {"topic": "Neuro/CVT/Vascular", "q": "A boxer sustains a rotational head injury; CT is relatively normal but he is comatose. MRI shows multiple small hemorrhages at the gray-white junction and corpus callosum. What is the diagnosis?", "choices": ["Epidural hematoma", "Concussion only", "Diffuse axonal injury", "Subdural hematoma", "Brain abscess"], "ans": 2, "exp": "Diffuse axonal injury (DAI): จาก 'rotational/shearing' forces → axonal disruption ที่ gray-white junction, corpus callosum, brainstem. CT มักดู 'ไม่สมกับ' ระดับความรู้สึกตัว (coma); MRI ไวกว่า (petechial hemorrhages/DWI). พยากรณ์ขึ้นกับความรุนแรง; รักษาประคับประคอง/ICP. เป็นสาเหตุ persistent coma หลัง trauma."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has trigeminal neuralgia with severe, brief, electric-shock-like facial pain triggered by touch. What is the first-line treatment?", "choices": ["Opioids", "Surgery first", "NSAIDs", "Carbamazepine", "Antibiotics"], "ans": 3, "exp": "Trigeminal neuralgia: ปวดหน้าแปลบเหมือนไฟช็อตสั้นๆ ตาม trigeminal distribution, trigger จากการสัมผัส/เคี้ยว. มักจาก neurovascular compression. First-line = 'carbamazepine' (หรือ oxcarbazepine). ดื้อยา → microvascular decompression, gamma knife, rhizotomy. MRI แยก secondary cause (tumor, MS)."}, {"topic": "Neuro/CVT/Vascular", "q": "A child has a posterior fossa tumor; the most common malignant brain tumor in children arising in the cerebellum/vermis is which?", "choices": ["Glioblastoma", "Meningioma", "Craniopharyngioma", "Ependymoma", "Medulloblastoma"], "ans": 4, "exp": "Medulloblastoma: embryonal tumor ที่ cerebellum/vermis — มะเร็งสมองที่พบบ่อยในเด็ก → ataxia + สัญญาณ raised ICP (obstructive hydrocephalus จากกด 4th ventricle). แพร่ทาง CSF ('drop metastases'). รักษา: resection + craniospinal RT + chemo. Pilocytic astrocytoma = benign, พยากรณ์ดี."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient develops fever, headache, and focal neurologic deficit; MRI shows a subdural collection with enhancement after sinusitis. What is the diagnosis?", "choices": ["Subdural empyema", "Epidural hematoma", "Chronic subdural hematoma", "Meningioma", "Brain abscess"], "ans": 0, "exp": "Subdural empyema: หนองใน subdural space (มักลุกลามจาก sinusitis/otitis/mastoiditis) → ไข้ + headache + focal deficit/seizure + ลุกลามเร็ว. เป็น neurosurgical emergency → 'urgent surgical drainage' + IV antibiotics + แก้แหล่งติดเชื้อ. ต่างจาก chronic SDH (ไม่ติดเชื้อ, ผู้สูงอายุ)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with severe head injury has refractory raised intracranial pressure. Which is an appropriate medical measure to lower ICP?", "choices": ["Warming blanket for this patient", "Hyperosmolar therapy (mannitol/hypertonic saline)", "Aggressive IV fluid to hypertension initially", "Trendelenburg positioning for this patient", "Hypoventilation for this patient"], "ans": 1, "exp": "การลด ICP: head-up 30° (neutral neck), adequate sedation/analgesia, 'hyperosmolar therapy (mannitol หรือ hypertonic saline)', maintain CPP (avoid hypotension/hypoxia), controlled ventilation (normocapnia; hyperventilation ชั่วคราวเฉพาะ herniation), CSF drainage (EVD), และ decompressive craniectomy ในรายดื้อ. หลีกเลี่ยงสิ่งที่เพิ่ม ICP."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a thoracic aortic aneurysm found incidentally. Which underlying connective tissue disorder should be considered in a young patient?", "choices": ["Rheumatoid arthritis", "Osteoarthritis", "Marfan syndrome", "Gout", "Diabetes"], "ans": 2, "exp": "Thoracic aortic aneurysm/dissection ในคนอายุน้อย → นึกถึง connective tissue disorder: 'Marfan syndrome' (FBN1 - tall, arachnodactyly, lens dislocation, aortic root dilation), Loeys-Dietz, Ehlers-Danlos vascular type, bicuspid aortic valve. ต้องเฝ้าระวัง/ผ่าตัดที่ threshold เล็กกว่าปกติ + beta-blocker/ARB."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a chronic lung condition with foul sputum, recurrent infections, and 'tram-track' airway dilation on CT. What is the diagnosis?", "choices": ["Pneumothorax", "Lung abscess", "Pulmonary embolism", "Bronchiectasis", "Mesothelioma"], "ans": 3, "exp": "Bronchiectasis: การขยายถาวรของ bronchi จากการทำลาย (post-infection - TB/pertussis, cystic fibrosis, immunodeficiency, obstruction) → ไอเสมหะมากเรื้อรัง/มีกลิ่น, hemoptysis, การติดเชื้อซ้ำ. CT: 'tram-track/signet-ring' dilated airways. รักษา: airway clearance, antibiotics, จัดการสาเหตุ; localized รุนแรง → resection."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient aspirates and develops a cavity with an air-fluid level in the lung containing pus. What is the diagnosis and treatment?", "choices": ["Empyema, decortication", "Pneumothorax, chest tube", "Pulmonary embolism, anticoagulation", "Mesothelioma, surgery", "Lung abscess, antibiotics and drainage"], "ans": 4, "exp": "Lung abscess (มักจาก aspiration - dependent segments, anaerobes): ไข้, ไอเสมหะเหม็น, CT/X-ray เห็น 'cavity + air-fluid level'. รักษา: 'antibiotics ระยะยาว (ครอบคลุม anaerobe)' + postural drainage; ล้มเหลว/ใหญ่ → percutaneous/surgical drainage. ต่างจาก empyema (ใน pleural space)."}, {"topic": "Neuro/CVT/Vascular", "q": "A neonate is cyanotic from birth with 'egg-on-a-string' cardiac silhouette; the aorta arises from the right ventricle and pulmonary artery from the left. What is the diagnosis?", "choices": ["Transposition of the great arteries", "VSD for this patient", "Tetralogy of Fallot in this case", "Coarctation for this patient", "Patent ductus arteriosus alone"], "ans": 0, "exp": "Transposition of the great arteries (TGA): aorta จาก RV, pulmonary artery จาก LV → 2 circulations แยกกัน → cyanosis รุนแรงแรกเกิด (survival ต้องมี mixing: PDA/PFO/VSD). X-ray: 'egg-on-a-string'. รักษา: 'prostaglandin E1' (คง PDA), balloon atrial septostomy, แล้ว arterial switch operation."}, {"topic": "Neuro/CVT/Vascular", "q": "An asymptomatic newborn has a continuous 'machinery' murmur; echocardiography shows a patent ductus arteriosus. In a premature infant, which drug may close it?", "choices": ["Furosemide in this case", "Indomethacin or ibuprofen", "Prostaglandin E1 alone", "Digoxin as first step", "Adenosine in this case"], "ans": 1, "exp": "Patent ductus arteriosus (PDA): continuous 'machinery' murmur (left infraclavicular). ใน 'preterm' ที่มีอาการ → 'indomethacin/ibuprofen' (ยับยั้ง prostaglandin → ปิด duct) หรือ surgical/catheter closure. ตรงข้าม: ใน duct-dependent CHD ให้ 'prostaglandin E1' เพื่อ 'คง' duct เปิด. Term/persistent → catheter/surgical closure."}, {"topic": "Neuro/CVT/Vascular", "q": "A hypertensive young patient has upper limb hypertension with weak/delayed femoral pulses and rib notching on X-ray. What is the diagnosis?", "choices": ["Pheochromocytoma", "Renal artery stenosis", "Coarctation of the aorta", "Aortic stenosis", "Takayasu arteritis"], "ans": 2, "exp": "Coarctation of the aorta: การตีบของ aorta (มักหลัง left subclavian) → 'upper limb hypertension + radiofemoral delay/weak femoral pulses', 'rib notching' (collateral จาก intercostal arteries), '3 sign'. สัมพันธ์ bicuspid aortic valve, Turner syndrome. รักษา: surgical repair หรือ balloon/stent. เป็นสาเหตุ secondary HT ในเด็ก/หนุ่มสาว."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient sustains a concussion in sport with brief confusion but a normal CT. What is the appropriate return-to-play principle?", "choices": ["Return immediately if CT normal", "Never return to sport", "Return after 24 hours regardless", "Graduated return only after symptom-free", "Return once pain-free with medication"], "ans": 3, "exp": "Concussion (mild TBI): อาการชั่วคราว (สับสน, ปวดศีรษะ, มึน), CT ปกติ. การกลับเล่นกีฬาต้อง 'graduated return-to-play' หลัง 'หายอาการ' (symptom-free) ทีละขั้น. หลีกเลี่ยง second impact syndrome (การกระแทกซ้ำก่อนหาย → สมองบวมรุนแรง). พักสมอง (cognitive/physical rest) ช่วงแรก."}, {"topic": "Neuro/CVT/Vascular", "q": "An elderly patient with a chronic subdural hematoma has progressive symptoms and a large hypodense collection with mass effect. What is the management?", "choices": ["Anticoagulation as first step", "Observation always initially", "Antibiotics for this patient", "Lumbar puncture as first step", "Surgical evacuation (burr holes)"], "ans": 4, "exp": "Chronic subdural hematoma ที่มีอาการ/ใหญ่/mass effect → 'surgical drainage (burr hole evacuation)' — พยากรณ์ดี. Small/asymptomatic → สังเกต ± หยุด anticoagulant. พบในผู้สูงอายุ/atrophy/anticoagulant. CT: hypodense (chronic) crescent collection. อาจเป็นซ้ำ."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient is found to have an unruptured 8 mm cerebral aneurysm incidentally. What determines management (observe vs treat)?", "choices": ["Size, location, and rupture risk factors", "Anticoagulate for this patient", "Always immediate clipping in this case", "Always ignore for this patient", "Antibiotics for this patient"], "ans": 0, "exp": "Unruptured intracranial aneurysm: การตัดสินใจ (surveillance vs coiling/clipping) ขึ้นกับ 'size (ใหญ่เสี่ยงกว่า), location (posterior circulation เสี่ยงกว่า), morphology, growth, อายุ, ประวัติ SAH/ครอบครัว, symptoms'. ใช้ PHASES score ช่วย. Ruptured aneurysm (SAH) = ต้องรักษาเร็ว. เลิกบุหรี่/คุมความดัน."}, {"topic": "Neuro/CVT/Vascular", "q": "A child with a ventriculoperitoneal shunt develops headache, vomiting, and lethargy. What must be suspected?", "choices": ["Ear infection in this case", "Shunt malfunction/obstruction", "Migraine for this patient", "Gastroenteritis initially", "Normal behavior initially"], "ans": 1, "exp": "VP shunt malfunction (obstruction/infection/disconnection) → กลับมามี raised ICP: headache, vomiting, lethargy, ± bulging fontanelle/sunset eyes (ทารก). ประเมิน: shunt series (X-ray), CT (ventricle โต), shunt tap. เป็น emergency → neurosurgery (revision). Shunt infection มักภายในไม่กี่เดือนหลังใส่."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has severe mitral regurgitation from a flail leaflet with worsening heart failure. What is the definitive treatment?", "choices": ["Antibiotics for this patient", "Beta-blocker only", "Mitral valve repair or replacement", "Observation for this patient", "Diuretics alone"], "ans": 2, "exp": "Mitral regurgitation (chronic primary, เช่น flail leaflet/prolapse/endocarditis): pansystolic murmur ที่ apex ร้าวไปรักแร้. Severe + symptomatic หรือ LV dysfunction/dilation → 'mitral valve repair (นิยม, ผลดีกว่า) หรือ replacement'. Acute severe MR (papillary muscle rupture post-MI, endocarditis) = emergency surgery."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with a mechanical prosthetic heart valve requires which long-term therapy?", "choices": ["Aspirin only", "No anticoagulation initially", "DOAC preferred in this case", "Lifelong warfarin (target INR)", "Antibiotics lifelong alone"], "ans": 3, "exp": "Mechanical prosthetic valve ต้องการ 'lifelong warfarin' (target INR ตามชนิด/ตำแหน่งลิ้น, มัก 2.5-3.5) — 'DOAC ห้ามใช้' (RE-ALIGN trial). Bioprosthetic valve ต้องการ anticoagulation สั้นๆ แล้ว aspirin. ทั้งคู่ต้อง endocarditis prophylaxis. ให้คำปรึกษาเรื่อง durability vs anticoagulation ในการเลือกลิ้น."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has syncope and a diastolic 'tumor plop'; echocardiography shows a mobile left atrial mass. What is the diagnosis?", "choices": ["Aortic stenosis", "Mitral stenosis", "Endocarditis vegetation", "Thrombus only", "Atrial myxoma"], "ans": 4, "exp": "Atrial myxoma (เนื้องอกหัวใจ primary ที่พบบ่อยสุด, มัก left atrium): อาจอุดกั้น mitral valve (syncope เปลี่ยนตามท่า, 'tumor plop'), embolization, constitutional symptoms (ไข้, น้ำหนักลด - เลียนแบบ endocarditis/vasculitis). Echo วินิจฉัย. รักษา: surgical resection."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient after cardiac surgery has hypotension, raised JVP, pulsus paradoxus, and equalization of diastolic pressures. What is the diagnosis?", "choices": ["Cardiac tamponade", "Tension pneumothorax", "Pulmonary embolism", "Myocardial infarction", "Sepsis"], "ans": 0, "exp": "Post-op cardiac tamponade: hypotension + raised JVP + pulsus paradoxus + muffled heart sounds; echo เห็น effusion + diastolic collapse. หลังผ่าตัดหัวใจ (bleeding into pericardium) เป็น emergency → 'pericardiocentesis/surgical re-exploration'. ต่างจาก tension pneumothorax (trachea เบน, เสียงหายใจลด)."}, {"topic": "Neuro/CVT/Vascular", "q": "A stable patient has a Stanford type B aortic dissection (descending aorta only) without complications. What is the initial management?", "choices": ["Thrombolysis for this patient", "Medical therapy (impulse control with beta-blocker)", "Emergency surgery always for this patient", "Anticoagulation for this patient", "No treatment for this patient"], "ans": 1, "exp": "Uncomplicated Stanford type B dissection (descending) → 'medical management': 'impulse control' ด้วย IV beta-blocker (ลด HR <60 และ BP) ± vasodilator, ปวด. Complicated type B (malperfusion, rupture, refractory pain/HT, expansion) → TEVAR/surgery. ต่างจาก type A (ascending) ที่ต้องผ่าตัดฉุกเฉิน."}, {"topic": "Neuro/CVT/Vascular", "q": "A lung cancer is confirmed as non-small cell carcinoma confined to the lung without nodal spread (early stage). What is the preferred treatment?", "choices": ["Chemotherapy only", "Radiotherapy only", "Surgical resection (lobectomy)", "Palliative care in this case", "Observation for this patient"], "ans": 2, "exp": "Non-small cell lung cancer (NSCLC) ระยะต้น (I-II, resectable, adequate lung function) → 'surgical resection (lobectomy + mediastinal node sampling)' เป็นการรักษาหลัก ± adjuvant chemo. Locally advanced (IIIA) → multimodal. Metastatic → systemic (chemo/targeted/immunotherapy). ต่างจาก SCLC (chemo/RT เป็นหลัก, ไม่ค่อยผ่าตัด)."}, {"topic": "Neuro/CVT/Vascular", "q": "A pleural effusion is analyzed with Light criteria showing an exudate. Which finding indicates an exudate?", "choices": ["Very low protein for this patient", "Low LDH for this patient", "Transudative appearance initially", "Pleural/serum protein ratio over 0.5", "Normal glucose only"], "ans": 3, "exp": "Light criteria (exudate ถ้าเข้า ≥1 ข้อ): pleural/serum protein >0.5, pleural/serum LDH >0.6, หรือ pleural LDH >2/3 upper normal. Exudate = inflammatory/malignant/infective (pneumonia, TB, cancer, PE). Transudate = hydrostatic/oncotic (heart failure, cirrhosis, nephrotic). ช่วยแยกสาเหตุและการดูแล."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a popliteal artery aneurysm. What is a major complication distinguishing it from an aortic aneurysm?", "choices": ["No complications for this patient", "Rupture is the main risk for this patient", "Causes hypertension for this patient", "Causes stroke for this patient", "Thromboembolism causing acute limb ischemia"], "ans": 4, "exp": "Popliteal artery aneurysm (peripheral aneurysm ที่พบบ่อยสุด, มัก bilateral, สัมพันธ์ AAA): ภาวะแทรกซ้อนหลักคือ 'thrombosis/thromboembolism → acute limb ischemia' (ไม่ใช่ rupture เป็นหลักเหมือน AAA). อาจกด vein/nerve. รักษา: ผ่าตัด (bypass + ligation) หรือ endovascular เมื่อ symptomatic/ใหญ่. ตรวจ AAA ร่วม."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has arm claudication and neurologic symptoms of vertebrobasilar insufficiency when using the arm; there is a blood pressure difference between arms. What is the diagnosis?", "choices": ["Subclavian steal syndrome", "Raynaud phenomenon", "Thoracic outlet syndrome", "Carotid stenosis", "Buerger disease"], "ans": 0, "exp": "Subclavian steal syndrome: การตีบ/อุดตันของ subclavian artery 'ก่อน' vertebral origin → เมื่อใช้แขน เลือดถูก 'ดึง' จาก vertebral artery (retrograde) → vertebrobasilar insufficiency (มึน, เห็นภาพซ้อน) + arm claudication + 'BP ต่างสองแขน'. รักษา: revascularization ถ้ามีอาการ. ตรวจ duplex/angiography."}, {"topic": "Neuro/CVT/Vascular", "q": "A young woman has hypertension resistant to medication; imaging shows a 'string of beads' appearance of the renal artery. What is the diagnosis?", "choices": ["Conn syndrome", "Fibromuscular dysplasia", "Atherosclerotic renal artery stenosis", "Pheochromocytoma", "Coarctation"], "ans": 1, "exp": "Renal artery stenosis จาก 'fibromuscular dysplasia' (หญิงสาว, 'string of beads' ที่ mid-distal renal artery) → secondary HT (renin-angiotensin). ต่างจาก atherosclerotic RAS (สูงอายุ, ostial/proximal). รักษา FMD: angioplasty (มัก ไม่ stent) ± antihypertensive. ระวัง AKI เมื่อให้ ACEI ใน bilateral RAS."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has chronic postprandial abdominal pain, weight loss (food fear), and a bruit; angiography shows stenosis of two mesenteric arteries. What is the diagnosis?", "choices": ["Gastric cancer", "Peptic ulcer", "Chronic mesenteric ischemia", "Chronic pancreatitis", "IBD"], "ans": 2, "exp": "Chronic mesenteric ischemia ('intestinal angina'): ปวดท้องหลังอาหาร 15-30 นาที + 'weight loss/food fear' (sitophobia) + bruit; มักต้องตีบ ≥2 ใน 3 mesenteric arteries (celiac, SMA, IMA - collateral). สัมพันธ์ atherosclerosis/สูบบุหรี่. รักษา: revascularization (endovascular/bypass). ต่างจาก acute mesenteric ischemia (เฉียบพลันรุนแรง)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient develops a pulsatile, painful mass at a femoral arterial puncture site after catheterization, with a bruit. What is the diagnosis?", "choices": ["True aneurysm as first step", "Hematoma only", "AV fistula for this patient", "Pseudoaneurysm (false aneurysm)", "Cellulitis for this patient"], "ans": 3, "exp": "Pseudoaneurysm (false aneurysm): เลือดรั่วออกนอกผนังหลอดเลือดแต่ถูกกักด้วย surrounding tissue (ไม่มีผนัง 3 ชั้น) — มัก 'หลัง arterial puncture' (femoral cath) → pulsatile mass + bruit + 'to-and-fro' flow บน duplex. รักษา: ultrasound-guided compression/thrombin injection หรือ surgery. ต่างจาก true aneurysm (ผนังครบ 3 ชั้น)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a superficial vein that is tender, red, and cord-like along its course (superficial thrombophlebitis). If it extends near the saphenofemoral junction, what is the concern?", "choices": ["Arterial occlusion as first step", "Lymphedema for this patient", "Cellulitis only", "No concern for this patient", "Progression to deep vein thrombosis"], "ans": 4, "exp": "Superficial thrombophlebitis: vein แข็งเป็นลำ แดง เจ็บ. ส่วนใหญ่ benign (warm compress, NSAIDs). แต่ถ้า 'ลุกลามใกล้ saphenofemoral junction หรือยาว >5 cm' เสี่ยงลามเข้า deep system (DVT/PE) → พิจารณา anticoagulation + duplex ติดตาม. Recurrent/migratory → หา malignancy (Trousseau) / thrombophilia."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a spinal epidural abscess with back pain, fever, and progressive neurologic deficit. What is the appropriate management?", "choices": ["Urgent decompression and antibiotics", "Antibiotics alone always initially", "Observation for this patient", "Physiotherapy for this patient", "Bracing only"], "ans": 0, "exp": "Spinal epidural abscess: triad ปวดหลัง + ไข้ + neurologic deficit (progressive). เชื้อบ่อย S. aureus (hematogenous/IVDU/DM). MRI ยืนยัน. เป็น emergency → 'surgical decompression + drainage + IV antibiotics' (โดยเฉพาะเมื่อมี neuro deficit); เล็ก/ไม่มี deficit อาจ antibiotic + monitoring ใกล้ชิด. ล่าช้า → paralysis ถาวร."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a syrinx (fluid-filled cavity) in the spinal cord causing a 'cape-like' loss of pain/temperature sensation with preserved touch. What is the diagnosis?", "choices": ["Cord tumor", "Syringomyelia", "Multiple sclerosis", "Transverse myelitis", "Cervical spondylosis"], "ans": 1, "exp": "Syringomyelia: fluid cavity (syrinx) ใน central cord → กด crossing spinothalamic fibers → 'cape-like/dissociated sensory loss' (สูญเสีย pain/temperature ที่แขน/ไหล่ แต่คง touch/proprioception), ± lower motor neuron แขน. สัมพันธ์ 'Chiari I malformation', trauma, tumor. MRI. รักษาที่สาเหตุ (posterior fossa decompression) ± shunt."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient after a cardiac operation develops fever, sternal instability, and purulent wound discharge. What is the diagnosis?", "choices": ["Pneumonia for this patient", "Simple superficial infection initially", "Deep sternal wound infection/mediastinitis", "Pericarditis for this patient", "Costochondritis for this patient"], "ans": 2, "exp": "Deep sternal wound infection/mediastinitis (หลัง median sternotomy): ไข้ + sternal instability/click + purulent discharge + sepsis. เชื้อ S. aureus/gram-negative. เป็นภาวะแทรกซ้อนร้ายแรง → 'surgical debridement + sternal rewiring/reconstruction (flap) + IV antibiotics'. ปัจจัยเสี่ยง: DM, obesity, BIMA harvest, prolonged surgery."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with atrial fibrillation and a left atrial thrombus is at risk of which complication relevant to vascular/cardiac surgery?", "choices": ["Deep vein thrombosis", "Pulmonary embolism", "Hemorrhage", "Systemic (arterial) embolism", "Aneurysm"], "ans": 3, "exp": "Atrial fibrillation → stasis ใน left atrium/appendage → thrombus → 'systemic arterial embolism' (stroke, acute limb ischemia, mesenteric/renal/splenic infarct). ป้องกันด้วย anticoagulation (CHA2DS2-VASc). เป็นสาเหตุ embolic acute limb ischemia และ cardioembolic stroke ที่พบบ่อย. ต่างจาก DVT/PE (venous system)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with COPD has a solitary pulmonary nodule that is stable in size for over 2 years on serial imaging. What does stability suggest?", "choices": ["Definitely malignant", "Requires immediate resection", "Metastasis", "Active infection", "Likely benign"], "ans": 4, "exp": "Solitary pulmonary nodule ที่ 'ขนาดคงที่ ≥2 ปี' (บน serial imaging) บ่งชี้ 'benign' (doubling time ยาว) → มักติดตามต่อ/หยุด. Benign features: เล็ก, ขอบเรียบ, calcification (central/popcorn/laminated). Malignant: โตขึ้น, spiculated, >8mm, ผู้สูบบุหรี่ → biopsy/PET. Growth rate สำคัญในการตัดสิน."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient develops chylothorax (milky pleural fluid high in triglycerides) after thoracic surgery. What structure was injured?", "choices": ["Thoracic duct", "Bronchus", "Azygos vein", "Esophagus", "Pericardium"], "ans": 0, "exp": "Chylothorax: การรั่วของ 'thoracic duct' (lymph) → milky pleural fluid, triglyceride สูง (>110 mg/dL), chylomicrons. สาเหตุ: iatrogenic (esophagectomy/thoracic surgery), trauma, malignancy (lymphoma อุดตัน). รักษา: chest drainage + low-fat/MCT diet หรือ NPO+TPN, octreotide; ล้มเหลว → thoracic duct ligation/embolization."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with hand pain and pallor on overhead activity has a cervical rib compressing the brachial plexus and subclavian vessels. What is the diagnosis?", "choices": ["Carpal tunnel syndrome", "Thoracic outlet syndrome", "Cubital tunnel syndrome", "Raynaud phenomenon", "Buerger disease"], "ans": 1, "exp": "Thoracic outlet syndrome: การกด neurovascular bundle (brachial plexus + subclavian vessels) ที่ thoracic outlet (จาก cervical rib, กล้ามเนื้อ scalene, ท่าทาง) → อาการทาง neurogenic (ชา/อ่อนแรงมือ, มัก ulnar - พบบ่อยสุด), vascular (pallor/pain เมื่อยกแขน, Adson test). รักษา: physio/posture; ดื้อ/vascular → decompression (rib resection)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient is confirmed brain dead. Which is a criterion for brainstem death?", "choices": ["Low GCS only", "Fixed reversible coma for this patient", "Absent brainstem reflexes and apnea with a known irreversible cause", "Abnormal EEG only", "Cardiac arrest only"], "ans": 2, "exp": "การวินิจฉัย brain(stem) death: มี 'known irreversible cause' + exclude confounders (hypothermia, drugs, metabolic) + 'coma ลึก + absent brainstem reflexes (pupillary, corneal, oculocephalic/vestibular, gag/cough) + positive apnea test'. ทำโดยแพทย์ที่มีคุณสมบัติ 2 คน ตามเกณฑ์. สำคัญต่อ organ donation/withdrawal."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient after limb revascularization for prolonged acute ischemia develops a tense, painful compartment. What is the appropriate management?", "choices": ["Elevation only", "Anticoagulation only", "Observation", "Fasciotomy", "Amputation"], "ans": 3, "exp": "Reperfusion หลัง prolonged limb ischemia (revascularization) → 'reperfusion injury/edema' → compartment syndrome. รักษา: 'fasciotomy' (มัก prophylactic ในผู้ที่ ischemia นาน >4-6 ชม.). เฝ้าระวัง 'reperfusion syndrome': hyperkalemia, myoglobinuria (AKI), acidosis (คล้าย crush). ตรวจ compartment pressure/clinical."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has diabetes and a black, dry, mummified toe with a clear demarcation line and no active infection. What type of gangrene is this?", "choices": ["Fournier gangrene", "Wet gangrene", "Gas gangrene", "Necrotizing fasciitis", "Dry gangrene"], "ans": 4, "exp": "Dry gangrene: เนื้อตายจาก ischemia (arterial insufficiency) — แห้ง ดำ mummified, มี demarcation ชัด, 'ไม่มีการติดเชื้อ/หนอง'. มัก auto-amputate หรือรอ demarcation แล้วตัด. ต่างจาก 'wet gangrene' (ติดเชื้อร่วม, บวม เหม็น, sepsis → ต้องตัดฉุกเฉิน + antibiotic). จัดการ ischemia/revascularization + ควบคุมเบาหวาน."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has an ankle-brachial index of 0.35 with rest pain and non-healing ulcers. What does this indicate?", "choices": ["Critical limb ischemia needing revascularization", "Normal circulation for this patient", "Mild claudication only", "Venous disease for this patient", "No intervention needed for this patient"], "ans": 0, "exp": "ABI: >0.9 ปกติ; 0.4-0.9 claudication; '<0.4 = critical limb ischemia (CLI)' → rest pain, tissue loss (ulcer/gangrene) → 'urgent revascularization' (endovascular/bypass) เพื่อ save limb + wound care + risk factor. (ABI >1.3 = incompressible/calcified - DM/CKD, แปลผลระวัง → ใช้ toe pressure)."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has an incidental finding of a carotid body tumor (paraganglioma) at the carotid bifurcation, splaying the internal and external carotid ('lyre sign'). What is the treatment for a symptomatic/enlarging tumor?", "choices": ["Observation always", "Surgical resection", "Chemotherapy", "Radiotherapy alone always", "Antibiotics"], "ans": 1, "exp": "Carotid body tumor (paraganglioma): ก้อนที่ carotid bifurcation, pulsatile, เคลื่อนด้านข้างได้แต่ไม่ขึ้นลง, 'splaying ICA/ECA (lyre sign)' บน angiography. ส่วนใหญ่ benign แต่โตช้าและ vascular. รักษา symptomatic/enlarging: 'surgical resection' (± preoperative embolization); RT ในบางราย. ประเมิน catecholamine (functional) ก่อนผ่าตัด."}, {"topic": "Neuro/CVT/Vascular", "q": "A neonate has bilious vomiting and the surgical team suspects a duct-dependent cyanotic lesion. Which drug maintains ductal patency while awaiting surgery?", "choices": ["Furosemide", "Indomethacin", "Prostaglandin E1", "Adenosine", "Digoxin"], "ans": 2, "exp": "Duct-dependent congenital heart lesions (เช่น TGA, pulmonary atresia, critical coarctation, HLHS): การอยู่รอดต้องมี PDA เพื่อ mixing/perfusion → ให้ 'prostaglandin E1 (alprostadil)' คง duct เปิด ระหว่างรอผ่าตัด. ตรงข้ามกับ preterm PDA ที่ต้องการปิด (indomethacin/ibuprofen). Cyanosis + duct-dependent = PGE1."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a spinal cord injury with loss of motor function and pain/temperature below the lesion, but preserved proprioception and vibration. What syndrome is this?", "choices": ["Central cord syndrome", "Brown-Sequard syndrome", "Posterior cord syndrome", "Anterior cord syndrome", "Cauda equina syndrome"], "ans": 3, "exp": "Anterior cord syndrome: บาดเจ็บ anterior 2/3 ของ cord (มักจาก anterior spinal artery infarct/flexion injury) → สูญเสีย motor (corticospinal) + pain/temperature (spinothalamic) ใต้ระดับ แต่ 'คง proprioception/vibration (dorsal column)'. พยากรณ์ฟื้นตัวแย่ที่สุดในกลุ่ม incomplete."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a chest X-ray showing a large abdominal aortic aneurysm and presents with sudden severe back/abdominal pain and hypotension. What is the management?", "choices": ["Elective repair later", "CT then observe", "Anticoagulation", "Antibiotics", "Emergency repair (open/EVAR)"], "ans": 4, "exp": "Ruptured AAA: triad 'ปวดท้อง/หลังเฉียบพลัน + hypotension + pulsatile abdominal mass' → 'emergency repair' (open หรือ EVAR) ทันที. ผู้ป่วย unstable → ห้องผ่าตัดเลย (ไม่รอ imaging); stable → CT ด่วนอาจช่วยวางแผน EVAR. permissive hypotension ระหว่างรอ. อัตราตายสูงมาก."}, {"topic": "Neuro/CVT/Vascular", "q": "A child has an atrial septal defect with a fixed, widely split S2. What is characteristic of ASD?", "choices": ["Fixed splitting of S2", "Rib notching", "Continuous machinery murmur", "Cyanosis at birth", "Boot-shaped heart"], "ans": 0, "exp": "Atrial septal defect (ASD): left-to-right shunt → 'fixed widely split S2' (ไม่เปลี่ยนตามการหายใจ) + systolic ejection murmur (เพิ่ม flow ผ่าน pulmonary valve). Acyanotic; อาจไม่มีอาการจนโต (heart failure, AF, pulmonary HT/Eisenmenger, paradoxical emboli). รักษา: catheter/surgical closure ในราย significant."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has recurrent spontaneous pneumothorax on the same side. What is the appropriate definitive treatment?", "choices": ["Antibiotics for this patient", "VATS with bullectomy and pleurodesis", "Repeated needle aspiration alone", "Observation for this patient", "Long-term oxygen for this patient"], "ans": 1, "exp": "Recurrent (or persistent air leak) spontaneous pneumothorax → 'VATS bullectomy + pleurodesis (mechanical/chemical)' เพื่อป้องกันการเป็นซ้ำ. ข้อบ่งชี้ surgery: recurrence (ครั้งที่ 2 ข้างเดิม หรือ contralateral), persistent air leak >3-5 วัน, bilateral, อาชีพเสี่ยง (นักบิน/นักดำน้ำ), hemothorax."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with chronic venous insufficiency and varicose veins with reflux at the saphenofemoral junction has recurrent symptoms despite compression. What is a definitive treatment option?", "choices": ["Anticoagulation in this case", "Antibiotics for this patient", "Endovenous ablation or surgery", "Diuretics for this patient", "Bed rest for this patient"], "ans": 2, "exp": "Varicose veins (superficial venous reflux): เริ่มด้วย conservative (compression stockings, leg elevation, exercise). Symptomatic/complications (ulcer, bleeding, thrombophlebitis) หรือดื้อ → 'endovenous thermal ablation (laser/radiofrequency)' หรือ surgery (high ligation + stripping)/foam sclerotherapy. ประเมิน reflux ด้วย duplex ก่อน. ต้องแน่ใจ deep system ปกติ."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient after major vascular surgery is at high risk of VTE. What is appropriate prophylaxis?", "choices": ["No prophylaxis", "Therapeutic anticoagulation always", "Aspirin only", "Mechanical plus pharmacologic prophylaxis", "Bed rest only"], "ans": 3, "exp": "ผู้ป่วยผ่าตัดใหญ่ = high VTE risk → 'mechanical (IPC/stockings) + pharmacologic (LMWH/heparin) prophylaxis' + early mobilization. ประเมิน bleeding risk ร่วม (ผ่าตัด neuro/บางกรณีเริ่ม pharmacologic ช้าลง). Caprini score ช่วยประเมิน. ป้องกัน DVT/PE ซึ่งเป็นสาเหตุการตายที่ป้องกันได้."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient develops sudden ventricular fibrillation after cardiac surgery. What is the immediate management?", "choices": ["Diuretics for this patient", "Give beta-blocker in this case", "Observe for this patient", "Pacing only", "Immediate defibrillation and CPR"], "ans": 4, "exp": "Ventricular fibrillation (pulseless) = cardiac arrest → 'immediate defibrillation (unsynchronized shock) + CPR' ตาม ACLS, epinephrine, amiodarone, หาสาเหตุ (5H5T - post-op: hypoxia, electrolyte-hyperkalemia, tamponade, MI/ischemia). Post-cardiac surgery arrest มี protocol เฉพาะ (พิจารณา resternotomy). Shockable rhythm → shock เร็ว."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a spinal cord injury at the conus medullaris (L1-L2). Which feature distinguishes conus from cauda equina syndrome?", "choices": ["Early symmetric bladder/bowel dysfunction with mixed signs", "Pure motor deficit for this patient", "Only unilateral leg pain for this patient", "No bladder involvement for this patient", "Preserved reflexes always for this patient"], "ans": 0, "exp": "Conus medullaris syndrome: บาดเจ็บที่ปลาย cord (L1-2) → 'early, symmetric' bladder/bowel/sexual dysfunction, saddle anesthesia, mixed UMN+LMN signs, ปวดน้อยกว่า. Cauda equina syndrome: บาดเจ็บ nerve roots ใต้ conus → asymmetric, ปวดมาก (radicular), LMN signs, bladder dysfunction มาช้ากว่า. ทั้งคู่ต้อง urgent MRI + decompression."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with lung cancer needs staging. Which imaging assesses distant metastasis and nodal involvement for treatment planning?", "choices": ["No imaging", "PET-CT", "Chest X-ray only", "Abdominal ultrasound", "Bone X-ray only"], "ans": 1, "exp": "Lung cancer staging (TNM): 'CT chest/upper abdomen + PET-CT' (ประเมิน nodes/distant metastasis - adrenal, liver, bone), + brain MRI (ในบางระยะ), ± EBUS/mediastinoscopy สำหรับ mediastinal nodes. Staging กำหนดการรักษา (resectable vs systemic). PET-CT ช่วยแยก resectable/unresectable และหลีกเลี่ยงผ่าตัดที่ไม่ได้ประโยชน์."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a stab wound to the chest and develops hypotension with distended neck veins; ultrasound shows pericardial fluid with tamponade. What is the definitive management?", "choices": ["Antibiotics only", "Oral fluids for this patient", "Surgical pericardial decompression (thoracotomy)", "Chest physiotherapy for this patient", "Observation for this patient"], "ans": 2, "exp": "Penetrating cardiac injury with tamponade (Beck triad + FAST pericardial fluid): pericardiocentesis เป็น temporizing เท่านั้น → definitive คือ 'emergency surgery (thoracotomy/sternotomy) เพื่อ decompress + repair cardiac wound'. Unstable penetrating chest trauma อาจต้อง ED thoracotomy. เป็น surgical emergency."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient with severe head injury has a cerebral perfusion pressure (CPP) that must be maintained. How is CPP calculated?", "choices": ["Systolic BP minus ICP for this patient", "ICP minus MAP for this patient", "MAP plus ICP for this patient", "Mean arterial pressure minus intracranial pressure", "Diastolic BP only"], "ans": 3, "exp": "Cerebral perfusion pressure 'CPP = MAP − ICP' (เป้าหมายมัก ≥60-70 mmHg ใน severe TBI). การลด CPP (จาก ICP สูงหรือ MAP ต่ำ - hypotension) → cerebral ischemia (secondary injury). จึงต้องคุม ICP และหลีกเลี่ยง hypotension/hypoxia. เป็นหลักการดูแล neurocritical care."}, {"topic": "Neuro/CVT/Vascular", "q": "A patient has a large hemothorax with over 1500 mL initial drainage or ongoing bleeding of 200 mL/hr. What is the indication?", "choices": ["Observation only", "Antibiotics only", "Repeat chest X-ray in 24 hours", "Diuretics", "Thoracotomy for surgical control"], "ans": 4, "exp": "Massive hemothorax: chest tube ออกเลือด '>1,500 mL ทันที' หรือ 'ongoing >200 mL/hr × 2-4 ชม.' หรือ hemodynamic instability → ข้อบ่งชี้ 'thoracotomy' เพื่อควบคุมแหล่งเลือด (systemic - intercostal/internal mammary, hilar, great vessels). ร่วมกับ resuscitation. ส่วนใหญ่ hemothorax เล็ก-กลางหายด้วย chest tube."}]}, {"id": "nl2-2021", "title": "NL 2 ปี 2021 (VICHAKARN_SMST)", "subject": "past", "questions": [{"topic": "Cardiology", "q": "A 50-year-old male, heavy smoker, presented with a severe chest pain for 30 minutes at a community hospital. He has no known underlying diseases. PE: V/S stable; CVS - no neck vein engorged, PMI 5th ICS MCL, normal S1S2, S3 gallop; RS - fine crepitation both basal lungs; EKG: STE at V4-6, STD II, III, aVF; TropT: Elevated. It takes 150 minutes to travel from this community hospital to the cardiac center. Aside from aspirin and clopidogrel, what is the proper management in this patient?", "choices": ["Streptokinase", "Enoxaparin", "Ticagrelor", "Furosemide", "Refer for primary PCI"], "ans": 0, "exp": "STEMI (anterior). กฎเวลา reperfusion: ถ้าคาดว่า first-medical-contact ถึง PCI-device นานเกิน 120 นาที ให้เลือก fibrinolysis (ในที่นี้ระยะทาง 150 นาที > 120) — ยาละลายลิ่มที่มีคือ streptokinase แล้วจึงส่งต่อทำ PCI (pharmaco-invasive). *หมายเหตุ: ไฟล์ต้นฉบับไฮไลต์ตัวเลือก “Refer for primary PCI” แต่ตามแนวทางเวลา >120 นาที ควรให้ยาละลายลิ่มก่อน จึงเลือก Streptokinase*"}, {"topic": "Cardiology", "q": "A 30-year-old female presented with lightheadedness with paroxysmal palpitation for 1 month. She experienced this symptom 2-3 times per week especially after voiding. PE: unremarkable. EKG: normal sinus rhythm, HR 80/min, no ST-T change, no AV block. What is investigation?", "choices": ["Echo", "Tilt table test", "Exercise stress test", "24 hr holter monitoring", "Carotid ultrasound"], "ans": 1, "exp": "อาการเป็นลม/หน้ามืดสัมพันธ์กับการถ่ายปัสสาวะ (post-void) เข้าได้กับ situational/reflex (vasovagal) syncope — การตรวจยืนยันคือ tilt table test. EKG ปกติและไม่มี structural clue จึงไม่ใช่ arrhythmia (holter) หรือ ischemia (EST)."}, {"topic": "Cardiology", "q": "A man known case ESRD (not on RRT). EKG as shown (wide bizarre QRS / sine-wave pattern). What is the most proper management?", "choices": ["Furosemide", "Insulin", "10% calcium gluconate", "7.5% bicarbonate"], "ans": 2, "exp": "ESRD + EKG QRS กว้างผิดรูป/sine wave = severe hyperkalemia. ลำดับแรกต้องให้ calcium gluconate เพื่อ stabilize cardiac membrane ป้องกัน arrhythmia (แม้ไม่ลดระดับ K). จากนั้นจึง shift K เข้าเซลล์ (insulin+glucose, bicarbonate) และกำจัด K (diuretic/dialysis).", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q5.png"}, {"topic": "Cardiology", "q": "Female s/p radical mastectomy, currently on doxorubicin for 6 months, presented with dyspnea. PE: V/S - RR 20/min, PR 120 bpm, BP 80/60 mmHg; CVS - faint heart sound, normal S1S2 no murmur; Lung - clear and equal breath sound; Abd - Liver 3 cm bcm. What's proper management?", "choices": ["IV Furosemide", "IV Dobutamine", "Pericardiocentesis", "Echocardiogram"], "ans": 3, "exp": "Doxorubicin เป็น anthracycline ที่ทำให้เกิด cardiotoxicity ได้ทั้ง dilated cardiomyopathy และ pericardial effusion. อาการ hypotension + faint heart sound + tachycardia + hepatic congestion ต้องแยกระหว่าง cardiomyopathy กับ tamponade — จึงทำ echocardiogram เพื่อประเมิน EF/effusion ก่อนเลือกการรักษา (furosemide/inotrope/pericardiocentesis)."}, {"topic": "Cardiology", "q": "ผู้ป่วยชาย 40 ปี มาตรวจสุขภาพประจำปี ไม่มีประวัติโรคหัวใจ ไม่มีอาการ ไม่เคยออกกำลังกาย ให้แนะนำ activity ที่ช่วยป้องกัน cardiovascular disease", "choices": ["15 min jogging 3 days/week", "Walking 2000 steps/day", "2 set of 10 squatting per day", "One hour yoga per day", "30 min brief walking 5 days/week"], "ans": 4, "exp": "คำแนะนำการออกกำลังกายเพื่อป้องกันโรคหัวใจและหลอดเลือด = aerobic ระดับปานกลางอย่างน้อย 150 นาที/สัปดาห์ → เดินเร็ว 30 นาที × 5 วัน = 150 นาที/สัปดาห์ ตรงเป้าที่สุดและเหมาะกับผู้เริ่มต้น."}, {"topic": "Cardiology", "q": "ให้ประวัติเข้าได้กับ pericarditis (pericardial effusion เจาะดูดน้ำออกมา ให้ profile) ถาม long term prophylaxis เพื่อป้องกันภาวะแทรกซ้อนระยะยาว", "choices": ["Prednisolone", "ASA", "Colchicine", "Anti TB Drug"], "ans": 0, "exp": "กรณี pericardial effusion ที่ profile เข้าได้กับ TB pericarditis (lymphocyte เด่น, ADA สูง) การให้ adjunctive corticosteroid (prednisolone) ร่วมกับ anti-TB ช่วยลดโอกาสเกิด constrictive pericarditis ในระยะยาว. *ถ้าเป็น idiopathic/viral recurrent pericarditis การป้องกันการเป็นซ้ำจะใช้ colchicine — ต้องดู profile ประกอบ*"}, {"topic": "Cardiology", "q": "ชาย 60 ปี มาด้วย chest pain, dx MI s/p PCI กำลังจะ discharge กลับบ้าน u/d DLP, HT. Lipid profile: cho 180, TG 250, HDL 40. ก่อนกลับบ้านควรทำอย่างไรกับ DLP?", "choices": ["Direct LDL", "High intensity statin", "Repeat lipid profile ก่อนให้ยา", "Low intensity statin + fenofibrate", "Moderate intensity statin"], "ans": 1, "exp": "ผู้ป่วยหลัง MI/PCI = ASCVD ความเสี่ยงสูงมาก ต้องได้ high-intensity statin (atorvastatin 40-80 หรือ rosuvastatin 20-40) โดยไม่ต้องรอ/ขึ้นกับระดับ LDL เป้าหมาย LDL < 55 มก./ดล. และลด ≥ 50%."}, {"topic": "Neurology", "q": "A 50-year-old woman presented with episodic sharp stabbing pain at left mandible radiate to TM joint and then deep in left ear. These episodes are triggered with smiling and touching face. PE: no neurological deficit, no dental caries. What is the most appropriate treatment?", "choices": ["Tramadol", "Ibuprofen", "Carbamazepine", "Amitriptyline", "Prednisolone"], "ans": 2, "exp": "ปวดแปลบสั้น ๆ ตามแนว trigeminal (mandibular) กระตุ้นด้วยการสัมผัส/ยิ้ม โดยไม่มี neuro deficit = trigeminal neuralgia. ยา first-line คือ carbamazepine (หรือ oxcarbazepine)."}, {"topic": "Pulmonology", "q": "ผู้ชาย 22 ปี เล่นฟุตบอลแล้วอยู่ดี ๆ ก็เหนื่อย PE: mild hyperresonance on percussion left side. CXR: visceral pleural line ห่างจาก chest wall 1 cm. What is the most proper management?", "choices": ["O2 supplement", "Simple aspiration", "Tube thoracostomy", "Observe", "Surgical thoracotomy"], "ans": 3, "exp": "Primary spontaneous pneumothorax ขนาดเล็ก (rim < 2 ซม. ที่นี่ 1 ซม.) อาการน้อย = observe (± ให้ O2 เร่งการดูดกลับของอากาศ). ถ้าขนาดใหญ่/อาการมากจึงพิจารณา aspiration หรือ ICD."}, {"topic": "Pulmonology", "q": "A 25-year-old female presented with dyspnea and cyanosis for 1 hour, U/D myasthenia gravis, lost follow up 1 month. PE: V/S - BP 90/60 mmHg, PR 100 bpm, RR 30/min; Lung - shallow breathing, cyanosis, no adventitious sound. What is most likely the etiology (mechanism of hypoxemia)?", "choices": ["Shunt", "Dead space", "Diffusion defect", "V/Q mismatch", "Hypoventilation"], "ans": 4, "exp": "MG ที่ขาดยา → myasthenic crisis กล้ามเนื้อหายใจอ่อนแรง → หายใจตื้น (shallow breathing) = alveolar hypoventilation ทำให้ PaCO2 สูงและ PaO2 ต่ำ (เขียว) โดยปอดเองปกติ (no adventitious sound). กลไก hypoxemia คือ hypoventilation."}, {"topic": "Pulmonology", "q": "ผู้ชายมาด้วย respiratory distress RR 10 เหงื่อแตก มี retraction. PE: lung - clear both lungs, poor air entry, minimal wheezing. What's proper management?", "choices": ["ETT", "Salbutamol NB", "Ipratropium NB"], "ans": 0, "exp": "RR ต่ำ (10) + เหงื่อแตก + retraction + poor air entry = ผู้ป่วยกำลังหมดแรงหายใจ (impending respiratory failure). ต้อง secure airway ด้วย endotracheal intubation ทันที ไม่ใช่แค่พ่นยา."}, {"topic": "Pulmonology", "q": "A 50-year-old female with advanced stage CA pancreas presented with shortness of breath and chest tightness 3 hours prior to admission. PE: V/S - BT 37.8°C, PR 110 bpm, RR 30/min, BP 110/70 mmHg, SpO2 90% RA; Heart - normal S1S2, no murmur, no gallop; EKG: sinus tachycardia; CXR: no infiltration. What is the most appropriate management?", "choices": ["IV fluid loading", "LMWH", "ASA Nitrate", "Thrombolytics", "Observe and Follow up EKG next 12h"], "ans": 1, "exp": "มะเร็ง (hypercoagulable) + เหนื่อยเฉียบพลัน + tachycardia + hypoxia (SpO2 90%) + EKG sinus tachy + CXR ปกติ = pulmonary embolism. ผู้ป่วย hemodynamic ยังคงที่ (ไม่ใช่ massive) จึงรักษาด้วย anticoagulation (LMWH); thrombolytics ใช้เฉพาะ massive PE ที่ช็อก."}, {"topic": "Pulmonology", "q": "A 70-year-old male came in with an acute exacerbation from U/D COPD. He received antimicrobial agent, bronchodilator, oxygen cannula 5 LPM and became clinically improved. Two days later, he looks stuporous but still arousal. He has a very slow respiratory rate. What is the most appropriate management?", "choices": ["Add dexamethasone", "Change antimicrobial agent", "endotracheal intubation", "increase bronchodilator dose", "discontinue oxygen treatment"], "ans": 2, "exp": "COPD ที่ได้ O2 flow สูง (5 LPM) เกินไป → CO2 คั่ง (hypercapnia/CO2 narcosis) ทำให้ซึมและ RR ช้าลง = hypercapnic respiratory failure ที่มีระดับความรู้สึกตัวลด. ต้องช่วยหายใจ (NIV/intubation) — ในตัวเลือกนี้คือ endotracheal intubation. (การ off O2 ทันทีจะทำให้ hypoxia)"}, {"topic": "Pulmonology", "q": "Patient with COPD exacerbation ได้ ATB กับ O2 cannula 5 LPM อาการเริ่มดีขึ้น 2 วันต่อมาอาการแย่ลง stupor RR ร่วง (ลดลง) ถามว่าทำอย่างไร", "choices": ["เปลี่ยน ATB", "ให้ dexamethasone", "off O2", "ETT"], "ans": 3, "exp": "เหมือนข้อก่อนหน้า (CO2 narcosis จาก O2 มากเกินใน COPD) — ผู้ป่วยซึม RR ช้า = hypercapnic respiratory failure ต้องช่วยหายใจด้วย ETT. *ไฟล์ต้นฉบับไฮไลต์ “ให้ dexamethasone” ซึ่งไม่แก้ปัญหา CO2 คั่งเฉียบพลัน จึงเลือก ETT ตามหลักการ*"}, {"topic": "Pulmonology", "q": "ชายไทย หอบเหนื่อย ตรวจเจอ pleural effusion, pleural profile: ADA 50. ถามทำอะไรต่อ", "choices": ["Antibiotics", "ส่ง pleural cytology ต่อ", "Anti tb drug", "Repeat ซ้ำ"], "ans": 2, "exp": "Pleural effusion ที่ ADA สูง (> 40 U/L, ที่นี่ 50) ในผู้ป่วยไทยที่มี exudative lymphocytic effusion เข้าได้กับ tuberculous pleuritis อย่างมาก → เริ่ม anti-TB drug (ADA สูงมีความไวสูงในการวินิจฉัย TB pleuritis)."}, {"topic": "Pulmonology", "q": "20 years old male playing soccer then sudden has dyspnea and chest pain. CXR shows 1 cm of pneumothorax. What is the proper management?", "choices": ["oxygen therapy", "ICD", "Thoracentesis"], "ans": 0, "exp": "Primary spontaneous pneumothorax ขนาดเล็ก (1 ซม. < 2 ซม.) → ให้ oxygen therapy + observe (O2 ช่วยเร่งการดูดกลับของอากาศในเยื่อหุ้มปอด). ยังไม่ต้องใส่ ICD/aspiration ถ้าขนาดเล็กและอาการไม่มาก."}, {"topic": "Rheumatology", "q": "A 40-year-old woman present with chronic cough and mild dyspnea for 1 month. She had generalized skin thickening for 5 years. PE: Raynaud phenomenon at both fingers and toes, skin thickening at extremities, chest wall, abdomen. What is the most likely cause of pulmonary abnormality in this patient?", "choices": ["Pneumothorax", "Pulmonary fibrosis", "Pleural effusion", "Pulmonary nodule"], "ans": 1, "exp": "ผิวหนังหนาทั้งตัว + Raynaud = systemic sclerosis (scleroderma). ภาวะปอดที่พบบ่อยและเป็นสาเหตุอาการไอ/เหนื่อยเรื้อรังคือ interstitial lung disease → pulmonary fibrosis (ควรเฝ้าระวัง PAH ด้วย)."}, {"topic": "Hematology", "q": "A 50-year-old female with an underlying disease of acute myeloblastic leukemia was admitted for chemotherapy. Lab pre-chemotherapy: Hb 9, WBC 198,000 (N1 L1 blast98). Post-CMT Day 1, she developed oliguria (urine output = 50 ml/day) with creatinine rising from 1 to 2.5 mg/dL. Elyte: Na 140, K 6, Cl 100, HCO3 15, Ca 7.5, Alb 4, Phosphate 7. What is the most likely diagnosis?", "choices": ["Obstructive nephropathy", "Rhabdomyolysis", "Tumor lysis syndrome", "Drug induced nephropathy"], "ans": 2, "exp": "หลังให้ chemo ในมะเร็งที่ tumor burden สูง (blast 98%, WBC สูง) เกิด AKI + hyperK + hyperphosphatemia + hypocalcemia = tumor lysis syndrome (เซลล์มะเร็งแตกปล่อย K/PO4/uric acid). ป้องกัน/รักษาด้วย hydration + allopurinol/rasburicase + แก้ electrolyte."}, {"topic": "Hematology", "q": "A 16-year-old female presented with oral mucosal bleeding and hypermenorrhea. She has no family history of bleeding disorder. Lab: CBC - WNL (Plt normal); Coagulogram - PT 10, aPTT 33 correctable with mixing test. What is the most likely diagnosis?", "choices": ["Factor 7 deficiency", "Factor 8 inhibitor", "Factor 8 deficiency", "vWF deficiency", "Antiphospholipid syndrome"], "ans": 3, "exp": "เลือดออกแบบ mucocutaneous (เยื่อบุ + ประจำเดือนมาก) + platelet ปกติ + PT ปกติ + aPTT ยาวเล็กน้อยที่ correct ด้วย mixing (= ขาด factor ไม่ใช่ inhibitor) = von Willebrand disease (vWF พา factor VIII จึงทำ aPTT ยาวได้). *ต้นฉบับไฮไลต์ Factor 7 deficiency แต่ factor VII จะทำ PT ยาว (ที่นี่ PT ปกติ) จึงไม่ใช่*"}, {"topic": "Hematology", "q": "A 28-year-old female presented with dyspnea on exertion for 4 days. CBC: Hb 7, Hct 21, MCV 58. PBS: anisocytosis 2+ poikilocytosis 1+. Hb typing: homozygous Hb E. What is the cause of anemia in this patient?", "choices": ["Anemia of inflammation", "Iron deficiency anemia", "Pernicious anemia", "Autoimmune hemolytic anemia", "Hemoglobin E disease"], "ans": 4, "exp": "Hb typing เป็น homozygous Hb E → Hemoglobin E disease (microcytic anemia, MCV ต่ำ, target cell). เป็น hemoglobinopathy ที่พบบ่อยในไทย — ระวังอย่าให้ธาตุเหล็กเกินถ้าไม่ได้ขาดจริง.", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q24.png"}, {"topic": "Hematology", "q": "ชาย 20 ปี acute dyspnea on exertion, intermittent dark urine 3 months. CBC: Hb 6.2, MCV 68, Polychromasia 1+, Schistocyte 2+. What is the most likely diagnosis?", "choices": ["PNH", "AIHA", "G6PD", "HbH", "HS"], "ans": 0, "exp": "ปัสสาวะสีเข้มเป็นพัก ๆ (hemoglobinuria) เรื้อรังหลายเดือน + hemolysis (polychromasia, schistocyte) = paroxysmal nocturnal hemoglobinuria (PNH). การเสีย hemoglobin/iron ทางปัสสาวะเรื้อรังทำให้ MCV ต่ำได้. วินิจฉัยด้วย flow cytometry (CD55/CD59)."}, {"topic": "Hematology", "q": "หญิง มาด้วย bleed เยอะ ประจำเดือนมาเยอะ ส่ง CBC เจอ isolated thrombocytopenia ส่งอะไรต่อ", "choices": ["Bleeding time", "Anti HIV Anti HCV", "Bone marrow aspiration"], "ans": 1, "exp": "หญิงสาว isolated thrombocytopenia นึกถึง ITP ซึ่งเป็น diagnosis of exclusion — ควรคัดกรองสาเหตุ secondary ก่อน โดยส่ง anti-HIV, anti-HCV (เป็นสาเหตุ secondary ITP ที่พบบ่อย). Bone marrow ไม่จำเป็นในคนอายุน้อยที่ line อื่นปกติ."}, {"topic": "Hematology", "q": "A 68-year-old woman presents with dyspnea on exertion 4 months PTA. She had gait ataxia and paresthesia. PE: marked pallor, no jaundice, no hepatosplenomegaly, loss of proprioception and vibration test. CBC: Hb 6.8, Hct 20.4, MCV 115, RDW 24, WBC 3500 (N 53, L 35), Plt 85,000. What is diagnosis?", "choices": ["Acute leukemia", "Aplastic anemia", "Cobalamin deficiency", "Folate deficiency", "Paroxysmal Nocturnal Hemoglobinuria"], "ans": 2, "exp": "Macrocytic anemia (MCV 115) + อาการทางระบบประสาทของ dorsal column (สูญเสีย proprioception/vibration, gait ataxia = subacute combined degeneration) + mild pancytopenia = vitamin B12 (cobalamin) deficiency. Folate ขาดจะไม่มีอาการทางประสาท. *ต้นฉบับไฮไลต์ PNH ซึ่งไม่เข้ากับ macrocytosis + neuro sign*"}, {"topic": "Hematology", "q": "70 yo Female patient with paresthesia. CBC: MCV 110. What is the diagnosis?", "choices": ["Folate deficiency", "Cobalamin deficiency"], "ans": 1, "exp": "Macrocytic anemia (MCV 110) + paresthesia (อาการทางประสาท) = vitamin B12 (cobalamin) deficiency (subacute combined degeneration). Folate deficiency ให้ภาพ megaloblastic เหมือนกันแต่ไม่มีอาการทางประสาท."}, {"topic": "Hematology", "q": "หญิงไทย มาด้วย mucosal bleeding, มีประวัติ recurrent mucosal bleeding มาก่อน ไม่มีประวัติคนในครอบครัวเป็น bleeding disorder. Lab: Hct 12.5%, WBC 4500, Plt 222,000, Coag PT normal, aPTT prolong, Correct by mixing study. What is diagnosis?", "choices": ["VwD disease", "Factor VII deficiency", "Factor VIII Inhibitor", "Hemophilia"], "ans": 0, "exp": "เลือดออกเยื่อบุซ้ำ ๆ + platelet ปกติ + PT ปกติ + aPTT ยาวที่ correct ด้วย mixing (ขาด factor ไม่ใช่ inhibitor) + ไม่มีประวัติครอบครัว/เป็นหญิง = von Willebrand disease. (Hemophilia = X-linked ในผู้ชาย เลือดออกในข้อ/กล้ามเนื้อ; Factor VII จะทำ PT ยาว)."}, {"topic": "GI/Hepatology", "q": "A 60-year-old male came to the ER because of hematemesis. He has a history of alcohol drinking. BP 100/70 mmHg. PE: GA - Drowsiness; Abdomen - spider nevi, palmar erythema, splenomegaly, ascites. NG content is 200ml fresh blood, Hct 25%. After fluid resuscitation, what is next management?", "choices": ["EGD", "Cold NSS lavage", "Transamine", "Plasma transfusion", "Sengstaken blakemore"], "ans": 0, "exp": "Cirrhosis (spider nevi, palmar erythema, ascites) + hematemesis = variceal bleeding. หลัง resuscitation ขั้นถัดไปคือ EGD เพื่อวินิจฉัยและทำ endoscopic band ligation (ร่วมกับ vasoactive drug + prophylactic antibiotic). *ต้นฉบับไฮไลต์ Sengstaken-Blakemore ซึ่งเป็นแค่ balloon tamponade ชั่วคราวเมื่อ endoscopy คุมไม่ได้ ไม่ใช่ขั้นแรก*"}, {"topic": "GI/Hepatology", "q": "A 25-year-old man presented with acute abdominal pain and nausea/vomiting for 1 day. Previously, he took NSAIDs for his migraine and drank 2 cans of beer once a week. PE: BT 38°C, epigastric pain, eruptive xanthoma both ankles. What is the most likely etiology of his illness?", "choices": ["NSAIDs", "Hypertriglyceridemia", "Gallstone", "Hypercholesterolemia", "Alcohol"], "ans": 1, "exp": "Acute pancreatitis (ปวด epigastrium + N/V + ไข้) + eruptive xanthoma (สัญญาณของ triglyceride สูงมาก) → สาเหตุคือ hypertriglyceridemia (TG มัก> 1000). Eruptive xanthoma เป็นเบาะแสสำคัญของ severe hypertriglyceridemia."}, {"topic": "Cardiology", "q": "A 50-year-old male with poor controlled HT presented with a severe progressive chest pain radiating to back 1 hr PTA. PE: pulse regular (upper 2+ lower 1+), BP 100/80 mmHg. What is the diagnosis?", "choices": ["Acute pericarditis", "Acute MI", "Aortic dissection", "PE", "Acute pancreatitis"], "ans": 2, "exp": "เจ็บอกรุนแรงร้าวไปหลัง + ประวัติ HT คุมไม่ดี + ชีพจร/ความดันแขน-ขาไม่เท่ากัน (upper 2+ lower 1+) = aortic dissection. ยืนยันด้วย CT angiography; รักษาคุม HR/BP (beta-blocker) และผ่าตัดถ้า type A."}, {"topic": "GI/Hepatology", "q": "A 50-year-old female with underlying disease of T2DM had a fever and abdominal pain for 3 wks. PE: V/S - BT 38.3°C, P 100 bpm, RR 20/min, BP 130/80 mmHg; Abdomen - mild jaundice, tenderness at RUQ, Murphy's sign negative, liver 2 cm BRCM, liver span 12 cm, impalpable spleen. Lab: Albumin 3, Globulin 4, TB 4, DB 2.2, AST 248, ALT 310, ALP 386. What is the next appropriate management?", "choices": ["Melioid titer", "H/C", "E. histolytica titer", "U/S upper abd", "MRI/MRCP"], "ans": 3, "exp": "ไข้เรื้อรัง 3 สัปดาห์ + RUQ pain + ตับโตกดเจ็บ + ตัวเหลือง + enzyme ตับขึ้น ในผู้ป่วยเบาหวาน → สงสัย liver abscess/โรคทางเดินน้ำดี. ขั้นถัดไปที่เหมาะสมและทำง่ายคือ ultrasound upper abdomen เพื่อหา abscess/ท่อน้ำดีอุดตันก่อนตรวจอื่น."}, {"topic": "Pulmonology", "q": "Case: 55 yo Thai lady suspected CA pancreas. CC: 3hr PTA chest tightness. V/S: BT 37.8, PR 110 bpm, BP 110/70, O2 sat 90% RA, JVP 5cm, others wnl. EKG: Sinus tachycardia. Initial management? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["IV fluid loading", "ASA + Nitrate", "Thrombolytics", "Observe and repeat EKG in 12h", "LMWH (anticoagulation)"], "ans": 4, "exp": "มะเร็ง (hypercoagulable) + เหนื่อย/แน่นอกเฉียบพลัน + tachycardia + hypoxia (SpO2 90%) + sinus tachy = pulmonary embolism. ผู้ป่วยยัง hemodynamic คงที่ → รักษาด้วย anticoagulation (LMWH). thrombolytics เฉพาะ massive PE ที่ช็อก. *ต้นฉบับไม่มีตัวเลือก — แต่งขึ้นตามแนวข้อคล้ายกันในชุดนี้*"}, {"topic": "Hematology", "q": "A young man presented with dark urine and jaundice. A few days ago, he had URI symptoms. PBS as in picture. What is the diagnosis? (ต้นฉบับตัวเลือกไม่ครบ — ใส่เท่าที่มี)", "choices": ["G6PD deficiency", "Thalassemia"], "ans": 0, "exp": "ภาวะเม็ดเลือดแดงแตกเฉียบพลันหลังติดเชื้อ (URI) + ปัสสาวะเข้ม + ตัวเหลือง = G6PD deficiency (oxidative hemolysis ที่ถูกกระตุ้นด้วยการติดเชื้อ/ยา/ถั่วปากอ้า) — PBS พบ bite cell และ Heinz body."}, {"topic": "GI/Hepatology", "q": "A 40-year-old male presented with epigastric pain & burning sensation for 8 weeks. Symptoms are relieved by omeprazole & simethicone. He has a weight loss of 5 kg. PE: stable v/s, mild pale conjunctiva, mild epigastric distension, otherwise normal. What is the most appropriate management?", "choices": ["Urea breath test", "Gastroduodenoscopy", "Stool occult blood", "Switch omeprazole to pantoprazole", "CT upper abdomen"], "ans": 1, "exp": "Dyspepsia ที่มี alarm features (น้ำหนักลด 5 กก., ซีด/pale conjunctiva) → ต้องส่อง gastroduodenoscopy (EGD) เพื่อตัดมะเร็งกระเพาะ/แผล. ไม่ใช่แค่ปรับยาหรือ urea breath test."}, {"topic": "GI/Hepatology", "q": "A 50 years old male came to the hospital for a regular check up. PE: mild pale conjunctiva, dull splenic positive (splenomegaly), left lobe liver just palpate. Lab: CBC - Hb 9, MCV 100, Plt 80,000; LFT - Albumin 3, Globulin 5, AST 85, ALT 62, ALP 102. What is the most likely diagnosis?", "choices": ["Fatty liver", "Hypersplenism", "Cirrhosis", "Hb H", "Vit. 12 def."], "ans": 2, "exp": "Anemia + thrombocytopenia (Plt 80,000) + splenomegaly + hepatomegaly + A/G reversed (Alb 3 ต่ำ Globulin 5 สูง) + transaminase ขึ้นเล็กน้อย = chronic liver disease → cirrhosis ที่มี portal hypertension/hypersplenism (ทำให้ cytopenia). *ต้นฉบับไฮไลต์ Fatty liver แต่ fatty liver ไม่ทำให้ม้ามโต/เกล็ดเลือดต่ำ/globulin สูง*"}, {"topic": "GI/Hepatology", "q": "A 45-year-old man presents with acute sharp epigastric pain. He has a history of NSAIDs use due to back pain. PE: V/S - BT 37.2°C, PR 120 bpm, RR 24/min, BP 140/90 mmHg; GA - agitated and sweating; Abdomen - marked tenderness at upper abdomen, loss of hepatic dullness. What is the initial investigation?", "choices": ["serum amylase", "ultrasound abdomen", "CT abdomen", "acute abdomen series", "CTA whole aorta"], "ans": 3, "exp": "ประวัติ NSAIDs + ปวดท้องเฉียบพลัน + loss of hepatic dullness = สงสัย perforated peptic ulcer (มี free air). การตรวจเบื้องต้นคือ acute abdomen series (upright CXR/abdomen film) เพื่อดู free air ใต้กระบังลม."}, {"topic": "GI/Hepatology", "q": "A female came in for a check up. PE: liver span 11 cm, normal เกือบหมด ยกเว้น AST 260, ALT 120, ALP 100. Dx?", "choices": ["Fatty liver", "Drug induced hepatitis", "Alcoholic hepatitis", "Chronic viral hepatitis"], "ans": 2, "exp": "AST 260 > ALT 120 (AST:ALT ≈ 2:1) โดยค่าไม่สูงมาก (< 300) = ลักษณะเฉพาะของ alcoholic hepatitis. (Fatty liver/NAFLD มักมี ALT > AST; viral hepatitis มัก ALT สูงเด่น). ควรถามประวัติดื่มสุราประกอบ"}, {"topic": "Neurology", "q": "A 50-year-old alcoholic man presents with acute confusion. DTX 45 mg/dl. What is the most appropriate initial management?", "choices": ["Thiamine", "Serum blood sugar", "Repeat DTX", "50% Glucose bolus", "Serum electrolyte"], "ans": 0, "exp": "ผู้ป่วยติดสุรา + hypoglycemia (DTX 45) + สับสน — ต้องให้ thiamine ก่อน/พร้อมกับ glucose เพื่อป้องกัน Wernicke encephalopathy (การให้ glucose ก่อนในคนขาด thiamine อาจกระตุ้นให้เกิด Wernicke). จึงเริ่มด้วย thiamine."}, {"topic": "GI/Hepatology", "q": "หญิง 20 ปี รักษา acne vulgaris อยู่ มาด้วย chest pain when swallow กับมี occasional heart burn ไม่สัมพันธ์กับ exertion ไม่มี sign ของ hypovolemia, V/S stable, ตรวจร่างกายปกติหมด. ถาม most proper investigation?", "choices": ["EKG 12 lead", "Barium esophagography", "24 hr pH monitor", "CXR AP Lat", "Esophageal manometry"], "ans": 1, "exp": "หญิงสาวกินยารักษาสิว (มัก doxycycline) + เจ็บอกเวลากลืน (odynophagia) + แสบยอดอก ไม่สัมพันธ์การออกแรง = pill-induced esophagitis/โรคหลอดอาหาร. ในตัวเลือกนี้ barium esophagography ใช้ประเมินหลอดอาหาร (แผล/ตีบ) ได้. *ที่จริง endoscopy (EGD) เหมาะสุดแต่ไม่มีในตัวเลือก*"}, {"topic": "GI/Hepatology", "q": "เป็น GERD ถามควรกินอะไร (อาหารที่เหมาะกับผู้ป่วย GERD)", "choices": ["Vegetables with chilli pepper", "Sausage with tomato sauces", "Pancake with honey syrup", "Fried (ของทอด)"], "ans": 2, "exp": "GERD ควรเลี่ยงอาหารกระตุ้นกรด/คลายหูรูด: เผ็ด (พริก), มะเขือเทศ/ซอสเปรี้ยว, ของทอด/ไขมันสูง, ช็อกโกแลต, คาเฟอีน. ในตัวเลือกนี้ pancake ราดน้ำผึ้งกระตุ้นน้อยที่สุด."}, {"topic": "GI/Hepatology", "q": "ผู้ชายอายุ 55 ปี สุขภาพดีมาตลอด มาตรวจสุขภาพ V/S stable, LFT: TP 7, Alb 3.5, TB 0.8, DB 0.2, AST 260, ALT 127, ALP 102. เป็นอะไร", "choices": ["Fatty liver", "Autoimmune hepatitis", "Chronic HBV hepatitis", "Alcoholic hepatitis", "Drug-induced hepatitis"], "ans": 3, "exp": "AST 260 > ALT 127 (ratio ≈ 2:1) ค่าไม่สูงมาก = alcoholic hepatitis (จุดสำคัญคือ AST:ALT > 2:1). *ต้นฉบับไฮไลต์ Fatty liver — ซึ่งมักให้ ALT > AST; ถ้าไม่มีประวัติสุราจริงค่อยพิจารณา NAFLD*"}, {"topic": "GI/Hepatology", "q": "A previous healthy 50-year-old came for health checkup. V/S: BT 37, PR 98, RR 16, BP 130/80 mmHg. PE: Liver 1 FB BRCM (liver span 14 cm), others unremarkable. Lab: LFT - TP 7, TB 0.8, DB 0.4, AST 267, ALT 127, ALP 102, other investigations WNL. What is the most likely diagnosis?", "choices": ["Fatty liver", "AIH", "Drug induced hepatitis", "Chronic viral hepatitis B", "Alcoholic hepatitis"], "ans": 4, "exp": "ตับโต (span 14 ซม.) + AST 267 > ALT 127 (AST:ALT ≈ 2:1) = alcoholic hepatitis. รูปแบบ AST เด่นกว่า ALT ~2 เท่าเป็นเบาะแสสำคัญของภาวะจากสุรา."}, {"topic": "Nephrology", "q": "A 60-year-old male presents with acute dyspnea. PE: BP 180/110 mmHg, Lung - crepitation, Extremities - pitting edema. ให้ IV Furosemide ไปแล้ว ต้องให้อะไรเพิ่ม?", "choices": ["nitroprusside", "labetalol", "amlodipine", "hydralazine", "nitroglycerine"], "ans": 0, "exp": "Acute pulmonary edema + hypertensive emergency (180/110) → หลัง diuretic ต้องให้ vasodilator ลด afterload/preload อย่างรวดเร็ว. Nitroprusside (ขยายทั้ง artery+vein) ลด afterload ได้ดีในภาวะความดันสูงมาก. *nitroglycerine ก็ใช้ได้ (เน้นลด preload) และมักเลือกใน pulmonary edema เช่นกัน*"}, {"topic": "Endocrinology", "q": "A 70-year-old female presented with alteration of consciousness (ซึม). PE: V/S - BP 120/80 mmHg; Neuro - drowsiness. Elyte: Ca 18. What is the next appropriate management?", "choices": ["NSS + furosemide", "Calcitonin + pamidronate", "NSS + pamidronate", "Calcitonin + furosemide", "Hemodialysis"], "ans": 1, "exp": "Hypercalcemic crisis (Ca 18 + ซึม) ต้องลด Ca เร็ว: calcitonin (ออกฤทธิ์เร็วใน 2-4 ชม.) + bisphosphonate (pamidronate, ฤทธิ์นานแต่ช้า) — จึงเลือก calcitonin + pamidronate. *สำคัญ: ต้องให้ IV isotonic saline hydration ควบคู่เสมอ; furosemide ไม่แนะนำ routine; hemodialysis สงวนไว้กรณีไตวาย/ดื้อการรักษา*"}, {"topic": "Nephrology", "q": "A 25 years old man presented with generalized edema for 2 months. PE: BP 110/70 mmHg, puffy eyelids, pitting edema 4+. Labs: UA - Protein 4+, RBC 0-1, WBC 0-1; 24 hrs protein 8 g; Blood chem - Albumin 2, Cholesterol 450, Creatinine 0.8. What is the diagnosis?", "choices": ["IgA nephropathy", "Membranous nephropathy", "Minimal change disease", "Focal segmental", "Membrano-proliferative glomerulonephritis"], "ans": 2, "exp": "Nephrotic syndrome (proteinuria > 3.5 g/วัน [8 g], hypoalbuminemia [2], hyperlipidemia [chol 450], edema) + urine sediment สะอาด (ไม่มี RBC/WBC) ในคนอายุน้อย (25 ปี) = minimal change disease (สาเหตุ nephrotic ที่พบบ่อยในเด็ก/วัยรุ่น, ตอบสนอง steroid ดี). IgA/MPGN มักมี hematuria."}, {"topic": "Endocrinology", "q": "A 13-year-old girl presented with acanthosis nigricans, no nocturia, no weight loss. BW 70 kg, HT 150 cm, FBS 105, HbA1C 6. What should be done next?", "choices": ["Leptin level", "Insulin level", "C-Peptide Level", "Oral glucose tolerance test", "Anti-GAD"], "ans": 3, "exp": "เด็กอ้วน + acanthosis nigricans (insulin resistance) + FBS 105 (impaired fasting glucose) + HbA1c 6 (prediabetes) — ขั้นถัดไปเพื่อยืนยันเบาหวาน/IGT คือ oral glucose tolerance test (75 g OGTT)."}, {"topic": "Endocrinology", "q": "A 70-year-old female, U/D Grave's disease s/p radioactive iodine ablation, presented with hoarseness, slow thinking and weight gain for 3 months. Which parameter is the most sensitive in this patient?", "choices": ["FreeT3", "FreeT4", "Thyroid antibody", "Thyroid anti globin", "TSH"], "ans": 4, "exp": "หลัง RAI ablation มักเกิด hypothyroidism (เสียงแหบ คิดช้า น้ำหนักขึ้น). ใน primary hypothyroidism ค่าที่ไวที่สุด (เปลี่ยนก่อนและมากสุด) คือ TSH (สูงขึ้น)."}, {"topic": "Neurology", "q": "A 56-year-old male with U/D tetraplegia (quadriplegia) presents with paroxysmal throbbing headache and intermittent hypertension. PE: V/S - BT 36.5°C, BP 150/100 mmHg, PR 50 bpm, RR 20/min; GA - flushing and sweating. After bed rest for 30 minutes BP 150/100 mmHg. What is the diagnosis?", "choices": ["Autonomic dysreflexia", "Anxiety disorder", "Pheochromocytoma", "Migraine headache", "Essential hypertension"], "ans": 0, "exp": "ผู้ป่วยบาดเจ็บไขสันหลัง (tetraplegia, รอยโรคเหนือ T6) + ปวดหัวเป็นพัก ๆ + ความดันพุ่ง + หน้าแดง/เหงื่อออก + หัวใจเต้นช้า (reflex bradycardia) = autonomic dysreflexia (สิ่งกระตุ้นใต้รอยโรค เช่นปัสสาวะคั่ง → sympathetic surge). *ต้นฉบับไฮไลต์ Migraine ซึ่งไม่อธิบาย HT/flushing/bradycardia*"}, {"topic": "Endocrinology", "q": "A 52-year-old woman presented with abdominal discomfort, bloating and flatulence for a month. She had a history of type 2 DM and was on multiple oral hypoglycemic drugs. Which drug can cause this side effect?", "choices": ["Glipizide", "Acarbose", "Metformin", "Pioglitazone", "Sitagliptin"], "ans": 1, "exp": "ท้องอืด/มีลมมาก (bloating, flatulence) เป็นผลข้างเคียงเด่นของ acarbose (alpha-glucosidase inhibitor) เพราะยับยั้งการย่อยแป้ง → น้ำตาลไปหมักที่ลำไส้ใหญ่เกิดแก๊ส."}, {"topic": "Endocrinology", "q": "A female with U/D of Grave's disease on MMI for 6 months visits the hospital for her first ANC. Her LMP was 8 weeks. She is clinically stable with normal TFT. What is the best management?", "choices": ["Discontinue MMI", "Increase dose MMI", "Switch to PTU", "Decrease dose MMI", "Continue MMI ตามเดิม"], "ans": 2, "exp": "ตั้งครรภ์ไตรมาสแรก (LMP 8 สัปดาห์) ที่ใช้ methimazole (MMI) → ควรเปลี่ยนเป็น PTU เพราะ MMI ในไตรมาสแรกเสี่ยง teratogenic (aplasia cutis, choanal/esophageal atresia). (หลังไตรมาสแรกมักเปลี่ยนกลับเป็น MMI เพราะ PTU เสี่ยงตับ)"}, {"topic": "Neurology", "q": "A 60 years old male, U/D DMT2, active smoking, on metformin/simvastatin/enalapril, presented with Rt hemiparesis, BP 200/100. CT: hypodense lesion at Lt internal capsule. Lab: FBS 120, LDL 110, Cr 0.8. What is the most appropriate management?", "choices": ["rTPA", "Warfarin", "Nicardipine IV", "change simvastatin to atorvastatin", "Add glipizide"], "ans": 3, "exp": "Ischemic stroke ที่ CT เห็น hypodense lesion แล้ว (= infarct เกิดขึ้นชัด/พ้นหน้าต่าง) → ไม่ให้ rtPA. BP 200/100 ยังไม่เกิน 220/120 จึงไม่ลด (permissive HT). การจัดการที่เหมาะคือ secondary prevention → เปลี่ยนเป็น high-intensity statin (atorvastatin) + antiplatelet + คุมปัจจัยเสี่ยง."}, {"topic": "Endocrinology", "q": "ผู้หญิง 20 ปี shaking hand, palpitation, ก่อนหน้านั้นมีไข้ เจ็บ anterior neck, V/S ปกติ, thyroid enlargement 25g, no bruit, กดไม่เจ็บ. ถาม management", "choices": ["MMI", "Propranolol", "PTU"], "ans": 1, "exp": "ไข้นำมาก่อน + เจ็บบริเวณต่อมไทรอยด์ + thyrotoxicosis (มือสั่น ใจสั่น) = subacute (de Quervain) thyroiditis (หลังติดเชื้อไวรัส). thyrotoxicosis เกิดจากต่อมถูกทำลายปล่อยฮอร์โมนออกมา ไม่ใช่การสร้างเกิน → รักษาตามอาการด้วย propranolol (+ NSAID) ไม่ใช้ยาต้านไทรอยด์ (MMI/PTU)."}, {"topic": "Endocrinology", "q": "ผู้ป่วยมี น้ำตาลต่ำ, Na ต่ำ, K สูง, BP ตก (adrenal crisis). ให้อะไร", "choices": ["Hydrocortisone", "Fluticasone"], "ans": 0, "exp": "Hypoglycemia + hyponatremia + hyperkalemia + hypotension = adrenal insufficiency/crisis → ให้ IV hydrocortisone ทันที (glucocorticoid + mineralocorticoid effect). Fluticasone เป็น steroid สูดพ่นเฉพาะที่ ใช้ไม่ได้."}, {"topic": "Endocrinology", "q": "DKA มา load NSS 500 ไม่ให้แลปอะไรมาเลย ถามว่าทำอะไรต่อ", "choices": ["IV+KCl", "NSS ต่อ", "Insulin"], "ans": 1, "exp": "DKA ลำดับการรักษา: IV fluid resuscitation ก่อน (ยังขาดน้ำมาก) และต้องรู้ระดับ K ก่อนเริ่ม insulin (ถ้า K < 3.3 ต้องเติม K ก่อน). เมื่อยังไม่มีผลแลป → ให้ continue NSS resuscitation + ส่งแลปก่อน ยังไม่รีบให้ insulin/KCl แบบไม่รู้ค่า."}, {"topic": "Infectious disease", "q": "A 36-year-old man with chronic alcohol drinking presented with fever, pain and skin lesions (hemorrhagic bullae) for one day PTA. He had signs of chronic liver disease. Recently, he had seafood. PE: V/S - BT 39°C, BP 90/60 mmHg, PR 120 bpm; Abd - palmar erythema, spider nevi, superficial vein dilate. What is the causative pathogen?", "choices": ["Streptococcus pyogenes", "Staphylococcus aureus", "Vibrio vulnificus", "Aeromonas hydrophila", "Clostridium perfringens"], "ans": 2, "exp": "Cirrhosis (spider nevi, palmar erythema) + กินอาหารทะเล + hemorrhagic bullae ลุกลามเร็ว + sepsis = Vibrio vulnificus (พบในผู้ป่วยตับแข็ง/ภูมิคุ้มกันบกพร่องหลังสัมผัสน้ำทะเล/อาหารทะเลดิบ → necrotizing soft tissue infection + septic shock).", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q55.png"}, {"topic": "Infectious disease", "q": "A man came to ask about his hepatitis serology profile. His result is HBsAg: negative, anti-HBs: negative, anti-HBc: positive. What is your advice?", "choices": ["HBV vaccine", "Lamivudine", "Anti-HDV", "Reassurance"], "ans": 3, "exp": "Isolated anti-HBc (HBsAg−, anti-HBs−, anti-HBc+) ในประเทศที่ HBV ชุก (ไทย) ส่วนใหญ่หมายถึง resolved/past infection (anti-HBs หายไปตามเวลา) — ถือว่าเคยติดและหายแล้ว จึงให้ reassurance (ไม่ใช่ active infection, ไม่ต้อง lamivudine; anti-HDV ตรวจเฉพาะเมื่อ HBsAg+). *ต้นฉบับไฮไลต์ Anti-HDV ซึ่งไม่ถูกต้อง; บางแนวทางพิจารณาให้ HBV vaccine challenge เพื่อดู immunity*"}, {"topic": "Infectious disease", "q": "A 19-year-old male who has a history of visiting a national park, presents with fever and malaise. PE: V/S - BT 39°C others are normal; Skin - 8 mm oval lesion with black scale and central crust (eschar) at inguinal area. What is the most likely complication from this condition?", "choices": ["Toxic shock syndrome", "Intravascular sequestration", "Splenic rupture", "Hypoglycemia", "Aseptic meningitis"], "ans": 4, "exp": "ไข้ + eschar (แผลสะเก็ดดำ) หลังเข้าป่า/อุทยาน = scrub typhus (Orientia tsutsugamushi). ภาวะแทรกซ้อนที่พบได้คือ meningoencephalitis (aseptic meningitis) รวมถึง ARDS/AKI/myocarditis. (Intravascular sequestration/hypoglycemia เป็นของ malaria; splenic rupture ของ EBV/typhoid)"}, {"topic": "Infectious disease", "q": "Melioidosis — ส่ง Investigation อะไรเพื่อ confirm", "choices": ["Hemoculture", "Melioid titer", "HAV IgM"], "ans": 0, "exp": "การวินิจฉัยยืนยัน melioidosis (Burkholderia pseudomallei) มาตรฐานคือ culture (เลือด/หนอง/สารคัดหลั่ง) → hemoculture. Serology (titer) มีความจำเพาะต่ำในพื้นที่ระบาด."}, {"topic": "Infectious disease", "q": "A 50-year-old female U/D Type 2 DM presents with fever and abdominal pain for 2 weeks. V/S: BT 40°C. LFT: TB 5, DB 4, AST 120, ALT 140, ALP 400. U/S: Multiple hypoechoic lesions in liver and spleen. ถามเชื้อที่เป็น etiology", "choices": ["Enterobacter", "Burkholderia pseudomallei", "Klebsiella", "Pseudomonas", "TB"], "ans": 1, "exp": "ผู้ป่วยเบาหวานในไทย + ไข้เรื้อรัง + ฝีหลายจุดทั้งใน ตับและม้าม (multiple hepatosplenic microabscesses) = melioidosis (Burkholderia pseudomallei) ซึ่งเป็นลักษณะเฉพาะ. *ต้นฉบับไฮไลต์ Klebsiella ซึ่งมักเป็นฝีตับก้อนเดี่ยว ไม่ค่อยลามไปม้าม*"}, {"topic": "Infectious disease", "q": "ชาย 26 ปี HIV positive มาด้วยปวดหัว, nausea, ตามัว, stiff neck positive. CT: no space occupying lesion. What is the diagnosis?", "choices": ["Toxoplasmosis", "Bact. meningitis", "Crypto meningitis", "HSV encephalitis", "CMV encephalitis"], "ans": 2, "exp": "HIV + ปวดหัว + คลื่นไส้ + ตามัว (raised ICP) + คอแข็ง + CT ไม่มี mass = cryptococcal meningitis (Cryptococcus neoformans, พบเมื่อ CD4 < 100, ทำให้ ICP สูง). Toxoplasmosis จะเห็น ring-enhancing lesion บน CT (มี SOL) ซึ่งข้อนี้ไม่มี."}, {"topic": "Infectious disease", "q": "A 70-year-old patient has been admitted with pneumonia and receives ceftriaxone for 10 days. Later, the patient develops watery diarrhea and fever. V/S: BT 38°C, BP 110/70 mmHg. C. diff toxin: positive. What is the most appropriate management? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Oral metronidazole", "Loperamide (antimotility)", "Continue ceftriaxone", "Oral vancomycin", "IV ciprofloxacin"], "ans": 3, "exp": "Antibiotic-associated diarrhea + C. difficile toxin positive = C. difficile infection. รักษา first-line ด้วย oral vancomycin (หรือ fidaxomicin) และหยุด antibiotic ต้นเหตุ (ceftriaxone). metronidazole เป็นทางเลือกรอง; หลีกเลี่ยง antimotility (loperamide) เพราะเสี่ยง toxic megacolon."}, {"topic": "Infectious disease", "q": "ผู้ป่วยกินอาหารมา มี clinical เป็น diarrhea แล้วต่อมากลายเป็น HUS (hemolytic uremic syndrome) ถามว่าน่าจะกินอะไรมา", "choices": ["Sushi", "Foie Gras", "Soft boiled egg", "Pork Chop", "Beef burger"], "ans": 4, "exp": "ท้องเสียแล้วตามด้วย HUS (MAHA + thrombocytopenia + AKI) เกิดจาก Shiga toxin-producing E. coli O157:H7 ซึ่งพบใน เนื้อวัวปรุงไม่สุก (hamburger/beef burger). *หลีกเลี่ยง antibiotic/antimotility เพราะเพิ่มการปล่อย toxin*"}, {"topic": "Infectious disease", "q": "A 15 years old girl presents with a painful genital ulcer. G/S: gram-negative coccobacilli in parallel rows (school of fish). What is the treatment?", "choices": ["Azithromycin", "Cefdinir", "Doxycycline"], "ans": 0, "exp": "แผลอวัยวะเพศที่ เจ็บ + gram-negative coccobacilli เรียงตัวแบบ school of fish = chancroid (Haemophilus ducreyi). รักษาด้วย azithromycin (single dose) หรือ ceftriaxone/ciprofloxacin. (ต่างจาก syphilis ที่แผลไม่เจ็บ)"}, {"topic": "Infectious disease", "q": "An elderly male, U/D ESRD on regular HD, presents with clinical pneumonia c sepsis. Film: Bilateral opacity infiltration. ถาม causative agents", "choices": ["B.cepacia complex", "P.aeruginosa", "Influenza", "CMV"], "ans": 1, "exp": "ผู้ป่วย ESRD ที่ฟอกเลือดประจำ = กลุ่ม healthcare-associated → pneumonia c sepsis จากเชื้อ gram-negative ที่พบบ่อยคือ Pseudomonas aeruginosa. ควรเลือก empiric ATB ที่คลุม Pseudomonas."}, {"topic": "Neurology", "q": "Male 20 ปี present with behavior change with convulsion for 1 day. He has severe headache for 3 days. PE: BT 38.9°C, BP 140/80 mmHg, PR 98/min, Drowsiness, Stiffness of neck positive, No neurodeficit, otherwise unremarkable. LP: Numerous RBC with xanthochromia, WBC 20, protein 80, CSF glucose:plasma glucose ratio = 0.4. Diagnosis?", "choices": ["Rupture aneurysm", "Cryptococcal meningitis", "Herpes encephalitis", "TB meningoencephalitis", "Meningococcal meningitis"], "ans": 2, "exp": "พฤติกรรมเปลี่ยน + ชัก + ไข้ + ปวดหัว + CSF มี RBC/xanthochromia (จาก hemorrhagic necrosis ของ temporal lobe) = herpes simplex encephalitis. ต้องเริ่ม IV acyclovir ทันทีโดยไม่รอผล PCR. (Rupture aneurysm/SAH ไม่มีไข้+behavior change+ชัก)"}, {"topic": "Neurology", "q": "A previously healthy 40 YOM present with fever, chill and severe diffuse headache for 3 days. BT 40, PR 120, RR 20, BP 100/70 mmHg, Positive neck stiffness and papilledema, other neurological normal. After blood drawn for investigation, which of the following is appropriate initial management?", "choices": ["LP", "CT brain with contrast", "NSS loading", "IV antibiotic", "IV dexamethasone"], "ans": 3, "exp": "สงสัย bacterial meningitis + มี papilledema (ICP สูง) → ห้าม LP ก่อน (เสี่ยง herniation) ต้อง CT ก่อน LP. แต่ห้ามหน่วงการรักษา — หลังเจาะ hemoculture แล้ว ให้ empiric IV antibiotic (พร้อม/ก่อนหน้าด้วย dexamethasone) ทันที แล้วค่อยทำ CT → LP. *dexamethasone ควรให้ก่อน/พร้อม dose ATB แรก*"}, {"topic": "Pediatrics", "q": "A 3 years old patient presented with fever and dysuria. PE: V/S BT 38.9°C, PR 110, RR 30, BP 90/60 mmHg. UA: WBC 30-50, RBC 5-10, nitrite 1+, Epi 1-2. Which of the following is the lab which able to confirm her diagnosis?", "choices": ["E.coli 10^4 from midstream urine", "E.coli 10^3 from urine catheterization", "E.faecalis 10^3 from urine catheterization", "S.saprophyticus 10^3 from urine catheterization", "E.coli 10^1 from suprapubic aspiration"], "ans": 4, "exp": "เกณฑ์ยืนยัน UTI ตามวิธีเก็บปัสสาวะ: suprapubic aspiration = พบเชื้อ uropathogen ปริมาณเท่าใดก็ตามถือว่ามีความหมาย (กระเพาะปัสสาวะปกติปลอดเชื้อ) จึง E.coli จาก SPA = confirm ได้. Midstream ต้อง ≥ 10^5, catheterization ต้อง ≥ 10^4 จึงไม่เข้าเกณฑ์."}, {"topic": "Infectious disease", "q": "HIV patient with fever, multiple stage vesicles on trunk and extremities, develops dyspnea. PE: lung - fine crepitation. What is the management?", "choices": ["IV acyclovir + steroids", "oral acyclovir"], "ans": 0, "exp": "HIV (immunocompromised) + ตุ่มน้ำหลายระยะกระจายทั้งตัว (disseminated varicella) + ปอดอักเสบ (varicella pneumonia, visceral involvement) → ต้องให้ IV acyclovir (ไม่ใช่ oral) เพราะเป็น disseminated/visceral disease ในคนภูมิคุ้มกันต่ำ."}, {"topic": "Cardiology", "q": "Patient has low grade fever, dry cough, weight loss, clear lung sound, normal S1S2, pericardial friction rub. What is the management for this complication (TB pericarditis)?", "choices": ["ASA", "Prednisolone", "ibuprofen"], "ans": 1, "exp": "ภาพเข้าได้กับ TB pericarditis. การให้ adjunctive corticosteroid (prednisolone) ช่วยลดการเกิด constrictive pericarditis ในระยะยาว (ควบคู่กับ anti-TB). NSAID/ASA ใช้ใน viral/idiopathic pericarditis มากกว่า."}, {"topic": "Infectious disease", "q": "Patient with genital ulcer, shallow, painful, Gram stain shows gram negative coccobacilli in school of fish pattern (H. ducreyi). What is proper management?", "choices": ["Cefdinir", "Amoxicillin", "Levofloxacin"], "ans": 2, "exp": "Chancroid (Haemophilus ducreyi). ยาที่ใช้ได้: azithromycin, ceftriaxone, ciprofloxacin/fluoroquinolone, erythromycin. ในตัวเลือกนี้ levofloxacin (fluoroquinolone) ครอบคลุม H. ducreyi. (Amoxicillin ไม่ไว้ใจเพราะเชื้อสร้าง beta-lactamase)"}, {"topic": "Neurology", "q": "A 40-year-old man was found unconscious in his bedroom. He has a history of complex partial seizure well controlled by phenytoin for 5 years. PE: V/S - BT 37°C, RR 12/min, BP 165/80 mmHg, PR 110 bpm; Neuro - mid gaze pinpoint pupils, absent oculocephalic reflex, frequent extension posture. What is the diagnosis?", "choices": ["thalamic infarction", "medulla hemorrhage", "encephalitis", "pontine hemorrhage", "phenytoin intoxication"], "ans": 3, "exp": "Coma + pinpoint pupils (รูม่านตาเล็กมาก) + absent oculocephalic (doll's eye) + decerebrate/extension posture + mid-position gaze + HT = pontine hemorrhage (คลาสสิก: pinpoint pupils + quadriparesis + coma)."}, {"topic": "Neurology", "q": "A 60-year-old female presented with progressive muscle weakness for 2 weeks. She also had a fever and right side headache. U/D: DM, HT, chronic sinusitis. PE: V/S - BT 39°C, PR 100, BP 150/100 mmHg; CNS - drowsy, Lt side hemiparesis with Lt side facial palsy (UMN). What is the most likely diagnosis?", "choices": ["Brain tumor", "Cerebral infarction", "Bacterial meningitis", "Intracerebral hemorrhage", "Brain abscess"], "ans": 4, "exp": "อาการค่อยเป็นค่อยไป (2 สัปดาห์) + ไข้ + ปวดหัว + focal deficit (hemiparesis, facial palsy UMN) + มีแหล่งติดเชื้อ (chronic sinusitis) ในผู้ป่วยเบาหวาน = brain abscess (ลามจาก sinusitis). ยืนยันด้วย CT/MRI with contrast (ring-enhancing lesion)."}, {"topic": "Neurology", "q": "A 70-year-old male with U/D HT came to the hospital with an alteration of consciousness 1 hour PTA. He had left motor weakness with dysarthria and headache at 3 hours PTA and for the next 2 hours he developed lethargy and vomiting. PE: BP 160/100 mmHg; Neuro - E3M4V3, pupil 3 mm RTL, Lt.Hemiparesis, Lt BBK positive, stiffness of neck negative. What is the most likely diagnosis?", "choices": ["Intracranial hemorrhage", "Brain abscess", "Cerebral infarction", "Subarachnoid hemorrhage", "Hypertensive encephalopathy"], "ans": 0, "exp": "HT + อ่อนแรงครึ่งซีกเฉียบพลัน + ปวดหัว + ระดับความรู้สึกตัวแย่ลงเร็ว + อาเจียน (raised ICP) = intracerebral (intracranial) hemorrhage. (Ischemic infarct มักไม่ปวดหัว/อาเจียน/ซึมเร็วในช่วงแรกเท่า ICH)"}, {"topic": "Neurology", "q": "A 15-year-old girl presented with progressive ascending limb weakness 3 days ago. She had a history of URI symptoms 2 weeks ago. PE: CNS - Generalized weakness, absent DTR, decreased pin-prick sensation at palm and sole. What is the likely diagnosis?", "choices": ["Rhabdomyolysis", "GBS", "MS", "Transverse myelitis", "HypoK periodic paralysis"], "ans": 1, "exp": "อ่อนแรงแบบ ascending + areflexia (absent DTR) + หลังติดเชื้อ (URI 2 สัปดาห์ก่อน) = Guillain-Barré syndrome (GBS). CSF จะพบ albuminocytologic dissociation; เฝ้าระวังการหายใจล้มเหลว. รักษาด้วย IVIG/plasma exchange."}, {"topic": "Neurology", "q": "Female มาด้วย behavioral change 1 day, ทำปากขมุบขมิบ (lip smacking), chewing, fumbling เป็นอยู่ไม่กี่นาที (จำไม่ได้), หลังจากนั้นหมดสติไม่รู้สึกตัว แล้วค่อย ๆ gain conscious ใน 15 นาที. Dx?", "choices": ["Factitious disorder", "Dissociative disorder", "Absence seizure"], "ans": 2, "exp": "มี automatisms (ปากขมุบขมิบ เคี้ยว fumbling) + สับสน/ไม่รู้สึกตัว + postictal (ค่อย ๆ ฟื้นใน 15 นาที) = อาการชักแบบ focal impaired awareness (complex partial) — เป็นอาการชักจริง (organic) ไม่ใช่ psychiatric (dissociative/factitious). *ในตัวเลือกนี้ Absence seizure เป็นตัวเลือกชักที่ใกล้สุด แม้ทางคลินิกจะเป็น complex partial มากกว่า*"}, {"topic": "Neurology", "q": "A 50-year-old female patient U/D DM type2 (diagnosed 2 years) presented with bilateral hand numbness for 6 months with normal feeling in both feet. PE: bilateral thenar muscle atrophy, decreased pinprick sensation thumb to middle finger. Both feet are normal. Dx?", "choices": ["C-spondylosis", "Diabetic distal symmetric polyneuropathy", "Vit. B12 deficiency", "carpal tunnel syndrome"], "ans": 3, "exp": "ชาสองมือในแนว median nerve (นิ้วโป้งถึงนิ้วกลาง) + thenar atrophy + เท้าปกติ = carpal tunnel syndrome (median nerve entrapment) ทั้งสองข้าง. ต่างจาก diabetic polyneuropathy ที่จะเริ่มที่เท้าแบบ stocking ก่อน."}, {"topic": "Neurology", "q": "A 65-year-old man presents with a progressive weakness for 8 hours. PE: V/S - BP 160/100; CNS - Lt hemiparesis grade III spastic dysarthria, no aphasia. CT brain non CM: internal capsule infarction. What is the cause?", "choices": ["Large vessel", "Thrombosis", "Vessel to vessel emboli", "Cardiac to vessel emboli", "Small vessel"], "ans": 4, "exp": "Lacunar infarct ที่ internal capsule + pure motor hemiparesis + ไม่มี cortical sign (no aphasia) + HT = small vessel disease (lipohyalinosis ของหลอดเลือดเล็ก)."}, {"topic": "Neurology", "q": "Thai female 30 year old has recurrent right side troubling headache 3 mo with intense severity and progressive worsening with N/V last 6 hr, it happens before menstruation cycle. What is the Dx?", "choices": ["Migraine headache", "Brain tumor", "Tension type headache", "Trigeminal neuralgia", "Arteriovenous malformation"], "ans": 0, "exp": "ปวดหัวข้างเดียวเป็นซ้ำ ๆ + คลื่นไส้อาเจียน + สัมพันธ์กับรอบเดือน (menstrual/catamenial migraine) = migraine headache. *ต้นฉบับไฮไลต์ Trigeminal neuralgia ซึ่งเป็นปวดแปลบสั้น ๆ ที่ใบหน้า ไม่ใช่ปวดหัวตุบ ๆ พร้อมคลื่นไส้*"}, {"topic": "Neurology", "q": "A 65-year-old active smoker presents with weakness for 8 hours. His right-sided suddenly weak accompanying slur speech. V/S: BP 160/90, PR 88 (regular), RR 16, normal heart examination. Spastic dysarthria, no aphasia, Rt. hemiparesis grade III both UE and LE, normal sensation. EKG: normal sinus rhythm. CT: hypodense lesion at Lt.internal capsule. What is the most likely cause of the mechanism?", "choices": ["Cardiac to vessel embolism", "Small vessels thrombosis", "Large arterial thrombosis", "Vessel to vessel embolism", "Thrombophilia"], "ans": 1, "exp": "Pure motor hemiparesis (แขนขาข้างเดียวเท่ากัน) + ไม่มี cortical sign (no aphasia, sensation ปกติ) + lacune ที่ internal capsule + จังหวะหัวใจปกติ (ไม่มี AF) = lacunar stroke จาก small vessel disease (small vessels thrombosis / lipohyalinosis)."}, {"topic": "Neurology", "q": "A 20 years old man came with an alteration of consciousness. He had high grade fever with myalgia yesterday. V/S: BT 39°C, PR 100 bpm, BP 90/60 mmHg. CNS: Drowsiness, Pupils 2 mm RTLBE, Motor power at least gr.IV all extremities. Skin: Petechial rash on both legs. CBC: Hb 14, Platelets 150,000, WBC 20,000 (N80 L8 M2). CSF: RBC 1-2, WBC 120 (PMN90%), Protein 50, Sugar 20 (serum 90). CSF g/s: gram negative coccobacilli. Which is appropriate management?", "choices": ["Penicillin G", "Metronidazole", "Meropenem", "Erythromycin", "Piperacillin and tazobactam"], "ans": 2, "exp": "Bacterial meningitis (CSF PMN เด่น, glucose ต่ำ ratio ~0.22, protein สูง) + gram-negative coccobacilli → ในตัวเลือกนี้ meropenem คลุมเชื้อ gram-negative และผ่าน CSF ได้ดี (penicillin G ไม่ครอบคลุมเชื้อที่สร้าง beta-lactamase). *มาตรฐาน empiric จริงคือ ceftriaxone ± vancomycin ซึ่งไม่มีในตัวเลือก; ถ้าเป็น meningococcus จาก petechiae จะใช้ penicillin G ได้*"}, {"topic": "Neurology", "q": "A 30-year-old man weakness 30 min PTA. His symptom occurs 2 hr after finishing playing football. He had also experienced symptoms like this before last 6 month and the symptom was resolved spontaneously. PE: anterior deltoid and iliopsoas grade 3, intact sensory, DTR 2+ all. Electrolyte: Na 137, K 2.3, Cl 105, HCO3 24. What is the prevention?", "choices": ["Regularly exercise", "Avoid high-lipid food", "Take high potassium diet", "Avoid high-carbohydrate food", "Take potassium"], "ans": 3, "exp": "อ่อนแรงกล้ามเนื้อต้นแขน/ขาเป็นพัก ๆ หลังออกกำลัง + K ต่ำมาก (2.3) + หายเอง = hypokalemic periodic paralysis (มักเป็น thyrotoxic PP ในชายเอเชีย). ถูกกระตุ้นด้วยอาหารคาร์บสูงและการพักหลังออกกำลัง → ป้องกันด้วยการหลีกเลี่ยงอาหารคาร์โบไฮเดรตสูง (และรักษา hyperthyroid ถ้ามี). ระดับ K รวมในตัวปกติ การกิน K ไม่ป้องกัน"}, {"topic": "Neurology", "q": "Case female 25 yr, GA 8 wk, Hx GTC seizure 1 mo, เคยใช้ยา carbamazepine แล้ว MP rash ขึ้น. มีอาการชักอีกครั้ง 1 wk PTA. ถามว่าต่อไปจะให้ยากันชักอะไร", "choices": ["Phenytoin", "Phenobarbital", "Valproate", "Topiramate", "Levetiracetam"], "ans": 4, "exp": "หญิงตั้งครรภ์ที่ต้องใช้ยากันชัก + แพ้ carbamazepine (MP rash) → เลือก levetiracetam (หรือ lamotrigine) เพราะเสี่ยง teratogenic ต่ำที่สุด. หลีกเลี่ยง valproate (teratogenic สูงสุด), phenytoin/phenobarbital/topiramate (เสี่ยงเช่นกัน)."}, {"topic": "Infectious disease", "q": "A 24 years old female presented with a headache and blurred vision intermittently for 2 weeks. U/D: HIV with poor medication. What is diagnosis?", "choices": ["Cryptococcal meningitis", "Bacterial meningitis", "Toxoplasmosis", "Herpes encephalitis", "CMV Encephalitis"], "ans": 0, "exp": "HIV ที่กินยาไม่สม่ำเสมอ + ปวดหัว + ตามัวเป็นพัก ๆ (raised ICP) 2 สัปดาห์ = cryptococcal meningitis (Cryptococcus neoformans ทำให้ ICP สูง). วินิจฉัยด้วย serum/CSF cryptococcal antigen + LP วัด opening pressure."}, {"topic": "Neurology", "q": "ชายหนุ่ม 20 ปี มาด้วย behavioral change 1 วัน, ก่อนหน้านั้นสามวัน มีประวัติปวดหัวมากเหมือนจะระเบิด, ตรวจร่างกายมี stiff neck ไม่มี neuro deficit, เจาะ LP ไปเจอ numerous RBC, xanthochromia, Protein 80, glucose ratio 0.5. ถาม diagnosis", "choices": ["Cryptococcal meningitis", "Subarachnoid hemorrhage", "TB meningitis", "Bacterial meningitis"], "ans": 1, "exp": "ปวดหัวรุนแรงเฉียบพลันเหมือนจะระเบิด (thunderclap headache) + คอแข็ง + CSF มี RBC จำนวนมาก + xanthochromia + glucose ปกติ (ratio 0.5) = subarachnoid hemorrhage (SAH). ยืนยัน/หาสาเหตุด้วย CT/CT angiography (aneurysm)."}, {"topic": "Neurology", "q": "Pt. with U/D hypertension presented with Rt.side weakness, BBK+ve at Rt., Rt.motor gr.3 แขนเท่ากับขา. CT: hypodensity lesion at Lt.internal capsule. What is the etiology of this condition?", "choices": ["Cardioembolic", "vessel to vessel", "small vessel thrombosis", "large vessel thrombosis"], "ans": 2, "exp": "Pure motor hemiparesis (แขน = ขา) + lacune ที่ internal capsule + HT = lacunar stroke จาก small vessel thrombosis (lipohyalinosis)."}, {"topic": "Dermatology", "q": "ผู้หญิง 25 ปี มีผื่นขึ้น itchy rash มา 2 วัน แขนทั้งสองข้างที่ flexor area. ถามจะให้ยาอะไร", "choices": ["Ranitidine", "Omalizumab", "Prednisolone", "Cetirizine", "Azathioprine"], "ans": 3, "exp": "ผื่นคันเฉียบพลันบริเวณข้อพับ (eczema/urticaria) → รักษาอาการคันด้วย antihistamine เช่น cetirizine (2nd gen). (Ranitidine เป็น H2-blocker; omalizumab/azathioprine/steroid ใช้ในรายรุนแรง/เรื้อรัง)"}, {"topic": "Dermatology", "q": "A 55-year-old female presented with itchy rashes on both legs for 4 months. PE: symmetrical ill defined lichenification at both medial sides of ankles with multiple varicose veins. What is the most appropriate management?", "choices": ["Oral steroid", "Clotrimazole cream", "ไม่ใช้รองเท้าที่ทำจากหนังหรือพลาสติก", "Emollient", "Low potency topical steroid"], "ans": 4, "exp": "Lichenification ที่ข้อเท้าด้านในทั้งสองข้าง + เส้นเลือดขอด (varicose veins) = stasis dermatitis (venous eczema). รักษาการอักเสบด้วย topical corticosteroid + emollient + compression/ยกขา. *ต้นฉบับไฮไลต์ 'ไม่ใส่รองเท้าหนัง/พลาสติก' ซึ่งเป็นของ contact dermatitis ไม่ตรงกับ stasis dermatitis*"}, {"topic": "Ophthalmology", "q": "ผู้หญิงมี left upper lid mass, size 4 mm, no growth, well demarcated. Mx?", "choices": ["Excisional biopsy", "Incisional and curettage", "Incisional biopsy", "Steroid injection"], "ans": 0, "exp": "ก้อนที่เปลือกตาขนาดเล็ก (4 มม.) ขอบชัด ไม่โต (benign) → excisional biopsy (ตัดออกทั้งก้อน) เพื่อทั้งรักษาและส่งพยาธิ. (ถ้าเป็น chalazion อาจ incision & curettage หรือ steroid injection)"}, {"topic": "Dermatology", "q": "A 40 years old farmer presents with non pruritic lesion at thumb 4 months, lesion described by picture (multiple black dots at thumb tip). What is the cause of this lesion?", "choices": ["Latex glove", "HPV infection", "Chronic friction at effect side", "Frequently washing hand", "Contact pesticide"], "ans": 1, "exp": "รอยโรคที่นิ้วโป้ง ผิวขรุขระ มีจุดดำหลายจุด (thrombosed capillaries) = verruca vulgaris (common wart) ซึ่งเกิดจาก HPV infection.", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q88.png"}, {"topic": "Dermatology", "q": "A 20 years old female (pregnancy) presents with non-pruritic lesion at face for 1 month. Lesion: multiple inflammation, multistage of papule, macule, nodule (acne). What is the most appropriate treatment?", "choices": ["Topical isotretinoin", "Topical adapalene", "Topical azelaic acid", "Topical steroid", "Oral isotretinoin"], "ans": 2, "exp": "Acne ในหญิงตั้งครรภ์ → ห้ามใช้ retinoid ทั้ง oral และ topical (isotretinoin/adapalene เป็น teratogen). ยาที่ปลอดภัยในการตั้งครรภ์คือ topical azelaic acid (หรือ topical erythromycin/benzoyl peroxide). *ต้นฉบับไฮไลต์ Oral isotretinoin ซึ่งเป็นข้อห้ามเด็ดขาดในหญิงตั้งครรภ์*"}, {"topic": "Rheumatology", "q": "A female had symptoms of calcinosis, Raynaud phenomenon, sclerodactyly, telangiectasia. What is the diagnosis?", "choices": ["Pulmonary fibrosis", "Systemic sclerosis", "Dermatomyositis", "CREST syndrome"], "ans": 3, "exp": "Calcinosis + Raynaud + Sclerodactyly + Telangiectasia = CREST syndrome (limited cutaneous systemic sclerosis; C-R-E-S-T = Calcinosis, Raynaud, Esophageal dysmotility, Sclerodactyly, Telangiectasia). สัมพันธ์กับ anti-centromere antibody."}, {"topic": "Rheumatology", "q": "A 25 years old female presents with fever and joint pain for 2 months. PE: BT 38.5°C, BP 130/80, PR 96, RR 20; Skin - erythematous rash both cheeks sparing nasolabial fold; MSK - warm tender swelling both knees and wrists. CBC: HCT normal, WBC 3,600 (N80 L20), PLT 180,000. PBS: microspherocyte 1+ polychromasia 2+. What is the most likely diagnosis?", "choices": ["Evan's syndrome", "Rheumatoid arthritis", "Acute rheumatic fever", "Mixed connective tissue", "SLE"], "ans": 4, "exp": "malar rash เว้น nasolabial fold + arthritis (เข่า/ข้อมือ) + leukopenia (WBC 3,600) + hemolysis (spherocyte/polychromasia) + ไข้ ในหญิงสาว = SLE (เข้าหลายเกณฑ์: mucocutaneous + arthritis + hematologic). ตรวจ ANA/anti-dsDNA ยืนยัน."}, {"topic": "Rheumatology", "q": "ปวดเข่า 6 เดือน กิน NSAIDs ดีขึ้น, รอบนี้เจ็บเข่า 2 วัน บวมแดงร้อน เจาะน้ำในข้อ เจอ crystal รูป rhomboid shape. ส่งอะไร (investigation)", "choices": ["Serum Ca, PO4", "ANA", "Anti-CCP", "ASO titer", "Serum uric"], "ans": 0, "exp": "ผลึกรูป rhomboid (positive birefringence) = calcium pyrophosphate (CPPD/pseudogout). CPPD สัมพันธ์กับโรคเมตาบอลิก โดยเฉพาะ hyperparathyroidism → ควรส่ง serum Ca, PO4 (และ Mg/ferritin) หาสาเหตุ. (Serum uric ใช้กับ gout ที่ผลึกรูปเข็ม negative birefringence)"}, {"topic": "Rheumatology", "q": "A 64-year-old female presents with both hand pain and hand movement difficulty in the early morning for 3 months. PE: swelling and tenderness at both wrists and MCP joint. X-ray: soft tissue swelling both hands, periarticular osteopenia at MCP joint, erosion of ulnar styloid, mild intercarpal space narrowing. What is the diagnosis?", "choices": ["Gouty arthritis", "Rheumatoid arthritis", "Psoriatic arthritis", "CPPD arthropathy", "Erosive osteoarthritis"], "ans": 1, "exp": "ปวดข้อเล็กสองข้างแบบสมมาตร (MCP, wrist) + ข้อฝืดตอนเช้านาน + X-ray มี periarticular osteopenia + marginal erosion (ulnar styloid) = rheumatoid arthritis. ตรวจ RF/anti-CCP ยืนยัน."}, {"topic": "Rheumatology", "q": "Pt age 70 yrs U/D HTN, ให้ clinical setting of SLE มา. ถามว่า which anti-hypertensive drug ที่ผู้ป่วยกินมาตลอด (ทำให้เกิด drug-induced lupus)", "choices": ["Amlodipine", "Enalapril", "Hydralazine", "HCTZ"], "ans": 2, "exp": "Drug-induced lupus ที่พบบ่อยเกิดจาก hydralazine (และ procainamide, isoniazid) — มี anti-histone antibody, มัก spares ไต/CNS และหายเมื่อหยุดยา."}, {"topic": "Rheumatology", "q": "A 58 years old man U/D CKD stage 3 presents with intermittent arthralgia for 2 days. His symptoms began after activity and lasted for 4-5 days. His symptoms affect both the ankle and knee but only 1-2 joints were affected during each episode. Synovial fluid reveals a negative birefringent crystal. What is proper management?", "choices": ["Tramadol", "Ibuprofen", "Colchicine", "Prednisolone"], "ans": 3, "exp": "Acute gout (ผลึก negative birefringent = monosodium urate) ในผู้ป่วย CKD stage 3 → NSAIDs (ibuprofen) ควรหลีกเลี่ยง (ทำไตแย่), colchicine ต้องปรับขนาด/ระวังใน CKD → เลือก corticosteroid (prednisolone) ซึ่งปลอดภัยกว่าในผู้ป่วยไต."}, {"topic": "Surgery", "q": "A man presented with fever and perianal mass with fluctuation and redness. What is management?", "choices": ["Warm sitz bath", "ATB", "I&D", "lateral internal sphincterotomy"], "ans": 2, "exp": "ก้อนรอบทวารหนักที่มี fluctuation + แดง + ไข้ = perianal abscess → รักษาด้วย incision and drainage (I&D). Antibiotic เป็นตัวเสริมในรายที่มี cellulitis/ภูมิคุ้มกันต่ำ/เบาหวาน แต่หลักคือระบายหนอง."}, {"topic": "Surgery", "q": "A 35-year-old man presented with whooshing sounds in his right ear with headache and diplopia for 1 day. He had a past history of a high-speed motorcycle accident and had a frontal skull fracture with mild TBI which he had just discharged from hospitalization 10 days ago. PE: bilateral conjunctival injection, Rt. eye proptosis and pulsatile exophthalmos. What is the most likely diagnosis?", "choices": ["carotid-cavernous fistula", "cavernous sinus thrombosis", "retrobulbar hemorrhage"], "ans": 0, "exp": "หลังบาดเจ็บศีรษะ + เสียงฟู่ในหู (bruit) + pulsatile exophthalmos (ตาโปนเต้นตามชีพจร) + conjunctival injection = carotid-cavernous fistula (การเชื่อมต่อผิดปกติระหว่าง carotid กับ cavernous sinus). *ต้นฉบับไฮไลต์ retrobulbar hemorrhage ซึ่งเกิดเฉียบพลันหลังบาดเจ็บและไม่ pulsatile/ไม่มี bruit*"}, {"topic": "Surgery", "q": "An 85-year-old man presented with aspiration and voice changing while eating and drinking. The symptoms worsened when drinking than eating solid food. His underlying disease is dementia. What is the most likely diagnosis?", "choices": ["Achalasia", "Oropharyngeal dysphagia", "Diffuse esophageal spasm", "Esophageal cancer", "GERD"], "ans": 1, "exp": "สำลัก + เสียงเปลี่ยนขณะกลืน + แย่กับของเหลวมากกว่าของแข็ง + ผู้สูงอายุที่มีภาวะสมองเสื่อม (สาเหตุทางประสาท) = oropharyngeal dysphagia (transfer dysphagia). ต่างจากโรคหลอดอาหาร (achalasia/CA) ที่มักกลืนของแข็งลำบากกว่า"}, {"topic": "Surgery", "q": "A 63-year-old man presents with an acute urinary retention. He previously had lower urinary tract symptoms for 1 year. A yellowish urine of 600 ml was obtained by urine catheterization. DRE: prostate gland enlarge, no nodule. What is the most proper initial investigation?", "choices": ["UA, PSA", "Ultrasonography", "BUN, Cr", "Cystoscope", "Retrograde urethrogram"], "ans": 2, "exp": "BPH + acute urinary retention (ปัสสาวะ 600 มล.) — การตรวจเบื้องต้นที่สำคัญคือประเมิน renal function (BUN, Cr) เพราะการอุดกั้นอาจทำให้เกิด post-obstructive/post-renal AKI. (PSA ไม่ควรเจาะช่วงเพิ่งคาสาย/มี retention เพราะสูงลวง)"}, {"topic": "Surgery", "q": "A 30-year-old male presents with right groin mass and nausea vomiting for 8 hours after lifting a heavy box. PE: V/S - BT 38, BP 130/90; Abdomen - right groin mass swelling, marked tenderness. What is the most appropriate management?", "choices": ["Ultrasound", "CT", "Manual reduction", "Groin exploration", "I&D"], "ans": 3, "exp": "ก้อนที่ขาหนีบหลังยกของหนัก + N/V + กดเจ็บมาก + ไข้ = strangulated inguinal hernia (ลำไส้ขาดเลือด) เป็นภาวะฉุกเฉิน → surgical groin exploration ทันที. ห้าม manual reduction (เสี่ยงดันลำไส้ที่ตายกลับเข้าช่องท้อง)."}, {"topic": "Surgery", "q": "A 6-year-old boy visits an emergency room unconsciously with a well demarcated second degree burn from abdomen to both feet, sparing popliteal fossae and skin creases. What is the appropriate investigation for diagnosis?", "choices": ["MRI for musculoskeletal trauma", "CT scan for intracranial hemorrhage", "Bun, Cr, CPK, electrolyte", "Ophthalmoscope for retinal hemorrhage", "Plain film for fracture of extremities"], "ans": 4, "exp": "แผลไฟลวกขอบชัด เว้นข้อพับ/รอยย่น (immersion/stocking-glove pattern) = สงสัย non-accidental injury (child abuse). การตรวจสำคัญคือ skeletal survey (plain film หา fracture เก่า/ซ่อนเร้นหลายตำแหน่ง)."}, {"topic": "Pediatrics", "q": "An otherwise healthy 1 month child presents with sudden greenish vomiting for 6 hours. He has occasional crying with mild abdominal distension. PE: V/S - BT 37.4°C, BP 60/40, PR 160/min, RR 50/min; HEENT - dry lips; Abdomen - mild distension, hyperactive bowel sounds, no tenderness or guarding, no mass, bloody mucous stool on per rectal examination. Plain abdominal x-ray: distended stomach, without air in bowel. What is the most likely diagnosis?", "choices": ["Midgut volvulus", "Hypertrophic pyloric stenosis", "Duodenal atresia", "Jejunal atresia", "Intussusception"], "ans": 0, "exp": "ทารก + อาเจียนสีเขียว (bilious) เฉียบพลัน + ถ่ายมูกเลือด (bowel ischemia) + x-ray ท้องไม่มีลม (gasless) = midgut volvulus จาก malrotation (ภาวะฉุกเฉินทางศัลยกรรม). Bilious vomiting ในทารกต้องนึกถึง malrotation/volvulus จนกว่าจะพิสูจน์เป็นอื่น"}, {"topic": "Pediatrics", "q": "A 2 month old boy presented with progressive non bilious vomiting after breastfeeding for 2 wk. He was born at term with BW 3000 g. PE: V/S - BT 37°C, PR 140 bpm, RR 40, Weight 2900 g; GA - lethargy; HEENT - sunken eyeballs; Abdomen - movable olive mass at epigastrium. What is the most proper investigation?", "choices": ["Plain film abdomen", "U/S abdomen", "Barium swallowing", "CT abdomen", "EGD"], "ans": 1, "exp": "อาเจียนพุ่งไม่มีน้ำดี (non-bilious) + คลำได้ olive mass ที่ลิ้นปี่ + ขาดน้ำ/น้ำหนักลด = hypertrophic pyloric stenosis. ตรวจยืนยันด้วย ultrasound abdomen (วัดความหนา/ยาวของ pyloric muscle)."}, {"topic": "Surgery", "q": "ผู้ป่วยชาย acute sharp epigastric pain, can't maintain upright position, V/S ดี, PE: board-like rigidity (สงสัย perforate). What is the most proper investigation?", "choices": ["Serum amylase", "CT abdomen", "Acute abdomen series", "CTA"], "ans": 2, "exp": "ปวดท้องเฉียบพลันรุนแรง + board-like rigidity (peritonitis) = สงสัย perforated viscus (perforated peptic ulcer). ตรวจเบื้องต้นด้วย acute abdomen series (upright film) เพื่อดู free air ใต้กระบังลม."}, {"topic": "Orthopedics", "q": "Male U/D BPH s/p TURP มาด้วย Right foot drop 1 day. PE: Rt. Foot cannot dorsiflex, loss sensation at dorsal and lateral malleolus of Rt. Foot, tibialis anterior/peroneal muscle weakness. Diagnosis?", "choices": ["L5-S1 nerve root injury", "Tibial nerve injury", "Sciatic nerve injury", "Peroneal nerve injury", "Sural nerve injury"], "ans": 3, "exp": "Foot drop (dorsiflex ไม่ได้) + eversion อ่อนแรง + ชาหลังเท้า/malleolus ด้านนอก + อ่อนแรง tibialis anterior/peroneal = common peroneal (fibular) nerve injury (มักจากท่าขาช่วงผ่าตัด/การกดทับที่ fibular head)."}, {"topic": "Pediatrics", "q": "Term 38 wk, excessive saliva after birth, hx of polyhydramnios, insert OG tube cannot pass into stomach. Film chest include abdomen: curling of OG tube at neck level, normal bowel gas pattern. Diagnosis?", "choices": ["esophageal atresia", "esophageal web", "duodenal atresia", "HPS"], "ans": 0, "exp": "น้ำลายมากตั้งแต่แรกเกิด + ประวัติ polyhydramnios + ใส่ OG tube ไม่ลงกระเพาะ (ขดที่คอ) + มีลมในลำไส้ปกติ = esophageal atresia with tracheoesophageal fistula (type C — มีลมในลำไส้จาก fistula)."}, {"topic": "Neurology", "q": "ผช 70 ปี u/d HT มาด้วย Weak Lt side แขน พูดไม่ชัด, ก่อนหน้านี้ 2 ชม.มีปวดหัวหนักมาก หลังจากนั้น 3 ชม.มีอ้วก, BP 160/110. What is the most likely diagnosis?", "choices": ["Intracerebral hemorrhage", "Subdural hemorrhage", "Hypertension encephalopathy", "Subarachnoid hemorrhage"], "ans": 0, "exp": "HT + อ่อนแรงครึ่งซีก + พูดไม่ชัด + ปวดหัวรุนแรง + อาเจียน (raised ICP) + BP สูง = intracerebral hemorrhage (hypertensive ICH, มักที่ basal ganglia/internal capsule)."}, {"topic": "Surgery", "q": "Hx of head trauma มาด้วย ปวดหัว, bilateral proptosis, ฟังได้ orbital bruits. Diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Cavernous sinus thrombosis", "Carotid-cavernous fistula", "Retrobulbar hemorrhage", "Orbital cellulitis"], "ans": 1, "exp": "หลังบาดเจ็บศีรษะ + ตาโปนสองข้าง + ได้ยิน orbital bruit = carotid-cavernous fistula (การเชื่อมต่อผิดปกติของ carotid กับ cavernous sinus ทำให้เลือดแดงไหลย้อนเข้า orbital veins)."}, {"topic": "Surgery", "q": "ชายอายุ 55 ปี ปัสสาวะไม่ออก 8 ชั่วโมง มีไข้ ฉี่แสบขัด ปวด perineum. PE: V/S - BT 39°C, PR 110 bpm, BP 140/100; Abdomen - suprapubic mass; PR - prostate enlargement and tenderness. Diagnosis?", "choices": ["Benign prostate hyperplasia", "Gonococcal Urethritis", "Acute prostatitis", "Prostate cancer", "Bladder cancer"], "ans": 2, "exp": "ไข้ + ปัสสาวะแสบขัด + ปวด perineum + ต่อมลูกหมากโต กดเจ็บ (tender) + ปัสสาวะไม่ออก = acute (bacterial) prostatitis. ต่อมลูกหมากที่กดเจ็บ + ไข้เป็นเบาะแสสำคัญ (ระวังการคลึงต่อมแรง ๆ เสี่ยง bacteremia)."}, {"topic": "Surgery", "q": "A 14 years old boy presents with acute left scrotal pain described as abrupt and severe pain while playing sports. PE: BT 37.6°C, Lt. Scrotal swelling redness tenderness. UA: normal. What is appropriate management?", "choices": ["NSAIDs", "Antibiotic", "Color doppler ultrasound", "Surgical exploration", "Hernioplasty"], "ans": 3, "exp": "ปวดถุงอัณฑะเฉียบพลันรุนแรงในเด็กชายวัยรุ่นขณะออกกำลัง + บวมแดง + UA ปกติ = testicular torsion (ภาวะฉุกเฉิน ต้องคลายภายใน ~6 ชม.). เมื่อสงสัยชัดควร surgical exploration ทันที (detorsion + orchiopexy) โดยไม่รอ imaging"}, {"topic": "Surgery", "q": "ชายหนุ่ม ตกจากเสาไฟฟ้า คนเห็นเหตุการณ์ให้ประวัติว่าสลบไป 2 นาที หลังจากนั้นตื่นดีพูดคุยรู้เรื่อง พอ EMS มาถึงยัง alert อยู่ แต่ต่อมาเริ่ม stupor (lucid interval). Diagnosis?", "choices": ["Subdural hematoma", "Epidural hematoma", "Post Concussion"], "ans": 1, "exp": "บาดเจ็บศีรษะ + สลบสั้น ๆ → ตื่นดี (lucid interval) → แล้วซึมลง = epidural hematoma (เลือดออกจาก middle meningeal artery, ภาพ CT รูปเลนส์ biconvex). ต้องผ่าตัดระบายเลือดด่วน"}, {"topic": "Surgery", "q": "มาด้วยริดสีดวงที่ก้น มีสามก้อนอยู่ทางด้าน left lateral, right anterior, right posterior, ดันกลับไม่เข้า. ถามทำอย่างไร", "choices": ["Hemorrhoidectomy", "Warm sitz bath", "Daflon", "Rubber band ligation"], "ans": 0, "exp": "ริดสีดวงทวารหลายก้อน (ครบทั้ง 3 ตำแหน่งหลัก) ที่ดันกลับไม่เข้า (irreducible, grade IV) → รักษาด้วย hemorrhoidectomy. Rubber band ligation เหมาะกับ grade I-III ก้อนเดี่ยว; sitz bath/Daflon เป็นการรักษาประคับประคอง"}, {"topic": "Surgery", "q": "หญิงตั้งครรภ์ (จำอายุครรภ์ไม่ได้) มาด้วยปวดท้องฝั่งขวา มีคลื่นไส้ อาเจียนหลายรอบ ตรวจร่างกายปวดฝั่งขวาจริง ดันมดลูกไปทางฝั่งขวาแล้วเจ็บมากขึ้น. Diagnosis?", "choices": ["Ureteric stone", "Acute appendicitis", "Acute cholecystitis"], "ans": 1, "exp": "หญิงตั้งครรภ์ + ปวดท้องขวา + N/V + กดเจ็บขวา + ดันมดลูกไปขวาแล้วเจ็บมากขึ้น (uterine displacement sign) = acute appendicitis (เป็น non-obstetric surgical emergency ที่พบบ่อยสุดในหญิงตั้งครรภ์; ไส้ติ่งถูกดันสูงขึ้นตามมดลูก)."}, {"topic": "Surgery", "q": "ผู้ป่วยมาด้วยไข้ ปวดขา 6 วัน โดย 7 วันก่อนโดนไม้แทงขา ทำแผลเองที่บ้าน. PE: laceration wound with greenish discharge with bleb around lesion. ถาม management", "choices": ["I&D", "wound dressing", "debridement c fasciotomy"], "ans": 2, "exp": "แผลหลังถูกแทง + หนองเขียว + bleb (bullae) รอบแผล + ไข้ + ปวดมาก = necrotizing soft tissue infection (necrotizing fasciitis) → ต้อง surgical debridement + fasciotomy ด่วน (ร่วม broad-spectrum ATB). แค่ I&D/wound dressing ไม่พอ"}, {"topic": "Surgery", "q": "Prostate คลำได้ nodule, PSA = 4.5. ทำอย่างไร (ไม่มีตัวเลือก MRI)", "choices": ["F/U 1mo", "TURP", "TRUS biopsy"], "ans": 2, "exp": "คลำต่อมลูกหมากได้ nodule (DRE ผิดปกติ) + PSA สูงเล็กน้อย (4.5) → สงสัยมะเร็งต่อมลูกหมาก ต้องทำ TRUS-guided biopsy (การมี nodule เป็นข้อบ่งชี้ biopsy ไม่ว่า PSA เท่าใด). *ต้นฉบับไฮไลต์ F/U 1 เดือน ซึ่งไม่เหมาะเมื่อคลำได้ nodule*"}, {"topic": "Orthopedics", "q": "ทำ TURP มาแล้ว foot drop ถามว่าเป็นที่ nerve ไหน", "choices": ["Peroneal", "L5-S1 Root", "Tibial"], "ans": 0, "exp": "Foot drop หลังผ่าตัดในท่า lithotomy = common peroneal (fibular) nerve palsy (ถูกกดที่บริเวณ fibular head). อาการ: dorsiflex ไม่ได้ + ชาหลังเท้า"}, {"topic": "Infectious disease", "q": "กินอาหารทะเลมา มี hemorrhagic bleb คลำได้ crepitation. ถามเชื้อ (ต้นฉบับตัวเลือกไม่ครบ — ใส่เท่าที่มี)", "choices": ["vibrio vulnificus", "clostridium perfringen"], "ans": 0, "exp": "กินอาหารทะเล + hemorrhagic bulla + soft tissue infection = Vibrio vulnificus (พบในผู้ป่วยตับแข็ง/ภูมิคุ้มกันต่ำ ทำให้เกิด hemorrhagic bullae + necrotizing fasciitis + septic shock)."}, {"topic": "Surgery", "q": "วัยรุ่นชายปวดไข่ขวา 1 วัน PS 6/10, cremasteric reflex positive. ทำอย่างไร", "choices": ["ตัดไข่ขวา (right orchiectomy)", "ATB (antibiotic/conservative)", "ตัดไข่ให้หมด (bilateral orchiectomy)"], "ans": 1, "exp": "ปวดอัณฑะที่ยังมี cremasteric reflex (positive) → torsion ของอัณฑะมีโอกาสน้อย (torsion มัก reflex หายไป) นึกถึง epididymo-orchitis หรือ torsion of appendix testis → รักษาแบบประคับประคอง/antibiotic ไม่ผ่าตัดตัดอัณฑะ"}, {"topic": "Surgery", "q": "เด็กอายุ 18 เดือน ไข่ไม่ลง 1 ข้าง (undescended testis) ทำอย่างไร", "choices": ["Testosterone", "Follow up", "Orchidopexy"], "ans": 2, "exp": "Undescended testis (cryptorchidism) ที่ยังไม่ลงเมื่ออายุเกิน 6-12 เดือน (ที่นี่ 18 เดือน) → ทำ orchidopexy (ผ่าตัดนำอัณฑะลงถุงและตรึงไว้) เพื่อลดเสี่ยงมะเร็ง/มีบุตรยาก. *ต้นฉบับไฮไลต์ Testosterone ซึ่งการรักษาด้วยฮอร์โมนไม่ได้ผล/ไม่แนะนำ*"}, {"topic": "Cardiology", "q": "Male 44 yr มาตรวจร่างกายเฉย ๆ เจอว่า BP แขนสองข้างไม่เท่ากัน บนกับล่างก็ไม่เท่ากัน. ถามว่าเป็นอะไร", "choices": ["Coarctation", "Takayasu"], "ans": 0, "exp": "ความดันแขนสูงกว่าขา (upper > lower) เป็นลักษณะเฉพาะของ coarctation of aorta (มี radio-femoral delay, HT ที่แขน). Takayasu (pulseless disease) มักในหญิงเอเชียอายุน้อย"}, {"topic": "Surgery", "q": "30 ปี มาด้วย off and on anal bleeding, V/S stable. Procto: irreducible, internal hemorrhoid. Mx?", "choices": ["stool softener", "Ligation", "hemorrhoidectomy"], "ans": 2, "exp": "Internal hemorrhoid ที่ดันกลับไม่เข้า (irreducible = grade IV) → รักษาด้วย hemorrhoidectomy. Rubber band ligation เหมาะกับ grade I-III"}, {"topic": "Forensic", "q": "อธิบายลักษณะแผล: มี satellite lesion, เห็น skin bridge, can't defined edge (ขอบไม่ชัด). เรียกว่าแผลชนิดใด", "choices": ["Laceration", "Abrasion", "Contusion", "Cut wound"], "ans": 0, "exp": "แผลที่มี tissue/skin bridge คร่อมอยู่ + ขอบไม่เรียบ/ไม่ชัด = laceration (แผลฉีกขาดจากแรงทื่อ). ต่างจาก cut/incised wound (แผลจากของมีคม ขอบเรียบ ไม่มี tissue bridge)"}, {"topic": "Surgery", "q": "30 years old Thai male fall from electrical pole 4 meters. Unconscious 2 min then awake, active ระหว่างอยู่บนรถพยาบาลตื่นดี active ดี พอมาถึง ER มี drowsiness, confusion. ถามว่าเป็นอะไร", "choices": ["Subdural hematoma", "Epidural hematoma", "Electrical injury", "Diffuse axonal injury", "Post concussion"], "ans": 1, "exp": "สลบสั้น ๆ → ตื่นดี (lucid interval) → แล้วซึม/สับสนลง = epidural hematoma (เลือดออก middle meningeal artery). *ต้นฉบับไฮไลต์ Subdural hematoma แต่ lucid interval เป็นลักษณะคลาสสิกของ epidural hematoma*"}, {"topic": "Obstetrics & Gynecology", "q": "A 25-year-old female GA 8 wk with a history of GTC 2 episodes happened one month and one week ago. She also had a history of carbamazepine-induced rash. What is the next management?", "choices": ["Phenytoin", "Topiramate", "Levetiracetam", "Valproate", "Phenobarbital"], "ans": 2, "exp": "หญิงตั้งครรภ์ + ต้องคุมชัก + แพ้ carbamazepine → เลือก levetiracetam (หรือ lamotrigine) เพราะเสี่ยง teratogenic ต่ำสุด. หลีกเลี่ยง valproate (teratogen สูงสุด), phenytoin/phenobarbital/topiramate"}, {"topic": "Obstetrics & Gynecology", "q": "A 29-year-old female G3P2 (2 previous C/S, fetal birth weight 3,600 and 3,800 g). First ANC at 12 wk. Her past ANC visits were unremarkable. What is the appropriate management at GA 20 wk?", "choices": ["50 g OGTT", "Plan vaginal delivery", "Plan C/S at GA 37 wk with tubal sterilization", "Routine ultrasound"], "ans": 3, "exp": "ที่อายุครรภ์ 20 สัปดาห์ การดูแลตามปกติคือ routine (anomaly) ultrasound (ตรวจโครงสร้างทารกที่ ~18-22 wk). 50 g OGTT ทำที่ 24-28 wk; ผู้มี 2 previous C/S จะวางแผน elective repeat C/S ในช่วงใกล้คลอด (ไม่ใช่ที่ 20 wk)"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old female G2P1001 GA 36 wk with a history of previous C/S came to the hospital with bright red blood bleeding per vagina. PE: P120/min, BP 80/60 mmHg, generalized abdominal tenderness with rebound tenderness, palpable fetal part. What is the most likely diagnosis?", "choices": ["Placenta previa", "Abruptio placenta", "Ruptured Vasa previa", "Mucous blood show", "Uterine rupture"], "ans": 4, "exp": "แผลผ่าคลอดเดิม + เลือดออก + ปวดท้องทั่ว + rebound + คลำ fetal part ได้ชัด (ทารกออกมาในช่องท้อง) + shock = uterine rupture (มดลูกแตก ภาวะฉุกเฉิน ต้องผ่าตัดด่วน)"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year old pregnant woman presents with a non pruritic lesion at face for 1 month. PE: multiple stages of inflammation papule, pustule, nodule (acne). What is the most appropriate management?", "choices": ["Topical azelaic acid", "Topical tretinoin", "Topical adapalene", "Topical steroid lotion", "Oral isotretinoin"], "ans": 0, "exp": "สิวในหญิงตั้งครรภ์ → ห้ามใช้ retinoid ทั้ง oral/topical (tretinoin, adapalene, isotretinoin = teratogen). ยาที่ปลอดภัยคือ topical azelaic acid (หรือ topical erythromycin/benzoyl peroxide)"}, {"topic": "Obstetrics & Gynecology", "q": "A 18-year-old female puerperium, breastfeeding, delivered an infant 6 weeks ago. Which contraception is the most appropriate?", "choices": ["DMPA", "Subdermal implant", "Combined pills", "Condom", "Contraceptive patch"], "ans": 1, "exp": "หญิงให้นมบุตร → หลีกเลี่ยงฮอร์โมนที่มี estrogen (combined pills, patch — ลดน้ำนม + เสี่ยง VTE). เลือก progestin-only ที่มีประสิทธิภาพสูง เช่น subdermal implant (LARC) — ปลอดภัยในการให้นมและคุมกำเนิดได้ดีที่สุด (DMPA ก็เป็น progestin-only ที่ใช้ได้เช่นกัน)"}, {"topic": "Obstetrics & Gynecology", "q": "A 20-year-old woman GA 10 wk came to ANC. No hx of jaundice. PE: unremarkable. Lab: HBsAg Positive. What is the appropriate management (next test)?", "choices": ["HbcAg", "Anti HBs", "HbeAg", "Anti HBc", "Anti HDV"], "ans": 2, "exp": "หญิงตั้งครรภ์ HBsAg positive → ตรวจ HBeAg (และ HBV DNA) เพื่อประเมินความสามารถในการแพร่เชื้อ/ความเสี่ยงถ่ายทอดสู่ทารก. ถ้า HBeAg+ หรือ viral load สูง ให้ antiviral (tenofovir) ไตรมาสสาม + ทารกได้ HBIG + วัคซีนแรกเกิด"}, {"topic": "Obstetrics & Gynecology", "q": "A 30-year-old patient complained of amenorrhea after an abortion. She underwent dilation and curettage. What is the most proper investigation?", "choices": ["FSH and E2 level", "TSH and PRL level", "Pelvic ultrasound", "Hysteroscopy", "SIS"], "ans": 3, "exp": "ขาดประจำเดือนหลังขูดมดลูก (D&C) = สงสัย Asherman syndrome (พังผืดในโพรงมดลูก). การตรวจที่ดีที่สุดคือ hysteroscopy (มองเห็นและแยกพังผืดได้โดยตรง). SIS/HSG ก็ช่วยได้"}, {"topic": "Obstetrics & Gynecology", "q": "A 18 years old female G2P0 GA 32 weeks presents with fluid leakage from vagina 2 hr PTA. No fever, no abdominal pain, normal fetal movement as the day before. What is the next appropriate management?", "choices": ["U/S", "Cervical swab culture", "PV", "EFM", "Nitrazine test"], "ans": 4, "exp": "สงสัย preterm PROM (น้ำเดินที่ 32 สัปดาห์) → ยืนยันการแตกของถุงน้ำคร่ำด้วย nitrazine test (น้ำคร่ำเป็นด่างเปลี่ยนสี) หรือ sterile speculum (pooling/ferning). หลีกเลี่ยงการตรวจภายในด้วยนิ้ว (digital PV) เพราะเพิ่มการติดเชื้อ"}, {"topic": "Obstetrics & Gynecology", "q": "Case pregnancy G1, มี labor pain, cervix 8 cm 100% effaced, FHR 90 bpm, PV มี cord in vagina (cord prolapse). ถาม management", "choices": ["c/s emer", "reverse trendelenburg", "empty bladder", "ดัน cord กลับเข้าไป"], "ans": 0, "exp": "Umbilical cord prolapse + fetal bradycardia (FHR 90) = ภาวะฉุกเฉินทางสูติกรรม → emergency C/S. ระหว่างเตรียม: ยกส่วนนำของทารกออกจากสายสะดือด้วยมือ + จัดท่า knee-chest/Trendelenburg. *ห้ามดันสายสะดือกลับเข้าไป*"}, {"topic": "Obstetrics & Gynecology", "q": "ท้อง 25 wk ตรวจร่างกายพบ heart failure. ให้ยาอะไร (ต้นฉบับตัวเลือกไม่ครบ — ใส่เท่าที่มี)", "choices": ["ARB", "IV furosemide"], "ans": 1, "exp": "หญิงตั้งครรภ์ที่มี heart failure/pulmonary congestion → ให้ IV furosemide ลด volume ได้. *ARB (และ ACEI) เป็นข้อห้ามในการตั้งครรภ์ (teratogenic)*"}, {"topic": "Obstetrics & Gynecology", "q": "A 52-year-old female u/d DM, para 2, present with vaginal spotting for 1 mo. No pelvic pain. PE: BW 70, H 150, V/S 140/90 mmHg, No pale conjunctiva. PV: MIUB normal; VG - atrophic mucosa, blood; Os - close, minimal bloody d/c per os; Ut - normal size; Adnexa - no mass, not tender. Most proper investigation?", "choices": ["Pap", "CA125", "F&C", "TVS", "FSH, E2"], "ans": 2, "exp": "เลือดออกทางช่องคลอดในวัยหมดประจำเดือน (postmenopausal bleeding) + ปัจจัยเสี่ยง (อ้วน, DM) → ต้องตัดมะเร็งเยื่อบุโพรงมดลูก. การตรวจที่ได้ชิ้นเนื้อวินิจฉัยคือ fractional curettage (F&C). (TVS วัดความหนาเยื่อบุมดลูกใช้เป็น initial screening ได้)"}, {"topic": "Obstetrics & Gynecology", "q": "Pregnancy เป็น DM อยู่เดิม ได้ยา Glipizide อยู่ ถาม management", "choices": ["ให้ Glipizide ต่อ", "Glipizide + metformin", "Lifestyle modification", "เปลี่ยนเป็น metformin (MFM)"], "ans": 3, "exp": "เบาหวานที่ตั้งครรภ์ — gold standard คือเปลี่ยนเป็น insulin. เมื่อไม่มี insulin ในตัวเลือก metformin ปลอดภัยกว่า sulfonylurea (glipizide ผ่านรก เสี่ยง neonatal hypoglycemia). *ต้นฉบับไฮไลต์ 'ให้ glipizide ต่อ' ซึ่งไม่เหมาะ; ตัวเลือกที่ควรมีจริงคือ insulin*"}, {"topic": "Obstetrics & Gynecology", "q": "25 yo Pregnancy GA 8 weeks มีประวัติชักแบบ GTC มา 2 ครั้ง เคยได้ carbamazepine แล้วผื่นขึ้น. ควรให้ยาอะไร", "choices": ["Phenytoin", "Topiramate", "Phenobarbital", "Valproic acid", "Levetiracetam"], "ans": 4, "exp": "หญิงตั้งครรภ์ + คุมชัก + แพ้ carbamazepine → levetiracetam (หรือ lamotrigine) เสี่ยง teratogenic ต่ำสุด. หลีกเลี่ยง valproic acid (teratogen สูงสุด)"}, {"topic": "Obstetrics & Gynecology", "q": "A 34 yr women has been aborted for 3 pregnancies at 7, 11, 8 wk. What is the most likely cause of her miscarriage?", "choices": ["Chromosome abnormality", "Myoma uteri", "Bicornuate uterus", "Recurrent infection", "Cervical incompetence"], "ans": 0, "exp": "แท้งซ้ำในไตรมาสแรก (7, 11, 8 สัปดาห์ ล้วนช่วงต้น) → สาเหตุที่พบบ่อยที่สุดคือความผิดปกติของโครโมโซม (เช่น parental balanced translocation/fetal aneuploidy). Cervical incompetence/bicornuate มักทำให้แท้งไตรมาสสอง"}, {"topic": "Obstetrics & Gynecology", "q": "คลอดเด็กแล้วเกิด shoulder dystocia. Management (ขั้นแรก)?", "choices": ["posterior shoulder", "McRobert", "Wood screw maneuver", "Suprapubic pressure"], "ans": 1, "exp": "Shoulder dystocia — ขั้นแรกคือ McRoberts maneuver (งอสะโพกแม่เข้าหาท้อง) ± suprapubic pressure. การคลอดไหล่หลัง (deliver posterior shoulder/arm)/Wood screw เป็น maneuver ลำดับถัดไป. *ต้นฉบับไฮไลต์ posterior shoulder ซึ่งไม่ใช่ขั้นแรก*"}, {"topic": "Obstetrics & Gynecology", "q": "Thai female 28 years old G1P0 GA 38 wks คลอดลูกที่บ้านมาแล้ว 2 hrs PTA แต่รกยังไม่คลอด (retained placenta), แม่ V/S BP 120/80 PR 100. ทำ cord controlled traction แล้วเกิด avulsed cord. ควรทำอะไรต่อ", "choices": ["Crede maneuver", "Ergonovine", "Manual extraction of placenta"], "ans": 2, "exp": "รกค้าง (retained placenta) + สายสะดือขาดขณะดึง (avulsed cord) → ต้องทำ manual removal of placenta (ล้วงรก) ในห้องผ่าตัด/ภายใต้ยาระงับความรู้สึก. Crede/ergonovine ไม่ช่วยเมื่อสายสะดือขาดแล้ว"}, {"topic": "Obstetrics & Gynecology", "q": "แม่ No ANC คลอดก่อนมาโรงพยาบาล โดยใช้กรรไกรที่บ้านตัด cord (unclean). PE: BT 37°C, PR 100, BP 70/50, RR 30. นอกจากการให้ IV penicillin จะให้อะไรเพิ่ม", "choices": ["Gentamicin", "Gentamicin + Tetanus toxoid", "Gentamicin + Tetanus immunoglobulin", "Gentamicin + Tetanus toxoid + Tetanus immunoglobulin", "Tetanus immunoglobulin"], "ans": 3, "exp": "คลอดสกปรก (ตัดสายสะดือด้วยกรรไกรบ้าน) + ไม่ได้ ANC/ไม่ทราบประวัติวัคซีน = tetanus-prone → ให้ทั้ง active (tetanus toxoid) + passive (tetanus immunoglobulin) ร่วมกับ antibiotic (penicillin + gentamicin คลุมกว้างสำหรับ sepsis). *โจทย์ไม่ชัดว่าถามแม่หรือทารก แต่กรณี unknown vaccination + dirty ให้ toxoid + TIG*"}, {"topic": "Obstetrics & Gynecology", "q": "A 27 y/o GA 38, low risk, labor pain, FHR 150, longitudinal, contraction interval 7 min duration 45 sec, cx 4 cm eff 80% station 0, membrane intact. Management?", "choices": ["C/S", "PGE1", "Oxytocin", "Observe", "Amniotomy"], "ans": 4, "exp": "ปากมดลูก 4 ซม. บาง 80% (favorable) แต่ contraction ห่าง (7 นาที = inadequate) + ถุงน้ำยังไม่แตก → augment labor ด้วย amniotomy (AROM) ก่อน แล้วค่อยพิจารณา oxytocin. *ต้นฉบับไฮไลต์ PGE1 ซึ่งใช้ ripening ปากมดลูกที่ยังไม่พร้อม — แต่ที่นี่ปากมดลูกพร้อมแล้ว*"}, {"topic": "Obstetrics & Gynecology", "q": "Postpartum 2 wk รู้สึกหงุดหงิด มีปากเสียงกับสามีหลายครั้ง รู้สึกผิด เลี้ยงลูกไม่ดี บางครั้งอยากทำร้ายลูกเวลาลูกร้อง. ถามว่าเป็นอะไร", "choices": ["Postpartum depression", "Adjustment disorder", "Factitious disorder", "GAD"], "ans": 0, "exp": "หลังคลอด 2 สัปดาห์ + อารมณ์เศร้า/หงุดหงิด + รู้สึกผิด/ตนเองเลี้ยงลูกไม่ดี + คิดทำร้ายลูก = postpartum depression (ต่างจาก postpartum blues ที่อาการน้อยและหายเองใน 2 สัปดาห์). ความคิดทำร้ายลูกเป็นสัญญาณอันตราย ต้องรีบดูแล"}, {"topic": "Obstetrics & Gynecology", "q": "Pregnancy c placenta previa, ให้ advice เรื่อง sexual intercourse (SI)", "choices": ["Be Gentle", "No SI", "Side by side", "Wait until GA 36 wk", "SI as usual"], "ans": 1, "exp": "ภาวะรกเกาะต่ำ (placenta previa) → แนะนำ งดการมีเพศสัมพันธ์ (No SI) และหลีกเลี่ยงการตรวจภายใน/สอดใส่ เพราะเสี่ยงกระตุ้นเลือดออก"}, {"topic": "Obstetrics & Gynecology", "q": "A 20 year-old primigravida came for the first ANC. No history of jaundice. Physical examination is unremarkable. All investigations are within normal limits except HBsAg positive. What is the proper investigation?", "choices": ["HBc Ag", "Anti-HBs Ab", "HBe Ag", "Anti-HbcAb", "Anti-HDV"], "ans": 2, "exp": "หญิงตั้งครรภ์ HBsAg+ → ตรวจ HBeAg (และ HBV DNA) ประเมินความสามารถในการแพร่เชื้อสู่ทารก. *ต้นฉบับไฮไลต์ Anti-HDV ซึ่งไม่ใช่ priority ในการประเมินการถ่ายทอดสู่ทารก*"}, {"topic": "Obstetrics & Gynecology", "q": "Female ~28 y/o presented with vaginal bleeding. PV: bleeding per cervical os, uterus 12 wk size. TVS: intrauterine pregnancy without fetal heartbeat, US calculated GA 12 wk. What is the most proper management?", "choices": ["F/U 1 wk", "Oxytocin", "MVA", "Misoprostol", "D&C"], "ans": 3, "exp": "IUP ที่ไม่มี fetal heartbeat + ขนาด 12 สัปดาห์ = missed abortion. รักษาด้วย medical management (misoprostol) เพื่อขับชิ้นเนื้อ หรือ surgical evacuation (MVA/suction D&C) เป็นทางเลือก. Oxytocin ไม่ได้ผลในไตรมาสแรก"}, {"topic": "Obstetrics & Gynecology", "q": "หญิงท้อง GA 25 Wk no u/d, presented progressive dyspnea on exertion. PE: JVP 5 cm above sternal notch, PMI at 6th ICS anterior mid axillary line (displaced), rales both lower lungs, pitting edema both legs. Appropriate management?", "choices": ["PO diuretic", "Dobutamine", "IV morphine", "IV nitroglycerin", "IV furosemide"], "ans": 4, "exp": "ภาวะหัวใจล้มเหลวในหญิงตั้งครรภ์ (JVP สูง, หัวใจโต, rales, ขาบวม = volume overload/pulmonary congestion) → IV furosemide ลด preload/คั่งน้ำ. Dobutamine ใช้เมื่อ cardiogenic shock; nitroglycerin เป็น adjunct"}, {"topic": "Obstetrics & Gynecology", "q": "A 26 year-old pregnant woman, G1P0 GA 34 wks, comes for routine antenatal care. She reports that her baby is less active than usual. On PE, you cannot detect a fetal heart beat either by a stethoscope or a fetal heart doppler. Which is the most appropriate management?", "choices": ["Ultrasonogram", "Non stress test", "Vibroacoustic stimulation test", "Internal fetal monitoring", "Terminate of pregnancy"], "ans": 0, "exp": "ตรวจไม่พบเสียงหัวใจทารกด้วย stethoscope/doppler → ต้องยืนยันด้วย real-time ultrasound (ดู fetal cardiac activity) ก่อนสรุปว่าเป็น fetal demise หรือหาสาเหตุ. NST/VST ต้องมี FHR อยู่ก่อนจึงทำได้"}, {"topic": "Obstetrics & Gynecology", "q": "A 33 year-old pregnant woman G2P1001 GA 34 week come to ANC. She has had a persistent headache and epigastric pain for 1 day. PE: BP 150/90 mmHg, pitting edema 2+. Lab: BUN 20, Cr 1.2, Hb 10.2, WBC 10500, Plt 90000, AST 30, ALT 50. What is the diagnosis?", "choices": ["Gestational GDM", "Preeclampsia with severe features", "Preeclampsia without severe features", "Eclampsia", "Chronic hypertension with superimposed preeclampsia with severe features"], "ans": 1, "exp": "BP ≥ 140/90 หลัง 20 สัปดาห์ + มี severe features (ปวดหัวต่อเนื่อง, epigastric pain, thrombocytopenia Plt < 100,000) = preeclampsia with severe features. (ไม่ใช่ eclampsia เพราะยังไม่ชัก; ไม่มีประวัติ HT ก่อน 20 wk จึงไม่ใช่ superimposed)"}, {"topic": "Obstetrics & Gynecology", "q": "แม่อายุ 34 แท้งบ่อย แท้งตอน GA 7,11,8 ตามลำดับ. ถามว่าเกิดจากอะไร", "choices": ["Myoma uteri", "Bicornuate uterus", "chromosome abnormality", "recurrent infection", "cervix incompetent"], "ans": 2, "exp": "แท้งซ้ำในไตรมาสแรก (7,11,8 สัปดาห์) → สาเหตุที่พบบ่อยสุดคือความผิดปกติของโครโมโซม (parental balanced translocation/fetal aneuploidy). cervical incompetence/bicornuate มักแท้งไตรมาสสอง"}, {"topic": "Obstetrics & Gynecology", "q": "30 yr old G2P1001 GA ใกล้ term มาด้วย bright red bleeding per vagina with abdominal pain. PE: PR 120, BP drop, palpable fetal part, FHS 80. Dx?", "choices": ["Mucous bloody show", "Abruptio placenta", "Uterine rupture"], "ans": 1, "exp": "เลือดออกทางช่องคลอด + ปวดท้อง + มารดาช็อก + fetal distress (FHS 80) ในมดลูกที่ไม่มีแผลผ่าตัดเดิม = abruptio placentae (รกลอกตัวก่อนกำหนด). *ถ้ามีแผลผ่าคลอดเดิม + คลำ fetal part ได้ชัด ให้คิดถึง uterine rupture*"}, {"topic": "Obstetrics & Gynecology", "q": "28 y/o G2P1 GA 14 wk second visit ANC. Lab: Patient - MCV 61, DCIP+, HbE 19%; husband - MCV 58, DCIP+, HbE 98%. Proper management?", "choices": ["Routine ANC", "Cordocentesis for fetal alpha thal", "Amniocentesis for fetal DNA B-thal", "Husband alpha thal PCR", "Patient DNA test for B-thal"], "ans": 4, "exp": "ทั้งคู่ MCV ต่ำมาก + DCIP+ (มี HbE). ภรรยา HbE trait (E 19%) แต่ MCV ต่ำผิดปกติ (61) ชวนให้มี beta-thal ร่วม; สามี HbE สูงมาก (E 98% = homozygous HbE หรือ HbE/beta-thal). เพื่อประเมินความเสี่ยงลูกเป็น beta-thalassemia/HbE ต้องตรวจ DNA beta-thal ในภรรยา (ถ้าเป็นพาหะ beta-thal ร่วม → ลูกเสี่ยงโรครุนแรง → prenatal diagnosis)"}, {"topic": "Obstetrics & Gynecology", "q": "30 yr G2P1001 GA 36 wk hx of Cesarean section มาด้วย Red bright blood from vagina. PE: BP 80/60 PR 120. Abd: Generalized tender c rebound tenderness, Palpable fetal part, FHS 80. Dx?", "choices": ["Uterine rupture", "Placenta previa", "Abrubtio placenta", "Rupture vasa previa", "Mucous bloody show"], "ans": 0, "exp": "มีแผลผ่าคลอดเดิม (previous C/S) + เลือดออก + ปวดท้องทั่ว + rebound + คลำ fetal part ได้ชัด (ทารกออกมาในช่องท้อง) + ช็อก + fetal distress = uterine rupture (มดลูกแตกจากรอยแผลเดิม)"}, {"topic": "Obstetrics & Gynecology", "q": "A 50 year-old healthy female feels a sudden hot and cold sensation all over the body and cannot sleep well. She feels pain in vagina during having sex. Her husband says that she has mood swings. She underwent hysterectomy due to myoma uteri 2 years ago. What is the appropriate management?", "choices": ["OCP", "E only pill", "P only pill", "cyclic E+P", "continuous E+P"], "ans": 1, "exp": "อาการวัยทอง (ร้อนวูบวาบ, นอนไม่หลับ, ช่องคลอดแห้ง/เจ็บเวลามีเพศสัมพันธ์, อารมณ์แปรปรวน) ในผู้ที่ตัดมดลูกไปแล้ว → ให้ estrogen-only replacement (ไม่ต้องมี progestin เพราะไม่มีมดลูกให้ป้องกัน endometrial hyperplasia)"}, {"topic": "Obstetrics & Gynecology", "q": "A 20 years old female presented with massive vaginal bleeding after illegal abortion. PE: pale, BP 90/60 mmHg, PR 120 bpm, RR 24, Hct 25%. ได้ NSS กับ PRC. หลังจากนั้น 10 min มี chest tightness and agitation. V/S: BP 80/60, HR 120, RR 30. Lung: wheezing both lungs. ถามสาเหตุเกิดจากอะไร", "choices": ["Acute pulmonary edema", "Pulmonary embolism", "Mismatch transfusion", "Amniotic embolism", "Septic shock"], "ans": 2, "exp": "อาการเฉียบพลันหลังให้ PRC ~10 นาที (แน่นอก กระสับกระส่าย ความดันตก wheezing) = acute hemolytic transfusion reaction จาก ABO mismatch (mismatch transfusion). ต้องหยุดให้เลือดทันที + resuscitate + ตรวจซ้ำ"}, {"topic": "Obstetrics & Gynecology", "q": "คนท้อง GA 12 มาด้วยลูกดิ้นน้อยลง มาตรวจฟังด้วย stethoscope และตรวจตาม ANC ไม่เจอ FHS. ถาม most proper management", "choices": ["นัดอีก 1 week มาตรวจใหม่", "Termination", "PV", "UGS (ultrasound)"], "ans": 3, "exp": "ฟังไม่พบเสียงหัวใจทารก → ยืนยันด้วย ultrasound (UGS) ว่ามี fetal cardiac activity หรือไม่ ก่อนตัดสินใจ. ไม่ควรนัดรอ 1 สัปดาห์หรือ terminate โดยไม่ยืนยันก่อน"}, {"topic": "Obstetrics & Gynecology", "q": "Pregnancy ประมาณ first trimester เป็น hyperthyroid กิน MMI (methimazole) อยู่แล้ว เพิ่งรู้ว่าท้อง. ควรทำอย่างไร (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือกชัด)", "choices": ["Continue MMI same dose", "Increase MMI dose", "Decrease MMI dose", "Discontinue MMI", "Switch to PTU"], "ans": 4, "exp": "หญิงตั้งครรภ์ไตรมาสแรกที่ใช้ MMI → เปลี่ยนเป็น PTU เพราะ MMI ในไตรมาสแรกเสี่ยง teratogenic (aplasia cutis, choanal/esophageal atresia). หลังไตรมาสแรกมักเปลี่ยนกลับเป็น MMI"}, {"topic": "Obstetrics & Gynecology", "q": "มารดา G1P0 GA 41 wk มาฝากครรภ์ตามนัด ตรวจร่างกายปกติดี ลูกดิ้นดี V/S stable. ถามทำอย่างไรดี", "choices": ["Membranous stripping เลย", "นัดติดตามอาการ อีกที 1 wk", "นัด admit เพื่อผ่าคลอด อีกที 1 wk", "เจาะถุงน้ำคร่ำ ณ visit นั้นเลย"], "ans": 0, "exp": "GA 41 สัปดาห์ (ใกล้ post-term) → ควรกระตุ้นให้เข้าสู่การคลอด. Membrane stripping/sweeping ช่วยกระตุ้นการคลอดตามธรรมชาติและลด post-term. การรอ 1 สัปดาห์เสี่ยง post-term; C/S ไม่มีข้อบ่งชี้; amniotomy ทำเมื่อพร้อมคลอด/admit"}, {"topic": "Obstetrics & Gynecology", "q": "Female pt underwent illegal abortion, she has amenorrhea ever since. What is the proper management?", "choices": ["Ultrasound", "hysteroscopy"], "ans": 1, "exp": "ขาดประจำเดือนหลังทำแท้ง/ขูดมดลูก = Asherman syndrome (พังผืดในโพรงมดลูก) → hysteroscopy วินิจฉัยและแยกพังผืดได้โดยตรง"}, {"topic": "Obstetrics & Gynecology", "q": "ผู้ป่วยหญิงอายุ 60 มี N/V เคยมีประวัติ PPH (postpartum hemorrhage) ไม่ได้บอกว่าเมื่อไหร่. ถามว่าเป็นอะไร", "choices": ["empty sella syndrome", "Sheehan syndrome"], "ans": 1, "exp": "ประวัติตกเลือดหลังคลอด (PPH) รุนแรง + ต่อมามีอาการ hypopituitarism (คลื่นไส้อาเจียนจาก adrenal insufficiency ฯลฯ) = Sheehan syndrome (ต่อมใต้สมองส่วนหน้าตายจากการขาดเลือดหลัง PPH)"}, {"topic": "Obstetrics & Gynecology", "q": "หญิงมีก้อน fluctuate ที่ตำแหน่ง 4 นาฬิกาของ labia ขนาด 4x4 cm. ถามว่าทำอะไร", "choices": ["Marsupialization", "i&d"], "ans": 0, "exp": "ก้อนที่ labia ตำแหน่ง 4-5 นาฬิกา = Bartholin gland cyst/abscess. การรักษาที่ลดการเป็นซ้ำ (definitive) คือ marsupialization. (I&D เดี่ยว ๆ เป็นซ้ำง่าย; abscess เฉียบพลันอาจใช้ I&D + Word catheter)"}, {"topic": "Obstetrics & Gynecology", "q": "หญิงมาฝากครรภ์ แม่ MCV ต่ำ DCIP+ HbE trait; พ่อ MCV ต่ำ DCIP+ HbA2/E 98% เป็น homozygous HbE. ถามว่าต้องตรวจอะไรต่อ", "choices": ["ANC ปกติ", "ส่ง alpha-thal ทั้งพ่อทั้งแม่"], "ans": 1, "exp": "ทั้งคู่ MCV ต่ำที่อธิบายด้วย HbE อย่างเดียวไม่พอ → สงสัยมี alpha-thalassemia ร่วมทั้งคู่ ต้องส่ง alpha-thal gene (PCR) ทั้งพ่อและแม่ เพื่อประเมินความเสี่ยงลูกเป็น Hb Bart's hydrops fetalis (ถ้าทั้งคู่เป็น alpha-thal-1 carrier)"}, {"topic": "Obstetrics & Gynecology", "q": "หญิงท้อง GA จำไม่ได้แต่พร้อมคลอด cx 3 cm efface จำไม่ได้ uc 45\"/7' (contraction 45 วินาที ห่าง 7 นาที = inadequate). ถามว่าทำอะไร", "choices": ["เจาะถุงน้ำ (amniotomy)", "iv oxytocin"], "ans": 0, "exp": "contraction ยังห่าง (inadequate) + ถุงน้ำยังไม่แตก → augment labor ด้วย amniotomy (เจาะถุงน้ำ) ก่อน แล้วค่อยพิจารณา oxytocin ถ้ายังไม่พอ"}, {"topic": "Obstetrics & Gynecology", "q": "A 30 years old presented with recurrent postcoital bleeding 3 mon PTA, LMP 2 weeks ago. PE: Smooth surface, finger-like mass with narrow stalk protruding from cervical os. ให้ทำอะไรต่อ", "choices": ["HBV DNA", "Polypectomy", "Sclerotherapy", "Punch biopsy", "Colposcopy with biopsy"], "ans": 1, "exp": "ก้อนผิวเรียบ รูปนิ้วมือ มีก้านแคบยื่นจากปากมดลูก + เลือดออกหลังมีเพศสัมพันธ์ = cervical polyp → รักษาด้วย polypectomy (บิด/ตัดออก + ส่งพยาธิ)"}, {"topic": "Obstetrics & Gynecology", "q": "A 29 year old woman presented with galactorrhea and absent menstruation for several months. BP 141/90 PR 50. No cushingoid appearance, no acromegaly. Pituitary MRI show mass 1 cm at gland with no chiasmatic invasion. Dx?", "choices": ["Schwannoma", "Craniopharyngioma", "Prolactinoma", "Sheehan syndrome"], "ans": 2, "exp": "น้ำนมไหล (galactorrhea) + ขาดประจำเดือน + pituitary microadenoma 1 ซม. = prolactinoma. รักษาด้วย dopamine agonist (cabergoline/bromocriptine)"}, {"topic": "Obstetrics & Gynecology", "q": "Female 30 ปี U/D Grave disease on MMI 6 mo มา 1st ANC, LMP 2 mo. V/S stable, TFT normal, No thyroid gl enlargement. Mx?", "choices": ["stop MMI", "decreased dose MMI", "increased dose MMI", "change to PTU", "continued dose MMI"], "ans": 3, "exp": "หญิงตั้งครรภ์ไตรมาสแรกที่ใช้ MMI → เปลี่ยนเป็น PTU (MMI ในไตรมาสแรกเสี่ยง teratogenic). ไม่หยุดยา (เพราะยังต้องคุม hyperthyroid ระวัง thyroid storm)"}, {"topic": "Obstetrics & Gynecology", "q": "ผู้หญิง sexual active มาด้วยปวดหน่วงท้องน้อยด้านขวาล่าง, ใส่ IUD มา 2 ปีแล้ว. PE: RLQ tenderness and rebound tenderness. PV: mucopurulent per os, inflammatory Cx, cervical motion tenderness, Rt adnexal mass 5 cm. What is the most appropriate mx?", "choices": ["UPT", "ผ่า explore laparotomy", "Remove IUD", "Cervical swab C/S for aerobe", "IV ATB"], "ans": 4, "exp": "PID ที่มี tubo-ovarian abscess (adnexal mass 5 ซม. + cervical motion tenderness + mucopurulent discharge) → เริ่มด้วย IV broad-spectrum antibiotics. พิจารณาถอด IUD + drainage/surgery ถ้าไม่ตอบสนอง/แตก"}, {"topic": "Obstetrics & Gynecology", "q": "แม่เด็ก 15 ปี กำลังให้นมบุตร คลอดไปเมื่อ 6 สัปดาห์ก่อน. จะแนะนำให้ใช้ contraception อะไรดี", "choices": ["Subdermal implant", "DMPA", "Contraceptive pill", "Condom", "Contraceptive patch"], "ans": 0, "exp": "หญิงให้นมบุตร → หลีกเลี่ยง estrogen (pill/patch). เลือก progestin-only ที่มีประสิทธิภาพสูงและเหมาะกับวัยรุ่น = subdermal implant (LARC). (DMPA ก็เป็น progestin-only ที่ใช้ได้)"}, {"topic": "Pediatrics", "q": "เด็กชายไข้ + DOE 2 วัน. PE: V/S BT 38.5°C, PR 116 bpm, BP and RR normal; GA - marked pallor; HEENT - mild icteric sclera; GI - hepatosplenomegaly. Labs: CBC - Hb 7, Hct 21, MCV 68, MCHC 28, RDW 23%, WBC 11800 (pmn 80), platelet normal. PBS: anisopoikilocytosis, hypochromic microcytic 2+, polychromasia, basophilic stippling. What is the most proper investigation?", "choices": ["OF test", "Hb typing", "Urine hemosiderin", "G6PD level", "DAT"], "ans": 1, "exp": "เด็กที่มี microcytic hypochromic anemia + hemolysis (ตัวเหลือง, ตับม้ามโต, polychromasia) + basophilic stippling + anisopoikilocytosis = thalassemia → ตรวจ Hb typing เพื่อวินิจฉัยชนิด"}, {"topic": "Pediatrics", "q": "A Newborn day of life 3, PE: positive Ortolani's test of Lt. hip. What is the appropriate management?", "choices": ["F/U 2 wk", "F/U 2 months", "U/S", "CT", "MRI"], "ans": 2, "exp": "Ortolani positive = developmental dysplasia of the hip (DDH) — ข้อสะโพกเคลื่อน. ในทารก (< 6 เดือน กระดูกยังไม่ ossify) ตรวจยืนยันด้วย ultrasound ของสะโพก (ไม่ใช้ X-ray/CT). รักษาด้วย Pavlik harness"}, {"topic": "Pediatrics", "q": "A newborn day of life 5. Mother had a mucopurulent vaginal discharge. Gram stain found intracellular gram negative diplococci. Clinical: active newborn, no fever, no eye discharge. What is the proper management?", "choices": ["Topical neomycin", "Topical polymyxin B", "IV cloxacillin + gentamicin", "IV Ceftriaxone", "IV ampicillin + gentamicin"], "ans": 3, "exp": "แม่ติดเชื้อ gonorrhea (intracellular gram-negative diplococci) → ทารกที่สัมผัสเชื้อต้องได้ ceftriaxone (single dose IV/IM) เพื่อป้องกัน/รักษา gonococcal ophthalmia neonatorum (ยาหยอดตาเฉพาะที่ไม่พอ)"}, {"topic": "Pediatrics", "q": "A term male newborn jaundice, กินนมแม่ดี, อายุ 2 วัน. ลูก group B, Rh positive, DAT negative. แม่ group O, Rh positive. Blood smear เป็น hemolysis (schistocytes, polychromasia), reticulocyte 3%. What is the cause of jaundice?", "choices": ["Hereditary spherocytosis", "ABO incompatibility", "G6PD def"], "ans": 1, "exp": "แม่ group O + ลูก group B = ABO incompatibility (ABO hemolytic disease of newborn) — anti-A/anti-B (IgG) ของแม่ผ่านรกทำลายเม็ดเลือดลูก. DAT อาจ negative/weak ได้ใน ABO HDN (ต่างจาก Rh ที่ DAT positive ชัด)"}, {"topic": "Pediatrics", "q": "Term neonate มีอาการเหนื่อย (respiratory distress). PE: scaphoid abdomen, decreased breath sound ด้านขวา. ถาม appropriate initial mx", "choices": ["ET tube", "CXR", "Oxygen mask ventilation", "Nasal CPAP", "Rt. pleural tapping"], "ans": 0, "exp": "scaphoid abdomen + เสียงหายใจลดข้างหนึ่ง + หายใจลำบากในทารกแรกเกิด = congenital diaphragmatic hernia (CDH). การจัดการเบื้องต้นคือ ET tube (intubation) + NG decompression. *ห้าม bag-mask ventilation เพราะดันลมเข้าลำไส้ที่อยู่ในทรวงอก ทำให้ปอดถูกกดมากขึ้น*"}, {"topic": "Pediatrics", "q": "Term NB, V/S at 1 hr, PE: RR 48, MAP 44, BW 4000. Collected blood only at the right parietal bone (ไม่ข้าม suture). Mx?", "choices": ["Blood gas", "Serial hct", "DTX", "U/s brain", "X-ray scalp"], "ans": 1, "exp": "เลือดคั่งใต้ periosteum จำกัดที่กระดูก parietal ข้างเดียว ไม่ข้าม suture = cephalohematoma. ส่วนใหญ่หายเอง → ติดตามด้วย serial hct (เฝ้าภาวะซีดจากเสียเลือด) และเฝ้าระวัง hyperbilirubinemia"}, {"topic": "Pediatrics", "q": "A term infant was born at home to a mother with no ANC. She cut umbilical cord with scissors. PE: BT 37°C, BP 55/38 mmHg, HR 140 bpm, RR 50/min, others WNL. นอกจากรักษาด้วย ampicillin แล้วให้อะไรอีก", "choices": ["Gentamicin", "Tetanus toxoid", "Gentamicin + tetanus toxoid + immune globulin", "Gentamicin + tetanus toxoid", "Immune globulin"], "ans": 2, "exp": "ทารกคลอดสกปรก (ตัดสายสะดือด้วยกรรไกร) + ไม่มี ANC → เสี่ยง neonatal sepsis + neonatal tetanus → เพิ่ม gentamicin (คลุม sepsis ร่วม ampicillin) + tetanus immune globulin (TIG, passive) ± tetanus toxoid. ตัวเลือกที่ครบสุดคือ gentamicin + toxoid + immune globulin"}, {"topic": "Pediatrics", "q": "1 day old term presents with tachypnea. Mother had PROM for 24 hr. PE: V/S - HR 170 bpm, RR 90 bpm, BP 64/38 mmHg, O2sat 98%; Lung - Subcostal retraction, normal breath sound, no crepitation. Lab: WBC 25,000 (pmn 85, L 10), Platelet 180,000. CXR: Normal. What is the most proper investigation?", "choices": ["Urine culture", "Lumbar puncture", "CRP", "Hemoculture", "Arterial blood gas"], "ans": 3, "exp": "ทารกแรกเกิด + PROM 24 ชม. (risk factor) + tachypnea + leukocytosis (WBC 25,000, left shift) = สงสัย neonatal sepsis → ตรวจยืนยันด้วย hemoculture (gold standard) ก่อนให้ empiric antibiotic"}, {"topic": "Pediatrics", "q": "NB 4200 g, vacuum delivery, BP 60/30, เจอ fluctuate boggy mass with head skin ecchymosis. ถามว่า diag อะไร", "choices": ["caput succedaneum", "Cephalhematoma", "subgaleal hematoma", "ICH"], "ans": 2, "exp": "หลังคลอดด้วย vacuum + ก้อนนุ่มยวบข้ามรอยต่อกะโหลก + ecchymosis + ความดันตก (เสียเลือดมาก) = subgaleal hemorrhage (เลือดออกใต้ galea ปริมาณมาก เสี่ยงช็อก). ต่างจาก caput (บวมน้ำ ข้าม suture ไม่ช็อก) และ cephalohematoma (ไม่ข้าม suture)"}, {"topic": "Pediatrics", "q": "เด็กแรกเกิด GA 38 wk BW 4000 g แม่เป็นเบาหวาน APGAR 2,5 เจาะน้ำตาลที่ 1 ชม.แรกได้ 45 มีอาการ hypotonia ร่วม. ถามทำอย่างไร", "choices": ["IV 10% dextrose 8 ml (bolus)", "Early feed", "IV 10% dextrose ปรับ rate", "Follow up อีกที่ 2 ชม"], "ans": 0, "exp": "ทารกแม่เบาหวาน (IDM) ตัวโต + hypoglycemia (45) + มีอาการ (hypotonia) = symptomatic neonatal hypoglycemia → ให้ IV dextrose bolus (D10 2 mL/kg ≈ 8 mL สำหรับ 4 กก.) ไม่ใช่แค่ให้กินนม/รอดู"}, {"topic": "Pediatrics", "q": "เด็ก 6 ปี มี left rhinorrhea with left facial pain. PE: bilateral congestion at inferior turbinate, Lt nasal discharge. Diagnosis?", "choices": ["allergic rhinitis", "foreign body in Lt nostril", "adenoid hypertrophy", "Lt sinusitis"], "ans": 1, "exp": "น้ำมูก/หนองข้างเดียว (unilateral) ในเด็กเล็ก = สิ่งแปลกปลอมในจมูก (nasal foreign body) จนกว่าจะพิสูจน์เป็นอื่น (มักมีกลิ่นเหม็น). *โจทย์ต้นฉบับจัดรูปแบบตัวเลือกไม่ชัด — เรียบเรียงตามที่ปรากฏ; ถ้าเน้นปวดใบหน้า+น้ำมูกข้างเดียวอาจเป็น sinusitis*"}, {"topic": "Pediatrics", "q": "วัยรุ่น urticaria 2 วัน (เป็นแค่แขน). First line treatment? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับตัวเลือกหาย)", "choices": ["1st-generation antihistamine", "Systemic corticosteroid", "2nd-generation (non-sedating) antihistamine เช่น cetirizine", "IM epinephrine", "Topical corticosteroid"], "ans": 2, "exp": "Urticaria (ลมพิษ) รักษา first-line ด้วย second-generation (non-sedating) antihistamine เช่น cetirizine/loratadine. steroid ใช้ในรายรุนแรง/ดื้อ; epinephrine ใช้เมื่อมี anaphylaxis"}, {"topic": "Pediatrics", "q": "A child presented with dyspnea. She sat in a tripod position. Lateral neck film shows thumb sign. What is the diagnosis?", "choices": ["Epiglottitis", "Viral croup"], "ans": 0, "exp": "หายใจลำบาก + นั่งท่า tripod + lateral neck film เห็น thumb sign (epiglottis บวม) = acute epiglottitis (ภาวะฉุกเฉินทางเดินหายใจ ห้ามตรวจคอกระตุ้น secure airway โดยผู้เชี่ยวชาญ + ceftriaxone). (Croup = steeple sign)", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q186.png"}, {"topic": "Pediatrics", "q": "เด็กมีไข้ ไอ มา 3 วันแล้ว มาวันนี้มี barking cough + stridor + mucopurulent rhinorrhea. Dx?", "choices": ["Acute epiglottitis", "Pneumonia", "Bacterial tracheitis", "Viral croup"], "ans": 3, "exp": "ไอเสียงก้อง (barking/seal-like cough) + stridor + นำมาด้วย URI (rhinorrhea) = viral croup (laryngotracheobronchitis จาก parainfluenza). Epiglottitis จะ toxic + drooling ไม่มี barking cough; bacterial tracheitis toxic + ไข้สูง เสมหะข้น ไม่ตอบสนอง croup treatment"}, {"topic": "Pediatrics", "q": "เด็กหญิง ~10 ขวบ มาด้วยเหนื่อย สงสัย pneumonia ได้ Ceftriaxone 4 วันแล้วไม่ดีขึ้น ยังมีไข้สูงอยู่. CXR: moderate pleural effusion, เจาะน้ำมาเป็น transudate. ต้องทำยังไงต่อ", "choices": ["Add Azithromycin", "Add Levofloxacin", "Switch to Imipenem", "Repeat thoracentesis", "Insert chest tube"], "ans": 0, "exp": "เด็กวัยเรียนที่ pneumonia ไม่ตอบสนอง beta-lactam (ceftriaxone) → คิดถึงเชื้อ atypical (Mycoplasma pneumoniae) → เพิ่ม macrolide (azithromycin). Effusion เป็น transudate (uncomplicated) จึงยังไม่ต้องใส่ chest tube"}, {"topic": "Pediatrics", "q": "เด็ก 6 ปี มี sleeping problem 2 ปี + bilateral nasal obstruction, runny nose, aural fullness. Sleep test: mild OSA. PE: bilateral pale swelling nasal mucosa, tonsil grade I both sides. Lateral neck: adenoid gland hypertrophy 50%. Most appropriate mx?", "choices": ["Nasal CPAP", "Adenoidectomy", "Intranasal steroid", "Oral prednisone", "Oral antihistamine"], "ans": 1, "exp": "OSA ในเด็กจาก adenoid hypertrophy (adenoid โต 50%, tonsil เล็ก grade I) → adenoidectomy เป็นการรักษาที่จัดการต้นเหตุทางกายวิภาค. *ใน mild OSA ที่มี allergic rhinitis ร่วม intranasal steroid เป็นทางเลือกเริ่มต้นแบบไม่ผ่าตัดได้เช่นกัน*"}, {"topic": "Pediatrics", "q": "เด็ก 1 ปี มีอาการ cyanosis when crying or defecation เคยมีอาการมาก่อน (hypoxic spell). PE: central cyanosis, clubbing finger. ถาม mx", "choices": ["Digitalis", "Furosemide", "Morphine", "Adenosine"], "ans": 2, "exp": "เขียวเวลาร้อง/เบ่ง + clubbing + hypoxic (cyanotic/tet) spell = Tetralogy of Fallot. การรักษา tet spell: knee-chest position, O2, morphine (ลด hyperpnea/infundibular spasm), IV fluid, propranolol. ในตัวเลือกนี้คือ morphine"}, {"topic": "Pediatrics", "q": "เด็กมี palpable purpura ที่ขา 2 ข้าง ปวดท้อง ปัสสาวะมี red cell. Diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Immune thrombocytopenic purpura (ITP)", "Hemolytic uremic syndrome", "Meningococcemia", "Henoch-Schönlein purpura (IgA vasculitis)", "Systemic lupus erythematosus"], "ans": 3, "exp": "จุดเลือดออกคลำได้ (palpable purpura) ที่ขาทั้งสองข้าง + ปวดท้อง + ปัสสาวะมีเม็ดเลือดแดง (renal involvement) = Henoch-Schönlein purpura (IgA vasculitis) — tetrad คือ purpura ที่ก้น/ขา, arthritis, abdominal pain, nephritis. ต่างจาก ITP ที่ purpura ไม่นูน (non-palpable) และเกล็ดเลือดต่ำ"}, {"topic": "Pediatrics", "q": "A 9-year-old girl presented with a brief episode of staring and decreased school performance for 3 months. She usually stared for 10-15 seconds without responding to a call. PE: stable vital signs, no neurological deficits. What is the most appropriate management?", "choices": ["CT brain", "LP", "Phenytoin", "Diazepam", "EEG"], "ans": 4, "exp": "เหม่อลอย จ้องนิ่ง 10-15 วินาที ไม่ตอบสนอง + การเรียนแย่ลง = absence seizure (childhood absence epilepsy). ขั้นตอนที่เหมาะสมคือทำ EEG (พบ 3 Hz generalized spike-and-wave) เพื่อยืนยัน. *ต้นฉบับไฮไลต์ phenytoin ซึ่งผิด — phenytoin ทำให้ absence แย่ลง ยาที่ใช้จริงคือ ethosuximide/valproate*"}, {"topic": "Pediatrics", "q": "เด็กชาย 16 ปี unresponsiveness 1 hr. PE: BT 37°C, PR 60 bpm, RR 10/min, BP 152/84 mmHg. CNS - withdrawal to painful stimulation, pupil Rt 5 mm not react to light, pupil Lt 3 mm not react to light, DTR 2+ all. What is the initial management?", "choices": ["ETT (endotracheal intubation)", "CT brain", "MRI brain", "Raise head 30-45 degree", "IV dexamethasone"], "ans": 0, "exp": "ผู้ป่วยหมดสติ (GCS ต่ำ, withdrawal to pain) + Cushing's reflex (BP สูง 152/84, bradycardia PR 60, RR ต่ำ 10) + pupil ไม่เท่ากันไม่ตอบสนองแสง = ภาวะ raised ICP/herniation. Initial management ตามหลัก ABC คือ secure airway ด้วย ETT (GCS ≤ 8 ต้องใส่ท่อ) ก่อน แล้วจึงจัดการ ICP อื่น"}, {"topic": "Pediatrics", "q": "A 3 years old with no underlying disease presents with abdominal distention for 2 weeks. PE: Rt mass at RUQ 8×8 cm. CBC: Hct 37%, WBC normal. UA: RBC 30-50 cells, WBC 3-5 cells. What is the diagnosis?", "choices": ["Neuroblastoma", "Wilms tumor", "Hepatoblastoma", "Pheochromocytoma"], "ans": 1, "exp": "ก้อนในท้องเด็ก 3 ขวบ + ปัสสาวะมีเม็ดเลือดแดง (hematuria) ชี้ว่ามาจากไต = Wilms tumor (nephroblastoma). Neuroblastoma มักข้าม midline + ไม่มี hematuria, hepatoblastoma มาจากตับ AFP สูง, pheochromocytoma มี HT/เหงื่อออก"}, {"topic": "Pediatrics", "q": "เด็กชาย 4 ปี ไข้ 2 วัน shortness of breath เมื่อคืน ปัสสาวะสีเข้ม. PE: BT 37.5°C, RR 40, PR 140, BP 100/60, moderate pale conjunctiva. CBC: Hb 5.0, WBC 15,000 (N80 L20), Platelet 390,000. UA: dark urine, Urobilinogen +ve, Blood 2+. What is management?", "choices": ["Force diuresis", "Urine alkalinization", "PRC transfusion", "Prednisolone", "IV immunoglobulin"], "ans": 2, "exp": "ไข้เป็นตัวกระตุ้น + ซีดเฉียบพลันรุนแรง (Hb 5.0) + ปัสสาวะสีเข้ม (hemoglobinuria, urobilinogen +) = acute hemolysis (นึกถึง G6PD deficiency). ซีดรุนแรงมีอาการ (เหนื่อย หัวใจเต้นเร็ว) → รักษาด้วย PRC transfusion + หยุดตัวกระตุ้น"}, {"topic": "Pediatrics", "q": "คนไข้เด็ก มาด้วย vomiting and diarrhea. V/S ปกติ ตรวจเจอ hyperpigmented ที่ nipple และ palmar crease. Lab: hypoNa, hyperK น่าจะเป็น Addison disease. Most appropriate management?", "choices": ["3% NaCl", "HCO3", "Fludrocortisone", "Hydrocortisone"], "ans": 3, "exp": "Adrenal insufficiency/Addisonian crisis (hyperpigmentation, hypoNa/hyperK) → รักษาเฉียบพลันด้วย hydrocortisone (stress-dose มีทั้งฤทธิ์ gluco- และ mineralocorticoid) ร่วมกับ IV NSS. Fludrocortisone ใช้ maintenance ระยะยาว ไม่ใช่ภาวะเฉียบพลัน"}, {"topic": "Pediatrics", "q": "เด็กหญิงวัยรุ่น ตัวใหญ่ อ้วนมาก มี acanthosis nigricans. HbA1c 6%, FBS 83 mg/dL. Investigate อะไรดี", "choices": ["OGTT", "Insulin level", "C-peptide"], "ans": 0, "exp": "วัยรุ่นอ้วน + acanthosis nigricans (ภาวะดื้ออินซูลิน) + HbA1c 6% (ก้ำกึ่ง prediabetes) แต่ FBS ปกติ → ตรวจ OGTT (oral glucose tolerance test) เพื่อยืนยัน prediabetes/DM ที่ระดับ 2 ชม.หลังกินกลูโคส"}, {"topic": "Pediatrics", "q": "เด็กน้อยอ้วก ถ่ายเป็นเลือด (currant jelly stool). Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Intussusception"], "ans": 0, "exp": "เด็กเล็กอาเจียน + ถ่ายเป็นเลือดมูก (currant jelly stool) ± ก้อนไส้กรอกในท้อง = Intussusception (ลำไส้กลืนกัน). วินิจฉัยด้วย US (target sign) รักษาด้วย air/contrast enema reduction"}, {"topic": "Pediatrics", "q": "A child usually makes an abnormal sound. Sometimes he can control the symptom. No abnormal movement was observed. What is the diagnosis?", "choices": ["Tourette syndrome", "Tic disorder (vocal tic)"], "ans": 1, "exp": "มีแค่เสียงผิดปกติ (vocal tic) กดข่มได้ชั่วคราว และ 'ไม่มี' การเคลื่อนไหวผิดปกติ (ไม่มี motor tic) = tic disorder (persistent vocal tic). Tourette syndrome ต้องมีทั้ง motor และ vocal tics นานกว่า 1 ปี"}, {"topic": "Pediatrics", "q": "A 9 years old girl presents with a minor headache and stomachache and refuses to go to school. She is afraid that if something bad happens, she will not be with her mother. She sometimes dreams that she is alone and is found alone crying. PE: unremarkable. What is the most likely diagnosis?", "choices": ["Normal reaction", "Simple phobia", "Separation anxiety disorder", "Schizophrenia", "Sibling rivalry"], "ans": 2, "exp": "ปวดหัว/ปวดท้อง (somatic) + ไม่ยอมไปโรงเรียน + กลัวพลัดพรากจากแม่ (กลัวไม่ได้อยู่กับแม่) + ฝันว่าอยู่คนเดียว = Separation anxiety disorder"}, {"topic": "Pediatrics", "q": "เด็กชอบป่วยวันธรรมดา ไม่ยอมไปโรงเรียน เสาร์อาทิตย์อาการดี อยู่กับแม่ตลอด กลัวแม่หาย. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Social phobia", "Separation anxiety disorder"], "ans": 1, "exp": "ป่วยเฉพาะวันไปโรงเรียน หายในวันหยุด + ติดแม่ กลัวแม่หาย = Separation anxiety disorder. *ต้นฉบับไฮไลต์ social phobia ซึ่งไม่ตรง — social phobia คือกลัวการเข้าสังคม/ถูกจับจ้อง ไม่ใช่กลัวพลัดพรากจากผู้เลี้ยง*"}, {"topic": "Pediatrics", "q": "เด็กผู้หญิง 3 ขวบ นน 19 กก. สูง 102 ซม. กินข้าววันละ 4 มื้อ นมวันละ 6 แก้ว. คำแนะนำที่เหมาะสม", "choices": ["ออกกำลังกาย", "เปลี่ยนนมจาก whole milk เป็น skim milk", "กินเท่าเดิม", "ลดข้าว", "ลดนมและข้าว"], "ans": 4, "exp": "เด็ก 3 ขวบ นน 19 กก. (เกินเกณฑ์ ปกติ ~14 กก.) = overweight จากพลังงานเกิน โดยเฉพาะนม 6 แก้ว/วัน (มากเกิน) + ข้าว 4 มื้อ → แนะนำลดปริมาณนมและข้าวลง (ลดพลังงานส่วนเกินทั้งสองแหล่ง)"}, {"topic": "Pediatrics", "q": "เด็ก มีไข้ 2 วัน barking cough. V/S: BT 38°C, SpO2 92%. What is the prevention of this disease?", "choices": ["Frequent hand washing", "Vaccination", "Wearing mask when going outside"], "ans": 0, "exp": "ไอเสียงก้อง (barking cough) = viral croup จาก parainfluenza virus ซึ่งยังไม่มีวัคซีนเฉพาะ. ป้องกันการแพร่เชื้อทางเดินหายใจ (droplet/contact) ด้วยการล้างมือบ่อย ๆ (frequent hand washing)"}, {"topic": "Pediatrics", "q": "Five children visited the ER with bloody diarrhea and acute renal failure after eating together at a birthday party. What did they eat?", "choices": ["Soft boiled egg", "Beef hamburger", "Sushi", "Foie gras", "Pork chop"], "ans": 1, "exp": "ถ่ายเป็นเลือด + ไตวายเฉียบพลันเป็นกลุ่ม = Hemolytic Uremic Syndrome (HUS) จาก E. coli O157:H7 (Shiga toxin) ที่สัมพันธ์กับ 'เนื้อบดปรุงไม่สุก' (undercooked ground beef/hamburger) แบบคลาสสิก. *ต้นฉบับไฮไลต์ pork chop ซึ่งไม่ตรงกับ EHEC/HUS ที่โยงกับเนื้อวัวบด*"}, {"topic": "Pediatrics", "q": "A child presented with high grade fever, drowsiness and purple (purpuric) rash as in a picture. What is proper management?", "choices": ["Ciprofloxacin", "Rifampicin", "PGS (Penicillin G sodium)", "Colistin", "Cloxacillin"], "ans": 2, "exp": "ไข้สูง + ซึม + purpura/petechiae ทั่วตัว = meningococcemia (Neisseria meningitidis, ± Waterhouse-Friderichsen). รักษาด้วย Penicillin G (PGS) หรือ ceftriaxone. Rifampicin/ciprofloxacin ใช้เป็น prophylaxis ผู้สัมผัส ไม่ใช่การรักษา", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q205.png"}, {"topic": "Pediatrics", "q": "A child presented with high grade fever, conjunctivitis, strawberry tongue, hand edema, lymphadenopathy. What is the most serious complication of this disease? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับให้คำตอบว่า coronary aneurysm)", "choices": ["Valvular heart disease", "Myocarditis", "Arrhythmia", "Coronary artery aneurysm", "Pericardial effusion"], "ans": 3, "exp": "ไข้สูง + เยื่อบุตาแดง + strawberry tongue + มือบวม + ต่อมน้ำเหลืองโต = Kawasaki disease. ภาวะแทรกซ้อนที่ร้ายแรงที่สุดคือ coronary artery aneurysm (เส้นเลือดหัวใจโป่งพอง) → ต้องรักษาด้วย IVIG + aspirin ภายใน 10 วัน"}, {"topic": "Pediatrics", "q": "A child presented with fever, mass at preauricular area on both sides (bilateral parotid swelling). What is the complication of this disease?", "choices": ["Myocarditis", "Orchitis"], "ans": 1, "exp": "ก้อนบริเวณหน้าหู 2 ข้าง (bilateral parotitis) = mumps (คางทูม). ภาวะแทรกซ้อนที่พบคือ orchitis (อัณฑะอักเสบ ในเด็กชายวัยหลังวัยรุ่น), รวมถึง aseptic meningitis, pancreatitis"}, {"topic": "Pediatrics", "q": "A 14-day-old infant presented with eye redness (neonatal conjunctivitis). What is the treatment? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Erythromycin"], "ans": 0, "exp": "เยื่อบุตาอักเสบในทารกช่วงวันที่ 5-14 = Chlamydia trachomatis → รักษาด้วย oral erythromycin (systemic) เพื่อป้องกัน chlamydial pneumonia ร่วมด้วย"}, {"topic": "Pediatrics", "q": "A 12 years old girl presented with tachypnea on day 7 of being diagnosed with dengue shock syndrome. PE: BT 36.5°C, RR 40/min. Lung - fine crepitation lower lung, decreased Rt breath sound. Skin - present of convalescent rash. What is proper management?", "choices": ["NB Salbutamol", "IV Diuretic", "IV Morphine", "IV Corticosteroids", "IV Aminophylline"], "ans": 1, "exp": "วันที่ 7 ของ dengue = convalescent (reabsorption) phase สารน้ำที่รั่วออกไปถูกดูดกลับ → fluid overload/pulmonary edema + pleural effusion (crepitation, breath sound ลดลง). รักษาด้วย IV diuretic (furosemide) เพื่อขับน้ำส่วนเกิน"}, {"topic": "Pediatrics", "q": "A 5 years old girl presents with high grade fever and severe right ear pain. PE: BT 38.5°C, PR 110 bpm. Right ear effusion behind inflamed and bulging tympanic membrane. What is the appropriate treatment?", "choices": ["Cloxacillin", "Clindamycin", "Amoxicillin", "Cephalexin", "Ciprofloxacin"], "ans": 2, "exp": "เยื่อแก้วหูแดงโป่ง + มี effusion + ไข้ + ปวดหู = acute otitis media. ยา first-line คือ amoxicillin (high-dose) ครอบคลุมเชื้อหลัก S. pneumoniae, H. influenzae, M. catarrhalis"}, {"topic": "Pediatrics", "q": "A 12-year-old boy arrives with pain and inflammation over the ball of his left foot and red streaks extending up the inner aspect of his leg. He remembers removing a wood splinter from the sole of his foot on the previous day. Which of the following is the most likely infecting organism?", "choices": ["C. perfringens", "S. aureus", "Strep Group A"], "ans": 2, "exp": "เส้นแดงลามขึ้นตามขา (lymphangitis) หลังบาดแผลที่เท้า = Group A Streptococcus (Streptococcus pyogenes) เป็นสาเหตุคลาสสิกของ lymphangitis/cellulitis ที่ลามเร็ว"}, {"topic": "Pediatrics", "q": "3 year old girl present with dysuria and fever. PE: BT 38.9°C, PR 110 bpm, RR 30, BP 90/60 mmHg. UA: sp.gr 1.025 turbid, WBC 20-30, RBC 5-10, sq 1-2, nitrite +ve. Which is correct UTI diagnosis?", "choices": ["10^4 E.coli in midstream urine", "10^3 E.coli in urine cath", "10^3 E. faecalis urine cath", "10^3 S. saprophyticus urine cath", "10^1 E.coli in suprapubic aspiration"], "ans": 4, "exp": "เกณฑ์วินิจฉัย UTI ขึ้นกับวิธีเก็บ: suprapubic aspiration = ขึ้นเชื้อเท่าไรก็ถือว่ามีความหมาย (แม้ 10^1); catheterized ต้อง ≥5×10^4; midstream clean-catch ต้อง ≥10^5. ดังนั้นข้อที่ถูกต้องคือ 10^1 E.coli จาก suprapubic (ข้ออื่นปริมาณไม่ถึงเกณฑ์ตามวิธีเก็บ)"}, {"topic": "Pediatrics", "q": "Child with prolonged fever, palm and sole erythema, papular rash at trunk, bilateral conjunctival injection, Rt cervical LN tenderness. What is the complication of this disease?", "choices": ["Coronary aneurysm", "Myocarditis", "Pericarditis"], "ans": 0, "exp": "ไข้เรื้อรัง + ฝ่ามือฝ่าเท้าแดง + ผื่นที่ลำตัว + เยื่อบุตาแดง 2 ข้าง + ต่อมน้ำเหลืองคอโต = Kawasaki disease → ภาวะแทรกซ้อนที่สำคัญคือ coronary artery aneurysm"}, {"topic": "Pediatrics", "q": "เด็กปวดแก้มสองข้าง (bilateral parotitis) ได้วัคซีนตาม EPI. ต้องหาภาวะแทรกซ้อนอะไรเพิ่ม (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Orchitis"], "ans": 0, "exp": "คางทูม (mumps parotitis) → ต้องเฝ้าระวัง/ตรวจหา orchitis (อัณฑะอักเสบ) ในเด็กชาย รวมถึง aseptic meningitis, pancreatitis"}, {"topic": "Pediatrics", "q": "A 2 year-old boy presents with fever, reddening of eye & mouth, erythematous swelling of palms and soles with periungual desquamation, enlargement of cervical LN. Treatment initiates this patient to avoid following consequences?", "choices": ["Endarteritis obliterans", "Rheumatic Heart disease", "Coronary artery aneurysm", "Leukocytoclastic vasculitis", "Cerebral venous sinus thrombosis"], "ans": 2, "exp": "Kawasaki disease (ไข้ + ตา/ปากแดง + ฝ่ามือฝ่าเท้าบวมแดง + ลอกรอบเล็บ + ต่อมน้ำเหลืองโต). การรักษาด้วย IVIG + aspirin ภายใน 10 วัน มีเป้าหมายเพื่อป้องกัน coronary artery aneurysm. *ต้นฉบับไฮไลต์ endarteritis obliterans ซึ่งไม่ใช่ผลลัพธ์หลักที่ต้องการป้องกัน*"}, {"topic": "Orthopedics", "q": "A 20-year-old basketball player presented with a finger as in a picture (mallet finger — DIP ยืดไม่ขึ้น). What is the appropriate management? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Buddy splint", "Aluminium splint", "K-wire"], "ans": 1, "exp": "นิ้วปลายงอเหยียดไม่ขึ้น (mallet finger — extensor tendon avulsion ที่ DIP) → รักษาด้วยการดาม DIP ให้เหยียดตรงต่อเนื่อง 6-8 สัปดาห์ด้วย aluminium (mallet) splint. K-wire ใช้เมื่อมี bony fragment ใหญ่/ไม่ตอบสนอง", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q216.png"}, {"topic": "Orthopedics", "q": "A Thai male 50 years old presents with chronic bilateral knee pain. He complained about epigastric pain for 3 months. He took OTC ibuprofen for 6 months to relieve his knee pain. PE: no abdominal tenderness, bilateral valgus knee, crepitation both knees. EGD: diffuse erythematous gastritis. Histopathology: reactive gastritis suspicious from medication-induced. What is the best management?", "choices": ["Add omeprazole", "Stop ibuprofen, add omeprazole", "Add alginic acid (gaviscon)", "Change ibuprofen to paracetamol and orphenadrine"], "ans": 1, "exp": "NSAID-induced gastritis (ibuprofen 6 เดือน + reactive gastritis) → best management คือหยุดยาต้นเหตุ (ibuprofen) และเพิ่ม PPI (omeprazole) เพื่อรักษาแผลกระเพาะ. การให้ PPI อย่างเดียวโดยไม่หยุด NSAID ไม่เพียงพอ"}, {"topic": "Orthopedics", "q": "เด็กชาย 6 ขวบ มา รพ ด้วยไม่ยอมยืนด้วยขาซ้าย 2 สัปดาห์. PE: BT 38.6°C, ขาซ้ายอยู่ในท่า flex hip ตลอดเวลา, pain on motion, บวม. CBC: WBC 25,000 PMN predominate. Film hip ดูเหมือนปกติ. จะส่ง investigation อะไร", "choices": ["U/S (ultrasound of hip)", "ESR", "Bone scan", "CT", "MRI"], "ans": 0, "exp": "ไข้ + ไม่ลงน้ำหนัก + สะโพกงอค้าง (position of comfort) + WBC สูง PMN + film ปกติ = สงสัย septic arthritis of hip. Investigation ที่เหมาะสมคือ ultrasound สะโพก (ตรวจหา joint effusion และใช้นำการเจาะดูดข้อ = diagnosis ยืนยัน)"}, {"topic": "Orthopedics", "q": "ผู้ป่วย 70 ปี ปวดเข่า 2 ข้าง ปวดมากตอนแบกของ. PE: Genu varus, crepitation. Diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Rheumatoid arthritis", "Osteoarthritis of knee", "Gouty arthritis", "Septic arthritis", "Pseudogout (CPPD)"], "ans": 1, "exp": "ผู้สูงอายุ ปวดเข่า 2 ข้างเวลาลงน้ำหนัก/แบกของ + genu varus (เข่าโก่ง) + crepitation = primary osteoarthritis of knee (ข้อเข่าเสื่อม)"}, {"topic": "Psychiatry", "q": "A 28 years old female presented with left wrist pain after falling at 2 AM. PE: BP 120/80, PR 80, poor eye contact, multiple stage contusion at back, costal margin, and mild contusion at left wrist. She wants to go home due to concern about a 7-days old baby. What is the initial management?", "choices": ["Tell the police", "Film left wrist", "More history taking", "Send CBC, PT, PTT", "D/C with ibuprofen"], "ans": 2, "exp": "รอยฟกช้ำหลายระยะ (multiple stage contusion) ในตำแหน่งที่ไม่สอดคล้องกับการล้ม + poor eye contact + มีลูกอ่อน 7 วัน = สงสัย intimate partner violence (ความรุนแรงในครอบครัว). Initial management คือซักประวัติเพิ่ม (สร้างความไว้วางใจ ประเมินความปลอดภัย) ไม่ใช่แจ้งตำรวจทันทีโดยไม่ได้รับความยินยอม"}, {"topic": "Orthopedics", "q": "ผู้ป่วยชาย ปวดหลัง. PE: Rt EHL grade 4, decreased anteromedial sensation of leg. Film: L-S spine osteophyte L4-5 and narrow disc space. What is diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Disc herniation", "Spinal stenosis", "Spondylolisthesis"], "ans": 0, "exp": "อ่อนแรง EHL (extensor hallucis longus = L5) + ชาด้าน anteromedial ของขา + ช่องหมอนรองกระดูก L4-5 แคบ = herniated disc L4-5 กดรากประสาท L5 (L5 radiculopathy). Spinal stenosis ให้ neurogenic claudication 2 ข้างสัมพันธ์ท่าทาง"}, {"topic": "Psychiatry", "q": "A 30-year-old female presents with a history of palpitation, chest tightness, dizziness and fear of dying 3 times in a month. This happened unexpectedly and she has a fear of going out alone. What is the most appropriate management?", "choices": ["Propranolol", "Diazepam", "Fluoxetine", "Carbamazepine"], "ans": 2, "exp": "panic attack ที่เกิดขึ้นเองซ้ำ ๆ (ใจสั่น แน่นหน้าอก กลัวตาย) + กลัวออกนอกบ้านคนเดียว = panic disorder with agoraphobia. การรักษาหลักระยะยาวคือ SSRI (fluoxetine). benzodiazepine ใช้ระยะสั้นเท่านั้น"}, {"topic": "Psychiatry", "q": "A 14-year-old female was brought to the ER by her mother 1 hour after taking 20 paracetamol pills. She admits to having done the same thing 6 months ago after her father and mother got divorced. PE: patient is irritable, refuses to do anything. What is the diagnosis?", "choices": ["Adjustment disorder", "Adolescent turmoil", "Borderline disorder", "Anxiety disorder", "Major depressive disorder"], "ans": 0, "exp": "พฤติกรรมทำร้ายตัวเอง (กินยาเกินขนาด) ที่สัมพันธ์กับความเครียดที่ระบุได้ (พ่อแม่หย่า) ภายในไม่กี่เดือน + อารมณ์หงุดหงิด = adjustment disorder. borderline PD มักไม่วินิจฉัยก่อนอายุ 18 และต้องมี pattern ที่ pervasive"}, {"topic": "Psychiatry", "q": "A 50-year-old man presents with fever, chill, agitation and confusion. He has a history of long term medical use for mental illness. PE: BT 40°C, HR 110 bpm, BP 140/100 mmHg, RR 20/min, muscle rigidity, diaphoresis with disorientation. What is the most likely cause?", "choices": ["Alprazolam", "Haloperidol", "Fluoxetine", "Lithium", "Sodium valproate"], "ans": 1, "exp": "ไข้สูง + เกร็งกล้ามเนื้อ (rigidity) + autonomic instability + สับสน = Neuroleptic Malignant Syndrome (NMS) ซึ่งเกิดจากยา antipsychotic → haloperidol"}, {"topic": "Psychiatry", "q": "เด็กสาว ขี้อายมาตั้งแต่เด็ก รู้สึกเข้ากับเพื่อนไม่ได้ รู้สึกว่าตัวเองไม่ดีพอ ร่วมกับกินเยอะ นอนเยอะ น้ำหนักขึ้น (เรื้อรัง). ถามว่าเป็นอะไร", "choices": ["Major depressive disorder", "Avoidant personality", "Dysthymia (persistent depressive disorder)", "Social phobia"], "ans": 2, "exp": "อารมณ์ซึมเศร้าเรื้อรังระดับต่ำ ๆ มานาน + อาการแบบ atypical (กินเยอะ นอนเยอะ น้ำหนักขึ้น) + รู้สึกด้อยค่า = dysthymia (persistent depressive disorder). *มีลักษณะ avoidant ปนอยู่ แต่อาการ vegetative ชี้ไปทาง depressive disorder เรื้อรัง*"}, {"topic": "Psychiatry", "q": "เด็กหญิงวัยรุ่น ขาดเรียนหลายเดือน เลือกกินอาหาร/คุมอาหาร (diet control) น้ำหนักลดลงมาก v/s stable ดูผอมมาก. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Anorexia nervosa", "Bulimia nervosa"], "ans": 0, "exp": "จำกัดอาหาร/คุมอาหารเข้มงวด + น้ำหนักลดมาก + ผอมมาก (low body weight) = anorexia nervosa (restricting type). bulimia มักน้ำหนักปกติ + binge/purge"}, {"topic": "Psychiatry", "q": "A 75 years old male comes for an annual check up. No U/D. Last year's check up was normal. In the past 6 months he had a memory problem — cannot remember visitors he has not met for decades, and forgot some things in shopping list. He is homebound, no stress. What is diagnosis?", "choices": ["Normal forgetfulness", "Dementia", "Major depressive disorder", "Ill-anxiety disorder", "Mild cognitive impairment"], "ans": 4, "exp": "ความจำถดถอยเกินวัยปกติแต่ยังทำกิจวัตรประจำวัน (ADL) ได้ ไม่กระทบการดำเนินชีวิต = mild cognitive impairment (MCI). dementia ต้องมี functional impairment ในชีวิตประจำวันร่วมด้วย"}, {"topic": "Psychiatry", "q": "A 70-year-old woman underwent an operation for a right hip fracture. After 2 days, she says that she saw ghosts and climbed out of bed. PE: CNS - disorientation, inattention. What is proper treatment?", "choices": ["Haloperidol", "Amitriptyline", "Alprazolam", "Diazepam", "Sodium valproate"], "ans": 0, "exp": "หลังผ่าตัด 2 วัน + เห็นภาพหลอน + disorientation + inattention (อาการขึ้น ๆ ลง ๆ) = postoperative delirium. รักษาภาวะกระวนกระวายด้วย low-dose haloperidol. benzodiazepine ทำให้ delirium แย่ลง (ยกเว้น alcohol withdrawal)"}, {"topic": "Psychiatry", "q": "ผู้ป่วยหญิง มีอาการกลัวต้องออกไปข้างนอก เช่น ไปขึ้นรถไฟฟ้า มีใจสั่น (palpitation) ร่วมด้วย เป็นมาหลายเดือน อย่างอื่นปกติดี. Diagnosis? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Panic disorder", "Agoraphobia", "Specific phobia", "Adjustment disorder"], "ans": 1, "exp": "กลัวสถานการณ์ที่หนีออกยาก/ขอความช่วยเหลือยาก เช่น ที่สาธารณะ รถไฟฟ้า = agoraphobia. ต่างจาก panic disorder ที่เด่นเรื่อง panic attack เกิดเองไม่คาดคิดซ้ำ ๆ"}, {"topic": "Psychiatry", "q": "A 30 years old female with irritable mood, insomnia and chronic headache for 6 months after her work got promoted, with impaired work function. What is the specific treatment?", "choices": ["Clonazepam", "Lithium", "Fluoxetine", "Sertraline", "Valproate"], "ans": 2, "exp": "อาการวิตกกังวล/ซึมเศร้าเรื้อรังหลังเจอความเครียด (เลื่อนตำแหน่ง) + กระทบการทำงาน → รักษาจำเพาะด้วย SSRI (fluoxetine). *sertraline ก็เป็น SSRI ที่ใช้ได้เช่นกัน; benzodiazepine ใช้เสริมระยะสั้น*"}, {"topic": "Psychiatry", "q": "A 25 years old woman presented with sudden paresthesia of right hand and foot with mild weakness of left hand. The event occurred after she drove and hit another car at slow speed. She denied LOC and confusion. PE: unremarkable. What is the most likely diagnosis?", "choices": ["Adjustment disorder", "Factitious disorder", "Acute stress disorder", "Conversion disorder", "Panic disorder"], "ans": 3, "exp": "อาการทางระบบประสาท (ชา/อ่อนแรง) ที่ไม่เข้ากับ anatomy + เกิดหลังเหตุการณ์เครียด (อุบัติเหตุ) + ตรวจร่างกายปกติ = conversion disorder (functional neurological symptom disorder)"}, {"topic": "Psychiatry", "q": "A 30 years old female presented with irritable mood and agitation. She works all day and nights, spends all money for many creative projects, and has a history of depressive episodes and suicidal attempts. What is the most likely diagnosis?", "choices": ["Bipolar disorder", "Conversion disorder", "Schizoaffective disorder", "Persistent depressive disorder"], "ans": 0, "exp": "อาการ mania (นอนน้อย ใช้เงินเยอะ ทำโปรเจกต์เยอะ หงุดหงิด พลังงานสูง) + ประวัติ depressive episodes = bipolar disorder (มี manic + depressive episodes)"}, {"topic": "Psychiatry", "q": "นักแสดงหญิง กังวลเรื่องรูปร่าง/กลัวอ้วน 1 เดือนก่อนมามีคลื่นไส้อาเจียน ปวดตามตัว และได้ยินเพื่อน ๆ นินทาตนเอง (paranoia). น่าจะใช้สารอะไร", "choices": ["Amphetamine", "PTSD", "Cocaine", "Cannabis"], "ans": 0, "exp": "กังวลเรื่องหุ่น/กลัวอ้วน (ใช้ยาลดน้ำหนัก) + อาการ paranoid (ได้ยินคนนินทา) + คลื่นไส้ ปวดตัว (withdrawal) = amphetamine (ยากระตุ้น ใช้คุมน้ำหนัก ทำให้เกิด psychosis/paranoia)"}, {"topic": "Psychiatry", "q": "ผู้หญิงขับรถชนแล้วมีอาการอ่อนแรง (weakness) โดยตรวจร่างกายไม่พบพยาธิสภาพ. เป็นอะไร (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Factitious disorder", "Conversion disorder"], "ans": 1, "exp": "อ่อนแรงเกิดขึ้นหลังเหตุการณ์เครียด (อุบัติเหตุ) โดยไม่มีสาเหตุทางกาย = conversion disorder. factitious disorder คือแกล้งป่วยเพื่อรับบทผู้ป่วย (โดยไม่มีผลประโยชน์ภายนอก)"}, {"topic": "Psychiatry", "q": "A 65 year-old retired woman presented with recent memory impairment 6 months after her husband passed away. She has poor concentration, decreased interest in her hobbies, insomnia, and weight loss. She sometimes wishes for her death but denies suicidal idea. No underlying disease nor medication. What is the most likely diagnosis?", "choices": ["Adjustment disorder", "Generalized anxiety disorder", "Major depressive disorder", "Somatic symptom disorder", "Major neurocognitive disorder"], "ans": 2, "exp": "อาการซึมเศร้าครบ (anhedonia, insomnia, น้ำหนักลด, สมาธิแย่, อยากตาย) หลังสูญเสียคู่สมรส ≥ 6 เดือน + ความจำแย่ (pseudodementia จากซึมเศร้า) = major depressive disorder"}, {"topic": "Psychiatry", "q": "ชายสูงอายุ มาด้วย fever with chill, agitation, confusion หลังกินยาหลายตัว. PE: BT 40°C, PR 110, RR 20, BP ปกติ, muscle rigidity, disorientation, diaphoresis. Cause น่าจะจากอะไร", "choices": ["Alprazolam", "Lithium", "Sertraline", "Haloperidol", "Sodium valproate"], "ans": 3, "exp": "ไข้สูง + rigidity + autonomic instability + สับสน หลังได้ยา antipsychotic = Neuroleptic Malignant Syndrome (NMS) → haloperidol"}, {"topic": "Ophthalmology", "q": "A 14-year-old boy presented with cannot close his Lt eye and drooling from his Lt lip for 1 day. No pain. No other neurological deficit. What is the most appropriate treatment?", "choices": ["Gabapentin", "Prednisolone"], "ans": 1, "exp": "อ่อนแรงกล้ามเนื้อใบหน้าครึ่งซีก (หลับตาไม่สนิท + มุมปากตก น้ำลายไหล) แบบ lower motor neuron เส้นเดียว ไม่มี deficit อื่น = Bell's palsy. รักษาด้วย corticosteroid (prednisolone) เริ่มเร็วภายใน 72 ชม. + ดูแลกระจกตา"}, {"topic": "Ophthalmology", "q": "A 25-year-old female developed progressive vision loss of the right eye for 5 days. Right eye - pain provoked by eye movement & globe palpation, loss of color vision + cecocentral scotoma. VA: Right 6/24, Left 6/6. PE: hyperemia + swelling of optic disc, +RAPD Rt eye. What is the diagnosis?", "choices": ["Optic neuritis", "Papilledema", "Compressive optic neuropathy", "Anterior ischemic optic neuropathy", "Hereditary optic neuropathy"], "ans": 0, "exp": "หญิงสาว + สูญเสียการมองเห็นข้างเดียวแบบมีปวดเวลากรอกตา + เห็นสีผิดเพี้ยน (dyschromatopsia) + RAPD + จานประสาทตาบวม = optic neuritis (มักสัมพันธ์ MS)"}, {"topic": "Ophthalmology", "q": "An 84-year-old female presents with eye irritation and tearing for months, with off and on redness at the nasal side of eyes. PE: both eyes 20/25, pink triangular tissue at limbus extending to cornea. What is management?", "choices": ["Topical steroid", "Artificial tear", "Topical mupirocin", "Excision", "I&D"], "ans": 1, "exp": "เนื้อสามเหลี่ยมสีชมพูจาก limbus เข้าหากระจกตา = pterygium (ต้อเนื้อ). ขนาดเล็ก VA ดี มีแค่ระคายเคือง → รักษาตามอาการด้วย artificial tears. ผ่าตัด (excision) เมื่อบังแกนการมองเห็น/โตมาก/รบกวนความสวยงาม"}, {"topic": "Ophthalmology", "q": "Acute pain with visual loss at Rt eye. PE: dilated (mid-dilated) pupil Rt eye, shallow anterior chamber, conjunctival injection. What is the proper investigation?", "choices": ["VA", "Confrontation test", "Tonometry", "External eye movement"], "ans": 2, "exp": "ตาแดงปวดเฉียบพลัน + รูม่านตาขยายค้าง + ช่องหน้าลูกตาตื้น = acute angle-closure glaucoma → investigation ที่เหมาะสมคือ tonometry (วัดความดันลูกตา IOP ซึ่งจะสูงมาก)"}, {"topic": "Ophthalmology", "q": "A 68-year-old woman presents with a left upper eyelid mass for 1 month. Not painful, not growing. PE: 4-mm round nodule, well demarcated and smooth surface on left upper eyelid. What is the most appropriate management?", "choices": ["Warm compression and oral antibiotic", "Intralesional steroid injection", "Incisional biopsy", "Incision and curettage", "Excisional biopsy"], "ans": 3, "exp": "ก้อนเปลือกตาไม่เจ็บ เรื้อรัง กลม ขอบชัด = chalazion (ต้อกุ้งยิงชนิดไม่อักเสบ). ก้อนที่คงอยู่นาน ~1 เดือน รักษาด้วย incision and curettage. (chalazion เป็น granuloma ปลอดเชื้อ ไม่จำเป็นต้องกิน antibiotic)"}, {"topic": "Ophthalmology", "q": "Patient had done facial filler injection then presented with Rt eye acute painless visual loss (image shows CRAO). What is the diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Central retinal vein occlusion (CRVO)", "Optic neuritis", "Retinal detachment", "Vitreous hemorrhage", "Central retinal artery occlusion (CRAO)"], "ans": 4, "exp": "สูญเสียการมองเห็นเฉียบพลันแบบไม่ปวดหลังฉีด filler ใบหน้า = central retinal artery occlusion (CRAO) จาก filler อุดหลอดเลือด (retrograde embolization). จอตาซีด + cherry-red spot"}, {"topic": "Ophthalmology", "q": "ผู้ชายขี่รถจักรยานยนต์ แล้วรู้สึกระคายเคืองตาเวลากระพริบตา. VA 20/20, cornea clear. What is the proper investigation?", "choices": ["Upper lid eversion", "Fluorescein stain", "IOP measurement"], "ans": 0, "exp": "รู้สึกเคืองเวลากระพริบตา + ขี่มอเตอร์ไซค์ (ลม/ผงเข้าตา) + กระจกตาใส = สงสัย subtarsal foreign body ใต้เปลือกตาบน → ตรวจด้วยการปลิ้นเปลือกตาบน (upper lid eversion) หา FB"}, {"topic": "Ophthalmology", "q": "74 y/o female, both eyes tearing and irritation, redness at nasal side. PE: VA 20/25 both eyes, no injection, pink triangular fibrotic tissue 1 mm extended to cornea. Management?", "choices": ["Dexamethasone eye drop", "Artificial tear", "Antihistamine eye drop", "Excision"], "ans": 1, "exp": "pterygium ขนาดเล็ก (1 mm) VA ดี มีแค่ระคายเคือง → artificial tears ตามอาการ"}, {"topic": "Ophthalmology", "q": "หญิงอายุมาก เคืองตาด้าน nasal 2 ข้าง น้ำตาไหล ตรวจพบ pterygium at nasal side both eyes เลย limbus เข้าไปเล็กน้อย, อื่น ๆ ปกติ. Management?", "choices": ["Dexamethasone eye drop", "Polymyxin eye drop", "Artificial tear", "NSAIDs eye drop", "Pterygium excision"], "ans": 2, "exp": "pterygium ขนาดเล็ก อาการน้อย → รักษาตามอาการด้วย artificial tears. ผ่าตัดเมื่อโตเข้าใกล้/บังแกนการมองเห็น"}, {"topic": "Ophthalmology", "q": "หญิง มาด้วยตา 2 ข้าง tearing, irritating หลายเดือน ตาแดงด้าน nasal. PE: VA 20/25 both eyes, no ciliary injection, fibrovascular tissue extending from limbus to cornea 1 mm. จะทำอะไรดี", "choices": ["Dexamethasone eye drop", "Diclofenac eye drop", "Polymyxin B eye drop", "Artificial tear", "Excision of fibrovascular membrane"], "ans": 3, "exp": "pterygium ขนาดเล็ก (1 mm) VA ดี ไม่มี ciliary injection → รักษาตามอาการด้วย artificial tears"}, {"topic": "ENT", "q": "A man presented with a tender mass at the right peritonsillar area with uvular deviation. What should be done next?", "choices": ["Incision & drainage", "External drainage", "Needle aspiration"], "ans": 2, "exp": "ก้อนกดเจ็บบริเวณ peritonsillar + ลิ้นไก่เบี้ยว = peritonsillar abscess (ฝีรอบทอนซิล). ขั้นต่อไปคือ needle aspiration (ทั้งวินิจฉัยและระบายหนอง) ± I&D + antibiotic"}, {"topic": "ENT", "q": "A 20 years old female presented with vertigo for 2 days with a history of URI 3 weeks ago. There was neither hearing loss nor tinnitus. PE: spontaneous nystagmus to the right side, normal otoscope, normal neuro exam, Weber no lateralization, Rinne positive both ears. What is the most likely diagnosis?", "choices": ["Vestibular neuritis", "Labyrinthitis", "Acoustic neuroma", "Meniere's disease", "BPPV"], "ans": 0, "exp": "เวียนหัวต่อเนื่องหลัง URI + 'ไม่มี' การได้ยินลดลง/tinnitus + การได้ยินปกติ = vestibular neuritis. Labyrinthitis จะมีการได้ยินลดลงร่วม; Meniere มี hearing loss + tinnitus + aural fullness"}, {"topic": "ENT", "q": "After a shooting practice, a 17-year-old man presents with continuous buzzing noise in his right ear for 2 days. He still can hear normal conversation. PE: normal eardrum, Weber no lateralization, Rinne AC>BC both ears. What is the most likely diagnosis?", "choices": ["Otosclerosis", "Acoustic trauma", "Otomastoiditis", "Meniere's disease", "Ossicular chain disruption"], "ans": 1, "exp": "เสียงดังจากปืน (loud noise exposure) → tinnitus + sensorineural hearing loss ความถี่สูง (Rinne AC>BC = ไม่ใช่ conductive) = acoustic trauma / noise-induced hearing loss"}, {"topic": "ENT", "q": "A 45 year old male presents with swelling and erythema at bilateral upper neck and chin for 2 days. PE: BT 38°C, RR 24, PR 100, mild dyspnea, generalized swelling and erythema at submental + bilateral submandibular area, swelling at floor of mouth with tongue protrusion. What is the diagnosis?", "choices": ["Peritonsillar abscess", "Parapharyngeal abscess", "Ludwig's angina", "Retropharyngeal abscess", "Submandibular space abscess"], "ans": 2, "exp": "การติดเชื้อลามทั้ง submental + submandibular 2 ข้าง + พื้นปากบวมดันลิ้น + เริ่มหายใจลำบาก = Ludwig's angina (cellulitis ของ floor of mouth) — ภาวะฉุกเฉินที่ต้องเฝ้าระวัง airway"}, {"topic": "ENT", "q": "ให้รูป impacted cerumen (ขี้หูอุดตัน). What is the diagnosis? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับไม่มีตัวเลือก)", "choices": ["Otomycosis", "Foreign body in ear canal", "Cholesteatoma", "Impacted cerumen", "Acute otitis media"], "ans": 3, "exp": "ก้อนขี้หู (cerumen) อุดตันช่องหูภายนอก = impacted cerumen. รักษาด้วย cerumenolytic / irrigation / manual removal"}, {"topic": "ENT", "q": "Patient with bilateral submandibular swelling and tongue protrusion. What is the diagnosis?", "choices": ["Submandibular abscess", "Ludwig's angina", "Peritonsillar abscess"], "ans": 1, "exp": "บวม submandibular 2 ข้าง + ดันลิ้น = Ludwig's angina (การติดเชื้อ floor of mouth 2 ข้าง เสี่ยงอุดกั้นทางเดินหายใจ)"}, {"topic": "ENT", "q": "Presented with thyroid nodule 3 cm, TFT normal. What is proper management?", "choices": ["FNA", "Ultrasound", "Thyroid scan"], "ans": 0, "exp": "ก้อนไทรอยด์ขนาด 3 ซม. + TFT ปกติ (euthyroid) → ทำ FNA (fine needle aspiration) เพื่อดู cytology (มักทำภายใต้ ultrasound). thyroid scan ใช้เมื่อ TSH ต่ำ (สงสัย hot nodule)"}, {"topic": "ENT", "q": "Acute otitis externa in a long-standing DM patient (beware malignant otitis externa). Which antibiotic?", "choices": ["Ceftriaxone", "Ceftazidime"], "ans": 1, "exp": "malignant (necrotizing) otitis externa ในผู้ป่วยเบาหวาน เกิดจาก Pseudomonas aeruginosa → ต้องใช้ยาคลุม Pseudomonas เช่น ceftazidime (หรือ ciprofloxacin/piperacillin-tazobactam)"}, {"topic": "Forensic", "q": "A 40-year-old male was found dead in a closely sealed car in the driver seat. Inside the car, a stove was found. Postmortem change: livor mortis was blanchable dark red (cherry-red) color at back and buttock. What is the cause of death?", "choices": ["Environmental asphyxia", "Cyanide toxicity", "Carbon monoxide toxicity", "Methane toxicity", "Hydrogen sulfide toxicity"], "ans": 2, "exp": "รถปิดสนิท + มีเตาเผาไหม้ในรถ + livor mortis สีแดงสด (cherry-red) = carbon monoxide poisoning (CO จับ Hb เป็น carboxyhemoglobin สีแดงสด)"}, {"topic": "Forensic", "q": "A 16-year-old girl was sexually assaulted 3 days ago. PE: two oval marks at neck. PV: new tear posterior fourchette with bleeding. Spermatozoa and acid phosphatase were tested negative. What is true about this case?", "choices": ["Oval mark is bite mark", "Acid phosphatase is false negative", "No sperm indicates no sexual intercourse", "New tear indicated vaginal penetration", "Oval mark indicated sexual assault"], "ans": 3, "exp": "3 วันหลังเหตุ การตรวจไม่พบ sperm/acid phosphatase เป็นเรื่องปกติ (สลายภายใน ~48-72 ชม.) ไม่ใช่ false negative และไม่ได้แปลว่าไม่มีการร่วมเพศ. รอยฉีกใหม่ที่ posterior fourchette บ่งชี้การสอดใส่ทางช่องคลอด (penetration) จึงเป็นข้อที่ถูก"}, {"topic": "Forensic", "q": "A 50 years old man was crushed by a truck, admitted with hypovolemic shock (liver laceration + femur fracture). Surgery successful, discharged. One week later he developed MI, admitted to CCU; 2 weeks later developed bronchopneumonia progressing to septic shock and died. What is the cause of death that should be written on the death certificate?", "choices": ["Septicemia", "Massive blood loss", "Liver rupture", "Fracture of femur", "Traffic injury"], "ans": 4, "exp": "ใบมรณบัตรระบุ 'underlying cause of death' = เหตุการณ์แรกที่เริ่มลูกโซ่นำไปสู่การตาย. ทุกอย่าง (shock → MI → pneumonia → sepsis) สืบเนื่องจากอุบัติเหตุจราจร (traffic injury) จึงเป็น underlying cause"}, {"topic": "Forensic", "q": "A 45-year-old female was found dead in the middle of the road. Police suspected traffic injury. Her back has a patterned mark. What is the cause of the mark? (ต้นฉบับมีตัวเลือกไม่ครบ ใส่เท่าที่มี)", "choices": ["Tyre mark"], "ans": 0, "exp": "รอยลายบนหลังผู้ถูกรถทับ = tyre mark (รอยดอกยางรถ) — เป็น patterned abrasion/bruise ที่บ่งชี้ว่าถูกล้อรถทับ", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q258.png"}, {"topic": "Forensic", "q": "A case of gunshot injury (image shows a round central hole surrounded by wide soot blackening and seared margins). What can be assumed from this wound?", "choices": ["Exit wound", "Close contact gunshot wound"], "ans": 1, "exp": "มีเขม่าดำ (soot) + ขอบไหม้เกรียม (searing) รอบรูกระสุน = บาดแผลกระสุนทางเข้าระยะประชิด/สัมผัส (close-contact entrance wound). แผลทางออก (exit) จะไม่มีเขม่า ขอบปลิ้นออก", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q259.png"}, {"topic": "Forensic", "q": "แผลที่ขมับกะโหลก เป็นรอยกระสุนกลม ไม่แตกเป็นรูปดาว มีรอยดินปืน (tattooing/stippling) แต่ไม่มีเขม่า (soot). คิดว่าเกิดจากระยะไหน", "choices": ["Blast wound", "Stab wound", "Near/Close (intermediate) range", "Contact range", "Long distance range"], "ans": 2, "exp": "มี powder tattooing (stippling) แต่ 'ไม่มี' soot และไม่ stellate = intermediate (near/close) range. Contact = มี soot + stellate + muzzle imprint; distant = ไม่มีทั้ง soot และ tattooing", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q260.png"}, {"topic": "Forensic", "q": "A man brought to ER after traffic injury: fractures Lt 6th-8th ribs, decreased breath sound Lt lung, received CPR before death. Autopsy: Rt butterfly fracture of tibia, multiple abrasions at Lt trunk, CXR Lt hemothorax. What is the sign that indicates traffic injury?", "choices": ["Hemothorax due to rib fractures", "Brush abrasions are dice injury", "Injury from side injury", "Tibial fracture is from a bumper injury", "Was hit with a motorcycle"], "ans": 3, "exp": "butterfly (wedge) fracture ของกระดูก tibia = bumper fracture คลาสสิกของคนเดินถนนที่ถูกกันชนรถชน บ่งชี้ว่าเป็น traffic injury และบอกทิศทางการชน"}, {"topic": "Forensic", "q": "เด็กหญิง GA 16 wk มากับแม่ ขอทำแท้งเพราะตั้งครรภ์จากการถูกล่วงละเมิดทางเพศ (sexual assault) โดยเพื่อนร่วมชั้น. ต้องทำอย่างไร", "choices": ["ถามศาล", "ถามตำรวจ", "ถามพ่อของเด็กในครรภ์", "ทำไม่ได้เพราะ advance GA", "ทำได้เลย เป็นสิทธิที่ถูกต้องตามกฎหมาย"], "ans": 4, "exp": "การตั้งครรภ์จากการถูกข่มขืน/ล่วงละเมิดทางเพศ เป็นข้อบ่งชี้ที่ยุติการตั้งครรภ์ได้ตามกฎหมายไทย (แม้ GA เกิน 12 สัปดาห์) → ทำได้เลยเป็นสิทธิที่ถูกต้อง (ภายใต้การให้คำปรึกษา)"}, {"topic": "Forensic", "q": "มารดาพาเด็กมาด้วยปัสสาวะเป็นเลือด ตรวจพบ posterior hymen tear ไม่พบคราบสเปิร์ม สงสัยการล่วงละเมิดทางเพศเด็ก. Initial management?", "choices": ["ทำให้เด็กรู้สึกปลอดภัยก่อน", "โทรหาตำรวจ", "ซักประวัติแม่เพิ่มเติม", "ถามประวัติญาติคนอื่นเพิ่มเติม"], "ans": 0, "exp": "สงสัยการล่วงละเมิดทางเพศเด็ก → initial management คือทำให้เด็กรู้สึกปลอดภัยและไว้วางใจก่อน (establish safety/rapport) ก่อนซักประวัติและตรวจร่างกาย"}, {"topic": "Forensic", "q": "A 25 years old man brought to ER after traffic injury with a 3-cm stellate lesion at scalp. Soft tissue strands were seen bridging and undermining the wound edge. Which term best describes the type of lesion?", "choices": ["Avulsion", "Laceration", "Abrasion", "Contusion", "Incision"], "ans": 1, "exp": "แผลขอบไม่เรียบ (stellate) + มี tissue bridging (เนื้อเยื่อขึงข้ามแผล) + undermined edge = laceration (แผลฉีกขาดจากแรงทื่อ). แผล incision จากของมีคมจะขอบเรียบ ไม่มี tissue bridge"}, {"topic": "Forensic", "q": "แพทย์นิติเวชไปดูศพแขวนคอ พบรอยเชือกที่หน้าคอเฉียงขึ้นไปหลังหู (inverted V สูง) รอบปากมีแผลจากน้ำยาล้างห้องน้ำ และมีขวดน้ำยาวางข้างศพ. สาเหตุการตาย", "choices": ["Neck fracture due to hanging", "Brain anoxia due to hanging", "Neck vessels compression due to hanging"], "ans": 2, "exp": "การแขวนคอทั่วไป (ไม่ใช่ judicial hanging) กลไกการตายหลักคือการกดหลอดเลือดที่คอ (carotid/jugular) ทำให้สมองขาดเลือด — ใช้แรงน้อยกว่าการอุดทางเดินหายใจ และไม่จำเป็นต้องมีกระดูกคอหัก"}, {"topic": "Forensic", "q": "ชันสูตรศพในรถที่ปิดผนึกด้วยเทปรอบกระจกและประตู พบ livor ที่หลังและหลังขา (ตามท่าศพ) มี red-black skin sign และพบเตาเผาไหม้ในรถ. ตายจากอะไร", "choices": ["Carbon monoxide", "Cyanide"], "ans": 0, "exp": "รถปิดผนึก + เตาเผาไหม้ (การเผาไหม้ไม่สมบูรณ์) = carbon monoxide poisoning (CO) — livor สีแดง (carboxyhemoglobin)"}, {"topic": "Emergency", "q": "A 3-year-old presented with unconsciousness after drinking unknown fluid at a jewelry store. PE: PR 100 bpm, RR 10/min, BP 50/30 mmHg, SpO2 80%, capillary refill 6 seconds, pupil 3 mm sluggish response. What is the most likely cause?", "choices": ["Alcohol", "Non-acetone nail remover", "Glass cleaner", "Cyanide"], "ans": 3, "exp": "ร้านทอง/เครื่องประดับ ใช้ cyanide (ชุบ/ล้างทอง). กินแล้วหมดสติเร็ว + ช็อก + SpO2 ต่ำ (cellular hypoxia จาก cyanide ยับยั้ง cytochrome oxidase) = cyanide poisoning"}, {"topic": "Emergency", "q": "Wasp sting with 30 wounds, no stridor, no dyspnea. Apart from anaphylaxis, which condition should be observed?", "choices": ["Rhabdomyolysis", "Encephalopathy"], "ans": 0, "exp": "ถูกต่อ/แตนต่อยหลายแผล (envenomation ปริมาณมาก) → พิษทำให้เกิด rhabdomyolysis + hemolysis → เสี่ยง AKI จึงต้องเฝ้าระวัง rhabdomyolysis"}, {"topic": "Emergency", "q": "โดนแมงกะพรุนต่อย. Management?", "choices": ["Cold immersion 30 min", "Remove tentacle ด้วย NSS", "Irrigate แผลด้วย sterile water", "Irrigate ด้วย sodium bicarbonate"], "ans": 1, "exp": "แมงกะพรุนต่อย: ห้ามใช้น้ำจืด (hypotonic กระตุ้น nematocyst ยิงพิษเพิ่ม) → ล้าง/เอาหนวด (tentacle) ออกด้วยน้ำเกลือ (NSS, isotonic) หรือน้ำทะเล; box jellyfish ใช้ vinegar"}, {"topic": "Emergency", "q": "A woman was stabbed with a knife in the abdomen. V/S: BP 90/60, PR 100. What is the most appropriate management?", "choices": ["FAST", "CT abdomen", "Exploratory laparotomy", "Diagnostic laparoscopy", "Remove knife and explore wound"], "ans": 2, "exp": "penetrating abdominal trauma (ถูกแทง) + hemodynamic instability (BP ตก, tachycardia) → exploratory laparotomy ทันที ไม่เสียเวลาส่ง imaging (และห้ามดึงมีด/ของที่คาอยู่ออกนอกห้องผ่าตัด)"}, {"topic": "Emergency", "q": "ผู้ป่วยชายถูกต่อต่อยหลายตัว v/s stable. Complication ที่ต้องป้องกัน", "choices": ["Encephalopathy", "Meningitis", "Peripheral neuropathy", "Rhabdomyolysis", "CHF"], "ans": 3, "exp": "ถูกต่อ/แตนต่อยหลายแผล → พิษก่อ rhabdomyolysis (+ hemolysis) → เสี่ยง acute kidney injury จึงต้องเฝ้าระวัง/ป้องกัน rhabdomyolysis (ให้ IV fluid)"}, {"topic": "Emergency", "q": "กิน seafood แล้วเกิด wheal and flare (urticaria). PE: v/s stable, BP 100/60, lung: wheezing both lungs. Management?", "choices": ["Adrenaline IM", "ยา antihistamine IV", "Salbutamol NB"], "ans": 0, "exp": "ปฏิกิริยาแพ้ที่มี wheezing (หลอดลมหดเกร็ง = respiratory involvement) ร่วมกับ urticaria = anaphylaxis → first-line คือ adrenaline (epinephrine) IM ทันที แม้ความดันยังปกติ"}, {"topic": "Emergency", "q": "ผู้หญิงนักศึกษา มา ER หลังซ้อมเชียร์ มีหายใจเร็วและ carpopedal spasm = hyperventilation syndrome. Management?", "choices": ["บอกให้หายใจช้า ๆ (coaching/reassurance)", "หายใจในถุงพลาสติก"], "ans": 0, "exp": "hyperventilation syndrome → รักษาด้วยการให้ความมั่นใจและฝึกหายใจช้า ๆ (slow breathing coaching). การหายใจในถุง (rebreathing) เลิกแนะนำแล้วเพราะเสี่ยงภาวะขาดออกซิเจน"}, {"topic": "Emergency", "q": "เด็กกินน้ำยาล้างห้องน้ำ (สารกัดกร่อน) มา 1 ชม.ก่อน. ทำอะไรดี", "choices": ["Activated charcoal", "EGD (endoscopy)", "NG lavage", "Alkalinization"], "ans": 1, "exp": "กลืนสารกัดกร่อน (caustic ingestion): ห้ามให้ activated charcoal, ห้าม NG lavage, ห้าม neutralize → ทำ endoscopy (EGD) ภายใน 12-24 ชม. เพื่อประเมินความรุนแรงของแผลในหลอดอาหาร/กระเพาะ"}, {"topic": "Emergency", "q": "โดน box jellyfish (แมงกะพรุนกล่อง) ต่อย. Proper management? (ตัวเลือกแต่งขึ้นมาเอง ต้นฉบับตัวเลือกไม่ชัด)", "choices": ["ราดด้วยน้ำจืด/น้ำกลั่น (DW)", "ถูบริเวณที่โดนต่อย", "ราดด้วยน้ำส้มสายชู (vinegar/acetic acid) แล้วเอาหนวดออก", "ประคบน้ำแข็งลงบนแผลโดยตรง"], "ans": 2, "exp": "box jellyfish: ราดด้วยน้ำส้มสายชู (vinegar 4-6% acetic acid) เพื่อยับยั้ง nematocyst ก่อนเอาหนวดออก. ห้ามใช้น้ำจืด/น้ำกลั่น (hypotonic กระตุ้นการยิงพิษเพิ่ม) และห้ามถู"}, {"topic": "Emergency", "q": "ผู้ชายจะฆ่าตัวตาย มา ER โวยวาย วุ่นวาย (agitated). ทำอย่างไร", "choices": ["ให้พูดระบาย death wish", "Sedate", "มัด (restrain)", "จัดให้อยู่ในมุมสงบ/ปลอดภัยของ ER พร้อมเฝ้าดูแล"], "ans": 3, "exp": "ผู้ป่วยฆ่าตัวตายที่กระวนกระวายรุนแรง → เริ่มด้วยการจัดสิ่งแวดล้อมที่สงบและปลอดภัย ลดสิ่งกระตุ้น + เฝ้าระวังใกล้ชิด (de-escalation) ก่อน. sedate/restrain ใช้เมื่อ verbal de-escalation ไม่ได้ผลและเสี่ยงอันตราย"}, {"topic": "Emergency", "q": "เด็ก (อายุ > 1 ปี) มีอะไรติดคอ หายใจไม่ออก ไอไม่ออก (complete airway obstruction, ยังรู้สึกตัว). ทำอย่างไร", "choices": ["Back blow", "Heimlich maneuver (abdominal thrust)"], "ans": 1, "exp": "เด็กโต (>1 ปี) ที่สำลักอุดกั้นทางเดินหายใจสมบูรณ์ (ไอไม่ออก) และยังรู้สึกตัว → ทำ Heimlich maneuver (abdominal thrust). ทารก <1 ปี จึงใช้ back blow 5 ครั้งสลับ chest thrust"}, {"topic": "Emergency", "q": "ผู้ป่วย cardiac arrest ในรถ ambulance เปิดเส้น IV ไม่ได้. ทำอย่างไร", "choices": ["Intraosseous (IO) access", "Chest compression only"], "ans": 0, "exp": "ขณะ CPR ถ้าเปิด IV ไม่ได้ภายในเวลาอันสั้น → ใช้ intraosseous (IO) access เพื่อให้ยา/สารน้ำ (เร็วและเชื่อถือได้)"}, {"topic": "Emergency", "q": "ผู้ป่วยมีแผ่นฝ้า (membrane) สกปรกที่คอ + stridor + contact bleeding (เยื่อเปื่อยเลือดออกง่าย). ทำอย่างไรเพื่อเปิดทางเดินหายใจ", "choices": ["ETT (endotracheal intubation)", "Emergency tracheostomy"], "ans": 1, "exp": "เยื่อ (pseudomembrane เช่น diphtheria) ที่เปื่อยเลือดออกง่าย + อุดกั้นทางเดินหายใจส่วนบน → การใส่ ETT เสี่ยงดันเยื่อหลุด/เลือดออกซ้ำ จึงเลือก emergency tracheostomy เพื่อเปิดทางเดินหายใจใต้ตำแหน่งอุดกั้น"}, {"topic": "Community/EBM", "q": "In a study about asthma in children: of 100 children who lived with a smoker father, 20 developed asthma; of 200 children who lived with a non-smoker father, 10 developed asthma. What is the relative risk of asthma among children who lived with a smoking father?", "choices": ["0.05", "0.25", "4.00", "0.33", "2.00"], "ans": 2, "exp": "RR = (risk ในกลุ่มสัมผัส)/(risk ในกลุ่มไม่สัมผัส) = (20/100)/(10/200) = 0.20/0.05 = 4.00"}, {"topic": "Community/EBM", "q": "A village near a gold mine. Many people developed generalized multiple nodular (hyperkeratotic) lesions on both hands with peripheral numbness and lightheadedness. What is the cause?", "choices": ["Lead", "Nickel", "Mercury", "Arsenic", "Cadmium"], "ans": 3, "exp": "เหมืองทอง + ผิวหนังหนาตัวเป็นตุ่ม (arsenical keratosis) ที่ฝ่ามือ 2 ข้าง + peripheral neuropathy (ชาปลายมือปลายเท้า) = พิษสารหนู (arsenic)", "img": "https://cdn.jsdelivr.net/gh/MercenzK/Web-quiz-images@main/NL2-2021-Q281.png"}, {"topic": "Community/EBM", "q": "A man visited OPD with BP 140/90 twice, 15 mins apart at the hospital. At home, his BP is always below 140/90. What should be done next?", "choices": ["Reassurance", "Start anti-hypertensive drug"], "ans": 0, "exp": "ความดันสูงเฉพาะที่ รพ. แต่ที่บ้านปกติ = white coat hypertension → ให้ความมั่นใจ (reassurance) + ติดตามด้วย home/ambulatory BP ไม่จำเป็นต้องเริ่มยาลดความดันทันที"}, {"topic": "Community/EBM", "q": "You are a doctor in a rural area with heavy use of insecticide. Which lab should be used to monitor the health risk of this community?", "choices": ["Serum for cholinesterase level", "Urine for paraquat level", "Urine for organophosphate level", "Serum for organophosphate level", "Serum for pyrethroid level"], "ans": 0, "exp": "ยาฆ่าแมลงกลุ่ม organophosphate/carbamate ยับยั้งเอนไซม์ cholinesterase → ใช้ระดับ serum (plasma/RBC) cholinesterase เป็นตัวเฝ้าระวังการสัมผัสของชุมชน"}, {"topic": "Emergency", "q": "ญาตินำส่งผู้ป่วยที่พยายามแขวนคอ (suicide attempt) มาที่ ER. เราควรทำอะไร", "choices": ["ให้ผู้ป่วยอยู่มุมเงียบ ๆ ที่ ER", "พูดคุยเรื่อง death wish (ถามความคิดฆ่าตัวตายอย่างเปิดเผย)", "Restrain", "Sedate", "คุยกับผู้ป่วยด้วยเหตุผล"], "ans": 1, "exp": "ผู้ป่วยหลังพยายามฆ่าตัวตาย → ควรพูดคุยประเมินความคิดฆ่าตัวตาย (death wish/suicidal ideation) อย่างเปิดเผยและไม่ตัดสิน. การถามเรื่องฆ่าตัวตายไม่ได้เพิ่มความเสี่ยง แต่ช่วยประเมินและสร้างความไว้วางใจ"}, {"topic": "Ethics", "q": "A man with CA head of pancreas is planned for elective Whipple's operation. It was canceled because the pre-booked ICU was taken by a major hospital donor planning for elective knee arthroplasty. According to the four principles of ethics, which is breached?", "choices": ["Autonomy", "Beneficence", "Distributive justice", "Non-maleficence", "Absolute veracity"], "ans": 2, "exp": "การให้สิทธิ์ทรัพยากร (ICU) แก่ผู้บริจาคก่อนผู้ป่วยที่จำเป็นกว่า = ละเมิดหลัก distributive justice (การจัดสรรทรัพยากรอย่างเป็นธรรม)"}, {"topic": "Community/EBM", "q": "In a food poisoning outbreak, the investigator interviewed 80 students who went to the party. 45 of 60 who drank cocktails developed food poisoning whereas 1 of 20 who didn't drink developed it. Other foods showed no significance. Which type of study is this?", "choices": ["Prospective cohort study", "Case control study", "Experimental study", "Retrospective cohort study", "Cross sectional study"], "ans": 3, "exp": "สอบสวนการระบาดโดยย้อนดูการสัมผัส แล้วแบ่งกลุ่มตาม 'exposure' (ดื่ม/ไม่ดื่ม cocktail) เปรียบเทียบ attack rate = retrospective cohort study (คำนวณ RR ได้)"}, {"topic": "Community/EBM", "q": "A 40-year-old man smokes 40 cigarettes/day for 10 years. His wife wants him to stop but he doesn't. He usually smokes when he wakes up. What should be done?", "choices": ["Nicotine replacement therapy", "Bupropion therapy", "Acupuncture therapy", "Cognitive behavioral therapy", "Assess pros and cons of smoking"], "ans": 4, "exp": "ผู้ป่วย 'ยังไม่พร้อมเลิก' (precontemplation) → ใช้ motivational interviewing โดยประเมินข้อดี-ข้อเสียของการสูบบุหรี่ก่อน. ยา (NRT/bupropion) เหมาะกับผู้ที่พร้อมเลิกแล้ว"}, {"topic": "Ethics", "q": "เด็กหญิงอายุ 14 ปี ตั้งครรภ์ 12 สัปดาห์ มากับแม่เพื่อขอทำแท้ง ท้องนี้เกิดจากการถูกล่วงละเมิดทางเพศ (sexual assault) โดยเพื่อนร่วมชั้น. จะทำแท้งให้ไหม", "choices": ["ทำได้ เป็นสิทธิตามกฎหมาย (rightful)", "รอคำสั่งศาล", "ถามตำรวจก่อน", "ขออนุญาตพ่อของเด็กในครรภ์ก่อน", "สายเกินไป ท้องแก่เกิน"], "ans": 0, "exp": "ตั้งครรภ์จากการถูกข่มขืน/ล่วงละเมิดทางเพศ เป็นข้อบ่งชี้ที่ยุติการตั้งครรภ์ได้ตามกฎหมาย → ทำได้เลย (ไม่ต้องรอศาล/ตำรวจ/พ่อเด็ก)"}, {"topic": "Family Medicine", "q": "ทีมเยี่ยมบ้านไปเยี่ยมผู้ป่วยหญิง มี recurrent dizziness อาศัยอยู่กับลูกชายวัยรุ่น กังวลเรื่องอนาคตของลูก. ตาม family life cycle task ควรแนะนำอย่างไร", "choices": ["Make more family network", "Discuss appropriate freedom and responsibility", "Balance her son's need and interest", "Build mother-son relationship"], "ans": 1, "exp": "ครอบครัวที่มีลูกวัยรุ่น (family with adolescents) task คือปรับขอบเขตครอบครัวให้ยืดหยุ่น ให้ลูกมีอิสระควบคู่กับความรับผิดชอบที่เหมาะสม (freedom & responsibility)"}, {"topic": "Family Medicine", "q": "A multidisciplinary team visits a 50-year-old woman with recurrent dizziness. She lives with her teenage son and is always concerned about his education and future. According to the appropriate family life cycle, what is the most appropriate advice?", "choices": ["Make more family network", "Balance son's interest and need", "Balance son's freedom and responsibility", "Adjust satisfying home", "Rebuild mother-son relationship"], "ans": 2, "exp": "ครอบครัวที่มีลูกวัยรุ่น (adolescent stage) → task คือเพิ่มความยืดหยุ่นของขอบเขต ให้ลูกมีอิสระคู่กับความรับผิดชอบ (balance freedom and responsibility)"}, {"topic": "Community/EBM", "q": "A 60-year-old man diagnosed with cirrhosis for 3 months, drinks 35 units of alcohol daily for 40 years. Doctor advised cessation. The patient said that his friend died after stopping drinking. What stage of change is the man in?", "choices": ["Contemplation", "Planning", "Action", "Precontemplation", "Maintenance"], "ans": 3, "exp": "ผู้ป่วยยังไม่คิดจะเปลี่ยนพฤติกรรม + หาข้ออ้าง/ต่อต้าน (เพื่อนตายหลังเลิกเหล้า) = precontemplation stage (ตาม transtheoretical model)"}, {"topic": "Community/EBM", "q": "In a survey, weights of primary school girls are 20, 25, 30, 30, 35, 40, 45 kg. Which is correct regarding the central tendency?", "choices": ["Mean > mode > median", "Mean > median > mode", "Median > mode > mean", "Median > mode = mean", "Mean > median = mode"], "ans": 4, "exp": "เรียงข้อมูล: 20,25,30,30,35,40,45 (n=7). median = ค่ากลาง = 30; mode = 30 (ซ้ำมากสุด); mean = 225/7 ≈ 32.1. ดังนั้น mean (32.1) > median (30) = mode (30)"}, {"topic": "Ethics", "q": "ผู้ป่วย CA head of pancreas มีคิวผ่าตัดแล้ว อยู่ ๆ มี VIP มาแย่งคิว OR ไป (เคสไม่ฉุกเฉิน). ผิดหลักจริยธรรมข้อใด", "choices": ["Distributive justice", "Beneficence", "Non-maleficence"], "ans": 0, "exp": "การให้ VIP แย่งคิวห้องผ่าตัดจากผู้ป่วยที่จำเป็นกว่า/มีคิวก่อน = ละเมิดหลัก distributive justice (การจัดสรรทรัพยากรอย่างเป็นธรรม)"}, {"topic": "Ethics", "q": "หญิง GA 16 สัปดาห์ ตั้งครรภ์จากการถูกล่วงละเมิดทางเพศ (sexual assault) โดยเพื่อนร่วมห้อง มา รพ. กับแม่ ถามว่าทำแท้งได้ไหม", "choices": ["ไม่ทำ", "ทำได้เลย", "ถามพ่อของเด็กในครรภ์ก่อน", "ถามศาลก่อน"], "ans": 1, "exp": "ตั้งครรภ์จากการถูกข่มขืน/ล่วงละเมิดทางเพศ เป็นข้อบ่งชี้ที่ยุติการตั้งครรภ์ได้ตามกฎหมายไทย → ทำได้เลย (ภายใต้การให้คำปรึกษาตามขั้นตอน)"}]}];
